    // ViewModel（延迟初始化，在获取到 conversationId 后创建）
    private var viewModel: ChatViewModel? = null
    private var viewModelConversationId: String? = null // 记录当前 ViewModel 对应的 conversationId
    
    /**
     * 获取有效的 conversationId（从多个来源，按优先级）
     */
    private fun getValidConversationId(): String {
        // 优先级1：currentConversation（已同步的）
        val id1 = currentConversation?.id
        
        // 优先级2：arguments 中的 conversation
        val id2 = arguments?.getSerializable("conversation")?.let { (it as? Conversation)?.id }
        
        // 优先级3：viewModelConversationId（当前 ViewModel 的 ID）
        val id3 = viewModelConversationId
        
        // 选择第一个非空的 ID
        val rawId = id1 ?: id2 ?: id3
        
        // 校验并规范化
        return ConversationIdNormalizer.normalize(rawId)
    }
    
    /**
     * 获取或创建 ViewModel
     * 使用 conversationId 作为 key，确保每个对话有独立的 ViewModel 实例
     */
    private fun getViewModel(): ChatViewModel {
        // 确保 currentConversation 已同步
        ensureCurrentConversationSynced()
        
        // 获取有效的 conversationId
        val conversationId = getValidConversationId()
        
        // 如果 ViewModel 不存在或 conversationId 发生变化，重新获取
        if (viewModel == null || viewModelConversationId != conversationId) {
            try {
                // 使用 conversationId 作为 ViewModelProvider 的 key，确保每个对话有独立的 ViewModel
                val key = "ChatViewModel_$conversationId"
                viewModel = ViewModelProvider(
                    requireActivity(),
                    ViewModelProviderFactory(conversationId)
                ).get(key, ChatViewModel::class.java)
                viewModelConversationId = conversationId
                
                // 确保 ViewModel 已正确初始化
                viewModel?.initialize(conversationId)
                
                Log.d(TAG, "获取 ViewModel，对话ID: $conversationId，key: $key")
            } catch (e: Exception) {
                Log.e(TAG, "获取 ViewModel 失败: ${e.message}", e)
                // 如果获取失败，尝试使用 default
                if (conversationId != "default") {
                    Log.w(TAG, "尝试使用 default ViewModel")
                    val defaultKey = "ChatViewModel_default"
                    viewModel = ViewModelProvider(
                        requireActivity(),
                        ViewModelProviderFactory("default")
                    ).get(defaultKey, ChatViewModel::class.java)
                    viewModelConversationId = "default"
                    viewModel?.initialize("default")
                } else {
                    throw e // 如果已经是 default 还失败，抛出异常
                }
            }
        }
        return viewModel ?: throw IllegalStateException("无法获取 ViewModel")
    }
    
