    // 消息监听器（用于批测等功能）
    interface MessageListener {
        fun onAnswerReceived(answer: String)
        fun onTaskComplete()
        fun onTaskError(error: String)
    }
    
    private val messageListeners = mutableListOf<MessageListener>()
    
    /**
     * 添加消息监听器
     */
    fun addMessageListener(listener: MessageListener) {
        if (!messageListeners.contains(listener)) {
            messageListeners.add(listener)
            Log.d(TAG, "添加消息监听器，当前监听器数量: ${messageListeners.size}")
        }
    }
    
    /**
     * 移除消息监听器
     */
    fun removeMessageListener(listener: MessageListener) {
        messageListeners.remove(listener)
        Log.d(TAG, "移除消息监听器，当前监听器数量: ${messageListeners.size}")
    }
    
    /**
     * 通知所有监听器收到answer
     */
    private fun notifyAnswerReceived(answer: String) {
        messageListeners.forEach { listener ->
            try {
                listener.onAnswerReceived(answer)
            } catch (e: Exception) {
                Log.e(TAG, "通知监听器answer时异常: ${e.message}", e)
            }
        }
    }
    
    /**
     * 播放call_user提示音效（滴一声）
     */
    private fun playCallUserSound() {
        chatAudioFeedback.playCallUserSound()
    }

    /**
     * 播放任务完成音效（播放音频文件）
     */
    private fun playTaskCompleteSound() {
        chatAudioFeedback.playTaskCompleteSound(requireContext())
    }

    /**
     * 测试播放指定音调（用于试听不同音效）；音调常量说明见 [ChatAudioFeedbackController] / [ChatConstants.COMMON_TONES]
     */
    fun testTone(toneType: Int, durationMs: Int = 500) {
        chatAudioFeedback.testTone(toneType, durationMs)
    }

    /**
     * 通知所有监听器任务完成
     */
    fun notifyTaskComplete() {
        // 播放任务完成音效
        playTaskCompleteSound()
        
        messageListeners.forEach { listener ->
            try {
                listener.onTaskComplete()
            } catch (e: Exception) {
                Log.e(TAG, "通知监听器任务完成时异常: ${e.message}", e)
            }
        }
    }

    /**
     * 悬浮球发起任务完成后，统一显示结果弹窗：
     * 1) 优先使用本次结果文本；
     * 2) 为空时回退到最近一条助手回复；
     * 3) 再为空则显示“任务已完成”。
     */
    private fun showCompanionResultOverlay(preferredText: String?) {
        val mainActivity = activity as? MainActivity
        if (mainActivity == null) {
            Log.w(TAG, "showCompanionResultOverlay: mainActivity为null，无法显示弹窗")
            return
        }

        val textFromHistory = chatMessages
            .asReversed()
            .firstOrNull { msg ->
                ChatConstants.isMainAssistantSender(msg.sender) && msg.message.isNotBlank()
            }
            ?.message

        val resultText = preferredText?.trim().takeIf { !it.isNullOrEmpty() }
            ?: textFromHistory
            ?: "任务已完成"

        TaskResultOverlayManager.show(
            context = mainActivity,
            resultText = resultText
        )
    }
    
    /**
     * 通知所有监听器任务错误
     */
    private fun notifyTaskError(error: String) {
        messageListeners.forEach { listener ->
            try {
                listener.onTaskError(error)
            } catch (e: Exception) {
                Log.e(TAG, "通知监听器任务错误时异常: ${e.message}", e)
            }
        }
    }
    
    /**
     * 检查任务是否正在运行（供外部调用，如批测）
     * @return 是否正在运行
     */
    fun isTaskRunning(): Boolean {
        return isTaskRunning
    }
    
    /**
     * 检查任务是否暂停（供外部调用）
     * @return 是否暂停
     */
    fun isTaskPaused(): Boolean {
        return isTaskPaused
    }
    
    /**
     * 检查是否处于手动接管状态
     */
    fun isManualTakeover(): Boolean {
        return isManualTakeover
    }
    
    /**
     * 获取ChatAdapter（供外部调用，用于检查Fragment是否已完全初始化）
     * @return ChatAdapter实例，如果未初始化则返回null
     */
    fun getChatAdapter(): ChatAdapter? {
        return chatAdapter
    }
    
    /**
     * 暂停任务
     */
    fun pauseTask() {
        if (!isTaskRunning || isTaskPaused) {
            return
        }
        
        isTaskPaused = true
        Log.d(TAG, "任务已暂停")
        mainScope.launch {
            withContext(Dispatchers.Main) {
                addChatMessage("系统", "任务已暂停")
                
                // 显示暂停提示弹窗
                val currentActivity = activity
                if (currentActivity != null) {
                    TaskPauseOverlayManager.show(currentActivity)
                } else {
                    Log.w(TAG, "Activity为null，无法显示暂停提示弹窗")
                }
            }
        }
    }
    
    /**
     * 继续任务
     */
    fun resumeTask() {
        if (!isTaskRunning || !isTaskPaused) {
            return
        }
        
        // 检查是否有待处理的call_user任务
        if (pendingCallUser && pendingCallUserText != null && originalQuery != null) {
            Log.d(TAG, "继续call_user任务")
            continueCallUserTask()
            return
        }
        
        isTaskPaused = false
        Log.d(TAG, "任务已继续")
        mainScope.launch {
            withContext(Dispatchers.Main) {
                addChatMessage("系统", "任务已继续")
            }
            
            // 更新交互时间，避免超时
            updateLastInteractionTime()
            
            // 继续任务循环
            if (currentQuery != null) {
                continueTaskLoop()
            }
        }
    }
    
