    private var batchRestoreSessionId: Int = 0
    
    /**
     * 一页能显示的消息数量（缓存值，避免重复计算）
     * 根据屏幕高度和消息项的平均高度动态计算
     * 消息项最小高度约：上下边距(16dp) + 头像(36dp) + 文本内容(约20dp) = 72dp
     * 为了留出一些缓冲，使用80dp作为平均高度
     */
    private var cachedMessagesPerPage: Int? = null
    
    private fun getMessagesPerPage(): Int {
        if (cachedMessagesPerPage != null) {
            return cachedMessagesPerPage!!
        }
        
        val messagesPerPage = try {
            val displayMetrics = resources.displayMetrics
            val screenHeightDp = displayMetrics.heightPixels / displayMetrics.density
            // 减去输入框区域高度（约100dp）和其他UI元素（约50dp）
            val availableHeightDp = screenHeightDp - 150f
            // 每条消息平均高度约80dp，加上一些缓冲，计算能显示多少条
            val calculated = (availableHeightDp / 80f).toInt()
            // 至少显示10条，最多不超过30条（避免一次性加载太多）
            calculated.coerceIn(10, 30)
        } catch (e: Exception) {
            // 如果计算失败，使用默认值15条（约一屏）
            Log.w(TAG, "计算一页消息数量失败，使用默认值15: ${e.message}")
            15
        }
        
        cachedMessagesPerPage = messagesPerPage
        Log.d(TAG, "计算一页消息数量: $messagesPerPage 条")
        return messagesPerPage
    }
    
    private val MESSAGES_PER_PAGE: Int
        get() = getMessagesPerPage()
    
