    /**
     * 获取当前对话对应的服务器地址
     * 优先使用小助手专用地址，如果没有则使用对应的默认地址
     */
    private fun getServerUrlForConversation(): String {
        val prefs = requireContext().getSharedPreferences("app_prefs", android.content.Context.MODE_PRIVATE)
        val conversationId = currentConversation?.id
        
        // 自定义小助手：使用存储的 baseUrl
        if (CustomAssistantManager.isCustomAssistantId(conversationId)) {
            val assistant = CustomAssistantManager.getById(requireContext(), conversationId ?: "")
            return assistant?.baseUrl ?: (prefs.getString("chat_server_url", ChatConstants.DEFAULT_CHAT_SERVER_URL) ?: ChatConstants.DEFAULT_CHAT_SERVER_URL)
        }
        
        // 如果是技能学习小助手，优先加载专用地址，如果没有则使用技能学习小助手的默认地址
        if (conversationId == ConversationListFragment.CONVERSATION_ID_SKILL_LEARNING) {
            val specificKey = "chat_server_url_$conversationId"
            val specificUrl = prefs.getString(specificKey, null)
            if (specificUrl != null) {
                return specificUrl
            }
            // 使用技能学习小助手的默认地址，确保不被全局默认服务覆盖
            return ChatConstants.DEFAULT_SKILL_LEARNING_SERVER_URL
        }
        
        // 如果是聊天小助手，优先加载专用地址，如果没有则使用聊天小助手的默认地址
        if (conversationId == ConversationListFragment.CONVERSATION_ID_CHAT_ASSISTANT) {
            val specificKey = "chat_server_url_$conversationId"
            val specificUrl = prefs.getString(specificKey, null)
            if (specificUrl != null) {
                return specificUrl
            }
            return ChatConstants.DEFAULT_CHAT_ASSISTANT_SERVER_URL
        }
        
        // 如果是TopoClaw或人工客服，优先加载专用地址
        if (conversationId == ConversationListFragment.CONVERSATION_ID_ASSISTANT ||
            conversationId == ConversationListFragment.CONVERSATION_ID_CUSTOMER_SERVICE) {
            val specificKey = "chat_server_url_$conversationId"
            val specificUrl = prefs.getString(specificKey, null)
            if (specificUrl != null) {
                return specificUrl
            }
        }
        
        // 使用全局默认地址
        return prefs.getString("chat_server_url", ChatConstants.DEFAULT_CHAT_SERVER_URL) ?: ChatConstants.DEFAULT_CHAT_SERVER_URL
    }
    
    /**
     * 从聊天小助手 API 加载历史（跨设备同步）
     * 使用 imei 生成 thread_id，与 PC 端保持一致
     */
    private suspend fun loadChatAssistantHistoryFromApi() = withContext(Dispatchers.IO) {
        ensureNetworkServiceInitialized()
        val apiService = NetworkService.getApiService() ?: return@withContext
        val imei = ProfileManager.getOrGenerateImei(requireContext())
        val threadId = Uuid5Util.chatAssistantThreadId(imei)
        val vm = getViewModel()
        try {
            vm.initialize(ConversationListFragment.CONVERSATION_ID_CHAT_ASSISTANT)
            val response = apiService.getChatAssistantHistory(threadId = threadId, limit = 100)
            if (response.isSuccessful) {
                val body = response.body()
                val messages = body?.messages ?: emptyList()
                val chatMessages = messages.map { m ->
                    val sender = if (m.role == "user") "我" else "聊天小助手"
                    val type = if (m.role == "user") "user" else "answer"
                    ChatMessage(sender, m.content, type, System.currentTimeMillis() - (100 - m.order) * 1000L, "", null, null, null)
                }
                withContext(Dispatchers.Main) {
                    vm.clearMessages()
                    vm.addMessages(chatMessages)
                }
                Log.d(TAG, "聊天小助手历史加载成功: ${chatMessages.size} 条")
            } else {
                Log.w(TAG, "聊天小助手历史加载失败: ${response.code()}")
            }
        } catch (e: Exception) {
            Log.e(TAG, "聊天小助手历史加载异常: ${e.message}", e)
        }
    }

    /**
     * 自定义小助手（chat）：从 customer_service 加载历史（跨设备同步）
     */
    private suspend fun loadCustomAssistantHistoryFromApi(assistantId: String, assistantName: String) = withContext(Dispatchers.IO) {
        val prefs = requireContext().getSharedPreferences("app_prefs", Context.MODE_PRIVATE)
        val customerServiceUrl = prefs.getString("customer_service_url", ServiceUrlConfig.DEFAULT_CUSTOMER_SERVICE_URL)
            ?: ServiceUrlConfig.DEFAULT_CUSTOMER_SERVICE_URL
        CustomerServiceNetwork.initialize(customerServiceUrl)
        val apiService = CustomerServiceNetwork.getApiService() ?: return@withContext
        val imei = ProfileManager.getOrGenerateImei(requireContext())
        val vm = getViewModel()
        try {
            vm.initialize(assistantId)
            val response = apiService.getMessages(imei = imei, conversationId = assistantId, limit = 100)
            if (response.isSuccessful) {
                val body = response.body()
                val messages = body?.messages ?: emptyList()
                val chatMessages = messages.asReversed().map { m ->
                    val sender = when (m.sender) {
                        "我" -> "我"
                        else -> assistantName
                    }
                    val type = when (m.type) {
                        "user" -> "user"
                        else -> "answer"
                    }
                    val ts = m.created_at?.let { ChatIsoTime.parseToMillis(it) } ?: System.currentTimeMillis()
                    ChatMessage(sender, m.content ?: "", type, ts, "", null, null, null)
                }
                withContext(Dispatchers.Main) {
                    vm.clearMessages()
                    vm.addMessages(chatMessages)
                }
                Log.d(TAG, "自定义小助手历史加载成功: ${chatMessages.size} 条")
            } else {
                Log.w(TAG, "自定义小助手历史加载失败: ${response.code()}")
            }
        } catch (e: Exception) {
            Log.e(TAG, "自定义小助手历史加载异常: ${e.message}", e)
        }
    }

    /**
     * 确保NetworkService已使用当前对话对应的URL初始化
     * 在每次发送请求前调用，确保使用正确的服务地址
     */
    private fun ensureNetworkServiceInitialized() {
        try {
            // 检查Fragment是否还存在
            if (!isAdded || activity == null) {
                Log.w(TAG, "Fragment已销毁，跳过NetworkService初始化")
                return
            }
            
            // 如果是端云互发、人工客服或好友对话，不需要初始化HTTP服务（使用WebSocket）
            val conversationId = currentConversation?.id
            if (conversationId == ConversationListFragment.CONVERSATION_ID_ME ||
                conversationId == ConversationListFragment.CONVERSATION_ID_CUSTOMER_SERVICE ||
                conversationId?.startsWith("friend_") == true) {
                Log.d(TAG, "人工客服或好友对话，跳过NetworkService初始化（使用WebSocket）")
                return
            }
            
            val serverUrl = getServerUrlForConversation()
            NetworkService.initialize(serverUrl, requireContext())
            Log.d(TAG, "确保NetworkService已初始化，使用URL: $serverUrl")
        } catch (e: Exception) {
            Log.e(TAG, "初始化NetworkService失败: ${e.message}", e)
        }
    }
    
    /**
     * 是否开启了「是否获取已安装应用」开关
     */
    private fun isFetchInstalledAppsForCloudEnabled(): Boolean {
        if (!isAdded || context == null) return false
        return requireContext().getSharedPreferences("app_prefs", Context.MODE_PRIVATE)
            .getBoolean("fetch_installed_apps_for_cloud", false)
    }

    /**
     * 当「是否获取已安装应用」开关开启时，返回 MVP 格式的 install_apps JSON 字符串；
     * 否则返回 null
     */
    private fun getInstallAppsParamForUpload(): String? {
        if (!isAdded || context == null) return null
        if (!isFetchInstalledAppsForCloudEnabled()) return null
        val list = AppInstallHelper.getInstalledAppNamesForCloud(requireContext())
        if (list.isEmpty()) return null
        return org.json.JSONArray(list).toString()
    }
    
    /**
     * 是否使用 next_action 接口（由服务页面开关控制）
     */
    private fun useNextActionApi(): Boolean {
        if (!isAdded || context == null) return false
        return requireContext().getSharedPreferences("app_prefs", Context.MODE_PRIVATE)
            .getBoolean("use_next_action_api", false)
    }
    
    /**
     * 获取 install_apps 列表（用于 next_action 的 JSON 数组）
     */
    private fun getInstallAppsListForNextAction(): List<String>? {
        val json = getInstallAppsParamForUpload() ?: return null
        return try {
            org.json.JSONArray(json).let { arr ->
                List(arr.length()) { arr.getString(it) }
            }
        } catch (e: Exception) {
            null
        }
    }
    
    /**
     * 执行云侧请求（根据开关选择 upload 或 next_action），返回 (Response, ChatResponse?)
     * 用于统一处理所有需要分支的发送逻辑
     */
    private suspend fun performCloudRequest(
        apiService: com.cloudcontrol.demo.ApiService,
        chatUuid: String,
        query: String,
        rawBase64: String,
        urlEncodedBase64: String,
        userResponse: String? = null,
        userExample: String? = null,
        chatSummary: String? = null,
        packageName: String?,
        className: String?,
        imei: String,
        proMode: Boolean? = null,
        batchTestMode: Boolean? = null,
        swipeSearchContext: String? = null
    ): Pair<retrofit2.Response<*>, ChatResponse?> {
        return if (useNextActionApi()) {
            // next_action 开启时不传递 activity 信息
            val req = NextActionRequest(
                task_id = chatUuid,
                duid = imei,
                image_url = NextActionPayloadHelper.imageUrlFromRawBase64(rawBase64),
                query = query,
                user_response = userResponse,
                install_apps = getInstallAppsListForNextAction()
            )
            val r = apiService.sendNextActionRequest(req)
            Pair(r, r.body()?.toChatResponse())
        } else {
            val r = apiService.sendChatMessage(
                uuid = chatUuid,
                query = query,
                image = urlEncodedBase64,
                userResponse = userResponse,
                userExample = userExample,
                chatSummary = chatSummary,
                packageName = packageName,
                className = className,
                imei = imei,
                proMode = proMode,
                batchTestMode = batchTestMode,
                swipeSearchContext = swipeSearchContext,
                outputLanguage = LanguageManager.getSavedLanguage(requireContext()),
                installApps = getInstallAppsParamForUpload()
            )
            Pair(r, r.body())
        }
    }
    
    override fun onCreateView(
        inflater: LayoutInflater,
        container: ViewGroup?,
        savedInstanceState: Bundle?
    ): View {
        _binding = FragmentChatBinding.inflate(inflater, container, false)
        return binding.root
    }
    
    override fun onViewCreated(view: View, savedInstanceState: Bundle?) {
        super.onViewCreated(view, savedInstanceState)
        
        // 设置窗口软输入模式为 adjustResize，但通过代码固定标题栏位置
        activity?.window?.setSoftInputMode(android.view.WindowManager.LayoutParams.SOFT_INPUT_ADJUST_RESIZE)
        
        // 固定标题栏位置：监听WindowInsets变化，确保标题栏不被推起
        binding.llTitleBar.setOnApplyWindowInsetsListener { view, insets ->
            // 不应用任何insets，保持标题栏固定
            view.setPadding(0, 0, 0, 0)
            insets
        }
        
        // 获取传递的对话信息（确保从 arguments 同步）
        ensureCurrentConversationSynced()
        
        // 如果 Fragment 被复用，重置 viewModel 引用（确保使用正确的 ViewModel）
        val currentConversationId = currentConversation?.id
            ?: arguments?.getSerializable("conversation")?.let { (it as? Conversation)?.id }
            ?: "default"
        
        // 如果 conversationId 变化，需要重新获取 ViewModel
        if (viewModelConversationId != null && viewModelConversationId != currentConversationId) {
            Log.d(TAG, "检测到 conversationId 变化：$viewModelConversationId -> $currentConversationId，重置 ViewModel")
            viewModel = null
            viewModelConversationId = null
        }
        
        // 初始化 ViewModel（必须在获取到 currentConversation 之后）
        val vm = getViewModel()
        
        // 观察 ViewModel 中的消息变化，自动更新 UI
        vm.chatMessages.onEach { messages: List<ChatMessage> ->
            // 当 ViewModel 中的消息变化时，更新 adapter
            val adapter = chatAdapter
            if (adapter != null && !isRestoringMessages) {
                // 只在非恢复状态下更新，避免循环更新
                val currentItems = adapter.getItems()
                val currentMessageCount = currentItems.count { it is ChatItem.Message }
                if (currentMessageCount != messages.size) {
                    Log.d(TAG, "ViewModel消息变化，更新adapter: ViewModel有${messages.size}条，adapter有${currentMessageCount}条")
                    // 这里不直接更新，而是通过 restoreChatMessages 来统一处理
                    // 避免重复逻辑
                }
            }
        }.launchIn(lifecycleScope)
        
        // 切换对话时重置筛选状态
        filteredImeis = emptyList()
        
        // 如果对话之前被删除了，先恢复它（从"已删除"Set中移除）
        currentConversation?.id?.let { conversationId ->
            val prefs = requireContext().getSharedPreferences("conversations", android.content.Context.MODE_PRIVATE)
            val deletedSet = prefs.getStringSet("deleted_conversations", mutableSetOf())?.toMutableSet() ?: mutableSetOf()
            if (conversationId in deletedSet) {
                // 恢复对话：从已删除Set中移除
                deletedSet.remove(conversationId)
                prefs.edit()
                    .putStringSet("deleted_conversations", deletedSet)
                    .apply()
                Log.d(TAG, "已恢复被删除的对话: $conversationId")
                
                // 通知对话列表Fragment更新（如果存在）
                try {
                    val fragmentManager = parentFragmentManager
                    val conversationListFragment = fragmentManager.fragments.find { it is ConversationListFragment } as? ConversationListFragment
                    conversationListFragment?.loadConversations()
                } catch (e: Exception) {
                    Log.w(TAG, "通知对话列表更新失败: ${e.message}")
                }
            }
        }
        
        // 生成UUID（每次Fragment创建时重新生成）
        chatUuid = UUID.randomUUID().toString()
        
        // 检查是否有待执行的技能（从其他Fragment跳转过来时）
        pendingSkillToExecute?.let { skill ->
            Log.d(TAG, "onViewCreated: 检测到待执行的技能，开始执行: ${skill.title}")
            // 延迟执行，确保Fragment完全初始化
            view.post {
                executeSkill(skill)
            }
            // 清除pendingSkillToExecute，避免重复执行
            pendingSkillToExecute = null
        }
        
        // 从SharedPreferences加载云侧服务地址（优先使用小助手专用地址）
        val serverUrl = getServerUrlForConversation()
        
        // 初始化聊天网络服务
        NetworkService.initialize(serverUrl, requireContext())
        
        // 加载"端侧变化检测"开关设置（缓存到成员变量，避免每次动作执行前都读取SharedPreferences）
        val prefs = requireContext().getSharedPreferences("app_prefs", Context.MODE_PRIVATE)
        sendBeforeActionImageEnabled = prefs.getBoolean("send_before_action_image", false) // 默认false（关闭）
        updateActionCompletionDelayCache() // 更新动作完成后延迟时间缓存
        
        setupUI()
        PcOnlineStatusManager.addListener(pcOnlineStatusListener)
        PcOnlineStatusManager.startChecking(requireContext())
        
        // 检查是否有待发送的客服消息（从反馈页面跳转过来时）
        // 必须在setupUI()之后检查，确保chatAdapter已初始化
        if (currentConversation?.id == ConversationListFragment.CONVERSATION_ID_CUSTOMER_SERVICE) {
            val prefs = requireContext().getSharedPreferences("app_prefs", android.content.Context.MODE_PRIVATE)
            val pendingMessage = prefs.getString("pending_customer_service_message", null)
            if (pendingMessage != null) {
                Log.d(TAG, "onViewCreated: 检测到待发送的客服消息，开始发送")
                // 清除待发送消息（先清除，避免重复发送）
                prefs.edit().remove("pending_customer_service_message").apply()
                // 使用协程等待Fragment完全初始化后再发送消息
                mainScope.launch {
                    // 等待UI完全准备好（等待restoreChatMessages完成）
                    var waitCount = 0
                    while (isRestoringMessages && waitCount < 50) {
                        delay(100)
                        waitCount++
                    }
                    // 额外延迟，确保RecyclerView完全渲染
                    delay(500)
                    
                    withContext(Dispatchers.Main) {
                        // 再次检查chatAdapter是否已初始化
                        if (chatAdapter == null) {
                            Log.w(TAG, "onViewCreated: chatAdapter仍未初始化，延迟发送消息")
                            delay(300)
                        }
                        
                        Log.d(TAG, "onViewCreated: Fragment初始化完成，发送客服消息")
                        executeQueryFromExternal(pendingMessage)
                        // 确保消息显示后滚动到底部
                        view.postDelayed({
                            binding?.rvChatMessages?.smoothScrollToPosition(chatAdapter?.itemCount ?: 0)
                        }, 300)
                    }
                }
            }
        }
        
        // 注册系统返回键回调
        onBackPressedCallback = object : OnBackPressedCallback(true) {
            override fun handleOnBackPressed() {
                // 使用和返回按钮相同的逻辑
                handleBackPress()
            }
        }
        requireActivity().onBackPressedDispatcher.addCallback(viewLifecycleOwner, onBackPressedCallback!!)
        
        // 加载用户查询历史
        loadUserQueryHistory()
        
        // 性能优化：延迟恢复聊天记录，先让UI完全渲染完成，避免卡顿
        // 使用post确保RecyclerView已经完成初始布局后再加载数据，减少延迟时间
        view.post {
            mainScope.launch {
                ensureCurrentConversationSynced()
                val conversationId = currentConversation?.id
                    ?: arguments?.getSerializable("conversation")?.let { (it as? Conversation)?.id }
                    ?: viewModelConversationId ?: "default"
                // 进入聊天时确保连接存在（兜底：启动失败或断线后恢复），需在 ensureMultiSessionInitialized 之前
                if (conversationId == ConversationListFragment.CONVERSATION_ID_CHAT_ASSISTANT) {
                    val imei = ProfileManager.getOrGenerateImei(requireContext())
                    val threadId = Uuid5Util.chatAssistantThreadId(imei)
                    val baseUrl = ChatWebSocketPool.getDefaultChatBaseUrl(requireContext())
                    ChatWebSocketPool.ensureConnected(requireContext(), baseUrl, threadId, false)
                }
                // 多 session 自定义小助手：优先初始化（迁移、订阅、push 回调），单 session 再在 when 中注册
                if (CustomAssistantManager.isCustomAssistantId(conversationId)) {
                    val a = CustomAssistantManager.getById(requireContext(), conversationId)
                    if (a != null && a.hasChat() && a.multiSession) {
                        ensureMultiSessionInitialized(conversationId)
                    }
                }
                // 聊天长连接：默认聊天小助手由 ChatWebSocketPool.connectAll 预建连；这里只注册回调
                when {
                    conversationId == ConversationListFragment.CONVERSATION_ID_CHAT_ASSISTANT -> {
                        val threadId = Uuid5Util.chatAssistantThreadId(ProfileManager.getOrGenerateImei(requireContext()))
                        ChatWebSocketPool.setOnAssistantPush(threadId) { content ->
                            if (currentConversation?.id == ConversationListFragment.CONVERSATION_ID_CHAT_ASSISTANT) {
                                addChatMessage("聊天小助手", content, isAnswer = true)
                            }
                        }
                    }
                    CustomAssistantManager.isCustomAssistantId(conversationId) -> {
                        val assistant = CustomAssistantManager.getById(requireContext(), conversationId)
                        if (assistant != null && assistant.hasChat()) {
                            val imei = ProfileManager.getOrGenerateImei(requireContext())
                            val threadId = "${imei}_${conversationId}"
                            if (assistant.multiSession) {
                                // 多 session：ensureMultiSessionInitialized 会订阅 thread 并注册 push 回调
                                ensureMultiSessionInitialized(conversationId)
                            } else {
                                ChatWebSocketPool.setOnAssistantPush(threadId) { content ->
                                    if (currentConversation?.id == conversationId) {
                                        addChatMessage(assistant.name, content, isAnswer = true)
                                    }
                                }
                            }
                        }
                    }
                    else -> { /* 非聊天小助手，不需注册回调 */ }
                }
                val adapter = chatAdapter
                val adapterHasItems = adapter?.getItems()?.isNotEmpty() ?: false
                val vm = getViewModel()
                val vmHasMessages = vm.getMessages().isNotEmpty()
                val conversationIdForLoad = currentConversation?.id
                    ?: arguments?.getSerializable("conversation")?.let { (it as? Conversation)?.id }
                    ?: viewModelConversationId
                    ?: "default"

                // 好友会话：会话外收到消息时 MainActivity 只写入 prefs，ViewModel 仍可能是旧列表。
                // 若此处因「ViewModel 已有数据」走快捷恢复而跳过 loadMessagesFromPrefs，进入会话后新消息会消失。
                if (conversationIdForLoad.startsWith("friend_") && !adapterHasItems && !isRestoringMessages) {
                    Log.d(TAG, "onViewCreated: 好友会话，从 SharedPreferences 重新加载以合并后台/离线消息，对话ID: $conversationIdForLoad")
                    vm.loadMessagesFromPrefs(requireContext(), conversationIdForLoad)
                    var waitFriend = 0
                    while (vm.isRestoringMessages.value && waitFriend < 50) {
                        delay(100)
                        waitFriend++
                    }
                    if (vm.getMessages().isNotEmpty()) {
                        restoreChatMessagesFromViewModel()
                    }
                    return@launch
                }

                // 自定义小助手（多 session）即使 ViewModel 已有旧数据，也要优先按 session 从本地重载：
                // 会话外同步写入的是 chat_messages_${conversationId}_${sessionId}，直接恢复旧 ViewModel 会漏掉新会话消息。
                if (CustomAssistantManager.isCustomAssistantId(conversationIdForLoad) && !adapterHasItems && !isRestoringMessages) {
                    val assistant = CustomAssistantManager.getById(requireContext(), conversationIdForLoad)
                    if (assistant != null && assistant.multiSession) {
                        Log.d(TAG, "onViewCreated: 自定义小助手多 session，优先按 session 重载消息，对话ID: $conversationIdForLoad")
                        ensureMultiSessionInitialized(conversationIdForLoad)
                        val sid = currentSessionIdForMultiSession ?: run {
                            Log.w(TAG, "ensureMultiSessionInitialized 未设置 currentSessionIdForMultiSession")
                            return@launch
                        }
                        loadMessagesForMultiSessionSession(conversationIdForLoad, sid, assistant)
                        return@launch
                    }
                }

                // ViewModel 已有数据但可能是旧的：会话外 MainActivity 只写入 prefs，ViewModel 不会同步更新。
                // 从 prefs 重载以合并后台/离线消息，与好友会话、多 session 自定义小助手一致。
                if (vmHasMessages && !adapterHasItems && !isRestoringMessages) {
                    Log.d(TAG, "onViewCreated: ViewModel有旧数据，从 SharedPreferences 重新加载以合并后台消息，对话ID: $conversationIdForLoad")
                    vm.loadMessagesFromPrefs(requireContext(), conversationIdForLoad)
                    var waitReload = 0
                    while (vm.isRestoringMessages.value && waitReload < 50) {
                        delay(100)
                        waitReload++
                    }
                    if (vm.getMessages().isNotEmpty()) {
                        restoreChatMessagesFromViewModel()
                    }
                    return@launch
                }
                
                // 如果 ViewModel 为空，才加载消息
                if (!vmHasMessages && !adapterHasItems && !isRestoringMessages) {
                    val conversationId = conversationIdForLoad
                    // 聊天小助手：从 API 加载历史（跨设备同步）
                    if (conversationId == ConversationListFragment.CONVERSATION_ID_CHAT_ASSISTANT) {
                        Log.d(TAG, "onViewCreated: 聊天小助手，从API加载历史")
                        loadChatAssistantHistoryFromApi()
                        if (vm.getMessages().isNotEmpty()) {
                            restoreChatMessagesFromViewModel()
                        }
                        return@launch
                    }
                    // 自定义小助手：多 session 必须用 chat_messages_${id}_${sessionId}，与 PC 同步/会话外写入一致。
                    // 若仅当 hasChat() 才走多 session 加载，无 chat 能力时会落到下方无 session 的 loadMessagesFromPrefs，读到空列表。
                    if (CustomAssistantManager.isCustomAssistantId(conversationId)) {
                        val assistant = CustomAssistantManager.getById(requireContext(), conversationId)
                        if (assistant != null && assistant.multiSession) {
                            ensureMultiSessionInitialized(conversationId)
                            val sid = currentSessionIdForMultiSession ?: run {
                                Log.w(TAG, "ensureMultiSessionInitialized 未设置 currentSessionIdForMultiSession")
                                return@launch
                            }
                            loadMessagesForMultiSessionSession(conversationId, sid, assistant)
                            return@launch
                        }
                        if (assistant != null && assistant.hasChat() && !assistant.multiSession) {
                            Log.d(TAG, "onViewCreated: 自定义小助手（单 session），从 customer_service 加载历史")
                            loadCustomAssistantHistoryFromApi(conversationId, assistant.name)
                            if (vm.getMessages().isNotEmpty()) restoreChatMessagesFromViewModel()
                            return@launch
                        }
                    }
                    Log.d(TAG, "onViewCreated: ViewModel为空，从SharedPreferences加载消息，对话ID: $conversationId")
                    vm.loadMessagesFromPrefs(requireContext(), conversationId)
                    // 等待加载完成
                    var waitCount = 0
                    while (vm.isRestoringMessages.value && waitCount < 50) {
                        delay(100)
                        waitCount++
                    }
                    // 从 ViewModel 恢复消息到 adapter
                    if (vm.getMessages().isNotEmpty()) {
                        restoreChatMessagesFromViewModel()
                    }
                    return@launch
                }
                
                // 如果是管理员模式对话，加载所有用户的聊天记录
                if (currentConversation?.id == ConversationListFragment.CONVERSATION_ID_ADMIN_CUSTOMER_SERVICE) {
                    if (!adapterHasItems && !isRestoringMessages) {
                        Log.d(TAG, "onViewCreated: 管理员模式对话，开始加载所有聊天记录")
                        loadAllCustomerServiceChats()
                    }
                    // 更新输入框提示
                    updateAdminInputHint()
                } else if (adapterHasItems) {
                    Log.d(TAG, "onViewCreated: adapter已有${adapter?.getItems()?.size ?: 0}条消息，跳过恢复")
                }
                
                // 如果是人工客服对话，确保欢迎消息存在并置顶
                if (currentConversation?.id == ConversationListFragment.CONVERSATION_ID_CUSTOMER_SERVICE) {
                    // 等待恢复消息完成（最多等待3秒）
                    var waitCount = 0
                    while (isRestoringMessages && waitCount < 30) {
                        delay(100)
                        waitCount++
                    }
                    // 延迟一下确保UI完全准备好
                    delay(200)
                    Log.d(TAG, "onViewCreated: 恢复消息完成，检查是否需要添加欢迎消息")
                    ensureWelcomeMessageAtTop()
                }
            }
        } // 使用post而不是postDelayed，减少延迟，提升响应速度
    }
    
    // 用于跟踪ActionBar和导航栏的状态，避免重复操作
    private var isActionBarHidden = false
    private var isNavigationBarHidden = false
    
    override fun onResume() {
        super.onResume()
        Log.d(TAG, "ChatFragment onResume: isAdded=$isAdded, isHidden=$isHidden, activity=${activity != null}, view=${view != null}")
        
        // 仅当有待处理的权限回调时才自动切回（说明是从系统设置页返回），
        // 普通后台恢复不应自动跳转，否则用户从 Launcher 回来会被强制拉进聊天页。
        val hasPendingPermissionWork = pendingQueryAfterPermission != null
                || pendingQueryAfterAccessibility != null
                || pendingQueryAfterIME != null
        if (isHidden && isAdded && activity != null && hasPendingPermissionWork) {
            Log.w(TAG, "onResume: Fragment被隐藏且有待处理权限回调，切换回ChatFragment")
            val conversation = currentConversation ?: (arguments?.getSerializable("conversation") as? Conversation)
            if (conversation != null) {
                Log.d(TAG, "onResume: 切换回ChatFragment，conversationId=${conversation.id}")
                view?.postDelayed({
                    if (isAdded && activity != null) {
                        (activity as? MainActivity)?.switchToChatFragment(conversation)
                        Log.d(TAG, "onResume: 已切换回ChatFragment")
                    }
                }, 300)
            }
        }
        // 检查Fragment是否还存在
        if (!isAdded || activity == null) {
            Log.w(TAG, "ChatFragment onResume: Fragment未附加或Activity为null，直接返回")
            return
        }
        
        // 只有在Fragment可见且未隐藏时才更新UI（使用hide/show时，onResume可能被调用但Fragment仍被隐藏）
        if (!isHidden) {
            updateActionBarAndNavigation()
        }
        
        // 延迟执行非关键操作，避免阻塞Fragment切换
        view?.post {
            // 刷新"端侧变化检测"开关缓存（确保从服务页面返回后设置立即生效）
            val prefs = requireContext().getSharedPreferences("app_prefs", Context.MODE_PRIVATE)
            sendBeforeActionImageEnabled = prefs.getBoolean("send_before_action_image", false)
            updateActionCompletionDelayCache() // 更新动作完成后延迟时间缓存
            
            // 设置当前对话ID（用于判断是否在人工客服聊天页面）
            val mainActivity = activity as? MainActivity
            currentConversation?.id?.let { conversationId ->
                mainActivity?.setCurrentConversationId(conversationId)
                // 后台期间消息通常只落盘到 prefs；若当前会话存在未读，优先重载，避免前台仍显示旧列表。
                val unreadForConversation = ConversationSessionNotifier.getUnreadCountForList(requireContext(), conversationId)
                if (unreadForConversation > 0) {
                    Log.d(TAG, "onResume: 检测到当前会话未读=$unreadForConversation，触发prefs重载，对话ID: $conversationId")
                    reloadMessagesFromPrefsAfterExternalWrite()
                }
            }
            
            // 进入会话后延迟清未读，避免后台恢复自动进页时“未读一闪而过”
            scheduleClearUnreadForCurrentConversation("onResume")
            // 好友 prefs 重载改在 onHiddenChanged（从隐藏回到可见）触发，勿在每次 onResume 全量恢复，否则与 onViewCreated 首次恢复重复叠行
            
            // 尝试恢复待恢复的技能卡片（技能可能已经加载完成）
            retryPendingSkillMessages()
            
            // 如果是管理员模式，启动定时刷新
            if (currentConversation?.id == ConversationListFragment.CONVERSATION_ID_ADMIN_CUSTOMER_SERVICE) {
                startAdminModeRefresh()
            } else {
                stopAdminModeRefresh()
            }
            
            // 更新"猜你想搜"和"Beta"按钮的可见性（切换对话时也需要更新）
            updateRecommendationsButtonsVisibility()
        }

        // 关键恢复链路必须在真正的 onResume 执行：
        // 无障碍授权返回后，继续走自定义小助手 pending -> 输入法检查/切换流程。
        restorePendingCustomAssistantStateIfNeeded()
        tryResumePendingCustomAssistantExecution("onResume")
        tryResumePendingAccessibilityExecution("onResume")
    }
    
    /**
     * 检查是否是简单聊天对话（人工客服、好友对话或自建群组）
     */
    internal fun isSimpleChatConversation(): Boolean {
        val conversationId = currentConversation?.id
        return conversationId == ConversationListFragment.CONVERSATION_ID_ME ||
               conversationId == ConversationListFragment.CONVERSATION_ID_CUSTOMER_SERVICE ||
               conversationId?.startsWith("friend_") == true ||
               conversationId?.startsWith("group_") == true ||
               conversationId == ConversationListFragment.CONVERSATION_ID_GROUP
    }

    /**
     * 输入框右侧按钮是否使用「表情/键盘」模式。
     * 规则：简单聊天会话 + 内置默认自定义小助手 custom_topoclaw。
     */
    internal fun shouldUseEmojiInputButton(): Boolean {
        val conversationId = currentConversation?.id
        return isSimpleChatConversation() || conversationId == BUILTIN_DEFAULT_CUSTOM_ASSISTANT_ID
    }
    
    /**
     * 检查是否是自定义小助手「聊天优先」模式：任务先走 /chat，只有 need_execution 为 true 时才检查权限并进入执行流程。
     * 此类对话在发送消息时跳过截图、无障碍、startTaskInternal 等执行预检。
     */
    private fun isCustomAssistantChatFirst(): Boolean {
        val conversationId = currentConversation?.id
        if (!CustomAssistantManager.isCustomAssistantId(conversationId)) return false
        val assistant = CustomAssistantManager.getById(requireContext(), conversationId ?: "")
        return assistant != null && assistant.hasChat()
    }

    /**
     * 是否为「仅手机端执行」的自定义小助手（无 chat 能力）。
     * 此类小助手直接走 /upload，需始终带截图（与 startCustomAssistantExecution 一致），
     * 因部分后端（如 UnifiedAssistant）不支持「无截图首包」规划。
     */
    private fun isCustomAssistantExecutionOnly(): Boolean {
        val conversationId = currentConversation?.id ?: return false
        if (!CustomAssistantManager.isCustomAssistantId(conversationId)) return false
        val assistant = CustomAssistantManager.getById(requireContext(), conversationId) ?: return false
        return assistant.hasExecutionMobile() && !assistant.hasChat()
    }

    /**
     * 自定义小助手走端侧 GUI/upload 循环时，完成态已有助手回复或其它 UI，不再插入「任务已完成 ✓」系统气泡。
     */
    private fun shouldSuppressCustomAssistantTaskCompletedCheckmark(): Boolean {
        val cid = currentConversation?.id ?: return false
        return CustomAssistantManager.isCustomAssistantId(cid)
    }

    /**
     * 更新"猜你想搜"和"Beta"按钮的可见性
     */
    internal fun updateRecommendationsButtonsVisibility() {
        if (!isAdded || _binding == null) return
        
        val conversationId = currentConversation?.id
        val isCustomAssistantConversation = CustomAssistantManager.isCustomAssistantId(conversationId)
        val isGroupConversation = conversationId?.startsWith("group_") == true ||
                conversationId == ConversationListFragment.CONVERSATION_ID_GROUP
        if (conversationId == ConversationListFragment.CONVERSATION_ID_ME ||
            conversationId == ConversationListFragment.CONVERSATION_ID_CUSTOMER_SERVICE ||
            conversationId?.startsWith("friend_") == true) {
                // 端云互发、人工客服或好友页面，隐藏所有按钮
            binding.llRecommendationsHeader.visibility = android.view.View.GONE
            binding.tvProButton.visibility = android.view.View.GONE
            binding.btnNewTopic.visibility = android.view.View.GONE
            binding.btnFilterUsers.visibility = android.view.View.GONE
            binding.llRecommendationsPanel.visibility = android.view.View.GONE
            binding.btnCustomAssistantMore.visibility = android.view.View.GONE
        } else if (conversationId == ConversationListFragment.CONVERSATION_ID_ADMIN_CUSTOMER_SERVICE) {
            // 管理员模式下，只显示筛选用户按钮
            binding.llRecommendationsHeader.visibility = android.view.View.GONE
            binding.tvProButton.visibility = android.view.View.GONE
            binding.btnNewTopic.visibility = android.view.View.GONE
            binding.btnFilterUsers.visibility = android.view.View.VISIBLE
            binding.llRecommendationsPanel.visibility = android.view.View.VISIBLE
            binding.btnCustomAssistantMore.visibility = android.view.View.GONE
        } else if (isCustomAssistantConversation || isGroupConversation) {
            // 新需求：自定义小助手和群聊会话隐藏「猜你想做 / Beta / 新话题」
            binding.llRecommendationsHeader.visibility = android.view.View.GONE
            binding.tvProButton.visibility = android.view.View.GONE
            binding.btnNewTopic.visibility = android.view.View.GONE
            binding.btnFilterUsers.visibility = android.view.View.GONE
            // 自定义小助手保留「更多」入口；群聊不显示任何按钮
            binding.btnCustomAssistantMore.visibility = if (isCustomAssistantConversation) {
                android.view.View.VISIBLE
            } else {
                android.view.View.GONE
            }
            binding.llRecommendationsPanel.visibility = if (isCustomAssistantConversation) {
                android.view.View.VISIBLE
            } else {
                android.view.View.GONE
            }
        } else {
            // 其他对话类型，正常显示
            binding.llRecommendationsHeader.visibility = android.view.View.VISIBLE
            binding.tvProButton.visibility = android.view.View.VISIBLE
            binding.btnFilterUsers.visibility = android.view.View.GONE
            
            // 只在TopoClaw、技能执行小助手、聊天小助手时显示"新话题"按钮
            val isAssistantOrSkill = conversationId == ConversationListFragment.CONVERSATION_ID_ASSISTANT ||
                    conversationId == ConversationListFragment.CONVERSATION_ID_SKILL_LEARNING ||
                    conversationId == ConversationListFragment.CONVERSATION_ID_CHAT_ASSISTANT
            binding.btnNewTopic.visibility = if (isAssistantOrSkill) {
                android.view.View.VISIBLE
            } else {
                android.view.View.GONE
            }
            // 自定义小助手专属：显示「更多」按钮，点击弹出侧边栏
            binding.btnCustomAssistantMore.visibility = if (isCustomAssistantConversation) {
                android.view.View.VISIBLE
            } else {
                android.view.View.GONE
            }
            binding.llRecommendationsPanel.visibility = android.view.View.VISIBLE
        }
        
        // 更新输入框右侧按钮图标（简单聊天显示表情，其他显示下拉箭头）
        updateInputButtonIcon()
    }
    
    /**
     * 清空历史记录和对话总结
     */
    internal fun clearHistoryAndSummary() {
        val conversationId = currentConversation?.id ?: return
        
        try {
            val prefs = requireContext().getSharedPreferences("app_prefs", android.content.Context.MODE_PRIVATE)
            
            // 删除历史记录
            val contextKey = "chat_context_$conversationId"
            prefs.edit().remove(contextKey).apply()
            Log.d(TAG, "已删除历史记录: $contextKey")
            
            // 删除对话总结
            val summaryKey = "chat_summary_$conversationId"
            prefs.edit().remove(summaryKey).apply()
            Log.d(TAG, "已删除对话总结: $summaryKey")
        } catch (e: Exception) {
            Log.e(TAG, "清空历史记录和对话总结失败: ${e.message}", e)
        }
    }
    
    /**
     * 新话题提示点击回调（供 NewTopicHintViewHolder 调用）
     */
    internal fun onNewTopicHintClicked() {
        clearHistoryAndSummary()
        chatSummary = null
        updateNewTopicHintVisibility()
        Toast.makeText(requireContext(), "开始新话题", Toast.LENGTH_SHORT).show()
    }
    
    /**
     * 更新输入框右侧按钮图标
     */
    internal fun updateInputButtonIcon() {
        if (!isAdded || _binding == null) return
        
        if (shouldUseEmojiInputButton()) {
            // 简单聊天对话：根据表情面板状态显示不同图标
            if (isEmojiPanelVisible) {
                // 表情面板显示时：显示键盘图标
                binding.btnQueryDropdown.setImageResource(R.drawable.ic_keyboard)
                binding.btnQueryDropdown.contentDescription = "键盘"
            } else {
                // 表情面板隐藏时：显示表情图标
                binding.btnQueryDropdown.setImageResource(R.drawable.ic_emoji)
                binding.btnQueryDropdown.contentDescription = "表情"
            }
        } else {
            // 其他对话类型：显示下拉箭头图标
            binding.btnQueryDropdown.setImageResource(R.drawable.ic_arrow_drop_down)
            binding.btnQueryDropdown.contentDescription = "预设查询"
        }
    }
    
    /**
     * 更新ActionBar和导航栏的显示状态（隐藏）
     */
    private fun updateActionBarAndNavigation() {
        try {
            val mainActivity = activity as? MainActivity ?: return
            
            // 检查ActionBar状态，避免重复操作
            val actionBar = mainActivity.supportActionBar
            if (actionBar != null && actionBar.isShowing && !isActionBarHidden) {
                mainActivity.hideActionBarInstantly()
                isActionBarHidden = true
            }
            
            // 检查导航栏状态，避免重复操作
            if (!isNavigationBarHidden) {
                mainActivity.setBottomNavigationVisibility(false)
                isNavigationBarHidden = true
            }
        } catch (e: Exception) {
            Log.w(TAG, "更新ActionBar和导航栏失败: ${e.message}", e)
        }
    }
    
    /**
     * 优化RecyclerView在Fragment切换时的性能
     * @param isHiding true表示Fragment正在隐藏，false表示Fragment正在显示
     */
    private fun optimizeRecyclerViewForTransition(isHiding: Boolean) {
        ChatUiSetupController.optimizeRecyclerViewForTransition(this, isHiding)
    }
    
    /**
     * 启动管理员模式定时刷新
     */
    private fun startAdminModeRefresh() {
        stopAdminModeRefresh()  // 先停止之前的任务
        
        adminModeRefreshJob = mainScope.launch {
            while (isActive && isAdded) {
                delay(3000)  // 每3秒刷新一次
                if (currentConversation?.id == ConversationListFragment.CONVERSATION_ID_ADMIN_CUSTOMER_SERVICE) {
                    refreshAdminChats()
                }
            }
        }
        Log.d(TAG, "管理员模式定时刷新已启动")
    }
    
    /**
     * 停止管理员模式定时刷新
     */
    private fun stopAdminModeRefresh() {
        adminModeRefreshJob?.cancel()
        adminModeRefreshJob = null
        Log.d(TAG, "管理员模式定时刷新已停止")
    }
    
    /**
     * 刷新管理员聊天记录（增量更新）
     */
    private suspend fun refreshAdminChats() = withContext(Dispatchers.IO) {
        try {
            val prefs = requireContext().getSharedPreferences("app_prefs", android.content.Context.MODE_PRIVATE)
            val conversationId = ConversationListFragment.CONVERSATION_ID_CUSTOMER_SERVICE
            val specificKey = "chat_server_url_$conversationId"
            val customerServiceUrl = prefs.getString(specificKey, null)
                ?: prefs.getString("customer_service_url", null)
                ?: ServiceUrlConfig.DEFAULT_CUSTOMER_SERVICE_URL
            
            CustomerServiceNetwork.initialize(customerServiceUrl)
            val apiService = CustomerServiceNetwork.getApiService() ?: return@withContext
            
            val response = apiService.getAllChats()
            if (response.isSuccessful && response.body()?.success == true) {
                val chats = response.body()?.chats ?: emptyList()
                
                // 检查是否有新消息（通过比较最后一条消息的时间戳）
                var hasNewMessages = false
                var maxTimestamp = lastRefreshTime
                chats.forEach { userChat ->
                    val messages = userChat.messages ?: emptyList()
                    if (messages.isNotEmpty()) {
                        val lastMessageTime = messages.last().timestamp
                        if (lastMessageTime > lastRefreshTime) {
                            hasNewMessages = true
                            maxTimestamp = maxOf(maxTimestamp, lastMessageTime)
                        }
                    }
                }
                
                if (hasNewMessages) {
                    Log.d(TAG, "检测到新消息（上次刷新: $lastRefreshTime），重新加载聊天记录")
                    // 重新加载所有聊天记录（会更新lastRefreshTime）
                    loadAllCustomerServiceChats(forceRefresh = true)
                } else {
                    Log.d(TAG, "无新消息（上次刷新: $lastRefreshTime）")
                }
            }
        } catch (e: Exception) {
            Log.w(TAG, "刷新管理员聊天记录失败: ${e.message}", e)
        }
        
        // 隐藏ActionBar（聊天页面有自己的标题栏）
        // 使用无动画版本，避免向上过渡效果
        try {
            (activity as? MainActivity)?.hideActionBarWithoutAnimation()
        } catch (e: Exception) {
            Log.w(TAG, "隐藏ActionBar失败: ${e.message}", e)
        }
        
        // 隐藏底部导航栏（聊天页面不需要底部导航）
        try {
            (activity as? MainActivity)?.setBottomNavigationVisibility(false)
        } catch (e: Exception) {
            Log.w(TAG, "隐藏底部导航栏失败: ${e.message}", e)
        }
        
        // 每次回到Fragment时重新加载云侧服务地址（可能在其他页面修改了）
        try {
            val serverUrl = getServerUrlForConversation()
            NetworkService.initialize(serverUrl, requireContext())
        } catch (e: Exception) {
            Log.w(TAG, "初始化网络服务失败: ${e.message}", e)
        }
        
        // 重新检查截图权限状态（可能在服务页面已授权）
        try {
            val chatService = ChatScreenshotService.getInstance()
            val isReady = chatService != null && chatService.isReady()
            Log.d(TAG, "onResume: 检查截图权限，服务就绪=$isReady")
        } catch (e: Exception) {
            Log.w(TAG, "检查截图权限失败: ${e.message}", e)
        }
        
        // 重新应用聊天背景（用户可能在设置页面修改了背景）
        applyChatBackground()
        restorePendingCustomAssistantStateIfNeeded()
        
        tryResumePendingCustomAssistantExecution("onResume")
        tryResumePendingAccessibilityExecution("onResume")
        
        // 检查截图权限状态（用户可能从权限请求页面返回）
        try {
            val pendingQuery = pendingQueryAfterPermission
            if (pendingQuery != null) {
                val chatService = ChatScreenshotService.getInstance()
                val isReady = chatService != null && chatService.isReady()
                Log.d(TAG, "onResume: 检查截图权限状态 - pendingQuery=$pendingQuery, isReady=$isReady, isAdded=$isAdded, view=${view != null}")
                if (isReady) {
                    // 截图权限已就绪，自动发送待发送的消息
                    // 注意：不要立即清除pendingQueryAfterPermission，等延迟执行成功后再清除
                    Log.d(TAG, "onResume: 截图权限已就绪，准备自动继续发送消息: $pendingQuery")
                    view?.postDelayed({
                        // 检查Fragment状态，避免在Fragment销毁后执行导致崩溃
                        if (!isAdded || view == null) {
                            Log.w(TAG, "onResume回调：Fragment已销毁，无法自动发送消息，保留pendingQueryAfterPermission以便下次处理")
                            return@postDelayed
                        }
                        
                        // 再次检查pendingQuery（可能在延迟期间被其他逻辑清除）
                        val currentPendingQuery = pendingQueryAfterPermission
                        if (currentPendingQuery == null) {
                            Log.w(TAG, "onResume回调：pendingQueryAfterPermission已被清除，跳过执行")
                            return@postDelayed
                        }
                        
                        // 延迟一下等待服务完全初始化
                        val retryChatService = ChatScreenshotService.getInstance()
                        val retryIsReady = retryChatService != null && retryChatService.isReady()
                        if (retryIsReady) {
                            // 清除pendingQueryAfterPermission（在确认可以执行后再清除）
                            pendingQueryAfterPermission = null
                            // 直接调用executeQueryInternal，它内部会检查无障碍服务状态
                            // 如果无障碍服务未启用，executeQueryInternal会提示用户
                            // 如果已启用但实例未就绪，会在startTaskInternal中等待
                            Log.d(TAG, "onResume: 截图权限已就绪，交由executeQueryInternal处理后续权限检查: $currentPendingQuery")
                            addChatMessage("系统", "正在自动发送消息...")
                            executeQueryInternal(currentPendingQuery)
                        } else {
                            Log.w(TAG, "onResume: 截图服务仍未就绪，请稍后手动发送，保留pendingQueryAfterPermission")
                            addChatMessage("系统", "服务初始化中，请稍后手动发送消息")
                        }
                    }, 500) // 延迟500ms等待服务初始化
                } else {
                    Log.d(TAG, "onResume: 截图权限未就绪，保留pendingQueryAfterPermission，等待权限授权")
                }
            }
        } catch (e: Exception) {
            Log.w(TAG, "检查截图权限状态失败: ${e.message}", e)
        }
        
        // 检查无障碍服务状态（用户可能从设置页面返回）
        try {
            val pendingQuery = pendingQueryAfterAccessibility
            Log.d(TAG, "onResume: 检查无障碍服务状态 - pendingQuery=$pendingQuery")
            if (pendingQuery != null) {
                // 先检查系统权限状态（权限可能已授予但服务未连接）
                val hasPermission = checkAccessibilityServicePermission()
                val serviceConnected = MyAccessibilityService.getInstance() != null
                Log.d(TAG, "onResume: 无障碍服务状态 - 权限已授予=$hasPermission, 服务已连接=$serviceConnected")
                
                if (hasPermission) {
                    // 权限已授予，等待服务连接后自动发送
                    pendingQueryAfterAccessibility = null
                    Log.d(TAG, "onResume: 无障碍服务权限已授予，等待服务连接后自动发送: $pendingQuery")
                    
                    // 如果服务已经连接，立即发送（但需要先检查输入法）
                    if (serviceConnected) {
                        Log.d(TAG, "onResume: 无障碍服务已连接，准备检查输入法后发送消息: $pendingQuery")
                        view?.post {
                            // 检查Fragment状态
                            if (!isAdded || view == null) {
                                Log.w(TAG, "onResume回调（无障碍立即发送）：Fragment已销毁，无法自动发送消息")
                                return@post
                            }
                            addChatMessage("系统", "无障碍服务已启用，正在检查输入法...")
                            // 直接调用，与截图权限授予后的处理方式一致
                            executeQueryInternal(pendingQuery)
                        }
                    } else {
                        // 服务未连接，等待服务连接（最多等待10秒）
                        var retryCount = 0
                        val maxRetries = 20
                        val delayMs = 500L
                        
                        val checkServiceConnection = object : Runnable {
                            override fun run() {
                                // 检查Fragment状态
                                if (!isAdded || view == null) {
                                    Log.w(TAG, "onResume回调（无障碍等待）：Fragment已销毁，停止等待服务连接")
                                    return
                                }
                                
                                val accessibilityService = MyAccessibilityService.getInstance()
                                if (accessibilityService != null) {
                                    // 服务已连接，自动发送（但需要先检查输入法）
                                    Log.d(TAG, "onResume: 无障碍服务已连接，准备检查输入法后发送消息: $pendingQuery")
                                    view?.post {
                                        // 再次检查Fragment状态
                                        if (!isAdded || view == null) {
                                            Log.w(TAG, "onResume回调（无障碍发送）：Fragment已销毁，无法自动发送消息")
                                            return@post
                                        }
                                        addChatMessage("系统", "无障碍服务已启用，正在检查输入法...")
                                        // 直接调用，与截图权限授予后的处理方式一致
                                        executeQueryInternal(pendingQuery)
                                    }
                                } else if (retryCount < maxRetries) {
                                    // 服务未连接，继续等待
                                    retryCount++
                                    Log.d(TAG, "onResume: 等待无障碍服务连接... ($retryCount/$maxRetries)")
                                    view?.postDelayed(this, delayMs)
                                } else {
                                    // 超时，恢复pendingQuery让用户可以手动发送
                                    Log.w(TAG, "onResume: 无障碍服务连接超时，请稍后手动发送")
                                    pendingQueryAfterAccessibility = pendingQuery
                                    view?.post {
                                        // 检查Fragment状态
                                        if (!isAdded || view == null) {
                                            Log.w(TAG, "onResume回调（无障碍超时）：Fragment已销毁，无法显示消息")
                                            return@post
                                        }
                                        addChatMessage("系统", "服务连接超时，请稍后手动发送消息")
                                    }
                                }
                            }
                        }
                        
                        view?.postDelayed(checkServiceConnection, 500) // 延迟500ms开始检查
                    }
                } else {
                    // 权限未授予，但可能是系统状态更新延迟，延迟一下再检查一次
                    Log.d(TAG, "onResume: 无障碍服务权限未授予，延迟500ms后再次检查（可能是系统状态更新延迟）")
                    view?.postDelayed({
                        // 检查Fragment状态
                        if (!isAdded || view == null) {
                            Log.w(TAG, "onResume回调（延迟检查）：Fragment已销毁，无法检查权限状态")
                            return@postDelayed
                        }
                        
                        val retryHasPermission = checkAccessibilityServicePermission()
                        val retryServiceConnected = MyAccessibilityService.getInstance() != null
                        Log.d(TAG, "onResume: 延迟检查无障碍服务状态 - 权限已授予=$retryHasPermission, 服务已连接=$retryServiceConnected")
                        if (retryHasPermission) {
                            // 权限已授予，等待服务连接后自动发送
                            val retryPendingQuery = pendingQueryAfterAccessibility
                            if (retryPendingQuery != null) {
                                pendingQueryAfterAccessibility = null
                                Log.d(TAG, "onResume: 延迟检查发现权限已授予，等待服务连接后自动发送: $retryPendingQuery")
                                
                                if (retryServiceConnected) {
                                    // 服务已连接，立即发送（但需要先检查输入法）
                                    Log.d(TAG, "onResume: 延迟检查发现服务已连接，准备检查输入法后发送消息: $retryPendingQuery")
                                    view?.post {
                                        // 再次检查Fragment状态
                                        if (!isAdded || view == null) {
                                            Log.w(TAG, "onResume回调（延迟检查发送）：Fragment已销毁，无法自动发送消息")
                                            return@post
                                        }
                                        addChatMessage("系统", "无障碍服务已启用，正在检查输入法...")
                                        // 使用协程确保输入法检查完成后再发送
                                        mainScope.launch {
                                            executeQueryInternal(retryPendingQuery)
                                        }
                                    }
                                } else {
                                    // 服务未连接，等待服务连接
                                    var retryCount = 0
                                    val maxRetries = 20
                                    val delayMs = 500L
                                    
                                    val checkServiceConnection = object : Runnable {
                                        override fun run() {
                                            // 检查Fragment状态
                                            if (!isAdded || view == null) {
                                                Log.w(TAG, "onResume回调（延迟检查等待）：Fragment已销毁，停止等待服务连接")
                                                return
                                            }
                                            
                                            val accessibilityService = MyAccessibilityService.getInstance()
                                            if (accessibilityService != null) {
                                                Log.d(TAG, "onResume: 延迟检查后服务已连接，自动继续发送消息: $retryPendingQuery")
                                                view?.post {
                                                    // 再次检查Fragment状态
                                                    if (!isAdded || view == null) {
                                                        Log.w(TAG, "onResume回调（延迟检查发送）：Fragment已销毁，无法自动发送消息")
                                                        return@post
                                                    }
                                                    addChatMessage("系统", "无障碍服务已启用，正在自动发送消息...")
                                                    executeQueryInternal(retryPendingQuery)
                                                }
                                            } else if (retryCount < maxRetries) {
                                                retryCount++
                                                Log.d(TAG, "onResume: 延迟检查后等待无障碍服务连接... ($retryCount/$maxRetries)")
                                                view?.postDelayed(this, delayMs)
                                            } else {
                                                Log.w(TAG, "onResume: 延迟检查后无障碍服务连接超时，请稍后手动发送")
                                                pendingQueryAfterAccessibility = retryPendingQuery
                                                view?.post {
                                                    // 检查Fragment状态
                                                    if (!isAdded || view == null) {
                                                        Log.w(TAG, "onResume回调（延迟检查超时）：Fragment已销毁，无法显示消息")
                                                        return@post
                                                    }
                                                    addChatMessage("系统", "服务连接超时，请稍后手动发送消息")
                                                }
                                            }
                                        }
                                    }
                                    
                                    view?.postDelayed(checkServiceConnection, 500)
                                }
                            }
                        } else {
                            // 权限确实未授予，保持pendingQuery不变
                            Log.d(TAG, "onResume: 延迟检查确认无障碍服务权限未授予，等待用户授权")
                        }
                    }, 500)
                }
            } else {
                Log.d(TAG, "onResume: 无障碍服务 - 无待发送的消息")
            }
        } catch (e: Exception) {
            Log.w(TAG, "检查无障碍服务状态失败: ${e.message}", e)
        }
        
        // 检查输入法状态（用户可能从设置页面返回）
        try {
            val pendingQuery = pendingQueryAfterIME
            val pendingImage = pendingImageAfterIME
            if (pendingQuery != null) {
                val accessibilityService = MyAccessibilityService.getInstance()
                if (accessibilityService != null) {
                    val customIMEId = "${requireContext().packageName}/${SimpleInputMethodService::class.java.name}"
                    val isIMEEnabled = checkIfIMEEnabled(requireContext(), customIMEId)
                    
                    if (isIMEEnabled) {
                        // 检查输入法是否已经是默认输入法（双重验证）
                        val imeService = SimpleInputMethodService.getInstance()
                        val isServiceActive = imeService != null
                        val currentIME = accessibilityService.getCurrentIME()
                        val normalizedCurrentIME = currentIME?.trim()?.lowercase()
                        val normalizedCustomIMEId = customIMEId.trim().lowercase()
                        val isIMEIdMatch = normalizedCurrentIME == normalizedCustomIMEId
                        val isCustomIMEActive = isServiceActive || isIMEIdMatch
                        
                        Log.d(TAG, "onResume: 检查输入法状态")
                        Log.d(TAG, "  - 输入法已启用: $isIMEEnabled")
                        Log.d(TAG, "  - 输入法服务激活: $isServiceActive")
                        Log.d(TAG, "  - 输入法ID匹配: $isIMEIdMatch")
                        Log.d(TAG, "  - 是默认输入法: $isCustomIMEActive")
                        
                        // 只有当输入法已启用且是默认输入法时，才自动发送消息
                        if (isCustomIMEActive) {
                            // 输入法已是默认输入法，恢复图片并自动发送待发送的消息
                            pendingQueryAfterIME = null
                            selectedImageBase64 = pendingImageAfterIME
                            pendingImageAfterIME = null
                            
                            Log.d(TAG, "onResume: 输入法已是默认输入法，自动继续发送消息: $pendingQuery")
                            view?.post {
                                addChatMessage("系统", "输入法已切换为默认输入法，正在自动发送消息...")
                                executeQueryInternal(pendingQuery)
                            } // 使用post而不是postDelayed，减少延迟，提升响应速度
                        } else {
                            // 输入法已启用但不是默认输入法，需要走切换输入法的流程
                            Log.d(TAG, "onResume: 输入法已启用但不是默认输入法，重新走切换输入法流程")
                            view?.post {
                                // 恢复图片，然后重新执行任务（会走切换输入法的流程）
                                selectedImageBase64 = pendingImageAfterIME
                                executeQueryInternal(pendingQuery)
                            } // 使用post而不是postDelayed，减少延迟，提升响应速度
                        }
                    }
                }
            }
        } catch (e: Exception) {
            Log.w(TAG, "检查输入法状态失败: ${e.message}", e)
        }
        
        // 自定义小助手 / gui_execute：等待 TopoClaw 输入法（与 pendingQueryAfterIME 并行）
        try {
            val pendingCustomIme = pendingCustomAssistantAfterIME
            if (pendingCustomIme != null) {
                val accessibilityService = MyAccessibilityService.getInstance()
                if (accessibilityService != null) {
                    val customIMEId = "${requireContext().packageName}/${SimpleInputMethodService::class.java.name}"
                    val isIMEEnabled = checkIfIMEEnabled(requireContext(), customIMEId)
                    if (isIMEEnabled) {
                        val imeService = SimpleInputMethodService.getInstance()
                        val isServiceActive = imeService != null
                        val currentIME = accessibilityService.getCurrentIME()
                        val normalizedCurrentIME = currentIME?.trim()?.lowercase()
                        val normalizedCustomIMEId = customIMEId.trim().lowercase()
                        val isIMEIdMatch = normalizedCurrentIME == normalizedCustomIMEId
                        val isCustomIMEActive = isServiceActive || isIMEIdMatch
                        Log.d(TAG, "onResume: 自定义小助手输入法检查 - 已启用=$isIMEEnabled, 已为TopoClaw=$isCustomIMEActive")
                        if (isCustomIMEActive) {
                            pendingCustomAssistantAfterIME = null
                            view?.post {
                                pendingCustomIme.guiExecuteContext?.let { assistantGuiExecuteContext = it }
                                addChatMessage("系统", "输入法已就绪，继续执行…")
                                startCustomAssistantExecution(
                                    pendingCustomIme.assistant,
                                    pendingCustomIme.query,
                                    pendingCustomIme.chatSummary
                                )
                            }
                        } else {
                            view?.post {
                                mainScope.launch {
                                    ensureCustomIMEForCustomAssistantExecution(
                                        pendingCustomIme.assistant,
                                        pendingCustomIme.query,
                                        pendingCustomIme.chatSummary,
                                        pendingCustomIme.guiExecuteContext
                                    )
                                }
                            }
                        }
                    }
                }
            }
        } catch (e: Exception) {
            Log.w(TAG, "检查自定义小助手输入法状态失败: ${e.message}", e)
        }
        
        // 如果聊天记录为空，尝试恢复（可能是在回退时Fragment被重新创建）
        // 但是，如果是从悬浮球录制触发的，不要恢复聊天记录（避免触发TopoClaw）
        // 同时检查是否正在恢复，避免重复加载
        // 注意：onViewCreated中已经调用了restoreChatMessages，这里不应该再次调用
        // 只有在onViewCreated未执行恢复的情况下才恢复（比如Fragment被重新创建）
        val fromOverlayRecording = arguments?.getBoolean("fromOverlayRecording", false) ?: false
        val vm = try { getViewModel() } catch (_: Exception) { null }
        val vmHasData = vm != null && vm.getMessages().isNotEmpty()
        val vmIsLoading = vm?.isRestoringMessages?.value == true
        if (chatMessages.isEmpty() && currentConversation != null && !fromOverlayRecording && !isRestoringMessages
            && !vmHasData && !vmIsLoading) {
            val adapter = chatAdapter
            if (adapter == null || adapter.getItems().isEmpty()) {
                Log.d(TAG, "onResume: 检测到聊天记录为空且adapter也为空，ViewModel也为空，开始恢复")
                mainScope.launch {
                    restoreChatMessages()
                }
            } else {
                Log.d(TAG, "onResume: adapter中已有${adapter.getItems().size}条消息，跳过恢复（避免重复）")
            }
        }
        
        // 无论当前对话是什么，都设置WebSocket消息回调
        // 因为好友消息需要全局接收（无论用户在哪个页面）
        val conversationId = currentConversation?.id
        val mainActivity = activity as? MainActivity
        val webSocket = mainActivity?.getCustomerServiceWebSocket()
        
        // 如果WebSocket实例存在，立即设置回调（即使连接还在建立中）
        // 这样一旦连接建立并收到消息，回调就已经准备好了
        if (webSocket != null) {
            Log.d(TAG, "onResume: WebSocket实例存在，立即设置消息回调（连接状态: ${webSocket.isConnected()}，当前对话: $conversationId）")
            setupCustomerServiceMessageCallback(webSocket)
            
            // 如果未连接，主动尝试重连
            if (!webSocket.isConnected()) {
                Log.d(TAG, "onResume: WebSocket未连接，主动尝试重连")
                mainScope.launch {
                    ensureCustomerServiceWebSocketConnected()
                }
            }
        } else {
            // WebSocket实例不存在，需要创建并连接
            Log.d(TAG, "onResume: WebSocket实例不存在，创建并连接")
            mainScope.launch {
                ensureCustomerServiceWebSocketConnected()
            }
        }
        
        // 如果是人工客服对话或好友对话，加载待处理消息
        if (conversationId == ConversationListFragment.CONVERSATION_ID_CUSTOMER_SERVICE ||
            conversationId?.startsWith("friend_") == true) {
            // 延迟加载待处理消息，确保恢复消息完成后再加载
            // 这样可以避免恢复消息时清空待处理消息
            mainScope.launch {
                // 等待恢复消息完成（最多等待3秒）
                var waitCount = 0
                while (isRestoringMessages && waitCount < 30) {
                    delay(100)
                    waitCount++
                }
                Log.d(TAG, "恢复消息完成或超时，开始加载待处理消息")
                loadPendingCustomerServiceMessages()
                
                // 确保欢迎消息存在并置顶
                ensureWelcomeMessageAtTop()
            }
        }
    }
    
    /**
     * 加载待处理的人工客服消息（不在聊天页面时收到的消息）
     * 注意：待处理消息已经在恢复消息时合并到恢复列表中，这里只需要清除待处理消息和未读计数
     */
    private fun loadPendingCustomerServiceMessages() {
        val ctx = context ?: return
        Log.d(TAG, "========== 开始检查待处理消息 ==========")
        val hasPending = CustomerServiceUnreadManager.hasPendingMessages(ctx)
        Log.d(TAG, "是否有待处理消息: $hasPending")
        
        if (hasPending) {
            // 待处理消息已经在恢复消息时合并到恢复列表中，这里只需要清除
            // 但是，如果恢复消息还没有完成，或者恢复失败，仍然需要加载待处理消息
            if (isRestoringMessages) {
                Log.d(TAG, "恢复消息正在进行中，待处理消息已在恢复时合并，只清除待处理消息")
                // 清除待处理消息（不添加，因为已经在恢复时合并了）
                CustomerServiceUnreadManager.getAndClearPendingMessages(ctx)
            } else {
                // 恢复消息已完成或未执行，需要加载待处理消息
                val pendingMessages = CustomerServiceUnreadManager.getAndClearPendingMessages(ctx)
                Log.d(TAG, "加载 ${pendingMessages.size} 条待处理的人工客服消息")
                
                pendingMessages.forEachIndexed { index, (sender, content, timestamp) ->
                    Log.d(TAG, "待处理消息[$index]: sender=$sender, content=${content.take(50)}, timestamp=$timestamp")
                    
                    // 过滤掉欢迎消息（欢迎消息由ensureWelcomeMessageAtTop()管理，置顶显示）
                    if (sender == "人工客服" && 
                        content.contains("我是人工客服") && 
                        (content.contains("使用说明") || content.contains("清除数据"))) {
                        Log.d(TAG, "过滤掉待处理消息中的欢迎消息（由置顶逻辑管理）: ${content.take(50)}")
                        return@forEachIndexed
                    }
                    
                    // 检查消息是否已存在（去重）
                    val messageHash = messageHashForDedup(ChatMessage(sender, content, "system", timestamp, ""))
                    if (!messageHashSet.contains(messageHash)) {
                        addChatMessage(sender, content, skipSystemMessageContainer = true)
                    } else {
                        Log.d(TAG, "待处理消息已存在，跳过: ${content.take(50)}")
                    }
                }
            }
            
            // 清除未读计数
            val unreadCount = CustomerServiceUnreadManager.getUnreadCount(ctx)
            Log.d(TAG, "清除未读计数，当前未读数: $unreadCount")
            CustomerServiceUnreadManager.clearUnreadCount(ctx)
            updateUnreadBadge()
            Log.d(TAG, "待处理消息处理完成")
        } else {
            Log.d(TAG, "没有待处理消息")
        }
        Log.d(TAG, "========== 待处理消息检查完成 ==========")
    }
    
    /**
     * 判断回复是否复述了任务内容
     * 如果回复中包含原始查询的关键内容，认为是复述
     */
    private fun isRepeatingTask(replyText: String?, originalQuery: String): Boolean {
        if (replyText.isNullOrBlank() || originalQuery.isBlank()) {
            return false
        }
        
        // 移除@小助手等标记，提取实际任务内容
        val cleanQuery = ChatConstants.stripMainAssistantMentions(originalQuery)
            .replace("@小助手", "", ignoreCase = true)
            .replace("@assistant", "", ignoreCase = true)
            .replace("@自动执行助手", "", ignoreCase = true)
            .trim()
        
        if (cleanQuery.isBlank()) {
            return false
        }
        
        val replyLower = replyText.lowercase()
        val queryLower = cleanQuery.lowercase()
        
        // 检查1: 回复明显是复述格式（如"好的，我来帮您..."、"我已经帮你..."等）
        val isRepeatingFormat = (replyLower.contains("好的") || replyLower.contains("已经") || replyLower.contains("正在")) && 
                               (replyLower.contains("帮您") || replyLower.contains("为您") || 
                                replyLower.contains("我来") || replyLower.contains("开始") ||
                                replyLower.contains("帮你") || replyLower.contains("为您"))
        
        if (isRepeatingFormat) {
            Log.d(TAG, "检测到复述格式: $replyText")
            return true
        }
        
        // 检查2: 回复开头包含任务内容（如"我已经帮你打开了小红书"）
        // 检查回复的前50%是否包含查询的主要内容
        val replyPrefix = replyLower.take(replyLower.length / 2)
        if (replyPrefix.contains(queryLower) || queryLower.contains(replyPrefix.take(10))) {
            Log.d(TAG, "检测到回复开头包含任务内容: $replyText")
            return true
        }
        
        // 检查3: 提取查询中的关键词（长度>=2的词），检查回复中是否包含多个关键词
        val queryWords = cleanQuery.split(Regex("[\\s，。、；：！？,.;:!?]"))
            .filter { it.length >= 2 && !it.matches(Regex("^[的了吗呢啊吧]+$")) } // 过滤掉语气词
            .map { it.lowercase() }
            .distinct()
        
        if (queryWords.isEmpty()) {
            return false
        }
        
        // 检查回复中是否包含查询中的多个关键词（至少2个，或者如果查询很短则至少1个）
        val matchedWords = queryWords.count { word ->
            replyLower.contains(word)
        }
        
        val minMatchedWords = if (queryWords.size <= 2) 1 else 2
        
        if (matchedWords >= minMatchedWords) {
            Log.d(TAG, "检测到回复包含${matchedWords}个任务关键词: $replyText, 查询: $cleanQuery")
            return true
        }
        
        return false
    }
    
    /**
     * 处理@TopoClaw的群组消息
     * 直接调用TopoClaw的/upload接口，不经过customer服务
     */
    private suspend fun handleAssistantGroupMessage(groupId: String, query: String) {
        try {
            Log.d(TAG, "开始处理@TopoClaw的群组消息: groupId=$groupId, query=$query")
            
            // 获取TopoClaw服务地址（严格参考TopoClaw主页的获取方式）
            val prefs = requireContext().getSharedPreferences("app_prefs", android.content.Context.MODE_PRIVATE)
            val conversationId = ConversationListFragment.CONVERSATION_ID_ASSISTANT
            
            // 优先使用TopoClaw的专用地址配置
            val specificKey = "chat_server_url_$conversationId"
            val specificUrl = prefs.getString(specificKey, null)
            
            // 如果没有专用配置，使用全局默认地址（与getServerUrlForConversation逻辑一致）
            val agentUrl = if (specificUrl != null) {
                specificUrl
            } else {
                prefs.getString("chat_server_url", ChatConstants.DEFAULT_CHAT_SERVER_URL) ?: ChatConstants.DEFAULT_CHAT_SERVER_URL
            }
            
            Log.d(TAG, "使用TopoClaw服务地址: $agentUrl (专用配置: ${specificUrl != null})")
            
            // 确保URL以/结尾
            val baseUrl = if (agentUrl.endsWith("/")) agentUrl else "$agentUrl/"
            
            // 初始化NetworkService（如果尚未初始化）
            if (!NetworkService.isInitialized() || NetworkService.getCurrentBaseUrl() != baseUrl) {
                NetworkService.initialize(baseUrl, requireContext())
            }
            
            val apiService = NetworkService.getApiService()
            if (apiService == null) {
                Log.e(TAG, "无法获取API服务实例")
                withContext(Dispatchers.Main) {
                    addChatMessage("系统", "无法连接到${ChatConstants.ASSISTANT_DISPLAY_NAME}服务")
                }
                return
            }
            
            // 生成UUID
            val chatUuid = java.util.UUID.randomUUID().toString()
            
            // 群组消息不使用截图，使用空字符串（与TopoClaw主页第一次发送时一致）
            // 参考TopoClaw主页的处理：第一次发送时使用空字符串，让云侧决定是否需要截图
            val emptyImage = ""
            
            // 获取当前用户IMEI
            val imei = ProfileManager.getOrGenerateImei(requireContext())
            
            // 获取当前Activity信息
            val (packageName, className) = MyAccessibilityService.getCurrentActivityInfo()
            
            // 调用TopoClaw接口（upload 或 next_action）
            val apiPath = if (useNextActionApi()) "next_action" else "upload"
            Log.d(TAG, "调用TopoClaw服务: $baseUrl$apiPath, query: $query, uuid: $chatUuid")
            val response = try {
                if (useNextActionApi()) {
                    // next_action 开启时不传递 activity 信息
                    val req = NextActionRequest(
                        task_id = chatUuid,
                        duid = imei,
                        image_url = NextActionPayloadHelper.imageUrlFromRawBase64(emptyImage),  // 群组消息无截图，用占位图
                        query = query,
                        user_response = null,
                        install_apps = getInstallAppsListForNextAction()
                    )
                    apiService.sendNextActionRequest(req)
                } else {
                    apiService.sendChatMessage(
                        uuid = chatUuid,
                        query = query,
                        image = emptyImage,
                        image2 = null,
                        userResponse = null,
                        userExample = null,
                        chatSummary = null,
                        packageName = packageName,
                        className = className,
                        imei = imei,
                        outputLanguage = LanguageManager.getSavedLanguage(requireContext()),
                        installApps = getInstallAppsParamForUpload()
                    )
                }
            } catch (e: Exception) {
                Log.e(TAG, "调用TopoClaw服务异常: ${e.message}", e)
                withContext(Dispatchers.Main) {
                    addChatMessage("系统", "调用${ChatConstants.ASSISTANT_DISPLAY_NAME}服务失败: ${e.message}")
                }
                return
            }
            
            if (response.isSuccessful) {
                val chatResponse = if (useNextActionApi()) {
                    (response.body() as? NextActionResponse)?.toChatResponse()
                } else {
                    response.body() as? ChatResponse
                }
                if (chatResponse != null) {
                    // 提取回复文本（严格参考TopoClaw的解析方式）
                    val actionType = chatResponse.action_type?.lowercase()
                    val replyText = when {
                        // answer动作：优先使用params或text字段
                        actionType == "answer" -> {
                            chatResponse.params ?: chatResponse.text ?: chatResponse.message
                        }
                        // complete动作：使用getCompleteDisplayText（next_action 开关打开时会解析 arguments 作为最终回答）
                        actionType == "complete" -> {
                            ChatResponseDisplayHelper.getCompleteDisplayText(
                                chatResponse,
                                useNextActionApi(),
                                isMaxStepTriggered = ChatResponseDisplayHelper.isMaxStepTriggeredReason(chatResponse.reason)
                            )
                        }
                        // call_user动作：不显示message（由call_user处理逻辑统一处理）
                        actionType == "call_user" -> {
                            null  // call_user动作不在这里发送回复
                        }
                        // 其他情况：优先使用message字段，如果没有则使用reason或thought
                        else -> {
                            chatResponse.message ?: chatResponse.reason ?: chatResponse.thought
                        }
                    } ?: when {
                        // 如果所有字段都为空，根据action_type生成默认回复
                        actionType == "complete" -> "任务已完成"
                        actionType != null -> "已处理您的请求（动作类型: $actionType）"
                        else -> "已收到您的消息，正在处理中..."
                    }
                    
                    // 如果是call_user动作，不发送回复（由call_user处理逻辑统一处理）
                    if (actionType == "call_user") {
                        Log.d(TAG, "收到call_user动作，不在此处发送回复")
                        return
                    }
                    
                    Log.d(TAG, "TopoClaw处理成功，action_type: $actionType, 回复: $replyText")
                    
                    // 通过customer服务的API接口发送结果回群组
                    // 注意：这里没有群组上下文，所以不添加@IMEI前缀
                    // 传递actionType，用于接收消息时判断显示方式
                    sendAssistantReplyToGroup(groupId, replyText, imei, null, actionType)
                } else {
                    Log.w(TAG, "TopoClaw响应体为null")
                    withContext(Dispatchers.Main) {
                        addChatMessage("系统", "${ChatConstants.ASSISTANT_DISPLAY_NAME}返回空响应")
                    }
                }
            } else {
                val errorBody = response.errorBody()?.string()
                Log.e(TAG, "TopoClaw请求失败: ${response.code()} - ${response.message()}")
                Log.e(TAG, "错误响应体: $errorBody")
                Log.e(TAG, "请求参数 - uuid: $chatUuid, query: $query, imei: $imei")
                withContext(Dispatchers.Main) {
                    val errorMsg = if (errorBody != null && errorBody.isNotBlank()) {
                        "${ChatConstants.ASSISTANT_DISPLAY_NAME}处理失败: ${response.code()}\n错误详情: ${errorBody.take(200)}"
                    } else {
                        "${ChatConstants.ASSISTANT_DISPLAY_NAME}处理失败: ${response.code()} - ${response.message()}"
                    }
                    addChatMessage("系统", errorMsg)
                }
            }
        } catch (e: Exception) {
            Log.e(TAG, "处理@TopoClaw群组消息异常: ${e.message}", e)
            withContext(Dispatchers.Main) {
                addChatMessage("系统", "处理失败: ${e.message}")
            }
        }
    }
    
    /**
     * 发送回复消息到群组（以小助手或系统身份）
     * @param actionType 动作类型（用于判断显示方式和发送者身份：answer=小助手身份，其他=系统消息身份）
     * @param senderName 自定义发送者名称，用于群组管理小助手等场景；为 null 时使用默认（answer=TopoClaw，其他=系统）
     * @param skipDedupRecord 为 true 时不记录去重（用于群组@场景：本端未先 addChatMessage，需通过收到广播来显示）
     */
    private suspend fun sendAssistantReplyToGroup(groupId: String, content: String, imei: String, senderImei: String? = null, actionType: String? = null, senderName: String? = null, skipDedupRecord: Boolean = false) {
        // 记录动作类型到临时Map（用于接收消息时判断显示方式）
        // 即使assistantGroupContext被清空，也能通过groupId找到对应的actionType
        if (actionType != null) {
            groupActionTypeMap[groupId] = actionType
            Log.d(TAG, "记录动作类型到临时Map: groupId=$groupId, actionType=$actionType")
        }
        try {
            // 根据actionType决定发送者身份：answer动作使用小助手身份，其他中间动作使用系统消息身份；senderName 优先
            val sender = senderName ?: when {
                actionType?.lowercase() == "answer" -> ChatConstants.ASSISTANT_DISPLAY_NAME
                else -> "系统"
            }
            
            // 构建最终消息内容
            // 对于answer动作，如果有senderImei，添加"@用户名："前缀，表示这是回复给发起任务的用户
            // 优先使用昵称（当前用户用ProfileManager，其他用户用FriendManager），无昵称时回退到IMEI
            val finalContent = buildString {
                if ((sender != "系统") && senderImei != null && senderImei.isNotBlank()) {
                    val currentImei = ProfileManager.getOrGenerateImei(requireContext())
                    val displayNameForMention = if (senderImei == currentImei) {
                        // 本端用户：优先使用个人资料中的昵称
                        getCurrentUserDisplayName()
                    } else {
                        // 其他用户：优先从好友列表获取昵称
                        val friend = FriendManager.getFriend(requireContext(), senderImei)
                        friend?.nickname ?: senderImei.take(8) + "..."
                    }
                    append("@$displayNameForMention：")
                }
                append(content)
            }
            Log.d(TAG, "发送消息到群组: groupId=$groupId, sender=$sender, content=$finalContent, senderImei=$senderImei, actionType=$actionType, skipDedupRecord=$skipDedupRecord")
            
            // 本端已本地添加此消息时记录去重；群组@场景下本端未先添加，需通过广播显示，故不记录
            if (!skipDedupRecord) {
                val dedupKey = "${groupId}\u0001$finalContent"
                recentlySentAssistantToGroup[dedupKey] = System.currentTimeMillis()
                pruneRecentlySentAssistantToGroup()
            }
            
            // 获取customer服务地址
            val prefs = requireContext().getSharedPreferences("app_prefs", android.content.Context.MODE_PRIVATE)
            val conversationId = ConversationListFragment.CONVERSATION_ID_CUSTOMER_SERVICE
            val specificKey = "chat_server_url_$conversationId"
            val specificUrl = prefs.getString(specificKey, null)
            val customerServiceUrl = specificUrl ?: prefs.getString("customer_service_url", ServiceUrlConfig.DEFAULT_CUSTOMER_SERVICE_URL)
            
            if (customerServiceUrl == null) {
                Log.e(TAG, "Customer服务地址未配置")
                return
            }
            
            // 确保URL以/结尾
            val baseUrl = if (customerServiceUrl.endsWith("/")) customerServiceUrl else "$customerServiceUrl/"
            
            // 初始化CustomerServiceNetwork（如果尚未初始化）
            CustomerServiceNetwork.initialize(baseUrl)
            
            val apiService = CustomerServiceNetwork.getApiService()
            if (apiService == null) {
                Log.e(TAG, "无法获取CustomerService API服务实例")
                return
            }
            
            // 调用API发送消息（根据sender参数决定是小助手消息还是系统消息）
            Log.d(TAG, "调用API发送消息到群组 - groupId: $groupId, sender: $sender, content: $content, imei: $imei")
            Log.d(TAG, "API Base URL: $baseUrl")
            Log.d(TAG, "完整请求URL应该是: ${baseUrl}api/groups/send-assistant-message")
            val response = apiService.sendAssistantGroupMessage(
                SendAssistantGroupMessageRequest(
                    groupId = groupId,
                    content = finalContent,
                    imei = imei,
                    sender = sender
                )
            )
            
            Log.d(TAG, "API响应 - isSuccessful: ${response.isSuccessful}, code: ${response.code()}, message: ${response.message()}")
            if (response.isSuccessful) {
                val responseBody = response.body()
                Log.d(TAG, "${if (sender == "系统") "系统消息" else "小助手回复"}已发送到群组，响应体: $responseBody")
            } else {
                val errorBody = response.errorBody()?.string()
                Log.e(TAG, "发送${if (sender == "系统") "系统消息" else "小助手回复"}失败: ${response.code()} - ${response.message()}, errorBody: $errorBody")
                // 打印请求详情以便调试
                Log.e(TAG, "请求详情 - Base URL: $baseUrl, 路径: api/groups/send-assistant-message")
                Log.e(TAG, "完整请求URL: ${baseUrl}api/groups/send-assistant-message")
                Log.e(TAG, "请求方法: POST")
                Log.e(TAG, "请求体: groupId=$groupId, sender=$sender, content=$content, imei=$imei")
                
                // 405错误通常表示路由不匹配
                if (response.code() == 405) {
                    Log.e(TAG, "收到405错误，可能是路由路径不匹配。请检查:")
                    Log.e(TAG, "1. customer_service服务是否正在运行")
                    Log.e(TAG, "2. 服务端路由定义: POST /api/groups/send-assistant-message")
                    Log.e(TAG, "3. 若使用默认 customer_service 根路径，完整路径示例: ${ServiceUrlConfig.DEFAULT_CUSTOMER_SERVICE_URL}api/groups/send-assistant-message")
                    Log.e(TAG, "4. 检查服务端日志，看是否收到请求")
                    
                    // 尝试使用WebSocket作为备选方案（但这需要以ASSISTANT_BOT_ID身份发送，可能需要服务端支持）
                    Log.w(TAG, "HTTP API失败，无法通过WebSocket发送小助手回复（需要ASSISTANT_BOT_ID身份）")
                }
            }
        } catch (e: Exception) {
            Log.e(TAG, "发送消息到群组异常: ${e.message}", e)
        }
    }
    
    /**
     * 清理过期的 recentlySentAssistantToGroup 记录
     */
    private fun pruneRecentlySentAssistantToGroup() {
        val now = System.currentTimeMillis()
        val toRemove = recentlySentAssistantToGroup.filter { (_, ts) -> now - ts > RECENTLY_SENT_EXPIRE_MS }.keys
        toRemove.forEach { recentlySentAssistantToGroup.remove(it) }
        if (toRemove.isNotEmpty()) Log.d(TAG, "清理过期去重记录: ${toRemove.size} 条")
    }
    
    /**
     * 检查并标记：是否应跳过收到的群组小助手消息（本端已本地添加并发送，收到广播时去重）
     * @return true 表示应跳过，已从记录中移除
     */
    internal fun shouldSkipReceivedAssistantMessage(groupId: String, content: String): Boolean {
        val key = "${groupId}\u0001$content"
        val removed = recentlySentAssistantToGroup.remove(key)
        if (removed != null) Log.d(TAG, "去重：跳过本端已发送的小助手消息广播 groupId=$groupId")
        return removed != null
    }

    private fun pruneRecentlySentOwnGroupMessages() {
        val now = System.currentTimeMillis()
        val expiredIds = recentlySentOwnGroupMessageIds
            .filterValues { now - it > RECENTLY_SENT_OWN_GROUP_MESSAGE_EXPIRE_MS }
            .keys
        expiredIds.forEach { recentlySentOwnGroupMessageIds.remove(it) }

        val expiredKeys = recentlySentOwnGroupMessageKeys
            .filterValues { now - it > RECENTLY_SENT_OWN_GROUP_MESSAGE_EXPIRE_MS }
            .keys
        expiredKeys.forEach { recentlySentOwnGroupMessageKeys.remove(it) }
    }

    private fun buildOwnGroupMessageDedupKey(groupId: String, content: String, messageType: String): String {
        return "${groupId}\u0001${messageType}\u0001$content"
    }

    private fun pruneRecentlyReceivedGroupMessages() {
        val now = System.currentTimeMillis()
        val expiredIds = recentlyReceivedGroupMessageIds
            .filterValues { now - it > RECENTLY_RECEIVED_GROUP_MESSAGE_EXPIRE_MS }
            .keys
        expiredIds.forEach { recentlyReceivedGroupMessageIds.remove(it) }

        val expiredKeys = recentlyReceivedGroupMessageKeys
            .filterValues { now - it > RECENTLY_RECEIVED_GROUP_MESSAGE_EXPIRE_MS }
            .keys
        expiredKeys.forEach { recentlyReceivedGroupMessageKeys.remove(it) }
    }

    private fun buildInboundGroupMessageDedupKey(
        groupId: String,
        senderImei: String,
        content: String,
        messageType: String,
        timestamp: Long
    ): String {
        val senderKey = senderImei.ifBlank { "unknown" }
        return "${groupId}\u0001${senderKey}\u0001${messageType}\u0001${timestamp}\u0001${content.hashCode()}"
    }

    private fun shouldSkipInboundGroupMessage(
        groupId: String,
        senderImei: String,
        content: String,
        messageType: String,
        messageId: String?,
        timestamp: Long
    ): Boolean {
        pruneRecentlyReceivedGroupMessages()
        val now = System.currentTimeMillis()

        if (!messageId.isNullOrBlank()) {
            if (recentlyReceivedGroupMessageIds.containsKey(messageId)) {
                Log.d(TAG, "去重：重复群组广播 message_id=$messageId，跳过显示")
                return true
            }
            recentlyReceivedGroupMessageIds[messageId] = now
            return false
        }

        val key = buildInboundGroupMessageDedupKey(groupId, senderImei, content, messageType, timestamp)
        if (recentlyReceivedGroupMessageKeys.containsKey(key)) {
            Log.d(TAG, "去重：重复群组广播（兜底键）groupId=$groupId，跳过显示")
            return true
        }
        recentlyReceivedGroupMessageKeys[key] = now
        return false
    }

    internal fun buildGroupConversationIds(groupId: String): LinkedHashSet<String> {
        val trimmed = groupId.trim()
        val ids = linkedSetOf<String>()
        if (trimmed.isBlank()) return ids
        if (trimmed.startsWith("group_")) {
            ids.add(trimmed)
            ids.add("group_$trimmed")
        } else {
            ids.add("group_$trimmed")
        }
        return ids
    }

    internal fun markOwnGroupMessageSent(
        groupId: String,
        content: String,
        messageType: String,
        messageId: String?
    ) {
        val now = System.currentTimeMillis()
        if (!messageId.isNullOrBlank()) {
            recentlySentOwnGroupMessageIds[messageId] = now
        }
        val dedupKey = buildOwnGroupMessageDedupKey(groupId, content, messageType)
        recentlySentOwnGroupMessageKeys[dedupKey] = now
        pruneRecentlySentOwnGroupMessages()
    }

    internal fun shouldSkipOwnGroupEchoMessage(
        groupId: String,
        content: String,
        messageType: String,
        messageId: String?,
        senderOrigin: String?
    ): Boolean {
        // 服务器透传 sender_origin 时，优先按来源判断，避免跨端消息被误判
        if (senderOrigin.equals("mobile", ignoreCase = true)) {
            Log.d(TAG, "去重：检测到本机来源回声(sender_origin=mobile)，跳过显示")
            return true
        }

        if (!messageId.isNullOrBlank()) {
            val removed = recentlySentOwnGroupMessageIds.remove(messageId)
            if (removed != null) {
                Log.d(TAG, "去重：命中本机已发送message_id=$messageId，跳过显示")
                pruneRecentlySentOwnGroupMessages()
                return true
            }
        }

        val dedupKey = buildOwnGroupMessageDedupKey(groupId, content, messageType)
        val removedByKey = recentlySentOwnGroupMessageKeys.remove(dedupKey)
        if (removedByKey != null) {
            Log.d(TAG, "去重：命中文本兜底键，跳过本机回声 groupId=$groupId")
            pruneRecentlySentOwnGroupMessages()
            return true
        }

        pruneRecentlySentOwnGroupMessages()
        return false
    }
    
    /**
     * 群组管理小助手反馈流程：子助手执行完成后，调用群组管理者总结或继续调度（与 PC 侧逻辑一致）
     * @param groupId 群组 ID
     * @param executedAssistantName 刚执行完成的小助手名称
     * @param executedCommand 执行的指令
     * @param result 执行结果
     */
    private suspend fun doGroupManagerFeedbackFlow(
        groupId: String,
        executedAssistantName: String,
        executedCommand: String,
        result: String
    ) {
        val feedbackCtx = groupManagerFeedbackContext ?: return
        val gm = feedbackCtx.groupManagerAssistant
        val round = feedbackCtx.round
        val originalGroupConv = assistantGroupContext?.originalConversation
        if (round > CustomAssistantManager.MAX_GROUP_MANAGER_FOLLOW_UP_ROUNDS) {
            Log.d(TAG, "群组管理反馈已达最大轮次($round)，不再调度")
            withContext(Dispatchers.Main) {
                try {
                    (activity as? MainActivity)?.bringAppToForeground()?.let { if (it) delay(300) }
                } catch (e: Exception) {
                    Log.e(TAG, "群组管理反馈(最大轮次)：返回到应用页面时出错: ${e.message}", e)
                }
                currentConversation = originalGroupConv
                assistantGroupContext = null
                groupManagerFeedbackContext = null
            }
            return
        }
        val feedbackMsg = CustomAssistantManager.buildExecutionFeedbackMessage(
            requireContext(),
            feedbackCtx.userQuery,
            executedAssistantName,
            executedCommand,
            result,
            round,
            feedbackCtx.assistantsWithNames,
            memberNames = feedbackCtx.memberNames,
            senderName = feedbackCtx.senderName
        )
        Log.d(TAG, "群组管理反馈: 调用群组管理者总结/调度, round=$round")
        try {
            val imei = ProfileManager.getOrGenerateImei(requireContext())
            val threadId = "${imei}_group_${groupId}_${gm.id}"
            ChatWebSocketPool.ensureConnected(requireContext(), gm.baseUrl, threadId, gm.multiSession)
            val chatResp = ChatWebSocketPool.sendChat(gm.baseUrl, threadId, feedbackMsg, null)
            val gmFullText = chatResp.response
            val groupConversationIds = buildGroupConversationIds(groupId)
            val isViewingTargetGroup = currentConversation?.id in groupConversationIds
            withContext(Dispatchers.Main) {
                if (isViewingTargetGroup) {
                    addChatMessage(gm.name, gmFullText, isAnswer = true)
                }
            }
            // 只有当前就在目标群会话时，才本地先加并依赖去重；否则必须允许广播落地，避免被去重吞掉
            sendAssistantReplyToGroup(
                groupId = groupId,
                content = gmFullText,
                imei = imei,
                senderImei = null,
                actionType = "answer",
                senderName = gm.name,
                skipDedupRecord = !isViewingTargetGroup
            )
            val mention = CustomAssistantManager.parseGroupManagerMention(requireContext(), gmFullText, feedbackCtx.assistantsWithNames)
            if (mention != null && mention.first != gm.id && mention.second.isNotBlank() && round < CustomAssistantManager.MAX_GROUP_MANAGER_FOLLOW_UP_ROUNDS) {
                val (nextId, nextCmd) = mention
                Log.d(TAG, "群组管理者继续调度: @$nextId $nextCmd")
                val (nextConvId, nextConvName) = when (nextId) {
                    ConversationListFragment.CONVERSATION_ID_ASSISTANT ->
                        ConversationListFragment.CONVERSATION_ID_ASSISTANT to getString(R.string.auto_execute_assistant)
                    else -> {
                        val custom = CustomAssistantManager.getById(requireContext(), nextId)
                        (custom?.id ?: nextId) to (custom?.name ?: "小助手")
                    }
                }
                withContext(Dispatchers.Main) {
                    currentConversation = Conversation(id = nextConvId, name = nextConvName, lastMessage = nextCmd, lastMessageTime = System.currentTimeMillis())
                    assistantGroupContext = AssistantGroupContext(groupId, originalGroupConv, nextCmd, imei)
                    groupManagerFeedbackContext = GroupManagerFeedbackContext(
                        userQuery = feedbackCtx.userQuery,
                        groupManagerAssistant = gm,
                        round = round + 1,
                        assistantsWithNames = feedbackCtx.assistantsWithNames,
                        memberNames = feedbackCtx.memberNames,
                        senderName = feedbackCtx.senderName
                    )
                }
                withContext(Dispatchers.Main) { executeQueryInternal(nextCmd) }
            } else {
                withContext(Dispatchers.Main) {
                    try {
                        (activity as? MainActivity)?.bringAppToForeground()?.let { if (it) delay(300) }
                    } catch (e: Exception) {
                        Log.e(TAG, "群组管理反馈完成：返回到应用页面时出错: ${e.message}", e)
                    }
                    currentConversation = originalGroupConv
                    assistantGroupContext = null
                    groupManagerFeedbackContext = null
                }
            }
        } catch (e: Exception) {
            Log.e(TAG, "群组管理反馈失败: ${e.message}", e)
            withContext(Dispatchers.Main) {
                try {
                    (activity as? MainActivity)?.bringAppToForeground()?.let { if (it) delay(300) }
                } catch (e2: Exception) {
                    Log.e(TAG, "群组管理反馈失败后返回到应用页面出错: ${e2.message}", e2)
                }
                addChatMessage("系统", "群组管理小助手反馈失败: ${e.message}")
                assistantGroupContext = null
                groupManagerFeedbackContext = null
            }
        }
    }
    
