    /**
     * 确保欢迎消息存在并置顶（仅人工客服对话）
     * 如果欢迎消息不存在，则添加；如果存在但不在第一位，则移动到第一位
     */
    private fun ensureWelcomeMessageAtTop() {
        val ctx = context ?: return
        if (currentConversation?.id != ConversationListFragment.CONVERSATION_ID_CUSTOMER_SERVICE) {
            return
        }
        
        val adapter = chatAdapter ?: return
        
        // 欢迎消息内容
        val welcomeMessage = "我是人工客服"
        
        // 检查是否已有欢迎消息
        if (adapter.hasWelcomeMessage()) {
            // 已有欢迎消息，确保在第一位
            adapter.ensureWelcomeMessageAtTop()
            Log.d(TAG, "欢迎消息已存在，确保在第一位")
        } else {
            // 没有欢迎消息，添加并置顶
            val welcomeItem = ChatItem.Message(
                sender = "人工客服",
                message = welcomeMessage,
                isUserMessage = false,
                isComplete = false,
                isAnswer = false,
                timestamp = System.currentTimeMillis(),
                recommendations = null
            )
            
            if (adapter.addWelcomeMessageIfNeeded(welcomeItem)) {
                Log.d(TAG, "已添加欢迎消息并置顶")
                
                // 保存到聊天记录（但不保存欢迎消息到SharedPreferences，避免恢复时重复）
                // 因为欢迎消息是置顶的，不需要持久化
            } else {
                Log.d(TAG, "欢迎消息已存在")
            }
        }
    }
    
    /**
     * 确保人工客服WebSocket连接已建立
     * 如果未连接，会尝试重新初始化并连接
     * @return WebSocket实例，如果连接失败返回null
     */
    private suspend fun ensureCustomerServiceWebSocketConnected(): CustomerServiceWebSocket? {
        val mainActivity = activity as? MainActivity ?: return null
        val conversationId = currentConversation?.id ?: return null
        
        // 先检查是否已有连接
        var webSocket = mainActivity.getCustomerServiceWebSocket()
        if (webSocket != null && webSocket.isConnected()) {
            Log.d(TAG, "WebSocket已连接，设置消息回调")
            setupCustomerServiceMessageCallback(webSocket)
            return webSocket
        }
        
        Log.d(TAG, "WebSocket未连接，开始重新初始化并连接")
        try {
            // 如果存在旧的WebSocket实例但未连接，先断开它
            if (webSocket != null && !webSocket.isConnected()) {
                Log.d(TAG, "断开旧的WebSocket连接")
                webSocket.disconnect()
            }
            
            // 获取配置的地址（优先使用专用配置）
            val prefs = requireContext().getSharedPreferences("app_prefs", android.content.Context.MODE_PRIVATE)
            val specificKey = "chat_server_url_$conversationId"
            val specificUrl = prefs.getString(specificKey, null)
            val customerServiceUrl = specificUrl ?: prefs.getString("customer_service_url", ServiceUrlConfig.DEFAULT_CUSTOMER_SERVICE_URL)
            
            // 重新初始化网络服务
            CustomerServiceNetwork.initialize(customerServiceUrl ?: ServiceUrlConfig.DEFAULT_CUSTOMER_SERVICE_URL)
            
            // 注册用户并连接WebSocket
            val imei = ProfileManager.getOrGenerateImei(requireContext())
            val apiService = CustomerServiceNetwork.getApiService()
            if (apiService == null) {
                Log.e(TAG, "CustomerServiceNetwork未初始化")
                return null
            }
            
            val deviceInfo = mapOf(
                "model" to android.os.Build.MODEL,
                "brand" to android.os.Build.BRAND,
                "sdk" to android.os.Build.VERSION.SDK_INT.toString()
            )
            val response = apiService.register(RegisterRequest(imei = imei, device_info = deviceInfo))
            if (!response.isSuccessful) {
                Log.e(TAG, "用户注册失败: ${response.code()}")
                return null
            }
            
            Log.d(TAG, "用户注册成功，开始连接WebSocket")
            val baseUrl = CustomerServiceNetwork.getCurrentBaseUrl() ?: customerServiceUrl ?: ServiceUrlConfig.DEFAULT_CUSTOMER_SERVICE_URL
            
            // 先保存旧的WebSocket，避免在设置新连接时丢失消息
            val oldWebSocket = mainActivity.getCustomerServiceWebSocket()
            
            val newWebSocket = CustomerServiceWebSocket(requireContext()).apply {
                connect(imei, baseUrl)
            }
            
            // 先设置新的WebSocket到MainActivity，这会设置全局监听器
            // 这样即使连接还在建立中，一旦连接建立并收到消息，全局监听器就已经准备好了
            mainActivity.setCustomerServiceWebSocket(newWebSocket)
            
            // 立即设置ChatFragment的消息回调，避免连接建立后消息到达时回调还未设置
            Log.d(TAG, "立即设置消息回调（连接可能还在建立中）")
            setupCustomerServiceMessageCallback(newWebSocket)
            
            // 延迟释放旧的WebSocket，给旧连接一些时间处理未完成的消息
            // 但不要等待太久，避免资源浪费
            if (oldWebSocket != null && oldWebSocket != newWebSocket) {
                CoroutineScope(Dispatchers.IO).launch {
                    delay(2000) // 等待2秒，让旧连接处理完未完成的消息
                    if (oldWebSocket != mainActivity.getCustomerServiceWebSocket()) {
                        // 确认旧连接已经被替换，才释放
                        Log.d(TAG, "释放旧的WebSocket连接")
                        oldWebSocket.release()
                    }
                }
            }
            
            // 等待WebSocket连接建立（最多等待5秒）
            var retryCount = 0
            while (retryCount < 10 && !newWebSocket.isConnected()) {
                delay(500)
                retryCount++
            }
            
            if (newWebSocket.isConnected()) {
                Log.d(TAG, "WebSocket连接成功")
                return newWebSocket
            } else {
                Log.w(TAG, "WebSocket连接超时，但回调已设置，连接建立后仍可接收消息")
                // 即使连接超时，也返回WebSocket实例，因为连接可能在后台继续建立
                return newWebSocket
            }
        } catch (e: Exception) {
            Log.e(TAG, "确保WebSocket连接失败: ${e.message}", e)
            return null
        }
    }
    
    /**
     * 手动处理好友消息（供MainActivity调用，当回调被覆盖时）
     */
    fun handleFriendMessageDirectly(messageText: String, count: Int) {
        Log.d(TAG, "handleFriendMessageDirectly: 手动处理好友消息")
        try {
            val json = org.json.JSONObject(messageText)
            val type = json.getString("type")
            if (type == "friend_sync_message") {
                ChatCustomerServiceWebSocketHandler.processFriendSyncMessage(this, json)
                return
            }
            if (type == "friend_message") {
                val content = json.getString("content")
                val senderImei = json.optString("senderImei", "")
                val messageType = json.optString("message_type", "text")
                val imageBase64 = json.optString("imageBase64", null)
                // 提取skillId（如果是技能分享消息）
                val skillId = json.optString("skillId", null)
                val timestamp = ChatWebSocketJsonUtils.parseMessageTimestamp(json, "timestamp")
                Log.d(TAG, "手动处理好友消息: senderImei=$senderImei, content=$content, messageType=$messageType, hasImage=${imageBase64 != null}, skillId=$skillId")
                
                // 检查当前对话是否为该好友的对话
                val conversationId = currentConversation?.id
                val friendConversationId = "friend_$senderImei"
                
                if (conversationId == friendConversationId) {
                    // 在当前好友对话页面，直接显示消息
                    Log.d(TAG, "在当前好友对话页面，直接显示消息（手动处理）")
                    view?.post {
                        if (isAdded && _binding != null) {
                            val friend = FriendManager.getFriend(requireContext(), senderImei)
                            val senderName = friend?.nickname ?: senderImei.take(8) + "..."
                            
                            // 如果有图片，保存并显示图片消息
                            if (imageBase64 != null && messageType == "image") {
                                mainScope.launch {
                                    try {
                                        val imagePath = saveImageFromBase64(imageBase64)
                                        if (imagePath != null) {
                                            withContext(Dispatchers.Main) {
                                                addReceivedImageMessage(imagePath, content, senderName, timestamp, senderImei)
                                            }
                                        } else {
                                            withContext(Dispatchers.Main) {
                                                addChatMessage(senderName, if (content.isNotEmpty()) content else "[图片]", skipSystemMessageContainer = true, timestamp = timestamp)
                                            }
                                        }
                                    } catch (e: Exception) {
                                        Log.e(TAG, "保存接收到的图片失败: ${e.message}", e)
                                        withContext(Dispatchers.Main) {
                                            addChatMessage(senderName, if (content.isNotEmpty()) content else "[图片]", skipSystemMessageContainer = true, timestamp = timestamp)
                                        }
                                    }
                                }
                            } else {
                                // 如果消息包含skillId，传递给addChatMessage以便正确识别技能消息
                                addChatMessage(senderName, content, skipSystemMessageContainer = true, timestamp = timestamp, skillId = skillId, senderImei = senderImei)
                            }
                            Log.d(TAG, "好友消息已添加到聊天界面（手动处理）")
                        }
                    }
                }
            }
        } catch (e: Exception) {
            Log.e(TAG, "handleFriendMessageDirectly异常: ${e.message}", e)
            e.printStackTrace()
        }
    }
    
