    /**
     * 外部（如离线补发）已向 prefs 写入当前会话消息后，从存储重载到列表，避免必须离开再进入会话才刷新。
     */
    fun reloadMessagesFromPrefsAfterExternalWrite() {
        if (!isAdded) return
        ensureMainScopeActive()
        mainScope.launch {
            val conversationId = currentConversation?.id ?: return@launch
            var wait = 0
            while (isRestoringMessages && wait < 50) {
                delay(50)
                wait++
            }
            try {
                val vm = getViewModel()
                var sessionIdForLoad = currentSessionIdForMultiSession
                if (CustomAssistantManager.isCustomAssistantId(conversationId)) {
                    val assistant = CustomAssistantManager.getById(requireContext(), conversationId)
                    if (assistant != null && assistant.multiSession) {
                        ensureMultiSessionInitialized(conversationId)
                        sessionIdForLoad = currentSessionIdForMultiSession
                        Log.d(
                            TAG,
                            "reloadMessagesFromPrefsAfterExternalWrite: 多session会话，按session加载 sid=$sessionIdForLoad"
                        )
                    }
                }
                vm.loadMessagesFromPrefs(requireContext(), conversationId, sessionIdForLoad)
                var w2 = 0
                while (vm.isRestoringMessages.value && w2 < 50) {
                    delay(50)
                    w2++
                }
                if (vm.getMessages().isNotEmpty()) {
                    restoreChatMessagesFromViewModel()
                } else {
                    Log.w(TAG, "reloadMessagesFromPrefsAfterExternalWrite: 首次重载为空，尝试兜底恢复")
                    triggerFallbackRestoreIfNeeded("reloadMessagesFromPrefsAfterExternalWrite")
                }
            } catch (e: Exception) {
                Log.e(TAG, "reloadMessagesFromPrefsAfterExternalWrite: ${e.message}", e)
            }
        }
    }

    private fun triggerFallbackRestoreIfNeeded(reason: String) {
        if (!isAdded) return
        ensureMainScopeActive()
        val conversationId = currentConversation?.id ?: return
        val adapterHasItems = chatAdapter?.getItems()?.isNotEmpty() ?: false
        val vm = getViewModel()
        val vmMessages = vm.getMessages()
        val vmHasMessages = vmMessages.isNotEmpty()
        if (adapterHasItems || isRestoringMessages) return

        // 自愈：adapter为空但ViewModel有消息时，优先从ViewModel强制恢复UI
        if (vmHasMessages) {
            Log.w(TAG, "$reason: adapter为空但ViewModel有${vmMessages.size}条，强制从ViewModel恢复")
            mainScope.launch {
                restoreChatMessagesFromViewModel()
            }
            return
        }

        mainScope.launch {
            try {
                if (CustomAssistantManager.isCustomAssistantId(conversationId)) {
                    val assistant = CustomAssistantManager.getById(requireContext(), conversationId)
                    if (assistant != null && assistant.multiSession) {
                        ensureMultiSessionInitialized(conversationId)
                        val sid = currentSessionIdForMultiSession
                        if (!sid.isNullOrBlank()) {
                            Log.d(TAG, "$reason: 多session兜底恢复 sid=$sid")
                            loadMessagesForMultiSessionSession(conversationId, sid, assistant)
                            return@launch
                        } else {
                            Log.w(TAG, "$reason: 多session兜底恢复失败，sessionId为空")
                        }
                    }
                }

                Log.d(TAG, "$reason: 普通兜底恢复，从SharedPreferences加载")
                vm.loadMessagesFromPrefs(requireContext(), conversationId, currentSessionIdForMultiSession)
                var waitCount = 0
                while (vm.isRestoringMessages.value && waitCount < 50) {
                    delay(50)
                    waitCount++
                }
                if (vm.getMessages().isNotEmpty()) {
                    restoreChatMessagesFromViewModel()
                } else {
                    Log.w(TAG, "$reason: 兜底恢复后仍无消息")
                }
            } catch (e: Exception) {
                Log.e(TAG, "$reason: 兜底恢复异常: ${e.message}", e)
            }
        }
    }
    
    /**
     * 手动处理人工客服消息（供MainActivity调用，当回调被覆盖时）
     */
    fun handleServiceMessageDirectly(messageText: String, count: Int) {
        Log.d(TAG, "handleServiceMessageDirectly: 手动处理人工客服消息")
        try {
            val json = org.json.JSONObject(messageText)
            val type = json.getString("type")
            if (type == "service_message") {
                val content = json.getString("content")
                val conversationId = currentConversation?.id
                val timestamp = ChatWebSocketJsonUtils.parseMessageTimestamp(json, "timestamp")
                Log.d(TAG, "手动处理人工客服消息: content=${content.take(50)}, 当前对话ID: $conversationId")
                
                // 检查当前对话是否为人工客服对话
                if (conversationId == ConversationListFragment.CONVERSATION_ID_CUSTOMER_SERVICE) {
                    // 在人工客服对话页面，直接显示消息
                    Log.d(TAG, "在人工客服对话页面，直接显示消息（手动处理）")
                    view?.post {
                        if (isAdded && _binding != null) {
                            addChatMessage("人工客服", content, skipSystemMessageContainer = true, timestamp = timestamp)
                            CustomerServiceUnreadManager.clearUnreadCount(requireContext())
                            updateUnreadBadge()
                            Log.d(TAG, "人工客服消息已添加到聊天界面（手动处理）")
                        } else {
                            Log.w(TAG, "Fragment未添加或binding为null，无法显示消息（手动处理）")
                        }
                    }
                } else {
                    Log.d(TAG, "当前不在人工客服对话页面（对话ID: $conversationId），跳过手动处理")
                }
            }
        } catch (e: Exception) {
            Log.e(TAG, "手动处理人工客服消息失败: ${e.message}", e)
            e.printStackTrace()
        }
    }
    
    /**
     * 手动处理 assistant_user_message / assistant_sync_message（PC 端跨设备同步，供 MainActivity 调用）
     * 当不在目标对话时，会显示 Toast 提醒用户
     */
    fun canHandleRealtimeAssistantSync(): Boolean {
        val host = activity as? MainActivity
        val inForeground = host?.isAppInForeground() == true
        val resumed = lifecycle.currentState.isAtLeast(androidx.lifecycle.Lifecycle.State.RESUMED)
        val canHandle = isAdded && !isHidden && _binding != null && view != null && resumed && inForeground
        if (!canHandle) {
            Log.d(
                TAG,
                "canHandleRealtimeAssistantSync=false, " +
                    "isAdded=$isAdded, isHidden=$isHidden, hasBinding=${_binding != null}, " +
                    "hasView=${view != null}, resumed=$resumed, inForeground=$inForeground"
            )
        }
        return canHandle
    }

    internal data class AssistantSyncImagePayload(
        val base64: String,
        val fileName: String,
        val messageType: String,
    )

    internal fun parseAssistantSyncImagePayloads(json: org.json.JSONObject): List<AssistantSyncImagePayload> {
        val result = mutableListOf<AssistantSyncImagePayload>()
        val dedupe = LinkedHashSet<String>()
        val fileList = json.optJSONArray("file_list")
        if (fileList != null) {
            for (idx in 0 until fileList.length()) {
                val item = fileList.optJSONObject(idx) ?: continue
                val base64 = item.optString("file_base64", null)?.takeIf { it.isNotBlank() }
                    ?: item.optString("fileBase64", null)?.takeIf { it.isNotBlank() }
                    ?: item.optString("imageBase64", null)?.takeIf { it.isNotBlank() }
                    ?: continue
                if (!dedupe.add(base64)) continue
                val messageType = item.optString("message_type", "image").ifBlank { "image" }
                val fileName = item.optString("file_name", null)?.takeIf { it.isNotBlank() }
                    ?: item.optString("fileName", null)?.takeIf { it.isNotBlank() }
                    ?: if (messageType == "file") "文件" else "图片.png"
                result.add(
                    AssistantSyncImagePayload(
                        base64 = base64,
                        fileName = fileName,
                        messageType = messageType,
                    )
                )
            }
        }
        val fallbackBase64 = json.optString("file_base64", null)?.takeIf { it.isNotBlank() }
            ?: json.optString("fileBase64", null)?.takeIf { it.isNotBlank() }
            ?: json.optString("imageBase64", null)?.takeIf { it.isNotBlank() }
        if (fallbackBase64 != null && dedupe.add(fallbackBase64)) {
            val messageType = json.optString("message_type", "image").ifBlank { "image" }
            val fileName = json.optString("file_name", null)?.takeIf { it.isNotBlank() }
                ?: json.optString("fileName", null)?.takeIf { it.isNotBlank() }
                ?: if (messageType == "file") "文件" else "图片.png"
            result.add(
                AssistantSyncImagePayload(
                    base64 = fallbackBase64,
                    fileName = fileName,
                    messageType = messageType,
                )
            )
        }
        return result
    }

    internal fun findAssistantSyncPersistIndex(
        messagesArray: org.json.JSONArray,
        syncMessageId: String,
        imageIndex: Int?,
    ): Int {
        for (i in 0 until messagesArray.length()) {
            val item = messagesArray.optJSONObject(i) ?: continue
            if (item.optString("syncMessageId", "") != syncMessageId) continue
            if (imageIndex == null) return i
            if (item.optInt("syncImageIndex", -1) == imageIndex) return i
        }
        return -1
    }

    internal fun upsertAssistantSyncPersistMessage(
        messagesArray: org.json.JSONArray,
        messageObj: org.json.JSONObject,
        syncMessageId: String?,
        imageIndex: Int? = null,
    ) {
        if (syncMessageId.isNullOrBlank()) {
            messagesArray.put(messageObj)
            return
        }
        messageObj.put("syncMessageId", syncMessageId)
        imageIndex?.let { messageObj.put("syncImageIndex", it) }
        val hitIndex = findAssistantSyncPersistIndex(messagesArray, syncMessageId, imageIndex)
        if (hitIndex < 0) {
            messagesArray.put(messageObj)
            return
        }
        val existing = messagesArray.optJSONObject(hitIndex) ?: org.json.JSONObject()
        val merged = org.json.JSONObject(existing.toString())
        merged.put("sender", messageObj.optString("sender", existing.optString("sender", "")))
        val nextMessage = messageObj.optString("message", "")
        if (nextMessage.isNotBlank()) {
            merged.put("message", nextMessage)
        }
        val nextType = messageObj.optString("type", "")
        if (nextType.isNotBlank()) merged.put("type", nextType)
        if (messageObj.has("imagePath")) {
            merged.put("imagePath", messageObj.optString("imagePath"))
        }
        if (messageObj.has("senderImei")) {
            merged.put("senderImei", messageObj.optString("senderImei"))
        }
        val oldTs = existing.optLong("timestamp", 0L)
        val newTs = messageObj.optLong("timestamp", oldTs)
        merged.put("timestamp", maxOf(oldTs, newTs))
        merged.put("syncMessageId", syncMessageId)
        imageIndex?.let { merged.put("syncImageIndex", it) }
        merged.put("uuid", existing.optString("uuid", java.util.UUID.randomUUID().toString()))
        messagesArray.put(hitIndex, merged)
    }

    /**
     * 手动处理 assistant_user_message / assistant_sync_message（PC 端跨设备同步，供 MainActivity 调用）
     * 当不在目标对话时，会显示 Toast 提醒用户
     */
    fun handleAssistantSyncMessageDirectly(messageText: String) {
        Log.d(TAG, "handleAssistantSyncMessageDirectly: 手动处理小助手同步消息")
        try {
            val json = org.json.JSONObject(messageText)
            val type = json.getString("type")
            if (type != "assistant_user_message" && type != "assistant_sync_message") return
            val content = json.optString("content", "")
            val rawSender = json.optString("sender", if (type == "assistant_user_message") "我" else "系统")
            val senderImei = json.optString("senderImei", null)?.takeIf { it.isNotBlank() }
                ?: json.optString("sender_imei", null)?.takeIf { it.isNotBlank() }
            val syncMessageId = json.optString("message_id", "").trim().ifBlank { null }
            val convIdRaw = json.optString("conversation_id", "assistant").trim()
            val timestamp = ChatWebSocketJsonUtils.parseMessageTimestamp(json, "timestamp")
            val (targetConvId, targetSessionId) = if (convIdRaw.contains("__")) {
                val parts = convIdRaw.split("__", limit = 2)
                parts[0] to parts.getOrNull(1)
            } else {
                convIdRaw to null
            }
            val sender = ChatConstants.normalizeAssistantSenderForConversation(rawSender, targetConvId)
            val isAnswer = type == "assistant_sync_message" &&
                    AssistantSyncMessageHelper.isAnswerSyncMessage(sender, targetConvId, requireContext())
            val isViewing = currentConversation?.id == targetConvId &&
                    AssistantSyncMessageHelper.isViewingAssistantSyncSession(
                        targetSessionId,
                        currentSessionIdForMultiSession
                    )
            val imagePayloads = parseAssistantSyncImagePayloads(json)
            val hasImage = imagePayloads.isNotEmpty()
            // 收到 assistant_user_message（对端发送了消息）时，若目标对话是自定义小助手，则标记为处理中
            val isCustomAssistantConv = CustomAssistantManager.isCustomAssistantId(targetConvId)
            if (type == "assistant_user_message" && isCustomAssistantConv && !isCustomAssistantProcessing) {
                view?.post {
                    if (isAdded && _binding != null) {
                        isCustomAssistantProcessing = true
                        updateButtonVisibility()
                    }
                }
            }
            val shouldClearThinking = type == "assistant_sync_message" && isAnswer
            if (isViewing) {
                if (hasImage) {
                    mainScope.launch {
                        try {
                            val savedImages = withContext(kotlinx.coroutines.Dispatchers.IO) {
                                imagePayloads.mapIndexed { index, payload ->
                                    index to saveImageFromBase64(payload.base64)
                                }
                            }
                            withContext(kotlinx.coroutines.Dispatchers.Main) {
                                if (isAdded && _binding != null) {
                                    var hasRenderedImage = false
                                    savedImages.forEach { (index, imagePath) ->
                                        if (imagePath != null) {
                                            hasRenderedImage = true
                                            val imageContent = if (index == 0) content else ""
                                            if (type == "assistant_user_message") {
                                                addImageMessage(imagePath, imageContent, sender = sender.ifBlank { "我" })
                                            } else {
                                                addReceivedImageMessage(
                                                    imagePath,
                                                    imageContent,
                                                    sender,
                                                    timestamp,
                                                    senderImei,
                                                    clearThinking = shouldClearThinking && index == 0
                                                )
                                            }
                                        }
                                    }
                                    if (!hasRenderedImage) {
                                        addChatMessage(sender, content.ifEmpty { "[图片]" }, isAnswer = isAnswer, skipSystemMessageContainer = true, timestamp = timestamp, senderImei = senderImei, clearThinking = shouldClearThinking)
                                    }
                                    if (isAnswer && isCustomAssistantProcessing) {
                                        isCustomAssistantProcessing = false
                                        updateButtonVisibility()
                                    }
                                }
                            }
                        } catch (e: Exception) {
                            Log.e(TAG, "assistant_sync_message 图片保存失败: ${e.message}", e)
                            withContext(kotlinx.coroutines.Dispatchers.Main) {
                                if (isAdded && _binding != null) {
                                    addChatMessage(sender, content.ifEmpty { "[图片]" }, isAnswer = isAnswer, skipSystemMessageContainer = true, timestamp = timestamp, senderImei = senderImei, clearThinking = shouldClearThinking)
                                }
                            }
                        }
                    }
                } else {
                    view?.post {
                        if (isAdded && _binding != null) {
                            addChatMessage(sender, content, isAnswer = isAnswer, skipSystemMessageContainer = true, timestamp = timestamp, senderImei = senderImei, clearThinking = shouldClearThinking)
                            if (isAnswer && isCustomAssistantProcessing) {
                                isCustomAssistantProcessing = false
                                updateButtonVisibility()
                            }
                        }
                    }
                }
            } else {
                if (isAnswer && isCustomAssistantProcessing) {
                    view?.post {
                        isCustomAssistantProcessing = false
                        updateButtonVisibility()
                    }
                }
                if (hasImage) {
                    mainScope.launch {
                        try {
                            val prefs = requireContext().getSharedPreferences("app_prefs", android.content.Context.MODE_PRIVATE)
                            val msgKey = AssistantSyncMessageHelper.resolveAssistantMsgKey(requireContext(), targetConvId, targetSessionId)
                            val existingMessagesJson = prefs.getString(msgKey, null)
                            val messagesArray = if (existingMessagesJson != null) org.json.JSONArray(existingMessagesJson) else org.json.JSONArray()
                            var hasPersistedImage = false
                            imagePayloads.forEachIndexed { index, payload ->
                                val imagePath = saveImageFromBase64(payload.base64)
                                if (imagePath != null) {
                                    hasPersistedImage = true
                                    val imgFile = java.io.File(imagePath)
                                    val msgText = if (index == 0 && content.isNotEmpty()) "$content\n[图片: ${imgFile.name}]" else "[图片: ${imgFile.name}]"
                                    upsertAssistantSyncPersistMessage(
                                        messagesArray,
                                        org.json.JSONObject().apply {
                                            put("sender", sender)
                                            put("message", msgText)
                                            put("type", "image")
                                            put("timestamp", timestamp)
                                            put("uuid", java.util.UUID.randomUUID().toString())
                                            put("imagePath", imgFile.absolutePath)
                                            senderImei?.let { put("senderImei", it) }
                                        },
                                        syncMessageId,
                                        imageIndex = index,
                                    )
                                }
                            }
                            if (!hasPersistedImage) {
                                val persistType = if (type == "assistant_user_message") "text" else if (isAnswer) "answer" else "system"
                                upsertAssistantSyncPersistMessage(
                                    messagesArray,
                                    org.json.JSONObject().apply {
                                        put("sender", sender)
                                        put("message", content.ifEmpty { "[图片]" })
                                        put("type", persistType)
                                        put("timestamp", timestamp)
                                        put("uuid", java.util.UUID.randomUUID().toString())
                                        senderImei?.let { put("senderImei", it) }
                                    },
                                    syncMessageId,
                                )
                            }
                            prefs.edit().putString(msgKey, messagesArray.toString()).apply()
                            updateConversationLastMessage(targetConvId, if (hasPersistedImage) "[图片]" else content)
                            Log.d(TAG, "assistant_sync_message(含图片) 已保存: $msgKey")
                            switchToSessionIfNeededForIncomingSync(targetConvId, targetSessionId)
                            withContext(kotlinx.coroutines.Dispatchers.Main) {
                                if (isAdded) {
                                    android.widget.Toast.makeText(requireContext(), "收到小助手新消息", android.widget.Toast.LENGTH_SHORT).show()
                                }
                            }
                        } catch (e: Exception) {
                            Log.e(TAG, "保存 assistant_sync_message 图片失败: ${e.message}", e)
                            withContext(kotlinx.coroutines.Dispatchers.Main) {
                                if (isAdded) {
                                    android.widget.Toast.makeText(requireContext(), "收到小助手新消息", android.widget.Toast.LENGTH_SHORT).show()
                                }
                            }
                        }
                    }
                } else {
                    try {
                        val prefs = requireContext().getSharedPreferences("app_prefs", android.content.Context.MODE_PRIVATE)
                        val msgKey = AssistantSyncMessageHelper.resolveAssistantMsgKey(requireContext(), targetConvId, targetSessionId)
                        val existingMessagesJson = prefs.getString(msgKey, null)
                        val messagesArray = if (existingMessagesJson != null) org.json.JSONArray(existingMessagesJson) else org.json.JSONArray()
                        val persistType = if (type == "assistant_user_message") "text" else if (isAnswer) "answer" else "system"
                        upsertAssistantSyncPersistMessage(
                            messagesArray,
                            org.json.JSONObject().apply {
                                put("sender", sender)
                                put("message", content)
                                put("type", persistType)
                                put("timestamp", timestamp)
                                put("uuid", java.util.UUID.randomUUID().toString())
                            },
                            syncMessageId,
                        )
                        prefs.edit().putString(msgKey, messagesArray.toString()).apply()
                        updateConversationLastMessage(targetConvId, content)
                        Log.d(TAG, "assistant_sync_message 已保存: $msgKey")
                        switchToSessionIfNeededForIncomingSync(targetConvId, targetSessionId)
                        view?.post {
                            if (isAdded) {
                                android.widget.Toast.makeText(requireContext(), "收到小助手新消息", android.widget.Toast.LENGTH_SHORT).show()
                            }
                        }
                    } catch (e: Exception) {
                        Log.e(TAG, "保存 assistant_sync_message 失败: ${e.message}", e)
                        view?.post {
                            if (isAdded) {
                                android.widget.Toast.makeText(requireContext(), "收到小助手新消息", android.widget.Toast.LENGTH_SHORT).show()
                            }
                        }
                    }
                }
            }
        } catch (e: Exception) {
            Log.e(TAG, "handleAssistantSyncMessageDirectly 失败: ${e.message}", e)
        }
    }

    /**
     * 手动处理 assistant_thinking_sync / mobile_execute_pc_thinking，
     * 将中间思考展示在聊天区「正在思考」条目，而不是悬浮窗。
     */
    fun handleAssistantThinkingSyncDirectly(messageText: String) {
        try {
            val json = org.json.JSONObject(messageText)
            val type = json.optString("type", "")
            if (type != "assistant_thinking_sync" && type != "mobile_execute_pc_thinking") return
            val thinking = json.optString("thinking_content", "").trim()
            if (thinking.isBlank()) return
            val convIdRaw = json.optString("conversation_id", "assistant").trim()
            val (targetConvId, targetSessionId) = if (convIdRaw.contains("__")) {
                val parts = convIdRaw.split("__", limit = 2)
                parts[0] to parts.getOrNull(1)
            } else {
                convIdRaw to null
            }
            val isViewing = currentConversation?.id == targetConvId &&
                AssistantSyncMessageHelper.isViewingAssistantSyncSession(
                    targetSessionId,
                    currentSessionIdForMultiSession
                )
            if (!isViewing) return

            val customAssistant = if (CustomAssistantManager.isCustomAssistantId(targetConvId)) {
                CustomAssistantManager.getById(requireContext(), targetConvId)
            } else null
            val sender = json.optString("sender", "").ifBlank {
                customAssistant?.name ?: "小助手"
            }
            val details = thinking
                .split('\n')
                .map { it.trim() }
                .filter { it.isNotBlank() }
            val key = json.optString("message_id", "").trim().ifBlank {
                "assistant_thinking_${targetConvId}"
            }
            view?.post {
                if (isAdded && _binding != null) {
                    showAssistantThinkingIndicator(
                        sender = sender,
                        assistantId = customAssistant?.id,
                        avatarBase64 = customAssistant?.avatar,
                        details = details,
                        key = key
                    )
                }
            }
        } catch (e: Exception) {
            Log.e(TAG, "handleAssistantThinkingSyncDirectly 异常: ${e.message}", e)
        }
    }
    
    /**
     * 手动处理 mobile_execute_pc_result（PC 执行完成后的结果，供 MainActivity 调用）
     */
    fun handleMobileExecutePcResultDirectly(messageText: String) {
        Log.d(TAG, "handleMobileExecutePcResultDirectly: PC 执行完成，更新结果")
        try {
            val json = org.json.JSONObject(messageText)
            val success = json.optBoolean("success", false)
            val content = json.optString("content", "")
            val error = json.optString("error", "")
            val imageBase64 = json.optString("file_base64", null)?.takeIf { it.isNotEmpty() }
                ?: json.optString("fileBase64", null)?.takeIf { it.isNotEmpty() }
                ?: json.optString("imageBase64", null)?.takeIf { it.isNotEmpty() }
            val messageType = json.optString("message_type", "")
            val hasImage = imageBase64 != null && (
                messageType == "image" || messageType == "file" || messageType.isEmpty()
            )
            val convId = json.optString("conversation_id", "")
            val isCustomAssistantConv = CustomAssistantManager.isCustomAssistantId(convId)
            val rawAssistantName = if (convId.isNotBlank()) {
                CustomAssistantManager.getById(requireContext(), convId)?.name ?: "小助手"
            } else "小助手"
            val assistantName = ChatConstants.normalizeAssistantSenderForConversation(rawAssistantName, convId)
            val hadRunningState = isTaskRunning || isCustomAssistantProcessing
            val resultText = if (success) {
                content.takeIf { it.isNotBlank() } ?: if (hasImage) "[图片]" else "任务已完成"
            } else {
                "执行失败：${error.takeIf { it.isNotBlank() } ?: "未知错误"}"
            }
            // PC执行结果到达即视为任务结束，先收尾状态，避免会话页一直显示“运行中”
            if (hadRunningState) {
                stopTask(delaySummary = true)
                notifyTaskComplete()
            }

            if (hasImage && imageBase64 != null && success) {
                mainScope.launch {
                    try {
                        val imagePath = saveImageFromBase64(imageBase64)
                        withContext(Dispatchers.Main) {
                            if (isAdded && _binding != null) {
                                if (imagePath != null) {
                                    addReceivedImageMessage(imagePath, content, assistantName, System.currentTimeMillis(), clearThinking = true)
                                } else {
                                    addChatMessage(assistantName, resultText, isAnswer = true, clearThinking = true)
                                }
                                if (isCustomAssistantProcessing) {
                                    isCustomAssistantProcessing = false
                                    updateButtonVisibility()
                                }
                                Log.d(TAG, "mobile_execute_pc_result(含图片) 已添加到聊天界面: $resultText")
                            }
                        }
                    } catch (e: Exception) {
                        Log.e(TAG, "mobile_execute_pc_result 图片保存失败: ${e.message}", e)
                        view?.post {
                            if (isAdded && _binding != null) {
                                addChatMessage(assistantName, resultText, isAnswer = true, clearThinking = true)
                                if (isCustomAssistantProcessing) {
                                    isCustomAssistantProcessing = false
                                    updateButtonVisibility()
                                }
                                Log.d(TAG, "mobile_execute_pc_result 图片失败后已回退文本展示: $resultText")
                            }
                        }
                    }
                }
            } else {
                view?.post {
                    if (isAdded && _binding != null) {
                        addChatMessage(assistantName, resultText, isAnswer = true, clearThinking = true)
                        if (isCustomAssistantProcessing) {
                            isCustomAssistantProcessing = false
                            updateButtonVisibility()
                        }
                        Log.d(TAG, "mobile_execute_pc_result 已添加到聊天界面: $resultText")
                    }
                }
            }
        } catch (e: Exception) {
            Log.e(TAG, "handleMobileExecutePcResultDirectly 异常: ${e.message}", e)
        }
    }
    
    /**
     * 处理对端（电脑端）发来的停止任务指令
     */
    fun handleRemoteStopTask() {
        Log.d(TAG, "handleRemoteStopTask: 收到对端停止任务指令")
        if (!isAdded || _binding == null) return
        if (isTaskRunning || isCustomAssistantProcessing) {
            addChatMessage("系统", "对端已停止任务", isAnswer = false)
            if (isCustomAssistantProcessing && !isTaskRunning) {
                isCustomAssistantProcessing = false
                updateButtonVisibility()
            }
            stopTask()
        }
    }

    /**
     * 手动处理群组消息（供MainActivity调用，当回调被覆盖时）
     */
    fun handleGroupMessageDirectly(messageText: String, count: Int) {
        Log.d(TAG, "handleGroupMessageDirectly: 手动处理群组消息")
        try {
            val json = org.json.JSONObject(messageText)
            val type = json.getString("type")
            if (type == "group_message") {
                val content = json.getString("content")
                val groupId = json.optString("groupId", "")
                val senderImei = json.optString("senderImei", "")
                val sender = json.optString("sender", "群成员")
                val messageType = json.optString("message_type", "text")
                val messageId = json.optString("message_id", "")
                val senderOrigin = json.optString("sender_origin", "")
                val imageBase64 = json.optString("imageBase64", null)
                val isAssistantReply = json.optBoolean("is_assistant_reply", false)
                val timestamp = ChatWebSocketJsonUtils.parseMessageTimestamp(json, "timestamp")
                val currentImei = ProfileManager.getOrGenerateImei(requireContext())
                Log.d(TAG, "========== handleGroupMessageDirectly: 手动处理群组消息 ==========")
                Log.d(TAG, "手动处理群组消息: groupId=$groupId, senderImei=$senderImei, content=$content, messageType=$messageType, messageId=$messageId, senderOrigin=$senderOrigin, hasImage=${imageBase64 != null}, isAssistantReply=$isAssistantReply")
                Log.d(TAG, "手动处理群组消息: currentImei=$currentImei, 是否自己发送=${senderImei == currentImei}")
                Log.d(TAG, "手动处理群组消息: assistantGroupContext=${if (assistantGroupContext != null) "存在(groupId=${assistantGroupContext?.groupId})" else "不存在"}")
                
                // 检查当前对话是否为该群组的对话
                val conversationId = currentConversation?.id
                val groupConversationIds = buildGroupConversationIds(groupId)
                val groupConversationId = groupConversationIds.firstOrNull() ?: "group_$groupId"
                
                // 检查是否有群组上下文（@小助手的情况）
                val groupContext = assistantGroupContext
                val isInGroupContext = groupContext != null &&
                    groupContext.groupId.removePrefix("group_") == groupId.removePrefix("group_")
                
                // 检查当前会话是否是该群组的自定义助手
                val isCustomAssistantInGroup = conversationId != null &&
                    CustomAssistantManager.isCustomAssistantId(conversationId) &&
                    run {
                        val bareGroupId = groupId.removePrefix("group_")
                        val group = GroupManager.getGroup(requireContext(), bareGroupId)
                            ?: GroupManager.getGroup(requireContext(), groupId)
                        group != null && conversationId in group.assistants
                    }
                
                val shouldShowMessage = (conversationId != null && conversationId in groupConversationIds) ||
                    conversationId == ConversationListFragment.CONVERSATION_ID_GROUP ||
                    isInGroupContext ||
                    isCustomAssistantInGroup ||
                    (isAssistantReply && ChatConstants.isMainAssistantSender(sender))
                
                Log.d(TAG, "检查对话匹配 - conversationId: $conversationId, groupConversationId: $groupConversationId, isInGroupContext: $isInGroupContext, isCustomAssistantInGroup: $isCustomAssistantInGroup, isAssistantReply: $isAssistantReply, shouldShowMessage: $shouldShowMessage")
                
                // 如果是自己发送的消息，已在 performSendChatMessage 中本地添加，无需再通过 WebSocket 回调添加，避免重复显示
                if (shouldShowMessage && senderImei == currentImei && !isAssistantReply &&
                    shouldSkipOwnGroupEchoMessage(
                        groupId = groupId,
                        content = content,
                        messageType = messageType,
                        messageId = messageId,
                        senderOrigin = senderOrigin
                    )
                ) {
                    Log.d(TAG, "收到自己发送的群组消息（手动处理），判定为本机回声，跳过添加")
                } else if (shouldShowMessage && isAssistantReply && shouldSkipReceivedAssistantMessage(groupId, content)) {
                    Log.d(TAG, "收到本端已发送的小助手消息广播（手动处理），跳过添加，避免复述")
                } else if (shouldShowMessage && shouldSkipInboundGroupMessage(
                        groupId = groupId,
                        senderImei = senderImei,
                        content = content,
                        messageType = messageType,
                        messageId = messageId.takeIf { it.isNotBlank() },
                        timestamp = timestamp
                    )
                ) {
                    Log.d(TAG, "收到重复群组消息（手动处理），跳过添加")
                } else if (shouldShowMessage) {
                    // 在当前群组对话页面，或者有群组上下文（@小助手的情况），直接显示消息
                    Log.d(TAG, "在当前群组对话页面或有群组上下文，直接显示消息（手动处理）")
                    Log.d(TAG, "Fragment状态检查: isAdded=$isAdded, view=${view != null}, _binding=${_binding != null}")
                    
                    // 如果有群组上下文（@小助手场景）或当前是群组内自定义助手，但当前对话ID不是群组对话，
                    // 需要临时切换对话上下文来保存消息到正确的群组
                    val originalConversation = if ((isInGroupContext || isCustomAssistantInGroup) && 
                        conversationId != groupConversationId && 
                        conversationId != ConversationListFragment.CONVERSATION_ID_GROUP) {
                        Log.d(TAG, "临时切换对话上下文以保存消息到正确的群组对话: $groupConversationId (isInGroupContext=$isInGroupContext, isCustomAssistantInGroup=$isCustomAssistantInGroup)")
                        val original = currentConversation
                        currentConversation = Conversation(
                            id = groupConversationId,
                            name = "群组",
                            lastMessage = content,
                            lastMessageTime = timestamp
                        )
                        Log.d(TAG, "对话上下文已切换: ${original?.id} -> ${currentConversation?.id}")
                        original
                    } else {
                        null
                    }
                    
                    view?.post {
                        Log.d(TAG, "view.post回调执行，再次检查Fragment状态: isAdded=$isAdded, _binding=${_binding != null}")
                        if (isAdded && _binding != null) {
                            // 获取当前用户IMEI
                            val currentImei = ProfileManager.getOrGenerateImei(requireContext())
                            // 群组显示规则：成员优先昵称（无昵称则IMEI）；助手显示“助手昵称（主人昵称）”
                            val senderName = when {
                                senderImei == currentImei -> "我"
                                sender == "系统" -> "系统"
                                isAssistantReply -> formatAssistantDisplayNameWithOwner(sender, senderImei)
                                else -> {
                                    resolveMemberDisplayNameFromImei(senderImei, sender).ifBlank { sender.ifBlank { "群成员" } }
                                }
                            }
                            
                            // 判断显示方式：只有sender为"TopoClaw"且isAssistantReply为true时才显示为小助手消息
                            // 如果sender是"系统"，即使isAssistantReply为true，也应该显示为系统消息
                            val isAssistantMessage = isAssistantReply && ChatConstants.isMainAssistantSender(sender)
                            val skipSystemMessageContainer = if (isAssistantMessage) {
                                // 小助手回复统一以气泡形式显示
                                val groupConversationId = "group_$groupId"
                                val lastActionType = groupActionTypeMap[groupId]
                                Log.d(TAG, "小助手回复消息（手动处理） - groupId: $groupId, lastActionType: $lastActionType, 显示为气泡")
                                true  // 小助手回复统一显示为气泡
                            } else {
                                // 系统消息或其他消息：如果sender是"系统"，显示在系统消息容器中
                                val isSystemMessage = sender == "系统"
                                Log.d(TAG, "非小助手消息（手动处理） - sender: $sender, isSystemMessage: $isSystemMessage")
                                !isSystemMessage  // 系统消息不跳过系统消息容器，其他消息跳过
                            }
                            
                            Log.d(TAG, "准备添加群组消息到界面，发送者: $senderName, 内容长度: ${content.length}, 当前对话ID: ${currentConversation?.id}, skipSystemMessageContainer: $skipSystemMessageContainer, isAssistantMessage: $isAssistantMessage")
                            
                            // 如果有图片，保存并显示图片消息
                            if (imageBase64 != null && messageType == "image") {
                                mainScope.launch {
                                    try {
                                        val imagePath = saveImageFromBase64(imageBase64)
                                        if (imagePath != null) {
                                            withContext(Dispatchers.Main) {
                                                // 显示图片消息（左侧对齐，因为是接收到的消息）
                                                addReceivedImageMessage(imagePath, content, senderName, timestamp, senderImei)
                                            }
                                        } else {
                                            withContext(Dispatchers.Main) {
                                                // 小助手回复使用isAnswer=true确保显示为气泡消息
                                                addChatMessage(senderName, if (content.isNotEmpty()) content else "[图片]", isAnswer = isAssistantMessage, skipSystemMessageContainer = skipSystemMessageContainer, timestamp = timestamp, senderImei = senderImei)
                                            }
                                        }
                                    } catch (e: Exception) {
                                        Log.e(TAG, "保存接收到的群组图片失败: ${e.message}", e)
                                        withContext(Dispatchers.Main) {
                                            // 小助手回复使用isAnswer=true确保显示为气泡消息
                                            addChatMessage(senderName, if (content.isNotEmpty()) content else "[图片]", isAnswer = isAssistantMessage, skipSystemMessageContainer = skipSystemMessageContainer, timestamp = timestamp, senderImei = senderImei)
                                        }
                                    }
                                }
                            } else {
                                // 添加消息（此时currentConversation已切换到群组对话，消息会保存到正确的对话记录）
                                // 小助手回复使用isAnswer=true确保显示为气泡消息
                                addChatMessage(senderName, content, isAnswer = isAssistantMessage, skipSystemMessageContainer = skipSystemMessageContainer, timestamp = timestamp, senderImei = senderImei)
                            }
                            Log.d(TAG, "群组消息已添加到聊天界面（手动处理），发送者: $senderName, 保存到的对话ID: ${currentConversation?.id}")
                            
                            // 如果是小助手回复，从临时Map中清除动作类型，避免影响后续消息
                            if (isAssistantReply && ChatConstants.isMainAssistantSender(sender)) {
                                groupActionTypeMap.remove(groupId)
                                Log.d(TAG, "已从临时Map中清除动作类型（手动处理）: groupId=$groupId")
                            }
                            
                            // 恢复原始对话上下文（如果有临时切换）
                            if (originalConversation != null) {
                                Log.d(TAG, "恢复原始对话上下文: ${originalConversation.id}")
                                currentConversation = originalConversation
                            }
                        } else {
                            Log.w(TAG, "Fragment状态检查失败，无法添加消息: isAdded=$isAdded, _binding=${_binding != null}")
                            // 即使无法添加消息，也要恢复对话上下文
                            if (originalConversation != null) {
                                currentConversation = originalConversation
                            }
                        }
                    } ?: run {
                        Log.e(TAG, "view为null，无法使用post方法")
                        // 恢复原始对话上下文
                        if (originalConversation != null) {
                            currentConversation = originalConversation
                        }
                    }
                } else {
                    Log.w(TAG, "当前不在群组对话页面且没有群组上下文，跳过显示消息")
                    Log.w(TAG, "对话ID不匹配详情: conversationId=$conversationId, groupConversationId=$groupConversationId")
                    Log.w(TAG, "群组上下文: ${if (groupContext != null) "存在(groupId=${groupContext.groupId})" else "不存在"}")
                }
            }
        } catch (e: Exception) {
            Log.e(TAG, "handleGroupMessageDirectly异常: ${e.message}", e)
            e.printStackTrace()
        }
    }
    
    /**
     * 解析并展示/落盘端云「我的电脑」消息（支持文本、文件摘要、图片）
     */
    fun dispatchCrossDeviceMessage(json: org.json.JSONObject) {
        val content = json.optString("content", "")
        val sender = json.optString("sender", "我的电脑")
        val timestamp = ChatWebSocketJsonUtils.parseMessageTimestamp(json, "timestamp")
        val mainAct = activity as? MainActivity
        if (json.optString("message_type") == "file") {
            val displayContent = "[文件] ${json.optString("file_name", json.optString("fileName", "文件"))}"
            if (currentConversation?.id == ConversationListFragment.CONVERSATION_ID_ME) {
                view?.post {
                    if (isAdded && hasChatBinding) {
                        addChatMessage(sender, displayContent, skipSystemMessageContainer = true, timestamp = timestamp)
                    }
                    mainAct?.notifyInboundSessionMessage(ConversationListFragment.CONVERSATION_ID_ME, displayContent, incrementUnread = false)
                }
            } else {
                CrossDeviceMeMessageStore.appendMessage(requireContext(), sender, displayContent, timestamp, null)
                mainAct?.notifyInboundSessionMessage(ConversationListFragment.CONVERSATION_ID_ME, displayContent, incrementUnread = true)
            }
            return
        }
        val imageB64 = ChatWebSocketJsonUtils.extractCrossDeviceImageBase64(json)
        if (imageB64 != null) {
            mainScope.launch(Dispatchers.IO) {
                val path = ChatImageUtils.saveImageFromBase64(requireContext(), imageB64)
                withContext(Dispatchers.Main) {
                    if (!isAdded || _binding == null) return@withContext
                    val preview = content.ifEmpty { "[图片]" }
                    if (currentConversation?.id == ConversationListFragment.CONVERSATION_ID_ME) {
                        if (path != null) {
                            addReceivedImageMessage(path, content, sender, timestamp, null)
                        } else {
                            addChatMessage(sender, preview, skipSystemMessageContainer = true, timestamp = timestamp)
                        }
                        mainAct?.notifyInboundSessionMessage(ConversationListFragment.CONVERSATION_ID_ME, preview, incrementUnread = false)
                    } else {
                        CrossDeviceMeMessageStore.appendMessage(requireContext(), sender, content, timestamp, path)
                        mainAct?.notifyInboundSessionMessage(ConversationListFragment.CONVERSATION_ID_ME, preview, incrementUnread = true)
                    }
                }
            }
            return
        }
        if (currentConversation?.id == ConversationListFragment.CONVERSATION_ID_ME) {
            view?.post {
                if (isAdded && hasChatBinding) {
                    addChatMessage(sender, content, skipSystemMessageContainer = true, timestamp = timestamp)
                }
                mainAct?.notifyInboundSessionMessage(ConversationListFragment.CONVERSATION_ID_ME, content, incrementUnread = false)
            }
        } else {
            CrossDeviceMeMessageStore.appendMessage(requireContext(), sender, content, timestamp, null)
            mainAct?.notifyInboundSessionMessage(ConversationListFragment.CONVERSATION_ID_ME, content, incrementUnread = true)
        }
    }

    /**
     * 手动处理端云互发消息（供MainActivity调用，当回调被覆盖时）
     */
    fun handleCrossDeviceMessageDirectly(messageText: String, count: Int) {
        Log.d(TAG, "handleCrossDeviceMessageDirectly: 手动处理端云互发消息")
        try {
            val json = org.json.JSONObject(messageText)
            if (json.getString("type") == "cross_device_message") {
                dispatchCrossDeviceMessage(json)
            }
        } catch (e: Exception) {
            Log.e(TAG, "handleCrossDeviceMessageDirectly异常: ${e.message}", e)
            e.printStackTrace()
        }
    }
    
    /**
     * 手动处理远程执行指令（供MainActivity调用）
     */
    fun handleRemoteAssistantCommandDirectly(messageText: String, count: Int) {
        Log.d(TAG, "handleRemoteAssistantCommandDirectly: 手动处理远程执行指令")
        try {
            val json = org.json.JSONObject(messageText)
            val type = json.getString("type")
            if (type == "remote_assistant_command") {
                val groupId = json.optString("groupId", "")
                val targetImei = json.optString("targetImei", "")
                val command = json.optString("command", "")
                val senderImei = json.optString("senderImei", "")
                Log.d(TAG, "========== 收到远程执行指令 ==========")
                Log.d(TAG, "groupId=$groupId, targetImei=$targetImei, command=$command, senderImei=$senderImei")
                
                // 验证是否是自己
                val currentImei = ProfileManager.getOrGenerateImei(requireContext())
                if (targetImei != currentImei) {
                    Log.d(TAG, "远程指令目标不是自己，忽略: targetImei=$targetImei, currentImei=$currentImei")
                    return
                }
                
                // 远程指令需要自动添加 @TopoClaw 前缀（因为这是由其他任务指派的）
                val finalCommand = if (!ChatConstants.containsRemoteStyleAssistantMention(command)) {
                    "@${ChatConstants.ASSISTANT_DISPLAY_NAME} $command"
                } else {
                    command
                }
                
                // 检查"默认允许好友控制手机"开关：若开启则直接执行，否则显示权限确认弹窗
                val allowFriendControlByDefault = requireContext().getSharedPreferences("app_prefs", android.content.Context.MODE_PRIVATE)
                    .getBoolean("allow_friend_control_by_default", false)
                if (allowFriendControlByDefault) {
                    Log.d(TAG, "默认允许好友控制手机已开启，直接执行远程指令")
                    executeRemoteCommandDirectly(groupId, finalCommand, senderImei)
                } else {
                    Log.d(TAG, "确认是发给自己的远程指令，显示权限确认弹窗")
                    showRemoteControlPermissionDialog(senderImei, groupId, finalCommand)
                }
            }
        } catch (e: Exception) {
            Log.e(TAG, "handleRemoteAssistantCommandDirectly异常: ${e.message}", e)
            e.printStackTrace()
        }
    }
    
    /**
     * 显示远程控制权限确认弹窗
     */
    private fun showRemoteControlPermissionDialog(senderImei: String, groupId: String, command: String) {
        if (!isAdded || _binding == null) {
            Log.w(TAG, "Fragment未附加，无法显示权限确认弹窗")
            return
        }
        
        mainScope.launch {
            // 异步获取发送者昵称
            val senderName = withContext(Dispatchers.IO) {
                try {
                    val prefs = requireContext().getSharedPreferences("app_prefs", android.content.Context.MODE_PRIVATE)
                    val customerServiceUrl = prefs.getString("customer_service_url", ServiceUrlConfig.DEFAULT_CUSTOMER_SERVICE_URL)
                        ?: ServiceUrlConfig.DEFAULT_CUSTOMER_SERVICE_URL
                    CustomerServiceNetwork.initialize(customerServiceUrl)
                    val apiService = CustomerServiceNetwork.getApiService()
                    apiService?.getProfile(senderImei)?.let { response ->
                        if (response.isSuccessful && response.body()?.success == true) {
                            response.body()?.profile?.name
                        } else null
                    }
                } catch (e: Exception) {
                    Log.w(TAG, "获取发送者信息失败: ${e.message}")
                    null
                }
            }
            
            // 显示弹窗
            if (!isAdded || _binding == null) return@launch
            
            val displayName = senderName ?: senderImei.take(8) + "..."
            val dialog = android.app.AlertDialog.Builder(requireContext())
                .setTitle("远程控制请求")
                .setMessage("${displayName}尝试控制您的手机")
                .setPositiveButton("同意") { _, _ ->
                    executeRemoteCommand(groupId, command, senderImei)
                }
                .setNegativeButton("拒绝", null)
                .setCancelable(true)
                .create()
            dialog.show()
        }
    }
    
    /**
     * 直接执行远程控制指令（不显示权限确认弹窗）
     * 用于从悬浮窗权限确认后调用
     */
    fun executeRemoteCommandDirectly(groupId: String, command: String, senderImei: String) {
        executeRemoteCommand(groupId, command, senderImei)
    }

    /**
     * 处理 PC 端发起的执行指令（由 MainActivity 调用）
     * PC 发送 -> 后端转发 -> 手机执行 -> 结果回传 PC
     */
    /**
     * 执行 PC 端指令（供 MainActivity 批测流程调用，Fragment 已就绪时调用）
     * 与 sendMessageForBatchTest 类似，直接执行 query
     */
    fun executePcExecuteCommand(query: String, execUuid: String, messageId: String, steps: List<String>? = null, conversationId: String? = null) {
        Log.d(TAG, "executePcExecuteCommand: query=$query, uuid=$execUuid, messageId=$messageId, stepsCount=${steps?.size ?: 0}, conversationId=$conversationId")
        if (!isAdded || _binding == null) {
            Log.e(TAG, "executePcExecuteCommand: Fragment 未就绪，无法执行")
            return
        }
        val targetConvId = conversationId?.takeIf { it.isNotBlank() } ?: ConversationListFragment.CONVERSATION_ID_ASSISTANT
        currentConversation = if (conversationId != null && conversationId.startsWith("group_")) {
            // PC 群组 @ TopoClaw：保持/设置为群组对话，执行信息呈现在群组内
            val groupId = conversationId.removePrefix("group_")
            val group = GroupManager.getGroup(requireContext(), groupId)
            Conversation(
                id = conversationId,
                name = group?.name ?: "群组",
                avatar = null,
                lastMessage = query,
                lastMessageTime = System.currentTimeMillis()
            )
        } else {
            Conversation(
                id = ConversationListFragment.CONVERSATION_ID_ASSISTANT,
                name = ChatConstants.ASSISTANT_DISPLAY_NAME,
                avatar = null,
                lastMessage = query,
                lastMessageTime = System.currentTimeMillis()
            )
        }
        assistantPcExecuteContext = AssistantPcExecuteContext(execUuid, messageId, targetConvId)
        addChatMessage("系统", "收到 PC 端指令，开始执行...")
        if (steps != null && steps.isNotEmpty()) {
            pendingUserExample = SkillStepParser.parseStepsToUserExample(steps)
            Log.d(TAG, "executePcExecuteCommand: 已设置步骤 user_example，共 ${steps.size} 步")
        }
        Log.d(TAG, "executePcExecuteCommand: 已设置 PC 执行上下文，调用 executeQueryInternal")
        executeQueryInternal(query)
    }

    /**
     * mobile_tool/v1: 处理工具调用请求
     */
    fun handleMobileToolInvoke(json: JSONObject) {
        try {
            ensureMainScopeActive()
            val requestId = json.optString("request_id", "").trim()
            val protocol = json.optString("protocol", "mobile_tool/v1").trim().ifBlank { "mobile_tool/v1" }
            val conversationId = json.optString("conversation_id", currentConversation?.id ?: "assistant")
            val payload = json.optJSONObject("payload") ?: JSONObject()
            val tool = payload.optString("tool", "").trim()

            if (requestId.isBlank()) {
                Log.w(TAG, "mobile_tool_invoke 缺少 request_id")
                return
            }

            if (
                tool != "device.get_location" &&
                tool != "device.open_deeplink" &&
                tool != "device.gui_task_probe" &&
                tool != "device.set_clipboard_image" &&
                tool != "device.save_image_to_gallery"
            ) {
                sendMobileToolResult(
                    requestId = requestId,
                    protocol = protocol,
                    conversationId = conversationId,
                    ok = false,
                    tool = tool.ifBlank { "unknown" },
                    data = null,
                    errorCode = "UNSUPPORTED_TOOL",
                    errorMessage = "当前版本不支持工具: $tool",
                    retryable = false
                )
                return
            }

            val args = payload.optJSONObject("args") ?: JSONObject()
            if (tool == "device.gui_task_probe") {
                sendMobileToolAck(requestId, protocol, conversationId, accepted = true)
                sendCrossDeviceGuiTaskProbeAck(requestId = requestId, ok = true, error = null)
                sendMobileToolResult(
                    requestId = requestId,
                    protocol = protocol,
                    conversationId = conversationId,
                    ok = true,
                    tool = "device.gui_task_probe",
                    data = JSONObject().apply {
                        put("ready", true)
                        put("checked_at", isoTimestampNowUtc())
                    },
                    errorCode = null,
                    errorMessage = null,
                    retryable = false
                )
                return
            }
            if (tool == "device.open_deeplink") {
                sendMobileToolAck(requestId, protocol, conversationId, accepted = true)
                executeDeeplinkToolRequest(
                    requestId = requestId,
                    protocol = protocol,
                    conversationId = conversationId,
                    args = args
                )
                return
            }
            if (tool == "device.set_clipboard_image") {
                sendMobileToolAck(requestId, protocol, conversationId, accepted = true)
                executeSetClipboardImageToolRequest(
                    requestId = requestId,
                    protocol = protocol,
                    conversationId = conversationId,
                    args = args
                )
                return
            }
            if (tool == "device.save_image_to_gallery") {
                sendMobileToolAck(requestId, protocol, conversationId, accepted = true)
                executeSaveImageToGalleryToolRequest(
                    requestId = requestId,
                    protocol = protocol,
                    conversationId = conversationId,
                    args = args
                )
                return
            }

            val accuracy = args.optString("accuracy", "coarse").trim().lowercase()
            val requiresFine = accuracy == "fine"
            val withAddress = args.optBoolean("with_address", false)
            val timeoutMsRaw = args.optLong("timeout_ms", 8000L)
            val timeoutMs = timeoutMsRaw.coerceIn(1000L, 30_000L)

            clearStalePendingLocationRequestsBeforeNew(requestId)
            val pending = PendingLocationToolRequest(
                requestId = requestId,
                protocol = protocol,
                conversationId = conversationId,
                requiresFine = requiresFine,
                withAddress = withAddress,
                timeoutMs = timeoutMs
            )
            pendingLocationToolRequest = pending
            pendingLocationPermissionRequest = null
            sendMobileToolAck(requestId, protocol, conversationId, accepted = true)

            startLocationToolFlow(pending)
        } catch (e: Exception) {
            Log.e(TAG, "处理 mobile_tool_invoke 异常: ${e.message}", e)
        }
    }

    /**
     * mobile_tool/v1: 处理取消请求
     */
    fun handleMobileToolCancel(json: JSONObject) {
        val requestId = json.optString("request_id", "").trim()
        if (requestId.isBlank()) return
        val pending = when {
            pendingLocationToolRequest?.requestId == requestId -> pendingLocationToolRequest
            pendingLocationPermissionRequest?.requestId == requestId -> pendingLocationPermissionRequest
            else -> null
        }
        if (pending != null) {
            clearPendingLocationRequest(pending.requestId)
            sendMobileToolResult(
                requestId = pending.requestId,
                protocol = pending.protocol,
                conversationId = pending.conversationId,
                ok = false,
                tool = "device.get_location",
                data = null,
                errorCode = "CANCELLED",
                errorMessage = "请求已取消",
                retryable = false
            )
        }
    }

    private fun clearStalePendingLocationRequestsBeforeNew(newRequestId: String) {
        val staleRequests = linkedMapOf<String, PendingLocationToolRequest>()
        pendingLocationToolRequest?.let { staleRequests[it.requestId] = it }
        pendingLocationPermissionRequest?.let { staleRequests[it.requestId] = it }
        staleRequests.values.forEach { stale ->
            if (stale.requestId != newRequestId) {
                clearPendingLocationRequest(stale.requestId)
                Log.w(TAG, "新定位请求($newRequestId)到达，已清理旧 pending: ${stale.requestId}")
            }
        }
    }

    private fun startLocationToolFlow(request: PendingLocationToolRequest) {
        if (!isAdded || activity == null) {
            clearPendingLocationRequest(request.requestId)
            sendMobileToolResult(
                requestId = request.requestId,
                protocol = request.protocol,
                conversationId = request.conversationId,
                ok = false,
                tool = "device.get_location",
                data = null,
                errorCode = "INTERNAL_ERROR",
                errorMessage = "界面未就绪，无法执行定位请求",
                retryable = true
            )
            pendingLocationToolRequest = null
            return
        }

        val hasPermission =
            ContextCompat.checkSelfPermission(requireContext(), Manifest.permission.ACCESS_COARSE_LOCATION) == PackageManager.PERMISSION_GRANTED ||
                ContextCompat.checkSelfPermission(requireContext(), Manifest.permission.ACCESS_FINE_LOCATION) == PackageManager.PERMISSION_GRANTED

        if (hasPermission) {
            executeLocationToolRequest(request)
            return
        }

        sendMobileToolEvent(
            requestId = request.requestId,
            protocol = request.protocol,
            conversationId = request.conversationId,
            event = "permission_required",
            detail = JSONObject().apply {
                val permissions = org.json.JSONArray()
                permissions.put(Manifest.permission.ACCESS_COARSE_LOCATION)
                put("permissions", permissions)
                put("message", "需要定位权限以继续")
            }
        )

        // 直接拉起系统权限弹窗，不再先展示应用内确认弹窗。
        pendingLocationPermissionRequest = request
        val perms = arrayOf(Manifest.permission.ACCESS_COARSE_LOCATION)
        requestPermissions(perms, ChatConstants.REQUEST_CODE_MOBILE_TOOL_LOCATION)
    }

    private fun executeLocationToolRequest(request: PendingLocationToolRequest) {
        ensureMainScopeActive()
        mainScope.launch {
            try {
                pendingLocationPermissionRequest = null
                sendMobileToolEvent(
                    requestId = request.requestId,
                    protocol = request.protocol,
                    conversationId = request.conversationId,
                    event = "started",
                    detail = JSONObject().apply { put("tool", "device.get_location") }
                )

                val elapsedMs = SystemClock.elapsedRealtime() - request.createdAtElapsedMs
                val remainingMs = request.timeoutMs - elapsedMs
                if (remainingMs <= 1200L) {
                    clearPendingLocationRequest(request.requestId)
                    sendMobileToolResult(
                        requestId = request.requestId,
                        protocol = request.protocol,
                        conversationId = request.conversationId,
                        ok = false,
                        tool = "device.get_location",
                        data = null,
                        errorCode = "TIMEOUT",
                        errorMessage = "定位请求超时，请重试",
                        retryable = true
                    )
                    return@launch
                }

                val location = withContext(Dispatchers.Main) {
                    getCurrentLocationCompat(
                        timeoutMs = remainingMs.coerceIn(1000L, request.timeoutMs),
                        requiresFine = request.requiresFine
                    )
                }

                if (location == null) {
                    clearPendingLocationRequest(request.requestId)
                    sendMobileToolResult(
                        requestId = request.requestId,
                        protocol = request.protocol,
                        conversationId = request.conversationId,
                        ok = false,
                        tool = "device.get_location",
                        data = null,
                        errorCode = "DEPENDENCY_UNAVAILABLE",
                        errorMessage = "无法获取定位，请确认系统定位服务已开启",
                        retryable = true
                    )
                    return@launch
                }

                val data = JSONObject().apply {
                    put("lat", location.latitude)
                    put("lng", location.longitude)
                    put("accuracy_m", location.accuracy.toDouble())
                    put("provider", location.provider ?: "unknown")
                    put("address", JSONObject.NULL)
                    put("captured_at", isoTimestampNowUtc())
                }
                clearPendingLocationRequest(request.requestId)
                sendMobileToolResult(
                    requestId = request.requestId,
                    protocol = request.protocol,
                    conversationId = request.conversationId,
                    ok = true,
                    tool = "device.get_location",
                    data = data,
                    errorCode = null,
                    errorMessage = null,
                    retryable = false
                )
            } catch (ce: CancellationException) {
                val pending = when {
                    pendingLocationToolRequest?.requestId == request.requestId -> pendingLocationToolRequest
                    pendingLocationPermissionRequest?.requestId == request.requestId -> pendingLocationPermissionRequest
                    else -> null
                }
                if (pending != null) {
                    clearPendingLocationRequest(request.requestId)
                    sendMobileToolResult(
                        requestId = request.requestId,
                        protocol = request.protocol,
                        conversationId = request.conversationId,
                        ok = false,
                        tool = "device.get_location",
                        data = null,
                        errorCode = "CANCELLED",
                        errorMessage = "定位请求因页面切换被中断",
                        retryable = true
                    )
                }
                throw ce
            }
        }
    }

    private fun executeDeeplinkToolRequest(
        requestId: String,
        protocol: String,
        conversationId: String,
        args: JSONObject
    ) {
        mainScope.launch {
            val deeplink = args.optString("deeplink", "").trim()
            if (deeplink.isBlank()) {
                sendMobileToolResult(
                    requestId = requestId,
                    protocol = protocol,
                    conversationId = conversationId,
                    ok = false,
                    tool = "device.open_deeplink",
                    data = null,
                    errorCode = "INVALID_ARGS",
                    errorMessage = "缺少 deeplink 参数",
                    retryable = false
                )
                return@launch
            }

            sendMobileToolEvent(
                requestId = requestId,
                protocol = protocol,
                conversationId = conversationId,
                event = "started",
                detail = JSONObject().apply {
                    put("tool", "device.open_deeplink")
                    put("deeplink", deeplink)
                }
            )

            try {
                val intent = if (deeplink.startsWith("intent:", ignoreCase = true)) {
                    android.content.Intent.parseUri(deeplink, android.content.Intent.URI_INTENT_SCHEME)
                } else {
                    android.content.Intent(android.content.Intent.ACTION_VIEW, android.net.Uri.parse(deeplink))
                }.apply {
                    addFlags(android.content.Intent.FLAG_ACTIVITY_NEW_TASK)
                }

                val pm = requireContext().packageManager
                val resolved = intent.resolveActivity(pm)
                if (resolved == null) {
                    sendMobileToolResult(
                        requestId = requestId,
                        protocol = protocol,
                        conversationId = conversationId,
                        ok = false,
                        tool = "device.open_deeplink",
                        data = null,
                        errorCode = "NO_HANDLER",
                        errorMessage = "当前手机没有可处理该 deeplink 的应用",
                        retryable = false
                    )
                    return@launch
                }

                startActivity(intent)
                sendMobileToolResult(
                    requestId = requestId,
                    protocol = protocol,
                    conversationId = conversationId,
                    ok = true,
                    tool = "device.open_deeplink",
                    data = JSONObject().apply {
                        put("deeplink", deeplink)
                        put("resolved_activity", resolved.flattenToShortString())
                        put("executed", true)
                        put("executed_at", isoTimestampNowUtc())
                    },
                    errorCode = null,
                    errorMessage = null,
                    retryable = false
                )
            } catch (e: Exception) {
                sendMobileToolResult(
                    requestId = requestId,
                    protocol = protocol,
                    conversationId = conversationId,
                    ok = false,
                    tool = "device.open_deeplink",
                    data = null,
                    errorCode = "EXECUTION_FAILED",
                    errorMessage = e.message ?: "deeplink 执行失败",
                    retryable = false
                )
            }
        }
    }

    private fun executeSetClipboardImageToolRequest(
        requestId: String,
        protocol: String,
        conversationId: String,
        args: JSONObject
    ) {
        mainScope.launch {
            val imageBase64 = args.optString("image_base64", "").trim()
                .ifBlank { args.optString("imageBase64", "").trim() }
            val label = args.optString("label", "topoclaw_image").trim().ifBlank { "topoclaw_image" }
            if (imageBase64.isBlank()) {
                sendMobileToolResult(
                    requestId = requestId,
                    protocol = protocol,
                    conversationId = conversationId,
                    ok = false,
                    tool = "device.set_clipboard_image",
                    data = null,
                    errorCode = "INVALID_ARGS",
                    errorMessage = "缺少 image_base64 参数",
                    retryable = false
                )
                return@launch
            }

            sendMobileToolEvent(
                requestId = requestId,
                protocol = protocol,
                conversationId = conversationId,
                event = "started",
                detail = JSONObject().apply {
                    put("tool", "device.set_clipboard_image")
                    put("label", label)
                }
            )

            try {
                val imagePath = saveImageFromBase64(imageBase64)
                if (imagePath.isNullOrBlank()) {
                    sendMobileToolResult(
                        requestId = requestId,
                        protocol = protocol,
                        conversationId = conversationId,
                        ok = false,
                        tool = "device.set_clipboard_image",
                        data = null,
                        errorCode = "DECODE_FAILED",
                        errorMessage = "图片 base64 解析失败",
                        retryable = false
                    )
                    return@launch
                }

                val imageFile = java.io.File(imagePath)
                if (!imageFile.exists() || imageFile.length() <= 0L) {
                    sendMobileToolResult(
                        requestId = requestId,
                        protocol = protocol,
                        conversationId = conversationId,
                        ok = false,
                        tool = "device.set_clipboard_image",
                        data = null,
                        errorCode = "FILE_WRITE_FAILED",
                        errorMessage = "图片落盘失败",
                        retryable = true
                    )
                    return@launch
                }

                val clipboardUri = FileProvider.getUriForFile(
                    requireContext(),
                    "${requireContext().packageName}.fileprovider",
                    imageFile
                )
                val clipboard = requireContext().getSystemService(Context.CLIPBOARD_SERVICE) as ClipboardManager
                val clipData = ClipData.newUri(requireContext().contentResolver, label, clipboardUri)
                clipboard.setPrimaryClip(clipData)

                sendMobileToolResult(
                    requestId = requestId,
                    protocol = protocol,
                    conversationId = conversationId,
                    ok = true,
                    tool = "device.set_clipboard_image",
                    data = JSONObject().apply {
                        put("label", label)
                        put("uri", clipboardUri.toString())
                        put("path", imageFile.absolutePath)
                        put("size_bytes", imageFile.length())
                        put("updated_at", isoTimestampNowUtc())
                    },
                    errorCode = null,
                    errorMessage = null,
                    retryable = false
                )
            } catch (e: Exception) {
                sendMobileToolResult(
                    requestId = requestId,
                    protocol = protocol,
                    conversationId = conversationId,
                    ok = false,
                    tool = "device.set_clipboard_image",
                    data = null,
                    errorCode = "EXECUTION_FAILED",
                    errorMessage = e.message ?: "设置图片剪切板失败",
                    retryable = true
                )
            }
        }
    }

    private fun executeSaveImageToGalleryToolRequest(
        requestId: String,
