                sendMobileToolResult(
                    requestId = requestId,
                    protocol = protocol,
                    conversationId = conversationId,
                    ok = false,
                    tool = "device.save_image_to_gallery",
                    data = null,
                    errorCode = "EXECUTION_FAILED",
                    errorMessage = e.message ?: "保存到相册失败",
                    retryable = true
                )
            }
        }
    }

    @Suppress("UNUSED_PARAMETER")
    private suspend fun getCurrentLocationCompat(timeoutMs: Long, requiresFine: Boolean): Location? {
        val context = requireContext()
        val locationManager = context.getSystemService(Context.LOCATION_SERVICE) as? LocationManager ?: return null
        val providers = mutableListOf<String>()
        val gpsEnabled = runCatching { locationManager.isProviderEnabled(LocationManager.GPS_PROVIDER) }.getOrDefault(false)
        val networkEnabled = runCatching { locationManager.isProviderEnabled(LocationManager.NETWORK_PROVIDER) }.getOrDefault(false)
        // 无论 accuracy 传参为何，默认优先使用 NETWORK 提升成功率。

        if (networkEnabled) providers.add(LocationManager.NETWORK_PROVIDER)
        if (gpsEnabled) providers.add(LocationManager.GPS_PROVIDER)
        if (providers.isEmpty()) return null

        val provider = providers.first()
        return kotlinx.coroutines.suspendCancellableCoroutine { cont ->
            val handler = Handler(Looper.getMainLooper())
            var completed = false
            var listenerRef: LocationListener? = null

            fun complete(location: Location?) {
                if (completed) return
                completed = true
                listenerRef?.let {
                    runCatching { locationManager.removeUpdates(it) }
                }
                handler.removeCallbacksAndMessages(null)
                if (cont.isActive) cont.resume(location)
            }

            handler.postDelayed({ complete(null) }, timeoutMs)

            if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.R) {
                val executor = ContextCompat.getMainExecutor(context)
                runCatching {
                    locationManager.getCurrentLocation(provider, null, executor) { loc ->
                        complete(loc)
                    }
                }.onFailure {
                    complete(null)
                }
            } else {
                val listener = object : LocationListener {
                    override fun onLocationChanged(location: Location) {
                        complete(location)
                    }
                }
                listenerRef = listener
                runCatching {
                    @Suppress("DEPRECATION")
                    locationManager.requestSingleUpdate(provider, listener, Looper.getMainLooper())
                }.onFailure {
                    complete(null)
                }
            }

            cont.invokeOnCancellation {
                listenerRef?.let { listener ->
                    runCatching { locationManager.removeUpdates(listener) }
                }
                handler.removeCallbacksAndMessages(null)
            }
        }
    }

    private fun sendMobileToolAck(
        requestId: String,
        protocol: String,
        conversationId: String,
        accepted: Boolean
    ) {
        sendMobileToolEnvelope(
            type = "mobile_tool_ack",
            requestId = requestId,
            protocol = protocol,
            conversationId = conversationId,
            payload = JSONObject().apply {
                put("accepted", accepted)
                put("queue_position", 0)
            }
        )
    }

    private fun sendMobileToolEvent(
        requestId: String,
        protocol: String,
        conversationId: String,
        event: String,
        detail: JSONObject
    ) {
        sendMobileToolEnvelope(
            type = "mobile_tool_event",
            requestId = requestId,
            protocol = protocol,
            conversationId = conversationId,
            payload = JSONObject().apply {
                put("event", event)
                put("detail", detail)
            }
        )
    }

    private fun sendMobileToolResult(
        requestId: String,
        protocol: String,
        conversationId: String,
        ok: Boolean,
        tool: String,
        data: JSONObject?,
        errorCode: String?,
        errorMessage: String?,
        retryable: Boolean
    ) {
        sendMobileToolEnvelope(
            type = "mobile_tool_result",
            requestId = requestId,
            protocol = protocol,
            conversationId = conversationId,
            payload = JSONObject().apply {
                put("ok", ok)
                put("tool", tool)
                put("data", data ?: JSONObject.NULL)
                if (!ok) {
                    put("error", JSONObject().apply {
                        put("code", errorCode ?: "INTERNAL_ERROR")
                        put("message", errorMessage ?: "unknown error")
                        put("retryable", retryable)
                    })
                } else {
                    put("error", JSONObject.NULL)
                }
            }
        )
    }

    private fun sendMobileToolEnvelope(
        type: String,
        requestId: String,
        protocol: String,
        conversationId: String,
        payload: JSONObject
    ) {
        try {
            val ws = (activity as? MainActivity)?.getCustomerServiceWebSocket()
            if (ws == null) {
                Log.w(TAG, "sendMobileToolEnvelope: websocket 不可用, type=$type, requestId=$requestId")
                return
            }
            val message = JSONObject().apply {
                put("type", type)
                put("protocol", protocol.ifBlank { "mobile_tool/v1" })
                put("request_id", requestId)
                put("conversation_id", conversationId)
                put("timestamp", isoTimestampNowUtc())
                put("payload", payload)
            }
            ws.sendCustomMessage(message)
        } catch (e: Exception) {
            Log.e(TAG, "sendMobileToolEnvelope 异常: ${e.message}", e)
        }
    }

    private fun sendCrossDeviceGuiTaskProbeAck(
        requestId: String,
        ok: Boolean,
        error: String?
    ) {
        try {
            val ws = (activity as? MainActivity)?.getCustomerServiceWebSocket()
            if (ws == null) {
                Log.w(TAG, "sendCrossDeviceGuiTaskProbeAck: websocket 不可用, requestId=$requestId")
                return
            }
            val content = JSONObject().apply {
                put("request_id", requestId)
                put("ok", ok)
                if (!error.isNullOrBlank()) put("error", error)
            }.toString()
            val message = JSONObject().apply {
                put("type", "cross_device_message")
                put("message_type", "gui_task_probe_ack")
                put("content", content)
                put("timestamp", isoTimestampNowUtc())
            }
            ws.sendCustomMessage(message)
        } catch (e: Exception) {
            Log.e(TAG, "sendCrossDeviceGuiTaskProbeAck 异常: ${e.message}", e)
        }
    }

    private fun isoTimestampNowUtc(): String {
        val sdf = java.text.SimpleDateFormat("yyyy-MM-dd'T'HH:mm:ss.SSS'Z'", java.util.Locale.US)
        sdf.timeZone = java.util.TimeZone.getTimeZone("UTC")
        return sdf.format(java.util.Date())
    }
    
    /**
     * 执行 PC 端发起的自定义小助手指令（need_execution 后自动推送）
     * 使用 assistantBaseUrl 的 upload 接口，在对应小助手上下文中执行
     */
    fun executePcExecuteCommandForCustomAssistant(
        assistantBaseUrl: String,
        query: String,
        chatSummary: String?,
        execUuid: String,
        messageId: String,
        conversationId: String?
    ) {
        Log.d(TAG, "executePcExecuteCommandForCustomAssistant: baseUrl=$assistantBaseUrl, query=$query, conversationId=$conversationId")
        if (!isAdded || _binding == null) {
            Log.e(TAG, "executePcExecuteCommandForCustomAssistant: Fragment 未就绪，无法执行")
            return
        }
        assistantPcExecuteContext = AssistantPcExecuteContext(execUuid, messageId, conversationId)
        isCustomAssistantProcessing = true
        updateButtonVisibility()
        addChatMessage("系统", "收到 PC 端指令，开始执行...")
        val syntheticAssistant = CustomAssistantManager.CustomAssistant(
            id = "pc_execute_$execUuid",
            name = "PC端执行",
            intro = "",
            baseUrl = if (assistantBaseUrl.endsWith("/")) assistantBaseUrl else "$assistantBaseUrl/",
            capabilities = listOf(CustomAssistantManager.CAP_EXECUTION_MOBILE),
            avatar = null
        )
        beginCustomAssistantExecutionWithPermissionGate(syntheticAssistant, query, chatSummary, guiExecuteContext = null)
    }

    /**
     * 处理 GUI 执行请求（来自 Chat WebSocket 的 gui_execute_request）
     * 执行完成后通过 sendResult 回传 gui_execute_result。
     * 始终在用户当前选中的 session 内执行，不因 threadId 切换 session（与 PC 端线程可不一致）。
     */
    fun handleGuiExecuteRequest(
        baseUrl: String,
        threadId: String,
        requestId: String,
        query: String,
        chatSummary: String?,
        sendResult: (content: String?, error: String?) -> Unit
    ) {
        Log.d(TAG, "handleGuiExecuteRequest: baseUrl=$baseUrl, threadId=$threadId, requestId=$requestId")
        if (!isAdded || _binding == null) {
            Log.e(TAG, "handleGuiExecuteRequest: Fragment 未就绪")
            sendResult(null, "Fragment 未就绪")
            return
        }
        isCustomAssistantProcessing = true
        updateButtonVisibility()
        addChatMessage("系统", "收到 GUI 执行请求，开始执行...")
        val syntheticAssistant = CustomAssistantManager.CustomAssistant(
            id = "gui_exec_$requestId",
            name = "GUI执行",
            intro = "",
            baseUrl = if (baseUrl.endsWith("/")) baseUrl else "$baseUrl/",
            capabilities = listOf(CustomAssistantManager.CAP_EXECUTION_MOBILE),
            avatar = null
        )
        beginCustomAssistantExecutionWithPermissionGate(
            syntheticAssistant,
            query,
            chatSummary,
            guiExecuteContext = AssistantGuiExecuteContext(
                requestId = requestId,
                threadId = threadId.takeIf { it.isNotBlank() },
                sendResult = sendResult
            )
        )
    }
    
    /**
     * 执行远程控制指令
     */
    private fun executeRemoteCommand(groupId: String, command: String, senderImei: String) {
        mainScope.launch(Dispatchers.Main) {
            if (!isAdded || _binding == null) {
                Log.w(TAG, "Fragment未附加或binding为null，延迟处理远程指令")
                delay(500)
                if (!isAdded || _binding == null) return@launch
            }
            
            // 确保当前对话是群组对话
            val groupConversationId = "group_$groupId"
            val group = GroupManager.getGroup(requireContext(), groupId)
            val groupName = group?.name ?: "群组"
            
            if (currentConversation?.id != groupConversationId) {
                // 如果当前不是群组对话，通过MainActivity切换到群组对话
                val mainActivity = activity as? MainActivity
                if (mainActivity != null) {
                    val groupConversation = Conversation(
                        id = groupConversationId,
                        name = groupName,
                        avatar = null,
                        lastMessage = command,
                        lastMessageTime = System.currentTimeMillis()
                    )
                    mainActivity.switchToChatFragment(groupConversation)
                    // 等待Fragment切换完成
                    delay(300)
                    // 重新获取当前Fragment（可能是新的Fragment实例）
                    val newFragment = mainActivity.supportFragmentManager.fragments.find { it is ChatFragment } as? ChatFragment
                    if (newFragment != null && newFragment != this@ChatFragment) {
                        // 如果创建了新的Fragment，在新Fragment中执行
                        newFragment.executeRemoteCommandDirectly(groupId, command, senderImei)
                        return@launch
                    }
                }
                // 如果无法切换，更新当前对话信息
                currentConversation = Conversation(
                    id = groupConversationId,
                    name = groupName,
                    avatar = null,
                    lastMessage = command,
                    lastMessageTime = System.currentTimeMillis()
                )
            }
            
            addChatMessage("系统", "收到远程执行指令，开始执行...")
            
            // 远程指令需要自动添加 @TopoClaw 前缀（如果还没有的话）
            val finalCommand = if (!ChatConstants.containsRemoteStyleAssistantMention(command)) {
                "@${ChatConstants.ASSISTANT_DISPLAY_NAME} $command"
            } else {
                command
            }
            Log.d(TAG, "远程指令处理: 原始command=$command, 最终command=$finalCommand")
            
            // 保存群组上下文，用于后续发送结果回群组
            // originalConversation 保持为群组对话本身，这样执行完成后会回到群组
            assistantGroupContext = AssistantGroupContext(groupId, currentConversation, finalCommand, senderImei)
            Log.d(TAG, "已设置远程指令群组上下文 - groupId: $groupId, command: $finalCommand, senderImei: $senderImei")
            
            // 执行指令（使用executeQueryInternal，它会调用小助手API，但结果会通过assistantGroupContext返回到群组）
            executeQueryInternal(finalCommand)
        }
    }
    
