    override fun onPause() {
        super.onPause()
        // 检查Fragment是否还存在
        if (!isAdded || activity == null) return
        cancelPendingClearUnread("onPause")
        
        // 清除当前对话ID
        val mainActivity = activity as? MainActivity
        mainActivity?.setCurrentConversationId(null)
        
        // 注意：不要清除WebSocket消息监听回调
        // 因为好友消息需要全局接收，即使不在好友对话页面也应该能接收消息
        // 回调会在下一个Fragment的onResume中重新设置，或者由MainActivity统一管理
        // 如果清除回调，好友消息会丢失
        
        // 保存聊天记录（在离开页面时保存，取消防抖直接保存，使用commit确保同步）
        // 通过 ViewModel 保存，确保数据一致性
        try {
            saveJob?.cancel() // 取消防抖任务
            // 同步 adapter 数据到 ViewModel，然后保存
            syncAdapterToViewModel()
            saveChatMessages(sync = true) // 立即同步保存
            Log.d(TAG, "onPause: 已通过 ViewModel 保存聊天记录")
        } catch (e: Exception) {
            Log.w(TAG, "保存聊天记录失败: ${e.message}", e)
        }
        
        // 注意：当使用hide/add时，Fragment不会进入onPause，所以这里只在真正离开时执行
        // 注意：ActionBar和底部导航栏的显示由updateUIForCurrentFragment()统一管理，避免重复设置导致"跳一下"
        // 这里不再单独设置，让MainActivity的onBackStackChangedListener统一处理
    }
    
    /**
     * 当Fragment的隐藏状态改变时调用（使用hide/show时）
     * 当从ConversationProfileFragment返回时，Fragment会从隐藏变为显示
     */
    override fun onHiddenChanged(hidden: Boolean) {
        super.onHiddenChanged(hidden)
        
        var vmReloadTriggered = false
        // 当Fragment被隐藏时，清除当前对话ID，确保弹窗能正常显示
        if (hidden) {
            cancelPendingClearUnread("onHiddenChanged(hidden=true)")
            if (currentConversation?.id?.startsWith("friend_") == true) {
                friendPrefsReloadWhenBecomeVisible = true
            }
            prefsReloadNeededOnShow = true
            Log.d(TAG, "Fragment被隐藏，清除currentConversationId")
            val mainActivity = activity as? MainActivity
            mainActivity?.setCurrentConversationId(null)
            
            // Fragment被隐藏时，禁用回退回调（避免拦截系统返回键）
            onBackPressedCallback?.isEnabled = false
            Log.d(TAG, "Fragment被隐藏，禁用回退回调")
            
            // 保存聊天记录（hide/show时不会触发onPause，需要在这里保存，使用同步保存）
            // 通过 ViewModel 保存，确保数据一致性
            try {
                saveJob?.cancel()
                // 同步 adapter 数据到 ViewModel，然后保存
                syncAdapterToViewModel()
                saveChatMessages(sync = true)
                Log.d(TAG, "onHiddenChanged: 已通过 ViewModel 保存聊天记录")
            } catch (e: Exception) {
                Log.w(TAG, "保存聊天记录失败: ${e.message}", e)
            }
        } else {
            // Fragment显示时，重新设置当前对话ID
            Log.d(TAG, "Fragment显示，设置currentConversationId")
            val mainActivity = activity as? MainActivity
            currentConversation?.id?.let { conversationId ->
                mainActivity?.setCurrentConversationId(conversationId)

                // hide/show 模式不经过 onResume，这里同样走延迟清未读，避免自动恢复时立即清零
                scheduleClearUnreadForCurrentConversation("onHiddenChanged")

                if (conversationId.startsWith("friend_") && friendPrefsReloadWhenBecomeVisible) {
                    friendPrefsReloadWhenBecomeVisible = false
                    prefsReloadNeededOnShow = false
                    vmReloadTriggered = true
                    reloadMessagesFromPrefsAfterExternalWrite()
                } else if (prefsReloadNeededOnShow) {
                    prefsReloadNeededOnShow = false
                    vmReloadTriggered = true
                    reloadMessagesFromPrefsAfterExternalWrite()
                }
            }
            
            // Fragment显示时，确保回退回调已注册并启用
            if (isAdded && activity != null && view != null) {
                if (onBackPressedCallback == null) {
                    // 如果回调未注册，重新注册
                    Log.d(TAG, "Fragment显示，回退回调未注册，重新注册")
                    onBackPressedCallback = object : OnBackPressedCallback(true) {
                        override fun handleOnBackPressed() {
                            // 使用和返回按钮相同的逻辑
                            handleBackPress()
                        }
                    }
                    requireActivity().onBackPressedDispatcher.addCallback(viewLifecycleOwner, onBackPressedCallback!!)
                } else {
                    // 如果回调已存在，确保启用
                    onBackPressedCallback?.isEnabled = true
                    Log.d(TAG, "Fragment显示，启用回退回调")
                }
            }
        }
        
        if (!hidden && isAdded && activity != null) {
            // Fragment变为可见时，立即隐藏导航栏（避免从其他页面返回时导航栏仍然显示）
            (activity as? MainActivity)?.setBottomNavigationVisibility(false)
            // 重置导航栏隐藏标志，确保updateActionBarAndNavigation能正常工作
            isNavigationBarHidden = false
            
            // Fragment变为可见时，延迟更新UI，避免阻塞Fragment切换动画
            view?.post {
                // 确保UI正确显示
                updateActionBarAndNavigation()
                
                // 检查是否需要恢复聊天记录（使用hide/show时不会触发onPause/onResume）
                // 如果 ViewModel 重载已经被触发，跳过所有旧路径，避免双路径导致消息重复
                if (vmReloadTriggered) {
                    Log.d(TAG, "onHiddenChanged: ViewModel 重载已触发，跳过旧恢复路径（避免重复）")
                    triggerFallbackRestoreIfNeeded("onHiddenChanged")
                } else {
                    val fromOverlayRecording = arguments?.getBoolean("fromOverlayRecording", false) ?: false
                    if (currentConversation != null && !fromOverlayRecording && !isRestoringMessages) {
                        val adapter = chatAdapter
                        val adapterHasItems = adapter != null && adapter.getItems().isNotEmpty()

                        if (chatMessages.isEmpty()) {
                            if (adapterHasItems && adapter != null) {
                                Log.d(TAG, "onHiddenChanged: chatMessages为空但adapter有${adapter.getItems().size}条消息，从adapter恢复数据")
                                val items = adapter.getItems()
                                items.forEach { item ->
                                    if (item is ChatItem.Message) {
                                        val chatMessage = ChatMessage(
                                            sender = item.sender,
                                            message = item.message,
                                            type = when {
                                                item.isUserMessage -> "user"
                                                item.isComplete -> "complete"
                                                item.isAnswer -> "answer"
                                                else -> "system"
                                            },
                                            timestamp = item.timestamp,
                                            uuid = "",
                                            senderImei = item.senderImei
                                        )
                                        val messageHash = messageHashForDedup(chatMessage)
                                        if (!messageHashSet.contains(messageHash)) {
                                            chatMessages.add(chatMessage)
                                            messageHashSet.add(messageHash)
                                        }
                                    }
                                }
                                Log.d(TAG, "onHiddenChanged: 从adapter恢复了${chatMessages.size}条消息到chatMessages")
                            } else {
                                Log.d(TAG, "onHiddenChanged: 检测到聊天记录为空且adapter也为空，开始恢复")
                                mainScope.launch {
                                    restoreChatMessages()
                                }
                            }
                        } else if (adapterHasItems && adapter != null) {
                            val adapterSize = adapter.getItems().size
                            val messagesSize = chatMessages.size
                            if (kotlin.math.abs(adapterSize - messagesSize) > 5) {
                                Log.d(TAG, "onHiddenChanged: 检测到数据不一致（adapter: $adapterSize, chatMessages: $messagesSize），重新恢复")
                                mainScope.launch {
                                    restoreChatMessages()
                                }
                            } else {
                                Log.d(TAG, "onHiddenChanged: 数据一致（adapter: $adapterSize, chatMessages: $messagesSize），跳过恢复")
                            }
                        }
                    }
                }
            }
            
            // 优化RecyclerView性能：在Fragment切换时暂时禁用动画
            optimizeRecyclerViewForTransition(false)
        } else if (hidden) {
            // Fragment被隐藏时，优化RecyclerView性能
            optimizeRecyclerViewForTransition(true)
        }
    }

    private fun cancelPendingClearUnread(reason: String) {
        val active = clearUnreadJob?.isActive == true
        clearUnreadJob?.cancel()
        clearUnreadJob = null
        if (active) {
            Log.d(TAG, "取消延迟清未读任务: $reason")
        }
    }

    private fun scheduleClearUnreadForCurrentConversation(reason: String) {
        val conversationId = currentConversation?.id ?: return
        cancelPendingClearUnread("reschedule($reason)")
        clearUnreadJob = mainScope.launch {
            delay(CLEAR_UNREAD_DELAY_MS)
            if (!isAdded || isHidden || view == null || activity == null) {
                Log.d(TAG, "跳过清除会话未读($reason): Fragment当前不可见")
                return@launch
            }
            val mainActivity = activity as? MainActivity
            val activeConversationId = mainActivity?.getCurrentConversationId()
            if (activeConversationId != conversationId) {
                Log.d(TAG, "跳过清除会话未读($reason): 当前会话不匹配 active=$activeConversationId target=$conversationId")
                return@launch
            }

            ConversationSessionNotifier.clearUnread(requireContext(), conversationId)
            Log.d(TAG, "已清除会话未读(延迟${CLEAR_UNREAD_DELAY_MS}ms,$reason): $conversationId")
            if (conversationId == ConversationListFragment.CONVERSATION_ID_CUSTOMER_SERVICE) {
                updateUnreadBadge()
            }
            try {
                val conversationListFragment = parentFragmentManager.fragments.find { it is ConversationListFragment } as? ConversationListFragment
                conversationListFragment?.loadConversations()
            } catch (e: Exception) {
                Log.w(TAG, "通知对话列表更新失败: ${e.message}")
            }
        }
    }
    
    /**
     * 处理返回操作（返回按钮和系统返回键共用）
     */
    internal fun handleBackPress() {
        // 检查Fragment是否还存在
        if (_binding == null || !isAdded || activity == null) return
        
        // 如果输入法下拉栏打开，先收起下拉栏，不执行回退
        if (isEmojiPanelVisible || isMediaPanelVisible || isVoicePanelVisible) {
            if (isEmojiPanelVisible) {
                hideEmojiPanel()
            }
            if (isMediaPanelVisible) {
                hideMediaPanel()
            }
            if (isVoicePanelVisible) {
                hideVoicePanel()
            }
            return
        }
        
        // 如果处于多选模式，先退出多选模式
        if (isMultiSelectMode) {
            exitMultiSelectMode()
            return
        }
        
        // 检查 FragmentManager 状态
        if (!parentFragmentManager.isStateSaved) {
            try {
                // 检查是否是从通讯录（FriendFragment）进入的
                val fromFriendFragment = arguments?.getBoolean("from_friend_fragment", false) == true
                if (fromFriendFragment) {
                    // 查找隐藏的FriendFragment
                    val friendFragment = parentFragmentManager.fragments.find { it is FriendFragment && it.isHidden }
                    if (friendFragment != null) {
                        // FriendFragment被隐藏了，显示它并隐藏当前Fragment（会触发动画）
                        parentFragmentManager.beginTransaction()
                            .setCustomAnimations(
                                R.anim.slide_in_from_left,   // popEnter: 通讯录从左侧滑入
                                R.anim.slide_out_to_right    // popExit: 聊天详情页向右滑出
                            )
                            .hide(this@ChatFragment)
                            .show(friendFragment)
                            .commitAllowingStateLoss()
                        // 手动更新UI
                        (activity as? MainActivity)?.window?.decorView?.postDelayed({
                            (activity as? MainActivity)?.updateUIForCurrentFragment()
                        }, 100)
                        // 设置底部导航栏选中通讯录项
                        (activity as? MainActivity)?.window?.decorView?.post {
                            (activity as? MainActivity)?.let { mainActivity ->
                                try {
                                    mainActivity.setBottomNavigationSelectedItem(R.id.nav_friend)
                                } catch (e: Exception) {
                                    Log.w(TAG, "更新UI状态失败: ${e.message}", e)
                                }
                            }
                        }
                        return
                    } else {
                        // 如果没有找到隐藏的FriendFragment，尝试使用popBackStack
                        if (parentFragmentManager.backStackEntryCount > 0) {
                            try {
                                parentFragmentManager.popBackStack()
                                // 设置底部导航栏选中通讯录项
                                (activity as? MainActivity)?.window?.decorView?.post {
                                    (activity as? MainActivity)?.let { mainActivity ->
                                        try {
                                            mainActivity.setBottomNavigationSelectedItem(R.id.nav_friend)
                                        } catch (e: Exception) {
                                            Log.w(TAG, "更新UI状态失败: ${e.message}", e)
                                        }
                                    }
                                }
                                return
                            } catch (e: Exception) {
                                Log.e(TAG, "popBackStack失败: ${e.message}", e)
                                (activity as? MainActivity)?.let { mainActivity ->
                                    mainActivity.switchToTabFragment(R.id.nav_friend) { FriendFragment() }
                                    mainActivity.window.decorView.post {
                                        mainActivity.setBottomNavigationSelectedItem(R.id.nav_friend)
                                    }
                                }
                                return
                            }
                        } else {
                            Log.d(TAG, "返回栈为空，切换到通讯录页面")
                            (activity as? MainActivity)?.let { mainActivity ->
                                mainActivity.switchToTabFragment(R.id.nav_friend) { FriendFragment() }
                                mainActivity.window.decorView.post {
                                    mainActivity.setBottomNavigationSelectedItem(R.id.nav_friend)
                                }
                            }
                            return
                        }
                    }
                }
                
                // 检查返回栈中是否有对话列表的entry（通过检查返回栈entry的名称）
                val hasConversationListInBackStack = (0 until parentFragmentManager.backStackEntryCount).any { index ->
                    try {
                        val entry = parentFragmentManager.getBackStackEntryAt(index)
                        entry.name == "conversation_list" || entry.name == null
                    } catch (e: Exception) {
                        false
                    }
                }
                
                // 或者检查当前fragments中是否有ConversationListFragment
                val hasConversationListFragment = try {
                    parentFragmentManager.fragments.any { it is ConversationListFragment }
                } catch (e: Exception) {
                    false
                }
                
                if (hasConversationListInBackStack || hasConversationListFragment) {
                    // 有对话列表在返回栈中，使用popBackStack触发返回动画
                    // 或者如果ConversationListFragment被隐藏了，显示它并隐藏当前Fragment
                    val conversationListFragment = parentFragmentManager.fragments.find { it is ConversationListFragment && it.isHidden }
                    if (conversationListFragment != null) {
                        // ConversationListFragment被隐藏了，显示它并隐藏当前Fragment（会触发动画）
                        parentFragmentManager.beginTransaction()
                            .setCustomAnimations(
                                R.anim.slide_in_from_left,   // popEnter: 聊天主页从左侧滑入
                                R.anim.slide_out_to_right    // popExit: 聊天详情页向右滑出
                            )
                            .hide(this@ChatFragment)
                            .show(conversationListFragment)
                            .commitAllowingStateLoss()
                        // 由于hide/show不会触发onBackStackChangedListener，需要手动更新UI
                        // 注意：updateUIForCurrentFragment() 已经会正确处理底部导航栏的显示/隐藏
                        // 对于 ConversationListFragment，它会隐藏 Activity 层级的底部导航栏（因为使用 Fragment 层级的）
                        (activity as? MainActivity)?.window?.decorView?.postDelayed({
                            (activity as? MainActivity)?.updateUIForCurrentFragment()
                        }, 100)
                    } else if (parentFragmentManager.backStackEntryCount > 0) {
                        // 使用popBackStack触发返回动画
                        try {
                            parentFragmentManager.popBackStack()
                        } catch (e: Exception) {
                            Log.e(TAG, "popBackStack失败: ${e.message}", e)
                            (activity as? MainActivity)?.switchToTabFragment(R.id.nav_chat) { ConversationListFragment() }
                        }
                    } else {
                        Log.d(TAG, "返回栈为空，切换到对话列表页面")
                        (activity as? MainActivity)?.switchToTabFragment(R.id.nav_chat) { ConversationListFragment() }
                    }
                    // 注意：ActionBar和底部导航栏的显示由updateUIForCurrentFragment()统一管理
                    // 使用post确保Fragment切换完成后再更新选中项
                    (activity as? MainActivity)?.window?.decorView?.post {
                        (activity as? MainActivity)?.let { mainActivity ->
                            try {
                                mainActivity.setBottomNavigationSelectedItem(R.id.nav_chat)
                            } catch (e: Exception) {
                                Log.w(TAG, "更新UI状态失败: ${e.message}", e)
                            }
                        }
                    }
                } else if (parentFragmentManager.backStackEntryCount > 0) {
                    // 没有对话列表，但有返回栈，弹出（会触发popEnter和popExit动画）
                    try {
                        parentFragmentManager.popBackStack()
                    } catch (e: Exception) {
                        Log.e(TAG, "popBackStack失败: ${e.message}", e)
                        (activity as? MainActivity)?.switchToTabFragment(R.id.nav_chat) { ConversationListFragment() }
                    }
                } else {
                    Log.d(TAG, "返回栈为空，切换到对话列表页面")
                    (activity as? MainActivity)?.switchToTabFragment(R.id.nav_chat) { ConversationListFragment() }
                    // 注意：ActionBar和底部导航栏的显示由updateUIForCurrentFragment()统一管理
                    // 使用post确保Fragment切换完成后再更新选中项
                    (activity as? MainActivity)?.window?.decorView?.post {
                        (activity as? MainActivity)?.let { mainActivity ->
                            try {
                                mainActivity.setBottomNavigationSelectedItem(R.id.nav_chat)
                            } catch (e: Exception) {
                                Log.w(TAG, "更新UI状态失败: ${e.message}", e)
                            }
                        }
                    }
                }
            } catch (e: Exception) {
                Log.e(TAG, "返回失败: ${e.message}", e)
            }
        } else {
            // FragmentManager 状态已保存，无法执行事务
            Log.w(TAG, "FragmentManager状态已保存，无法执行返回操作")
        }
    }
    
