    /**
     * 显示用户筛选弹窗（管理员模式）
     */
    internal fun showUserFilterDialog() {
        if (allUserImeis.isEmpty()) {
            android.widget.Toast.makeText(requireContext(), "暂无用户数据", android.widget.Toast.LENGTH_SHORT).show()
            return
        }
        
        // 异步获取在线用户列表
        mainScope.launch {
            try {
                // 获取客服服务地址
                val prefs = requireContext().getSharedPreferences("app_prefs", android.content.Context.MODE_PRIVATE)
                val conversationId = ConversationListFragment.CONVERSATION_ID_CUSTOMER_SERVICE
                val specificKey = "chat_server_url_$conversationId"
                val customerServiceUrl = prefs.getString(specificKey, null)
                    ?: prefs.getString("customer_service_url", null)
                    ?: ServiceUrlConfig.DEFAULT_CUSTOMER_SERVICE_URL
                
                CustomerServiceNetwork.initialize(customerServiceUrl)
                val apiService = CustomerServiceNetwork.getApiService()
                
                val onlineUsers = if (apiService != null) {
                    try {
                        val response = apiService.getOnlineUsers()
                        if (response.isSuccessful && response.body()?.success == true) {
                            response.body()?.users ?: emptyList()
                        } else {
                            emptyList()
                        }
                    } catch (e: Exception) {
                        Log.w(TAG, "获取在线用户列表失败: ${e.message}")
                        emptyList()
                    }
                } else {
                    emptyList()
                }
                
                // 在主线程显示对话框
                withContext(Dispatchers.Main) {
                    // 创建数据列表：包含所有用户IMEI，并标记在线状态
                    val dialogItemsWithStatus = allUserImeis.map { imei ->
                        Pair(imei, onlineUsers.contains(imei))
                    }
                    
                    // 排序：在线用户排在前面
                    val sortedDialogItems = dialogItemsWithStatus.sortedByDescending { it.second }
                    val sortedImeis = sortedDialogItems.map { it.first }
                    
                    // 创建IMEI到原始索引的映射（用于保持选中状态）
                    val imeiToOriginalIndex = allUserImeis.mapIndexed { index, imei -> imei to index }.toMap()
                    
                    // 当前已选中的用户（基于排序后的列表）
                    val selectedItems = BooleanArray(sortedImeis.size) { index ->
                        val imei = sortedImeis[index]
                        filteredImeis.contains(imei)
                    }
                    
                    // 创建自定义Adapter用于多选对话框
                    val adapter = object : ArrayAdapter<Pair<String, Boolean>>(
                        requireContext(),
                        android.R.layout.simple_list_item_multiple_choice
                    ) {
                        override fun getView(position: Int, convertView: View?, parent: ViewGroup): View {
                            // 使用系统布局，但需要找到TextView来设置文本
                            val view = if (convertView != null) {
                                convertView
                            } else {
                                android.view.LayoutInflater.from(context).inflate(
                                    android.R.layout.simple_list_item_multiple_choice,
                                    parent,
                                    false
                                )
                            }
                            
                            val textView = view.findViewById<android.widget.TextView>(android.R.id.text1)
                            val item = getItem(position)!!
                            
                            // 用户IMEI选项
                            val imei = item.first
                            val isOnline = item.second
                            
                            // 设置IMEI文本颜色
                            if (isOnline) {
                                // 在线用户：IMEI显示为黄色
                                textView.setTextColor(android.graphics.Color.parseColor("#FFD700")) // 黄色
                            } else {
                                // 离线用户：默认颜色
                                textView.setTextColor(android.graphics.Color.parseColor("#000000")) // 黑色
                            }
                            
                            // 设置IMEI文本，确保不换行
                            textView.text = imei
                            textView.setSingleLine(true)
                            textView.ellipsize = android.text.TextUtils.TruncateAt.END
                            
                            // 获取textView的父布局
                            val parentLayout = textView.parent as? android.view.ViewGroup
                            
                            // 移除之前可能存在的"在线"标签
                            val existingTag = parentLayout?.findViewWithTag<android.widget.TextView>("online_tag")
                            existingTag?.let { parentLayout.removeView(it) }
                            
                            // 在线用户：添加"在线"标签（方块样式）
                            if (isOnline && parentLayout != null) {
                                val onlineTag = android.widget.TextView(context).apply {
                                    tag = "online_tag"
                                    text = "在线"
                                    textSize = 10f
                                    setTextColor(android.graphics.Color.parseColor("#FFD700")) // 黄色文字
                                    setPadding(
                                        (6 * resources.displayMetrics.density).toInt(),
                                        (2 * resources.displayMetrics.density).toInt(),
                                        (6 * resources.displayMetrics.density).toInt(),
                                        (2 * resources.displayMetrics.density).toInt()
                                    )
                                    gravity = android.view.Gravity.CENTER
                                    
                                    // 创建黄色背景的方块
                                    val drawable = android.graphics.drawable.GradientDrawable().apply {
                                        setColor(android.graphics.Color.parseColor("#FFFFE066")) // 浅黄色背景
                                        cornerRadius = 4f // 圆角
                                        setStroke(
                                            (1 * resources.displayMetrics.density).toInt(),
                                            android.graphics.Color.parseColor("#FFD700") // 黄色边框
                                        )
                                    }
                                    background = drawable
                                    
                                    // 设置布局参数，放在textView右侧
                                    if (parentLayout is android.widget.RelativeLayout) {
                                        layoutParams = android.widget.RelativeLayout.LayoutParams(
                                            android.widget.RelativeLayout.LayoutParams.WRAP_CONTENT,
                                            android.widget.RelativeLayout.LayoutParams.WRAP_CONTENT
                                        ).apply {
                                            addRule(android.widget.RelativeLayout.ALIGN_PARENT_END)
                                            addRule(android.widget.RelativeLayout.CENTER_VERTICAL)
                                            marginEnd = (8 * resources.displayMetrics.density).toInt()
                                        }
                                    } else if (parentLayout is android.widget.LinearLayout) {
                                        layoutParams = android.widget.LinearLayout.LayoutParams(
                                            android.widget.LinearLayout.LayoutParams.WRAP_CONTENT,
                                            android.widget.LinearLayout.LayoutParams.WRAP_CONTENT
                                        ).apply {
                                            marginStart = (8 * resources.displayMetrics.density).toInt()
                                        }
                                    }
                                }
                                parentLayout.addView(onlineTag)
                            }
                            
                            return view
                        }
                    }
                    
                    // 添加所有项目到Adapter（已排序，在线用户在前）
                    sortedDialogItems.forEach { adapter.add(it) }
                    
                    // 创建对话框
                    val dialogBuilder = android.app.AlertDialog.Builder(requireContext())
                        .setTitle("筛选用户（可多选）")
                        .setAdapter(adapter, null) // 先设置Adapter，但点击事件由ListView处理
                        .setPositiveButton("确定") { dialog, _ ->
                            val listView = (dialog as android.app.AlertDialog).listView
                            // 获取所有选中的用户（使用排序后的列表）
                            val selectedImeis = mutableListOf<String>()
                            for (i in 0 until listView.count) {
                                if (listView.isItemChecked(i)) {
                                    selectedImeis.add(sortedImeis[i])
                                }
                            }
                            
                            filteredImeis = selectedImeis
                            
                            // 自动设置selectedUserImei为第一个选中的用户（用于自动发送消息）
                            if (selectedImeis.isNotEmpty()) {
                                selectedUserImei = selectedImeis.first()
                                updateAdminInputHint()
                            } else {
                                selectedUserImei = null
                                updateAdminInputHint()
                            }
                            
                            // 更新筛选按钮文本
                            when {
                                selectedImeis.isEmpty() -> {
                                    binding.btnFilterUsers.text = "筛选用户"
                                }
                                selectedImeis.size == 1 -> {
                                    binding.btnFilterUsers.text = "筛选用户 (${selectedImeis.first()})"
                                }
                                else -> {
                                    binding.btnFilterUsers.text = "筛选用户 (${selectedImeis.size}个)"
                                }
                            }
                            
                            // 更新按钮可见性（确保筛选后输入框有内容时发送按钮显示）
                            updateButtonVisibility()
                            
                            // 重新加载聊天记录
                            mainScope.launch {
                                loadAllCustomerServiceChats(forceRefresh = true)
                            }
                        }
                        .setNegativeButton("取消", null)
                        .setNeutralButton("全选") { dialog, _ ->
                            val listView = (dialog as android.app.AlertDialog).listView
                            // 全选所有用户
                            for (i in 0 until listView.count) {
                                listView.setItemChecked(i, true)
                            }
                        }
                    
                    val dialog = dialogBuilder.create()
                    
                    // 设置ListView为多选模式
                    dialog.setOnShowListener {
                        val listView = dialog.listView
                        listView.choiceMode = android.widget.AbsListView.CHOICE_MODE_MULTIPLE
                        
                        // 设置初始选中状态（基于排序后的列表）
                        for (i in selectedItems.indices) {
                            listView.setItemChecked(i, selectedItems[i])
                        }
                    }
                    
                    dialog.show()
                }
            } catch (e: Exception) {
                Log.e(TAG, "显示筛选用户对话框失败: ${e.message}", e)
                withContext(Dispatchers.Main) {
                    android.widget.Toast.makeText(requireContext(), "获取在线状态失败: ${e.message}", android.widget.Toast.LENGTH_SHORT).show()
                }
            }
        }
    }
    
    /**
     * 更新管理员模式下的输入框提示
     */
    private fun updateAdminInputHint() {
        if (currentConversation?.id == ConversationListFragment.CONVERSATION_ID_ADMIN_CUSTOMER_SERVICE) {
            val hint = if (selectedUserImei != null) {
                "回复用户: ${selectedUserImei!!.take(8)}..."
            } else {
                "点击用户消息选择要回复的用户"
            }
            binding.etChatInput.hint = hint
        }
    }
    
    /**
     * 设置输入框文本变化监听
     */
    internal fun setupInputTextWatcher() {
        binding.etChatInput.addTextChangedListener(object : android.text.TextWatcher {
            override fun beforeTextChanged(s: CharSequence?, start: Int, count: Int, after: Int) {}
            
            override fun onTextChanged(s: CharSequence?, start: Int, before: Int, count: Int) {
                updateButtonVisibility()
                // 检测@符号
                checkForMention(s, start, before, count)
            }
            
            override fun afterTextChanged(s: android.text.Editable?) {}
        })
    }
    
    /**
     * 检测输入框中是否有@符号，如果有则显示候选列表
     */
    internal fun checkForMention(text: CharSequence?, start: Int, before: Int, count: Int) {
        if (text == null) {
            hideMentionPopup()
            return
        }
        
        // 只在群组对话中启用@提及功能
        val conversationId = currentConversation?.id
        val isGroup = conversationId?.startsWith("group_") == true || 
                      conversationId == ConversationListFragment.CONVERSATION_ID_GROUP
        
        if (!isGroup) {
            hideMentionPopup()
            return
        }
        
        // 获取光标位置
        val cursorPosition = binding.etChatInput.selectionStart
        if (cursorPosition < 0) {
            hideMentionPopup()
            return
        }
        
        // 从光标位置向前查找@符号
        var mentionStart = -1
        for (i in cursorPosition - 1 downTo 0) {
            if (i >= text.length) break
            val char = text[i]
            if (char == '@') {
                mentionStart = i
                break
            } else if (char == ' ' || char == '\n') {
                // 遇到空格或换行，说明@符号不在当前单词中
                break
            }
        }
        
        if (mentionStart >= 0) {
            // 找到了@符号，获取@后面的文本
            val query = if (cursorPosition > mentionStart + 1) {
                text.substring(mentionStart + 1, cursorPosition)
            } else {
                ""
            }
            
            currentMentionStart = mentionStart
            showMentionPopup(query)
        } else {
            // 没有找到@符号，隐藏候选列表
            hideMentionPopup()
        }
    }
    
    /**
     * 显示@提及候选列表
     */
    internal fun showMentionPopup(query: String) {
        // 获取群组成员候选列表
        val candidates = getGroupMentionCandidates(query)
        
        if (candidates.isEmpty()) {
            hideMentionPopup()
            return
        }
        
        mentionCandidates = candidates
        
        // 如果已有弹窗，先关闭
        mentionPopupWindow?.dismiss()
        
        // 加载布局
        val popupView = LayoutInflater.from(requireContext()).inflate(
            R.layout.popup_mention_list, null
        )
        val listView = popupView.findViewById<ListView>(R.id.lvMentionCandidates)
        
        // 创建适配器
        val adapter = object : android.widget.BaseAdapter() {
            override fun getCount(): Int = candidates.size
            
            override fun getItem(position: Int): MentionCandidate = candidates[position]
            
            override fun getItemId(position: Int): Long = position.toLong()
            
            override fun getView(position: Int, convertView: View?, parent: ViewGroup?): View {
                val view = convertView ?: LayoutInflater.from(requireContext())
                    .inflate(R.layout.item_mention_candidate, parent, false)
                
                val candidate = candidates[position]
                val tvName = view.findViewById<TextView>(R.id.tvName)
                val ivAvatar = view.findViewById<ImageView>(R.id.ivAvatar)
                
                // 设置显示名称
                val displayName = if (candidate.isAssistant) {
                    // TopoClaw：只显示名称，不显示IMEI
                    candidate.nickname ?: ChatConstants.ASSISTANT_DISPLAY_NAME
                } else {
                    // 其他好友：只显示昵称，如果没有昵称则显示IMEI
                    candidate.nickname ?: candidate.imei
                }
                tvName.text = displayName
                
                // 设置头像
                if (candidate.isAssistant) {
                    if (candidate.imei == ConversationListFragment.CONVERSATION_ID_ASSISTANT) {
                        ivAvatar.setImageResource(R.drawable.ic_assistant_avatar)
                    } else if (CustomAssistantManager.isCustomAssistantId(candidate.imei)) {
                        val assistant = CustomAssistantManager.getById(requireContext(), candidate.imei)
                        if (assistant != null) {
                            AvatarCacheManager.loadCustomAssistantAvatar(
                                context = requireContext(),
                                imageView = ivAvatar,
                                assistant = assistant,
                                cacheKey = "mention_candidate_${candidate.imei}",
                                validationTag = candidate.imei
                            )
                        } else {
                            ivAvatar.setImageResource(R.drawable.ic_system_avatar)
                        }
                    } else {
                        ivAvatar.setImageResource(R.drawable.ic_assistant_avatar)
                    }
                } else {
                    // 使用AvatarCacheManager加载候选对象头像，优先使用缓存避免闪烁
                    val cacheKey = "candidate_${candidate.imei}"
                    AvatarCacheManager.loadBase64Avatar(
                        context = requireContext(),
                        imageView = ivAvatar,
                        base64String = candidate.avatar,
                        defaultResId = R.drawable.ic_person,
                        cacheKey = cacheKey,
                        validationTag = candidate.imei
                    )
                }
                
                // 设置圆形头像
                ivAvatar.outlineProvider = object : android.view.ViewOutlineProvider() {
                    override fun getOutline(view: android.view.View, outline: android.graphics.Outline) {
                        outline.setOval(0, 0, view.width, view.height)
                    }
                }
                ivAvatar.clipToOutline = true
                
                // 设置点击监听器（因为布局中设置了clickable，需要手动处理点击事件）
                view.setOnClickListener {
                    if (position >= 0 && position < candidates.size) {
                        selectMentionCandidate(candidates[position])
                    }
                }
                
                return view
            }
        }
        
        listView.adapter = adapter
        
        // 设置列表项点击监听
        listView.setOnItemClickListener { _, _, position, _ ->
            if (position >= 0 && position < candidates.size) {
                selectMentionCandidate(candidates[position])
            }
        }
        
        // 计算弹窗大小
        val itemHeight = (56 * resources.displayMetrics.density).toInt() // 每个候选项的高度
        val maxHeight = itemHeight * 5 // 最多显示5个
        val totalHeight = itemHeight * candidates.size
        val listViewHeight = if (totalHeight > maxHeight) maxHeight else totalHeight
        
        // 计算宽度（与输入框宽度一致）
        val inputWidth = binding.etChatInput.width
        val popupWidth = if (inputWidth > 0) inputWidth else ViewGroup.LayoutParams.WRAP_CONTENT
        
        // 创建PopupWindow
        mentionPopupWindow = PopupWindow(
            popupView,
            popupWidth,
            listViewHeight,
            true // focusable
        )
        
        // 设置背景和样式
        mentionPopupWindow?.setBackgroundDrawable(
            ContextCompat.getDrawable(requireContext(), android.R.drawable.dialog_holo_light_frame)
        )
        mentionPopupWindow?.elevation = 8f
        
        // 设置外部点击关闭
        mentionPopupWindow?.isOutsideTouchable = true
        
        // 显示在输入框下方
        mentionPopupWindow?.showAsDropDown(binding.etChatInput, 0, 0, Gravity.START)
    }
    
    /**
     * 隐藏@提及候选列表
     */
    internal fun hideMentionPopup() {
        mentionPopupWindow?.dismiss()
        mentionPopupWindow = null
        currentMentionStart = -1
    }
    
    /**
     * 选择@提及候选对象
     */
    internal fun selectMentionCandidate(candidate: MentionCandidate) {
        val text = binding.etChatInput.text ?: return
        val mentionStart = currentMentionStart
        
        if (mentionStart < 0 || mentionStart >= text.length) {
            hideMentionPopup()
            return
        }
        
        // 构建要插入的文本
        val mentionText = if (candidate.isAssistant) {
            // TopoClaw：只插入名称，不显示IMEI
            "@${candidate.nickname ?: ChatConstants.ASSISTANT_DISPLAY_NAME}"
        } else {
            // 其他好友：实际发送的内容只显示IMEI
            "@${candidate.imei}"
        }
        
        // 找到@符号后到光标位置之间的文本，替换为mentionText
        val cursorPosition = binding.etChatInput.selectionStart
        val editable = android.text.Editable.Factory.getInstance().newEditable(text)
        
        // 删除@符号到光标位置之间的内容
        editable.delete(mentionStart, cursorPosition)
        
        // 插入新的@提及文本
        editable.insert(mentionStart, mentionText)
        
        // 更新输入框内容
        binding.etChatInput.setText(editable)
        
        // 将光标移到插入文本的末尾
        val newCursorPosition = mentionStart + mentionText.length
        binding.etChatInput.setSelection(newCursorPosition)
        
        // 隐藏候选列表
        hideMentionPopup()
    }
    
    /**
     * 获取群组@提及候选列表
     */
    internal fun getGroupMentionCandidates(query: String): List<MentionCandidate> {
        val conversationId = currentConversation?.id ?: return emptyList()
        
        val candidates = mutableListOf<MentionCandidate>()
        
        // 获取群组信息（用于判断是否显示小助手）
        val group = when {
            conversationId == ConversationListFragment.CONVERSATION_ID_GROUP -> {
                // 固定的"好友群"，获取所有好友
                val friends = FriendManager.getFriends(requireContext())
                    .filter { it.status == "accepted" }
                val currentImei = ProfileManager.getOrGenerateImei(requireContext())
                
                // 排除自己，添加好友到候选列表
                friends
                    .filter { it.imei != currentImei }
                    .forEach { friend ->
                        val candidate = MentionCandidate(
                            imei = friend.imei,
                            nickname = friend.nickname,
                            avatar = friend.avatar,
                            isAssistant = false
                        )
                        
                        // 根据query过滤
                        if (query.isEmpty() || 
                            candidate.nickname?.contains(query, ignoreCase = true) == true ||
                            candidate.imei.contains(query, ignoreCase = true)) {
                            candidates.add(candidate)
                        }
                    }
                
                return candidates
            }
            conversationId.startsWith("group_") -> {
                val groupId = conversationId.removePrefix("group_")
                GroupManager.getGroup(requireContext(), groupId)
            }
            else -> null
        }
        
        if (group == null) return candidates
        
        // 遍历群组内已添加的小助手（含TopoClaw、自定义小助手），加入 @ 候选列表
        val assistantIds = group.assistants.ifEmpty {
            if (group.assistantEnabled) listOf(ConversationListFragment.CONVERSATION_ID_ASSISTANT) else emptyList()
        }
        assistantIds.forEach { assistantId ->
            val (assistantName: String, avatar: String?) = when {
                assistantId == ConversationListFragment.CONVERSATION_ID_ASSISTANT -> {
                    getString(R.string.auto_execute_assistant) to null
                }
                CustomAssistantManager.isCustomAssistantId(assistantId) -> {
                    val custom = CustomAssistantManager.getById(requireContext(), assistantId)
                    if (custom != null) custom.name to custom.avatar else return@forEach
                }
                else -> return@forEach
            }
            if (query.isEmpty() || assistantName.contains(query, ignoreCase = true) || assistantId.contains(query, ignoreCase = true)) {
                candidates.add(
                    MentionCandidate(
                        imei = assistantId,
                        nickname = assistantName,
                        avatar = avatar,
                        isAssistant = true
                    )
                )
            }
        }
        
        val currentImei = ProfileManager.getOrGenerateImei(requireContext())
        
        // 遍历群组成员（排除自己）
        group.members.forEach { memberImei ->
            if (memberImei == currentImei) return@forEach
            
            // 获取成员信息
            val friend = FriendManager.getFriend(requireContext(), memberImei)
            
            val candidate = MentionCandidate(
                imei = memberImei,
                nickname = friend?.nickname,
                avatar = friend?.avatar,
                isAssistant = false
            )
            
            // 根据query过滤
            if (query.isEmpty() || 
                candidate.nickname?.contains(query, ignoreCase = true) == true ||
                candidate.imei.contains(query, ignoreCase = true)) {
                candidates.add(candidate)
            }
        }
        
        return candidates
    }
    
    /**
     * 检测消息是否 @ 提及了某群组内的某个小助手（自动执行或自定义），若匹配则返回其 ID
     * @param query 消息内容
     * @param groupConversationId 群组对话ID（group_xxx 或 CONVERSATION_ID_GROUP）。若为 null 则使用 currentConversation?.id（用于 performSendChatMessage 中 currentConversation 仍是群组时）。
     *                            在 executeQueryInternal 中若已有 assistantGroupContext，需传入 groupContext.originalConversation?.id，因此时 currentConversation 已切换为小助手。
     */
    internal fun findMentionedGroupAssistantId(query: String, groupConversationId: String? = null): String? {
        val conversationId = groupConversationId ?: currentConversation?.id ?: return null
        if (conversationId != ConversationListFragment.CONVERSATION_ID_GROUP && !conversationId.startsWith("group_")) return null
        
        val group = when {
            conversationId.startsWith("group_") -> {
                val groupId = conversationId.removePrefix("group_")
                GroupManager.getGroup(requireContext(), groupId)
            }
            else -> null
        } ?: return null
        
        val assistantIds = group.assistants.ifEmpty {
            if (group.assistantEnabled) listOf(ConversationListFragment.CONVERSATION_ID_ASSISTANT) else emptyList()
        }
        
        // 按名称长度降序，优先匹配更长名称（避免「功能测试」误匹配「功能测试小助手14」）
        val assistantsWithNames = assistantIds.mapNotNull { aid ->
            val name = when {
                aid == ConversationListFragment.CONVERSATION_ID_ASSISTANT -> getString(R.string.auto_execute_assistant)
                CustomAssistantManager.isCustomAssistantId(aid) -> CustomAssistantManager.getById(requireContext(), aid)?.name
                else -> null
            }
            if (name != null) aid to name else null
        }.sortedByDescending { it.second.length }
        
        for ((aid, name) in assistantsWithNames) {
            if (query.contains("@$name", ignoreCase = true)) return aid
        }
        return null
    }
    
    /** 消息中是否 @ 提及了某小助手（用于兼容旧逻辑的快速判断） */
    private fun isBuiltInAssistantMentioned(query: String): Boolean =
        ChatConstants.containsMainAssistantMention(query) ||
        query.contains("@小助手", ignoreCase = true) ||
        query.contains("@assistant", ignoreCase = true) ||
        query.contains("@自动执行助手", ignoreCase = true)
    
    /**
     * 更新按钮可见性（根据输入框内容和选择的图片）
     */
    internal fun updateButtonVisibility() {
        // 检查Fragment状态，确保可以安全更新UI
        if (!isAdded || view == null || _binding == null) {
            Log.w(TAG, "updateButtonVisibility: Fragment未附加或binding为空，跳过更新")
            return
        }
        
        // 确保在主线程执行
        if (!android.os.Looper.getMainLooper().isCurrentThread) {
            Log.w(TAG, "updateButtonVisibility: 不在主线程，切换到主线程执行")
            mainScope.launch(Dispatchers.Main) {
                updateButtonVisibility()
            }
            return
        }
        
        try {
            val hasText = binding.etChatInput.text?.toString()?.trim()?.isNotEmpty() ?: false
            val hasImage = selectedImageBase64 != null
            val isBusy = isTaskRunning || isCustomAssistantProcessing
            
            Log.d(TAG, "updateButtonVisibility: hasText=$hasText, hasImage=$hasImage, isTaskRunning=$isTaskRunning, isCustomAssistantProcessing=$isCustomAssistantProcessing, btnStopTask.visibility=${binding.btnStopTask.visibility}")
            
            if (isBusy) {
                binding.btnSendChat.setImageResource(R.drawable.ic_stop)
                binding.btnSendChat.contentDescription = "停止"
                binding.btnSendChat.visibility = View.VISIBLE
                binding.btnAddMedia.visibility = View.GONE
                Log.d(TAG, "updateButtonVisibility: 任务/小助手处理中，发送按钮变为停止图标")
            } else if (hasText || hasImage) {
                binding.btnSendChat.setImageResource(R.drawable.ic_send)
                binding.btnSendChat.contentDescription = "发送"
                binding.btnSendChat.visibility = View.VISIBLE
                binding.btnAddMedia.visibility = View.GONE
                Log.d(TAG, "updateButtonVisibility: 显示发送按钮，隐藏加号按钮")
            } else {
                binding.btnSendChat.setImageResource(R.drawable.ic_send)
                binding.btnSendChat.contentDescription = "发送"
                binding.btnSendChat.visibility = View.GONE
                binding.btnAddMedia.visibility = View.VISIBLE
                Log.d(TAG, "updateButtonVisibility: 任务未运行，显示加号按钮，隐藏发送按钮")
            }
            
            // 验证按钮状态是否正确设置
            if (binding.btnSendChat.visibility == View.GONE && binding.btnAddMedia.visibility == View.GONE) {
                Log.e(TAG, "updateButtonVisibility: 警告！发送按钮和加号按钮都隐藏了，强制显示加号按钮")
                binding.btnAddMedia.visibility = View.VISIBLE
            }
        } catch (e: Exception) {
            Log.e(TAG, "updateButtonVisibility: 更新按钮可见性时出错: ${e.message}", e)
            try {
                binding.btnAddMedia.visibility = View.VISIBLE
            } catch (ex: Exception) {
                Log.e(TAG, "updateButtonVisibility: 设置加号按钮可见性时出错: ${ex.message}", ex)
            }
        }
    }
    
    /**
     * 更新发送按钮可见性（供外部调用）
     */
    internal fun updateSendButtonVisibility() {
        updateButtonVisibility()
    }
    
    /**
     * 切换媒体选择面板
     */
    internal fun toggleMediaPanel() {
        if (isMediaPanelVisible) {
            hideMediaPanel()
        } else {
            showMediaPanel()
        }
    }
    
    /**
     * 显示媒体选择面板
     */
    internal fun showMediaPanel() {
        if (isMediaPanelVisible) {
            return
        }
        
        // 先收起键盘（如果弹起）
        hideKeyboard()
        // 等待键盘收起后再显示面板
        binding.root.postDelayed({
            if (_binding != null) {
                showMediaPanelInternal()
            }
        }, 300)
    }
    
    /**
     * 显示媒体选择面板（内部方法）
     */
    internal fun showMediaPanelInternal() {
        if (isMediaPanelVisible) {
            return
        }
        
        isMediaPanelVisible = true
        
        // 不使用全屏背景View，而是在RecyclerView上设置点击监听
        // 当媒体面板显示时，点击聊天消息区域会隐藏面板
        binding.rvChatMessages.setOnClickListener {
            if (isMediaPanelVisible && _binding != null) {
                hideMediaPanel()
            }
        }
        
        binding.llMediaPanel.visibility = View.VISIBLE
        
        // 先测量高度
        binding.llMediaPanel.measure(
            View.MeasureSpec.makeMeasureSpec(binding.root.width, View.MeasureSpec.EXACTLY),
            View.MeasureSpec.makeMeasureSpec(0, View.MeasureSpec.UNSPECIFIED)
        )
        val targetHeight = binding.llMediaPanel.measuredHeight
        
        // 从0高度滑出
        val layoutParams = binding.llMediaPanel.layoutParams
        layoutParams.height = 0
        binding.llMediaPanel.layoutParams = layoutParams
        binding.llMediaPanel.requestLayout()
        
        // 延迟一帧后开始动画，确保布局已更新
        binding.llMediaPanel.post {
            val binding = _binding ?: return@post
            android.animation.ValueAnimator.ofInt(0, targetHeight).apply {
                duration = 250
                addUpdateListener { animation ->
                    val currentBinding = _binding ?: return@addUpdateListener
                    val height = animation.animatedValue as Int
                    val params = currentBinding.llMediaPanel.layoutParams
                    params.height = height
                    currentBinding.llMediaPanel.layoutParams = params
                }
                start()
            }
        }
    }
    
    /**
     * 初始化推荐任务面板（显示默认推荐或上一次的推荐）
     */
    internal fun initRecommendationsPanel() {
        // 在人工客服页面、好友对话和管理员模式下，不显示推荐任务
        val conversationId = currentConversation?.id
        if (conversationId == ConversationListFragment.CONVERSATION_ID_CUSTOMER_SERVICE ||
