    /**
     * 震动反馈（点击按钮时）
     */
    internal fun vibrate() {
        try {
            val vibrator = if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.S) {
                val vibratorManager = requireContext().getSystemService(Context.VIBRATOR_MANAGER_SERVICE) as android.os.VibratorManager
                vibratorManager.defaultVibrator
            } else {
                @Suppress("DEPRECATION")
                requireContext().getSystemService(Context.VIBRATOR_SERVICE) as Vibrator
            }
            
            if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.O) {
                // Android 8.0及以上使用VibrationEffect
                val vibrationEffect = VibrationEffect.createOneShot(50, VibrationEffect.DEFAULT_AMPLITUDE)
                vibrator.vibrate(vibrationEffect)
            } else {
                // Android 8.0以下使用旧API
                @Suppress("DEPRECATION")
                vibrator.vibrate(50)
            }
        } catch (e: Exception) {
            // 如果震动失败（例如设备不支持），静默处理
            Log.d(TAG, "震动失败: ${e.message}")
        }
    }

    private var sessionListAdapter: SessionListAdapter? = null

    /**
     * 设置自定义小助手侧边栏内容（开启新对话 + 历史会话列表）
     */
    internal fun setupCustomAssistantDrawerContent() {
        val conversationId = currentConversation?.id ?: return
        if (!CustomAssistantManager.isCustomAssistantId(conversationId)) return
        val assistant = CustomAssistantManager.getById(requireContext(), conversationId) ?: return
        val isMultiSession = assistant.multiSession

        if (!isMultiSession) {
            binding.btnCustomAssistantNewSession.visibility = android.view.View.GONE
            binding.rvCustomAssistantSessions.visibility = android.view.View.GONE
            return
        }

        binding.btnCustomAssistantNewSession.visibility = android.view.View.VISIBLE
        binding.rvCustomAssistantSessions.visibility = android.view.View.VISIBLE

        binding.btnCustomAssistantNewSession.setOnClickListener {
            vibrate()
            handleNewSession()
        }

        sessionListAdapter = SessionListAdapter(
            listOf(),
            currentSessionIdForMultiSession,
            onSelect = { handleSelectSession(it) },
            onDelete = { handleDeleteSession(it) }
        )
        binding.rvCustomAssistantSessions.layoutManager = androidx.recyclerview.widget.LinearLayoutManager(requireContext())
        binding.rvCustomAssistantSessions.adapter = sessionListAdapter
        refreshDrawerSessions()
    }

    private fun refreshDrawerSessions() {
        val conversationId = currentConversation?.id ?: return
        val sessions = SessionStorage.loadSessions(requireContext(), conversationId)
        sessionListAdapter?.updateList(sessions, currentSessionIdForMultiSession)
    }

    /**
     * 以云侧为准：仅使用 remote，不合并 local-only，避免删除后刷新又出现。
     * 同 id 时取 createdAt 较大者或 title 非空者。
     */
    private fun mergeSessionsByRemote(local: List<SessionStorage.ChatSession>, remote: List<SessionStorage.ChatSession>): List<SessionStorage.ChatSession> {
        val localById = local.associateBy { it.id }
        val result = mutableListOf<SessionStorage.ChatSession>()
        for (s in remote) {
            val localVer = localById[s.id]
            val best = if (localVer == null) s
            else if (s.createdAt > localVer.createdAt || (s.createdAt == localVer.createdAt && s.title.isNotEmpty() && localVer.title.isEmpty())) s
            else localVer
            result.add(best)
        }
        return result.sortedByDescending { it.createdAt }
    }

    /**
     * 扫描 prefs 中已有聊天记录的 sessionId（PC/会话外写入可能尚未登记到 [SessionStorage]）。
     */
    private fun sessionIdsWithNonEmptyChatMessages(conversationId: String): List<String> {
        val prefs = requireContext().getSharedPreferences("app_prefs", Context.MODE_PRIVATE)
        val prefix = "chat_messages_${conversationId}_"
        val out = linkedSetOf<String>()
        for (key in prefs.all.keys) {
            if (!key.startsWith(prefix)) continue
            val json = prefs.getString(key, null) ?: continue
            if (json.isBlank() || json == "[]") continue
            val sid = key.removePrefix(prefix)
            if (sid.isNotEmpty()) out.add(sid)
        }
        return out.toList()
    }

    /**
     * 兜底：会话外收到消息时可能被误写入裸 key（chat_messages_${convId}，无 session 后缀）。
     * 多 session 加载路径只读带后缀的 key，裸 key 的数据会被遗漏。
     * 此方法将裸 key 中的消息按 uuid 去重后追加到最新 session 的 key 中，然后删除裸 key，确保不重复。
     */
    private fun mergeBareKeyOrphanIntoLatestSession(
        conversationId: String,
        sessions: List<SessionStorage.ChatSession>
    ) {
        try {
            val prefs = requireContext().getSharedPreferences("app_prefs", Context.MODE_PRIVATE)
            val bareKey = "chat_messages_$conversationId"
            val bareJson = prefs.getString(bareKey, null)
            if (bareJson.isNullOrBlank() || bareJson == "[]") return
            val latestSessionId = sessions.maxByOrNull { it.createdAt }?.id ?: return
            val sessionKey = "chat_messages_${conversationId}_$latestSessionId"
            val sessionJson = prefs.getString(sessionKey, null)
            val sessionArray = if (sessionJson != null) org.json.JSONArray(sessionJson) else org.json.JSONArray()
            val existingUuids = hashSetOf<String>()
            for (i in 0 until sessionArray.length()) {
                val uuid = sessionArray.getJSONObject(i).optString("uuid", "")
                if (uuid.isNotEmpty()) existingUuids.add(uuid)
            }
            val bareArray = org.json.JSONArray(bareJson)
            var merged = 0
            for (i in 0 until bareArray.length()) {
                val msg = bareArray.getJSONObject(i)
                val uuid = msg.optString("uuid", "")
                if (uuid.isNotEmpty() && uuid in existingUuids) continue
                sessionArray.put(msg)
                merged++
            }
            if (merged > 0) {
                prefs.edit()
                    .putString(sessionKey, sessionArray.toString())
                    .remove(bareKey)
                    .apply()
                Log.d(TAG, "mergeBareKeyOrphanIntoLatestSession: 从裸 key 合并 $merged 条消息到 session $latestSessionId")
            } else {
                prefs.edit().remove(bareKey).apply()
                Log.d(TAG, "mergeBareKeyOrphanIntoLatestSession: 裸 key 数据全部重复，已清理")
            }
        } catch (e: Exception) {
            Log.e(TAG, "mergeBareKeyOrphanIntoLatestSession 失败: ${e.message}", e)
        }
    }

    /**
     * 将「仅有 prefs、列表中无」的 session 补进侧栏数据，避免打开会话时选中空 session 而读不到 PC 同步内容。
     */
    private fun mergeOrphanChatPrefsSessionsIntoSessionList(
        conversationId: String,
        sessions: List<SessionStorage.ChatSession>
    ): List<SessionStorage.ChatSession> {
        val existingIds = sessions.map { it.id }.toSet()
        val orphanIds = sessionIdsWithNonEmptyChatMessages(conversationId).filter { it !in existingIds }
        if (orphanIds.isEmpty()) return sessions
        val title = getString(R.string.session_new_dialog)
        for (oid in orphanIds) {
            SessionStorage.addSession(
                requireContext(),
                conversationId,
                SessionStorage.ChatSession(oid, title, System.currentTimeMillis())
            )
            Log.d(TAG, "mergeOrphanChatPrefsSessionsIntoSessionList: 登记 prefs 中已有消息的 session=$oid")
        }
        return SessionStorage.loadSessions(requireContext(), conversationId)
    }

    /**
     * 在多个 session 中优先选「prefs 里已有消息」的线程，避免默认按 createdAt 选到空会话。
     */
    private fun pickSessionIdPreferringNonEmptyPrefs(
        conversationId: String,
        sessions: List<SessionStorage.ChatSession>
    ): String? {
        if (sessions.isEmpty()) return null
        val prefs = requireContext().getSharedPreferences("app_prefs", Context.MODE_PRIVATE)
        val prefix = "chat_messages_${conversationId}_"
        val withData = sessions.filter { s ->
            val json = prefs.getString("$prefix${s.id}", null)
            json != null && json.isNotBlank() && json != "[]"
        }
        return when {
            withData.size == 1 -> withData.first().id
            withData.size > 1 -> withData.maxByOrNull { it.createdAt }?.id
            else -> null
        }
    }

    /**
     * PC 同步写入的 session 与当前选中不一致时，切换到该 session 并从 prefs 加载（需先写入 prefs 再调用）。
     */
    fun switchToSessionIfNeededForIncomingSync(targetConvId: String, targetSessionId: String?) {
        if (targetSessionId == null) return
        if (currentConversation?.id != targetConvId) return
        if (!CustomAssistantManager.isCustomAssistantId(targetConvId)) return
        val assistant = CustomAssistantManager.getById(requireContext(), targetConvId) ?: return
        if (!assistant.multiSession) return
        if (targetSessionId == currentSessionIdForMultiSession) return
        val sessions = SessionStorage.loadSessions(requireContext(), targetConvId)
        if (sessions.none { it.id == targetSessionId }) {
            SessionStorage.addSession(
                requireContext(),
                targetConvId,
                SessionStorage.ChatSession(targetSessionId, getString(R.string.session_new_dialog), System.currentTimeMillis())
            )
        }
        view?.post {
            if (isAdded && _binding != null) {
                Log.d(TAG, "switchToSessionIfNeededForIncomingSync: $currentSessionIdForMultiSession -> $targetSessionId")
                handleSelectSession(targetSessionId)
            }
        }
    }

    private fun resetActiveSessionRemoteTsIfNeeded(conversationId: String) {
        if (lastRemoteActiveSessionAtConvId != conversationId) {
            lastRemoteActiveSessionAtConvId = conversationId
            lastRemoteActiveSessionAt = 0L
        }
    }

    private fun pushActiveSessionToServer(conversationId: String, sessionId: String) {
        val assistant = CustomAssistantManager.getById(requireContext(), conversationId) ?: return
        if (!assistant.multiSession || assistant.baseUrl.isBlank()) return
        mainScope.launch(Dispatchers.IO) {
            try {
                val prefs = requireContext().getSharedPreferences("app_prefs", Context.MODE_PRIVATE)
                val customerServiceUrl = prefs.getString("customer_service_url", ServiceUrlConfig.DEFAULT_CUSTOMER_SERVICE_URL)
                    ?: ServiceUrlConfig.DEFAULT_CUSTOMER_SERVICE_URL
                CustomerServiceNetwork.initialize(customerServiceUrl)
                val api = CustomerServiceNetwork.getApiService() ?: return@launch
                val imei = ProfileManager.getOrGenerateImei(requireContext())
                val resp = api.setActiveSession(
                    ActiveSessionSetRequest(imei, conversationId, sessionId, assistant.baseUrl)
                )
                if (resp.isSuccessful && resp.body()?.success == true) {
                    val ut = resp.body()?.updated_at ?: 0L
                    withContext(Dispatchers.Main) {
                        if (ut > lastRemoteActiveSessionAt) lastRemoteActiveSessionAt = ut
                    }
                }
            } catch (e: Exception) {
                Log.w(TAG, "pushActiveSessionToServer: ${e.message}")
            }
        }
    }

    internal fun applyRemoteCustomAssistantActiveSession(
        conversationId: String,
        baseUrl: String?,
        activeSessionId: String,
        updatedAt: Long
    ) {
        if (updatedAt <= lastRemoteActiveSessionAt) return
        val assistant = CustomAssistantManager.getById(requireContext(), conversationId) ?: return
        if (!assistant.multiSession) return
        val norm: (String) -> String = { it.trim().trimEnd('/') }
        val abu = norm(assistant.baseUrl)
        val msgBu = norm(baseUrl ?: "")
        if (abu.isNotEmpty() && msgBu.isNotEmpty() && abu != msgBu) return
        view?.post {
            if (!isAdded) return@post
            if (currentConversation?.id != conversationId) return@post
            if (activeSessionId == currentSessionIdForMultiSession) {
                lastRemoteActiveSessionAt = updatedAt
                return@post
            }
            lastRemoteActiveSessionAt = updatedAt
            var sl = SessionStorage.loadSessions(requireContext(), conversationId)
            if (sl.none { it.id == activeSessionId }) {
                SessionStorage.addSession(
                    requireContext(),
                    conversationId,
                    SessionStorage.ChatSession(activeSessionId, getString(R.string.session_new_dialog), System.currentTimeMillis())
                )
            }
            handleSelectSession(activeSessionId, pushActiveToServer = false)
        }
    }

    /**
     * 进入多 session 自定义小助手时初始化：加载 sessions，若为空则迁移旧数据，选中最新 session，订阅 thread
     */
    private fun ensureMultiSessionInitialized(conversationId: String) {
        val assistant = CustomAssistantManager.getById(requireContext(), conversationId)
        if (assistant == null || !assistant.multiSession) return
        resetActiveSessionRemoteTsIfNeeded(conversationId)
        var sessions = SessionStorage.loadSessions(requireContext(), conversationId)
        if (sessions.isEmpty()) {
            val imei = ProfileManager.getOrGenerateImei(requireContext())
            val oldThreadId = "${imei}_${conversationId}"
            val prefs = requireContext().getSharedPreferences("app_prefs", Context.MODE_PRIVATE)
            val oldMsg = prefs.getString("chat_messages_$conversationId", null)
            if (oldMsg != null) {
                val session = SessionStorage.ChatSession(
                    id = oldThreadId,
                    title = getString(R.string.session_new_dialog),
                    createdAt = System.currentTimeMillis()
                )
                SessionStorage.addSession(requireContext(), conversationId, session)
                prefs.edit()
                    .putString("chat_messages_${conversationId}_$oldThreadId", oldMsg)
                    .putLong("chat_messages_start_time_${conversationId}_$oldThreadId",
                        prefs.getLong("chat_messages_start_time_$conversationId", System.currentTimeMillis()))
                    .apply()
                val oldCtx = prefs.getString("chat_context_$conversationId", null)
                if (oldCtx != null) {
                    prefs.edit().putString("chat_context_${conversationId}_$oldThreadId", oldCtx).apply()
                }
                Log.d(TAG, "ensureMultiSessionInitialized: 迁移旧数据到 session $oldThreadId")
            }
            sessions = SessionStorage.loadSessions(requireContext(), conversationId)
        }
        if (sessions.isEmpty()) {
            val newId = UUID.randomUUID().toString()
            val session = SessionStorage.ChatSession(newId, getString(R.string.session_new_dialog), System.currentTimeMillis())
            SessionStorage.addSession(requireContext(), conversationId, session)
            sessions = listOf(session)
        }
        mergeBareKeyOrphanIntoLatestSession(conversationId, sessions)
        sessions = mergeOrphanChatPrefsSessionsIntoSessionList(conversationId, sessions)
        val preferredSessionId = pickSessionIdPreferringNonEmptyPrefs(conversationId, sessions)
        val latestSessionId = preferredSessionId ?: sessions.maxByOrNull { it.createdAt }?.id ?: return
        currentSessionIdForMultiSession = latestSessionId
        subscribedThreadIdForMultiSession?.let { tid ->
            ChatWebSocketPool.unsubscribeThread(getServerUrlForConversation(), tid)
        }
        ChatWebSocketPool.subscribeThread(getServerUrlForConversation(), latestSessionId)
        subscribedThreadIdForMultiSession = latestSessionId
        ChatWebSocketPool.setOnAssistantPush(latestSessionId) { content ->
            if (currentConversation?.id == conversationId && currentSessionIdForMultiSession == latestSessionId) {
                addChatMessage(assistant.name, content, isAnswer = true)
            }
        }
        // 后台同步 session 列表到云端，实现 PC/手机 跨端可见；先拉取再合并（支持删除同步）
        mainScope.launch(Dispatchers.IO) {
            try {
                if (assistant.baseUrl.isBlank()) {
                    Log.w(TAG, "ensureMultiSessionInitialized: baseUrl 为空，跳过 sync，PC 端 session 无法跨端同步（需 baseUrl 与 PC 使用相同 key）")
                    return@launch
                }
                val prefs = requireContext().getSharedPreferences("app_prefs", Context.MODE_PRIVATE)
                val customerServiceUrl = prefs.getString("customer_service_url", ServiceUrlConfig.DEFAULT_CUSTOMER_SERVICE_URL)
                    ?: ServiceUrlConfig.DEFAULT_CUSTOMER_SERVICE_URL
                CustomerServiceNetwork.initialize(customerServiceUrl)
                val api = CustomerServiceNetwork.getApiService() ?: return@launch
                val imei = ProfileManager.getOrGenerateImei(requireContext())
                val localList = SessionStorage.loadSessions(requireContext(), conversationId)
                // 以云侧为准：拉取服务端，直接使用，不合并 local-only（避免删除后刷新又出现）
                var merged = localList
                val getResp = api.getSessions(imei, conversationId, assistant.baseUrl)
                if (getResp.isSuccessful && getResp.body()?.success == true) {
                    val remote = (getResp.body()?.sessions ?: emptyList()).map {
                        SessionStorage.ChatSession(it.id, it.title, it.createdAt)
                    }
                    merged = if (remote.isNotEmpty()) remote else localList
                    withContext(Dispatchers.Main) {
                        if (currentConversation?.id == conversationId && isAdded && merged.isNotEmpty()) {
                            SessionStorage.saveSessions(requireContext(), conversationId, merged)
                            refreshDrawerSessions()
                        }
                    }
                }
                // 再同步本地到服务端
                Log.d(TAG, "[Session] ensureMultiSessionInitialized sync: imei=${imei.take(8)}..., baseUrl=${assistant.baseUrl.take(50)}..., localCount=${merged.size}")
                val request = SessionSyncRequest(
                    imei = imei,
                    conversation_id = conversationId,
                    sessions = merged.map { SessionItem(it.id, it.title, it.createdAt) },
                    base_url = assistant.baseUrl
                )
                val resp = api.syncSessions(request)
                if (resp.isSuccessful && resp.body()?.success == true) {
                    val synced = resp.body()?.sessions ?: return@launch
                    Log.d(TAG, "[Session] ensureMultiSessionInitialized sync 成功: returned=${synced.size}")
                    val finalList = mergeSessionsByRemote(merged, synced.map { SessionStorage.ChatSession(it.id, it.title, it.createdAt) })
                    withContext(Dispatchers.Main) {
                        if (currentConversation?.id == conversationId && isAdded && finalList.isNotEmpty()) {
                            SessionStorage.saveSessions(requireContext(), conversationId, finalList)
                            refreshDrawerSessions()
                        }
                    }
                } else {
                    Log.w(TAG, "[Session] ensureMultiSessionInitialized sync 失败: code=${resp.code()}, success=${resp.body()?.success}")
                }
                val activeGet = api.getActiveSession(imei, conversationId, assistant.baseUrl)
                if (activeGet.isSuccessful && activeGet.body()?.success == true) {
                    val aid = activeGet.body()?.active_session_id
                    val ut = activeGet.body()?.updated_at ?: 0L
                    if (!aid.isNullOrBlank() && ut > 0L) {
                        withContext(Dispatchers.Main) {
                            if (currentConversation?.id != conversationId || !isAdded) return@withContext
                            if (aid == currentSessionIdForMultiSession) {
                                lastRemoteActiveSessionAt = maxOf(lastRemoteActiveSessionAt, ut)
                                return@withContext
                            }
                            lastRemoteActiveSessionAt = ut
                            var sl = SessionStorage.loadSessions(requireContext(), conversationId)
                            if (sl.none { it.id == aid }) {
                                SessionStorage.addSession(
                                    requireContext(),
                                    conversationId,
                                    SessionStorage.ChatSession(aid, getString(R.string.session_new_dialog), System.currentTimeMillis())
                                )
                            }
                            handleSelectSession(aid, pushActiveToServer = false)
                            refreshDrawerSessions()
                        }
                    }
                }
            } catch (e: Exception) {
                Log.w(TAG, "ensureMultiSessionInitialized: session 同步失败 ${e.message}")
            }
        }
    }

    private fun handleNewSession() {
        val conversationId = currentConversation?.id ?: return
        val assistant = CustomAssistantManager.getById(requireContext(), conversationId) ?: return
        if (!assistant.multiSession) return
        val sessionId = UUID.randomUUID().toString()
        val session = SessionStorage.ChatSession(sessionId, getString(R.string.session_new_dialog), System.currentTimeMillis())
        SessionStorage.addSession(requireContext(), conversationId, session)
        currentSessionIdForMultiSession = sessionId
        subscribedThreadIdForMultiSession?.let { tid ->
            val baseUrl = getServerUrlForConversation()
            ChatWebSocketPool.unsubscribeThread(baseUrl, tid)
        }
        ChatWebSocketPool.subscribeThread(getServerUrlForConversation(), sessionId)
        subscribedThreadIdForMultiSession = sessionId
        getViewModel().clearMessages()
        chatAdapter?.clear()
        refreshDrawerSessions()
        binding.overlayCustomAssistantDrawer.visibility = android.view.View.GONE
        // 将新建的 session 同步到云端
        mainScope.launch(Dispatchers.IO) {
            try {
                if (assistant.baseUrl.isBlank()) {
                    Log.w(TAG, "handleNewSession: baseUrl 为空，跳过 sync，PC 端无法拉取本 session")
                    return@launch
                }
                val prefs = requireContext().getSharedPreferences("app_prefs", Context.MODE_PRIVATE)
                val customerServiceUrl = prefs.getString("customer_service_url", ServiceUrlConfig.DEFAULT_CUSTOMER_SERVICE_URL)
                    ?: ServiceUrlConfig.DEFAULT_CUSTOMER_SERVICE_URL
                CustomerServiceNetwork.initialize(customerServiceUrl)
                val api = CustomerServiceNetwork.getApiService() ?: return@launch
                val imei = ProfileManager.getOrGenerateImei(requireContext())
                val localList = SessionStorage.loadSessions(requireContext(), conversationId)
                Log.d(TAG, "[Session] handleNewSession sync: imei=${imei.take(8)}..., baseUrl=${assistant.baseUrl.take(50)}..., localCount=${localList.size}")
                val request = SessionSyncRequest(
                    imei = imei,
                    conversation_id = conversationId,
                    sessions = localList.map { SessionItem(it.id, it.title, it.createdAt) },
                    base_url = assistant.baseUrl
                )
                val resp = api.syncSessions(request)
                if (resp.isSuccessful && resp.body()?.success == true) {
                    val merged = resp.body()?.sessions ?: return@launch
                    Log.d(TAG, "[Session] handleNewSession sync 成功: returned=${merged.size}")
                    withContext(Dispatchers.Main) {
                        if (currentConversation?.id == conversationId && isAdded) {
                            SessionStorage.saveSessions(requireContext(), conversationId, merged.map { SessionStorage.ChatSession(it.id, it.title, it.createdAt) })
                            refreshDrawerSessions()
                        }
                    }
                } else {
                    Log.w(TAG, "[Session] handleNewSession sync 失败: code=${resp.code()}, success=${resp.body()?.success}")
                }
            } catch (e: Exception) {
                Log.w(TAG, "handleNewSession: session 同步失败 ${e.message}")
            }
            pushActiveSessionToServer(conversationId, sessionId)
        }
    }

    private fun handleSelectSession(sessionId: String, pushActiveToServer: Boolean = true) {
        if (sessionId == currentSessionIdForMultiSession) {
            binding.overlayCustomAssistantDrawer.visibility = android.view.View.GONE
            return
        }
        val conversationId = currentConversation?.id ?: return
        val assistant = CustomAssistantManager.getById(requireContext(), conversationId)
        getViewModel().saveMessagesToPrefs(requireContext(), conversationId, sync = true, currentSessionIdForMultiSession)
        subscribedThreadIdForMultiSession?.let { tid ->
            ChatWebSocketPool.unsubscribeThread(getServerUrlForConversation(), tid)
        }
        currentSessionIdForMultiSession = sessionId
        ChatWebSocketPool.subscribeThread(getServerUrlForConversation(), sessionId)
        subscribedThreadIdForMultiSession = sessionId
        ChatWebSocketPool.setOnAssistantPush(sessionId) { content ->
            if (currentConversation?.id == conversationId && currentSessionIdForMultiSession == sessionId) {
                addChatMessage(assistant?.name ?: "小助手", content, isAnswer = true)
            }
        }
        getViewModel().clearMessages()
        chatAdapter?.clear()
        loadMessagesForMultiSessionSession(conversationId, sessionId, assistant)
        refreshDrawerSessions()
        binding.overlayCustomAssistantDrawer.visibility = android.view.View.GONE
        if (pushActiveToServer) {
            pushActiveSessionToServer(conversationId, sessionId)
        }
    }

    /**
     * 多 session：加载消息，本地优先；若本地为空则从聊天小助手 API 拉取（跨设备同步，thread_id=sessionId）
     */
    private fun loadMessagesForMultiSessionSession(conversationId: String, sessionId: String, assistant: CustomAssistantManager.CustomAssistant?) {
        val vm = getViewModel()
        mainScope.launch {
            vm.initialize(conversationId)
            // 1. 先尝试本地
            vm.loadMessagesFromPrefs(requireContext(), conversationId, sessionId)
            var waitCount = 0
            while (vm.isRestoringMessages.value && waitCount < 50) {
                kotlinx.coroutines.delay(100)
                waitCount++
            }
            if (vm.getMessages().isNotEmpty()) {
                restoreChatMessagesFromViewModel()
                // 以第一条用户消息为标题（本地有消息但标题仍是「新对话」时更新）
                val firstUser = vm.getMessages().firstOrNull { it.type == "user" }
                if (firstUser != null && assistant != null && !assistant.baseUrl.isBlank()) {
                    val sessions = SessionStorage.loadSessions(requireContext(), conversationId)
                    val session = sessions.find { it.id == sessionId }
                    if (session != null && session.title == getString(R.string.session_new_dialog)) {
                        val newTitle = firstUser.message.take(30).let { if (it.length < firstUser.message.length) "$it..." else it }
                        SessionStorage.updateSessionTitle(requireContext(), conversationId, sessionId, newTitle)
                        refreshDrawerSessions()
                        // 同步标题到云端
                        mainScope.launch(Dispatchers.IO) {
                            try {
                                val prefs = requireContext().getSharedPreferences("app_prefs", Context.MODE_PRIVATE)
                                val csUrl = prefs.getString("customer_service_url", ServiceUrlConfig.DEFAULT_CUSTOMER_SERVICE_URL) ?: ServiceUrlConfig.DEFAULT_CUSTOMER_SERVICE_URL
                                CustomerServiceNetwork.initialize(csUrl)
                                val api = CustomerServiceNetwork.getApiService() ?: return@launch
                                val imei = ProfileManager.getOrGenerateImei(requireContext())
                                val localList = SessionStorage.loadSessions(requireContext(), conversationId)
                                val request = SessionSyncRequest(imei = imei, conversation_id = conversationId, sessions = localList.map { SessionItem(it.id, it.title, it.createdAt) }, base_url = assistant.baseUrl)
                                api.syncSessions(request)
                            } catch (_: Exception) {}
                        }
                    }
                }
                return@launch
            }
            // 2. 本地为空，从聊天小助手 API 拉取（PC 端消息存在 baseUrl 的 chat/history）
            if (assistant == null || assistant.baseUrl.isBlank()) return@launch
            val appCtx = requireContext().applicationContext
            kotlinx.coroutines.withContext(Dispatchers.IO) {
                try {
                    val baseUrl = if (assistant.baseUrl.endsWith("/")) assistant.baseUrl else "${assistant.baseUrl}/"
                    NetworkService.initialize(baseUrl, appCtx)
                    val apiService = NetworkService.getApiService() ?: return@withContext
                    val response = apiService.getChatAssistantHistory(threadId = sessionId, limit = 100)
                    if (response.isSuccessful) {
                        val messages = response.body()?.messages ?: emptyList()
                        val chatMessages = messages.mapIndexed { i, m ->
                            val sender = if (m.role == "user") "我" else (assistant.name)
                            val type = if (m.role == "user") "user" else "answer"
                            val ts = System.currentTimeMillis() - (100 - m.order).coerceAtLeast(0) * 1000L
                            ChatMessage(sender, m.content, type, ts, "", null, null, null)
                        }
                        withContext(Dispatchers.Main) {
                            if (currentConversation?.id == conversationId && currentSessionIdForMultiSession == sessionId) {
                                vm.clearMessages()
                                chatMessages.forEach { vm.addMessage(it) }
                                vm.saveMessagesToPrefs(requireContext(), conversationId, sync = true, sessionId)
                                restoreChatMessagesFromViewModel()
                                // 以第一条用户消息为标题（跨设备：PC 创建的消息在手机端加载时更新标题）
                                val firstUserMsg = messages.firstOrNull { it.role == "user" }
                                if (firstUserMsg != null) {
                                    val sessions = SessionStorage.loadSessions(requireContext(), conversationId)
                                    val session = sessions.find { it.id == sessionId }
                                    if (session != null && session.title == getString(R.string.session_new_dialog)) {
                                        val content = firstUserMsg.content ?: ""
                                        val newTitle = content.take(30).let { if (it.length < content.length) "$it..." else it }
                                        SessionStorage.updateSessionTitle(requireContext(), conversationId, sessionId, newTitle)
                                        refreshDrawerSessions()
                                        // 同步标题到云端
                                        mainScope.launch(Dispatchers.IO) {
                                            try {
                                                if (assistant.baseUrl.isBlank()) return@launch
                                                val prefs = requireContext().getSharedPreferences("app_prefs", Context.MODE_PRIVATE)
                                                val csUrl = prefs.getString("customer_service_url", ServiceUrlConfig.DEFAULT_CUSTOMER_SERVICE_URL) ?: ServiceUrlConfig.DEFAULT_CUSTOMER_SERVICE_URL
                                                CustomerServiceNetwork.initialize(csUrl)
                                                val api = CustomerServiceNetwork.getApiService() ?: return@launch
                                                val imei = ProfileManager.getOrGenerateImei(requireContext())
                                                val localList = SessionStorage.loadSessions(requireContext(), conversationId)
                                                val request = SessionSyncRequest(imei = imei, conversation_id = conversationId, sessions = localList.map { SessionItem(it.id, it.title, it.createdAt) }, base_url = assistant.baseUrl)
                                                api.syncSessions(request)
                                            } catch (_: Exception) {}
                                        }
                                    }
                                }
                                Log.d(TAG, "多 session 从 API 加载历史成功: ${chatMessages.size} 条, sessionId=$sessionId")
                            }
                        }
                    }
                } catch (e: Exception) {
                    Log.w(TAG, "多 session 从 API 加载历史失败: ${e.message}")
                }
            }
        }
    }

    private fun handleDeleteSession(sessionId: String) {
        val conversationId = currentConversation?.id ?: return
        val assistant = CustomAssistantManager.getById(requireContext(), conversationId)
        val sessions = SessionStorage.loadSessions(requireContext(), conversationId)
        if (sessions.size <= 1) {
            Toast.makeText(requireContext(), "至少保留一个会话", Toast.LENGTH_SHORT).show()
            return
        }
        SessionStorage.removeSession(requireContext(), conversationId, sessionId)
        removeMessagesForSession(conversationId, sessionId)
        if (currentSessionIdForMultiSession == sessionId) {
            val remaining = sessions.filter { it.id != sessionId }
            val nextId = remaining.firstOrNull()?.id ?: return
            handleSelectSession(nextId)
        }
        refreshDrawerSessions()
        // 同步删除后的列表到云端，使 PC 端也能删除
        if (assistant != null && assistant.multiSession && !assistant.baseUrl.isBlank()) {
            mainScope.launch(Dispatchers.IO) {
                try {
                    val prefs = requireContext().getSharedPreferences("app_prefs", Context.MODE_PRIVATE)
                    val csUrl = prefs.getString("customer_service_url", ServiceUrlConfig.DEFAULT_CUSTOMER_SERVICE_URL) ?: ServiceUrlConfig.DEFAULT_CUSTOMER_SERVICE_URL
                    CustomerServiceNetwork.initialize(csUrl)
                    val api = CustomerServiceNetwork.getApiService() ?: return@launch
                    val imei = ProfileManager.getOrGenerateImei(requireContext())
                    val localList = SessionStorage.loadSessions(requireContext(), conversationId)
                    if (localList.isNotEmpty()) {
                        val request = SessionSyncRequest(imei = imei, conversation_id = conversationId, sessions = localList.map { SessionItem(it.id, it.title, it.createdAt) }, base_url = assistant.baseUrl)
                        val resp = api.syncSessions(request)
                        if (resp.isSuccessful && resp.body()?.success == true) {
                            Log.d(TAG, "[Session] 删除后 sync 成功，其他端将同步删除")
                        }
                    }
                } catch (e: Exception) {
                    Log.w(TAG, "handleDeleteSession: sync 失败 ${e.message}")
                }
            }
        }
    }

    private fun removeMessagesForSession(conversationId: String, sessionId: String) {
        val prefs = requireContext().getSharedPreferences("app_prefs", Context.MODE_PRIVATE)
        prefs.edit().remove("chat_messages_${conversationId}_$sessionId")
            .remove("chat_messages_start_time_${conversationId}_$sessionId").apply()
    }

    /**
     * 会话列表适配器（多 session 侧边栏）
     */
    private class SessionListAdapter(
        private var sessions: List<SessionStorage.ChatSession>,
        private var selectedId: String?,
        private val onSelect: (String) -> Unit,
        private val onDelete: (String) -> Unit
    ) : RecyclerView.Adapter<SessionListAdapter.VH>() {
        class VH(val view: View) : RecyclerView.ViewHolder(view) {
            val tvTitle: TextView = view.findViewById(R.id.tvSessionTitle)
        }

        override fun onCreateViewHolder(parent: ViewGroup, viewType: Int): VH {
            val v = LayoutInflater.from(parent.context).inflate(R.layout.item_session, parent, false)
            return VH(v)
        }

        override fun onBindViewHolder(holder: VH, position: Int) {
            val s = sessions[position]
            holder.tvTitle.text = s.title
            holder.tvTitle.setTextColor(if (s.id == selectedId) 0xFF1976D2.toInt() else 0xFF666666.toInt())
            holder.view.setOnClickListener { onSelect(s.id) }
            holder.view.setOnLongClickListener {
                androidx.appcompat.app.AlertDialog.Builder(holder.view.context)
                    .setMessage(holder.view.context.getString(R.string.session_delete_confirm))
                    .setPositiveButton(android.R.string.ok) { _, _ -> onDelete(s.id) }
                    .setNegativeButton(android.R.string.cancel, null)
                    .show()
                true
            }
        }

        override fun getItemCount(): Int = sessions.size

        fun updateList(newSessions: List<SessionStorage.ChatSession>, newSelectedId: String?) {
            sessions = newSessions
            selectedId = newSelectedId
            notifyDataSetChanged()
        }
    }
    
    /**
     * 显示推荐任务弹窗
     */
    private fun showRecommendationsPanel(recommendations: List<String>) {
        // 在人工客服页面、好友对话和管理员模式下，不显示推荐任务
        val conversationId = currentConversation?.id
        if (conversationId == ConversationListFragment.CONVERSATION_ID_CUSTOMER_SERVICE ||
            conversationId?.startsWith("friend_") == true ||
            conversationId == ConversationListFragment.CONVERSATION_ID_ADMIN_CUSTOMER_SERVICE) {
            binding.llRecommendationsPanel.visibility = android.view.View.GONE
            return
        }
        
        currentRecommendations = recommendations
        binding.llRecommendationsPanel.visibility = android.view.View.VISIBLE
        
        // 清除之前的推荐任务
        binding.llRecommendationsContent.removeAllViews()
        
        // 添加推荐任务按钮（浅蓝色圆角矩形样式，左侧图标+右侧文字，紧凑小巧）
        recommendations.forEach { recommendation ->
            if (recommendation.isNotBlank()) {
                val recommendationButton = android.widget.LinearLayout(requireContext()).apply {
                    orientation = android.widget.LinearLayout.HORIZONTAL
                    gravity = android.view.Gravity.CENTER_VERTICAL
                    setPadding(
                        (10 * resources.displayMetrics.density).toInt(),
                        (6 * resources.displayMetrics.density).toInt(),
                        (10 * resources.displayMetrics.density).toInt(),
                        (6 * resources.displayMetrics.density).toInt()
                    )
                    
                    // 设置背景（与聊天页面一致，浅灰色边框）
                    val drawable = android.graphics.drawable.GradientDrawable().apply {
                        setColor(0xFFF9F9F9.toInt()) // 与聊天页面一致的背景色
                        cornerRadius = 6f
                        setStroke(
                            (1 * resources.displayMetrics.density).toInt(),
                            0xFFE0E0E0.toInt() // 浅灰色边框
                        )
                    }
                    background = drawable
                    
                    // 设置点击效果
                    isClickable = true
                    isFocusable = true
                    setOnClickListener {
                        // 点击推荐任务，开始执行
                        startTaskFromRecommendation(recommendation)
                    }
                    
                    layoutParams = android.widget.LinearLayout.LayoutParams(
                        android.widget.LinearLayout.LayoutParams.WRAP_CONTENT, // 只占据包裹内容的空间
                        android.widget.LinearLayout.LayoutParams.WRAP_CONTENT
                    ).apply {
                        setMargins(0, 2, 0, 2) // 减小上下间距
                    }
                    
                    // 添加文字（更小）
                    val textView = android.widget.TextView(requireContext()).apply {
                        text = recommendation
                        textSize = 13f // 字体小一点
                        setTextColor(0xFF666666.toInt()) // 灰色文字
                        layoutParams = android.widget.LinearLayout.LayoutParams(
                            android.widget.LinearLayout.LayoutParams.WRAP_CONTENT,
                            android.widget.LinearLayout.LayoutParams.WRAP_CONTENT
                        )
                    }
                    addView(textView)
                }
                binding.llRecommendationsContent.addView(recommendationButton)
            }
        }
        
        // 默认收起状态
        isRecommendationsExpanded = false
        binding.llRecommendationsContent.visibility = android.view.View.GONE
        updateRecommendationsHeaderState()
    }
    
    /**
     * 切换推荐任务弹窗展开/收起状态
     */
    internal fun toggleRecommendationsPanel() {
        isRecommendationsExpanded = !isRecommendationsExpanded
        if (isRecommendationsExpanded) {
            binding.llRecommendationsContent.visibility = android.view.View.VISIBLE
        } else {
            binding.llRecommendationsContent.visibility = android.view.View.GONE
        }
        updateRecommendationsHeaderState()
    }
    
    /**
     * 隐藏推荐任务弹窗
     */
    private fun hideRecommendationsPanel() {
        binding.llRecommendationsPanel.visibility = android.view.View.GONE
        currentRecommendations = null
        isRecommendationsExpanded = false
        updateRecommendationsHeaderState()
    }
    
    // 当前评价请求的位置（用于移除）
    private var currentFeedbackRequestPosition: Int = -1
    
    /**
     * 显示评价请求（仅在满足条件时显示）
     * 条件：1. 端侧非批测模式 2. TopoClaw 3. 任务正常结束（非max_step触发）或异常情况（用户中断或达到最大限制）
     * @param taskUuid 任务的uuid（如果为null则使用当前的chatUuid）
     * @param taskQuery 任务的query（如果为null则使用当前的currentQuery）
     * @param isException 是否为异常情况（用户中断或达到最大限制），默认为false
     */
    fun showFeedbackRequest(taskUuid: String? = null, taskQuery: String? = null, isException: Boolean = false) {
        try {
            Log.d(TAG, "========== 开始检查评价请求显示条件 ==========")
            val mainActivity = activity as? MainActivity
            val isBatchTesting = mainActivity?.isBatchTesting ?: false
            Log.d(TAG, "[评价请求] isBatchTesting: $isBatchTesting")
            
            // 检查是否为端侧非批测模式
            if (isBatchTesting) {
                Log.d(TAG, "[评价请求] 当前为批测模式，不显示评价请求")
                return
            }
            
            // 移除对话类型限制：允许在所有对话中显示反馈窗口
            // 特别是当用户手动中断任务时（通过悬浮球），无论当前在哪个对话中都应该显示
            val currentConvId = currentConversation?.id
            Log.d(TAG, "[评价请求] currentConversation?.id: $currentConvId")
            Log.d(TAG, "[评价请求] 允许在所有对话中显示反馈窗口（批测模式除外）")
            if (CustomAssistantManager.isCustomAssistantId(currentConvId)) {
                Log.d(TAG, "[评价请求] 当前为自定义小助手会话，跳过反馈请求")
                return
            }
            
            // 检查chatAdapter是否可用
            val adapter = chatAdapter
            if (adapter == null) {
                Log.w(TAG, "[评价请求] chatAdapter为null，无法显示评价请求")
                return
            }
            
            // 显示评价请求消息，保存当前任务的uuid和query
            val currentTime = System.currentTimeMillis()
            val feedbackTaskUuid = taskUuid ?: chatUuid
            val feedbackTaskQuery = taskQuery ?: (currentQuery ?: "")
            Log.d(TAG, "[评价请求] 传入的taskUuid: $taskUuid, 传入的taskQuery: $taskQuery")
            Log.d(TAG, "[评价请求] 当前chatUuid: $chatUuid, 当前currentQuery: $currentQuery")
            Log.d(TAG, "[评价请求] 最终使用的feedbackTaskUuid: $feedbackTaskUuid, feedbackTaskQuery: $feedbackTaskQuery")
            
            // 检查最后一条消息是否是TopoClaw的回复，如果是则先添加操作按钮栏
            val items = adapter.getItems()
            Log.d(TAG, "[操作按钮] 检查消息列表，总共有${items.size}条消息")
            
            // 从后往前查找最后一条TopoClaw的消息（支持"小助手"和"TopoClaw"两种sender）
            var lastAssistantMessage: ChatItem.Message? = null
            for (i in items.size - 1 downTo 0) {
                val item = items[i]
                if (item is ChatItem.Message && !item.isUserMessage) {
                    // 检查sender是否为"小助手"或"TopoClaw"
                    if (ChatConstants.isMainAssistantSender(item.sender)) {
                        lastAssistantMessage = item
                        Log.d(TAG, "[操作按钮] 找到TopoClaw回复消息: sender=${item.sender}, isUserMessage=${item.isUserMessage}, message长度=${item.message.length}")
                        break
                    }
                }
            }
            
            // 准备要添加的items列表，确保原子性添加，避免异步更新导致的覆盖问题
            val itemsToAdd = mutableListOf<ChatItem>()
            
            if (lastAssistantMessage != null) {
                Log.d(TAG, "[操作按钮] 检测到TopoClaw回复，添加操作按钮栏，query=$feedbackTaskQuery")
                itemsToAdd.add(ChatItem.ActionButtons(
                    message = lastAssistantMessage.message,
                    query = feedbackTaskQuery,
                    timestamp = currentTime
                ))
                Log.d(TAG, "[操作按钮] 操作按钮栏已准备添加")
            } else {
                Log.d(TAG, "[操作按钮] 未找到TopoClaw回复消息，不添加操作按钮栏")
                // 打印最后几条消息的类型用于调试
                val lastFewItems = items.takeLast(5)
                lastFewItems.forEachIndexed { index, item ->
                    Log.d(TAG, "[操作按钮] 最后${index + 1}条消息类型: ${item.javaClass.simpleName}, 如果是Message: sender=${(item as? ChatItem.Message)?.sender}, isUserMessage=${(item as? ChatItem.Message)?.isUserMessage}")
                }
            }
            
            // 添加评价请求
            itemsToAdd.add(ChatItem.FeedbackRequest(
                timestamp = currentTime,
                taskUuid = feedbackTaskUuid,
                taskQuery = feedbackTaskQuery,
                isException = isException
            ))
            
            // 一次性添加所有items，确保原子性，避免异步更新导致的覆盖问题
            if (itemsToAdd.isNotEmpty()) {
                adapter.addItems(itemsToAdd)
                if (lastAssistantMessage != null) {
                    Log.d(TAG, "[操作按钮] 操作按钮栏已添加（与评价请求一起）")
                }
            }
            currentFeedbackRequestPosition = adapter.itemCount - 1
            scrollToBottom()
            Log.d(TAG, "[评价请求] 已显示评价请求，位置: $currentFeedbackRequestPosition, adapter.itemCount: ${adapter.itemCount}")
            Log.d(TAG, "========== 评价请求显示完成 ==========")
        } catch (e: Exception) {
            Log.e(TAG, "[评价请求] 显示评价请求失败: ${e.message}", e)
            e.printStackTrace()
        }
    }
    
    /**
     * 发送反馈到云侧
     * @param rating 评分（0-5，0表示未评分，-1表示异常情况）
     * @param feedbackText 反馈文本内容
     * @param itemPosition 评价消息在列表中的位置（用于移除，如果为-1则使用currentFeedbackRequestPosition）
     * @param taskUuid 任务的uuid（如果为null则使用当前的chatUuid）
     * @param taskQuery 任务的query（如果为null则使用当前的currentQuery）
     * @param removeItem 是否移除评价消息，默认为true
     */
    fun sendFeedback(rating: Int, feedbackText: String, itemPosition: Int = -1, taskUuid: String? = null, taskQuery: String? = null, removeItem: Boolean = true) {
        // 优先使用传入的taskUuid和taskQuery（来自FeedbackRequest），如果没有则使用当前的
        val uuid = taskUuid?.takeIf { it.isNotBlank() } ?: chatUuid
        val query = taskQuery?.takeIf { it.isNotBlank() } ?: (currentQuery ?: "")
        
        if (uuid.isBlank()) {
            Log.w(TAG, "uuid为空，无法发送反馈")
            Toast.makeText(requireContext(), "无法发送反馈：任务ID为空", Toast.LENGTH_SHORT).show()
            return
        }
        
        mainScope.launch {
            try {
                Log.d(TAG, "开始发送反馈: rating=$rating, feedbackText=$feedbackText, uuid=$uuid, query=$query")
                
                // 获取API服务实例
                val apiService = NetworkService.getApiService()
                if (apiService == null) {
                    Log.e(TAG, "无法获取API服务实例")
                    withContext(Dispatchers.Main) {
                        Toast.makeText(requireContext(), "无法发送反馈：网络服务未初始化", Toast.LENGTH_SHORT).show()
                    }
                    return@launch
                }
                
                // 调用API发送反馈，传递query参数以确保保存到正确的目录
                val response = apiService.sendFeedback(
                    uuid = uuid,
                    query = query,
                    feedback = rating,
                    feedbackText = if (feedbackText.isNotBlank()) feedbackText else null
                )
                
                if (response.isSuccessful) {
                    Log.d(TAG, "反馈发送成功")
                    
                    // 保存反馈到本地文件
                    saveFeedbackToFile(rating, feedbackText)
                    
                    // 从列表中移除评价消息（如果需要）
                    if (removeItem) {
                        withContext(Dispatchers.Main) {
                            chatAdapter?.let { adapter ->
                                val positionToRemove = if (itemPosition >= 0) itemPosition else currentFeedbackRequestPosition
                                if (positionToRemove >= 0 && positionToRemove < adapter.itemCount) {
                                    // 查找并移除FeedbackRequest类型的item
                                    val items = adapter.getItems()
                                    for (i in items.size - 1 downTo 0) {
                                        if (items[i] is ChatItem.FeedbackRequest) {
                                            adapter.removeItemAt(i)
                                            break
                                        }
                                    }
                                }
                            }
                            // 重置位置
                            currentFeedbackRequestPosition = -1
                        }
                    }
                } else {
                    Log.e(TAG, "反馈发送失败: ${response.code()} - ${response.message()}")
                    Toast.makeText(requireContext(), "反馈发送失败，请重试", Toast.LENGTH_SHORT).show()
                }
            } catch (e: Exception) {
                Log.e(TAG, "发送反馈时出错: ${e.message}", e)
                Toast.makeText(requireContext(), "发送反馈时出错: ${e.message}", Toast.LENGTH_SHORT).show()
            }
        }
    }
    
    /**
     * 同步发送反馈到云侧（用于客服按钮，确保在发送给客服之前完成）
     * @param rating 评分（0-5，0表示未评分，-1表示异常情况）
     * @param feedbackText 反馈文本内容
     * @param taskUuid 任务的uuid（如果为null则使用当前的chatUuid）
     * @param taskQuery 任务的query（如果为null则使用当前的currentQuery）
     */
    private suspend fun sendFeedbackSync(rating: Int, feedbackText: String, taskUuid: String? = null, taskQuery: String? = null) {
        // 在主线程获取uuid和query（避免并发问题）
        val uuid = withContext(Dispatchers.Main) {
            taskUuid?.takeIf { it.isNotBlank() } ?: chatUuid
        }
        val query = withContext(Dispatchers.Main) {
            taskQuery?.takeIf { it.isNotBlank() } ?: (currentQuery ?: "")
        }
        
        if (uuid.isBlank()) {
            Log.w(TAG, "[同步发送反馈] uuid为空，无法发送反馈")
            return
        }
        
        try {
            Log.d(TAG, "[同步发送反馈] 开始发送反馈: rating=$rating, feedbackText=$feedbackText, uuid=$uuid, query=$query")
            
            // 在IO线程执行网络请求
            withContext(Dispatchers.IO) {
                // 获取API服务实例
                val apiService = NetworkService.getApiService()
                if (apiService == null) {
                    Log.e(TAG, "[同步发送反馈] 无法获取API服务实例")
                    return@withContext
                }
                
                // 调用API发送反馈，传递query参数以确保保存到正确的目录
                val response = apiService.sendFeedback(
                    uuid = uuid,
                    query = query,
                    feedback = rating,
                    feedbackText = if (feedbackText.isNotBlank()) feedbackText else null
                )
                
                if (response.isSuccessful) {
                    Log.d(TAG, "[同步发送反馈] 反馈发送成功")
                    
                    // 保存反馈到本地文件（需要在主线程）
                    withContext(Dispatchers.Main) {
                        saveFeedbackToFile(rating, feedbackText)
                    }
                } else {
                    Log.e(TAG, "[同步发送反馈] 反馈发送失败: ${response.code()} - ${response.message()}")
                }
            }
        } catch (e: Exception) {
            Log.e(TAG, "[同步发送反馈] 发送反馈时出错: ${e.message}", e)
        }
    }
    
    /**
     * 发送反馈到云端并发送给客服（用于客服按钮）
     * @param rating 评分（0-5，0表示未评分，-1表示异常情况）
     * @param feedbackText 反馈文本内容
     * @param itemPosition 评价消息在列表中的位置（用于移除）
     * @param taskUuid 任务的uuid
     * @param taskQuery 任务的query
     */
    /**
     * 处理客服按钮点击（先发送反馈到云端，再发送给客服）
     * @param rating 评分（0-5，0表示未评分，-1表示异常情况）
     * @param feedbackText 反馈文本内容
     * @param itemPosition 评价消息在列表中的位置
     * @param taskUuid 任务的uuid
     * @param taskQuery 任务的query
     */
    fun handleCustomerServiceButtonClick(rating: Int, feedbackText: String, itemPosition: Int, taskUuid: String?, taskQuery: String?) {
        mainScope.launch {
            try {
                // 先发送反馈到云端
                sendFeedbackSync(rating, feedbackText, taskUuid, taskQuery)
                
                // 然后发送反馈给客服（会移除评价消息）
                sendFeedbackToCustomerService(rating, feedbackText, itemPosition, taskUuid, taskQuery)
            } catch (e: Exception) {
                Log.e(TAG, "[客服按钮] 发送反馈时出错: ${e.message}", e)
            }
        }
    }
    
