    /**
     * 分享消息（供 ActionButtonsViewHolder 调用）
     */
    fun shareMessage(message: String) {
        if (message.isBlank()) return
        try {
            val intent = android.content.Intent().apply {
                action = android.content.Intent.ACTION_SEND
                type = "text/plain"
                putExtra(android.content.Intent.EXTRA_TEXT, message)
            }
            startActivity(android.content.Intent.createChooser(intent, "分享"))
        } catch (e: Exception) {
            Log.e(TAG, "分享失败: ${e.message}", e)
            Toast.makeText(requireContext(), "分享失败", Toast.LENGTH_SHORT).show()
        }
    }
    
    /**
     * 取消反馈请求
     */
    fun cancelFeedbackRequest(itemPosition: Int = -1) {
        Log.d(TAG, "取消反馈请求")
        mainScope.launch {
            withContext(Dispatchers.Main) {
                chatAdapter?.let { adapter ->
                    val positionToRemove = if (itemPosition >= 0) itemPosition else currentFeedbackRequestPosition
                    if (positionToRemove >= 0 && positionToRemove < adapter.itemCount) {
                        // 查找并移除FeedbackRequest类型的item
                        val items = adapter.getItems()
                        for (i in items.size - 1 downTo 0) {
                            if (items[i] is ChatItem.FeedbackRequest) {
                                adapter.removeItemAt(i)
                                break
                            }
                        }
                    }
                }
                // 重置位置
                currentFeedbackRequestPosition = -1
            }
        }
    }
    
    /**
     * 发送反馈给客服
     */
    fun sendFeedbackToCustomerService(rating: Int, feedbackText: String, itemPosition: Int = -1, taskUuid: String? = null, taskQuery: String? = null) {
        // 优先使用传入的taskUuid和taskQuery（来自FeedbackRequest），如果没有则使用当前的
        val uuid = taskUuid?.takeIf { it.isNotBlank() } ?: chatUuid
        val query = taskQuery?.takeIf { it.isNotBlank() } ?: (currentQuery ?: "未知任务")
        
        Log.d(TAG, "[发送反馈给客服] 传入的taskUuid=$taskUuid, taskQuery=$taskQuery")
        Log.d(TAG, "[发送反馈给客服] 当前chatUuid=$chatUuid, currentQuery=$currentQuery")
        Log.d(TAG, "[发送反馈给客服] 最终使用的uuid=$uuid, query=$query")
        
        if (uuid.isBlank()) {
            Log.w(TAG, "uuid为空，无法发送反馈给客服")
            Toast.makeText(requireContext(), "无法发送反馈：任务ID为空", Toast.LENGTH_SHORT).show()
            return
        }
        
        mainScope.launch {
            try {
                Log.d(TAG, "开始发送反馈给客服: rating=$rating, feedbackText=$feedbackText, query=$query, uuid=$uuid")
                
                // 构建客服消息
                val serviceMessage = buildString {
                    append("我在执行任务\"$query($uuid)\"时遇到了问题，")
                    append("我的打分是$rating，")
                    append("我的评价是\"$feedbackText\"，")
                    append("请加紧分析出错原因并告知我处理结果")
                }
                
                val mainActivity = activity as? MainActivity
                
                // 检查当前是否已经是人工客服对话
                val isCustomerService = currentConversation?.id == ConversationListFragment.CONVERSATION_ID_CUSTOMER_SERVICE
                
                if (!isCustomerService) {
                    // 切换到人工客服对话
                    Log.d(TAG, "当前不是人工客服对话，切换到人工客服对话")
                    
                    // 将消息保存到SharedPreferences，供新Fragment读取
                    val prefs = requireContext().getSharedPreferences("app_prefs", android.content.Context.MODE_PRIVATE)
                    prefs.edit().putString("pending_customer_service_message", serviceMessage).apply()
                    
                    withContext(Dispatchers.Main) {
                        // 创建人工客服对话
                        val customerServiceConversation = Conversation(
                            id = ConversationListFragment.CONVERSATION_ID_CUSTOMER_SERVICE,
                            name = "人工客服",
                            avatar = null,
                            lastMessage = null,
                            lastMessageTime = System.currentTimeMillis(),
                            isPinned = false
                        )
                        
                        // 使用复用机制切换到聊天页面
                        mainActivity?.switchToChatFragment(customerServiceConversation)
                    }
                    
                    // 消息已保存到SharedPreferences，onViewCreated会自动读取并发送
                    // 不需要在这里手动发送，避免与onViewCreated中的逻辑冲突
                    Log.d(TAG, "消息已保存到SharedPreferences，等待onViewCreated自动发送")
                } else {
                    // 当前已经是客服对话，直接发送消息
                    Log.d(TAG, "当前已是客服对话，直接发送消息")
                    executeQueryFromExternal(serviceMessage)
                }
                
                // 从列表中移除评价消息
                withContext(Dispatchers.Main) {
                    chatAdapter?.let { adapter ->
                        val positionToRemove = if (itemPosition >= 0) itemPosition else currentFeedbackRequestPosition
                        if (positionToRemove >= 0 && positionToRemove < adapter.itemCount) {
                            // 查找并移除FeedbackRequest类型的item
                            val items = adapter.getItems()
                            for (i in items.size - 1 downTo 0) {
                                if (items[i] is ChatItem.FeedbackRequest) {
                                    adapter.removeItemAt(i)
                                    break
                                }
                            }
                        }
                    }
                    // 重置位置
                    currentFeedbackRequestPosition = -1
                }
            } catch (e: Exception) {
                Log.e(TAG, "发送反馈给客服时出错: ${e.message}", e)
                withContext(Dispatchers.Main) {
                    Toast.makeText(requireContext(), "发送反馈给客服时出错: ${e.message}", Toast.LENGTH_SHORT).show()
                }
            }
        }
    }
    
    /**
     * 保存反馈到本地文件
     */
    private fun saveFeedbackToFile(rating: Int, feedbackText: String) {
        mainScope.launch(Dispatchers.IO) {
            try {
                val context = context ?: return@launch
                val prefs = context.getSharedPreferences("app_prefs", android.content.Context.MODE_PRIVATE)
                
                // 读取现有反馈记录
                val feedbackKey = "feedback_records_${currentConversation?.id ?: "default"}"
                val existingJson = prefs.getString(feedbackKey, null)
                val feedbackArray = if (existingJson != null) {
                    org.json.JSONArray(existingJson)
                } else {
                    org.json.JSONArray()
                }
                
                // 添加新反馈
                feedbackArray.put(org.json.JSONObject().apply {
                    put("uuid", chatUuid)
                    put("rating", rating)
                    put("feedback_text", feedbackText)
                    put("timestamp", System.currentTimeMillis())
                })
                
                // 保存到SharedPreferences
                prefs.edit().putString(feedbackKey, feedbackArray.toString()).apply()
                
                Log.d(TAG, "反馈已保存到本地文件")
            } catch (e: Exception) {
                Log.e(TAG, "保存反馈到文件失败: ${e.message}", e)
            }
        }
    }
    
    /**
     * 隐藏媒体选择面板
     */
    internal fun hideMediaPanel() {
        if (!isMediaPanelVisible) {
            return
        }
        
        isMediaPanelVisible = false
        
        // 检查binding是否有效
        val currentBinding = _binding ?: return
        
        // 移除RecyclerView的点击监听（避免在Fragment销毁后执行）
        try {
            currentBinding.rvChatMessages.setOnClickListener(null)
        } catch (e: Exception) {
            Log.w(TAG, "移除RecyclerView点击监听失败: ${e.message}")
        }
        
        val currentHeight = currentBinding.llMediaPanel.height
        
        if (currentHeight <= 0) {
            currentBinding.llMediaPanel.visibility = View.GONE
            return
        }
        
        // 滑入动画
        android.animation.ValueAnimator.ofInt(currentHeight, 0).apply {
            duration = 250
            addUpdateListener { animation ->
                val binding = _binding ?: return@addUpdateListener
                val height = animation.animatedValue as Int
                val params = binding.llMediaPanel.layoutParams
                params.height = height
                binding.llMediaPanel.layoutParams = params
            }
            addListener(object : android.animation.AnimatorListenerAdapter() {
                override fun onAnimationEnd(animation: android.animation.Animator) {
                    val binding = _binding ?: return
                    binding.llMediaPanel.visibility = View.GONE
                    val params = binding.llMediaPanel.layoutParams
                    params.height = ViewGroup.LayoutParams.WRAP_CONTENT
                    binding.llMediaPanel.layoutParams = params
                }
            })
            start()
        }
    }
    
