    /**
     * 选择视频
     */
    /**
     * 开始屏幕录制
     * 注意：不再需要无障碍服务，录屏功能只使用 MediaProjection API
     * 流程：清除后台应用（可选） -> 弹出权限申请 -> 完成申请后自动到home页面 -> 开始录屏
     */
    internal fun startScreenRecording() {
        hideMediaPanel()
        
        // 在后台协程中执行清除后台应用，然后请求权限
        mainScope.launch {
            try {
                // 检查是否开启了"录制前清除后台应用"开关
                val prefs = requireContext().getSharedPreferences("app_prefs", Context.MODE_PRIVATE)
                val shouldClearBackground = prefs.getBoolean("clear_background_before_recording", false)
                
                if (shouldClearBackground) {
                    Log.d(TAG, "开始录制前清除后台应用")
                    
                    // 检查无障碍服务是否可用
                    val accessibilityService = MyAccessibilityService.getInstance()
                    if (accessibilityService != null && Build.VERSION.SDK_INT >= Build.VERSION_CODES.N) {
                        withContext(Dispatchers.Main) {
                            addChatMessage("系统", "录制前清除后台应用...")
                        }
                        
                        // 清除后台应用，清除后不返回主页（因为要在应用内请求权限）
                        val success = accessibilityService.clearAppFromRecentTasks(returnToHome = false)
                        withContext(Dispatchers.Main) {
                            if (success) {
                                addChatMessage("系统", "✓ 已清除后台应用")
                            } else {
                                addChatMessage("系统", "✗ 清除后台应用失败")
                            }
                        }
                        // 等待清除操作完成
                        delay(1000)
                    } else {
                        Log.w(TAG, "无障碍服务未就绪或版本过低，跳过清除后台应用")
                        withContext(Dispatchers.Main) {
                            addChatMessage("系统", "✗ 无障碍服务未就绪，跳过清除后台应用")
                        }
                    }
                } else {
                    Log.d(TAG, "录制前清除后台应用开关未开启，跳过清除操作")
                }
            } catch (e: Exception) {
                Log.e(TAG, "清除后台应用异常: ${e.message}", e)
                withContext(Dispatchers.Main) {
                    addChatMessage("系统", "✗ 清除后台应用异常: ${e.message}")
                }
            }
            
            // 清除完成后，在应用内请求MediaProjection权限
            withContext(Dispatchers.Main) {
                try {
                    // 检查 Fragment 和 Activity 是否仍然有效
                    if (!isAdded || activity == null) {
                        Log.e(TAG, "Fragment 未附加或 Activity 为 null，无法请求录屏权限")
                        return@withContext
                    }
                    
                    val mediaProjectionManager = requireContext().getSystemService(android.content.Context.MEDIA_PROJECTION_SERVICE) as MediaProjectionManager
                    val captureIntent = mediaProjectionManager.createScreenCaptureIntent()
                    startActivityForResult(captureIntent, ChatConstants.REQUEST_MEDIA_PROJECTION_RECORDING)
                    Log.d(TAG, "已请求录屏权限")
                } catch (e: Exception) {
                    Log.e(TAG, "请求录屏权限失败: ${e.message}", e)
                    Toast.makeText(requireContext(), "请求录屏权限失败: ${e.message}", Toast.LENGTH_SHORT).show()
                }
            }
        }
    }
    
    /**
     * 停止屏幕录制
     */
    internal fun stopScreenRecording() {
        try {
            val intent = Intent(requireContext(), ScreenRecordingService::class.java).apply {
                action = ScreenRecordingService.ACTION_STOP
            }
            requireContext().startService(intent)
            Log.d(TAG, "已发送停止录屏请求")
        } catch (e: Exception) {
            Log.e(TAG, "停止录屏失败: ${e.message}", e)
            Toast.makeText(requireContext(), "停止录屏失败: ${e.message}", Toast.LENGTH_SHORT).show()
        }
    }
    
    /**
     * 处理Activity结果（包括媒体选择和截图权限）
     */
    override fun onActivityResult(requestCode: Int, resultCode: Int, data: Intent?) {
        super.onActivityResult(requestCode, resultCode, data)
        
        when (requestCode) {
            ChatConstants.REQUEST_CODE_PICK_IMAGE -> {
                if (resultCode == android.app.Activity.RESULT_OK && data != null) {
                    val imageUri = data.data
                    if (imageUri != null) {
                        handleMediaSelection(imageUri, "image")
                    }
                }
            }
            ChatConstants.REQUEST_CODE_PICK_VIDEO -> {
                if (resultCode == android.app.Activity.RESULT_OK && data != null) {
                    val videoUri = data.data
                    if (videoUri != null) {
                        handleMediaSelection(videoUri, "video")
                    }
                }
            }
            ChatConstants.REQUEST_MEDIA_PROJECTION_RECORDING -> {
                if (resultCode == android.app.Activity.RESULT_OK && data != null) {
                    // 权限申请完成后，自动返回home页面
                    mainScope.launch {
                        try {
                            val accessibilityService = MyAccessibilityService.getInstance()
                            if (accessibilityService != null) {
                                withContext(Dispatchers.Main) {
                                    accessibilityService.goHome()
                                    Log.d(TAG, "权限申请完成后已返回home页面")
                                }
                                // 等待返回home页面完成
                                delay(800)
                            } else {
                                Log.w(TAG, "无障碍服务未就绪，跳过返回home页面")
                            }
                            
                            // 返回home页面后，启动录屏服务
                            withContext(Dispatchers.Main) {
                                val intent = Intent(requireContext(), ScreenRecordingService::class.java).apply {
                                    action = ScreenRecordingService.ACTION_START
                                    putExtra(ScreenRecordingService.EXTRA_RESULT_CODE, resultCode)
                                    putExtra(ScreenRecordingService.EXTRA_RESULT_DATA, data)
                                }
                                
                                if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.O) {
                                    requireContext().startForegroundService(intent)
                                } else {
                                    requireContext().startService(intent)
                                }
                                
                                Log.d(TAG, "已启动录屏服务")
                            }
                        } catch (e: Exception) {
                            Log.e(TAG, "返回home页面或启动录屏服务失败: ${e.message}", e)
                            // 即使返回home失败，也尝试启动录屏服务
                            try {
                                val intent = Intent(requireContext(), ScreenRecordingService::class.java).apply {
                                    action = ScreenRecordingService.ACTION_START
                                    putExtra(ScreenRecordingService.EXTRA_RESULT_CODE, resultCode)
                                    putExtra(ScreenRecordingService.EXTRA_RESULT_DATA, data)
                                }
                                
                                if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.O) {
                                    requireContext().startForegroundService(intent)
                                } else {
                                    requireContext().startService(intent)
                                }
                            } catch (e2: Exception) {
                                Log.e(TAG, "启动录屏服务失败: ${e2.message}", e2)
                                Toast.makeText(requireContext(), "启动录屏服务失败: ${e2.message}", Toast.LENGTH_SHORT).show()
                            }
                        }
                    }
                } else {
                    Toast.makeText(requireContext(), "录屏权限被拒绝", Toast.LENGTH_SHORT).show()
                }
            }
            ChatConstants.REQUEST_MEDIA_PROJECTION_CHAT -> {
                if (resultCode == android.app.Activity.RESULT_OK && data != null) {
                    // 安全检查：确保Fragment仍然附加到Activity
                    if (!isAdded) {
                        Log.w(TAG, "onActivityResult(截图权限): Fragment未附加，无法处理权限结果")
                        return
                    }
                    
                    // 启动ChatScreenshotService（包裹在try-catch中，防止startForegroundService异常导致崩溃）
                    try {
                        val ctx = context ?: run {
                            Log.w(TAG, "onActivityResult(截图权限): context为null，无法启动截图服务")
                            return
                        }
                        val intent = Intent(ctx, ChatScreenshotService::class.java).apply {
                            action = ChatScreenshotService.ACTION_START
                            putExtra(ChatScreenshotService.EXTRA_RESULT_CODE, resultCode)
                            putExtra(ChatScreenshotService.EXTRA_RESULT_DATA, data)
                        }
                        
                        if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.O) {
                            ctx.startForegroundService(intent)
                        } else {
                            ctx.startService(intent)
                        }
                        Log.d(TAG, "onActivityResult(截图权限): 截图服务已启动")
                    } catch (e: Exception) {
                        Log.e(TAG, "onActivityResult(截图权限): 启动截图服务失败: ${e.message}", e)
                        addChatMessage("系统", "启动截图服务失败: ${e.message}")
                        pendingQueryAfterPermission = null
                        return
                    }
                    
                    addChatMessage("系统", "截图权限已授权")
                    
                    // 权限授权后，立即检查Fragment状态，确保ChatFragment仍然可见
                    if (isAdded && activity != null) {
                        // 检查Fragment是否被隐藏或当前显示的Fragment不是ChatFragment
                        if (isHidden) {
                            val conversation = currentConversation ?: (arguments?.getSerializable("conversation") as? Conversation)
                            if (conversation != null) {
                                (activity as? MainActivity)?.switchToChatFragment(conversation)
                            }
                        } else {
                            val currentFragment = (activity as? MainActivity)?.getActiveFragment()
                            if (currentFragment !is ChatFragment) {
                                val conversation = currentConversation ?: (arguments?.getSerializable("conversation") as? Conversation)
                                if (conversation != null) {
                                    (activity as? MainActivity)?.switchToChatFragment(conversation)
                                }
                            }
                        }
                    } else {
                        val conversation = currentConversation ?: (arguments?.getSerializable("conversation") as? Conversation)
                        if (conversation != null && activity != null) {
                            (activity as? MainActivity)?.switchToChatFragment(conversation)
                        }
                    }
                    
                    view?.postDelayed({
                        if (isAdded && activity != null) {
                            val currentFragment = (activity as? MainActivity)?.getActiveFragment()
                            if (currentFragment !is ChatFragment) {
                                val conversation = currentConversation ?: (arguments?.getSerializable("conversation") as? Conversation)
                                if (conversation != null) {
                                    (activity as? MainActivity)?.switchToChatFragment(conversation)
                                }
                            }
                        }
                    }, 100) // 延迟100ms再次检查
                    
                    // 延迟恢复返回键处理，避免权限授权对话框关闭时触发返回键导致Fragment切换
                    view?.postDelayed({
                        if (isAdded && view != null) {
                            onBackPressedCallback?.isEnabled = true
                        }
                    }, 500) // 延迟500ms恢复返回键处理，确保权限授权对话框完全关闭
                    
                    // 如果有待发送的消息，立即处理（权限已授权，可以继续执行任务）
                    val pendingQuery = pendingQueryAfterPermission
                    if (pendingQuery != null) {
                        // 延迟一下确保服务完全初始化，然后立即执行任务
                        view?.postDelayed({
                            if (isAdded && view != null) {
                                val currentPendingQuery = pendingQueryAfterPermission
                                if (currentPendingQuery != null) {
                                    val chatService = ChatScreenshotService.getInstance()
                                    val isReady = chatService != null && chatService.isReady()
                                    if (isReady) {
                                        // 清除pendingQueryAfterPermission（在确认可以执行后再清除）
                                        pendingQueryAfterPermission = null
                                        addChatMessage("系统", "正在自动发送消息...")
                                        executeQueryInternal(currentPendingQuery)
                                    }
                                    // 服务未就绪时，保留pendingQueryAfterPermission，让onResume来处理
                                }
                            }
                        }, 500) // 延迟500ms等待服务初始化
                    }
                    // 自定义小助手/gui_execute 仅缺截图时：服务初始化后再尝试补无障碍或启动（避免仅 onResume 时 isReady 仍为 false 卡住）
                    if (pendingCustomAssistantExecution != null) {
                        view?.postDelayed({
                            if (isAdded && view != null) {
                                tryResumePendingCustomAssistantExecution("onActivityResult(截图权限)")
                            }
                        }, 500)
                    }
                } else {
                    addChatMessage("系统", "截图权限授权失败")
                    pendingQueryAfterPermission = null
                    pendingCustomAssistantExecution?.guiExecuteContext?.let { guiCtx ->
                        pendingCustomAssistantExecution = null
                        pendingCustomAssistantA11yDialogShown = false
                        guiCtx.sendResult(null, "截图权限未授予")
                    }
                    // 延迟恢复返回键处理，避免权限授权对话框关闭时触发返回键导致Fragment切换
                    view?.postDelayed({
                        if (isAdded && view != null) {
                            onBackPressedCallback?.isEnabled = true
                            Log.d(TAG, "onActivityResult(截图权限): 权限授权失败，延迟恢复返回键处理")
                        } else {
                            Log.w(TAG, "onActivityResult(截图权限): Fragment已销毁，无法恢复返回键处理")
                        }
                    }, 500) // 延迟500ms恢复返回键处理，确保权限授权对话框完全关闭
                }
            }
        }
    }
    
    /**
     * 处理权限请求结果
     */
    override fun onRequestPermissionsResult(requestCode: Int, permissions: Array<out String>, grantResults: IntArray) {
        super.onRequestPermissionsResult(requestCode, permissions, grantResults)
        
        when (requestCode) {
            1001 -> {  // 录音权限
                if (grantResults.isNotEmpty() && grantResults[0] == PackageManager.PERMISSION_GRANTED) {
                    // 权限已授予，开始语音识别
                    startVoiceRecognition()
                } else {
                    // 权限被拒绝
                    Toast.makeText(requireContext(), "需要录音权限才能使用语音输入", Toast.LENGTH_SHORT).show()
                }
            }
            ChatConstants.REQUEST_CODE_SAVE_CHAT_IMAGE_GALLERY -> {
                val pending = pendingSaveGalleryUri
                pendingSaveGalleryUri = null
                if (grantResults.isNotEmpty() && grantResults[0] == PackageManager.PERMISSION_GRANTED) {
                    if (pending != null) trySaveGalleryImage(pending)
                } else {
                    Toast.makeText(requireContext(), getString(R.string.chat_storage_permission_for_save), Toast.LENGTH_SHORT).show()
                }
            }
            ChatConstants.REQUEST_CODE_MOBILE_TOOL_LOCATION -> {
                val pending = pendingLocationToolRequest ?: pendingLocationPermissionRequest
                if (pending == null) {
                    Log.w(TAG, "定位权限回调到达，但 pending 请求不存在，无法继续执行")
                    return
                }
                val granted =
                    ContextCompat.checkSelfPermission(requireContext(), Manifest.permission.ACCESS_COARSE_LOCATION) == PackageManager.PERMISSION_GRANTED ||
                        ContextCompat.checkSelfPermission(requireContext(), Manifest.permission.ACCESS_FINE_LOCATION) == PackageManager.PERMISSION_GRANTED
                if (granted) {
                    pendingLocationToolRequest = pending
                    pendingLocationPermissionRequest = null
                    executeLocationToolRequest(pending)
                } else {
                    clearPendingLocationRequest(pending.requestId)
                    sendMobileToolResult(
                        requestId = pending.requestId,
                        protocol = pending.protocol,
                        conversationId = pending.conversationId,
                        ok = false,
                        tool = "device.get_location",
                        data = null,
                        errorCode = "PERMISSION_DENIED",
                        errorMessage = "用户拒绝定位权限",
                        retryable = true
                    )
                }
            }
        }
    }

    private fun clearPendingLocationRequest(requestId: String) {
        if (pendingLocationToolRequest?.requestId == requestId) {
            pendingLocationToolRequest = null
        }
        if (pendingLocationPermissionRequest?.requestId == requestId) {
            pendingLocationPermissionRequest = null
        }
    }
    
    /**
     * 处理选择的媒体
     */
    private fun handleMediaSelection(uri: android.net.Uri, type: String) {
        Log.d(TAG, "选择了媒体: type=$type, uri=$uri")
        
        if (type == "image") {
            selectedImageUri = uri
            // 在后台协程中处理图片转换
            mainScope.launch {
                try {
                    val bitmap = withContext(Dispatchers.IO) {
                        requireContext().contentResolver.openInputStream(uri)?.use { inputStream ->
                            android.graphics.BitmapFactory.decodeStream(inputStream)
                        }
                    }
                    
                    if (bitmap != null) {
                        // 记录原始图片尺寸（压缩前）
                        val originalWidth = bitmap.width
                        val originalHeight = bitmap.height
                        
                        // 创建bitmap副本用于预览（因为原始bitmap会被recycle）
                        val previewBitmap = bitmap.copy(bitmap.config, false)
                        selectedImageBitmap = previewBitmap
                        
                        // 转换为Base64（ScreenshotHelper会自动压缩到40%分辨率）
                        selectedImageBase64 = screenshotBitmapToBase64(bitmap)
                        bitmap.recycle()  // 回收原始bitmap
                        
                        val cr = ScreenshotCompressionPrefs.getRatio(requireContext())
                        Log.d(TAG, "用户上传图片原始尺寸: ${originalWidth}x${originalHeight}，压缩后尺寸: ${(originalWidth * cr).toInt()}x${(originalHeight * cr).toInt()}")
                        
                        withContext(Dispatchers.Main) {
                            // 显示图片预览
                            showImagePreview(previewBitmap)
                            // 更新发送按钮状态
                            updateSendButtonVisibility()
                        }
                        Log.d(TAG, "图片处理完成，Base64长度: ${selectedImageBase64?.length ?: 0}")
                    } else {
                        withContext(Dispatchers.Main) {
                            Toast.makeText(requireContext(), "图片加载失败", Toast.LENGTH_SHORT).show()
                        }
                    }
                } catch (e: Exception) {
                    Log.e(TAG, "处理图片失败: ${e.message}", e)
                    withContext(Dispatchers.Main) {
                        Toast.makeText(requireContext(), "图片处理失败: ${e.message}", Toast.LENGTH_SHORT).show()
                    }
                }
            }
        } else {
            Toast.makeText(requireContext(), "已选择${if (type == "image") "图片" else "视频"}: $uri", Toast.LENGTH_SHORT).show()
        }
    }
    
    /**
     * 显示图片预览
     */
    private fun showImagePreview(bitmap: android.graphics.Bitmap) {
        try {
            binding.ivSelectedImage.setImageBitmap(bitmap)
            
            // 显示预览区域（不再显示图片信息）
            binding.llImagePreview.visibility = android.view.View.VISIBLE
            Log.d(TAG, "图片预览已显示: ${bitmap.width}x${bitmap.height}")
        } catch (e: Exception) {
            Log.e(TAG, "显示图片预览失败: ${e.message}", e)
        }
    }
    
    /**
     * 移除选择的图片
     */
    internal fun removeSelectedImage() {
        selectedImageUri = null
        selectedImageBase64 = null
        selectedImageBitmap?.recycle()
        selectedImageBitmap = null
        
        // 隐藏预览区域
        binding.llImagePreview.visibility = android.view.View.GONE
        binding.ivSelectedImage.setImageBitmap(null)
        
        // 更新发送按钮状态
        updateSendButtonVisibility()
        
        Log.d(TAG, "已移除选择的图片")
    }
    
    /**
     * 全屏显示图片（应用内查看；长按弹出操作菜单）
     */
    internal fun showImageFullScreen(uri: android.net.Uri) {
        try {
            val imageUri = resolveImageUriForFullscreen(uri) ?: return
            val dialog = Dialog(requireContext(), android.R.style.Theme_Black_NoTitleBar_Fullscreen)
            val dialogView = layoutInflater.inflate(R.layout.dialog_chat_image_fullscreen, null)
            dialog.setContentView(dialogView)
            val viewPager = dialogView.findViewById<ViewPager2>(R.id.vpFullscreenImages)
            val counterText = dialogView.findViewById<TextView>(R.id.tvImageCounter)
            val (imageUris, initialIndex) = collectConversationImageUris(imageUri)
            val pagerAdapter = FullscreenImagePagerAdapter(
                context = requireContext(),
                imageUris = imageUris,
                decodeBitmap = { targetUri -> decodeBitmapForDisplay(targetUri) },
                onSingleTap = { dialog.dismiss() },
                onLongPress = { targetUri ->
                    if (isAdded) {
                        showImageLongPressActions(targetUri)
                    }
                }
            )
            viewPager.adapter = pagerAdapter
            viewPager.setCurrentItem(initialIndex, false)

            val updateCounter: (Int) -> Unit = { position ->
                counterText.text = "${position + 1} / ${imageUris.size}"
            }
            updateCounter(initialIndex)
            viewPager.registerOnPageChangeCallback(object : ViewPager2.OnPageChangeCallback() {
                override fun onPageSelected(position: Int) {
                    updateCounter(position)
                }
            })

            dialog.setOnDismissListener {
                pagerAdapter.release()
            }
            dialog.window?.apply {
                setLayout(ViewGroup.LayoutParams.MATCH_PARENT, ViewGroup.LayoutParams.MATCH_PARENT)
                setBackgroundDrawableResource(android.R.color.black)
            }
            dialog.show()
            dialog.window?.let { window ->
                FullscreenImageDialogHelper.applyBlackSystemBars(window, dialogView)
            }
        } catch (e: Exception) {
            Log.e(TAG, "全屏显示图片失败: ${e.message}", e)
            Toast.makeText(requireContext(), getString(R.string.chat_save_image_failed), Toast.LENGTH_SHORT).show()
        }
    }

    private fun collectConversationImageUris(clickedUri: Uri): Pair<List<Uri>, Int> {
        val ordered = linkedMapOf<String, Uri>()
        chatAdapter?.getItems()?.forEach { item ->
            val imagePath = when (item) {
                is ChatItem.ImageMessage -> item.imagePath
                is ChatItem.ReceivedImageMessage -> item.imagePath
                else -> null
            } ?: return@forEach
            val safeFile = ChatImagePathGuard.resolveSafeLocalImageFile(requireContext(), imagePath) ?: return@forEach
            val safeUri = ChatImagePathGuard.toSafeViewUri(requireContext(), safeFile) ?: return@forEach
            ordered.putIfAbsent(safeUri.toString(), safeUri)
        }

        val imageUris = ordered.values.toMutableList()
        val clickedIndex = imageUris.indexOfFirst { it.toString() == clickedUri.toString() }
        val initialIndex = if (clickedIndex >= 0) {
            clickedIndex
        } else {
            imageUris.add(clickedUri)
            imageUris.lastIndex
        }
        return imageUris to initialIndex
    }
    
    private fun resolveImageUriForFullscreen(uri: Uri): Uri? {
        val safeUri = ChatImagePathGuard.resolveSafeViewUri(requireContext(), uri)
        if (safeUri == null) {
            Log.e(TAG, "不安全或无效图片 URI: $uri")
            Toast.makeText(requireContext(), getString(R.string.chat_image_load_failed), Toast.LENGTH_SHORT).show()
        }
        return safeUri
    }
    
    private fun decodeBitmapForDisplay(uri: Uri): Bitmap? {
        val resolver = requireContext().contentResolver
        val bounds = BitmapFactory.Options().apply { inJustDecodeBounds = true }
        // 仅读尺寸时 decodeStream 返回 null 属正常，不能用 ?: return null 误伤整条分支
        val inputForBounds = resolver.openInputStream(uri) ?: return null
        inputForBounds.use { BitmapFactory.decodeStream(it, null, bounds) }
        if (bounds.outWidth <= 0 || bounds.outHeight <= 0) return null
        var sample = 1
        val maxSide = 2048
        while (bounds.outWidth / sample > maxSide || bounds.outHeight / sample > maxSide) {
            sample *= 2
        }
        val opts = BitmapFactory.Options().apply { inSampleSize = sample }
        return resolver.openInputStream(uri)?.use { stream ->
            BitmapFactory.decodeStream(stream, null, opts)
        }
    }
    
    /** 长按后弹出图片操作菜单（保存、应用内分享、系统分享） */
    private fun showImageLongPressActions(imageUri: Uri) {
        if (!isAdded) return
        try {
            val dialog = AlertDialog.Builder(requireContext())
                .setItems(
                    arrayOf(
                        getString(R.string.chat_save_image),
                        "分享给应用内好友/群组",
                        "分享到其他应用"
                    )
                ) { _, which ->
                    when (which) {
                        0 -> trySaveGalleryImage(imageUri)
                        1 -> showInAppImageShareTargetPicker(imageUri)
                        2 -> shareImageToExternalApps(imageUri)
                    }
                }
                .create()
            dialog.show()
            dialog.window?.setBackgroundDrawableResource(R.drawable.dialog_rounded_background)
        } catch (e: Exception) {
            Log.e(TAG, "保存图片菜单失败: ${e.message}", e)
            Toast.makeText(requireContext(), getString(R.string.chat_save_image_failed), Toast.LENGTH_SHORT).show()
        }
    }

    private fun showInAppImageShareTargetPicker(imageUri: Uri) {
        if (!isAdded) return
        try {
            val friends = FriendManager.getFriends(requireContext())
                .filter { it.status == "accepted" }
            val groups = GroupManager.getGroups(requireContext())

            val friendOptions = mutableListOf<ShareTargetOption>()
            val groupOptions = mutableListOf<ShareTargetOption>()

            friends.forEach { friend ->
                friendOptions.add(
                    ShareTargetOption(
                        label = "好友: ${friend.nickname ?: friend.imei.take(8) + "..."}",
                        targetType = "friend",
                        targetId = friend.imei
                    )
                )
            }
            groups.forEach { group ->
                groupOptions.add(
                    ShareTargetOption(
                        label = "群组: ${group.name}",
                        targetType = "group",
                        targetId = group.groupId
                    )
                )
            }

            if (friendOptions.isEmpty() && groupOptions.isEmpty()) {
                Toast.makeText(requireContext(), "暂无好友或群组可分享", Toast.LENGTH_SHORT).show()
                return
            }

            var isFriendExpanded = true
            var isGroupExpanded = true
            var queryText = ""
            val shownRows = mutableListOf<ShareTargetRow>()
            val labels = mutableListOf<String>()
            val dialogView = LayoutInflater.from(requireContext())
                .inflate(R.layout.dialog_share_target_picker, null)
            val listView = dialogView.findViewById<ListView>(R.id.lvTargets)
            val searchInput = dialogView.findViewById<android.widget.EditText>(R.id.etSearch)
            val searchButton = dialogView.findViewById<android.widget.ImageButton>(R.id.btnSearch)
            val closeButton = dialogView.findViewById<android.widget.ImageButton>(R.id.btnClose)
            val adapter = ArrayAdapter(requireContext(), android.R.layout.simple_list_item_1, labels)
            listView.adapter = adapter

            fun rebuildRows() {
                val query = queryText.trim().lowercase(Locale.getDefault())
                val filteredFriends = if (query.isEmpty()) {
                    friendOptions
                } else {
                    friendOptions.filter { it.label.lowercase(Locale.getDefault()).contains(query) }
                }
                val filteredGroups = if (query.isEmpty()) {
                    groupOptions
                } else {
                    groupOptions.filter { it.label.lowercase(Locale.getDefault()).contains(query) }
                }

                shownRows.clear()
                labels.clear()

                shownRows.add(ShareTargetRow.Header("friend"))
                labels.add("好友 ${if (isFriendExpanded) "▼" else "▶"} (${filteredFriends.size})")
                if (isFriendExpanded) {
                    filteredFriends.forEach { option ->
                        shownRows.add(ShareTargetRow.Item(option))
                        labels.add(option.label)
                    }
                }

                shownRows.add(ShareTargetRow.Header("group"))
                labels.add("群组 ${if (isGroupExpanded) "▼" else "▶"} (${filteredGroups.size})")
                if (isGroupExpanded) {
                    filteredGroups.forEach { option ->
                        shownRows.add(ShareTargetRow.Item(option))
                        labels.add(option.label)
                    }
                }

                adapter.notifyDataSetChanged()
            }

            val dialog = AlertDialog.Builder(requireContext())
                .setView(dialogView)
                .create()

            listView.setOnItemClickListener { _, _, position, _ ->
                when (val row = shownRows.getOrNull(position) ?: return@setOnItemClickListener) {
                    is ShareTargetRow.Header -> {
                        if (row.section == "friend") {
                            isFriendExpanded = !isFriendExpanded
                        } else if (row.section == "group") {
                            isGroupExpanded = !isGroupExpanded
                        }
                        rebuildRows()
                    }
                    is ShareTargetRow.Item -> {
                        dialog.dismiss()
                        val targetType = row.option.targetType
                        val targetId = row.option.targetId
                        if (targetType == "friend" || targetType == "group") {
                            shareImageToInAppTarget(imageUri, targetType, targetId)
                        }
                    }
                }
            }

            closeButton.setOnClickListener { dialog.dismiss() }
            searchButton.setOnClickListener {
                if (searchInput.visibility == View.VISIBLE) {
                    searchInput.visibility = View.GONE
                    searchInput.setText("")
                } else {
                    searchInput.visibility = View.VISIBLE
                    searchInput.requestFocus()
                }
            }
            searchInput.addTextChangedListener(object : android.text.TextWatcher {
                override fun beforeTextChanged(s: CharSequence?, start: Int, count: Int, after: Int) = Unit
                override fun onTextChanged(s: CharSequence?, start: Int, before: Int, count: Int) {
                    queryText = s?.toString().orEmpty()
                    rebuildRows()
                }
                override fun afterTextChanged(s: android.text.Editable?) = Unit
            })

            rebuildRows()
            dialog.show()
            dialog.window?.setBackgroundDrawableResource(R.drawable.dialog_rounded_background)
        } catch (e: Exception) {
            Log.e(TAG, "打开应用内分享目标选择失败: ${e.message}", e)
            Toast.makeText(requireContext(), "分享失败：${e.message}", Toast.LENGTH_SHORT).show()
        }
    }

    private fun shareImageToInAppTarget(imageUri: Uri, targetType: String, targetId: String) {
        mainScope.launch {
            try {
                val mainActivity = activity as? MainActivity
                val webSocket = mainActivity?.getCustomerServiceWebSocket()
                if (webSocket == null || !webSocket.isConnected()) {
                    Toast.makeText(requireContext(), "无法连接到服务器，请稍后重试", Toast.LENGTH_SHORT).show()
                    return@launch
                }

                val imageBase64 = encodeImageUriToBase64(imageUri)
                if (imageBase64.isNullOrBlank()) {
                    Toast.makeText(requireContext(), "图片读取失败，无法分享", Toast.LENGTH_SHORT).show()
                    return@launch
                }

                val imagePathForLocalEcho = withContext(Dispatchers.IO) {
                    ChatImageUtils.saveImageFromBase64(requireContext(), imageBase64)
                }
                if (imagePathForLocalEcho == null) {
                    Toast.makeText(requireContext(), "图片处理失败，无法分享", Toast.LENGTH_SHORT).show()
                    return@launch
                }

                when (targetType) {
                    "friend" -> {
                        webSocket.sendFriendMessage(targetId, "[图片]", imageBase64)
                        val friend = FriendManager.getFriends(requireContext()).firstOrNull { it.imei == targetId }
                        val friendConversation = Conversation(
                            id = "friend_$targetId",
                            name = friend?.nickname ?: "好友",
                            avatar = friend?.avatar,
                            lastMessage = null,
                            lastMessageTime = System.currentTimeMillis()
                        )
                        val chatFragment = mainActivity.getOrCreateChatFragment(friendConversation)
                        chatFragment.addImageMessage(imagePathForLocalEcho, saveToHistory = true, sender = "我")
                        mainActivity.switchToChatFragment(friendConversation)
                        Toast.makeText(requireContext(), "图片已分享给好友", Toast.LENGTH_SHORT).show()
                    }

                    "group" -> {
                        val messageText = "[图片]"
                        val messageId = webSocket.sendGroupMessage(targetId, messageText, imageBase64)
                        markOwnGroupMessageSent(
                            groupId = targetId,
                            content = messageText,
                            messageType = "image",
                            messageId = messageId
                        )
                        val group = GroupManager.getGroups(requireContext()).firstOrNull { it.groupId == targetId }
                        val groupConversation = Conversation(
                            id = "group_$targetId",
                            name = group?.name ?: "群组",
                            avatar = null,
                            lastMessage = null,
                            lastMessageTime = System.currentTimeMillis()
                        )
                        val chatFragment = mainActivity.getOrCreateChatFragment(groupConversation)
                        chatFragment.addImageMessage(imagePathForLocalEcho, saveToHistory = true, sender = "我")
                        mainActivity.switchToChatFragment(groupConversation)
                        Toast.makeText(requireContext(), "图片已分享到群组", Toast.LENGTH_SHORT).show()
                    }
                }
            } catch (e: Exception) {
                Log.e(TAG, "应用内分享图片失败: ${e.message}", e)
                Toast.makeText(requireContext(), "分享失败：${e.message}", Toast.LENGTH_SHORT).show()
            }
        }
    }

    private suspend fun encodeImageUriToBase64(imageUri: Uri): String? = withContext(Dispatchers.IO) {
        try {
            val bitmap = requireContext().contentResolver.openInputStream(imageUri)?.use { inputStream ->
                BitmapFactory.decodeStream(inputStream)
            } ?: return@withContext null
            try {
                screenshotBitmapToBase64(bitmap)
            } finally {
                bitmap.recycle()
            }
        } catch (e: Exception) {
            Log.e(TAG, "编码分享图片失败: ${e.message}", e)
            null
        }
    }

    private fun shareImageToExternalApps(imageUri: Uri) {
        if (!isAdded) return
        try {
            val mimeType = requireContext().contentResolver.getType(imageUri)
                ?.takeIf { it.startsWith("image/") }
                ?: "image/*"
            val shareIntent = Intent(Intent.ACTION_SEND).apply {
                type = mimeType
                putExtra(Intent.EXTRA_STREAM, imageUri)
                addFlags(Intent.FLAG_GRANT_READ_URI_PERMISSION)
            }
            startActivity(Intent.createChooser(shareIntent, "分享图片"))
        } catch (e: Exception) {
            Log.e(TAG, "系统分享图片失败: ${e.message}", e)
            Toast.makeText(requireContext(), "分享失败：${e.message}", Toast.LENGTH_SHORT).show()
        }
    }
    
    private fun trySaveGalleryImage(uri: Uri) {
        if (Build.VERSION.SDK_INT < Build.VERSION_CODES.Q) {
            if (ContextCompat.checkSelfPermission(requireContext(), Manifest.permission.WRITE_EXTERNAL_STORAGE)
                != PackageManager.PERMISSION_GRANTED
            ) {
                pendingSaveGalleryUri = uri
                requestPermissions(
                    arrayOf(Manifest.permission.WRITE_EXTERNAL_STORAGE),
                    ChatConstants.REQUEST_CODE_SAVE_CHAT_IMAGE_GALLERY
                )
                return
            }
        }
        mainScope.launch {
            val ok = ChatImageGallerySaver.saveImageFromUri(requireContext(), uri)
            withContext(Dispatchers.Main) {
                Toast.makeText(
                    requireContext(),
                    if (ok) getString(R.string.chat_saved_to_gallery) else getString(R.string.chat_save_image_failed),
                    Toast.LENGTH_SHORT
                ).show()
            }
        }
    }
    
    /**
     * 压缩Bitmap
     */
    private fun screenshotBitmapToBase64(bitmap: android.graphics.Bitmap): String =
        ScreenshotHelper.bitmapToBase64(bitmap, requireContext())

    /**
     * 将压缩后图片的坐标映射回原始屏幕坐标
     * @param compressedX 压缩后图片的X坐标
     * @param compressedY 压缩后图片的Y坐标
     * @return Pair<Int, Int> 原始屏幕坐标 (x, y)
     */
    private fun mapCompressedCoordinateToOriginal(compressedX: Int, compressedY: Int): Pair<Int, Int> {
        if (currentOriginalImageWidth == 0 || currentOriginalImageHeight == 0) {
            // 如果没有记录原始尺寸，说明可能是用户上传的图片或其他情况，直接返回原坐标
            Log.w(TAG, "未记录原始图片尺寸，无法映射坐标，使用原坐标: ($compressedX, $compressedY)")
            return Pair(compressedX, compressedY)
        }
        
        val ratio = ScreenshotCompressionPrefs.getRatio(requireContext())
        val originalX = (compressedX / ratio).toInt()
        val originalY = (compressedY / ratio).toInt()
        
        Log.d(TAG, "坐标映射: 压缩后($compressedX, $compressedY) -> 原始($originalX, $originalY), 原始尺寸: ${currentOriginalImageWidth}x${currentOriginalImageHeight}")
        
        return Pair(originalX, originalY)
    }
    
    private fun compressBitmap(bitmap: android.graphics.Bitmap, maxWidth: Int, maxHeight: Int, quality: Int): android.graphics.Bitmap {
        val width = bitmap.width
        val height = bitmap.height
        
        if (width <= maxWidth && height <= maxHeight) {
            return bitmap
        }
        
        val scale = minOf(maxWidth.toFloat() / width, maxHeight.toFloat() / height)
        val newWidth = (width * scale).toInt()
        val newHeight = (height * scale).toInt()
        
        return android.graphics.Bitmap.createScaledBitmap(bitmap, newWidth, newHeight, true)
    }
    
    /**
     * 检查是否有文本被选中
     */
    internal fun checkHasTextSelection(): Boolean {
        try {
            val recyclerView = binding.rvChatMessages
            for (i in 0 until recyclerView.childCount) {
                val child = recyclerView.getChildAt(i)
                if (hasTextSelectionRecursive(child)) {
                    return true
                }
            }
        } catch (e: Exception) {
            Log.e(TAG, "检查文本选择失败: ${e.message}", e)
        }
        return false
    }
    
    /**
     * 递归检查视图树中是否有文本被选中
     */
    private fun hasTextSelectionRecursive(view: android.view.View): Boolean {
        if (view is android.widget.TextView) {
            return view.hasSelection()
        } else if (view is android.view.ViewGroup) {
            for (i in 0 until view.childCount) {
                if (hasTextSelectionRecursive(view.getChildAt(i))) {
                    return true
                }
            }
        }
        return false
    }
    
    /**
     * 清除所有文本选择
     */
    internal fun clearTextSelection() {
        try {
            // 遍历所有消息气泡，清除文本选择
            val recyclerView = binding.rvChatMessages
            for (i in 0 until recyclerView.childCount) {
                val child = recyclerView.getChildAt(i)
                clearTextSelectionRecursive(child)
            }
        } catch (e: Exception) {
            Log.e(TAG, "清除文本选择失败: ${e.message}", e)
        }
    }
    
    /**
     * 递归清除视图树中的文本选择
     */
    private fun clearTextSelectionRecursive(view: android.view.View) {
        if (view is android.widget.TextView) {
            // 清除文本选择：移除焦点并清除选择
            try {
                if (view.hasSelection()) {
                    // 通过清除焦点来清除文本选择
                    // clearFocus() 会自动清除文本选择状态
                    view.clearFocus()
                    // 确保视图失去焦点
                    view.isSelected = false
                } else {
                    view.clearFocus()
                }
            } catch (e: Exception) {
                // 如果清除选择失败，至少清除焦点
                Log.e(TAG, "清除文本选择失败: ${e.message}", e)
                view.clearFocus()
            }
        } else if (view is android.view.ViewGroup) {
            // 递归处理子视图
            for (i in 0 until view.childCount) {
                clearTextSelectionRecursive(view.getChildAt(i))
            }
        }
    }
    
    /**
     * 检查点是否在视图内
     */
    private fun isPointInView(view: android.view.View, x: Int, y: Int): Boolean {
        val location = IntArray(2)
        view.getLocationOnScreen(location)
        val viewX = location[0]
        val viewY = location[1]
        return x >= viewX && x <= viewX + view.width && y >= viewY && y <= viewY + view.height
    }
    
    /**
     * 隐藏键盘
     */
    internal fun hideKeyboard() {
        hideMentionPopup()  // 隐藏键盘时也隐藏@提及候选列表
        try {
            val inputMethodManager = requireContext().getSystemService(android.content.Context.INPUT_METHOD_SERVICE) as? android.view.inputmethod.InputMethodManager
            val currentFocus = activity?.currentFocus
            if (currentFocus != null) {
                inputMethodManager?.hideSoftInputFromWindow(currentFocus.windowToken, 0)
            } else {
                // 如果没有焦点，尝试从输入框隐藏键盘
                inputMethodManager?.hideSoftInputFromWindow(binding.etChatInput.windowToken, 0)
            }
        } catch (e: Exception) {
            Log.e(TAG, "隐藏键盘失败: ${e.message}", e)
        }
    }
    
    /**
     * 显示键盘
     */
    internal fun showKeyboard() {
        try {
            binding.etChatInput.requestFocus()
            val inputMethodManager = requireContext().getSystemService(android.content.Context.INPUT_METHOD_SERVICE) as? android.view.inputmethod.InputMethodManager
            inputMethodManager?.showSoftInput(binding.etChatInput, android.view.inputmethod.InputMethodManager.SHOW_IMPLICIT)
        } catch (e: Exception) {
            Log.e(TAG, "显示键盘失败: ${e.message}", e)
        }
    }
    
