    /**
     * 显示预设查询菜单（可滚动，包含预设查询和用户历史）
     */
    internal fun showPresetQueryMenu(anchor: View) {
        // 如果已有下拉菜单打开，先关闭
        popupWindow?.dismiss()
        
        // 合并预设查询和用户历史查询（预设查询在前，用户历史在后，最新的在最下面）
        val allQueries = mutableListOf<String>()
        allQueries.addAll(ChatConstants.PRESET_QUERIES)
        // 反转userQueryHistory，使最新的在最下面
        allQueries.addAll(userQueryHistory.reversed())
        
        if (allQueries.isEmpty()) {
            Toast.makeText(requireContext(), "暂无查询记录", Toast.LENGTH_SHORT).show()
            return
        }
        
        // 创建ListView用于显示查询列表
        val listView = ListView(requireContext())
        
        // 创建适配器
        val adapter = ArrayAdapter(
            requireContext(),
            android.R.layout.simple_list_item_1,
            allQueries
        )
        listView.adapter = adapter
        
        // 设置列表项点击监听
        listView.setOnItemClickListener { _, _, position, _ ->
            if (position >= 0 && position < allQueries.size) {
                val selectedQuery = allQueries[position]
                // 将选中的查询填入输入框
                binding.etChatInput.setText(selectedQuery)
                // 将光标移到末尾
                binding.etChatInput.setSelection(selectedQuery.length)
                // 关闭下拉菜单
                popupWindow?.dismiss()
            }
        }
        
        // 计算下拉菜单的高度（单页显示5个，每个约48dp）
        val itemHeight = (48 * resources.displayMetrics.density).toInt()
        val maxHeight = itemHeight * 5 // 单页显示5个
        val totalHeight = itemHeight * allQueries.size
        val listViewHeight = if (totalHeight > maxHeight) maxHeight else totalHeight
        
        // 设置ListView高度
        listView.layoutParams = ViewGroup.LayoutParams(
            ViewGroup.LayoutParams.MATCH_PARENT,
            listViewHeight
        )
        
        // 计算宽度（与输入框宽度一致）
        val inputWidth = binding.etChatInput.width
        val popupWidth = if (inputWidth > 0) inputWidth else ViewGroup.LayoutParams.WRAP_CONTENT
        
        // 创建PopupWindow
        popupWindow = PopupWindow(
            listView,
            popupWidth,
            listViewHeight,
            true // focusable
        )
        
        // 设置背景和样式
        popupWindow?.setBackgroundDrawable(
            ContextCompat.getDrawable(requireContext(), android.R.drawable.dialog_holo_light_frame)
        )
        popupWindow?.elevation = 8f
        
        // 设置外部点击关闭
        popupWindow?.isOutsideTouchable = true
        
        // 显示在输入框下方
        popupWindow?.showAsDropDown(binding.etChatInput, 0, 0, Gravity.START)
    }
    
