    /**
     * 切换表情面板显示/隐藏
     */
    internal fun toggleEmojiPanel() {
        if (isEmojiPanelVisible) {
            hideEmojiPanel()
        } else {
            showEmojiPanel()
        }
    }
    
    /**
     * 显示表情面板
     */
    internal fun showEmojiPanel() {
        if (isEmojiPanelVisible) {
            return
        }
        
        // 先隐藏其他面板
        if (isMediaPanelVisible) {
            hideMediaPanel()
        }
        if (isVoicePanelVisible) {
            hideVoicePanel()
        }
        
        // 先收起键盘（如果弹起）
        hideKeyboard()
        // 等待键盘收起后再显示面板
        binding.root.postDelayed({
            if (_binding != null) {
                showEmojiPanelInternal()
            }
        }, 300)
    }
    
    /**
     * 显示表情面板（内部方法）
     */
    internal fun showEmojiPanelInternal() {
        if (isEmojiPanelVisible) {
            return
        }
        
        isEmojiPanelVisible = true
        
        // 当表情面板显示时，点击屏幕其他区域会隐藏面板
        // 创建组合的触摸监听器，先调用原有监听器，再处理表情面板逻辑
        val combinedTouchListener = View.OnTouchListener { v, event ->
            // 先调用原有的触摸监听器（如果存在），保存返回值
            val originalResult = rvChatMessagesTouchListener?.onTouch(v, event) ?: false
            
            // 然后处理表情面板的逻辑（不消费事件，让点击事件也能触发）
            if (event.action == android.view.MotionEvent.ACTION_DOWN && isEmojiPanelVisible) {
                val binding = _binding ?: return@OnTouchListener originalResult
                
                // 获取触摸位置（相对于屏幕）
                val x = event.rawX.toInt()
                val y = event.rawY.toInt()
                
                // 检查点击位置是否在表情面板内
                val emojiPanelLocation = IntArray(2)
                binding.llEmojiPanel.getLocationOnScreen(emojiPanelLocation)
                val emojiPanelLeft = emojiPanelLocation[0]
                val emojiPanelTop = emojiPanelLocation[1]
                val emojiPanelRight = emojiPanelLeft + binding.llEmojiPanel.width
                val emojiPanelBottom = emojiPanelTop + binding.llEmojiPanel.height
                
                // 检查点击位置是否在表情按钮内
                val emojiButtonLocation = IntArray(2)
                binding.btnQueryDropdown.getLocationOnScreen(emojiButtonLocation)
                val emojiButtonLeft = emojiButtonLocation[0]
                val emojiButtonTop = emojiButtonLocation[1]
                val emojiButtonRight = emojiButtonLeft + binding.btnQueryDropdown.width
                val emojiButtonBottom = emojiButtonTop + binding.btnQueryDropdown.height
                
                // 如果点击位置不在表情面板和表情按钮内，则隐藏表情面板
                val isInEmojiPanel = x >= emojiPanelLeft && x <= emojiPanelRight && 
                                     y >= emojiPanelTop && y <= emojiPanelBottom
                val isInEmojiButton = x >= emojiButtonLeft && x <= emojiButtonRight && 
                                     y >= emojiButtonTop && y <= emojiButtonBottom
                
                if (!isInEmojiPanel && !isInEmojiButton) {
                    hideEmojiPanel()
                    // 不消费事件，让点击事件也能触发
                }
            }
            
            // 返回原有监听器的结果，不消费事件
            originalResult
        }
        
        // 为聊天消息区域设置组合触摸监听
        binding.rvChatMessages.setOnTouchListener(combinedTouchListener)
        
        // 为其他区域设置简单的触摸监听（只处理表情面板）
        emojiPanelTouchListener = View.OnTouchListener { v, event ->
            if (event.action == android.view.MotionEvent.ACTION_DOWN && isEmojiPanelVisible) {
                val binding = _binding ?: return@OnTouchListener false
                
                // 获取触摸位置（相对于屏幕）
                val x = event.rawX.toInt()
                val y = event.rawY.toInt()
                
                // 检查点击位置是否在表情面板内
                val emojiPanelLocation = IntArray(2)
                binding.llEmojiPanel.getLocationOnScreen(emojiPanelLocation)
                val emojiPanelLeft = emojiPanelLocation[0]
                val emojiPanelTop = emojiPanelLocation[1]
                val emojiPanelRight = emojiPanelLeft + binding.llEmojiPanel.width
                val emojiPanelBottom = emojiPanelTop + binding.llEmojiPanel.height
                
                // 检查点击位置是否在表情按钮内
                val emojiButtonLocation = IntArray(2)
                binding.btnQueryDropdown.getLocationOnScreen(emojiButtonLocation)
                val emojiButtonLeft = emojiButtonLocation[0]
                val emojiButtonTop = emojiButtonLocation[1]
                val emojiButtonRight = emojiButtonLeft + binding.btnQueryDropdown.width
                val emojiButtonBottom = emojiButtonTop + binding.btnQueryDropdown.height
                
                // 如果点击位置不在表情面板和表情按钮内，则隐藏表情面板
                val isInEmojiPanel = x >= emojiPanelLeft && x <= emojiPanelRight && 
                                     y >= emojiPanelTop && y <= emojiPanelBottom
                val isInEmojiButton = x >= emojiButtonLeft && x <= emojiButtonRight && 
                                     y >= emojiButtonTop && y <= emojiButtonBottom
                
                if (!isInEmojiPanel && !isInEmojiButton) {
                    hideEmojiPanel()
                }
            }
            false  // 不消费事件，让其他View正常处理
        }
        
        // 为标题栏设置触摸监听
        binding.llTitleBar.setOnTouchListener(emojiPanelTouchListener)
        
        // 为推荐任务面板设置触摸监听
        binding.llRecommendationsPanel.setOnTouchListener(emojiPanelTouchListener)
        
        // 为聊天内容区域设置触摸监听
        binding.llChatContent.setOnTouchListener(emojiPanelTouchListener)
        
        binding.llEmojiPanel.visibility = View.VISIBLE
        
        // 先测量高度
        binding.llEmojiPanel.measure(
            View.MeasureSpec.makeMeasureSpec(binding.root.width, View.MeasureSpec.EXACTLY),
            View.MeasureSpec.makeMeasureSpec(0, View.MeasureSpec.UNSPECIFIED)
        )
        val targetHeight = binding.llEmojiPanel.measuredHeight
        
        // 从0高度滑出
        val layoutParams = binding.llEmojiPanel.layoutParams
        layoutParams.height = 0
        binding.llEmojiPanel.layoutParams = layoutParams
        binding.llEmojiPanel.requestLayout()
        
        // 延迟一帧后开始动画，确保布局已更新
        binding.llEmojiPanel.post {
            val binding = _binding ?: return@post
            android.animation.ValueAnimator.ofInt(0, targetHeight).apply {
                duration = 250
                addUpdateListener { animation ->
                    val currentBinding = _binding ?: return@addUpdateListener
                    val height = animation.animatedValue as Int
                    val params = currentBinding.llEmojiPanel.layoutParams
                    params.height = height
                    currentBinding.llEmojiPanel.layoutParams = params
                }
                addListener(object : android.animation.AnimatorListenerAdapter() {
                    override fun onAnimationEnd(animation: android.animation.Animator) {
                        // 动画结束后更新按钮图标
                        updateInputButtonIcon()
                    }
                })
                start()
            }
        }
    }
    
    /**
     * 隐藏表情面板
     */
    internal fun hideEmojiPanel() {
        if (!isEmojiPanelVisible) {
            return
        }
        
        isEmojiPanelVisible = false
        
        // 检查binding是否有效
        val currentBinding = _binding ?: return
        
        // 移除表情面板相关的触摸监听（避免在Fragment销毁后执行）
        try {
            // 恢复RecyclerView的原有触摸监听器
            currentBinding.rvChatMessages.setOnTouchListener(rvChatMessagesTouchListener)
            
            // 移除其他区域的触摸监听
            currentBinding.llTitleBar.setOnTouchListener(null)
            currentBinding.llRecommendationsPanel.setOnTouchListener(null)
            currentBinding.llChatContent.setOnTouchListener(null)
            emojiPanelTouchListener = null
        } catch (e: Exception) {
            Log.w(TAG, "移除触摸监听失败: ${e.message}")
        }
        
        val currentHeight = currentBinding.llEmojiPanel.height
        
        if (currentHeight <= 0) {
            currentBinding.llEmojiPanel.visibility = View.GONE
            // 更新按钮图标
            updateInputButtonIcon()
            return
        }
        
        // 滑入动画
        android.animation.ValueAnimator.ofInt(currentHeight, 0).apply {
            duration = 250
            addUpdateListener { animation ->
                val binding = _binding ?: return@addUpdateListener
                val height = animation.animatedValue as Int
                val params = binding.llEmojiPanel.layoutParams
                params.height = height
                binding.llEmojiPanel.layoutParams = params
            }
            addListener(object : android.animation.AnimatorListenerAdapter() {
                override fun onAnimationEnd(animation: android.animation.Animator) {
                    val binding = _binding ?: return
                    binding.llEmojiPanel.visibility = View.GONE
                    val params = binding.llEmojiPanel.layoutParams
                    params.height = ViewGroup.LayoutParams.WRAP_CONTENT
                    binding.llEmojiPanel.layoutParams = params
                    // 动画结束后更新按钮图标
                    updateInputButtonIcon()
                }
            })
            start()
        }
    }
    
    /**
     * 显示Beta欢迎气泡弹窗（在按钮上方）
     */
    internal fun showBetaWelcomePopup(anchor: View) {
        // 如果已有气泡显示，先关闭
        betaWelcomePopupWindow?.dismiss()
        
        try {
            // 加载布局
            val popupView = LayoutInflater.from(requireContext()).inflate(
                R.layout.popup_beta_welcome, null
            )
            
            // 测量弹窗大小
            popupView.measure(
                View.MeasureSpec.makeMeasureSpec(0, View.MeasureSpec.UNSPECIFIED),
                View.MeasureSpec.makeMeasureSpec(0, View.MeasureSpec.UNSPECIFIED)
            )
            val popupWidth = popupView.measuredWidth
            val popupHeight = popupView.measuredHeight
            
            // 创建PopupWindow
            betaWelcomePopupWindow = PopupWindow(
                popupView,
                popupWidth,
                popupHeight,
                false // 不获取焦点，避免影响其他交互
            )
            
            // 设置背景（透明，使用布局中的背景）
            betaWelcomePopupWindow?.setBackgroundDrawable(
                ContextCompat.getDrawable(requireContext(), android.R.color.transparent)
            )
            
            // 设置外部点击关闭
            betaWelcomePopupWindow?.isOutsideTouchable = true
            
            // 设置阴影
            betaWelcomePopupWindow?.elevation = 12f
            
            // 计算按钮在屏幕上的位置
            val location = IntArray(2)
            anchor.getLocationOnScreen(location)
            val anchorX = location[0]
            val anchorY = location[1]
            val anchorWidth = anchor.width
            
            // 获取根视图的位置（用于计算相对位置）
            val rootLocation = IntArray(2)
            view?.getLocationOnScreen(rootLocation)
            val rootX = rootLocation[0]
            val rootY = rootLocation[1]
            
            // 计算弹窗位置（按钮上方居中）
            val popupX = anchorX + (anchorWidth - popupWidth) / 2
            val popupY = anchorY - popupHeight // 按钮上方0dp，紧贴按钮
            
            // 计算相对于根视图的位置
            val relativeX = popupX - rootX
            val relativeY = popupY - rootY
            
            // 显示弹窗
            betaWelcomePopupWindow?.showAtLocation(
                view,
                Gravity.NO_GRAVITY,
                relativeX,
                relativeY
            )
            
            // 添加淡入动画
            popupView.alpha = 0f
            popupView.animate()
                .alpha(1f)
                .setDuration(300)
                .start()
            
            // 7秒后自动关闭
            view?.postDelayed({
                betaWelcomePopupWindow?.dismiss()
            }, 7000)
            
        } catch (e: Exception) {
            Log.e(TAG, "显示Beta欢迎气泡失败: ${e.message}", e)
        }
    }
    
    /**
     * 发送聊天消息
     */
    internal fun sendChatMessage() {
        val query = binding.etChatInput.text.toString().trim()
        val hasImage = selectedImageBase64 != null
        
        // 允许query为空（如果用户只上传了图片）
        if (query.isEmpty() && !hasImage) {
            return
        }

        // 清空输入框（在读取内容后立即清空）
        binding.etChatInput.setText("")

        // 检查当前对话类型
        val conversationId = currentConversation?.id
        val isGroupOrFriendConversation = conversationId == ConversationListFragment.CONVERSATION_ID_ME ||
                conversationId?.startsWith("group_") == true ||
                conversationId == ConversationListFragment.CONVERSATION_ID_GROUP ||
                conversationId?.startsWith("friend_") == true ||
                conversationId == ConversationListFragment.CONVERSATION_ID_CUSTOMER_SERVICE
        
        if (isGroupOrFriendConversation) {
            // 群组或好友对话：先调用performSendChatMessage处理消息发送，然后它会调用executeQueryInternal
            Log.d(TAG, "sendChatMessage: 群组/好友对话，调用performSendChatMessage")
            mainScope.launch {
                performSendChatMessage(query, shouldGoHome = true)
            }
        } else {
            // 其他对话（TopoClaw等）：直接调用executeQueryInternal
            Log.d(TAG, "sendChatMessage: 其他对话，直接调用executeQueryInternal")
            executeQueryInternal(query)
        }
    }
    
    /**
     * 切换语音录制面板
     */
    internal fun toggleVoicePanel() {
        // 立即触发震动反馈，提升响应速度
        vibrate()
        
        if (isVoicePanelVisible) {
            hideVoicePanel()
        } else {
            showVoicePanel()
        }
    }
    
    /**
     * 显示语音录制面板
     */
    internal fun showVoicePanel() {
        if (isVoicePanelVisible) {
            return
        }
        
        // 如果媒体面板显示，先隐藏它
        if (isMediaPanelVisible) {
            hideMediaPanel()
        }
        
        // 先收起键盘（如果弹起）
        hideKeyboard()
        
        // 优化：如果键盘已经隐藏，立即显示面板；否则等待键盘收起
        if (!isKeyboardVisible) {
            // 键盘已隐藏，立即显示面板
            showVoicePanelInternal()
        } else {
            // 键盘正在显示，等待键盘收起后再显示面板
            // 使用更短的延迟，并监听键盘状态变化
            var checkCount = 0
            val maxChecks = 15 // 最多检查15次（约300ms）
            val checkInterval = 20L // 每20ms检查一次
            
            val checkRunnable = object : Runnable {
                override fun run() {
                    val currentBinding = _binding ?: return
                    checkCount++
                    
                    if (!isKeyboardVisible || checkCount >= maxChecks) {
                        // 键盘已隐藏或超时，显示面板
                        showVoicePanelInternal()
                    } else {
                        // 继续检查
                        binding.root.postDelayed(this, checkInterval)
                    }
                }
            }
            binding.root.postDelayed(checkRunnable, checkInterval)
        }
    }
    
    /**
     * 显示语音录制面板（内部方法）
     */
    internal fun showVoicePanelInternal() {
        if (isVoicePanelVisible) {
            return
        }
        
        isVoicePanelVisible = true
        
        // 当语音面板显示时，点击聊天消息区域会隐藏面板
        binding.rvChatMessages.setOnClickListener {
            if (isVoicePanelVisible && _binding != null) {
                hideVoicePanel()
            }
        }
        
        // 立即设置可见，提升响应速度
        binding.llVoicePanel.visibility = View.VISIBLE
        
        // 优化：预先测量高度，减少延迟
        val rootWidth = binding.root.width
        val targetHeight = if (rootWidth > 0) {
            // 如果根视图宽度已知，立即测量
            binding.llVoicePanel.measure(
                View.MeasureSpec.makeMeasureSpec(rootWidth, View.MeasureSpec.EXACTLY),
                View.MeasureSpec.makeMeasureSpec(0, View.MeasureSpec.UNSPECIFIED)
            )
            binding.llVoicePanel.measuredHeight
        } else {
            // 如果根视图宽度未知，使用post等待布局完成
            binding.llVoicePanel.post {
                val currentBinding = _binding ?: return@post
                val width = currentBinding.root.width
                if (width > 0) {
                    currentBinding.llVoicePanel.measure(
                        View.MeasureSpec.makeMeasureSpec(width, View.MeasureSpec.EXACTLY),
                        View.MeasureSpec.makeMeasureSpec(0, View.MeasureSpec.UNSPECIFIED)
                    )
                    val height = currentBinding.llVoicePanel.measuredHeight
                    startPanelAnimation(currentBinding, height)
                }
            }
            return // 等待测量完成后再继续
        }
        
        // 如果已经测量到高度，立即开始动画
        if (targetHeight > 0) {
            startPanelAnimation(binding, targetHeight)
        }
    }
    
    /**
     * 启动面板显示动画（优化：提取为独立方法，减少代码重复）
     */
    internal fun startPanelAnimation(binding: FragmentChatBinding, targetHeight: Int) {
        // 从0高度滑出
        val layoutParams = binding.llVoicePanel.layoutParams
        layoutParams.height = 0
        binding.llVoicePanel.layoutParams = layoutParams
        
        // 优化：如果视图已经附加到窗口，可以直接开始动画；否则使用post等待
        if (binding.llVoicePanel.isAttachedToWindow) {
            startAnimationImmediate(binding, targetHeight)
        } else {
            binding.llVoicePanel.post {
                val currentBinding = _binding ?: return@post
                startAnimationImmediate(currentBinding, targetHeight)
            }
        }
    }
    
    /**
     * 立即启动动画（内部方法）
     */
    internal fun startAnimationImmediate(binding: FragmentChatBinding, targetHeight: Int) {
        android.animation.ValueAnimator.ofInt(0, targetHeight).apply {
            duration = 200 // 缩短动画时间，提升响应速度
            interpolator = android.view.animation.DecelerateInterpolator(1.5f) // 使用减速插值器，更自然
            
            addUpdateListener { animation ->
                val currentBinding = _binding ?: return@addUpdateListener
                val height = animation.animatedValue as Int
                val params = currentBinding.llVoicePanel.layoutParams
                params.height = height
                currentBinding.llVoicePanel.layoutParams = params
            }
            start()
        }
    }
    
    /**
     * 隐藏语音录制面板
     */
    internal fun hideVoicePanel() {
        if (!isVoicePanelVisible) {
            return
        }
        
        isVoicePanelVisible = false
        
        // 检查binding是否有效
        val currentBinding = _binding ?: return
        
        // 如果正在录音，先停止录音
        if (isVoiceRecording) {
            stopVoiceRecognition()
        } else {
            // 即使没有录音，也确保停止动画
            stopRecordingRingAnimation()
        }
        
        // 移除RecyclerView的点击监听（避免在Fragment销毁后执行）
        try {
            currentBinding.rvChatMessages.setOnClickListener(null)
        } catch (e: Exception) {
            Log.w(TAG, "移除RecyclerView点击监听失败: ${e.message}")
        }
        
        val currentHeight = currentBinding.llVoicePanel.height
        
        if (currentHeight <= 0) {
            currentBinding.llVoicePanel.visibility = View.GONE
            return
        }
        
        // 滑入动画
        android.animation.ValueAnimator.ofInt(currentHeight, 0).apply {
            duration = 250
            addUpdateListener { animation ->
                val binding = _binding ?: return@addUpdateListener
                val height = animation.animatedValue as Int
                val params = binding.llVoicePanel.layoutParams
                params.height = height
                binding.llVoicePanel.layoutParams = params
            }
            addListener(object : android.animation.AnimatorListenerAdapter() {
                override fun onAnimationEnd(animation: android.animation.Animator) {
                    val binding = _binding ?: return
                    binding.llVoicePanel.visibility = View.GONE
                    val params = binding.llVoicePanel.layoutParams
                    params.height = ViewGroup.LayoutParams.WRAP_CONTENT
                    binding.llVoicePanel.layoutParams = params
                }
            })
            start()
        }
    }
    
    /**
     * 开始语音识别
     */
    internal fun startVoiceRecognition() {
        if (!BuildConfig.SPARKCHAIN_ENABLED) {
            Toast.makeText(requireContext(), VOICE_DISABLED_MESSAGE, Toast.LENGTH_SHORT).show()
            return
        }
        // 检查录音权限
        if (ContextCompat.checkSelfPermission(requireContext(), Manifest.permission.RECORD_AUDIO) 
            != PackageManager.PERMISSION_GRANTED) {
            // 请求权限
            ActivityCompat.requestPermissions(
                requireActivity(),
                arrayOf(Manifest.permission.RECORD_AUDIO),
                1001
            )
            Toast.makeText(requireContext(), "需要录音权限才能使用语音输入", Toast.LENGTH_SHORT).show()
            return
        }
        
        try {
            // 初始化ASR
            if (mAsr == null) {
                mAsr = ASR()
                mAsr?.registerCallbacks(asrCallbacks)
            }
            
            // 配置ASR参数
            mAsr?.language("zh_cn")  // 中文
            mAsr?.domain("iat")  // 日常用语
            mAsr?.accent("mandarin")  // 普通话
            mAsr?.vinfo(true)  // 返回子句结果对应的起始和结束的端点帧偏移值
            mAsr?.dwa("wpgs")  // 动态修正
            
            // 启动识别
            voiceRecognitionCount++
            val ret = mAsr?.start(voiceRecognitionCount.toString())
            
            if (ret == 0) {
                isVoiceRecording = true
                
                // 震动反馈
                vibrate()
                
                // 初始化录音管理器
                if (audioRecorderManager == null) {
                    audioRecorderManager = AudioRecorderManager.getInstance()
                }
                audioRecorderManager?.startRecord()
                audioRecorderManager?.registerCallBack(audioDataCallback)
                
                // 更新UI
                updateVoiceButtonState()
                // 启动转圈动画
                startRecordingRingAnimation()
                
                Log.d(TAG, "语音识别已启动")
            } else {
                Log.e(TAG, "语音识别启动失败，错误码: $ret")
                Toast.makeText(requireContext(), "语音识别启动失败，错误码: $ret", Toast.LENGTH_SHORT).show()
            }
        } catch (e: Exception) {
            Log.e(TAG, "启动语音识别异常: ${e.message}", e)
            Toast.makeText(requireContext(), "启动语音识别失败: ${e.message}", Toast.LENGTH_SHORT).show()
        }
    }
    
    /**
     * 停止语音识别
     */
    internal fun stopVoiceRecognition() {
        try {
            isVoiceRecording = false
            
            // 震动反馈
            vibrate()
            
            // 停止录音
            audioRecorderManager?.stopRecord()
            audioRecorderManager = null
            
            // 停止识别
            mAsr?.stop(false)  // false: 等云端最后一包下发后结束
            
            // 停止转圈动画
            stopRecordingRingAnimation()
            
            // 更新UI
            updateVoiceButtonState()
            
            Log.d(TAG, "语音识别已停止")
        } catch (e: Exception) {
            Log.e(TAG, "停止语音识别异常: ${e.message}", e)
        }
    }
    
    /**
     * 启动录音转圈动画
     */
    private fun startRecordingRingAnimation() {
        if (_binding == null || !isVoicePanelVisible) return
        
        try {
            val ringView = binding.ivRecordingRing
            if (ringView is RecordingRingView) {
                ringView.startAnimation()
            }
        } catch (e: Exception) {
            Log.e(TAG, "启动录音转圈动画失败: ${e.message}", e)
        }
    }
    
    /**
     * 停止录音转圈动画
     */
    private fun stopRecordingRingAnimation() {
        try {
            if (_binding != null) {
                val ringView = binding.ivRecordingRing
                if (ringView is RecordingRingView) {
                    ringView.stopAnimation()
                }
            }
        } catch (e: Exception) {
            Log.e(TAG, "停止录音转圈动画失败: ${e.message}", e)
        }
    }
    
    /**
     * 更新语音按钮状态
     */
    private fun updateVoiceButtonState() {
        if (_binding == null) return
        
        try {
            if (isVoiceRecording) {
                // 录音中：可以改变按钮样式或显示提示
                binding.btnVoiceInput.alpha = 0.6f
                binding.btnVoiceInput.setColorFilter(
                    ContextCompat.getColor(requireContext(), android.R.color.holo_red_dark)
                )
                // 更新语音面板中的提示文字和按钮状态
                if (isVoicePanelVisible) {
                    binding.tvVoiceHint.text = getString(R.string.tap_again_to_stop_recording)
                    binding.btnVoiceRecord.alpha = 0.8f
                }
            } else {
                // 未录音：恢复正常样式
                binding.btnVoiceInput.alpha = 1.0f
                binding.btnVoiceInput.clearColorFilter()
                // 更新语音面板中的提示文字和按钮状态
                if (isVoicePanelVisible) {
                    binding.tvVoiceHint.text = getString(R.string.tap_to_speak)
                    binding.btnVoiceRecord.alpha = 1.0f
                }
            }
        } catch (e: Exception) {
            Log.e(TAG, "更新语音按钮状态异常: ${e.message}", e)
        }
    }
    
    /**
     * ASR回调
     */
    private val asrCallbacks = object : AsrCallbacks {
        override fun onResult(asrResult: ASR.ASRResult, o: Any?) {
            val status = asrResult.status
            val result = asrResult.bestMatchText
            
            Log.d(TAG, "语音识别结果: status=$status, result=$result")
            
            // 在主线程更新UI
            activity?.runOnUiThread {
                if (_binding == null) return@runOnUiThread
                
                when (status) {
                    0 -> {
                        // 识别的第一块结果（中间结果）
                        // 可以实时显示在输入框中
                        binding.etChatInput.setText(result)
                        binding.etChatInput.setSelection(result.length)
                    }
                    1 -> {
                        // 识别中间结果
                        binding.etChatInput.setText(result)
                        binding.etChatInput.setSelection(result.length)
                    }
                    2 -> {
                        // 识别最后一块结果（最终结果）
                        binding.etChatInput.setText(result)
                        binding.etChatInput.setSelection(result.length)
                        
                        // 停止识别
                        stopVoiceRecognition()
                        
                        // 可选：自动发送消息
                        // sendChatMessage()
                    }
                }
            }
        }
        
        override fun onError(asrError: ASR.ASRError, o: Any?) {
            val code = asrError.code
            val msg = asrError.errMsg
            
            Log.e(TAG, "语音识别错误: code=$code, msg=$msg")
            
            // 在主线程显示错误提示
            activity?.runOnUiThread {
                Toast.makeText(requireContext(), "语音识别错误: $msg (错误码: $code)", Toast.LENGTH_SHORT).show()
                stopVoiceRecognition()
            }
        }
        
        override fun onBeginOfSpeech() {
            Log.d(TAG, "开始说话")
        }
        
        override fun onEndOfSpeech() {
            Log.d(TAG, "结束说话")
        }
    }
    
    /**
     * 音频数据回调
     */
    private val audioDataCallback = object : AudioRecorderManager.AudioDataCallback {
        override fun onAudioData(data: ByteArray, size: Int) {
            if (isVoiceRecording && mAsr != null) {
                val ret = mAsr?.write(data)
                if (ret != null && ret != 0) {
                    Log.e(TAG, "写入音频数据失败，错误码: $ret")
                }
            }
        }
        
        override fun onAudioVolume(db: Double, volume: Int) {
            // 可以在这里显示音量指示器
            // Log.d(TAG, "音量: db=$db, volume=$volume")
        }
    }
    
