    /**
     * 发送问字按钮任务（带图）
     * @param screenshotBase64 截图Base64字符串
     * @param userQuery 用户输入的查询文本（可以为空）
     */
    fun sendQuestionTask(screenshotBase64: String, userQuery: String) {
        Log.d(TAG, "sendQuestionTask: 开始发送问字任务，query='$userQuery', screenshot长度=${screenshotBase64.length}")
        
        try {
            // 检查Fragment是否已经完全初始化
            if (_binding == null || !isAdded || view == null) {
                Log.w(TAG, "sendQuestionTask: Fragment未完全初始化，延迟执行")
                // 延迟执行，确保Fragment完全初始化
                view?.post {
                    sendQuestionTaskInternal(screenshotBase64, userQuery)
                } ?: run {
                    // 如果view为null，等待一段时间后重试
                    mainScope.launch {
                        delay(300)
                        if (_binding != null && isAdded && view != null) {
                            view?.post {
                                sendQuestionTaskInternal(screenshotBase64, userQuery)
                            }
                        } else {
                            Log.e(TAG, "sendQuestionTask: Fragment初始化超时，无法发送任务")
                            addChatMessage("系统", "界面初始化失败，请重试")
                        }
                    }
                }
                return
            }
            
            // Fragment已初始化，直接执行
            sendQuestionTaskInternal(screenshotBase64, userQuery)
        } catch (e: Exception) {
            Log.e(TAG, "发送问字任务失败: ${e.message}", e)
            e.printStackTrace()
            addChatMessage("系统", "发送任务失败: ${e.message}")
        }
    }
    
    /**
     * 发送问字按钮任务的内部实现
     * @param screenshotBase64 截图Base64字符串
     * @param userQuery 用户输入的查询文本（可以为空）
     */
    private fun sendQuestionTaskInternal(screenshotBase64: String, userQuery: String) {
        Log.d(TAG, "sendQuestionTaskInternal: 开始发送问字任务，query='$userQuery', screenshot长度=${screenshotBase64.length}")
        
        try {
            // 再次检查Fragment状态
            if (_binding == null || !isAdded) {
                Log.e(TAG, "sendQuestionTaskInternal: Fragment状态异常，无法发送任务")
                return
            }
            
            // 检查NetworkService是否已初始化
            if (!NetworkService.isInitialized()) {
                Log.w(TAG, "sendQuestionTaskInternal: NetworkService未初始化，等待初始化完成")
                // 等待NetworkService初始化（onViewCreated中会初始化）
                mainScope.launch {
                    var retryCount = 0
                    while (retryCount < 20 && !NetworkService.isInitialized()) {
                        delay(100)
                        retryCount++
                    }
                    if (NetworkService.isInitialized()) {
                        Log.d(TAG, "sendQuestionTaskInternal: NetworkService已初始化，继续发送任务")
                        sendQuestionTaskInternal(screenshotBase64, userQuery)
                    } else {
                        Log.e(TAG, "sendQuestionTaskInternal: NetworkService初始化超时，无法发送任务")
                        addChatMessage("系统", "网络服务初始化失败，请重试")
                    }
                }
                return
            }
            
            Log.d(TAG, "sendQuestionTaskInternal: Fragment状态正常，NetworkService已初始化，继续执行")
            
            // 标记这是通过问字按钮发起的请求
            isQuestionButtonRequest = true
            Log.d(TAG, "sendQuestionTaskInternal: 已设置isQuestionButtonRequest=true，问字按钮请求将跳过gohome")
            
            // 保存截图到任务记录的images目录（在任务开始前保存）
            mainScope.launch {
                saveQuestionScreenshotToTaskRecords(screenshotBase64, userQuery)
            }
            
            // 设置截图数据
            selectedImageBase64 = screenshotBase64
            Log.d(TAG, "sendQuestionTaskInternal: selectedImageBase64已设置，长度=${screenshotBase64.length}")
            
            // 如果有用户输入，添加到输入框
            if (userQuery.isNotEmpty()) {
                binding.etChatInput.setText(userQuery)
                Log.d(TAG, "sendQuestionTaskInternal: 已设置用户输入到输入框: '$userQuery'")
            } else {
                binding.etChatInput.setText("")
                Log.d(TAG, "sendQuestionTaskInternal: 用户输入为空，只发送图片")
            }
            
            // 发送任务（query可以为空，只发送图片）
            Log.d(TAG, "sendQuestionTaskInternal: 准备调用executeQueryInternal，query='$userQuery', hasImage=${selectedImageBase64 != null}")
            executeQueryInternal(userQuery)
            Log.d(TAG, "sendQuestionTaskInternal: executeQueryInternal调用完成")
        } catch (e: Exception) {
            Log.e(TAG, "发送问字任务失败: ${e.message}", e)
            e.printStackTrace()
            addChatMessage("系统", "发送任务失败: ${e.message}")
        }
    }
    
    /**
     * 保存问字按钮的截图到任务记录的images目录
     * 目录格式：task_records/{prefix}_{query}_{uuid[:8]}/images/step_1.jpeg
     */
    private suspend fun saveQuestionScreenshotToTaskRecords(screenshotBase64: String, userQuery: String) = withContext(Dispatchers.IO) {
        try {
            // 生成任务记录目录名（格式：{prefix}_{query}_{uuid[:8]}）
            val timestamp = System.currentTimeMillis()
            val dateFormat = java.text.SimpleDateFormat("yyyyMMdd'T'HHmmss", java.util.Locale.getDefault())
            val prefix = dateFormat.format(java.util.Date(timestamp))
            val queryForDir = userQuery.ifEmpty { "question" }
            val uuidShort = chatUuid.take(8)
            val taskDirName = "${prefix}_${queryForDir}_$uuidShort"
            
            // 创建任务记录目录
            val taskRecordsDir = java.io.File(requireContext().getExternalFilesDir(null), "task_records")
            val taskDir = java.io.File(taskRecordsDir, taskDirName)
            val imagesDir = java.io.File(taskDir, "images")
            
            if (!imagesDir.exists()) {
                imagesDir.mkdirs()
                Log.d(TAG, "创建任务记录目录: ${imagesDir.absolutePath}")
            }
            
            // 保存截图（step_1.jpeg，因为这是第一步）
            val imageFileName = "step_1.jpeg"
            val imageFile = java.io.File(imagesDir, imageFileName)
            
            // 将Base64转换为字节数组并保存
            val base64Part = screenshotBase64.substringAfter("base64,")
            val imageBytes = android.util.Base64.decode(base64Part, android.util.Base64.NO_WRAP)
            
            imageFile.writeBytes(imageBytes)
            
            Log.d(TAG, "问字按钮截图已保存到任务记录: ${imageFile.absolutePath}")
        } catch (e: Exception) {
            Log.e(TAG, "保存问字按钮截图到任务记录失败: ${e.message}", e)
            e.printStackTrace()
            // 不抛出异常，避免影响任务发送
        }
    }
    
    /**
     * 执行技能
     * @param skill 技能对象
     */
    fun executeSkill(skill: Skill) {
        try {
            Log.d(TAG, "executeSkill: 开始执行技能 - ${skill.title}")
            
            // 检查当前对话是否是技能学习小助手
            if (currentConversation?.id != ConversationListFragment.CONVERSATION_ID_SKILL_LEARNING) {
                Log.w(TAG, "executeSkill: 当前不在技能学习小助手对话，需要先切换")
                // 如果不在技能学习小助手对话，先切换到该对话
                val skillConv = Conversation(
                    id = ConversationListFragment.CONVERSATION_ID_SKILL_LEARNING,
                    name = "技能学习小助手",
                    avatar = null,
                    lastMessage = null,
                    lastMessageTime = System.currentTimeMillis()
                )
                
                // 切换到技能学习小助手对话（使用复用机制）
                val mainActivity = activity as? MainActivity
                val chatFragment = mainActivity?.getOrCreateChatFragment(skillConv)
                
                // 保存技能信息到临时变量，等待Fragment切换后执行
                chatFragment?.pendingSkillToExecute = skill
                
                // 切换到聊天页面
                mainActivity?.switchToChatFragment(skillConv)
                
                return
            }
            
            // 解析技能步骤为user_example格式
            val userExample = SkillStepParser.parseStepsToUserExample(skill.steps)
            Log.d(TAG, "executeSkill: user_example=$userExample")
            
            // 保存user_example，在第一次发送时使用
            pendingUserExample = userExample
            
            // 执行query（使用技能标题作为query）
            executeQueryInternal(skill.title)
            
        } catch (e: Exception) {
            Log.e(TAG, "executeSkill异常: ${e.message}", e)
            addChatMessage("系统", "执行技能失败: ${e.message}")
        }
    }
    
    /**
     * 从外部执行query（供批测使用）
     * @param query 查询内容
     */
    fun executeQueryFromExternal(query: String) {
        if (query.isEmpty()) {
            Log.w(TAG, "executeQueryFromExternal: query为空")
            return
        }
        
        Log.d(TAG, "executeQueryFromExternal: 收到外部query=$query")
        executeQueryInternal(query)
    }
    
    /**
     * 批测专用：发送消息（供BatchTestController使用）
     * @param query 查询内容
     * @param batchTestId 批测ID（可选）
     */
    fun sendMessageForBatchTest(query: String, batchTestId: String? = null) {
        Log.d(TAG, "========== sendMessageForBatchTest 开始执行 ==========")
        Log.d(TAG, "sendMessageForBatchTest: query=$query, batchTestId=$batchTestId")
        Log.d(TAG, "sendMessageForBatchTest: Fragment状态 - isAdded=$isAdded, view=$view, binding=$binding")
        
        if (query.isEmpty()) {
            Log.w(TAG, "sendMessageForBatchTest: query为空")
            return
        }
        
        // 检查Fragment状态
        if (!isAdded || view == null) {
            Log.e(TAG, "sendMessageForBatchTest: Fragment未就绪，无法发送消息 - isAdded=$isAdded, view=$view")
            return
        }
        
        // 确保批测模式已设置
        val mainActivity = activity as? MainActivity
        val isBatchTesting = mainActivity?.isBatchTesting ?: false
        Log.d(TAG, "[批测检测] sendMessageForBatchTest: query=$query, batchTestId=$batchTestId, mainActivity=${mainActivity != null}, isBatchTesting=$isBatchTesting")
        
        if (!isBatchTesting) {
            Log.w(TAG, "[批测检测] 警告：sendMessageForBatchTest被调用，但isBatchTesting=false，可能存在问题")
        }
        
        // 直接调用executeQueryInternal，它会处理所有逻辑
        try {
            executeQueryInternal(query)
            Log.d(TAG, "sendMessageForBatchTest: executeQueryInternal调用成功")
        } catch (e: Exception) {
            Log.e(TAG, "sendMessageForBatchTest: executeQueryInternal异常: ${e.message}", e)
            e.printStackTrace()
            // 不抛出异常，避免崩溃
        }
        
        Log.d(TAG, "========== sendMessageForBatchTest 执行完成 ==========")
    }
    
    /**
     * 将技能作为query发送给云侧
     * @param skill 技能对象
     */
    fun sendSkillAsQuery(skill: Skill) {
        try {
            Log.d(TAG, "sendSkillAsQuery: 开始发送技能 - ${skill.title}")
            
            // 将技能格式化为query字符串
            val query = buildString {
                append(getString(R.string.execute_skill_format, skill.title))
                append(getString(R.string.action_steps_label))
                append("\n")
                skill.steps.forEachIndexed { index, step ->
                    append("${index + 1}. $step\n")
                }
                if (skill.originalPurpose != null) {
                    append(getString(R.string.original_purpose_format, skill.originalPurpose))
                }
            }
            
            Log.d(TAG, "sendSkillAsQuery: 格式化后的query=$query")
            
            // 检查当前对话是否是TopoClaw
            val conversationId = currentConversation?.id
            if (conversationId == ConversationListFragment.CONVERSATION_ID_ASSISTANT) {
                // 调用executeQueryInternal发送消息
                executeQueryInternal(query)
            } else {
                Log.w(TAG, "sendSkillAsQuery: 当前对话不是TopoClaw，conversationId=$conversationId")
                Toast.makeText(requireContext(), "只能在${ChatConstants.ASSISTANT_DISPLAY_NAME}聊天页面发送技能", Toast.LENGTH_SHORT).show()
            }
        } catch (e: Exception) {
            Log.e(TAG, "sendSkillAsQuery异常: ${e.message}", e)
            Toast.makeText(requireContext(), "发送技能失败: ${e.message}", Toast.LENGTH_SHORT).show()
        }
    }
    
    /**
     * 执行query的内部方法
     * @param query 查询内容
     */
    internal fun executeQueryInternal(query: String) {
        val stackTrace = Thread.currentThread().stackTrace.take(10).joinToString("\n") { it.toString() }
        Log.d(TAG, "========== executeQueryInternal 开始执行 ==========")
        Log.d(TAG, "executeQueryInternal: query='$query', selectedImageBase64=${selectedImageBase64 != null}")
        Log.d(TAG, "executeQueryInternal: Fragment状态 - isAdded=$isAdded, view=$view, binding=$binding")
        Log.d(TAG, "executeQueryInternal: 当前对话ID=${currentConversation?.id}, assistantGroupContext=${if (assistantGroupContext != null) "存在(groupId=${assistantGroupContext?.groupId}, originalQuery=${assistantGroupContext?.originalQuery})" else "不存在"}")
        Log.d(TAG, "executeQueryInternal: 调用堆栈:\n$stackTrace")
        
        // 检查Fragment状态
        if (!isAdded || view == null) {
            Log.e(TAG, "executeQueryInternal: Fragment未就绪，无法执行 - isAdded=$isAdded, view=$view")
            return
        }
        
        // 检查输入是否为空（允许query为空，只要有图片就可以发送）
        val hasImage = selectedImageBase64 != null
        if (query.trim().isEmpty() && !hasImage) {
            Log.w(TAG, "executeQueryInternal: 用户输入为空且没有图片，忽略执行")
            return
        }
        
        Log.d(TAG, "executeQueryInternal: 输入检查通过，继续执行")
        
        // 检查是否有残留的群组上下文（如果任务已经结束但上下文未清除）
        val groupContext = assistantGroupContext
        val conversationId = currentConversation?.id
        Log.d(TAG, "executeQueryInternal: 开始检查群组上下文 - conversationId=$conversationId, groupContext=${if (groupContext != null) "存在(groupId=${groupContext.groupId}, originalConversationId=${groupContext.originalConversation?.id})" else "不存在"}")
        
        // 如果当前对话是群组对话，但群组上下文存在且原始对话不是群组，说明应该恢复
        if (groupContext != null && 
            (conversationId?.startsWith("group_") == true || conversationId == ConversationListFragment.CONVERSATION_ID_GROUP) &&
            groupContext.originalConversation?.id?.startsWith("group_") != true &&
            groupContext.originalConversation?.id != ConversationListFragment.CONVERSATION_ID_GROUP) {
            // 这种情况不应该发生，但如果发生了，说明上下文不一致，需要恢复
            Log.w(TAG, "executeQueryInternal: 检测到上下文不一致，恢复原始对话上下文")
            currentConversation = groupContext.originalConversation
            assistantGroupContext = null
        }
        
        // 重要：如果有群组上下文，且消息中 @ 了群组内某小助手，说明这是任务执行中的调用，应保持上下文
        // 若消息中未 @ 任何群组内小助手，则恢复原始对话上下文
        // 注意：此时 currentConversation 可能已切到小助手，findMentionedGroupAssistantId 需用原始群组 ID 才能正确匹配
        val mentionedAssistantId = if (groupContext != null && groupContext.originalConversation != null) {
            findMentionedGroupAssistantId(query, groupContext.originalConversation!!.id)
        } else {
            findMentionedGroupAssistantId(query)
        }
        // 仅当当前对话是群组时才恢复上下文。若当前对话已是小助手，说明是群组管理者触发执行（cmd 不含 @），不应恢复，否则会误入群组分支并把 cmd 当用户消息发送，导致无限循环
        val isInGroupConversation = conversationId?.startsWith("group_") == true || conversationId == ConversationListFragment.CONVERSATION_ID_GROUP
        if (groupContext != null && mentionedAssistantId == null && isInGroupConversation) {
            Log.d(TAG, "executeQueryInternal: 消息中未 @ 群组内小助手，恢复原始对话上下文（当前对话ID: $conversationId）")
            currentConversation = groupContext.originalConversation
            assistantGroupContext = null
        } else if (groupContext != null && mentionedAssistantId != null) {
            // 有群组上下文且消息 @ 了群组内小助手，若当前对话不是该小助手，则切换过去
            if (conversationId != mentionedAssistantId) {
                val (aid, aname) = when (mentionedAssistantId) {
                    ConversationListFragment.CONVERSATION_ID_ASSISTANT ->
                        mentionedAssistantId to getString(R.string.auto_execute_assistant)
                    else -> {
                        val custom = CustomAssistantManager.getById(requireContext(), mentionedAssistantId)
                        (custom?.id ?: mentionedAssistantId) to (custom?.name ?: getString(R.string.custom_assistant_signature))
                    }
                }
                Log.d(TAG, "executeQueryInternal: 有群组上下文且消息 @ 了小助手，切换为对话: $aid")
                currentConversation = Conversation(id = aid, name = aname, lastMessage = query, lastMessageTime = System.currentTimeMillis())
            }
        }
        
        // 重新获取conversationId（可能已经恢复或切换）
        var finalConversationId = currentConversation?.id
        // 当 assistantPcExecuteContext 存在且 conversationId 为群组时，不走群组/好友发消息分支，
        // 而是走和TopoClaw相同的执行流程（权限检查、截图、调用 Agent、执行动作），使用TopoClaw的服务地址。
        // 群组是展示层，TopoClaw是执行层。
        val isGroupConversation = finalConversationId?.startsWith("group_") == true || finalConversationId == ConversationListFragment.CONVERSATION_ID_GROUP
        if (assistantPcExecuteContext != null && isGroupConversation) {
            Log.d(TAG, "========== executeQueryInternal: 群组内 PC 执行，切换到TopoClaw执行流程 ==========")
            val groupId = when {
                finalConversationId?.startsWith("group_") == true -> (finalConversationId ?: "").removePrefix("group_")
                finalConversationId == ConversationListFragment.CONVERSATION_ID_GROUP -> {
                    requireContext().getSharedPreferences("app_prefs", android.content.Context.MODE_PRIVATE)
                        .getString("default_group_id", null) ?: ""
                }
                else -> ""
            }
            if (groupId.isNotEmpty()) {
                val originalConversation = currentConversation
                val senderImei = ProfileManager.getOrGenerateImei(requireContext())
                assistantGroupContext = AssistantGroupContext(groupId, originalConversation, query, senderImei)
                currentConversation = Conversation(
                    id = ConversationListFragment.CONVERSATION_ID_ASSISTANT,
                    name = getString(R.string.auto_execute_assistant),
                    lastMessage = query,
                    lastMessageTime = System.currentTimeMillis()
                )
                finalConversationId = currentConversation?.id
                Log.d(TAG, "executeQueryInternal: 已切换到TopoClaw执行，结果将展示在群组 groupId=$groupId")
            }
        }
        val hasGroupContext = assistantGroupContext != null
        Log.d(TAG, "executeQueryInternal: 上下文检查完成 - finalConversationId=$finalConversationId, hasGroupContext=$hasGroupContext")
        Log.d(TAG, "========== executeQueryInternal: 关键判断点 ==========")
        Log.d(TAG, "executeQueryInternal: query=$query, finalConversationId=$finalConversationId, hasGroupContext=$hasGroupContext")
        if (hasGroupContext) {
            Log.d(TAG, "executeQueryInternal: assistantGroupContext详情 - groupId=${assistantGroupContext?.groupId}, originalConversationId=${assistantGroupContext?.originalConversation?.id}, originalQuery=${assistantGroupContext?.originalQuery}")
            Log.d(TAG, "executeQueryInternal: 有群组上下文，消息已通过performSendChatMessage()发送，跳过群组对话分支，直接执行任务逻辑")
        }
        
        // 管理员模式：回复用户消息，跳过权限检查，直接发送消息（和用户发送消息给人工客服一样）
        if (finalConversationId == ConversationListFragment.CONVERSATION_ID_ADMIN_CUSTOMER_SERVICE) {
            Log.d(TAG, "executeQueryInternal: 管理员模式对话，跳过权限检查，直接发送消息")
            // 优先使用筛选的用户，如果没有筛选则使用选中的用户
            val targetImeis = if (filteredImeis.isNotEmpty()) {
                filteredImeis
            } else if (selectedUserImei != null) {
                listOf(selectedUserImei!!)
            } else {
                emptyList()
            }
            
            if (targetImeis.isEmpty()) {
                addChatMessage("系统", "请先筛选或点击用户消息选择要回复的用户")
                return
            }
            
            // 自动设置selectedUserImei为第一个目标用户（用于显示提示）
            selectedUserImei = targetImeis.first()
            updateAdminInputHint()
            
            // 清空输入框（如果binding已初始化）
            try {
                binding?.etChatInput?.setText("")
            } catch (e: Exception) {
                Log.w(TAG, "executeQueryInternal: 清空输入框异常: ${e.message}", e)
            }
            
            // 确保在主线程执行，并且chatAdapter已初始化
            // 如果chatAdapter还未初始化，等待它初始化
            fun sendMessageWhenReady() {
                if (chatAdapter == null) {
                    Log.w(TAG, "executeQueryInternal: chatAdapter为null，等待初始化")
                    // 如果chatAdapter还未初始化，延迟执行
                    view?.postDelayed({
                        sendMessageWhenReady()
                    }, 100)
                    return
                }
                
                Log.d(TAG, "executeQueryInternal: chatAdapter已初始化，添加管理员消息")
                // 添加管理员消息到聊天框（必须在主线程执行，确保UI更新）
                addChatMessage("管理员", query, skipSystemMessageContainer = true)
                // 直接发送消息（通过API，不需要截图、无障碍、输入法检测）
                mainScope.launch {
                    performSendChatMessage(query, shouldGoHome = false)
                }
            }
            
            sendMessageWhenReady()
            return
        }
        
        // 用户发送消息给人工客服、好友、端云互发、聊天小助手或自建群组：跳过权限检查，直接发送消息
        // 重要：如果有群组上下文（hasGroupContext=true），说明消息已经通过performSendChatMessage()发送过了，
        // 不应该再次进入群组分支，应该直接执行任务逻辑（权限检查、截图、执行等）
        val isGroupOrFriendConversation = finalConversationId == ConversationListFragment.CONVERSATION_ID_ME ||
            finalConversationId == ConversationListFragment.CONVERSATION_ID_CUSTOMER_SERVICE ||
            finalConversationId == ConversationListFragment.CONVERSATION_ID_CHAT_ASSISTANT ||
            finalConversationId?.startsWith("friend_") == true ||
            finalConversationId?.startsWith("group_") == true ||
            finalConversationId == ConversationListFragment.CONVERSATION_ID_GROUP
        if (isGroupOrFriendConversation && !hasGroupContext) {
            Log.d(TAG, "========== executeQueryInternal: 进入群组/好友对话分支 ==========")
            Log.d(TAG, "executeQueryInternal: 人工客服、好友对话或自建群组，跳过权限检查，直接发送消息")
            Log.d(TAG, "executeQueryInternal: finalConversationId=$finalConversationId, hasGroupContext=$hasGroupContext")
            Log.d(TAG, "executeQueryInternal: 准备再次调用performSendChatMessage，query=$query")
            // 清空输入框（如果binding已初始化）
            try {
                binding?.etChatInput?.setText("")
            } catch (e: Exception) {
                Log.w(TAG, "executeQueryInternal: 清空输入框异常: ${e.message}", e)
            }
            
            // 确保在主线程执行，并且chatAdapter已初始化
            // 如果chatAdapter还未初始化，等待它初始化
            fun sendMessageWhenReady() {
                if (chatAdapter == null) {
                    Log.w(TAG, "executeQueryInternal: chatAdapter为null，等待初始化")
                    // 如果chatAdapter还未初始化，延迟执行
                    view?.postDelayed({
                        sendMessageWhenReady()
                    }, 100)
                    return
                }
                
                Log.d(TAG, "executeQueryInternal: chatAdapter已初始化，准备发送消息")
                // 如果有图片，不在这里添加消息，让performSendChatMessage统一处理图片和文本
                // 如果没有图片，先添加文本消息
                val hasImage = selectedImageBase64 != null
                if (!hasImage) {
                    addChatMessage(getSenderDisplayName(), query)
                }
                // 直接发送消息（通过WebSocket）
                Log.d(TAG, "executeQueryInternal: 在群组/好友分支中，准备调用performSendChatMessage")
                mainScope.launch {
                    Log.d(TAG, "executeQueryInternal: 开始调用performSendChatMessage（从群组/好友分支）")
                    performSendChatMessage(query, shouldGoHome = false)
                    Log.d(TAG, "executeQueryInternal: performSendChatMessage调用完成（从群组/好友分支）")
                }
            }
            
            sendMessageWhenReady()
            return
        }
        
        // 仅电脑端执行小助手：手机发送 -> 桥接到 PC 执行，不弹截图、无障碍、输入法检测
        val isPcOnlyAssistant = run {
            val convId = finalConversationId ?: return@run false
            if (!CustomAssistantManager.isCustomAssistantId(convId)) return@run false
            val ca = CustomAssistantManager.getById(requireContext(), convId) ?: return@run false
            !ca.hasChat() && ca.hasExecutionPc()
        }
        if (isPcOnlyAssistant) {
            Log.d(TAG, "========== executeQueryInternal: 仅电脑端执行小助手 ==========")
            Log.d(TAG, "executeQueryInternal: 跳过截图、无障碍、输入法检测，直接发送到 PC 执行")
            try { binding?.etChatInput?.setText("") } catch (e: Exception) { }
            fun sendMessageWhenReady() {
                if (chatAdapter == null) {
                    view?.postDelayed({ sendMessageWhenReady() }, 100)
                    return
                }
                val hasImage = selectedImageBase64 != null
                if (!hasImage) addChatMessage(getSenderDisplayName(), query)
                mainScope.launch { performSendChatMessage(query, shouldGoHome = false) }
            }
            sendMessageWhenReady()
            return
        }
        
        // 如果正在等待用户输入视频操作目的，将用户的回复作为query重新上传视频
        if (waitingForVideoPurpose && pendingVideoPath != null) {
            // 确保用户确实输入了内容（不是空字符串）
            val userPurpose = query.trim()
            if (userPurpose.isEmpty()) {
                Log.w(TAG, "用户输入的操作目的为空，继续等待")
                return
            }
            
            Log.d(TAG, "检测到用户输入视频操作目的，将上传视频: $userPurpose")
            
            // 显示用户输入的消息
            addChatMessage("我", userPurpose)
            
            // 显示"开始学习~"（使用 isAnswer = true 表示这是小助手的消息）
            addChatMessage("小助手", "开始学习~", isAnswer = true)
            
            // 清除等待状态
            val videoPathToUpload = pendingVideoPath!!
            val screenWidthToUpload = pendingScreenWidth
            val screenHeightToUpload = pendingScreenHeight
            waitingForVideoPurpose = false
            pendingVideoPath = null
            pendingScreenWidth = 0
            pendingScreenHeight = 0
            
            // 使用用户的回复作为query上传视频
            mainScope.launch {
                uploadVideoToCloudWithQuery(videoPathToUpload, screenWidthToUpload, screenHeightToUpload, userPurpose)
            }
            return
        }
        
        // 检查权限（如果用户选择了图片，第一次发送时不需要截图权限）
        // 人工客服和好友对话不需要截图权限
        // 自定义小助手聊天优先模式：先走 /chat，need_execution 时才检查权限，此处跳过
        val hasUserImage = selectedImageBase64 != null
        val isCustomChatFirst = isCustomAssistantChatFirst()
        val mainActivity = activity as? MainActivity
        val isFromCompanionMode = mainActivity?.isTaskFromCompanionMode ?: false
        val isCompanionAskScreenEnabled = mainActivity?.isCompanionAskScreenEnabled ?: false
        val shouldSkipScreenshotCheckForCompanion = isFromCompanionMode && !isCompanionAskScreenEnabled
        if (!hasUserImage && !isSimpleChatConversation() && !isCustomChatFirst && !shouldSkipScreenshotCheckForCompanion) {
            val chatService = ChatScreenshotService.getInstance()
            val isReady = chatService != null && chatService.isReady()
            Log.d(TAG, "executeQueryInternal: 检查截图权限，chatService=${chatService != null}, isReady=$isReady")
            
            if (!isReady) {
                // 保存待发送的消息，授权后自动发送
                pendingQueryAfterPermission = query
                Log.d(TAG, "executeQueryInternal: 保存待发送消息到pendingQueryAfterPermission: $query")
                
                // 临时禁用返回键处理，避免权限授权对话框关闭时触发返回键导致Fragment切换
                onBackPressedCallback?.isEnabled = false
                Log.d(TAG, "executeQueryInternal: 临时禁用返回键处理，避免权限授权过程中Fragment被切换")
                
                // 显示弹窗引导用户授权
                showScreenshotPermissionDialog {
                    Log.d(TAG, "用户确认授权截图权限")
                    requestChatScreenshotPermission()
                }
                Log.w(TAG, "executeQueryInternal: 权限检查失败 - chatService=${chatService != null}, isReady=${chatService?.isReady()}")
                return
            }
        } else {
            if (hasUserImage) {
                Log.d(TAG, "executeQueryInternal: 用户已选择图片，跳过截图权限检查")
            } else if (isSimpleChatConversation()) {
                Log.d(TAG, "executeQueryInternal: 人工客服或好友对话，跳过截图权限检查")
            } else if (isCustomChatFirst) {
                Log.d(TAG, "executeQueryInternal: 自定义小助手聊天优先模式，跳过截图权限检查")
            } else if (shouldSkipScreenshotCheckForCompanion) {
                Log.d(TAG, "executeQueryInternal: 悬浮球且问屏关闭，跳过截图权限检查")
            }
        }
        
        // 检查无障碍服务（发送消息时需要无障碍服务来执行操作）
        // 人工客服和好友对话不需要无障碍服务
        // 自定义小助手聊天优先模式：此处跳过，need_execution 时再检查
        // 悬浮球发起：按需求跳过无障碍预检查
        if (!isFromCompanionMode && !isSimpleChatConversation() && !isCustomChatFirst && !isAccessibilityServiceEnabled()) {
            // 保存待发送的消息，无障碍服务开启后自动发送
            pendingQueryAfterAccessibility = query
            
            // 显示弹窗引导用户开启无障碍服务
            showAccessibilityServiceDialog {
                Log.d(TAG, "用户确认前往无障碍设置")
                openAccessibilitySettings()
            }
            Log.w(TAG, "executeQueryInternal: 无障碍服务未启用")
            return
        } else if (isFromCompanionMode) {
            Log.d(TAG, "executeQueryInternal: 悬浮球发起，跳过无障碍服务预检查")
        }
        
        // 清空输入框（如果是从UI调用）
        try {
            binding?.etChatInput?.setText("")
        } catch (e: Exception) {
            Log.w(TAG, "executeQueryInternal: 清空输入框异常: ${e.message}", e)
            // 继续执行，不中断流程
        }
        
        // 如果存在待处理的call_user，将用户输入作为回复发送
        if (pendingCallUser && originalQuery != null) {
            Log.d(TAG, "检测到待处理的call_user，将用户输入作为回复发送: $query")
            addChatMessage(getSenderDisplayName(), query)
            // 清除call_user状态
            pendingCallUser = false
            pendingCallUserText = null
            // 使用原始query继续任务，并传递用户回复
            val originalQueryToUse = originalQuery!!
            originalQuery = null
            // 执行发送（传递用户回复）
            mainScope.launch {
                performSendChatMessage(originalQueryToUse, userResponse = query)
            }
            return
        }
        
        // 发送图片后立即隐藏输入框上方的图片预览
        try {
            if (selectedImageBase64 != null && selectedImageUri != null) {
                binding?.llImagePreview?.visibility = android.view.View.GONE
                binding?.ivSelectedImage?.setImageBitmap(null)
            }
        } catch (e: Exception) {
            Log.w(TAG, "executeQueryInternal: 隐藏图片预览异常: ${e.message}", e)
            // 继续执行，不中断流程
        }
        
        // 检查是否有群组上下文，如果有则跳过添加用户消息（消息已通过WebSocket发送到群组）
        // 例外：assistantPcExecuteContext 存在时为 PC 端群组执行，消息未通过 WebSocket 发送，需添加
        if (!hasGroupContext || assistantPcExecuteContext != null) {
            // 添加用户消息到聊天框（如果有图片，显示图片消息）
            if (selectedImageBase64 != null && selectedImageUri != null) {
                // 保存图片到本地并显示图片消息（异步，不阻塞发送）
                selectedImageUri?.let { uri ->
                    mainScope.launch {
                        try {
                            val imagePath = saveImageToLocal(uri)
                            if (imagePath != null) {
                                withContext(Dispatchers.Main) {
                                    addImageMessage(imagePath, query, sender = getSenderDisplayName())
                                }
                            } else {
                                // 如果保存失败，显示文本消息
                                withContext(Dispatchers.Main) {
                                    addChatMessage(getSenderDisplayName(), if (query.isNotEmpty()) query else "[图片]")
                                }
                            }
                        } catch (e: Exception) {
                            Log.e(TAG, "保存图片失败: ${e.message}", e)
                            withContext(Dispatchers.Main) {
                                addChatMessage(getSenderDisplayName(), if (query.isNotEmpty()) query else "[图片]")
                            }
                        }
                    }
                }
            } else {
                // 如果没有URI但有Base64（问字按钮场景），显示文本消息
                if (selectedImageBase64 != null && query.isEmpty()) {
                    addChatMessage(getSenderDisplayName(), "[图片]")
                } else {
                    addChatMessage(getSenderDisplayName(), query)
                }
            }
        } else {
            Log.d(TAG, "检测到群组上下文，跳过添加用户消息（消息已通过WebSocket发送到群组）")
        }
        
        // 保存查询到历史记录（排除预设查询，避免重复）
        if (query.isNotEmpty() && !ChatConstants.PRESET_QUERIES.contains(query)) {
            addQueryToHistory(query)
        }
        
        // 保存原始查询
        originalQuery = query
        
        // 检查NetworkService是否已初始化
        if (!NetworkService.isInitialized()) {
            Log.e(TAG, "executeQueryInternal: NetworkService未初始化，无法发送消息")
            addChatMessage("系统", "网络服务未初始化，请稍后重试")
            return
        }
        
        Log.d(TAG, "executeQueryInternal: NetworkService已初始化，准备开始任务")
        
        // 开始任务（等待输入法检查完成）
        Log.d(TAG, "executeQueryInternal: 准备启动协程，mainScope=$mainScope, isCustomChatFirst=$isCustomChatFirst")
        try {
            mainScope.launch {
                try {
                    Log.d(TAG, "executeQueryInternal: 协程已启动")
                    // 检查Fragment状态
                    if (!isAdded || view == null) {
                        Log.e(TAG, "executeQueryInternal: Fragment未就绪，无法开始任务 - isAdded=$isAdded, view=$view")
                        return@launch
                    }
                    
                    val taskStarted = if (isCustomChatFirst) {
                        // 自定义小助手聊天优先：跳过 startTaskInternal，直接发送
                        Log.d(TAG, "executeQueryInternal: 自定义小助手聊天优先模式，跳过 startTaskInternal，直接调用 performSendChatMessage")
                        true
                    } else {
                        Log.d(TAG, "executeQueryInternal: Fragment状态正常，准备调用startTaskInternal")
                        try {
                            Log.d(TAG, "executeQueryInternal: 开始调用startTaskInternal，query='$query'")
                            Log.d(TAG, "executeQueryInternal: 调用startTaskInternal前，无障碍服务实例=${if (MyAccessibilityService.getInstance() != null) "已就绪" else "为null"}")
                            val result = try {
                                startTaskInternal(query)
                            } catch (e: Exception) {
                                Log.e(TAG, "executeQueryInternal: startTaskInternal调用时出现异常: ${e.message}", e)
                                e.printStackTrace()
                                throw e
                            }
                            Log.d(TAG, "executeQueryInternal: startTaskInternal返回=$result")
                            if (result) {
                                Log.d(TAG, "executeQueryInternal: startTaskInternal返回true，输入法检查已通过，可以发送消息")
                            } else {
                                Log.w(TAG, "executeQueryInternal: startTaskInternal返回false，输入法检查未通过，不会发送消息")
                            }
                            result
                        } catch (e: Exception) {
                            Log.e(TAG, "executeQueryInternal: startTaskInternal异常: ${e.message}", e)
                            e.printStackTrace()
                            val sw = java.io.StringWriter()
                            val pw = java.io.PrintWriter(sw)
                            e.printStackTrace(pw)
                            Log.e(TAG, "executeQueryInternal: startTaskInternal异常堆栈:\n${sw.toString()}")
                            false
                        }
                    }
                
                Log.d(TAG, "executeQueryInternal: taskStarted=$taskStarted")
                
                if (!taskStarted) {
                    // 任务未开始（输入法未启用或切换失败），不发送消息
                    Log.d(TAG, "executeQueryInternal: 任务未开始，等待用户启用/切换输入法后再重试")
                    return@launch
                }
                
                // 再次检查Fragment状态
                if (!isAdded || view == null) {
                    Log.e(TAG, "executeQueryInternal: Fragment状态已改变，无法发送消息")
                    return@launch
                }
                
                // 任务已开始，执行发送（如果有pendingUserExample，在第一次发送时使用）
                // 注意：不要在这里清除selectedImageBase64，让performSendChatMessage来处理
                // 第一次发送时不回退到home页面，等收到规划结果后再决定是否回退
                Log.d(TAG, "executeQueryInternal: 准备调用performSendChatMessage，query='$query', hasImage=${selectedImageBase64 != null}")
                val userExample = pendingUserExample
                // 第一次发送后清除pendingUserExample
                pendingUserExample = null
                val shouldGoHomeOnFirstSend = isCustomAssistantExecutionOnly()
                Log.d(TAG, "executeQueryInternal: 开始调用performSendChatMessage")
                try {
                    performSendChatMessage(
                        query = query,
                        // 自定义小助手（仅手机端执行）首发前先回到桌面，再开始截图与上传
                        shouldGoHome = shouldGoHomeOnFirstSend,
                        userExample = userExample
                    )
                    Log.d(TAG, "executeQueryInternal: performSendChatMessage调用完成")
                } catch (e: Exception) {
                    // 重新抛出CancellationException，避免吞掉协程取消信号
                    if (e is kotlinx.coroutines.CancellationException) throw e
                    Log.e(TAG, "executeQueryInternal: performSendChatMessage异常: ${e.message}", e)
                    e.printStackTrace()
                    // 不抛出异常，避免崩溃
                }
            } catch (e: Exception) {
                // 重新抛出CancellationException，避免吞掉协程取消信号
                if (e is kotlinx.coroutines.CancellationException) throw e
                Log.e(TAG, "executeQueryInternal: 协程执行异常: ${e.message}", e)
                e.printStackTrace()
                // 打印完整堆栈
                val sw = java.io.StringWriter()
                val pw = java.io.PrintWriter(sw)
                e.printStackTrace(pw)
                Log.e(TAG, "executeQueryInternal: 协程异常堆栈:\n${sw.toString()}")
                // 不抛出异常，避免崩溃
            }
            }
        } catch (e: Exception) {
            Log.e(TAG, "executeQueryInternal: 启动协程异常: ${e.message}", e)
            e.printStackTrace()
            // 打印完整堆栈
            val sw = java.io.StringWriter()
            val pw = java.io.PrintWriter(sw)
            e.printStackTrace(pw)
            Log.e(TAG, "executeQueryInternal: 启动协程异常堆栈:\n${sw.toString()}")
        }
        
        Log.d(TAG, "========== executeQueryInternal 执行完成 ==========")
    }
    
    /**
     * 从异常检测触发call_user动作
     * @param callUserText call_user的文本内容
     */
    fun handleCallUserFromAnomalyDetection(callUserText: String) {
        Log.i(TAG, "[异常处理] 触发call_user动作: $callUserText")
        // 设置标记：刚刚执行了 call_user，下次必须上发云侧
        hasJustCalledUser = true
        Log.d(TAG, "[状态管理] 设置 hasJustCalledUser = true")
        // 使用lifecycleScope在主线程执行
        lifecycleScope.launch(Dispatchers.Main) {
            // 播放call_user提示音效
            playCallUserSound()
            
            // 保存原始query（如果还没有保存）
            if (originalQuery == null) {
                originalQuery = currentQuery
            }
            
            // 停止任务循环，等待用户输入
            taskJob?.cancel()
            taskJob = null
            
            // 先将call_user消息添加到聊天界面
            addChatMessage("系统", callUserText, isAnswer = true)
            Log.d(TAG, "[异常处理] call_user消息已添加到聊天框")
            
            val currentActivity = activity
            if (currentActivity != null) {
                val savedOriginalQuery: String? = originalQuery
                CallUserInputOverlayManager.show(
                    context = currentActivity,
                    questionText = callUserText,
                    onSend = { userInput: String ->
                        Log.d(TAG, "[异常处理] 用户通过悬浮窗输入: $userInput")
                        // 将用户输入添加到聊天界面
                        addChatMessage("我", userInput)
                        // 用户输入后，继续任务
                        if (savedOriginalQuery != null) {
                            originalQuery = null
                            handleCallUserResponse(savedOriginalQuery, userInput)
                        }
                    },
                    onCancel = {
                        Log.d(TAG, "[异常处理] 用户取消输入，停止任务")
                        // 用户取消，停止任务
                        stopTask()
                        notifyTaskComplete()
                    },
                    onManualTakeover = {
                        Log.d(TAG, "[异常处理] 用户点击手动接管")
                        // 设置手动接管状态
                        isManualTakeover = true
                        // 停止任务循环
                        taskJob?.cancel()
                        taskJob = null
                        // 添加提示消息
                        addChatMessage("系统", "已进入手动接管模式，请手动操作屏幕。操作完成后，点击悬浮球结束手动操作。")
                    }
                )
            } else {
                Log.w(TAG, "[异常处理] Activity为null，无法显示悬浮窗")
            }
        }
    }
    
    /**
     * 处理call_user的用户输入
     */
    private fun handleCallUserResponse(query: String, userResponse: String) {
        Log.d(TAG, "handleCallUserResponse: query=$query, userResponse=$userResponse")
        
        // 主动交互时，用户完成输入点击发送后，直接继续执行任务，不需要暂停和弹窗
        // 只有暂停任务、接续才需要暂停
        Log.d(TAG, "handleCallUserResponse: 用户完成输入，直接继续执行任务")
        
        mainScope.launch {
            performSendChatMessage(
                query = query,
                shouldGoHome = false, // call_user后不需要goHome，直接在当前屏幕执行
                userResponse = userResponse
            )
        }
    }
    
    /**
     * 继续call_user后的任务（用户点击悬浮球后调用）
     */
    private fun continueCallUserTask() {
        if (!pendingCallUser || pendingCallUserText == null || originalQuery == null) {
            Log.w(TAG, "continueCallUserTask: 没有待处理的call_user任务")
            return
        }
        
        val query = originalQuery!!
        val userResponse = pendingCallUserText!!
        
        // 清除状态
        pendingCallUser = false
        pendingCallUserText = null
        originalQuery = null
        isTaskPaused = false
        
        Log.d(TAG, "continueCallUserTask: 继续call_user任务，query=$query, userResponse=$userResponse")
        
        mainScope.launch {
            performSendChatMessage(
                query = query,
                shouldGoHome = false, // call_user后不需要goHome，直接在当前屏幕执行
                userResponse = userResponse
            )
        }
    }
    
    /**
     * 结束手动接管模式
     * 获取当前截图并发送给云侧，告知用户已手动操作
     */
    fun endManualTakeover() {
        if (!isManualTakeover) {
            Log.w(TAG, "endManualTakeover: 当前不处于手动接管状态")
            return
        }
        
        Log.d(TAG, "endManualTakeover: 开始结束手动接管")
        mainScope.launch {
            try {
                // 获取截图服务
                val chatService = ChatScreenshotService.getInstance()
                if (chatService == null || !chatService.isReady()) {
                    Log.w(TAG, "截图服务未就绪，无法结束手动接管")
                    withContext(Dispatchers.Main) {
                        addChatMessage("系统", "截图服务未就绪，无法结束手动操作")
                    }
                    return@launch
                }
                
                // 获取当前截图
                val bitmap = withContext(Dispatchers.IO) {
                    chatService.captureScreenshot()
                }
                
                if (bitmap == null) {
                    Log.w(TAG, "获取截图失败，无法结束手动接管")
                    withContext(Dispatchers.Main) {
                        addChatMessage("小助手", "获取截图失败，无法结束手动操作")
                    }
                    return@launch
                }
                
                // 转换为Base64
                val base64Image = try {
                    screenshotBitmapToBase64(bitmap)
                } catch (e: Exception) {
                    Log.e(TAG, "Base64转换失败: ${e.message}", e)
                    bitmap.recycle()
                    withContext(Dispatchers.Main) {
                        addChatMessage("系统", "图片转换失败: ${e.message}")
                    }
                    return@launch
                }
                
                bitmap.recycle()
                
                // 清理Base64字符串
                val cleanBase64 = base64Image.trim().replace("\n", "").replace("\r", "").replace(" ", "")
                
                // 验证Base64格式
                val (base64Part, isValidBase64) = try {
                    val base64Index = cleanBase64.indexOf(";base64,")
                    val part = if (base64Index != -1) {
                        cleanBase64.substring(base64Index + 8)
                    } else {
                        cleanBase64
                    }
                    if (part.length % 4 != 0) {
                        Pair(part, false)
                    } else {
                        android.util.Base64.decode(part, android.util.Base64.NO_WRAP)
                        Pair(part, true)
                    }
                } catch (e: Exception) {
                    Log.e(TAG, "Base64验证失败: ${e.message}", e)
                    Pair("", false)
                }
                
                if (!isValidBase64) {
                    Log.w(TAG, "Base64字符串无效，无法发送手动接管回复")
                    withContext(Dispatchers.Main) {
                        addChatMessage("系统", "Base64编码验证失败，无法继续")
                    }
                    // 清除手动接管状态
                    isManualTakeover = false
                    return@launch
                }
                
                val finalBase64 = cleanBase64
                
                // URL编码
                val urlEncodedBase64 = try {
                    java.net.URLEncoder.encode(finalBase64, "UTF-8")
                } catch (e: Exception) {
                    Log.e(TAG, "URL编码失败: ${e.message}", e)
                    finalBase64
                }
                
                // 获取原始query
                val savedOriginalQuery = originalQuery ?: currentQuery
                if (savedOriginalQuery == null) {
                    Log.w(TAG, "原始query为空，无法发送手动接管回复")
                    withContext(Dispatchers.Main) {
                        addChatMessage("系统", "任务查询为空，无法继续")
                    }
                    // 清除手动接管状态
                    isManualTakeover = false
                    return@launch
                }
                
                // 获取当前Activity信息
                val (packageName, className) = MyAccessibilityService.getCurrentActivityInfo()
                val imei = ProfileManager.getOrGenerateImei(requireContext())
                
                // 确保网络服务已初始化
                ensureNetworkServiceInitialized()
                val apiService = NetworkService.getApiService()
                if (apiService == null) {
                    Log.w(TAG, "ApiService未初始化，无法发送手动接管回复")
                    withContext(Dispatchers.Main) {
                        addChatMessage("系统", "网络服务未初始化，无法继续")
                    }
                    // 清除手动接管状态
                    isManualTakeover = false
                    return@launch
                }
                
                // 发送消息给云侧
                val userResponseText = "用户已手动操作，操作最终界面如图所示，请继续执行任务"
                Log.d(TAG, "发送手动接管回复: query=$savedOriginalQuery, userResponse=$userResponseText")
                Log.d(TAG, "Base64部分长度: ${base64Part.length}, 是否为4的倍数: ${base64Part.length % 4 == 0}")
                Log.d(TAG, "URL编码后长度: ${urlEncodedBase64.length}, 原始长度: ${finalBase64.length}")
                
                withContext(Dispatchers.Main) {
                    addChatMessage("系统", "手动操作已完成，正在发送截图...")
                }
                
                val (response, parsedChatResponse) = try {
                    val mainActivity = activity as? MainActivity
                    val isBatchTesting = mainActivity?.isBatchTesting ?: false
                    performCloudRequest(
                        apiService,
                        chatUuid,
                        savedOriginalQuery,
                        finalBase64,
                        urlEncodedBase64,
                        userResponse = userResponseText,
                        packageName = packageName,
                        className = className,
                        imei = imei,
                        proMode = if (isProModeEnabled) true else null,
                        batchTestMode = if (isBatchTesting) true else null
                    )
                } catch (e: Exception) {
                    Log.e(TAG, "发送手动接管回复失败: ${e.message}", e)
                    withContext(Dispatchers.Main) {
                        addChatMessage("系统", "发送失败: ${e.message}")
                    }
                    // 清除手动接管状态
                    isManualTakeover = false
                    return@launch
                }
                
                // 清除手动接管状态
                isManualTakeover = false
                originalQuery = null
                
                // 处理响应并继续任务
                if (response.isSuccessful) {
                    val chatResponse = parsedChatResponse
                    if (chatResponse != null) {
                        Log.d(TAG, "手动接管回复发送成功，继续任务")
                        withContext(Dispatchers.Main) {
                            addChatMessage("系统", "手动操作已发送，继续执行任务")
                        }
                        // 继续任务循环
                        continueTaskLoop()
                    } else {
                        Log.w(TAG, "手动接管回复响应体为空")
                        withContext(Dispatchers.Main) {
                            addChatMessage("系统", "服务器响应为空")
                        }
                    }
                } else {
                    Log.w(TAG, "手动接管回复发送失败，状态码: ${response.code()}")
                    withContext(Dispatchers.Main) {
                        addChatMessage("系统", "发送失败，状态码: ${response.code()}")
                    }
                }
            } catch (e: Exception) {
                Log.e(TAG, "结束手动接管异常: ${e.message}", e)
                withContext(Dispatchers.Main) {
                    addChatMessage("系统", "结束手动操作异常: ${e.message}")
                }
                // 清除手动接管状态
                isManualTakeover = false
            }
        }
    }
    
    /**
     * 处理补充任务（用户主动发起）
     * 从悬浮窗菜单调用
     */
    fun handleTaskSupplement() {
        Log.d(TAG, "handleTaskSupplement: 开始处理补充任务")
        
        // 检查任务状态
        if (!isTaskRunning || currentQuery == null) {
            Log.w(TAG, "handleTaskSupplement: 任务未运行或query为空，无法补充任务")
            mainScope.launch {
                withContext(Dispatchers.Main) {
                    addChatMessage("系统", "任务未运行，无法补充任务")
                }
            }
            return
        }
        
        mainScope.launch {
            withContext(Dispatchers.Main) {
                // 如果任务正在运行且未暂停，先暂停任务
                if (!isTaskPaused) {
                    Log.d(TAG, "handleTaskSupplement: 任务运行中，先暂停任务")
                    pauseTask()
                }
                
                // 停止任务循环，等待用户输入
                taskJob?.cancel()
                taskJob = null
                Log.d(TAG, "handleTaskSupplement: 已停止任务循环，等待用户输入")
                
                // 保存原始query（如果还没有保存）
                if (originalQuery == null) {
                    originalQuery = currentQuery
                }
                
                // 显示悬浮窗输入框（与call_user使用相同的UI和逻辑）
                val currentActivity = activity
                if (currentActivity != null) {
                    val savedOriginalQuery: String? = originalQuery
                    CallUserInputOverlayManager.show(
                        context = currentActivity,
                        questionText = "请输入补充任务指令：",
                        onSend = { userInput: String ->
                            Log.d(TAG, "用户通过补充任务输入: $userInput")
                            // 将用户输入添加到聊天界面
                            addChatMessage("我", userInput)
                            // 用户输入后，继续任务（与call_user逻辑一致）
                            if (savedOriginalQuery != null) {
                                originalQuery = null
                                handleTaskSupplementResponse(savedOriginalQuery, userInput)
                            }
                        },
                        onCancel = {
                            Log.d(TAG, "用户取消补充任务输入，停止任务")
                            // 用户取消，停止任务（与call_user逻辑一致）
                            stopTask()
                            notifyTaskComplete()
                        }
                    )
                } else {
                    Log.w(TAG, "Activity为null，无法显示补充任务输入框")
                }
            }
        }
    }
    
    /**
     * 处理补充任务的用户输入
     */
    private fun handleTaskSupplementResponse(query: String, userResponse: String) {
        Log.d(TAG, "handleTaskSupplementResponse: query=$query, userResponse=$userResponse")
        // 恢复任务（取消暂停状态），以便响应处理时能继续任务循环
        if (isTaskPaused) {
            Log.d(TAG, "handleTaskSupplementResponse: 恢复任务（取消暂停状态）")
            isTaskPaused = false
            // 更新UI状态，显示任务已继续（可选，因为用户已经知道任务在进行）
            // 这里不显示消息，因为用户刚刚发送了补充指令，不需要额外的提示
        }
        mainScope.launch {
            performSendChatMessage(
                query = query,
                shouldGoHome = false, // 补充任务后不需要goHome，直接在当前屏幕执行（与call_user一致）
                userResponse = userResponse // 直接传递用户输入，与call_user逻辑一致
            )
        }
    }
    
    /**
     * 执行发送聊天消息（协程）
     * @param query 查询内容
     * @param shouldGoHome 是否先回退到home页面（第一次发送时为true，后续循环为false）
     * @param userResponse 用户回复（用于call_user动作）
     * @param userExample 用户示例（用于技能执行）
     */
    private suspend fun performSendChatMessage(query: String, shouldGoHome: Boolean = true, userResponse: String? = null, userExample: String? = null) = withContext(Dispatchers.IO) {
        // 发送到云侧时，重置端侧异常检测状态
        hasJustCalledUser = false
        consecutiveWaitCount = 0
        isWaitRetry = false
        Log.d(TAG, "[状态管理] 发送到云侧，重置 hasJustCalledUser、consecutiveWaitCount 和 isWaitRetry")
        try {
            val stackTrace = Thread.currentThread().stackTrace.take(10).joinToString("\n") { it.toString() }
            Log.d(TAG, "========== performSendChatMessage: 开始 ==========")
            Log.d(TAG, "performSendChatMessage: query=$query, shouldGoHome=$shouldGoHome, userResponse=$userResponse, userExample=$userExample")
            Log.d(TAG, "performSendChatMessage: 调用堆栈:\n$stackTrace")
            Log.d(TAG, "performSendChatMessage: 当前对话ID=${currentConversation?.id}, assistantGroupContext=${if (assistantGroupContext != null) "存在(groupId=${assistantGroupContext?.groupId})" else "不存在"}")
            
            // 顶层分流：如果是人工客服或管理员模式，直接通过WebSocket/API发送并返回
            val conversationId = currentConversation?.id
            Log.d(TAG, "performSendChatMessage: conversationId=$conversationId, query=$query")
            
            // 管理员模式：通过API发送消息给选中的用户
            if (conversationId == ConversationListFragment.CONVERSATION_ID_ADMIN_CUSTOMER_SERVICE) {
                // 优先使用筛选的用户，如果没有筛选则使用选中的用户
                val targetImeis = if (filteredImeis.isNotEmpty()) {
                    filteredImeis
                } else if (selectedUserImei != null) {
                    listOf(selectedUserImei!!)
                } else {
                    emptyList()
                }
                
                if (targetImeis.isEmpty()) {
                    withContext(Dispatchers.Main) {
                        addChatMessage("系统", "请先筛选或点击用户消息选择要回复的用户")
                    }
                    return@withContext
                }
                
                Log.d(TAG, "管理员模式：准备发送消息给 ${targetImeis.size} 个用户: $targetImeis")
                
                // 通过API发送消息
                val prefs = requireContext().getSharedPreferences("app_prefs", android.content.Context.MODE_PRIVATE)
                val customerServiceUrl = prefs.getString("chat_server_url_${ConversationListFragment.CONVERSATION_ID_CUSTOMER_SERVICE}", null)
                    ?: prefs.getString("customer_service_url", ServiceUrlConfig.DEFAULT_CUSTOMER_SERVICE_URL)
                    ?: ServiceUrlConfig.DEFAULT_CUSTOMER_SERVICE_URL
                
                CustomerServiceNetwork.initialize(customerServiceUrl)
                val apiService = CustomerServiceNetwork.getApiService()
                
                if (apiService != null) {
                    var successCount = 0
                    var failCount = 0
                    val failMessages = mutableListOf<String>()
                    
                    // 循环发送给所有目标用户
                    for (targetImei in targetImeis) {
                        try {
                            val response = apiService.sendMessage(
                                SendMessageRequest(
                                    imei = targetImei,
                                    content = query,
                                    message_type = "text"
                                )
                            )
                            
                            if (response.isSuccessful && response.body()?.success == true) {
                                successCount++
                                Log.d(TAG, "管理员消息发送成功给用户: $targetImei")
                            } else {
                                failCount++
                                val errorMsg = response.body()?.message ?: "未知错误"
                                failMessages.add("$targetImei: $errorMsg")
                                Log.e(TAG, "管理员消息发送失败给用户 $targetImei: $errorMsg")
                            }
                        } catch (e: Exception) {
                            failCount++
                            failMessages.add("$targetImei: ${e.message}")
                            Log.e(TAG, "发送管理员消息异常给用户 $targetImei: ${e.message}", e)
                        }
                    }
                    
                    // 显示发送结果
                    withContext(Dispatchers.Main) {
                        when {
                            successCount > 0 && failCount == 0 -> {
                                if (targetImeis.size == 1) {
                                    Log.d(TAG, "管理员消息发送成功")
                                } else {
                                    addChatMessage("系统", "消息已成功发送给 $successCount 个用户")
                                }
                            }
                            successCount > 0 && failCount > 0 -> {
                                addChatMessage("系统", "消息已发送给 $successCount 个用户，$failCount 个失败\n${failMessages.joinToString("\n")}")
                            }
                            else -> {
                                addChatMessage("系统", "发送失败: ${failMessages.joinToString("\n")}")
                            }
                        }
                    }
                } else {
                    withContext(Dispatchers.Main) {
                        addChatMessage("系统", "无法连接到客服服务")
                    }
                }
                return@withContext
            }
            
            // 群组对话：通过WebSocket发送群组消息
            // 重要：如果有群组上下文，说明消息已经通过之前的performSendChatMessage()发送过了
            // 此时应该跳过群组消息处理，继续执行TopoClaw的逻辑（发送消息到API）
            val hasGroupContext = assistantGroupContext != null
            if (hasGroupContext) {
                // 有群组上下文，说明消息已经发送过了，跳过群组消息处理
                // 继续执行后续的TopoClaw逻辑（发送消息到API）
                Log.d(TAG, "========== performSendChatMessage: 检测到已有群组上下文，跳过群组消息处理，继续执行TopoClaw逻辑 ==========")
                Log.d(TAG, "performSendChatMessage: 有群组上下文，消息已发送，跳过群组消息处理，继续执行TopoClaw逻辑")
                Log.d(TAG, "performSendChatMessage: assistantGroupContext详情 - groupId=${assistantGroupContext?.groupId}, originalQuery=${assistantGroupContext?.originalQuery}")
                Log.d(TAG, "performSendChatMessage: 当前conversationId=${conversationId}，将继续执行TopoClaw逻辑（9215行之后）")
                // 不返回，继续执行后续的TopoClaw逻辑（9215行之后）
            } else if (conversationId?.startsWith("group_") == true || conversationId == ConversationListFragment.CONVERSATION_ID_GROUP) {
                // 只有在没有群组上下文的情况下，才进入群组消息发送逻辑
                
                // 如果是默认群组"好友群"，直接提示不可用
                if (conversationId == ConversationListFragment.CONVERSATION_ID_GROUP) {
                    withContext(Dispatchers.Main) {
                        addChatMessage("小助手", "默认群组\"好友群\"暂不可用，您可以邀请好友新建其他群组或加入由好友创建的群组来体验群组功能", isAnswer = true)
                    }
                    return@withContext
                }
                
                // 如果是其他群组，获取group_id
                val groupId = conversationId.removePrefix("group_")
                Log.d(TAG, "========== performSendChatMessage: 检测到群组对话 ==========")
                Log.d(TAG, "检测到群组对话，准备通过WebSocket发送群组消息: groupId=$groupId, query=$query")
                Log.d(TAG, "performSendChatMessage: 当前对话ID=$conversationId, assistantGroupContext=${if (assistantGroupContext != null) "存在(groupId=${assistantGroupContext?.groupId})" else "不存在"}")
                
                // 检测是否@了群组内的某个小助手（自动执行或自定义）
                val mentionedAssistantId = findMentionedGroupAssistantId(query)
                val isAssistantMentioned = mentionedAssistantId != null
                
                // 如果当前对话是小助手对话，但消息中没有@任何群组内小助手，且有群组上下文，应该恢复原始对话上下文
                if ((conversationId == ConversationListFragment.CONVERSATION_ID_ASSISTANT || CustomAssistantManager.isCustomAssistantId(conversationId)) &&
                    assistantGroupContext != null && 
                    findMentionedGroupAssistantId(query) == null) {
                    Log.d(TAG, "performSendChatMessage: 检测到残留的群组上下文，恢复原始对话上下文")
                    withContext(Dispatchers.Main) {
                        currentConversation = assistantGroupContext?.originalConversation
                        assistantGroupContext = null
                    }
                    // 重新获取conversationId和groupId
                    val restoredConversationId = currentConversation?.id
                    if (restoredConversationId?.startsWith("group_") == true || restoredConversationId == ConversationListFragment.CONVERSATION_ID_GROUP) {
                        val restoredGroupId = if (restoredConversationId == ConversationListFragment.CONVERSATION_ID_GROUP) {
                            val prefs = requireContext().getSharedPreferences("app_prefs", android.content.Context.MODE_PRIVATE)
                            prefs.getString("default_group_id", null) ?: run {
                                withContext(Dispatchers.Main) {
                                    addChatMessage("系统", "请先创建群组或选择具体群组")
                                }
                                return@withContext
                            }
                        } else {
                            restoredConversationId.removePrefix("group_")
                        }
                        // 继续发送普通群组消息
                        Log.d(TAG, "恢复上下文后，发送普通群组消息: $restoredGroupId")
                        val mainActivity = activity as? MainActivity
                        var webSocket = mainActivity?.getCustomerServiceWebSocket()
                        if (webSocket == null || !webSocket.isConnected()) {
                            val connectedWebSocket = ensureCustomerServiceWebSocketConnected()
                            if (connectedWebSocket != null) {
                                webSocket = connectedWebSocket
                            }
                        }
                        // 如果有图片，先保存并显示图片消息
                        // 注意：如果没有图片，文本消息已经在executeQueryInternal中添加了
                        if (selectedImageBase64 != null && selectedImageUri != null) {
                            val imageUri = selectedImageUri!!
                            val imagePath = withContext(Dispatchers.IO) {
                                saveImageToLocal(imageUri)
                            }
                            if (imagePath != null) {
                                // 图片保存成功，添加图片消息（包含文本和图片）
                                withContext(Dispatchers.Main) {
                                    addImageMessage(imagePath, query, sender = getSenderDisplayName())
                                }
                            } else {
                                // 图片保存失败，添加文本消息（如果没有图片，文本消息已经在executeQueryInternal中添加了）
                                // 这里需要添加，因为executeQueryInternal中有图片时不会添加文本消息
                                withContext(Dispatchers.Main) {
                                    addChatMessage(getSenderDisplayName(), if (query.isNotEmpty()) query else "[图片]")
                                }
                            }
                        } else if (selectedImageBase64 != null) {
                            // 只有Base64没有URI的情况，添加文本消息
                            withContext(Dispatchers.Main) {
                                addChatMessage(getSenderDisplayName(), if (query.isNotEmpty()) query else "[图片]")
                            }
                        }
                        // 如果没有图片，文本消息已经在executeQueryInternal中添加了，这里不需要再添加
                        
                        val finalWebSocket = mainActivity?.getCustomerServiceWebSocket()
                        if (finalWebSocket != null && finalWebSocket.isConnected()) {
                            // 发送普通群组消息，不自动添加@TopoClaw
                            val sentMessageType = if (selectedImageBase64 != null) "image" else "text"
                            val messageId = finalWebSocket.sendGroupMessage(restoredGroupId, query, selectedImageBase64)
                            markOwnGroupMessageSent(
                                groupId = restoredGroupId,
                                content = query,
                                messageType = sentMessageType,
                                messageId = messageId
                            )
                            // 清除图片选择状态
                            withContext(Dispatchers.Main) {
                                removeSelectedImage()
                            }
                        } else {
                            withContext(Dispatchers.Main) {
                                addChatMessage("系统", "无法连接到客服服务")
                            }
                        }
                        return@withContext
                    }
                }
                
                if (isAssistantMentioned) {
                    // 解析远程指令：若同时@了小助手和好友，则发给好友执行；若只@小助手则本地执行
                    val remoteCommand = parseRemoteCommand(query)
                    
                    if (remoteCommand != null) {
                        // 有@其他用户，需要远程执行
                        Log.d(TAG, "检测到远程指令: 目标用户=${remoteCommand.targetUsername}, 指令=${remoteCommand.command}")
                        
                        // 查找目标用户的IMEI
                        val targetImei = findImeiByUsername(remoteCommand.targetUsername, groupId)
                        if (targetImei == null) {
                            withContext(Dispatchers.Main) {
                                addChatMessage("系统", "未找到用户：${remoteCommand.targetUsername}")
                            }
                            return@withContext
                        }
                        
                        // 获取当前用户IMEI
                        val senderImei = ProfileManager.getOrGenerateImei(requireContext())
                        
                        // 如果目标是自己，直接本地执行
                        if (targetImei == senderImei) {
                            Log.d(TAG, "目标用户是自己，本地执行")
                            // 继续执行本地逻辑（下面的代码）
                        } else {
                            // 发送远程指令
                            // 先添加用户的消息到聊天界面（让发送者能看到自己发送的指令）
                            if (selectedImageBase64 != null && selectedImageUri != null) {
                                val imageUri = selectedImageUri!!
                                val imagePath = withContext(Dispatchers.IO) {
                                    saveImageToLocal(imageUri)
                                }
                                if (imagePath != null) {
                                    withContext(Dispatchers.Main) {
                                        addImageMessage(imagePath, query, sender = getSenderDisplayName())
                                    }
                                } else {
                                    withContext(Dispatchers.Main) {
                                        addChatMessage(getSenderDisplayName(), if (query.isNotEmpty()) query else "[图片]")
                                    }
                                }
                            } else if (selectedImageBase64 != null) {
                                withContext(Dispatchers.Main) {
                                    addChatMessage(getSenderDisplayName(), if (query.isNotEmpty()) query else "[图片]")
                                }
                            } else {
                                withContext(Dispatchers.Main) {
                                    addChatMessage(getSenderDisplayName(), query)
                                }
                            }
                            
                            val mainActivity = activity as? MainActivity
                            val webSocket = mainActivity?.getCustomerServiceWebSocket()
                            if (webSocket != null && webSocket.isConnected()) {
                                // 先发送群组消息（使用原始query，因为已经检测到@TopoClaw）
                                val sentMessageType = if (selectedImageBase64 != null) "image" else "text"
                                val messageId = webSocket.sendGroupMessage(groupId, query, selectedImageBase64)
                                markOwnGroupMessageSent(
                                    groupId = groupId,
                                    content = query,
                                    messageType = sentMessageType,
                                    messageId = messageId
                                )
                                
                                // 发送远程指令
                                webSocket.sendRemoteAssistantCommand(groupId, targetImei, remoteCommand.command, senderImei)
                                
                                withContext(Dispatchers.Main) {
                                    addChatMessage("系统", "已向@${remoteCommand.targetUsername}发送指令，等待执行...")
                                    // 清除图片选择状态
                                    removeSelectedImage()
                                }
                            } else {
                                withContext(Dispatchers.Main) {
                                    addChatMessage("系统", "无法连接到服务器")
                                }
                            }
                            return@withContext
                        }
                    }
                    
                    // 没有@其他用户或目标是自己，本地执行（原有逻辑）
                    Log.d(TAG, "检测到@TopoClaw，切换到TopoClaw模式执行 - groupId: $groupId, query: $query")
                    
                    // 重要：当检测到@小助手时，不会进入executeQueryInternal的群组分支，
                    // 所以需要在这里添加用户消息到聊天界面
                    if (selectedImageBase64 != null && selectedImageUri != null) {
                        val imageUri = selectedImageUri!!
                        val imagePath = withContext(Dispatchers.IO) {
                            saveImageToLocal(imageUri)
                        }
                        if (imagePath != null) {
                            // 图片保存成功，添加图片消息（包含文本和图片）
                            withContext(Dispatchers.Main) {
                                addImageMessage(imagePath, query, sender = getSenderDisplayName())
                            }
                        } else {
                            // 图片保存失败，添加文本消息
                            withContext(Dispatchers.Main) {
                                addChatMessage(getSenderDisplayName(), if (query.isNotEmpty()) query else "[图片]")
                            }
                        }
                    } else if (selectedImageBase64 != null) {
                        // 只有Base64没有URI的情况，添加文本消息
                        withContext(Dispatchers.Main) {
                            addChatMessage(getSenderDisplayName(), if (query.isNotEmpty()) query else "[图片]")
                        }
                    } else {
                        // 没有图片，添加文本消息
                        withContext(Dispatchers.Main) {
                            addChatMessage(getSenderDisplayName(), query)
                        }
                    }
                    
                    // 先发送群组消息（让其他成员看到，使用原始query）
                    val mainActivity = activity as? MainActivity
                    var webSocket = mainActivity?.getCustomerServiceWebSocket()
                    if (webSocket == null || !webSocket.isConnected()) {
                        val connectedWebSocket = ensureCustomerServiceWebSocketConnected()
                        if (connectedWebSocket != null) {
                            webSocket = connectedWebSocket
                        }
                    }
                    
                    val finalWebSocket = mainActivity?.getCustomerServiceWebSocket()
                    if (finalWebSocket != null && finalWebSocket.isConnected()) {
                        val currentImei = ProfileManager.getOrGenerateImei(requireContext())
                        Log.d(TAG, "========== 准备发送群组消息到WebSocket ==========")
                        Log.d(TAG, "发送群组消息: groupId=$groupId, query=$query, currentImei=$currentImei")
                        Log.d(TAG, "发送群组消息: assistantGroupContext=${if (assistantGroupContext != null) "存在" else "不存在"}")
                        val sentMessageType = if (selectedImageBase64 != null) "image" else "text"
                        val messageId = finalWebSocket.sendGroupMessage(groupId, query, selectedImageBase64)
                        markOwnGroupMessageSent(
                            groupId = groupId,
                            content = query,
                            messageType = sentMessageType,
                            messageId = messageId
                        )
                        Log.d(TAG, "========== 群组消息已发送到WebSocket ==========")
                        // 清除图片选择状态
                        withContext(Dispatchers.Main) {
                            removeSelectedImage()
                        }
                    } else {
                        Log.w(TAG, "WebSocket未连接，无法发送群组消息")
                    }
                    
                    // 重要：在切换对话上下文之前，确保用户消息已经保存到群组对话中
                    // 因为切换后，currentConversation会改变，后续的消息保存会使用新的对话ID
                    withContext(Dispatchers.Main) {
                        // 强制保存当前消息到群组对话（使用原始对话ID）
                        val originalConversationId = currentConversation?.id
                        if (originalConversationId != null) {
                            Log.d(TAG, "切换对话上下文前，强制保存消息到群组对话: $originalConversationId")
                            saveChatMessages(sync = true) // 同步保存，确保消息被保存到正确的对话
                        }
                    }
                    
                    // 临时切换到被 @ 的小助手对话上下文（TopoClaw或自定义小助手），然后调用executeQueryInternal
                    val originalConversation = currentConversation
                    Log.d(TAG, "保存原始对话上下文: ${originalConversation?.id}")
                    val (assistantConvId: String, assistantConvName: String) = when (mentionedAssistantId) {
                        ConversationListFragment.CONVERSATION_ID_ASSISTANT ->
                            ConversationListFragment.CONVERSATION_ID_ASSISTANT to getString(R.string.auto_execute_assistant)
                        else -> {
                            val custom = CustomAssistantManager.getById(requireContext(), mentionedAssistantId ?: "")
                            // 群里 @ 到陌生小助手时，不能回退到本地 TopoClaw，否则会串到自己的同名助手。
                            val fallbackId = (mentionedAssistantId ?: "").ifBlank { ConversationListFragment.CONVERSATION_ID_ASSISTANT }
                            (custom?.id ?: fallbackId) to (custom?.name ?: fallbackId)
                        }
                    }
                    val assistantConversation = Conversation(
                        id = assistantConvId,
                        name = assistantConvName,
                        lastMessage = query,
                        lastMessageTime = System.currentTimeMillis()
                    )
                    
                    // 临时切换对话上下文
                    currentConversation = assistantConversation
                    
                    // 获取当前用户IMEI（发起任务的用户）
                    val senderImei = ProfileManager.getOrGenerateImei(requireContext())
                    
                    // 保存群组ID和原始对话，用于后续发送结果回群组（使用原始query）
                    assistantGroupContext = AssistantGroupContext(groupId, originalConversation, query, senderImei)
                    Log.d(TAG, "已设置群组上下文 - groupId: $groupId, originalConversationId: ${originalConversation?.id}, originalQuery: $query, senderImei: $senderImei")
                    
                    // 在主线程调用executeQueryInternal（它会处理权限检测和执行流程，使用原始query）
                    withContext(Dispatchers.Main) {
                        Log.d(TAG, "========== 准备调用executeQueryInternal ==========")
                        Log.d(TAG, "调用executeQueryInternal: query=$query, currentConversation=${currentConversation?.id}, assistantGroupContext=${if (assistantGroupContext != null) "存在(groupId=${assistantGroupContext?.groupId})" else "不存在"}")
                        executeQueryInternal(query)
                        Log.d(TAG, "========== executeQueryInternal调用完成 ==========")
                    }
                    
                    return@withContext
                }
                
                // 群组管理小助手的调度由服务端通过 WebSocket 中继完成（TopoMobileRelayHub），
                // 移动端只需发送普通群组消息，服务端会自动分发给 GroupManager 等群组助手。
                
                val mainActivity = activity as? MainActivity
                var webSocket = mainActivity?.getCustomerServiceWebSocket()
                Log.d(TAG, "WebSocket实例: ${webSocket != null}, 连接状态: ${webSocket?.isConnected()}")
                
                // 如果WebSocket未连接，尝试重新初始化并连接
                if (webSocket == null || !webSocket.isConnected()) {
                    Log.d(TAG, "WebSocket未连接，尝试重新初始化并连接")
                    val connectedWebSocket = ensureCustomerServiceWebSocketConnected()
                    if (connectedWebSocket == null) {
                        Log.e(TAG, "WebSocket连接失败")
                        withContext(Dispatchers.Main) {
                            addChatMessage("系统", "无法连接到服务器，请检查网络连接或稍后重试")
                        }
                        return@withContext
                    }
                    webSocket = connectedWebSocket
                }
                
                // 如果有图片，先保存并显示图片消息
                if (selectedImageBase64 != null && selectedImageUri != null) {
                    val imageUri = selectedImageUri!!
                    val imagePath = withContext(Dispatchers.IO) {
                        saveImageToLocal(imageUri)
                    }
                    if (imagePath != null) {
                        // 图片保存成功，添加图片消息（包含文本和图片）
                        withContext(Dispatchers.Main) {
                            addImageMessage(imagePath, query, sender = getSenderDisplayName())
                        }
                    } else {
                        // 图片保存失败，添加文本消息
                        withContext(Dispatchers.Main) {
                            addChatMessage(getSenderDisplayName(), if (query.isNotEmpty()) query else "[图片]")
                        }
                    }
                } else if (selectedImageBase64 != null) {
                    // 只有Base64没有URI的情况，添加文本消息
                    withContext(Dispatchers.Main) {
                        addChatMessage(getSenderDisplayName(), if (query.isNotEmpty()) query else "[图片]")
                    }
                } else {
                    // 没有图片，添加文本消息
                    withContext(Dispatchers.Main) {
                        addChatMessage(getSenderDisplayName(), query)
                    }
                }
                
                // 再次检查连接状态并发送消息
                val finalWebSocket = mainActivity?.getCustomerServiceWebSocket()
                if (finalWebSocket != null && finalWebSocket.isConnected()) {
                    // 发送普通群组消息，不自动添加@TopoClaw
                    Log.d(TAG, "WebSocket已连接，开始发送群组消息: $query")
                    val sentMessageType = if (selectedImageBase64 != null) "image" else "text"
                    val messageId = finalWebSocket.sendGroupMessage(groupId, query, selectedImageBase64)
                    markOwnGroupMessageSent(
                        groupId = groupId,
                        content = query,
                        messageType = sentMessageType,
                        messageId = messageId
                    )
                    // 清除图片选择状态
                    withContext(Dispatchers.Main) {
                        removeSelectedImage()
                    }
                } else {
                    withContext(Dispatchers.Main) {
                        addChatMessage("系统", "WebSocket连接失败，无法发送消息")
                    }
                }
                return@withContext
            }
            
            // 好友对话：通过WebSocket发送好友消息
            if (conversationId?.startsWith("friend_") == true) {
                val friendImei = conversationId.removePrefix("friend_")
                Log.d(TAG, "检测到好友对话，准备通过WebSocket发送消息给好友: $friendImei")
                
                // 检查是否为好友关系
                val isFriend = FriendManager.isFriend(requireContext(), friendImei)
                if (!isFriend) {
                    withContext(Dispatchers.Main) {
                        addChatMessage("系统", "消息发送失败，对方不是您的好友")
                    }
                    return@withContext
                }
                
                // 如果有图片，先保存并显示图片消息
                if (selectedImageBase64 != null && selectedImageUri != null) {
                    val imageUri = selectedImageUri!!
                    val imagePath = withContext(Dispatchers.IO) {
                        saveImageToLocal(imageUri)
                    }
                    if (imagePath != null) {
                        // 图片保存成功，添加图片消息（包含文本和图片）
                        withContext(Dispatchers.Main) {
                            addImageMessage(imagePath, query)
                        }
                    } else {
                        // 图片保存失败，添加文本消息
                        withContext(Dispatchers.Main) {
                            addChatMessage("我", if (query.isNotEmpty()) query else "[图片]")
                        }
                    }
                } else if (selectedImageBase64 != null) {
                    // 只有Base64没有URI的情况，添加文本消息
                    withContext(Dispatchers.Main) {
                        addChatMessage("我", if (query.isNotEmpty()) query else "[图片]")
                    }
                } else {
                    // 没有图片，添加文本消息
                    withContext(Dispatchers.Main) {
                        addChatMessage("我", query)
                    }
                }
                
                val mainActivity = activity as? MainActivity
                var webSocket = mainActivity?.getCustomerServiceWebSocket()
                Log.d(TAG, "WebSocket实例: ${webSocket != null}, 连接状态: ${webSocket?.isConnected()}")
                
                // 如果WebSocket未连接，尝试重新初始化并连接
                if (webSocket == null || !webSocket.isConnected()) {
                    Log.d(TAG, "WebSocket未连接，尝试重新初始化并连接")
                    val connectedWebSocket = ensureCustomerServiceWebSocketConnected()
                    if (connectedWebSocket == null) {
                        Log.e(TAG, "WebSocket连接失败")
                        withContext(Dispatchers.Main) {
                            addChatMessage("系统", "无法连接到服务器，请检查网络连接或稍后重试")
                        }
                        return@withContext
                    }
                    webSocket = connectedWebSocket
                }
                
                // 再次检查连接状态并发送消息
                val finalWebSocket = mainActivity?.getCustomerServiceWebSocket()
                if (finalWebSocket != null && finalWebSocket.isConnected()) {
                    Log.d(TAG, "WebSocket已连接，开始发送好友消息: $query")
                    finalWebSocket.sendFriendMessage(friendImei, query, selectedImageBase64)
                    // 清除图片选择状态
                    withContext(Dispatchers.Main) {
                        removeSelectedImage()
                    }
                } else {
                    withContext(Dispatchers.Main) {
                        addChatMessage("系统", "WebSocket连接失败，无法发送消息")
                    }
                }
                return@withContext
            }
            
            if (conversationId == ConversationListFragment.CONVERSATION_ID_ME) {
                Log.d(TAG, "检测到端云互发对话，准备通过WebSocket发送消息")
                if (selectedImageBase64 != null && selectedImageUri != null) {
                    val imageUri = selectedImageUri!!
                    val imagePath = withContext(Dispatchers.IO) {
                        saveImageToLocal(imageUri)
                    }
                    withContext(Dispatchers.Main) {
                        if (imagePath != null) {
                            addImageMessage(imagePath, query, sender = getSenderDisplayName())
                        } else {
                            addChatMessage(getSenderDisplayName(), if (query.isNotEmpty()) query else "[图片]")
                        }
                    }
                } else if (selectedImageBase64 != null) {
                    val imagePath = withContext(Dispatchers.IO) {
                        saveImageFromBase64(selectedImageBase64!!)
                    }
                    withContext(Dispatchers.Main) {
                        if (imagePath != null) {
                            addImageMessage(imagePath, query, sender = getSenderDisplayName())
                        } else {
                            addChatMessage(getSenderDisplayName(), if (query.isNotEmpty()) query else "[图片]")
                        }
                    }
                } else {
                    withContext(Dispatchers.Main) {
                        addChatMessage(getSenderDisplayName(), query)
                    }
                }
                val mainActivity = activity as? MainActivity
                var webSocket = mainActivity?.getCustomerServiceWebSocket()
                if (webSocket == null || !webSocket.isConnected()) {
                    val connectedWebSocket = ensureCustomerServiceWebSocketConnected()
                    if (connectedWebSocket == null) {
                        withContext(Dispatchers.Main) {
                            addChatMessage("系统", "无法连接到服务器，请检查网络或稍后重试")
                        }
                        return@withContext
                    }
                    webSocket = connectedWebSocket
                }
                val finalWebSocket = mainActivity?.getCustomerServiceWebSocket()
                if (finalWebSocket != null && finalWebSocket.isConnected()) {
                    val msgType = if (selectedImageBase64 != null) "image" else "text"
                    finalWebSocket.sendCrossDeviceMessage(query, msgType, selectedImageBase64, null)
                    withContext(Dispatchers.Main) { removeSelectedImage() }
                } else {
                    withContext(Dispatchers.Main) {
                        addChatMessage("系统", "连接失败，无法发送消息")
                    }
                }
                return@withContext
            }
            
            // 自定义小助手：强制走中转到 PC 执行（不再手机端直连）
            val customAssistant = if (conversationId != null && CustomAssistantManager.isCustomAssistantId(conversationId)) {
                CustomAssistantManager.getById(requireContext(), conversationId)
            } else null
            if (customAssistant != null) {
                Log.d(TAG, "检测到自定义小助手: ${customAssistant.name}，强制通过中转发送到 PC 执行")
                withContext(Dispatchers.Main) {
                    isCustomAssistantProcessing = true
                    updateButtonVisibility()
                }

                // 仅手机端执行的自定义小助手：先回到 Android 桌面，再截图发送
                if (customAssistant.hasExecutionMobile() && !customAssistant.hasChat() && shouldGoHome) {
                    Log.d(TAG, "自定义小助手(仅手机端执行)：先回到 Android 桌面")
                    withContext(Dispatchers.Main) {
                        val accessibilityService = MyAccessibilityService.getInstance()
                        if (accessibilityService != null) {
                            accessibilityService.goHome()
                            Log.d(TAG, "已执行回退到 Android 桌面操作")
                        } else {
                            Log.w(TAG, "无障碍服务未就绪，无法回退到桌面")
                        }
                    }
                    delay(1000)
                }

                val imageBase64ForPc = selectedImageBase64
                val hasImage = imageBase64ForPc != null
                val messageText = if (query.isNotBlank()) query else if (hasImage) "[图片]" else ""
                if (messageText.isEmpty()) {
                    Log.w(TAG, "自定义小助手中转: 消息为空，跳过发送")
                    return@withContext
                }
                val outboundImages = imageBase64ForPc?.let { listOf(it) }
                // 用户消息已在 executeQueryInternal 中添加，此处不再重复添加。
                withContext(Dispatchers.Main) {
                    removeSelectedImage()
                    // 多 session：首条消息时更新 session 标题为 query，并同步到云端
                    if (customAssistant.multiSession) {
                        val sid = currentSessionIdForMultiSession ?: return@withContext
                        val convId = conversationId ?: customAssistant.id
                        val sessions = SessionStorage.loadSessions(requireContext(), convId)
                        val session = sessions.find { it.id == sid }
                        if (session != null && session.title == getString(R.string.session_new_dialog)) {
                            val newTitle = messageText.take(30).let { if (it.length < messageText.length) "$it..." else it }
                            SessionStorage.updateSessionTitle(requireContext(), convId, sid, newTitle)
                            refreshDrawerSessions()
                            mainScope.launch(Dispatchers.IO) {
                                try {
                                    if (customAssistant.baseUrl.isBlank()) return@launch
                                    val prefs = requireContext().getSharedPreferences("app_prefs", Context.MODE_PRIVATE)
                                    val csUrl = prefs.getString("customer_service_url", ServiceUrlConfig.DEFAULT_CUSTOMER_SERVICE_URL) ?: ServiceUrlConfig.DEFAULT_CUSTOMER_SERVICE_URL
                                    CustomerServiceNetwork.initialize(csUrl)
                                    val api = CustomerServiceNetwork.getApiService() ?: return@launch
                                    val imei = ProfileManager.getOrGenerateImei(requireContext())
                                    val localList = SessionStorage.loadSessions(requireContext(), convId)
                                    val request = SessionSyncRequest(imei = imei, conversation_id = convId, sessions = localList.map { SessionItem(it.id, it.title, it.createdAt) }, base_url = customAssistant.baseUrl)
                                    val resp = api.syncSessions(request)
                                    if (resp.isSuccessful && resp.body()?.success == true) {
                                        Log.d(TAG, "[Session] 首条消息后 sync 标题成功: sessionId=$sid, title=$newTitle")
                                    }
                                } catch (e: Exception) {
                                    Log.w(TAG, "首条消息后 sync 标题失败: ${e.message}")
                                }
                            }
                        }
                    }
                }
                val imei = ProfileManager.getOrGenerateImei(requireContext())
                // 手机端用户消息实时同步到 customer_service，PC 可收到 assistant_user_message
                val convIdForSync = if (customAssistant.multiSession) {
                    val sid = currentSessionIdForMultiSession
                    if (sid != null) "${conversationId ?: customAssistant.id}__$sid" else (conversationId ?: customAssistant.id)
                } else {
                    conversationId ?: customAssistant.id
                }
                (activity as? MainActivity)?.getCustomerServiceWebSocket()?.sendAssistantUserMessage(
                    content = messageText,
                    messageId = null,
                    conversationId = convIdForSync,
                    fileBase64 = imageBase64ForPc,
                    fileName = if (imageBase64ForPc != null) "图片.png" else null
                )
                withContext(Dispatchers.Main) {
                    showAssistantThinkingIndicator(
                        sender = customAssistant.name,
                        assistantId = customAssistant.id,
                        avatarBase64 = customAssistant.avatar
                    )
                }

                // 统一走 customer_service 中转到 PC，不在 APK 端直连 custom assistant baseUrl。

                val ws = (activity as? MainActivity)?.getCustomerServiceWebSocket()
                val connectedWs = if (ws != null && ws.isConnected()) ws else ensureCustomerServiceWebSocketConnected()
                if (connectedWs != null && connectedWs.isConnected()) {
                    val msgId = java.util.UUID.randomUUID().toString()
                    connectedWs.sendMobileExecutePcCommand(
                        query = messageText,
                        assistantBaseUrl = customAssistant.baseUrl,
                        conversationId = conversationId ?: customAssistant.id,
                        messageId = msgId,
                        chatSummary = messageText.take(80),
                        imageBase64 = imageBase64ForPc,
                        imageName = if (imageBase64ForPc != null) "图片.png" else null
                    )
                    Log.d(TAG, "自定义小助手中转消息已发送, msgId=$msgId")
                } else {
                    withContext(Dispatchers.Main) {
                        isCustomAssistantProcessing = false
                        updateButtonVisibility()
                        addChatMessage("系统", "连接失败，请确保电脑端已打开并保持连接", clearThinking = true)
                    }
                }
                return@withContext
            }
            
            // 聊天小助手：使用 WebSocket /ws 接口
            if (conversationId == ConversationListFragment.CONVERSATION_ID_CHAT_ASSISTANT) {
                Log.d(TAG, "检测到聊天小助手对话，使用 WebSocket 发送消息")
                
                val hasImage = selectedImageBase64 != null
                val messageText = if (query.isNotBlank()) query else if (hasImage) "[图片]" else ""
                if (messageText.isEmpty()) {
                    Log.w(TAG, "聊天小助手: 消息为空，跳过发送")
                    return@withContext
                }
                
                // 添加用户消息到聊天界面
                // 用户消息已在 executeQueryInternal 中添加，此处不再重复添加
                withContext(Dispatchers.Main) {
                    removeSelectedImage()
                }
                
                val baseUrl = getServerUrlForConversation()
                val imei = ProfileManager.getOrGenerateImei(requireContext())
                val threadId = Uuid5Util.chatAssistantThreadId(imei)
                try {
                    val body = ChatWebSocketPool.sendChat(
                        baseUrl = baseUrl,
                        threadId = threadId,
                        message = messageText,
                        images = null
                    )
                    val reply = body.response.takeIf { it.isNotBlank() } ?: "收到空回复"
                    withContext(Dispatchers.Main) {
                        addChatMessage("聊天小助手", reply, isAnswer = true)
                    }
                    Log.d(TAG, "聊天小助手回复成功")
                } catch (e: Exception) {
                    Log.e(TAG, "聊天小助手请求异常: ${e.message}", e)
                    withContext(Dispatchers.Main) {
                        addChatMessage("系统", "请求异常: ${e.message}")
                    }
                }
                return@withContext
            }
            
            if (conversationId == ConversationListFragment.CONVERSATION_ID_CUSTOMER_SERVICE) {
                Log.d(TAG, "检测到人工客服对话，准备通过WebSocket发送消息")
                
                // 添加用户消息到聊天界面
                withContext(Dispatchers.Main) {
                    addChatMessage("我", query)
                }
                
                val mainActivity = activity as? MainActivity
                var webSocket = mainActivity?.getCustomerServiceWebSocket()
                Log.d(TAG, "WebSocket实例: ${webSocket != null}, 连接状态: ${webSocket?.isConnected()}")
                
                // 如果WebSocket未连接，尝试重新初始化并连接
                if (webSocket == null || !webSocket.isConnected()) {
                    Log.d(TAG, "WebSocket未连接，尝试重新初始化并连接")
                    val connectedWebSocket = ensureCustomerServiceWebSocketConnected()
                    if (connectedWebSocket == null) {
                        Log.e(TAG, "WebSocket连接失败")
                        withContext(Dispatchers.Main) {
                            addChatMessage("系统", "无法连接到人工客服服务，请检查服务地址配置或稍后重试")
                        }
                        return@withContext
                    }
                    webSocket = connectedWebSocket
                }
                
                // 再次检查连接状态并发送消息
                val finalWebSocket = mainActivity?.getCustomerServiceWebSocket()
                if (finalWebSocket != null && finalWebSocket.isConnected()) {
                    Log.d(TAG, "WebSocket已连接，开始发送消息: $query")
                    finalWebSocket.sendMessage(query)
                    Log.d(TAG, "已通过WebSocket发送消息给人工客服: $query")
                    return@withContext
                } else {
                    Log.w(TAG, "WebSocket仍未连接，无法发送消息给人工客服")
                    Log.w(TAG, "  - webSocket实例: ${finalWebSocket != null}")
                    Log.w(TAG, "  - 连接状态: ${finalWebSocket?.isConnected()}")
                    withContext(Dispatchers.Main) {
                        addChatMessage("系统", "人工客服连接未建立，请检查服务地址配置或稍后重试")
                    }
                    return@withContext
                }
            }
            
            // 标记是否是第一次发送（需要等待规划结果）
            // 第一次发送：任务中的第一次发送（isFirstSendInTask为true）且userResponse为null（不是call_user后的回复）
            Log.d(TAG, "========== performSendChatMessage: 到达TopoClaw逻辑入口（9215行之后） ==========")
            Log.d(TAG, "performSendChatMessage: conversationId=$conversationId, hasGroupContext=$hasGroupContext, query=$query")
            // 端云同步：仅在新发起任务或用户回复时同步用户消息，避免任务循环中重复上报
            val isFirstSend = isFirstSendInTask && userResponse == null
            val shouldSyncUserMessage = isFirstSend || userResponse != null
            if (conversationId == ConversationListFragment.CONVERSATION_ID_ASSISTANT && !hasGroupContext && shouldSyncUserMessage) {
                // PC 执行时使用后端下发的 messageId，便于 PC 端按 id 去重；否则自生成
                val msgId = assistantPcExecuteContext?.messageId ?: java.util.UUID.randomUUID().toString()
                (activity as? MainActivity)?.getCustomerServiceWebSocket()?.sendAssistantUserMessage(query, msgId)
            }
            
            // 第一次发送时不回退到home页面，等收到规划结果后再决定
            // 只有call_user后的用户回复或后续循环时才回退到home页面
            // 清除后台应用在收到needs_screen_operation时执行，不在performSendChatMessage中执行
            if (shouldGoHome) {
                // 如果是call_user后的用户回复（userResponse不为null），只回退到home
                if (userResponse != null) {
                    Log.d(TAG, "call_user后的用户回复，只回退到home页面")
                    withContext(Dispatchers.Main) {
                        val accessibilityService = MyAccessibilityService.getInstance()
                        if (accessibilityService != null) {
                            accessibilityService.goHome()
                            Log.d(TAG, "已执行回退到home操作")
                        }
                    }
                    // 等待页面切换完成
                    delay(800)
                } else {
                    // 后续循环时，直接返回主页（清除后台应用在收到needs_screen_operation时执行）
                    Log.d(TAG, "后续循环，回退到home页面")
                    withContext(Dispatchers.Main) {
                        val accessibilityService = MyAccessibilityService.getInstance()
                        if (accessibilityService != null) {
                            accessibilityService.goHome()
                            Log.d(TAG, "已执行回退到home操作")
                        } else {
                            Log.w(TAG, "无障碍服务未就绪，无法回退到home")
                        }
                    }
                    // 等待页面切换完成
                    delay(800)
                }
            } else {
                // 后续循环时，等待一小段时间确保界面稳定
                delay(10)
            }
            
            // 如果有用户选择的图片，优先使用用户选择的图片；否则根据情况获取屏幕截图或发送空图片
            var userImageBase64: String = if (selectedImageBase64 != null) {
                // 用户选择了图片，使用用户选择的图片（不管shouldGoHome的值）
                Log.d(TAG, "使用用户选择的图片，Base64长度: ${selectedImageBase64!!.length}")
                
                // 记录用户上传图片的原始尺寸（从预览bitmap获取）
                selectedImageBitmap?.let {
                    currentOriginalImageWidth = it.width
                    currentOriginalImageHeight = it.height
                    Log.d(TAG, "用户上传图片原始尺寸: ${currentOriginalImageWidth}x${currentOriginalImageHeight}")
                }
                
                val imageBase64 = selectedImageBase64!!
                // 清除选择的图片（只发送一次）
                selectedImageBase64 = null
                selectedImageUri = null
                selectedImageBitmap?.recycle()
                selectedImageBitmap = null
                withContext(Dispatchers.Main) {
                    // 隐藏预览区域
                    binding.llImagePreview.visibility = android.view.View.GONE
                    binding.ivSelectedImage.setImageBitmap(null)
                    updateButtonVisibility()
                }
                imageBase64
            } else if (isFirstSend && !isCustomAssistantExecutionOnly()) {
                // 第一次发送且没有用户选择的图片，先不发送截图，等收到规划结果后再决定
                // 自定义小助手（仅手机端执行）需始终带截图，因部分后端不支持无截图首包
                Log.d(TAG, "第一次发送且没有用户图片，先发送请求（不包含截图），等待规划结果")
                ""  // 空字符串，表示不发送截图
            } else {
                // 后续循环时，获取屏幕截图
                // 如果是call_user后的用户回复，不获取新截图，使用空字符串（云侧会使用上一张截图）
                if (userResponse != null) {
                    Log.d(TAG, "call_user后的用户回复，不获取新截图，使用空字符串（云侧会使用上一张截图）")
                    ""  // 空字符串，表示不发送新截图
                } else {
                    // 需要获取截图，但这里不能直接return，所以先返回空字符串，然后在后面处理
                    // 实际上，我们需要在if-else表达式外处理截图获取
                    ""
                }
            }
            
            // 如果userImageBase64为空且（不是第一次发送 或 是仅手机端执行的自定义小助手）且不是call_user回复，需要获取截图
            // 仅手机端执行的自定义小助手第一次发送也需截图，因后端（如 UnifiedAssistant）要求
            // 用于保存与截图同步的包名和类名
            var screenshotPackageName: String? = null
            var screenshotClassName: String? = null

            if (userImageBase64.isEmpty() && (!isFirstSend || isCustomAssistantExecutionOnly()) && userResponse == null && selectedImageBase64 == null) {
                val chatService = ChatScreenshotService.getInstance()
                val bitmap = chatService?.captureScreenshot()
            
                if (bitmap == null) {
                    // 如果是 wait 后的重试，不进入截图失败逻辑，直接发送到云侧
                    if (isWaitRetry) {
                        Log.w(TAG, "[wait后] 重新获取截图失败，跳过截图失败逻辑，直接发送到云侧")
                        isWaitRetry = false
                        consecutiveWaitCount = 0
                        // 使用空截图发送到云侧
                        userImageBase64 = ""
                        // 继续后续流程
                        // 但由于没有截图，我们需要特殊处理
                        // 实际上，这里应该直接返回，让外层处理
                        // 但由于逻辑复杂，我们重置状态后继续
                        return@withContext
                    }
                    
                    screenshotFailCount++
                    Log.w(TAG, "截图失败，重试计数: $screenshotFailCount/$maxScreenshotFailRetries")
                    
                    if (screenshotFailCount >= maxScreenshotFailRetries) {
                        // 连续三次截图失败，停止任务
                        Log.e(TAG, "连续三次截图失败，停止任务")
                        withContext(Dispatchers.Main) {
                            addChatMessage("小助手", "截图失败，请至服务页面确定已授权截图权限")
                        }
                        stopTask()
                        return@withContext
                    } else {
                        // 未达到最大重试次数，继续重试
                        Log.w(TAG, "截图失败，继续重试...")
                        withContext(Dispatchers.Main) {
                            addChatMessage("小助手", "截图失败，继续重试...")
                        }
                        if (isTaskRunning) {
                            delay(2000)
                            continueTaskLoop()
                        }
                        return@withContext
                    }
                }
                
                // 截图成功，重置 wait 重试标志
                isWaitRetry = false
                
                // 截图成功，重置失败计数和 wait 重试标志
                screenshotFailCount = 0
                isWaitRetry = false
                
                // 在获取截图后立即获取包名和类名，确保与截图同步
                val (pkgName, clsName) = MyAccessibilityService.getCurrentActivityInfo()
                screenshotPackageName = pkgName
                screenshotClassName = clsName
                Log.d(TAG, "获取截图后立即获取包名: $pkgName, 类名: $clsName")
                
                // 记录原始图片尺寸（压缩前）
                val imageWidth = bitmap.width
                val imageHeight = bitmap.height
                currentOriginalImageWidth = imageWidth
                currentOriginalImageHeight = imageHeight
                
                val cr = ScreenshotCompressionPrefs.getRatio(requireContext())
                Log.d(TAG, "原始图片尺寸: ${imageWidth}x${imageHeight}，压缩后尺寸: ${(imageWidth * cr).toInt()}x${(imageHeight * cr).toInt()}")
                withContext(Dispatchers.Main) {
                    (activity as? MainActivity)?.addLog("原始图片尺寸: ${imageWidth}x${imageHeight}")
                }
                
                // ========== 端侧异常检测 ==========
                val (shouldSendToCloud, isWait) = processScreenshotWithAnomalyDetection(bitmap)
                
                if (!shouldSendToCloud) {
                    if (isWait) {
                        // wait情况：等待已经在 processScreenshotWithAnomalyDetection 内部完成（2秒）
                        // wait情况下，等待后重新获取截图并检测
                        // 如果重新获取截图失败，直接发送到云侧，不进入截图失败逻辑
                        Log.i(TAG, "[端侧异常检测] wait情况，等待后重新获取截图并检测")
                        bitmap.recycle()
                        // 设置标志位，标记这是 wait 后的重试
                        isWaitRetry = true
                        if (isTaskRunning) {
                            delay(1000)  // 额外等待1秒（总共等待3秒）
                            // 重新获取截图，如果失败，直接发送到云侧
                            val chatService = ChatScreenshotService.getInstance()
                            val newBitmap = chatService?.captureScreenshot()
                            if (newBitmap != null) {
                                // 重新获取截图成功，继续检测
                                isWaitRetry = false
                                val (shouldSend, isWaitAgain) = processScreenshotWithAnomalyDetection(newBitmap)
                                if (shouldSend) {
                                    // 需要发送到云侧，继续后续流程
                                    // 重新设置 userImageBase64
                                    val screenshotBase64 = screenshotBitmapToBase64(newBitmap)
                                    newBitmap.recycle()
                                    // 继续发送流程（这里需要重新进入发送逻辑）
                                    // 但由于逻辑复杂，还是调用 continueTaskLoop
                                    continueTaskLoop()
                                } else {
                                    // 不应该再 wait（因为已经 wait 过一次了），或者 call_user
                                    newBitmap.recycle()
                                    if (isWaitAgain) {
                                        // 不应该出现这种情况，因为最多 wait 1 次
                                        Log.w(TAG, "[wait后] 检测到再次 wait，直接发送到云侧")
                                        continueTaskLoop()
                                    } else {
                                        // call_user，已经处理
                                        return@withContext
                                    }
                                }
                            } else {
                                // wait 后重新获取截图失败，直接发送到云侧，不进入截图失败逻辑
                                Log.w(TAG, "[wait后] 重新获取截图失败，直接发送到云侧（不进入截图失败逻辑）")
                                isWaitRetry = false
                                // 重置 wait 计数，避免影响后续
                                consecutiveWaitCount = 0
                                // 直接发送到云侧（使用空截图，让云侧处理）
                                // 但由于没有截图，我们需要调用 continueTaskLoop，但需要确保不会再次进入 wait
                                // 实际上，由于 consecutiveWaitCount 已重置，下次检测不会再次 wait
                                continueTaskLoop()
                            }
                        }
                        return@withContext
                    } else {
                        // call_user情况：异常已在端侧处理，不发送到云侧，等待后重新截图
                        Log.i(TAG, "[端侧异常检测] call_user已处理，跳过本次云侧请求，等待后重新截图")
                        bitmap.recycle()
                        // 如果open失败，不继续任务循环，等待用户点击下载许可弹窗
                        if (isOpenFailed) {
                            Log.d(TAG, "[端侧异常检测] open失败，不继续任务循环，等待用户点击下载许可弹窗")
                            return@withContext
                        }
                        if (isTaskRunning) {
                            delay(1000)
                            continueTaskLoop()
                        }
                        return@withContext
                    }
                }
                // ===================================
                
                // 检查是否正在等待输入法切换
                if (MyAccessibilityService.isWaitingForIMESwitch()) {
                    Log.d(TAG, "[发送请求前检查] 正在等待输入法切换，跳过本次请求")
                    bitmap.recycle()
                    // 延迟后重新检查
                    delay(2000)
                    continueTaskLoop()
                    return@withContext
                }
                
                // 检查open失败标志和弹窗显示状态，如果open失败或弹窗正在显示，不发送请求，等待用户点击下载许可弹窗
                if (isOpenFailed || AppInstallConfirmOverlayManager.isDialogShowing()) {
                    Log.d(TAG, "[发送请求前检查] open失败或弹窗正在显示，不发送请求，等待用户点击下载许可弹窗")
                    bitmap.recycle()
                    return@withContext
                }
                
                // 转换为Base64（会自动压缩到40%）
                // 注意：任务循环中的截图只用于发送给云侧分析，不保存到相册
                // 只有用户明确要求截图时（通过screenshot动作）才会保存到相册
                userImageBase64 = screenshotBitmapToBase64(bitmap).also { bitmap.recycle() }
                
                // 如果"端侧变化检测"开关打开，异步延迟1s截medium图（不阻塞正常流程）
                if (sendBeforeActionImageEnabled) {
                    // 清空之前的medium截图（如果有）
                    mediumScreenshotBase64 = null
                    // 异步延迟1s截medium图
                    mainScope.launch(Dispatchers.IO) {
                        try {
                            delay(1000)  // 延迟1秒
                            // 检查任务是否还在运行，避免无效截图
                            if (!isTaskRunning) {
                                Log.d(TAG, "[medium截图] 任务已停止，取消medium截图")
                                return@launch
                            }
                            val chatService = ChatScreenshotService.getInstance()
                            val mediumBitmap = chatService?.captureScreenshot()
                            if (mediumBitmap != null) {
                                Log.d(TAG, "[medium截图] medium截图获取成功")
                                val mediumBase64 = screenshotBitmapToBase64(mediumBitmap).also { 
                                    mediumBitmap.recycle() 
                                }
                                // 清理Base64字符串
                                val cleanMediumBase64 = mediumBase64.trim().replace("\n", "").replace("\r", "").replace(" ", "")
                                // 存储medium截图（仅在任务仍在运行时）
                                if (isTaskRunning) {
                                    mediumScreenshotBase64 = cleanMediumBase64
                                    Log.d(TAG, "[medium截图] medium截图已存储，长度: ${cleanMediumBase64.length}")
                                } else {
                                    Log.d(TAG, "[medium截图] 任务已停止，不存储medium截图")
                                }
                            } else {
                                Log.w(TAG, "[medium截图] medium截图获取失败")
                            }
                        } catch (e: Exception) {
                            Log.e(TAG, "[medium截图] medium截图异常: ${e.message}", e)
                        }
                    }
                }
                
                // 截图完成后，显示之前保存的reasoning
                pendingReasoning?.let { reasoning ->
                    val context = this@ChatFragment.context
                    if (context != null) {
                        withContext(Dispatchers.Main) {
                            ReasoningOverlayManager.show(context, reasoning)
                        }
                        // 显示后清空pendingReasoning
                        pendingReasoning = null
                        Log.d(TAG, "截图完成，已显示reasoning悬浮窗")
                    }
                }
            }
            
            // 如果是第一次发送，需要特殊处理（提前return）
            // 注意：如果userImageBase64不为空（用户选择了图片），应该发送图片，不应该进入这个分支
            if (isFirstSend && userImageBase64.isEmpty()) {
                // 第一次发送且没有用户选择的图片，先不发送截图，等收到规划结果后再决定
                Log.d(TAG, "第一次发送且没有用户图片，先发送请求（不包含截图），等待规划结果")
                val userImageBase64 = ""  // 空字符串，表示不发送截图
                
                // 清理Base64字符串（空字符串）
                val cleanBase64 = ""
                val urlEncodedBase64 = ""
                
                // 确保使用当前对话对应的服务地址
                ensureNetworkServiceInitialized()
                
                // 发送请求（不包含图片）
                val apiService = NetworkService.getApiService()
                if (apiService == null) {
                    Log.w(TAG, "ApiService未初始化，继续重试...")
                    withContext(Dispatchers.Main) {
                        addChatMessage("系统", "网络服务未初始化，继续重试...")
                    }
                    if (isTaskRunning) {
                        delay(2000)
                        continueTaskLoop()
                    }
                    return@withContext
                }
                
                // 检查任务是否暂停
                if (isTaskPaused) {
                    Log.d(TAG, "任务已暂停，不向云侧发送请求")
                    return@withContext
                }
                
                // 更新最后一次交互时间
                updateLastInteractionTime()
                
                // 加载之前的对话总结（仅在第一次发送时）
                val previousSummary = if (isFirstSend) {
                    val conversationId = currentConversation?.id ?: "default"
                    Log.d(TAG, "第一次发送，尝试加载对话总结，conversationId: $conversationId")
                    val summary = loadChatSummary(conversationId)
                    if (summary != null) {
                        Log.d(TAG, "✓ 成功加载对话总结，长度: ${summary.length} 字符")
                        Log.d(TAG, "对话总结内容预览: ${summary.take(100)}...")
                    } else {
                        Log.d(TAG, "✗ 未找到对话总结（可能这是第一次对话）")
                    }
                    summary
                } else {
                    Log.d(TAG, "非第一次发送，不加载对话总结")
                    null
                }
                
                // 记录请求开始时间
                val requestStartTime = System.currentTimeMillis()
                Log.d(TAG, "[REQUEST] 开始发送请求(第一次) - query: $query, uuid: $chatUuid, imageLength: ${urlEncodedBase64.length}")
                
                // 获取当前 Activity 信息
                // 如果之前已经获取过（在截图时），优先使用截图时的包名，确保与截图同步
                val (packageName, className) = if (screenshotPackageName != null && screenshotClassName != null) {
                    Log.d(TAG, "使用截图时获取的包名: $screenshotPackageName, 类名: $screenshotClassName")
                    Pair(screenshotPackageName, screenshotClassName)
                } else {
                    // 如果没有截图（第一次发送且没有截图），则现在获取
                    val (pkgName, clsName) = MyAccessibilityService.getCurrentActivityInfo()
                    Log.d(TAG, "当前获取包名: $pkgName, 类名: $clsName")
                    Pair(pkgName, clsName)
                }
                
                val imei = ProfileManager.getOrGenerateImei(requireContext())
                
                // 普通请求（不再使用SSE流式请求）
                val (response, parsedChatResponse) = try {
                    val mainActivity = activity as? MainActivity
                    val isBatchTesting = mainActivity?.isBatchTesting ?: false
                    Log.d(TAG, "[批测检测] 发送消息前检测: mainActivity=${mainActivity != null}, isBatchTesting=$isBatchTesting, useNextActionApi=${useNextActionApi()}")
                    
                    if (useNextActionApi()) {
                        // next_action 开启时不传递 activity 信息
                        val req = NextActionRequest(
                            task_id = chatUuid,
                            duid = imei,
                            image_url = NextActionPayloadHelper.imageUrlFromRawBase64(urlEncodedBase64),  // 第一次发送无截图，用占位图
                            query = query,
                            user_response = userResponse,
                            install_apps = getInstallAppsListForNextAction()
                        )
                        val r = apiService.sendNextActionRequest(req)
                        Pair(r, r.body()?.toChatResponse())
                    } else {
                        val r = apiService.sendChatMessage(
                            uuid = chatUuid,
                            query = query,
                            image = urlEncodedBase64,
                            userResponse = userResponse,
                            userExample = userExample,
                            chatSummary = previousSummary,
                            packageName = packageName,
                            className = className,
                            imei = imei,
                            proMode = if (isProModeEnabled) true else null,
                            batchTestMode = if (isBatchTesting) true else null,
                            stream = null,  // 不再使用流式模式
                            outputLanguage = LanguageManager.getSavedLanguage(requireContext()),
                            installApps = getInstallAppsParamForUpload()
                        )
                        Pair(r, r.body())
                    }
                } catch (e: Exception) {
                    // 记录请求失败时间
                    val requestEndTime = System.currentTimeMillis()
                    val requestDuration = requestEndTime - requestStartTime
                    
                    // 对timeout异常进行特殊处理
                    val isTimeoutException = e is java.net.SocketTimeoutException || 
                                             e is java.io.InterruptedIOException ||
                                             (e.message?.contains("timeout", ignoreCase = true) == true)
                    
                    // 详细日志
                    Log.e(TAG, "[REQUEST] 请求异常(第一次) - 耗时: ${requestDuration}ms (${requestDuration / 1000.0}秒)")
                    Log.e(TAG, "[REQUEST] 异常类型: ${e.javaClass.simpleName}, 消息: ${e.message}")
                    Log.e(TAG, "[REQUEST] 是否为timeout: $isTimeoutException", e)
                    
                    if (isTimeoutException) {
                        // timeout异常：显示友好提示，不显示具体的timeout错误信息
                        Log.w(TAG, "[TIMEOUT] 请求超时，正在重试... (耗时: ${requestDuration}ms)")
                        withContext(Dispatchers.Main) {
                            addChatMessage("系统", "请求超时，正在重试...")
                        }
                    } else {
                        // 其他异常：重新抛出，让外层catch处理
                        throw e
                    }
                    // timeout时继续重试
                    if (isTaskRunning) {
                        delay(2000)
                        continueTaskLoop()
                    }
                    return@withContext
                }
                
                // 记录请求完成时间
                val requestEndTime = System.currentTimeMillis()
                val requestDuration = requestEndTime - requestStartTime
                Log.d(TAG, "[REQUEST] 请求完成(第一次) - 耗时: ${requestDuration}ms (${requestDuration / 1000.0}秒), 状态码: ${response.code()}")
                
                // 更新最后一次交互时间（收到响应后）
                updateLastInteractionTime()
                
                if (response.isSuccessful) {
                    val chatResponse = parsedChatResponse
                    if (chatResponse != null) {
                        Log.d(TAG, "收到规划结果: $chatResponse")
                        // 第一次发送完成后，标记为已经不是第一次发送了
                        if (isFirstSendInTask) {
                            isFirstSendInTask = false
                            Log.d(TAG, "第一次发送完成，后续循环将不再判断为第一次发送")
                        }
                        // 检查是否有群组上下文（@TopoClaw的情况）
                        val groupContext = assistantGroupContext
                        if (groupContext != null) {
                            // 如果是群组@TopoClaw，不在这里显示消息，而是发送回群组
                            Log.d(TAG, "检测到群组上下文（第一次发送），消息将发送回群组: ${groupContext.groupId}")
                            // 消息将在后续处理中发送回群组
                        } else {
                            // 普通情况：显示消息在聊天界面
                            withContext(Dispatchers.Main) {
                                // 如果是call_user动作，不在这里添加message，让call_user处理逻辑统一处理
                                val actionType = chatResponse.action_type
                                if (chatResponse.message != null && actionType?.lowercase() != "call_user") {
                                    addChatMessage("云侧", chatResponse.message)
                                }
                            }
                        }
                        
                        // 处理操作指令
                        val actionType = chatResponse.action_type
                        Log.d(TAG, "处理操作指令 - actionType: $actionType, isTaskRunning: $isTaskRunning")
                        if (actionType != null && isTaskRunning) {
                            // 如果是answer动作，不需要操作屏幕，不跳转桌面，直接结束
                            if (actionType.lowercase() == "answer") {
                                Log.d(TAG, "收到answer动作，不需要操作屏幕，不跳转桌面，直接结束")
                                Log.d(TAG, "answer动作字段详情 - params: ${chatResponse.params}, text: ${chatResponse.text}, message: ${chatResponse.message}")
                                // 优先从params获取，如果没有则从text获取，最后fallback到message
                                val answerText = chatResponse.params ?: chatResponse.text ?: chatResponse.message
                                Log.d(TAG, "answer动作提取的文本: $answerText")
                                
                                // 检查是否有群组上下文（@TopoClaw的情况）
                                val groupContext = assistantGroupContext
                                Log.d(TAG, "answer动作检查群组上下文 - assistantGroupContext: ${if (groupContext != null) "存在(groupId=${groupContext.groupId})" else "不存在"}")
                                if (groupContext != null) {
                                    val finalAnswerText = if (answerText != null && answerText.isNotBlank()) answerText else "任务已完成"
                                    val feedbackCtx = groupManagerFeedbackContext
                                    if (feedbackCtx != null) {
                                        // 群组管理小助手发起的执行：先将被调用小助手的结果发到群里，再由群组管理者总结或继续调度
                                        Log.d(TAG, "群组管理反馈: TopoClaw完成，先发结果到群组，再调用群组管理者总结/调度")
                                        val imei = ProfileManager.getOrGenerateImei(requireContext())
                                        mainScope.launch {
                                            sendAssistantReplyToGroup(groupContext.groupId, finalAnswerText, imei, groupContext.senderImei, actionType = "answer", senderName = getString(R.string.auto_execute_assistant), skipDedupRecord = true)
                                            doGroupManagerFeedbackFlow(
                                                groupContext.groupId,
                                                getString(R.string.auto_execute_assistant),
                                                groupContext.originalQuery,
                                                finalAnswerText
                                            )
                                        }
                                    } else {
                                        // 普通群组@TopoClaw：发送回群组，本端通过收到广播显示（skipDedupRecord 避免去重跳过）
                                        Log.d(TAG, "准备发送answer结果到群组 - groupId: ${groupContext.groupId}, content: $finalAnswerText")
                                        val imei = ProfileManager.getOrGenerateImei(requireContext())
                                        mainScope.launch {
                                            try {
                                                sendAssistantReplyToGroup(groupContext.groupId, finalAnswerText, imei, groupContext.senderImei, actionType = "answer", skipDedupRecord = true)
                                                Log.d(TAG, "answer结果已发送到群组")
                                            } catch (e: Exception) {
                                                Log.e(TAG, "发送answer结果到群组失败", e)
                                            }
                                            withContext(Dispatchers.Main) {
                                                try {
                                                    (activity as? MainActivity)?.bringAppToForeground()?.let { if (it) delay(300) }
                                                } catch (e: Exception) {
                                                    Log.e(TAG, "群组任务完成：返回到应用页面时出错: ${e.message}", e)
                                                }
                                                currentConversation = groupContext.originalConversation
                                                assistantGroupContext = null
                                                Log.d(TAG, "已恢复原始对话上下文，清空群组上下文")
                                            }
                                        }
                                    }
                                    withContext(Dispatchers.Main) { stopTask(delaySummary = false) }
                                    return@withContext
                                }

                                // PC 端执行指令：将结果回传 PC
                                val pcContext = assistantPcExecuteContext
                                if (pcContext != null) {
                                    val finalAnswerText = if (answerText != null && answerText.isNotBlank()) answerText else "任务已完成"
                                    Log.d(TAG, "准备发送 answer 结果到 PC - content: $finalAnswerText")
                                    withContext(Dispatchers.Main) {
                                        activity?.let { act ->
                                            (act as? MainActivity)?.getCustomerServiceWebSocket()
                                                ?.sendExecuteResult(finalAnswerText, pcContext.messageId, pcContext.uuid, pcContext.conversationId)
                                            assistantPcExecuteContext = null
                                            Log.d(TAG, "PC 执行结果已发送，已清空 PC 执行上下文")
                                        }
                                    }
                                    withContext(Dispatchers.Main) {
                                        addChatMessage("小助手", finalAnswerText, isAnswer = true)
                                        notifyAnswerReceived(finalAnswerText)
                                        stopTask(delaySummary = true)
                                        notifyTaskComplete()
                                    }
                                    return@withContext
                                }
                                
                                // 端云同步：小助手回复上报后端并推送给 PC
                                val finalAnswerText = if (answerText != null && answerText.isNotBlank()) answerText else "任务已完成"
                                if (currentConversation?.id == ConversationListFragment.CONVERSATION_ID_ASSISTANT) {
                                    withContext(Dispatchers.Main) {
                                        (activity as? MainActivity)?.getCustomerServiceWebSocket()?.sendAssistantMessage(finalAnswerText)
                                    }
                                }
                                
                                // 普通情况：显示消息在聊天界面
                                if (answerText != null && answerText.isNotBlank()) {
                                    withContext(Dispatchers.Main) {
                                        addChatMessage("小助手", answerText, isAnswer = true)
                                        notifyAnswerReceived(answerText)
                                        stopTask(delaySummary = true)
                                        notifyTaskComplete()
                                        // stopTask()已经清除了图片状态并更新了按钮可见性，无需再次手动设置
                                    }
                                } else {
                                    withContext(Dispatchers.Main) {
                                        if (!shouldSuppressCustomAssistantTaskCompletedCheckmark()) {
                                            addChatMessage("系统", "任务已完成 ✓", isComplete = true)
                                        }
                                        stopTask(delaySummary = true)
                                        notifyTaskComplete()
                                        // stopTask()已经清除了图片状态并更新了按钮可见性，无需再次手动设置
                                    }
                                }
                                return@withContext
                            }
                            
                            // 如果是needs_screen_operation动作，需要操作屏幕，先跳转桌面，获取截图后发送给云侧
                            if (actionType.lowercase() == "needs_screen_operation") {
                                Log.d(TAG, "收到needs_screen_operation动作，需要操作屏幕，先跳转桌面，获取截图后发送给云侧")
                                
                                // 显示网格激活特效（规划智能体判断需要操作屏幕后）
                                Log.d(TAG, "========== 准备显示网格激活特效 ==========")
                                try {
                                    withContext(Dispatchers.Main) {
                                        Log.d(TAG, "在主线程调用 GridActivationOverlayManager.showOnce")
                                        GridActivationOverlayManager.showOnce(requireContext())
                                        Log.d(TAG, "GridActivationOverlayManager.showOnce 调用完成")
                                    }
                                } catch (e: Exception) {
                                    Log.e(TAG, "显示网格激活特效失败: ${e.message}", e)
                                    e.printStackTrace()
                                }
                                Log.d(TAG, "========== 网格激活特效调用结束 ==========")
                                
                                // 接收规划智能体的内部消息（用户不可见，仅用于日志和调试）
                                val plannerMessage = chatResponse.planner_message
                                if (plannerMessage != null && plannerMessage.isNotEmpty()) {
                                    Log.d(TAG, "收到规划智能体内部消息（用户不可见）:\n$plannerMessage")
                                    // 可以在这里将planner_message用于日志记录、调试等，但不显示给用户
                                }
                                
                                // 步骤1: 检查是否需要清除后台应用（规划智能体识别到需要操作屏幕后，gohome前清除）
                                val prefs = requireContext().getSharedPreferences("app_prefs", android.content.Context.MODE_PRIVATE)
                                val shouldClearBackground = prefs.getBoolean("clear_background_before_task", false)
                                
                                if (shouldClearBackground) {
                                    Log.d(TAG, "收到needs_screen_operation动作，规划智能体识别到需要操作屏幕，在gohome前清除后台应用")
                                    withContext(Dispatchers.Main) {
                                        (activity as? MainActivity)?.addLog("规划完成，清除后台应用...")
                                    }
                                    
                                    try {
                                        val accessibilityService = MyAccessibilityService.getInstance()
                                        if (accessibilityService != null && Build.VERSION.SDK_INT >= Build.VERSION_CODES.N) {
                                            // 清除后台应用，清除后不返回主页（因为后面还要执行goHome）
                                            val success = accessibilityService.clearAppFromRecentTasks(returnToHome = false)
                                            withContext(Dispatchers.Main) {
                                                if (success) {
                                                    addChatMessage("系统", "✓ 已清除后台应用")
                                                    (activity as? MainActivity)?.addLog("清除后台应用成功")
                                                } else {
                                                    addChatMessage("系统", "✗ 清除后台应用失败")
                                                    (activity as? MainActivity)?.addLog("清除后台应用失败")
                                                }
                                            }
                                            // 等待清除操作完成
                                            delay(1000)
                                        } else {
                                            withContext(Dispatchers.Main) {
                                                addChatMessage("系统", "✗ 无障碍服务未就绪，无法清除后台应用")
                                                (activity as? MainActivity)?.addLog("清除后台应用失败：无障碍服务未就绪")
                                            }
                                        }
                                    } catch (e: Exception) {
                                        Log.e(TAG, "清除后台应用异常: ${e.message}", e)
                                        withContext(Dispatchers.Main) {
                                            addChatMessage("系统", "✗ 清除后台应用异常: ${e.message}")
                                            (activity as? MainActivity)?.addLog("清除后台应用异常: ${e.message}")
                                        }
                                    }
                                } else {
                                    Log.d(TAG, "收到needs_screen_operation动作，但清除后台应用设置未开启，跳过清除")
                                }
                                
                                // 步骤2: 跳转桌面（规划智能体识别到需要操作屏幕后）
                                // 注意：如果是通过问字按钮发起的请求，不需要gohome，直接在当前页面开始截图等工作
                                if (isQuestionButtonRequest) {
                                    Log.d(TAG, "问字按钮请求，跳过gohome操作，直接在当前页面开始截图")
                                    // 等待一下确保页面稳定（悬浮球请求时，页面可能还在加载中）
                                    delay(500)
                                } else {
                                    withContext(Dispatchers.Main) {
                                        val accessibilityService = MyAccessibilityService.getInstance()
                                        if (accessibilityService != null) {
                                            accessibilityService.goHome()
                                            Log.d(TAG, "已执行回退到home操作")
                                        } else {
                                            Log.w(TAG, "无障碍服务未就绪，无法回退到home")
                                        }
                                    }
                                    
                                    // 步骤3: 等待页面切换完成
                                    delay(1000)
                                }
                                
                                // 步骤4: 获取截图（问字按钮请求时获取当前页面截图，普通请求时获取gohome后的截图）
                                val chatService = ChatScreenshotService.getInstance()
                                val bitmap = chatService?.captureScreenshot()
                                
                                if (bitmap == null) {
                                    // 如果是 wait 后的重试，不进入截图失败逻辑，直接发送到云侧
                                    if (isWaitRetry) {
                                        Log.w(TAG, "[gohome后wait] 重新获取截图失败，跳过截图失败逻辑，直接发送到云侧")
                                        isWaitRetry = false
                                        consecutiveWaitCount = 0
                                        continueTaskLoop()
                                        return@withContext
                                    }
                                    
                                    screenshotFailCount++
                                    val logMsg = if (isQuestionButtonRequest) {
                                        "问字按钮请求：当前页面截图失败，重试计数: $screenshotFailCount/$maxScreenshotFailRetries"
                                    } else {
                                        "gohome后截图失败，重试计数: $screenshotFailCount/$maxScreenshotFailRetries"
                                    }
                                    Log.w(TAG, logMsg)
                                    
                                    if (screenshotFailCount >= maxScreenshotFailRetries) {
                                        // 连续三次截图失败，停止任务
                                        Log.e(TAG, "连续三次截图失败，停止任务")
                                        withContext(Dispatchers.Main) {
                                            addChatMessage("小助手", "截图失败，请至服务页面确定已授权截图权限")
                                        }
                                        stopTask()
                                        return@withContext
                                    } else {
                                        // 未达到最大重试次数，继续重试
                                        withContext(Dispatchers.Main) {
                                            addChatMessage("小助手", "截图失败，继续重试...")
                                        }
                                        if (isTaskRunning) {
                                            delay(2000)
                                            continueTaskLoop()
                                        }
                                        return@withContext
                                    }
                                }
                                
                                // 截图成功，重置失败计数和 wait 重试标志
                                screenshotFailCount = 0
                                isWaitRetry = false
                                
                                // ========== 端侧异常检测 ==========
                                val (shouldSendToCloud, isWait) = processScreenshotWithAnomalyDetection(bitmap)
                                
                                if (!shouldSendToCloud) {
                                    if (isWait) {
                                        // wait情况：等待已经在 processScreenshotWithAnomalyDetection 内部完成（2秒）
                                        Log.i(TAG, "[端侧异常检测] gohome后wait情况，等待后重新获取截图并检测")
                                        bitmap.recycle()
                                        if (isTaskRunning) {
                                            delay(1000)  // 额外等待1秒（总共等待3秒）
                                            continueTaskLoop()  // 重新获取截图并检测
                                        }
                                        return@withContext
                                    } else {
                                        // call_user情况：异常已在端侧处理，不发送到云侧，等待后重新截图
                                        Log.i(TAG, "[端侧异常检测] gohome后call_user已处理，跳过本次云侧请求，等待后重新截图")
                                        bitmap.recycle()
                                        // 如果open失败，不继续任务循环，等待用户点击下载许可弹窗
                                        if (isOpenFailed) {
                                            Log.d(TAG, "[端侧异常检测] gohome后open失败，不继续任务循环，等待用户点击下载许可弹窗")
                                            return@withContext
                                        }
                                        if (isTaskRunning) {
                                            delay(1000)
                                            continueTaskLoop()
                                        }
                                        return@withContext
                                    }
                                }
                                // ===================================
                                
                                // 检查open失败标志和弹窗显示状态，如果open失败或弹窗正在显示，不发送请求，等待用户点击下载许可弹窗
                                if (isOpenFailed || AppInstallConfirmOverlayManager.isDialogShowing()) {
                                    Log.d(TAG, "[gohome后发送请求前检查] open失败或弹窗正在显示，不发送请求，等待用户点击下载许可弹窗")
                                    bitmap.recycle()
                                    return@withContext
                                }
                                
                                // 步骤5: 转换为Base64
                                val screenshotBase64 = screenshotBitmapToBase64(bitmap).also { bitmap.recycle() }
                                
                                // 如果"端侧变化检测"开关打开，异步延迟1s截medium图（不阻塞正常流程）
                                if (sendBeforeActionImageEnabled) {
                                    // 清空之前的medium截图（如果有）
                                    mediumScreenshotBase64 = null
                                    // 异步延迟1s截medium图
                                    mainScope.launch(Dispatchers.IO) {
                                        try {
                                            delay(1000)  // 延迟1秒
                                            // 检查任务是否还在运行，避免无效截图
                                            if (!isTaskRunning) {
                                                Log.d(TAG, "[medium截图] 任务已停止，取消medium截图")
                                                return@launch
                                            }
                                            val chatService = ChatScreenshotService.getInstance()
                                            val mediumBitmap = chatService?.captureScreenshot()
                                            if (mediumBitmap != null) {
                                                Log.d(TAG, "[medium截图] medium截图获取成功")
                                                val mediumBase64 = screenshotBitmapToBase64(mediumBitmap).also { 
                                                    mediumBitmap.recycle() 
                                                }
                                                // 清理Base64字符串
                                                val cleanMediumBase64 = mediumBase64.trim().replace("\n", "").replace("\r", "").replace(" ", "")
                                                // 存储medium截图（仅在任务仍在运行时）
                                                if (isTaskRunning) {
                                                    mediumScreenshotBase64 = cleanMediumBase64
                                                    Log.d(TAG, "[medium截图] medium截图已存储，长度: ${cleanMediumBase64.length}")
                                                } else {
                                                    Log.d(TAG, "[medium截图] 任务已停止，不存储medium截图")
                                                }
                                            } else {
                                                Log.w(TAG, "[medium截图] medium截图获取失败")
                                            }
                                        } catch (e: Exception) {
                                            Log.e(TAG, "[medium截图] medium截图异常: ${e.message}", e)
                                        }
                                    }
                                }
                                
                                // 步骤6: 清理Base64字符串
                                val cleanBase64 = screenshotBase64.trim().replace("\n", "").replace("\r", "").replace(" ", "")
                                
                                // 步骤7: 验证Base64格式
                                val (base64Part, isValidBase64) = try {
                                    val base64Index = cleanBase64.indexOf(";base64,")
                                    val part = if (base64Index != -1) {
                                        cleanBase64.substring(base64Index + 8)
                                    } else {
                                        cleanBase64
                                    }
                                    if (part.length % 4 != 0) {
                                        Pair(part, false)
                                    } else {
                                        android.util.Base64.decode(part, android.util.Base64.NO_WRAP)
                                        Pair(part, true)
                                    }
                                } catch (e: Exception) {
                                    Log.e(TAG, "Base64验证失败: ${e.message}", e)
                                    Pair("", false)
                                }
                                
                                if (!isValidBase64) {
                                    Log.w(TAG, "Base64字符串无效，继续重试...")
                                    withContext(Dispatchers.Main) {
                                        addChatMessage("系统", "Base64编码验证失败，继续重试...")
                                    }
                                    if (isTaskRunning) {
                                        delay(2000)
                                        continueTaskLoop()
                                    }
                                    return@withContext
                                }
                                
                                val finalBase64 = cleanBase64
                                
                                // 步骤7: URL编码
                                val urlEncodedBase64 = try {
                                    java.net.URLEncoder.encode(finalBase64, "UTF-8")
                                } catch (e: Exception) {
                                    Log.e(TAG, "URL编码失败: ${e.message}", e)
                                    finalBase64
                                }
                                
                                // 确保使用当前对话对应的服务地址
                                ensureNetworkServiceInitialized()
                                
                                // 步骤8: 发送gohome后的截图到云侧（使用当前的query）
                                val apiService = NetworkService.getApiService()
                                if (apiService == null) {
                                    Log.w(TAG, "ApiService未初始化，继续重试...")
                                    withContext(Dispatchers.Main) {
                                        addChatMessage("系统", "网络服务未初始化，继续重试...")
                                    }
                                    if (isTaskRunning) {
                                        delay(2000)
                                        continueTaskLoop()
                                    }
                                    return@withContext
                                }
                                
                                // 检查任务是否暂停
                                if (isTaskPaused) {
                                    Log.d(TAG, "任务已暂停，不向云侧发送请求")
                                    return@withContext
                                }
                                
                                // 检查open失败标志和弹窗显示状态，如果open失败或弹窗正在显示，不发送请求，等待用户点击下载许可弹窗
                                if (isOpenFailed || AppInstallConfirmOverlayManager.isDialogShowing()) {
                                    Log.d(TAG, "[gohome后发送请求前检查] open失败或弹窗正在显示，不发送请求，等待用户点击下载许可弹窗")
                                    return@withContext
                                }
                                
                                // 更新最后一次交互时间
                                updateLastInteractionTime()
                                
                                val logMsg = if (isQuestionButtonRequest) {
                                    "发送问字按钮请求的截图到云侧，query=$query, imageLength=${urlEncodedBase64.length}"
                                } else {
                                    "发送gohome后的截图到云侧，query=$query, imageLength=${urlEncodedBase64.length}"
                                }
                                Log.d(TAG, logMsg)
                                // 获取当前 Activity 信息
                                val (packageName, className) = MyAccessibilityService.getCurrentActivityInfo()
                                val imei = ProfileManager.getOrGenerateImei(requireContext())
                                
                                // 检测是否为批测模式
                                val mainActivity = activity as? MainActivity
                                val isBatchTesting = mainActivity?.isBatchTesting ?: false
                                
                                val (response, parsedChatResponse) = try {
                                    performCloudRequest(
                                        apiService,
                                        chatUuid,
                                        query,
                                        cleanBase64,
                                        urlEncodedBase64,
                                        userResponse,
                                        userExample,
                                        null,
                                        packageName,
                                        className,
                                        imei,
                                        if (isProModeEnabled) true else null,
                                        if (isBatchTesting) true else null
                                    )
                                } catch (e: Exception) {
                                    // 对timeout异常进行特殊处理
                                    val isTimeoutException = e is java.net.SocketTimeoutException || 
                                                             e is java.io.InterruptedIOException ||
                                                             (e.message?.contains("timeout", ignoreCase = true) == true)
                                    
                                    if (isTimeoutException) {
                                        // timeout异常：显示友好提示，不显示具体的timeout错误信息
                                        Log.w(TAG, "请求超时，正在重试... (${e.message})")
                                        withContext(Dispatchers.Main) {
                                            addChatMessage("系统", "请求超时，正在重试...")
                                        }
                                    } else {
                                        // 其他异常：重新抛出，让外层catch处理
                                        throw e
                                    }
                                    // timeout时继续重试
                                    if (isTaskRunning) {
                                        delay(2000)
                                        continueTaskLoop()
                                    }
                                    return@withContext
                                }
                                
                                // 更新最后一次交互时间（收到响应后）
                                updateLastInteractionTime()
                                
                                // 步骤9: 处理响应并开始执行
                                if (response.isSuccessful) {
                                    val chatResponse = parsedChatResponse
                                    if (chatResponse != null) {
                                        Log.d(TAG, "收到响应: $chatResponse")
                                        Log.d(TAG, "收到响应详情 - action_type: ${chatResponse.action_type}, app_name: ${chatResponse.app_name}, reason: ${chatResponse.reason}, thought: ${chatResponse.thought}")
                                        withContext(Dispatchers.Main) {
                                            // 如果是call_user动作，不在这里添加message，让call_user处理逻辑统一处理
                                            val nextActionType = chatResponse.action_type
                                            if (chatResponse.message != null && nextActionType?.lowercase() != "call_user") {
                                                addChatMessage("云侧", chatResponse.message)
                                            }
                                            
                                            // 收到新响应时，先快速收起之前的reasoning悬浮窗
                                            ReasoningOverlayManager.hide()
                                            
                                            // 保存reasoning，等待截图完成后显示（当有action_type且有reasoning时）
                                            if (nextActionType != null && !chatResponse.reason.isNullOrBlank()) {
                                                pendingReasoning = chatResponse.reason
                                                Log.d(TAG, "保存reasoning等待截图完成后显示: ${chatResponse.reason}")
                                            } else {
                                                pendingReasoning = null
                                            }
                                        }
                                        
                                        // 等待100ms确保悬浮窗完全移除后再执行动作
                                        delay(100)
                                        
                                        // 处理操作指令并执行
                                        val nextActionType = chatResponse.action_type
                                        Log.d(TAG, "检查操作指令 - actionType: $nextActionType, isTaskRunning: $isTaskRunning, isTaskPaused: $isTaskPaused")
                                        
                                        // 如果任务已暂停，不执行动作
                                        if (isTaskPaused) {
                                            Log.d(TAG, "任务已暂停，不执行动作: $nextActionType")
                                            return@withContext
                                        }
                                        
                                        if (nextActionType != null && isTaskRunning) {
                                            Log.d(TAG, "收到操作指令: $nextActionType，开始执行")
                                            
                                            // 如果是第一次执行动作（currentStep == 0），显示网格激活特效
                                            // 排除不需要操作屏幕的动作（answer、call_user）
                                            val actionTypeLower = nextActionType.lowercase()
                                            val isScreenOperationAction = actionTypeLower !in listOf("answer", "call_user", "complete")
                                            if (currentStep == 0 && isScreenOperationAction) {
                                                Log.d(TAG, "========== 第一次执行操作动作，显示网格激活特效 ==========")
                                                try {
                                                    withContext(Dispatchers.Main) {
                                                        GridActivationOverlayManager.showOnce(requireContext())
                                                    }
                                                } catch (e: Exception) {
                                                    Log.e(TAG, "显示网格激活特效失败: ${e.message}", e)
                                                }
                                                Log.d(TAG, "========== 网格激活特效调用完成 ==========")
                                            }
                                            
                                            if (nextActionType.lowercase() == "open") {
                                                Log.d(TAG, "收到open动作，app_name: ${chatResponse.app_name}")
                                            }
                                            // 重置open失败标志
                                            isOpenFailed = false
                                            // 执行动作（添加异常处理，确保即使出错也能继续循环）
                                            val executedActionType2 = nextActionType
                                            try {
                                                executeAction(chatResponse)
                                                Log.d(TAG, "动作执行完成: $nextActionType")
                                            } catch (e: Exception) {
                                                Log.e(TAG, "执行动作时发生异常: ${e.message}", e)
                                                withContext(Dispatchers.Main) {
                                                    addChatMessage("系统", "执行动作异常: ${e.message}")
                                                }
                                            }
                                            
                                            // 执行完动作后，检查是否是open失败
                                            // 如果是open失败，不继续任务循环，等待用户点击下载许可弹窗
                                            if (isOpenFailed) {
                                                Log.d(TAG, "动作执行完成，但open失败，不继续任务循环，等待用户点击下载许可弹窗")
                                                return@withContext
                                            }
                                            
                                            // 执行完动作后，继续循环（无论成功还是失败都要继续）
                                            if (isTaskRunning) {
                                                Log.d(TAG, "动作执行完成，准备继续任务循环")
                                                delay(actionCompletionDelayMs)
                                                continueTaskLoop()
                                            } else {
                                                Log.w(TAG, "任务已停止，不继续循环")
                                            }
                                        } else {
                                            // 没有操作指令，继续循环
                                            if (isTaskRunning) {
                                                delay(actionCompletionDelayMs)
                                                continueTaskLoop()
                                            }
                                        }
                                    } else {
                                        Log.w(TAG, "响应体为空")
                                        if (isTaskRunning) {
                                            delay(2000)
                                            continueTaskLoop()
                                        }
                                    }
                                } else {
                                    Log.w(TAG, "请求失败: ${response.code()}")
                                    if (isTaskRunning) {
                                        delay(2000)
                                        continueTaskLoop()
                                    }
                                }
                                
                                return@withContext
                            }
                            
                            // 其他动作（理论上第一次请求不应该收到，但为了兼容性也处理）
                            Log.w(TAG, "第一次请求收到意外动作: $actionType，继续任务循环")
                            
                            // 显示网格激活特效（第一次收到需要操作屏幕的动作）
                            val actionTypeLower = actionType.lowercase()
                            val isScreenOperationAction = actionTypeLower !in listOf("answer", "call_user", "complete")
                            if (isScreenOperationAction) {
                                Log.d(TAG, "========== [第一次请求] 收到操作动作，显示网格激活特效 ==========")
                                try {
                                    withContext(Dispatchers.Main) {
                                        GridActivationOverlayManager.showOnce(requireContext())
                                    }
                                } catch (e: Exception) {
                                    Log.e(TAG, "[第一次请求] 显示网格激活特效失败: ${e.message}", e)
                                }
                                Log.d(TAG, "========== [第一次请求] 网格激活特效调用完成 ==========")
                            }
                            
                            // 步骤1: 检查是否需要清除后台应用（在gohome前清除）
                            val prefs = requireContext().getSharedPreferences("app_prefs", android.content.Context.MODE_PRIVATE)
                            val shouldClearBackground = prefs.getBoolean("clear_background_before_task", false)
                            
                            if (shouldClearBackground) {
                                Log.d(TAG, "收到意外动作: $actionType，在gohome前清除后台应用")
                                withContext(Dispatchers.Main) {
                                    (activity as? MainActivity)?.addLog("清除后台应用...")
                                }
                                
                                try {
                                    val accessibilityService = MyAccessibilityService.getInstance()
                                    if (accessibilityService != null && Build.VERSION.SDK_INT >= Build.VERSION_CODES.N) {
                                        // 清除后台应用，清除后不返回主页（因为后面还要执行goHome）
                                        val success = accessibilityService.clearAppFromRecentTasks(returnToHome = false)
                                        withContext(Dispatchers.Main) {
                                            if (success) {
                                                addChatMessage("系统", "✓ 已清除后台应用")
                                                (activity as? MainActivity)?.addLog("清除后台应用成功")
                                            } else {
                                                addChatMessage("系统", "✗ 清除后台应用失败")
                                                (activity as? MainActivity)?.addLog("清除后台应用失败")
                                            }
                                        }
                                        // 等待清除操作完成
                                        delay(1000)
                                    } else {
                                        withContext(Dispatchers.Main) {
                                            addChatMessage("系统", "✗ 无障碍服务未就绪，无法清除后台应用")
                                            (activity as? MainActivity)?.addLog("清除后台应用失败：无障碍服务未就绪")
                                        }
                                    }
                                } catch (e: Exception) {
                                    Log.e(TAG, "清除后台应用异常: ${e.message}", e)
                                    withContext(Dispatchers.Main) {
                                        addChatMessage("系统", "✗ 清除后台应用异常: ${e.message}")
                                        (activity as? MainActivity)?.addLog("清除后台应用异常: ${e.message}")
                                    }
                                }
                            } else {
                                Log.d(TAG, "收到意外动作: $actionType，但清除后台应用设置未开启，跳过清除")
                            }
                            
                            // 步骤2: 跳转桌面并继续
                            // 注意：如果是通过问字按钮发起的请求，不需要gohome，直接在当前页面开始截图等工作
                            if (isQuestionButtonRequest) {
                                Log.d(TAG, "问字按钮请求，跳过gohome操作，直接继续任务循环")
                            } else {
                                withContext(Dispatchers.Main) {
                                    val accessibilityService = MyAccessibilityService.getInstance()
                                    if (accessibilityService != null) {
                                        accessibilityService.goHome()
                                        Log.d(TAG, "已执行回退到home操作")
                                    } else {
                                        Log.w(TAG, "无障碍服务未就绪，无法回退到home")
                                    }
                                }
                                // 等待页面切换完成（增加等待时间确保页面切换完成）
                                delay(1000)
                            }
                            if (isTaskRunning) {
                                delay(actionCompletionDelayMs)
                                continueTaskLoop()
                            }
                            return@withContext
                        }
                    }
                }
                
                // 如果响应失败，继续重试
                if (isTaskRunning) {
                    delay(2000)
                    continueTaskLoop()
                }
                return@withContext
            }
            
            // 清理Base64字符串
            val cleanBase64 = userImageBase64.trim().replace("\n", "").replace("\r", "").replace(" ", "")
            
            // 验证Base64格式
            val (base64Part, isValidBase64) = try {
                val base64Index = cleanBase64.indexOf(";base64,")
                val part = if (base64Index != -1) {
                    cleanBase64.substring(base64Index + 8)
                } else {
                    cleanBase64
                }
                if (part.length % 4 != 0) {
                    Pair(part, false)
                } else {
                    android.util.Base64.decode(part, android.util.Base64.NO_WRAP)
                    Pair(part, true)
                }
            } catch (e: Exception) {
                Log.e(TAG, "Base64验证失败: ${e.message}", e)
                Pair("", false)
            }
            
            if (!isValidBase64) {
                Log.w(TAG, "Base64字符串无效，继续重试...")
                withContext(Dispatchers.Main) {
                    addChatMessage("系统", "Base64编码验证失败，继续重试...")
                }
                // Base64验证失败时继续重试，不停止任务
                if (isTaskRunning) {
                    delay(2000)
                    continueTaskLoop()
                }
                return@withContext
            }
            
            val finalBase64 = cleanBase64
            
            // URL编码
            val urlEncodedBase64 = try {
                java.net.URLEncoder.encode(finalBase64, "UTF-8")
            } catch (e: Exception) {
                Log.e(TAG, "URL编码失败: ${e.message}", e)
                finalBase64
            }
            
            // 确保使用当前对话对应的服务地址
            ensureNetworkServiceInitialized()
            
            // 发送请求
            val apiService = NetworkService.getApiService()
            if (apiService == null) {
                Log.w(TAG, "ApiService未初始化，继续重试...")
                withContext(Dispatchers.Main) {
                    addChatMessage("系统", "网络服务未初始化，继续重试...")
                }
                // 网络服务未初始化时继续重试，不停止任务
                if (isTaskRunning) {
                    delay(2000)
                    continueTaskLoop()
                }
                return@withContext
            }
            
            // 检查任务是否暂停，如果暂停则不发送请求
            if (isTaskPaused) {
                Log.d(TAG, "任务已暂停，不向云侧发送请求")
                return@withContext
            }
            
            // 检查open失败标志和弹窗显示状态，如果open失败或弹窗正在显示，不发送请求，等待用户点击下载许可弹窗
            if (isOpenFailed || AppInstallConfirmOverlayManager.isDialogShowing()) {
                Log.d(TAG, "[发送请求前检查] open失败或弹窗正在显示，不发送请求，等待用户点击下载许可弹窗")
                return@withContext
            }
            
            // 更新最后一次交互时间（发送请求前）
            updateLastInteractionTime()
            
            // 记录请求开始时间
            val requestStartTime = System.currentTimeMillis()
            Log.d(TAG, "[REQUEST] 开始发送请求 - query: $query, uuid: $chatUuid, imageLength: ${urlEncodedBase64.length}")
            
            // 仅在第一次发送时加载对话总结
            val previousSummary = if (isFirstSendInTask && userResponse == null) {
                val convId = currentConversation?.id ?: "default"
                Log.d(TAG, "第一次发送，尝试加载对话总结，conversationId: $convId")
                val summary = loadChatSummary(convId)
                if (summary != null) {
                    Log.d(TAG, "✓ 成功加载对话总结，长度: ${summary.length} 字符")
                    Log.d(TAG, "对话总结内容预览: ${summary.take(100)}...")
                } else {
                    Log.d(TAG, "✗ 未找到对话总结（可能这是第一次对话）")
                }
                summary
            } else {
                Log.d(TAG, "非第一次发送（isFirstSendInTask=$isFirstSendInTask, userResponse=$userResponse），不加载对话总结")
                null
            }
            
            // 获取当前 Activity 信息
            // 如果之前已经获取过（在截图时），优先使用截图时的包名，确保与截图同步
            val (packageName, className) = if (screenshotPackageName != null && screenshotClassName != null) {
                Log.d(TAG, "使用截图时获取的包名: $screenshotPackageName, 类名: $screenshotClassName")
                Pair(screenshotPackageName, screenshotClassName)
            } else {
                // 如果没有截图（第一次发送或用户选择的图片），则现在获取
                val (pkgName, clsName) = MyAccessibilityService.getCurrentActivityInfo()
                Log.d(TAG, "当前获取包名: $pkgName, 类名: $clsName")
                Pair(pkgName, clsName)
            }
            
            val imei = ProfileManager.getOrGenerateImei(requireContext())
            
            // 其他助手继续使用HTTP发送
            // 检测是否为批测模式
            val mainActivity = activity as? MainActivity
            val isBatchTesting = mainActivity?.isBatchTesting ?: false
            Log.d(TAG, "[批测检测] performSendChatMessage: mainActivity=${mainActivity != null}, isBatchTesting=$isBatchTesting, useNextActionApi=${useNextActionApi()}")
            
            val (response, chatResponse) = if (useNextActionApi()) {
                // next_action 开启时不传递 activity 信息
                val req = NextActionRequest(
                    task_id = chatUuid,
                    duid = imei,
                    image_url = NextActionPayloadHelper.imageUrlFromRawBase64(finalBase64),
                    query = query,
                    user_response = userResponse,
                    install_apps = getInstallAppsListForNextAction()
                )
                val r = apiService.sendNextActionRequest(req)
                Pair(r, r.body()?.toChatResponse())
            } else {
                val r = apiService.sendChatMessage(
                    uuid = chatUuid,
                    query = query,
                    image = urlEncodedBase64,
                    userResponse = userResponse,
                    userExample = userExample,
                    chatSummary = previousSummary,
                    packageName = packageName,
                    className = className,
                    imei = imei,
                    proMode = if (isProModeEnabled) true else null,
                    batchTestMode = if (isBatchTesting) true else null,
                    swipeSearchContext = currentSwipeSearchContext,
                    outputLanguage = LanguageManager.getSavedLanguage(requireContext()),
                    installApps = getInstallAppsParamForUpload()
                )
                Pair(r, r.body())
            }
            
            // 记录请求完成时间
            val requestEndTime = System.currentTimeMillis()
            val requestDuration = requestEndTime - requestStartTime
            Log.d(TAG, "[REQUEST] 请求完成 - 耗时: ${requestDuration}ms (${requestDuration / 1000.0}秒), 状态码: ${response.code()}")
            
            // 更新最后一次交互时间（收到响应后）
            updateLastInteractionTime()
            
            if (response.isSuccessful) {
                if (chatResponse != null) {
                    Log.d(TAG, "收到响应: $chatResponse")
                    // 添加详细的字段日志
                    Log.d(TAG, "响应字段详情 - action_type: ${chatResponse.action_type}, reason: ${chatResponse.reason}, thought: ${chatResponse.thought}, message: ${chatResponse.message}, params: ${chatResponse.params}, text: ${chatResponse.text}")
                    // 保存滑动搜索上下文（如果存在）
                    currentSwipeSearchContext = chatResponse.swipe_search_context?.let { 
                        com.google.gson.Gson().toJson(it) 
                    }
                    // 检查是否有群组上下文（@TopoClaw的情况）
                    val groupContext = assistantGroupContext
                    Log.d(TAG, "检查群组上下文 - assistantGroupContext: ${if (groupContext != null) "存在(groupId=${groupContext.groupId})" else "不存在"}")
                    if (groupContext != null) {
                        // 群组@TopoClaw：将结果发送回群组，不显示在聊天界面
                        Log.d(TAG, "检测到群组上下文，准备将结果发送回群组: ${groupContext.groupId}")
                        val actionType = chatResponse.action_type?.lowercase()
                        Log.d(TAG, "群组上下文处理 - action_type: $actionType")
                        val replyText = when {
                            // answer动作：优先使用params或text字段
                            actionType == "answer" -> {
                                val answerText = chatResponse.params ?: chatResponse.text ?: chatResponse.message
                                Log.d(TAG, "answer动作 - params: ${chatResponse.params}, text: ${chatResponse.text}, message: ${chatResponse.message}, 最终answerText: $answerText")
                                answerText
                            }
                            // complete动作：使用getCompleteDisplayText（next_action 开关打开时会解析 arguments 作为最终回答）
                            actionType == "complete" -> {
                                ChatResponseDisplayHelper.getCompleteDisplayText(
                                    chatResponse,
                                    useNextActionApi(),
                                    isMaxStepTriggered = ChatResponseDisplayHelper.isMaxStepTriggeredReason(chatResponse.reason)
                                )
                            }
                            // call_user动作：不发送回复（由call_user处理逻辑统一处理）
                            actionType == "call_user" -> {
                                null  // call_user动作不在这里发送回复
                            }
                            // 其他情况：优先使用message字段，如果没有则使用reason或thought
                            else -> {
                                chatResponse.message ?: chatResponse.reason ?: chatResponse.thought
                            }
                        } ?: when {
                            // 如果所有字段都为空，根据action_type生成默认回复
                            actionType == "complete" -> "任务已完成"
                            actionType != null -> "已处理您的请求（动作类型: $actionType）"
                            else -> "已收到您的消息，正在处理中..."
                        }
                        Log.d(TAG, "群组上下文处理 - replyText: $replyText")
                        
                        // 检查是否是复述任务，如果是则跳过发送
                        // 对于默认消息（如"已收到您的消息，正在处理中..."），不检测为复述
                        // 对于answer动作，不检测复述（因为answer动作本身就是最终回复，即使包含任务关键词也应该发送）
                        val isDefaultMessage = replyText == "已收到您的消息，正在处理中..." || 
                                             replyText == "任务已完成" ||
                                             (replyText?.startsWith("已处理您的请求") == true)
                        val isRepeating = actionType != "answer" && !isDefaultMessage && replyText != null && isRepeatingTask(replyText, groupContext.originalQuery)
                        if (isRepeating) {
                            Log.d(TAG, "检测到回复复述了任务内容，跳过发送到群组 - replyText: $replyText, originalQuery: ${groupContext.originalQuery}, actionType: $actionType")
                            // 如果是complete动作，虽然跳过发送，但需要停止任务并恢复上下文
                            if (actionType == "complete") {
                                Log.d(TAG, "complete动作的回复复述了任务，跳过发送，停止任务并恢复上下文")
                                mainScope.launch {
                                    // 跳转回TopoClaw应用
                                    withContext(Dispatchers.Main) {
                                        val mainActivity = activity as? MainActivity
                                        try {
                                            val success = mainActivity?.bringAppToForeground() ?: false
                                            if (success) {
                                                Log.d(TAG, "群组任务完成：已返回到TopoClaw应用页面")
                                                delay(300)
                                            }
                                        } catch (e: Exception) {
                                            Log.e(TAG, "群组任务完成：返回到应用页面时出错: ${e.message}", e)
                                        }
                                        
                                        // 恢复原始对话上下文
                                        currentConversation = groupContext.originalConversation
                                        assistantGroupContext = null
                                        Log.d(TAG, "已恢复原始对话上下文，清空群组上下文")
                                    }
                                }
                                
                                // 停止任务但不显示消息在聊天界面
                                withContext(Dispatchers.Main) {
                                    stopTask(delaySummary = false)
                                }
                                return@withContext
                            }
                            // 如果是answer动作，即使复述了任务，也应该继续执行到answer处理逻辑
                            // 因为answer动作的处理逻辑会检查复述并决定是否发送
                            if (actionType == "answer") {
                                Log.d(TAG, "answer动作的回复复述了任务，跳过发送，但继续执行到answer处理逻辑")
                                // 不return，继续执行到8484行的answer处理逻辑
                            }
                            // 其他动作（如open、click等）复述了任务，跳过发送回复，但继续执行动作
                            // 注意：不要return，让代码继续执行到动作处理部分
                            if (actionType != "call_user" && actionType != "answer" && actionType != "complete") {
                                Log.d(TAG, "其他动作(actionType=$actionType)的回复复述了任务，跳过发送，但继续执行动作")
                                // 不return，继续执行到动作处理部分
                            }
                        }
                        
                        // 如果是call_user动作，不发送回复（由call_user处理逻辑统一处理）
                        // 对于answer和complete动作，如果有群组上下文，在这里发送回复并return，不继续执行动作
                        if (actionType == "answer" || actionType == "complete") {
                            val finalReplyText = replyText?.takeIf { it.isNotBlank() } ?: "任务已完成"
                            val imei = ProfileManager.getOrGenerateImei(requireContext())
                            val feedbackCtx = groupManagerFeedbackContext
                            if (feedbackCtx != null) {
                                Log.d(TAG, "群组管理反馈(next_action): TopoClaw完成，先发结果到群组，再调用群组管理者总结/调度")
                                mainScope.launch {
                                    sendAssistantReplyToGroup(groupContext.groupId, finalReplyText, imei, groupContext.senderImei, actionType = actionType, senderName = getString(R.string.auto_execute_assistant), skipDedupRecord = true)
                                    doGroupManagerFeedbackFlow(
                                        groupContext.groupId,
                                        getString(R.string.auto_execute_assistant),
                                        groupContext.originalQuery,
                                        finalReplyText
                                    )
                                }
                            } else {
                                Log.d(TAG, "检测到answer或complete动作，准备发送回复到群组")
                                mainScope.launch {
                                    try {
                                        sendAssistantReplyToGroup(groupContext.groupId, finalReplyText, imei, groupContext.senderImei, actionType = actionType, skipDedupRecord = true)
                                        Log.d(TAG, "小助手回复已发送到群组")
                                    } catch (e: Exception) {
                                        Log.e(TAG, "发送小助手回复到群组失败", e)
                                    }
                                    withContext(Dispatchers.Main) {
                                        val mainActivity = activity as? MainActivity
                                        try {
                                            mainActivity?.bringAppToForeground()?.let { if (it) delay(300) }
                                        } catch (e: Exception) {
                                            Log.e(TAG, "群组任务完成：返回到应用页面时出错: ${e.message}", e)
                                        }
                                        currentConversation = groupContext.originalConversation
                                        assistantGroupContext = null
                                        Log.d(TAG, "已恢复原始对话上下文，清空群组上下文")
                                    }
                                }
                            }
                            withContext(Dispatchers.Main) { stopTask(delaySummary = false) }
                            return@withContext
                        }
                        
                        // 其他动作（非answer、complete、call_user），如果有回复文本且不是复述任务，发送回复，但继续执行动作
                        if (actionType != "call_user" && actionType != "answer" && actionType != "complete" && replyText != null && !isRepeating) {
                            val imei = ProfileManager.getOrGenerateImei(requireContext())
                            mainScope.launch {
                                sendAssistantReplyToGroup(groupContext.groupId, replyText, imei, groupContext.senderImei, actionType = actionType)
                            }
                        } else if (isRepeating && actionType != "call_user" && actionType != "answer" && actionType != "complete") {
                            Log.d(TAG, "其他动作(actionType=$actionType)的回复复述了任务，跳过发送，继续执行动作")
                        }
                        
                        // 群组上下文时，不显示消息在聊天界面，也不显示reasoning悬浮窗
                        // 但需要继续执行动作（如果需要）
                    } else {
                        // 普通情况：显示消息在聊天界面
                        withContext(Dispatchers.Main) {
                            // 显示云侧返回的消息
                            // 如果是call_user动作，不在这里添加message，让call_user处理逻辑统一处理
                            val actionType = chatResponse.action_type
                            if (chatResponse.message != null && actionType?.lowercase() != "call_user") {
                                addChatMessage("云侧", chatResponse.message)
                            }
                            
                            // 收到新响应时，先快速收起之前的reasoning悬浮窗
                            ReasoningOverlayManager.hide()
                            
                            // 保存reasoning，等待截图完成后显示（当有action_type且有reasoning时）
                            if (actionType != null && !chatResponse.reason.isNullOrBlank()) {
                                pendingReasoning = chatResponse.reason
                                Log.d(TAG, "保存reasoning等待截图完成后显示: ${chatResponse.reason}")
                            } else {
                                pendingReasoning = null
                            }
                        }
                    }
                    
                    // 等待100ms确保悬浮窗完全移除后再执行动作
                    delay(100)
                    
                    // 处理操作指令
                    val actionType = chatResponse.action_type
                    Log.d(TAG, "检查操作指令 - actionType: $actionType, isTaskRunning: $isTaskRunning")
                    if (actionType != null && isTaskRunning) {
                        Log.d(TAG, "收到操作指令: $actionType")
                        
                        // 处理complete指令
                        if (actionType.lowercase() == "complete") {
                            Log.d(TAG, "收到complete指令，任务完成")
                            // 添加调试日志，查看接收到的reason和thought
                            Log.d(TAG, "complete指令 - reason: ${chatResponse.reason}, thought: ${chatResponse.thought}")
                            
                            // 检查是否有群组上下文（@TopoClaw的情况）
                            val groupContext = assistantGroupContext
                            if (groupContext != null) {
                                // 群组@TopoClaw：将结果发送回群组
                                val reason = chatResponse.reason ?: ""
                                val isMaxStepTriggered = reason.contains("执行步数已达到最大限制") || 
                                                         reason.contains("超过最大执行步数限制")
                                val completeText = ChatResponseDisplayHelper.getCompleteDisplayText(chatResponse, useNextActionApi(), isMaxStepTriggered)
                                
                                // 检查是否是复述任务，如果是则跳过发送
                                val isRepeating = isRepeatingTask(completeText, groupContext.originalQuery)
                                if (isRepeating) {
                                    Log.d(TAG, "complete指令的回复复述了任务内容，跳过发送到群组 - completeText: $completeText, originalQuery: ${groupContext.originalQuery}")
                                    // 跳过发送，但需要停止任务并恢复上下文
                                    mainScope.launch {
                                        // 跳转回TopoClaw应用
                                        withContext(Dispatchers.Main) {
                                            val mainActivity = activity as? MainActivity
                                            try {
                                                val success = mainActivity?.bringAppToForeground() ?: false
                                                if (success) {
                                                    Log.d(TAG, "群组任务完成（complete指令）：已返回到TopoClaw应用页面")
                                                    delay(300)
                                                }
                                            } catch (e: Exception) {
                                                Log.e(TAG, "群组任务完成（complete指令）：返回到应用页面时出错: ${e.message}", e)
                                            }
                                            
                                            // 恢复原始对话上下文
                                            currentConversation = groupContext.originalConversation
                                            assistantGroupContext = null
                                        }
                                    }
                                    
                                    // 停止任务但不显示消息在聊天界面
                                    withContext(Dispatchers.Main) {
                                        stopTask(delaySummary = false)
                                    }
                                    return@withContext
                                }
                                
                                val feedbackCtx = groupManagerFeedbackContext
                                if (feedbackCtx != null) {
                                    Log.d(TAG, "群组管理反馈(complete): TopoClaw完成，先发结果到群组，再调用群组管理者总结/调度")
                                    val imei = ProfileManager.getOrGenerateImei(requireContext())
                                    mainScope.launch {
                                        sendAssistantReplyToGroup(groupContext.groupId, completeText, imei, groupContext.senderImei, actionType = "complete", senderName = getString(R.string.auto_execute_assistant), skipDedupRecord = true)
                                        doGroupManagerFeedbackFlow(
                                            groupContext.groupId,
                                            getString(R.string.auto_execute_assistant),
                                            groupContext.originalQuery,
                                            completeText
                                        )
                                    }
                                } else {
                                    val imei = ProfileManager.getOrGenerateImei(requireContext())
                                    mainScope.launch {
                                        sendAssistantReplyToGroup(groupContext.groupId, completeText, imei, groupContext.senderImei, actionType = "complete", skipDedupRecord = true)
                                        withContext(Dispatchers.Main) {
                                            val mainActivity = activity as? MainActivity
                                            try {
                                                mainActivity?.bringAppToForeground()?.let { if (it) delay(300) }
                                            } catch (e: Exception) {
                                                Log.e(TAG, "群组任务完成（complete指令）：返回到应用页面时出错: ${e.message}", e)
                                            }
                                            currentConversation = groupContext.originalConversation
                                            assistantGroupContext = null
                                        }
                                    }
                                }
                                withContext(Dispatchers.Main) { stopTask(delaySummary = false) }
                                return@withContext
                            }

                            // 入口统一处理：complete 视为 answer，将 params（arguments）作为最终回答展示
                            val reason = chatResponse.reason ?: ""
                            val isMaxStepTriggered = reason.contains("执行步数已达到最大限制") || 
                                                     reason.contains("超过最大执行步数限制")
                            val answerText = ChatResponseDisplayHelper.getCompleteDisplayText(chatResponse, useNextActionApi(), isMaxStepTriggered)
                            if (answerText.isNotBlank() && answerText != "任务已完成") {
                                withContext(Dispatchers.Main) {
                                    addChatMessage("小助手", answerText, isAnswer = true)
                                }
                            }

                            // PC 端执行指令：将 complete 结果回传 PC
                            val pcContextComplete = assistantPcExecuteContext
                            if (pcContextComplete != null) {
                                Log.d(TAG, "准备发送 complete 结果到 PC - content: $answerText")
                                withContext(Dispatchers.Main) {
                                    activity?.let { act ->
                                        (act as? MainActivity)?.getCustomerServiceWebSocket()
                                            ?.sendExecuteResult(answerText, pcContextComplete.messageId, pcContextComplete.uuid, pcContextComplete.conversationId)
                                        assistantPcExecuteContext = null
                                        Log.d(TAG, "PC 执行结果(complete)已发送，已清空 PC 执行上下文")
                                    }
                                    if (!shouldSuppressCustomAssistantTaskCompletedCheckmark()) {
                                        addChatMessage("系统", "任务已完成 ✓", isComplete = true)
                                    }
                                    stopTask(delaySummary = true)
                                    notifyTaskComplete()
                                }
                                return@withContext
                            }
                            
                            // 端云同步：complete 指令的小助手回复也上报
                            if (currentConversation?.id == ConversationListFragment.CONVERSATION_ID_ASSISTANT && answerText.isNotBlank()) {
                                withContext(Dispatchers.Main) {
                                    (activity as? MainActivity)?.getCustomerServiceWebSocket()?.sendAssistantMessage(answerText)
                                }
                            }
                            
                            withContext(Dispatchers.Main) {
                                val mainActivity = activity as? MainActivity
                                // 在stopTask()调用前先保存标志，避免被清除
                                val isFromExternal = mainActivity?.isTaskFromExternalApp ?: false
                                val originalPackage = mainActivity?.originalPackageName
                                
                                // 添加调试日志
                                Log.d(TAG, "complete指令处理 - isFromExternal: $isFromExternal, originalPackage: $originalPackage")
                                
                                // 步骤1: 判断任务来源并处理应用切换
                                // 检查是否是从伴随模式发起的任务（无论是否从外部应用）
                                val isFromCompanionMode = mainActivity?.isTaskFromCompanionMode ?: false
                                Log.d(TAG, "complete指令处理 - 检查伴随模式状态: isFromCompanionMode=$isFromCompanionMode, isFromExternal=$isFromExternal, originalPackage=$originalPackage")
                                
                                // 判断是否为max_step触发（在外层定义，以便后续使用）
                                val reason = chatResponse.reason ?: ""
                                val isMaxStepTriggered = reason.contains("执行步数已达到最大限制") || 
                                                         reason.contains("超过最大执行步数限制")
                                
                                if (isFromCompanionMode) {
                                    // 从伴随模式发起：不跳转回应用，只显示弹窗（回答已在入口添加）
                                    Log.d(TAG, "complete指令 - 任务从伴随模式发起，不跳转回应用，只显示弹窗")
                                    
                                    val resultText = ChatResponseDisplayHelper.getCompleteResultTextForOverlay(chatResponse, useNextActionApi())
                                    val hasAnswer = ChatResponseDisplayHelper.hasCompleteAnswerContent(chatResponse, useNextActionApi())
                                    
                                    if (!hasAnswer && !shouldSuppressCustomAssistantTaskCompletedCheckmark()) {
                                        addChatMessage("系统", "任务已完成 ✓", isComplete = true)
                                    }
                                    
                                    Log.d(TAG, "complete指令 - 开始显示任务结果弹窗")
                                    showCompanionResultOverlay(resultText)
                                    Log.d(TAG, "complete指令 - 任务结果弹窗已显示")
                                } else if (isFromExternal && originalPackage != null) {
                                    // 检查是否是从伴随模式发起的任务（回答已在入口添加）
                                    val isFromCompanionMode = mainActivity?.isTaskFromCompanionMode ?: false
                                    Log.d(TAG, "complete指令处理 - 检查伴随模式状态: isFromCompanionMode=$isFromCompanionMode, isFromExternal=$isFromExternal, originalPackage=$originalPackage")
                                    
                                    val resultText = ChatResponseDisplayHelper.getCompleteResultTextForOverlay(chatResponse, useNextActionApi())
                                    val hasAnswer = ChatResponseDisplayHelper.hasCompleteAnswerContent(chatResponse, useNextActionApi())
                                    
                                    if (!hasAnswer && !shouldSuppressCustomAssistantTaskCompletedCheckmark()) {
                                        addChatMessage("系统", "任务已完成 ✓", isComplete = true)
                                    }
                                    
                                    if (isFromCompanionMode) {
                                        // 从伴随模式发起：不跳转回应用，只显示弹窗
                                        Log.d(TAG, "complete指令 - 任务从伴随模式发起，不跳转回应用，只显示弹窗")
                                        Log.d(TAG, "complete指令 - 开始显示任务结果弹窗")
                                        showCompanionResultOverlay(resultText)
                                        Log.d(TAG, "complete指令 - 任务结果弹窗已显示")
                                    } else {
                                        // 从其他外部应用发起：切换回原应用并显示结果弹窗
                                        Log.d(TAG, "complete指令 - 任务从其他外部应用发起（非伴随模式），准备切回原应用: $originalPackage")
                                        
                                        // 尝试切换回原应用
                                        var switchSuccess = false
                                        try {
                                            Log.d(TAG, "complete指令 - 开始切换回原应用: $originalPackage")
                                            val success = mainActivity?.launchAppFromActivity(originalPackage) ?: false
                                            if (success) {
                                                Log.d(TAG, "complete指令 - 已切回原应用: $originalPackage")
                                                // 等待应用切换完成
                                                delay(500)
                                                switchSuccess = true
                                            } else {
                                                Log.w(TAG, "complete指令 - 切回原应用失败: $originalPackage，将在当前应用显示弹窗")
                                            }
                                        } catch (e: Exception) {
                                            Log.e(TAG, "complete指令 - 切回原应用时出错: ${e.message}，将在当前应用显示弹窗", e)
                                        }
                                        
                                        // 无论应用切换是否成功，都要显示结果弹窗（弹窗可以在任何应用上显示）
                                        if (mainActivity != null) {
                                            Log.d(TAG, "complete指令 - 显示任务结果弹窗，应用切换${if (switchSuccess) "成功" else "失败"}")
                                            showCompanionResultOverlay(resultText)
                                            Log.d(TAG, "complete指令 - 任务结果弹窗已显示")
                                        } else {
                                            Log.w(TAG, "complete指令 - 无法显示弹窗: mainActivity为null")
                                        }
                                    }
                                } else {
                                    // 从应用内发起：切回应用（回答已在入口添加）
                                    Log.d(TAG, "任务从应用内发起，保持原有逻辑")
                                    try {
                                        val success = mainActivity?.bringAppToForeground() ?: false
                                        if (success) {
                                            Log.d(TAG, "已返回到TopoClaw应用页面")
                                            // 等待应用切换到前台
                                            delay(300)
                                        } else {
                                            Log.w(TAG, "返回到TopoClaw应用页面失败")
                                        }
                                    } catch (e: Exception) {
                                        Log.e(TAG, "返回到应用页面时出错: ${e.message}", e)
                                    }
                                    
                                    val hasAnswer = ChatResponseDisplayHelper.hasCompleteAnswerContent(chatResponse, useNextActionApi())
                                    if (!hasAnswer && !shouldSuppressCustomAssistantTaskCompletedCheckmark()) {
                                        addChatMessage("系统", "任务已完成 ✓", isComplete = true)
                                    }
                                }
                                
                                // 步骤4: 在停止任务之前保存任务的uuid和query（用于反馈评测）
                                val taskUuidForFeedback = chatUuid
                                val taskQueryForFeedback = currentQuery
                                Log.d(TAG, "[complete指令] 保存任务信息用于反馈: taskUuidForFeedback=$taskUuidForFeedback, taskQueryForFeedback=$taskQueryForFeedback")
                                
                                // 步骤5: 停止任务（延迟调用总结，确保所有消息都已保存）
                                // stopTask()内部已经调用了updateButtonVisibility()，无需重复调用
                                stopTask(delaySummary = true)
                                notifyTaskComplete()
                                
                                // 步骤6: 检查是否需要显示评价请求（正常完成或异常情况都显示）
                                Log.d(TAG, "[complete指令] 准备检查是否显示评价请求: isMaxStepTriggered=$isMaxStepTriggered")
                                if (isMaxStepTriggered) {
                                    // max_step触发：显示异常反馈请求
                                    Log.d(TAG, "[complete指令] max_step触发，调用showFeedbackRequest(isException=true)，传入taskUuid=$taskUuidForFeedback, taskQuery=$taskQueryForFeedback")
                                    showFeedbackRequest(taskUuidForFeedback, taskQueryForFeedback, isException = true)
                                } else {
                                    // 正常完成：显示正常反馈请求
                                    Log.d(TAG, "[complete指令] 条件满足，调用showFeedbackRequest()，传入taskUuid=$taskUuidForFeedback, taskQuery=$taskQueryForFeedback")
                                    showFeedbackRequest(taskUuidForFeedback, taskQueryForFeedback)
                                }
                            }
                            return@withContext
                        }
                        
                        // 处理answer指令（等同于complete，直接结束任务）
                        if (actionType.lowercase() == "answer") {
                            // 优先从params获取，如果没有则从text获取，最后fallback到message
                            val answerText = chatResponse.params ?: chatResponse.text ?: chatResponse.message
                            Log.d(TAG, "处理answer指令: params=${chatResponse.params}, text=${chatResponse.text}, message=${chatResponse.message}, answerText=$answerText")
                            
                            // 检查是否有群组上下文（@TopoClaw的情况）
                            val groupContext = assistantGroupContext
                            if (groupContext != null) {
                                val finalAnswerText = if (answerText != null && answerText.isNotBlank()) answerText else "任务已完成"
                                val feedbackCtx = groupManagerFeedbackContext
                                if (feedbackCtx != null) {
                                    Log.d(TAG, "群组管理反馈(continueTaskLoop): TopoClaw完成，先发结果到群组，再调用群组管理者总结/调度")
                                    val imei = ProfileManager.getOrGenerateImei(requireContext())
                                    mainScope.launch {
                                        sendAssistantReplyToGroup(groupContext.groupId, finalAnswerText, imei, groupContext.senderImei, actionType = "answer", senderName = getString(R.string.auto_execute_assistant), skipDedupRecord = true)
                                        doGroupManagerFeedbackFlow(
                                            groupContext.groupId,
                                            getString(R.string.auto_execute_assistant),
                                            groupContext.originalQuery,
                                            finalAnswerText
                                        )
                                    }
                                } else {
                                    Log.d(TAG, "continueTaskLoop - 检测到群组上下文，将answer结果发送回群组")
                                    val imei = ProfileManager.getOrGenerateImei(requireContext())
                                    mainScope.launch {
                                        sendAssistantReplyToGroup(groupContext.groupId, finalAnswerText, imei, groupContext.senderImei, actionType = "answer", skipDedupRecord = true)
                                        withContext(Dispatchers.Main) {
                                            val mainActivity = activity as? MainActivity
                                            try {
                                                mainActivity?.bringAppToForeground()?.let { if (it) delay(300) }
                                            } catch (e: Exception) {
                                                Log.e(TAG, "群组任务完成（answer指令）：返回到应用页面时出错: ${e.message}", e)
                                            }
                                            currentConversation = groupContext.originalConversation
                                            assistantGroupContext = null
                                        }
                                    }
                                }
                                withContext(Dispatchers.Main) { stopTask(delaySummary = false) }
                                return@withContext
                            }
                            
                            if (answerText != null && answerText.isNotBlank()) {
                                Log.d(TAG, "收到answer指令，文本内容: $answerText，任务完成")
                                withContext(Dispatchers.Main) {
                                    val mainActivity = activity as? MainActivity
                                    // 在stopTask()调用前先保存标志，避免被清除
                                    val isFromExternal = mainActivity?.isTaskFromExternalApp ?: false
                                    val originalPackage = mainActivity?.originalPackageName
                                    
                                    // 添加调试日志
                                    Log.d(TAG, "answer指令处理 - isFromExternal: $isFromExternal, originalPackage: $originalPackage")
                                    
                                // 步骤1: 判断任务来源并处理应用切换
                                // 检查是否是从伴随模式发起的任务（无论是否从外部应用）
                                val isFromCompanionMode = mainActivity?.isTaskFromCompanionMode ?: false
                                Log.d(TAG, "answer指令处理 - 检查伴随模式状态: isFromCompanionMode=$isFromCompanionMode, isFromExternal=$isFromExternal, originalPackage=$originalPackage")
                                
                                // 先保存到聊天记录（无论是否显示弹窗都要保存）
                                addChatMessage("小助手", answerText, isAnswer = true)
                                
                                // answer指令表示正常完成，isMaxStepTriggered始终为false
                                val isMaxStepTriggered = false
                                
                                if (isFromCompanionMode) {
                                        // 从伴随模式发起：不跳转回应用，只显示弹窗
                                        Log.d(TAG, "answer指令 - 任务从伴随模式发起，不跳转回应用，只显示弹窗")
                                        Log.d(TAG, "answer指令 - 开始显示任务结果弹窗")
                                        showCompanionResultOverlay(answerText)
                                        Log.d(TAG, "answer指令 - 任务结果弹窗已显示")
                                    } else if (isFromExternal && originalPackage != null) {
                                        // 从其他外部应用发起：切换回原应用并显示结果弹窗
                                        Log.d(TAG, "answer指令 - 任务从其他外部应用发起（非伴随模式），准备切回原应用: $originalPackage")
                                        
                                        // 尝试切换回原应用
                                        var switchSuccess = false
                                        try {
                                            Log.d(TAG, "answer指令 - 开始切换回原应用: $originalPackage")
                                            val success = mainActivity?.launchAppFromActivity(originalPackage) ?: false
                                            if (success) {
                                                Log.d(TAG, "answer指令 - 已切回原应用: $originalPackage")
                                                // 等待应用切换完成
                                                delay(500)
                                                switchSuccess = true
                                            } else {
                                                Log.w(TAG, "answer指令 - 切回原应用失败: $originalPackage，将在当前应用显示弹窗")
                                            }
                                        } catch (e: Exception) {
                                            Log.e(TAG, "answer指令 - 切回原应用时出错: ${e.message}，将在当前应用显示弹窗", e)
                                        }
                                        
                                        // 无论应用切换是否成功，都要显示结果弹窗（弹窗可以在任何应用上显示）
                                        if (mainActivity != null) {
                                            Log.d(TAG, "answer指令 - 显示任务结果弹窗，应用切换${if (switchSuccess) "成功" else "失败"}")
                                            showCompanionResultOverlay(answerText)
                                            Log.d(TAG, "answer指令 - 任务结果弹窗已显示")
                                        } else {
                                            Log.w(TAG, "answer指令 - mainActivity为null，无法显示弹窗")
                                        }
                                    } else {
                                        // 从应用内发起：保持原有逻辑，切回应用并显示在聊天界面
                                        Log.d(TAG, "answer指令 - 任务从应用内发起，保持原有逻辑")
                                        try {
                                            val success = mainActivity?.bringAppToForeground() ?: false
                                            if (success) {
                                                Log.d(TAG, "answer指令 - 已返回到TopoClaw应用页面")
                                                delay(300)
                                            } else {
                                                Log.w(TAG, "answer指令 - 返回到TopoClaw应用页面失败")
                                            }
                                        } catch (e: Exception) {
                                            Log.e(TAG, "answer指令 - 返回到应用页面时出错: ${e.message}", e)
                                        }
                                    }
                                    
                                    // 步骤4: 在停止任务之前保存任务的uuid和query（用于反馈评测）
                                    val taskUuidForFeedback = chatUuid
                                    val taskQueryForFeedback = currentQuery
                                    Log.d(TAG, "[answer指令] 保存任务信息用于反馈: taskUuidForFeedback=$taskUuidForFeedback, taskQueryForFeedback=$taskQueryForFeedback")
                                    
                                    // 步骤5: 停止任务（延迟调用总结，确保所有消息都已保存）
                                    stopTask(delaySummary = true)
                                    
                                    // 通知监听器任务完成
                                    notifyTaskComplete()
                                    // stopTask()已经清除了图片状态并更新了按钮可见性，无需再次手动设置
                                    
                                    // 步骤6: 显示评价请求（answer指令表示正常完成）
                                    Log.d(TAG, "[answer指令] 准备调用showFeedbackRequest()，传入taskUuid=$taskUuidForFeedback, taskQuery=$taskQueryForFeedback")
                                    showFeedbackRequest(taskUuidForFeedback, taskQueryForFeedback)
                                }
                                return@withContext
                            } else {
                                Log.w(TAG, "answer指令缺少文本内容: params=${chatResponse.params}, text=${chatResponse.text}")
                                // 即使没有文本，也停止任务
                                withContext(Dispatchers.Main) {
                                    if (!shouldSuppressCustomAssistantTaskCompletedCheckmark()) {
                                        addChatMessage("系统", "任务已完成 ✓", isComplete = true)
                                    }
                                    stopTask()
                                    // stopTask()已经清除了图片状态并更新了按钮可见性，无需再次手动设置
                                    // 通知监听器任务完成（虽然没有answer文本）
                                    notifyTaskComplete()
                                }
                                return@withContext
                            }
                        }
                        
                        // 处理needs_screen_operation动作（后续循环中理论上不应该收到，但为了兼容性也处理）
                        if (actionType.lowercase() == "needs_screen_operation") {
                            Log.d(TAG, "收到needs_screen_operation动作，需要操作屏幕，先跳转桌面，获取截图后发送给云侧")
                            
                            // 显示网格激活特效（规划智能体判断需要操作屏幕后）
                            Log.d(TAG, "========== [后续循环] 准备显示网格激活特效 ==========")
                            try {
                                withContext(Dispatchers.Main) {
                                    Log.d(TAG, "[后续循环] 在主线程调用 GridActivationOverlayManager.showOnce")
                                    GridActivationOverlayManager.showOnce(requireContext())
                                    Log.d(TAG, "[后续循环] GridActivationOverlayManager.showOnce 调用完成")
                                }
                            } catch (e: Exception) {
                                Log.e(TAG, "[后续循环] 显示网格激活特效失败: ${e.message}", e)
                                e.printStackTrace()
                            }
                            Log.d(TAG, "========== [后续循环] 网格激活特效调用结束 ==========")
                            
                            // 接收规划智能体的内部消息（用户不可见，仅用于日志和调试）
                            val plannerMessage = chatResponse.planner_message
                            if (plannerMessage != null && plannerMessage.isNotEmpty()) {
                                Log.d(TAG, "收到规划智能体内部消息（用户不可见）:\n$plannerMessage")
                                // 可以在这里将planner_message用于日志记录、调试等，但不显示给用户
                            }
                            
                            // 步骤1: 检查是否需要清除后台应用（规划智能体识别到需要操作屏幕后，gohome前清除）
                            val prefs = requireContext().getSharedPreferences("app_prefs", android.content.Context.MODE_PRIVATE)
                            val shouldClearBackground = prefs.getBoolean("clear_background_before_task", false)
                            
                            if (shouldClearBackground) {
                                Log.d(TAG, "收到needs_screen_operation动作，规划智能体识别到需要操作屏幕，在gohome前清除后台应用")
                                withContext(Dispatchers.Main) {
                                    (activity as? MainActivity)?.addLog("规划完成，清除后台应用...")
                                }
                                
                                try {
                                    val accessibilityService = MyAccessibilityService.getInstance()
                                    if (accessibilityService != null && Build.VERSION.SDK_INT >= Build.VERSION_CODES.N) {
                                        // 清除后台应用，清除后不返回主页（因为后面还要执行goHome）
                                        val success = accessibilityService.clearAppFromRecentTasks(returnToHome = false)
                                        withContext(Dispatchers.Main) {
                                            if (success) {
                                                addChatMessage("系统", "✓ 已清除后台应用")
                                                (activity as? MainActivity)?.addLog("清除后台应用成功")
                                            } else {
                                                addChatMessage("系统", "✗ 清除后台应用失败")
                                                (activity as? MainActivity)?.addLog("清除后台应用失败")
                                            }
                                        }
                                        // 等待清除操作完成
                                        delay(1000)
                                    } else {
                                        withContext(Dispatchers.Main) {
                                            addChatMessage("系统", "✗ 无障碍服务未就绪，无法清除后台应用")
                                            (activity as? MainActivity)?.addLog("清除后台应用失败：无障碍服务未就绪")
                                        }
                                    }
                                } catch (e: Exception) {
                                    Log.e(TAG, "清除后台应用异常: ${e.message}", e)
                                    withContext(Dispatchers.Main) {
                                        addChatMessage("系统", "✗ 清除后台应用异常: ${e.message}")
                                        (activity as? MainActivity)?.addLog("清除后台应用异常: ${e.message}")
                                    }
                                }
                            } else {
                                Log.d(TAG, "收到needs_screen_operation动作，但清除后台应用设置未开启，跳过清除")
                            }
                            
                            // 步骤2: 跳转桌面（规划智能体识别到需要操作屏幕后）
                            // 注意：如果是通过问字按钮发起的请求，不需要gohome，直接在当前页面开始截图等工作
                            if (isQuestionButtonRequest) {
                                Log.d(TAG, "问字按钮请求，跳过gohome操作，直接在当前页面开始截图")
                                // 等待一下确保页面稳定（悬浮球请求时，页面可能还在加载中）
                                delay(500)
                            } else {
                                withContext(Dispatchers.Main) {
                                    val accessibilityService = MyAccessibilityService.getInstance()
                                    if (accessibilityService != null) {
                                        accessibilityService.goHome()
                                        Log.d(TAG, "已执行回退到home操作")
                                    } else {
                                        Log.w(TAG, "无障碍服务未就绪，无法回退到home")
                                    }
                                }
                                
                                // 步骤3: 等待页面切换完成
                                delay(1000)
                            }
                            
                            // 步骤4: 获取截图（问字按钮请求时获取当前页面截图，普通请求时获取gohome后的截图）
                            val chatService = ChatScreenshotService.getInstance()
                            val bitmap = chatService?.captureScreenshot()
                            
                            if (bitmap == null) {
                                screenshotFailCount++
                                val logMsg = if (isQuestionButtonRequest) {
                                    "问字按钮请求：当前页面截图失败，重试计数: $screenshotFailCount/$maxScreenshotFailRetries"
                                } else {
                                    "gohome后截图失败，重试计数: $screenshotFailCount/$maxScreenshotFailRetries"
                                }
                                Log.w(TAG, logMsg)
                                
                                if (screenshotFailCount >= maxScreenshotFailRetries) {
                                    // 连续三次截图失败，停止任务
                                    Log.e(TAG, "连续三次截图失败，停止任务")
                                    withContext(Dispatchers.Main) {
                                        addChatMessage("小助手", "截图失败，请至服务页面确定已授权截图权限")
                                    }
                                    stopTask()
                                    return@withContext
                                } else {
                                    // 未达到最大重试次数，继续重试
                                    withContext(Dispatchers.Main) {
                                        addChatMessage("小助手", "截图失败，继续重试...")
                                    }
                                    if (isTaskRunning) {
                                        delay(2000)
                                        continueTaskLoop()
                                    }
                                    return@withContext
                                }
                            }
                            
                            // 截图成功，重置失败计数
                            screenshotFailCount = 0
                            
                            // 在获取截图后立即获取包名和类名，确保与截图同步
                            val (gohomePackageName, gohomeClassName) = MyAccessibilityService.getCurrentActivityInfo()
                            Log.d(TAG, "gohome后获取截图时立即获取包名: $gohomePackageName, 类名: $gohomeClassName")
                            
                            // 步骤5: 转换为Base64
                            val screenshotBase64 = screenshotBitmapToBase64(bitmap).also { bitmap.recycle() }
                            
                            // 步骤6: 清理Base64字符串
                            val cleanBase64 = screenshotBase64.trim().replace("\n", "").replace("\r", "").replace(" ", "")
                            
                            // 步骤7: 验证Base64格式
                            val (base64Part, isValidBase64) = try {
                                val base64Index = cleanBase64.indexOf(";base64,")
                                val part = if (base64Index != -1) {
                                    cleanBase64.substring(base64Index + 8)
                                } else {
                                    cleanBase64
                                }
                                if (part.length % 4 != 0) {
                                    Pair(part, false)
                                } else {
                                    android.util.Base64.decode(part, android.util.Base64.NO_WRAP)
                                    Pair(part, true)
                                }
                            } catch (e: Exception) {
                                Log.e(TAG, "Base64验证失败: ${e.message}", e)
                                Pair("", false)
                            }
                            
                            if (!isValidBase64) {
                                Log.w(TAG, "Base64字符串无效，继续重试...")
                                withContext(Dispatchers.Main) {
                                    addChatMessage("系统", "Base64编码验证失败，继续重试...")
                                }
                                if (isTaskRunning) {
                                    delay(2000)
                                    continueTaskLoop()
                                }
                                return@withContext
                            }
                            
                            val finalBase64 = cleanBase64
                            
                            // 步骤7: URL编码
                            val urlEncodedBase64 = try {
                                java.net.URLEncoder.encode(finalBase64, "UTF-8")
                            } catch (e: Exception) {
                                Log.e(TAG, "URL编码失败: ${e.message}", e)
                                finalBase64
                            }
                            
                            // 确保使用当前对话对应的服务地址
                            ensureNetworkServiceInitialized()
                            
                            // 步骤8: 发送gohome后的截图到云侧（使用当前的query）
                            val apiService = NetworkService.getApiService()
                            if (apiService == null) {
                                Log.w(TAG, "ApiService未初始化，继续重试...")
                                withContext(Dispatchers.Main) {
                                    addChatMessage("系统", "网络服务未初始化，继续重试...")
                                }
                                if (isTaskRunning) {
                                    delay(2000)
                                    continueTaskLoop()
                                }
                                return@withContext
                            }
                            
                            // 检查任务是否暂停
                            if (isTaskPaused) {
                                Log.d(TAG, "任务已暂停，不向云侧发送请求")
                                return@withContext
                            }
                            
                            // 更新最后一次交互时间
                            updateLastInteractionTime()
                            
                            // 检查currentQuery是否为null，使用局部变量避免智能转换问题
                            val queryToSend = currentQuery
                            if (queryToSend == null) {
                                Log.w(TAG, "currentQuery为null，无法发送请求")
                                withContext(Dispatchers.Main) {
                                    addChatMessage("系统", "任务查询为空，无法继续")
                                }
                                if (isTaskRunning) {
                                    delay(2000)
                                    continueTaskLoop()
                                }
                                return@withContext
                            }
                            
                            Log.d(TAG, "发送gohome后的截图到云侧，query=$queryToSend")
                            // 使用截图时获取的包名和类名，确保与截图同步
                            val (packageName, className) = Pair(gohomePackageName, gohomeClassName)
                            Log.d(TAG, "使用gohome后截图时获取的包名: $packageName, 类名: $className")
                            val imei = ProfileManager.getOrGenerateImei(requireContext())
                            
                            // 检测是否为批测模式
                            val mainActivity = activity as? MainActivity
                            val isBatchTesting = mainActivity?.isBatchTesting ?: false
                            
                            val (response, parsedChatResponse) = try {
                                performCloudRequest(
                                    apiService,
                                    chatUuid,
                                    queryToSend,
                                    finalBase64,
                                    urlEncodedBase64,
                                    userResponse = null,
                                    userExample = null,
                                    chatSummary = null,
                                    packageName = packageName,
                                    className = className,
                                    imei = imei,
                                    proMode = if (isProModeEnabled) true else null,
                                    batchTestMode = if (isBatchTesting) true else null
                                )
                            } catch (e: Exception) {
                                // 对timeout异常进行特殊处理
                                val isTimeoutException = e is java.net.SocketTimeoutException || 
                                                         e is java.io.InterruptedIOException ||
                                                         (e.message?.contains("timeout", ignoreCase = true) == true)
                                
                                if (isTimeoutException) {
                                    // timeout异常：显示友好提示，不显示具体的timeout错误信息
                                    Log.w(TAG, "请求超时，正在重试... (${e.message})")
                                    withContext(Dispatchers.Main) {
                                        addChatMessage("系统", "请求超时，正在重试...")
                                    }
                                } else {
                                    // 其他异常：重新抛出，让外层catch处理
                                    throw e
                                }
                                // timeout时继续重试
                                if (isTaskRunning) {
                                    delay(2000)
                                    continueTaskLoop()
                                }
                                return@withContext
                            }
                            
                            // 更新最后一次交互时间（收到响应后）
                            updateLastInteractionTime()
                            
                            // 步骤9: 处理响应并开始执行
                            if (response.isSuccessful) {
                                val chatResponse = parsedChatResponse
                                if (chatResponse != null) {
                                    Log.d(TAG, "收到响应: $chatResponse")
                                    withContext(Dispatchers.Main) {
                                        // 如果是call_user动作，不在这里添加message，让call_user处理逻辑统一处理
                                        val nextActionType = chatResponse.action_type
                                        if (chatResponse.message != null && nextActionType?.lowercase() != "call_user") {
                                            addChatMessage("云侧", chatResponse.message)
                                        }
                                    }
                                    
                                    // 处理操作指令并执行
                                    val nextActionType = chatResponse.action_type
                                    
                                    // 如果任务已暂停，不执行动作
                                    if (isTaskPaused) {
                                        Log.d(TAG, "任务已暂停，不执行动作: $nextActionType")
                                        return@withContext
                                    }
                                    
                                    if (nextActionType != null && isTaskRunning) {
                                        Log.d(TAG, "收到操作指令: $nextActionType，开始执行")
                                        // 执行动作（添加异常处理，确保即使出错也能继续循环）
                                        val executedActionType3 = nextActionType
                                        try {
                                            executeAction(chatResponse)
                                            Log.d(TAG, "动作执行完成: $nextActionType")
                                        } catch (e: Exception) {
                                            Log.e(TAG, "执行动作时发生异常: ${e.message}", e)
                                            withContext(Dispatchers.Main) {
                                                addChatMessage("系统", "执行动作异常: ${e.message}")
                                            }
                                        }
                                        
                                        // 执行完动作后，继续循环（无论成功还是失败都要继续）
                                        if (isTaskRunning) {
                                            Log.d(TAG, "动作执行完成，准备继续任务循环")
                                            delay(actionCompletionDelayMs)
                                            continueTaskLoop()
                                        } else {
                                            Log.w(TAG, "任务已停止，不继续循环")
                                        }
                                    } else {
                                        // 没有操作指令，继续循环
                                        if (isTaskRunning) {
                                            delay(actionCompletionDelayMs)
                                            continueTaskLoop()
                                        }
                                    }
                                } else {
                                    Log.w(TAG, "响应体为空")
                                    if (isTaskRunning) {
                                        delay(2000)
                                        continueTaskLoop()
                                    }
                                }
                            } else {
                                Log.w(TAG, "请求失败: ${response.code()}")
                                if (isTaskRunning) {
                                    delay(2000)
                                    continueTaskLoop()
                                }
                            }
                            
                            return@withContext
                        }
                        
                        // 处理call_user指令
                        if (actionType.lowercase() == "call_user") {
                            val callUserText = chatResponse.text
                            Log.d(TAG, "处理call_user指令: text=$callUserText")
                            
                            if (callUserText != null && callUserText.isNotBlank()) {
                                Log.d(TAG, "收到call_user指令，询问内容: $callUserText")
                                withContext(Dispatchers.Main) {
                                    // 播放call_user提示音效
                                    playCallUserSound()
                                    
                                    // 保存原始query（如果还没有保存）
                                    if (originalQuery == null) {
                                        originalQuery = currentQuery
                                    }
                                    
                                    // 停止任务循环，等待用户输入
                                    taskJob?.cancel()
                                    taskJob = null
                                    
                                    // 显示悬浮窗输入框（不再跳转回应用）
                                    // 先将call_user消息添加到聊天界面
                                    addChatMessage("云侧", callUserText, isAnswer = true)
                                    Log.d(TAG, "call_user消息已添加到聊天框")
                                    
                                    val currentActivity = activity
                                    if (currentActivity != null) {
                                        val savedOriginalQuery: String? = originalQuery
                                        CallUserInputOverlayManager.show(
                                            context = currentActivity,
                                            questionText = callUserText,
                                            onSend = { userInput: String ->
                                                Log.d(TAG, "用户通过悬浮窗输入: $userInput")
                                                // 将用户输入添加到聊天界面
                                                addChatMessage("我", userInput)
                                                // 用户输入后，继续任务
                                                if (savedOriginalQuery != null) {
                                                    originalQuery = null
                                                    handleCallUserResponse(savedOriginalQuery, userInput)
                                                }
                                            },
                                            onCancel = {
                                                Log.d(TAG, "用户取消输入，停止任务")
                                                // 用户取消，停止任务
                                                stopTask()
                                                notifyTaskComplete()
                                            },
                                            onManualTakeover = {
                                                Log.d(TAG, "用户点击手动接管")
                                                // 设置手动接管状态
                                                isManualTakeover = true
                                                // 停止任务循环
                                                taskJob?.cancel()
                                                taskJob = null
                                                // 添加提示消息
                                                addChatMessage("系统", "已进入手动接管模式，请手动操作屏幕。操作完成后，点击悬浮球结束手动操作。")
                                            }
                                        )
                                    } else {
                                        Log.w(TAG, "Activity为null，无法显示悬浮窗")
                                    }
                                }
                                return@withContext
                            } else {
                                Log.w(TAG, "call_user指令缺少文本内容: text=${chatResponse.text}")
                                // 即使没有文本，也继续循环，避免卡死
                                if (isTaskRunning) {
                                    delay(actionCompletionDelayMs)
                                    continueTaskLoop()
                                }
                                return@withContext
                            }
                        }
                        
                        // 执行其他操作（添加异常处理，确保即使出错也能继续循环）
                        val executedActionType4 = chatResponse.action_type
                        try {
                            executeAction(chatResponse)
                            Log.d(TAG, "动作执行完成")
                        } catch (e: Exception) {
                            Log.e(TAG, "执行动作时发生异常: ${e.message}", e)
                            withContext(Dispatchers.Main) {
                                addChatMessage("系统", "执行动作异常: ${e.message}")
                            }
                        }
                        
                        // 执行完动作后，继续循环（无论成功还是失败都要继续）
                        if (isTaskRunning) {
                            Log.d(TAG, "动作执行完成，准备继续任务循环")
                            delay(actionCompletionDelayMs)
                            continueTaskLoop()
                        } else {
                            Log.w(TAG, "任务已停止，不继续循环")
                        }
                    } else {
                        // 没有操作指令，继续循环
                        if (isTaskRunning) {
                            delay(2000)
                            continueTaskLoop()
                        }
                    }
                } else {
                    Log.w(TAG, "响应体为空")
                    if (isTaskRunning) {
                        delay(2000)
                        continueTaskLoop()
                    }
                }
            } else {
                Log.w(TAG, "请求失败: ${response.code()}")
                withContext(Dispatchers.Main) {
                    addChatMessage("系统", "请求失败: ${response.code()}")
                }
                if (isTaskRunning) {
                    delay(2000)
                    continueTaskLoop()
                }
            }
        } catch (e: Exception) {
            // 对timeout异常进行特殊处理
            val isTimeoutException = e is java.net.SocketTimeoutException || 
                                     e is java.io.InterruptedIOException ||
                                     (e.message?.contains("timeout", ignoreCase = true) == true)
            
            // 详细日志：记录异常信息
            Log.e(TAG, "========== 请求异常详情 ==========")
            Log.e(TAG, "异常类型: ${e.javaClass.simpleName}")
            Log.e(TAG, "异常消息: ${e.message}")
            Log.e(TAG, "是否为timeout异常: $isTimeoutException")
            Log.e(TAG, "异常堆栈:", e)
            Log.e(TAG, "===================================")
            
            if (isTimeoutException) {
                // timeout异常：显示友好提示，不显示具体的timeout错误信息
                Log.w(TAG, "[TIMEOUT] 请求超时，正在重试... (异常类型: ${e.javaClass.simpleName}, 消息: ${e.message})")
                withContext(Dispatchers.Main) {
                    addChatMessage("系统", "请求超时，正在重试...")
                }
            } else {
                // 其他异常：显示错误消息
                Log.e(TAG, "[ERROR] 发送消息异常: ${e.message}", e)
                withContext(Dispatchers.Main) {
                    addChatMessage("系统", "发送失败: ${e.message}，继续重试...")
                }
            }
            // 发送异常时继续重试，不停止任务（除非收到complete）
            if (isTaskRunning) {
                delay(2000)
                continueTaskLoop()
            }
        }
    }
    
    /**
     * 获取动作完成后的延迟时间（毫秒）
     * 从SharedPreferences读取，如果未设置则返回默认值500ms
     */
    private fun getActionCompletionDelayMs(): Long {
        return try {
            val prefs = requireContext().getSharedPreferences("app_prefs", android.content.Context.MODE_PRIVATE)
            val delayMs = prefs.getInt("action_completion_delay_ms", 500)
            // 限制范围：0-5000ms
            when {
                delayMs < 0 -> 0L
                delayMs > 5000 -> 5000L
                else -> delayMs.toLong()
            }
        } catch (e: Exception) {
            Log.w(TAG, "读取动作完成后延迟时间失败，使用默认值500ms: ${e.message}")
            500L
        }
    }
    
    /**
     * 更新动作完成后延迟时间缓存
     * 在任务开始时调用，避免每次动作执行时都读取SharedPreferences
     */
    private fun updateActionCompletionDelayCache() {
        actionCompletionDelayMs = getActionCompletionDelayMs()
        Log.d(TAG, "动作完成后延迟时间缓存已更新: ${actionCompletionDelayMs}ms")
    }
    
    /**
     * 继续任务循环
     */
    private fun continueTaskLoop() {
        Log.d(TAG, "continueTaskLoop: isTaskRunning=$isTaskRunning, isTaskPaused=$isTaskPaused, isOpenFailed=$isOpenFailed, currentQuery=$currentQuery")
        if (!isTaskRunning || currentQuery == null) {
            Log.w(TAG, "continueTaskLoop: 任务未运行或query为空，不继续循环")
            return
        }
        
        // 如果任务已暂停，不继续循环
        if (isTaskPaused) {
            Log.d(TAG, "continueTaskLoop: 任务已暂停，不继续循环")
            return
        }
        
        // 如果正在等待输入法切换，不继续任务循环
        if (MyAccessibilityService.isWaitingForIMESwitch()) {
            Log.d(TAG, "continueTaskLoop: 正在等待输入法切换，不继续任务循环")
            return
        }
        
        // 如果open失败或弹窗正在显示，不继续任务循环，等待用户点击下载许可弹窗
        if (isOpenFailed || AppInstallConfirmOverlayManager.isDialogShowing()) {
            Log.d(TAG, "continueTaskLoop: open失败或弹窗正在显示，不继续任务循环，等待用户点击下载许可弹窗")
            return
        }
        
        // 取消之前的任务
        taskJob?.cancel()
        
        // 启动新的任务循环（后续循环不需要goHome，但需要发送截图）
        Log.d(TAG, "continueTaskLoop: 启动新的任务循环")
        taskJob = mainScope.launch {
            Log.d(TAG, "continueTaskLoop: 新任务循环已启动")
            performSendChatMessage(currentQuery!!, shouldGoHome = false, userResponse = null)
        }
    }
    
    /**
     * 请求安装应用
     * 当open失败时，向云侧发送安装请求
     * 在发送请求前，会先弹窗询问用户是否允许下载（使用悬浮窗，可在应用外显示）
     * 
     * 注意：此方法仅显示弹窗，不进行截图。截图操作仅在用户点击"允许"后，在executeAppInstallRequest中进行。
     */
    private fun requestAppInstall(appName: String) {
        try {
            Log.d(TAG, "requestAppInstall: 准备请求安装应用: $appName")
            
            val activity = activity
            if (activity == null) {
                Log.w(TAG, "requestAppInstall: Activity为null，无法显示弹窗")
                addChatMessage("系统", "无法显示确认弹窗")
                return
            }
            
            // 显示确认弹窗（使用悬浮窗格式，可在应用外显示）
            // 注意：此时不进行截图，截图仅在用户点击"允许"后进行
            AppInstallConfirmOverlayManager.show(
                context = activity,
                appName = appName,
                onConfirm = {
                    // 用户允许，继续执行安装请求（此时才会截图并上传）
                    Log.d(TAG, "requestAppInstall: 用户允许下载，开始执行安装请求")
                    mainScope.launch {
                        executeAppInstallRequest(appName)
                    }
                },
                onCancel = {
                    // 用户不允许，直接结束任务
                    Log.d(TAG, "requestAppInstall: 用户不允许下载，直接结束任务")
                    mainScope.launch {
                        // 重置open失败标志
                        isOpenFailed = false
                        Log.d(TAG, "requestAppInstall: 已重置isOpenFailed标志，弹窗状态: ${AppInstallConfirmOverlayManager.isDialogShowing()}")
                        // 通过助手气泡显示提示消息
                        addChatMessage("小助手", "未找到应用: $appName，任务已结束", isAnswer = true)
                        // 等待一小段时间确保弹窗完全关闭
                        delay(100)
                        // 直接结束任务
                        stopTask()
                        notifyTaskComplete()
                    }
                }
            )
        } catch (e: Exception) {
            Log.e(TAG, "requestAppInstall: 异常: ${e.message}", e)
            addChatMessage("系统", "安装请求异常: ${e.message}")
        }
    }
    
    /**
     * 执行应用安装请求（实际发送请求到云侧）
     * 此方法在用户点击"允许"后调用，先打开软件商店，然后截图并上传到云侧
     */
    private suspend fun executeAppInstallRequest(appName: String) = withContext(Dispatchers.IO) {
        try {
            Log.d(TAG, "executeAppInstallRequest: 开始执行安装请求: $appName")
            
            // 用户已点击"允许"，重置open失败标志，确保可以发送请求
            isOpenFailed = false
            Log.d(TAG, "executeAppInstallRequest: 已重置isOpenFailed标志，弹窗状态: ${AppInstallConfirmOverlayManager.isDialogShowing()}")
            
            // 确保弹窗已关闭（等待一小段时间确保弹窗完全关闭）
            delay(100)
            
            // 用户已点击"允许"，先打开软件商店
            val appStoreName = "软件商店"
            var appStorePackageName: String? = null
            
            withContext(Dispatchers.Main) {
                val activity = activity
                if (activity != null) {
                    if (isFetchInstalledAppsForCloudEnabled()) {
                        // 开关打开时：仅从已安装应用列表中查找
                        val installedMap = AppInstallHelper.getInstalledAppsNameToPackageMap(activity)
                        appStorePackageName = installedMap[appStoreName]
                            ?: installedMap.entries.find { (k, _) ->
                                k.contains(appStoreName) || appStoreName.contains(k)
                            }?.value
                    } else {
                        // 开关关闭时：先查默认映射，再查已安装应用
                        appStorePackageName = AppMappingManager.getPackageName(appStoreName)
                            ?: AppMappingManager.findPackageNameByAppName(appStoreName, activity)
                    }
                    
                    // 如果找到了包名，打开软件商店
                    if (appStorePackageName != null) {
                        Log.d(TAG, "executeAppInstallRequest: 找到软件商店包名: $appStorePackageName")
                        val mainActivity = activity as? MainActivity
                        val success = mainActivity?.launchAppFromActivity(appStorePackageName!!) ?: false
                        if (success) {
                            Log.d(TAG, "executeAppInstallRequest: 软件商店打开成功")
                            addChatMessage("系统", "正在打开软件商店...")
                        } else {
                            Log.w(TAG, "executeAppInstallRequest: 软件商店打开失败")
                            addChatMessage("系统", "打开软件商店失败，继续执行安装请求")
                        }
                    } else {
                        Log.w(TAG, "executeAppInstallRequest: 未找到软件商店包名，继续执行安装请求")
                        addChatMessage("系统", "未找到软件商店，继续执行安装请求")
                    }
                }
            }
            
            // 等待软件商店打开（延迟1.5秒）
            delay(1500)
            
            // 用户已点击"允许"，此时进行截图
            // 获取截图
            val chatService = ChatScreenshotService.getInstance()
            val bitmap = chatService?.captureScreenshot()
            
            if (bitmap == null) {
                Log.w(TAG, "executeAppInstallRequest: 截图失败，无法发送安装请求")
                withContext(Dispatchers.Main) {
                    addChatMessage("小助手", "无法获取截图，安装请求失败")
                }
                return@withContext
            }
            
            // 转换为Base64
            val screenshotBase64 = screenshotBitmapToBase64(bitmap).also { bitmap.recycle() }
            val cleanBase64 = screenshotBase64.trim().replace("\n", "").replace("\r", "").replace(" ", "")
            
            // URL编码
            val urlEncodedBase64 = try {
                java.net.URLEncoder.encode(cleanBase64, "UTF-8")
            } catch (e: Exception) {
                Log.e(TAG, "URL编码失败: ${e.message}", e)
                cleanBase64
            }
            
            // 构建安装请求query
            val installQuery = "需要安装应用: $appName"
            
            // 获取当前 Activity 信息
            val (packageName, className) = MyAccessibilityService.getCurrentActivityInfo()
            val imei = ProfileManager.getOrGenerateImei(requireContext())
            
            // 确保使用当前对话对应的服务地址
            ensureNetworkServiceInitialized()
            
            // 发送请求到云侧
            val apiService = NetworkService.getApiService()
            if (apiService == null) {
                Log.w(TAG, "executeAppInstallRequest: ApiService未初始化")
                return@withContext
            }
            
            withContext(Dispatchers.Main) {
                addChatMessage("系统", "正在请求安装应用: $appName")
            }
            
            val (response, parsedChatResponse) = try {
                val mainActivity = activity as? MainActivity
                val isBatchTesting = mainActivity?.isBatchTesting ?: false
                performCloudRequest(
                    apiService,
                    chatUuid,
                    installQuery,
                    cleanBase64,
                    urlEncodedBase64,
                    userResponse = null,
                    userExample = null,
                    chatSummary = null,
                    packageName = packageName,
                    className = className,
                    imei = imei,
                    proMode = if (isProModeEnabled) true else null,
                    batchTestMode = if (isBatchTesting) true else null
                )
            } catch (e: Exception) {
                Log.e(TAG, "executeAppInstallRequest: 发送安装请求失败: ${e.message}", e)
                withContext(Dispatchers.Main) {
                    addChatMessage("系统", "安装请求发送失败: ${e.message}")
                }
                return@withContext
            }
            
            if (response.isSuccessful) {
                val chatResponse = parsedChatResponse
                if (chatResponse != null) {
                    Log.d(TAG, "executeAppInstallRequest: 收到云侧响应: $chatResponse")
                    // 处理响应（云侧会返回install_app动作）
                    withContext(Dispatchers.Main) {
                        if (chatResponse.message != null) {
                            addChatMessage("云侧", chatResponse.message)
                        }
                    }
                    // 执行安装动作（添加异常处理，确保即使出错也能继续循环）
                    val executedActionType5 = chatResponse.action_type
                    try {
                        executeAction(chatResponse)
                        Log.d(TAG, "安装动作执行完成")
                    } catch (e: Exception) {
                        Log.e(TAG, "执行安装动作时发生异常: ${e.message}", e)
                        withContext(Dispatchers.Main) {
                            addChatMessage("系统", "执行安装动作异常: ${e.message}")
                        }
                    }
                    
                    // 执行完动作后，继续任务循环（让应用下载智能体继续工作）
                    withContext(Dispatchers.Main) {
                        if (isTaskRunning) {
                            Log.d(TAG, "安装动作执行完成，准备继续任务循环")
                            delay(actionCompletionDelayMs)
                            continueTaskLoop()
                        } else {
                            Log.w(TAG, "任务已停止，不继续循环")
                        }
                    }
                } else {
                    // 响应体为空，继续循环
                    Log.w(TAG, "executeAppInstallRequest: 响应体为空")
                    withContext(Dispatchers.Main) {
                        if (isTaskRunning) {
                            delay(2000)
                            continueTaskLoop()
                        }
                    }
                }
            } else {
                Log.w(TAG, "executeAppInstallRequest: 请求失败: ${response.code()} - ${response.message()}")
                withContext(Dispatchers.Main) {
                    addChatMessage("系统", "安装请求失败: ${response.code()}")
                    // 请求失败，继续循环重试
                    if (isTaskRunning) {
                        delay(2000)
                        continueTaskLoop()
                    }
                }
            }
        } catch (e: Exception) {
            Log.e(TAG, "executeAppInstallRequest: 异常: ${e.message}", e)
            withContext(Dispatchers.Main) {
                addChatMessage("系统", "安装请求异常: ${e.message}")
                // 异常时也继续循环，避免卡死
                if (isTaskRunning) {
                    delay(2000)
                    continueTaskLoop()
                }
            }
        }
    }
    
    /**
     * need_execution / gui_execute 等待权限时：截图与无障碍齐则启动；仅截图齐则补弹无障碍（闸门先拦截图时不会走到无障碍分支）。
     */
    private fun restorePendingCustomAssistantStateIfNeeded() {
        if (pendingCustomAssistantExecution == null && pendingCustomAssistantExecutionGlobal != null) {
            pendingCustomAssistantExecution = pendingCustomAssistantExecutionGlobal
            Log.d(TAG, "restorePendingCustomAssistantStateIfNeeded: 已恢复 pendingCustomAssistantExecution")
        }
        if (pendingCustomAssistantAfterIME == null && pendingCustomAssistantAfterIMEGlobal != null) {
            pendingCustomAssistantAfterIME = pendingCustomAssistantAfterIMEGlobal
            Log.d(TAG, "restorePendingCustomAssistantStateIfNeeded: 已恢复 pendingCustomAssistantAfterIME")
        }
    }

    private fun tryResumePendingCustomAssistantExecution(reason: String) {
        try {
            val pendingCustom = pendingCustomAssistantExecution ?: return
            val chatService = ChatScreenshotService.getInstance()
            val screenshotReady = chatService != null && chatService.isReady()
            val accessibilityReady = isAccessibilityServiceEnabled()
            when {
                screenshotReady && accessibilityReady -> {
                    Log.d(TAG, "$reason: 截图与无障碍已就绪，检查 TopoClaw 输入法后继续执行: ${pendingCustom.query}")
                    mainScope.launch {
                        try {
                            if (!ensureCustomIMEForCustomAssistantExecution(
                                    assistant = pendingCustom.assistant,
                                    query = pendingCustom.query,
                                    chatSummary = pendingCustom.chatSummary,
                                    guiExecuteContext = pendingCustom.guiExecuteContext
                                )) return@launch
                            withContext(Dispatchers.Main) {
                                pendingCustomAssistantExecution = null
                                pendingCustomAssistantExecutionGlobal = null
                                pendingCustomAssistantA11yDialogShown = false
                                pendingCustomAssistantAfterIME = null
                                pendingCustomAssistantAfterIMEGlobal = null
                                pendingCustom.guiExecuteContext?.let { assistantGuiExecuteContext = it }
                                startCustomAssistantExecution(
                                    assistant = pendingCustom.assistant,
                                    query = pendingCustom.query,
                                    chatSummary = pendingCustom.chatSummary
                                )
                            }
                        } catch (e: CancellationException) {
                            throw e
                        } catch (e: Exception) {
                            Log.e(TAG, "$reason: 输入法检查后启动失败: ${e.message}", e)
                        }
                    }
                }
                screenshotReady && !accessibilityReady && !pendingCustomAssistantA11yDialogShown -> {
                    pendingCustomAssistantA11yDialogShown = true
                    Log.d(TAG, "$reason: 截图已就绪，待无障碍，弹出无障碍引导")
                    showAccessibilityServiceDialog(
                        onCancel = {
                            val gui = pendingCustomAssistantExecution?.guiExecuteContext
                            if (gui != null) {
                                pendingCustomAssistantExecution = null
                                pendingCustomAssistantA11yDialogShown = false
                                gui.sendResult(null, "用户取消无障碍授权")
                            }
                        }
                    ) { openAccessibilitySettings() }
                    addChatMessage("系统", "需要无障碍服务才能执行操作，请前往设置开启")
                    // 关键时序：不要在设置页内立刻继续，等待用户返回应用(onResume)后再走下一步
                }
                screenshotReady && !accessibilityReady && pendingCustomAssistantA11yDialogShown -> {
                    // 已提示过无障碍：仅等待用户返回应用(onResume)后继续，避免设置页内提前触发输入法流程
                    Log.d(TAG, "$reason: 无障碍待就绪，等待用户返回应用后继续")
                    // 某些机型/系统上无障碍开关生效存在状态刷新延迟，这里补轮询，避免错过后续输入法检查。
                    ensurePendingCustomAssistantAccessibilityRecovery(reason)
                }
                else -> { /* 等待权限或服务连接 */ }
            }
        } catch (e: Exception) {
            Log.w(TAG, "tryResumePendingCustomAssistantExecution失败: ${e.message}", e)
        }
    }

    private fun ensurePendingCustomAssistantAccessibilityRecovery(reason: String) {
        if (pendingCustomAssistantExecution == null) return
        if (pendingCustomAssistantA11yReconnectJob?.isActive == true) {
            return
        }
        pendingCustomAssistantA11yReconnectJob = mainScope.launch {
            try {
                var retryCount = 0
                val maxRetries = 20
                while (retryCount < maxRetries) {
                    delay(500)
                    if (pendingCustomAssistantExecution == null) {
                        return@launch
                    }
                    if (isAccessibilityServiceEnabled()) {
                        // 仅在当前页面真正回到前台可交互时才继续，避免用户仍在系统设置页就提前推进后续动作。
                        val isUiReadyToResume =
                            isAdded &&
                            !isHidden &&
                            lifecycle.currentState.isAtLeast(androidx.lifecycle.Lifecycle.State.RESUMED) &&
                            view != null
                        if (isUiReadyToResume) {
                            Log.d(TAG, "$reason: 轮询检测到无障碍已生效，且应用已回前台，继续执行")
                            pendingCustomAssistantA11yReconnectJob = null
                            tryResumePendingCustomAssistantExecution("$reason(无障碍生效)")
                            return@launch
                        } else {
                            Log.d(TAG, "$reason: 无障碍已生效，但应用未回到前台，继续等待用户返回")
                        }
                    }
                    retryCount++
                    Log.d(TAG, "$reason: 等待无障碍状态刷新... ($retryCount/$maxRetries)")
                }
                Log.w(TAG, "$reason: 无障碍状态长时间未生效，重置弹窗标记，等待下次触发")
                pendingCustomAssistantA11yDialogShown = false
                withContext(Dispatchers.Main) {
                    addChatMessage("系统", "无障碍服务状态未及时刷新，请返回重试或再次前往设置确认已开启")
                }
            } catch (e: CancellationException) {
                throw e
            } catch (e: Exception) {
                Log.w(TAG, "ensurePendingCustomAssistantAccessibilityRecovery失败: ${e.message}", e)
            } finally {
                pendingCustomAssistantA11yReconnectJob = null
            }
        }
    }
    
    /** TopoClaw：无障碍授权后，若服务实例连接有延迟，自动轮询恢复流程。 */
    private fun tryResumePendingAccessibilityExecution(reason: String) {
        if (pendingQueryAfterAccessibility == null) return
        val hasPermission = checkAccessibilityServicePermission()
        val serviceConnected = MyAccessibilityService.getInstance() != null
        Log.d(
            TAG,
            "$reason: TopoClaw无障碍待恢复检查 - 权限已授予=$hasPermission, 服务已连接=$serviceConnected, pending=$pendingQueryAfterAccessibility"
        )
        if (hasPermission) {
            // 复用既有恢复入口，统一处理“等待服务连接后继续并检查输入法”
            if (!checkAndHandlePendingAccessibilityQuery()) {
                ensurePendingAccessibilityRecovery(reason)
            }
        } else {
            ensurePendingAccessibilityRecovery(reason)
        }
    }
    
    private fun ensurePendingAccessibilityRecovery(reason: String) {
        if (pendingQueryAfterAccessibility == null) return
        if (pendingAccessibilityReconnectJob?.isActive == true) return
        pendingAccessibilityReconnectJob = mainScope.launch {
            try {
                var retryCount = 0
                val maxRetries = 20
                while (retryCount < maxRetries) {
                    delay(500)
                    if (pendingQueryAfterAccessibility == null) {
                        return@launch
                    }
                    val hasPermission = checkAccessibilityServicePermission()
                    val serviceConnected = MyAccessibilityService.getInstance() != null
                    if (hasPermission) {
                        val handled = withContext(Dispatchers.Main) {
                            checkAndHandlePendingAccessibilityQuery()
                        }
                        if (handled) {
                            Log.d(TAG, "$reason: TopoClaw无障碍恢复轮询命中，已交由待发送恢复流程处理")
                            return@launch
                        }
                    }
                    retryCount++
                    Log.d(
                        TAG,
                        "$reason: 等待TopoClaw无障碍服务连接... ($retryCount/$maxRetries, permission=$hasPermission, connected=$serviceConnected)"
                    )
                }
                Log.w(TAG, "$reason: TopoClaw无障碍恢复轮询超时，等待下次onResume继续")
            } catch (e: CancellationException) {
                throw e
            } catch (e: Exception) {
                Log.w(TAG, "ensurePendingAccessibilityRecovery失败: ${e.message}", e)
            } finally {
                pendingAccessibilityReconnectJob = null
            }
        }
    }
    
    /**
     * 与 need_execution 一致：截图与无障碍就绪后再进入 upload 循环；否则 pending + 弹窗，授权后在 onResume 继续。
     * [guiExecuteContext] 仅 gui_execute_request：弹窗「取消」或拒绝系统截图时回传错误。
     */
    private fun beginCustomAssistantExecutionWithPermissionGate(
        assistant: CustomAssistantManager.CustomAssistant,
        query: String,
        chatSummary: String?,
        guiExecuteContext: AssistantGuiExecuteContext?
    ) {
        val chatService = ChatScreenshotService.getInstance()
        val screenshotReady = chatService != null && chatService.isReady()
        val accessibilityReady = isAccessibilityServiceEnabled()
        if (!screenshotReady) {
            pendingCustomAssistantA11yDialogShown = false
            pendingCustomAssistantExecution = PendingCustomAssistantExecution(
                assistant = assistant,
                query = query,
                chatSummary = chatSummary,
                guiExecuteContext = guiExecuteContext
            )
            pendingCustomAssistantExecutionGlobal = pendingCustomAssistantExecution
            showScreenshotPermissionDialog(
                onCancel = {
                    if (guiExecuteContext != null) {
                        pendingCustomAssistantExecution = null
                        pendingCustomAssistantExecutionGlobal = null
                        pendingCustomAssistantA11yDialogShown = false
                        guiExecuteContext.sendResult(null, "用户取消截图授权")
                    }
                }
            ) { requestChatScreenshotPermission() }
            addChatMessage("系统", "需要截图权限才能执行操作，请授权")
            return
        }
        if (!accessibilityReady) {
            pendingCustomAssistantExecution = PendingCustomAssistantExecution(
                assistant = assistant,
                query = query,
                chatSummary = chatSummary,
                guiExecuteContext = guiExecuteContext
            )
            pendingCustomAssistantExecutionGlobal = pendingCustomAssistantExecution
            pendingCustomAssistantA11yDialogShown = true
            showAccessibilityServiceDialog(
                onCancel = {
                    if (guiExecuteContext != null) {
                        pendingCustomAssistantExecution = null
                        pendingCustomAssistantExecutionGlobal = null
                        pendingCustomAssistantA11yDialogShown = false
                        guiExecuteContext.sendResult(null, "用户取消无障碍授权")
                    }
                }
            ) { openAccessibilitySettings() }
            addChatMessage("系统", "需要无障碍服务才能执行操作，请前往设置开启")
            return
        }
        mainScope.launch {
            try {
                if (!ensureCustomIMEForCustomAssistantExecution(
                        assistant = assistant,
                        query = query,
                        chatSummary = chatSummary,
                        guiExecuteContext = guiExecuteContext
                    )) return@launch
                withContext(Dispatchers.Main) {
                    pendingCustomAssistantAfterIME = null
                    pendingCustomAssistantAfterIMEGlobal = null
                    guiExecuteContext?.let { assistantGuiExecuteContext = it }
                    startCustomAssistantExecution(assistant, query, chatSummary)
                }
            } catch (e: CancellationException) {
                throw e
            } catch (e: Exception) {
                Log.e(TAG, "beginCustomAssistantExecutionWithPermissionGate: 输入法检查失败: ${e.message}", e)
            }
        }
    }
    
    /**
     * 与 [startTaskInternal] 一致：需 TopoClaw 为当前输入法；未启用则引导设置，已启用未默认则弹选择器/切换提示。
     * 若需用户操作则写入 [pendingCustomAssistantAfterIME] 并返回 false。
     */
    private suspend fun ensureCustomIMEForCustomAssistantExecution(
        assistant: CustomAssistantManager.CustomAssistant,
        query: String,
        chatSummary: String?,
        guiExecuteContext: AssistantGuiExecuteContext?
    ): Boolean {
        var accessibilityService = MyAccessibilityService.getInstance()
        if (accessibilityService == null) {
            for (i in 1..10) {
                delay(500)
                accessibilityService = MyAccessibilityService.getInstance()
                if (accessibilityService != null) break
            }
        }
        if (accessibilityService == null) {
            withContext(Dispatchers.Main) {
                addChatMessage("系统", "无障碍服务未就绪，无法检查输入法")
            }
            return false
        }
        val ctx = context ?: return false
        val customIMEId = "${ctx.packageName}/${SimpleInputMethodService::class.java.name}"
        val normalizedCustomIMEId = customIMEId.trim().lowercase()
        val imeService = SimpleInputMethodService.getInstance()
        val currentIME = accessibilityService.getCurrentIME()
        val normalizedCurrentIME = currentIME?.trim()?.lowercase()
        val isIMEIdMatch = normalizedCurrentIME == normalizedCustomIMEId
        val isCustomIMEActive = imeService != null || isIMEIdMatch
        if (isCustomIMEActive) {
            Log.d(TAG, "ensureCustomIMEForCustomAssistantExecution: 已是 TopoClaw 输入法")
            return true
        }
        val isIMEEnabled = checkIfIMEEnabled(ctx, customIMEId)
        if (!isIMEEnabled) {
            withContext(Dispatchers.Main) {
                pendingCustomAssistantExecution = null
                pendingCustomAssistantExecutionGlobal = null
                pendingCustomAssistantA11yDialogShown = false
                pendingCustomAssistantAfterIME = PendingCustomAssistantExecution(
                    assistant, query, chatSummary, guiExecuteContext
                )
                pendingCustomAssistantAfterIMEGlobal = pendingCustomAssistantAfterIME
                showIMEEnableGuideDialog(
                    customIMEId,
                    forCustomAssistantExecution = true,
                    onNegative = {
                        val gui = pendingCustomAssistantAfterIME?.guiExecuteContext
                        if (gui != null) {
                            pendingCustomAssistantAfterIME = null
                            pendingCustomAssistantAfterIMEGlobal = null
                            gui.sendResult(null, "用户取消启用输入法")
                        }
                    }
                )
                addChatMessage("系统", "需要先在系统设置中启用 TopoClaw 输入法，启用后返回本应用继续")
            }
            return false
        }
        withContext(Dispatchers.Main) {
            pendingCustomAssistantExecution = null
            pendingCustomAssistantExecutionGlobal = null
            pendingCustomAssistantA11yDialogShown = false
            pendingCustomAssistantAfterIME = PendingCustomAssistantExecution(
                assistant, query, chatSummary, guiExecuteContext
            )
            pendingCustomAssistantAfterIMEGlobal = pendingCustomAssistantAfterIME
            try {
                _binding?.etChatInput?.requestFocus()
            } catch (e: Exception) {
                Log.e(TAG, "ensureCustomIMEForCustomAssistantExecution: requestFocus: ${e.message}", e)
            }
        }
        // 从系统设置页返回时窗口焦点可能尚未恢复，直接调用 showInputMethodPicker 会静默失败。
        // 这里等待窗口可聚焦后重试几次，提升“先弹系统键盘选择器”的成功率。
        var pickerShown = false
        for (attempt in 1..8) {
            delay(500)
            val shownThisAttempt = withContext(Dispatchers.Main) {
                val imm = ctx.getSystemService(Context.INPUT_METHOD_SERVICE) as? InputMethodManager
                try {
                    val hasWindowFocus = activity?.window?.decorView?.hasWindowFocus() == true
                    val hasBindingView = _binding?.root?.windowToken != null
                    if (!hasWindowFocus && !hasBindingView) {
                        Log.d(TAG, "ensureCustomIMEForCustomAssistantExecution: 第${attempt}次弹输入法选择器前窗口未就绪，继续等待")
                        return@withContext false
                    }
                    Log.d(TAG, "ensureCustomIMEForCustomAssistantExecution: 第${attempt}次调用系统输入法选择器")
                    imm?.showInputMethodPicker()
                    true
                } catch (e: Exception) {
                    Log.e(TAG, "ensureCustomIMEForCustomAssistantExecution: showInputMethodPicker(第${attempt}次)失败: ${e.message}", e)
                    false
                }
            }
            if (shownThisAttempt) {
                pickerShown = true
                break
            }
        }
        if (!pickerShown) {
            Log.w(TAG, "ensureCustomIMEForCustomAssistantExecution: 多次尝试后仍未成功弹出输入法选择器")
        }
        for (i in 1..10) {
            delay(500)
            val newIme = SimpleInputMethodService.getInstance()
            val newIME = accessibilityService.getCurrentIME()
            val nn = newIME?.trim()?.lowercase()
            if (newIme != null || nn == normalizedCustomIMEId) {
                withContext(Dispatchers.Main) {
                    pendingCustomAssistantAfterIME = null
                    pendingCustomAssistantAfterIMEGlobal = null
                }
                Log.d(TAG, "ensureCustomIMEForCustomAssistantExecution: 已切换到 TopoClaw（${i * 500}ms）")
                return true
            }
        }
        // 首轮未成功：弹提示后再次尝试弹出系统输入法选择器，并启动后台监听
        withContext(Dispatchers.Main) {
            showIMESwitchDialogWithPicker()
        }
        startIMEChangeMonitoringForCustomAssistant()
        return false
    }
    
    /** 监听用户切换到 TopoClaw 输入法后启动自定义小助手执行（与 [startIMEChangeMonitoring] 对应） */
    private fun startIMEChangeMonitoringForCustomAssistant() {
        val pending = pendingCustomAssistantAfterIME
        if (pending == null) {
            Log.d(TAG, "startIMEChangeMonitoringForCustomAssistant: 无 pending，跳过")
            return
        }
        mainScope.launch {
            val accessibilityService = MyAccessibilityService.getInstance()
            if (accessibilityService == null) {
                Log.w(TAG, "startIMEChangeMonitoringForCustomAssistant: 无障碍未连接")
                return@launch
            }
            val customIMEId = "${requireContext().packageName}/${SimpleInputMethodService::class.java.name}"
            val normalizedCustomIMEId = customIMEId.trim().lowercase()
            delay(2000)
            val initialImeService = SimpleInputMethodService.getInstance()
            val initialIME = accessibilityService.getCurrentIME()
            val normalizedInitialIME = initialIME?.trim()?.lowercase()
            val initialIsCustomIMEActive =
                initialImeService != null || normalizedInitialIME == normalizedCustomIMEId
            if (initialIsCustomIMEActive) {
                delay(1000)
                val confirmIme = SimpleInputMethodService.getInstance()
                val confirmIME = accessibilityService.getCurrentIME()
                val n = confirmIME?.trim()?.lowercase()
                if (confirmIme != null || n == normalizedCustomIMEId) {
                    withContext(Dispatchers.Main) {
                        val p = pendingCustomAssistantAfterIME ?: return@withContext
                        pendingCustomAssistantAfterIME = null
                        pendingCustomAssistantAfterIMEGlobal = null
                        p.guiExecuteContext?.let { assistantGuiExecuteContext = it }
                        addChatMessage("系统", "输入法已就绪，继续执行…")
                        startCustomAssistantExecution(p.assistant, p.query, p.chatSummary)
                    }
                    return@launch
                }
            }
            for (i in 1..20) {
                delay(500)
                val svc = SimpleInputMethodService.getInstance()
                val cur = accessibilityService.getCurrentIME()?.trim()?.lowercase()
                val active = svc != null || cur == normalizedCustomIMEId
                if (active && !initialIsCustomIMEActive) {
                    withContext(Dispatchers.Main) {
                        val p = pendingCustomAssistantAfterIME ?: return@withContext
                        pendingCustomAssistantAfterIME = null
                        pendingCustomAssistantAfterIMEGlobal = null
                        p.guiExecuteContext?.let { assistantGuiExecuteContext = it }
                        addChatMessage("系统", "输入法已就绪，继续执行…")
                        startCustomAssistantExecution(p.assistant, p.query, p.chatSummary)
                    }
                    return@launch
                }
            }
            Log.w(TAG, "startIMEChangeMonitoringForCustomAssistant: 超时未检测到切换")
        }
    }
    
    /**
     * 自定义小助手执行流程：need_execution 后，截屏→调用 baseUrl/upload → 解析 ChatResponse → 执行动作（支持多步循环）
     */
    private fun startCustomAssistantExecution(
        assistant: CustomAssistantManager.CustomAssistant,
        query: String,
        chatSummary: String?
    ) {
        taskJob?.cancel()
        taskJob = mainScope.launch {
            try {
                // 强制走中转：APK 不再直连 assistant_base_url（仅普通任务）。
                // 但 gui_execute_request 回调场景必须保留端侧本地执行，并通过 sendResult 回传。
                val hasGuiExecuteCallback = assistantGuiExecuteContext != null
                if (!hasGuiExecuteCallback) {
                    val messageText = query.ifBlank { "[图片]" }
                    val ws = (activity as? MainActivity)?.getCustomerServiceWebSocket()
                    if (ws != null && ws.isConnected()) {
                        val msgId = java.util.UUID.randomUUID().toString()
                        ws.sendMobileExecutePcCommand(
                            query = messageText,
                            assistantBaseUrl = assistant.baseUrl,
                            conversationId = currentConversation?.id ?: assistant.id,
                            messageId = msgId,
                            chatSummary = (chatSummary ?: messageText).take(80)
                        )
                        addChatMessage("系统", "已通过中转发送到电脑端执行…")
                    } else {
                        addChatMessage("系统", "电脑执行通道未连接，请确保电脑端在线")
                    }
                    return@launch
                }

                val ws = (activity as? MainActivity)?.getCustomerServiceWebSocket()
                if (ws == null || !ws.isConnected()) {
                    addChatMessage("系统", "中转执行通道未连接")
                    assistantGuiExecuteContext?.let { it.sendResult(null, "中转执行通道未连接"); assistantGuiExecuteContext = null }
                    return@launch
                }
                // 轻量方案：设置任务状态并启动悬浮球转圈
                withContext(Dispatchers.Main) {
                    if (isAdded && _binding != null) {
                        isTaskRunning = true
                        (activity as? MainActivity)?.isTaskRunning = true
                        TaskIndicatorOverlayManager.updateOverlayForTaskStatus(true)
                        val mainActivity = activity as? MainActivity
                        if (mainActivity != null) {
                            val prefs = requireContext().getSharedPreferences("app_prefs", android.content.Context.MODE_PRIVATE)
                            val overlayEnabled = prefs.getBoolean("task_indicator_overlay_enabled", true)
                            if (overlayEnabled && !TaskIndicatorOverlayManager.isOverlayShowing()) {
                                TaskIndicatorOverlayManager.show(mainActivity)
                            }
                        }
                    }
                }
                // gui_execute_request 场景：先回到 Android 桌面再开始截图
                val accessibilityService = MyAccessibilityService.getInstance()
                if (accessibilityService != null) {
                    Log.d(TAG, "gui_execute_request：先回到 Android 桌面")
                    accessibilityService.goHome()
                    delay(1000)
                } else {
                    Log.w(TAG, "gui_execute_request：无障碍服务不可用，无法回到桌面")
                }

                val taskUuid = java.util.UUID.randomUUID().toString()
                val maxSteps = 20
                var step = 0
                var pendingGuiReasoning: String? = null
                addChatMessage("系统", "正在执行操作...")
                while (step < maxSteps && isAdded && isTaskRunning) {
                    step++
                    val chatService = ChatScreenshotService.getInstance()
                    val bitmap = withContext(Dispatchers.IO) { chatService?.captureScreenshot() }
                    if (bitmap == null) {
                        addChatMessage("系统", "截图失败，无法继续执行")
                        assistantGuiExecuteContext?.let { it.sendResult(null, "截图失败"); assistantGuiExecuteContext = null }
                        return@launch
                    }
                    currentOriginalImageWidth = bitmap.width
                    currentOriginalImageHeight = bitmap.height
                    val rawBase64 = screenshotBitmapToBase64(bitmap).also { bitmap.recycle() }
                    val cleanBase64 = rawBase64.trim().replace("\n", "").replace("\r", "").replace(" ", "")
                    // 参考主任务链路：截图完成后再展示上一轮推理，避免推理层进入下一张截图。
                    pendingGuiReasoning?.let { reasoning ->
                        val ctx = context
                        if (ctx != null) {
                            withContext(Dispatchers.Main) {
                                ReasoningOverlayManager.show(ctx, reasoning)
                            }
                            pendingGuiReasoning = null
                            Log.d(TAG, "自定义小助手：截图完成后显示reasoning悬浮窗")
                        }
                    }
                    val (packageName, _) = MyAccessibilityService.getCurrentActivityInfo()
                    val stepResponse = try {
                        ws.sendGuiStepRequest(
                            guiRequestId = assistantGuiExecuteContext?.requestId ?: taskUuid,
                            query = query,
                            screenshotBase64 = cleanBase64,
                            threadId = currentConversation?.id,
                            packageName = packageName,
                            userResponse = null,
                            timeoutMs = 120000L,
                        )
                    } catch (e: Exception) {
                        Log.e(TAG, "自定义小助手中转步骤请求异常: ${e.message}", e)
                        addChatMessage("系统", "请求失败: ${e.message}")
                        assistantGuiExecuteContext?.let { it.sendResult(null, "请求失败: ${e.message}"); assistantGuiExecuteContext = null }
                        return@launch
                    }
                    val ok = stepResponse.optBoolean("success", false)
                    if (!ok) {
                        val err = stepResponse.optString("error", "中转步骤失败")
                        addChatMessage("系统", "请求失败: ${err.take(120)}")
                        assistantGuiExecuteContext?.let { it.sendResult(null, err); assistantGuiExecuteContext = null }
                        return@launch
                    }
                    val chatResponseJson = stepResponse.optJSONObject("chat_response")
                    val chatResponse = chatResponseJson?.let {
                        com.google.gson.Gson().fromJson(it.toString(), ChatResponse::class.java)
                    } ?: run {
                        val serverError = stepResponse.optString("error", "").trim()
                        val errMsg = if (serverError.isNotEmpty()) "请求失败: ${serverError.take(120)}" else "响应格式错误: chat_response 为空"
                        addChatMessage("系统", errMsg)
                        assistantGuiExecuteContext?.let { it.sendResult(null, errMsg); assistantGuiExecuteContext = null }
                        return@launch
                    }
                    val actionType = chatResponse.action_type?.lowercase()
                    Log.d(TAG, "自定义小助手 upload 响应: action_type=$actionType, step=$step")
                    withContext(Dispatchers.Main) {
                        // 收到新响应先收起推理浮层，保证执行动作阶段不显示推理。
                        ReasoningOverlayManager.hide()
                        pendingGuiReasoning = if (actionType != null && !chatResponse.reason.isNullOrBlank()) {
                            chatResponse.reason
                        } else {
                            null
                        }
                    }
                    // 给浮层隐藏留一个小缓冲，避免与后续动作执行重叠。
                    delay(100)

                    // 终端动作：直接结束
                    when (actionType) {
                        "complete" -> {
                            val text = chatResponse.params ?: chatResponse.thought ?: chatResponse.reason ?: "任务已完成"
                            val pcCtx = assistantPcExecuteContext
                            val guiCtx = assistantGuiExecuteContext
                            // GUI 回调场景只回传结果，不在当前聊天窗口落气泡，避免展示模型中间总结文本。
                            if (guiCtx == null) {
                                addChatMessage(assistant.name, text, isComplete = true)
                            }
                            if (pcCtx != null) {
                                withContext(Dispatchers.Main) {
                                    (activity as? MainActivity)?.getCustomerServiceWebSocket()
                                        ?.sendExecuteResult(text, pcCtx.messageId, pcCtx.uuid, pcCtx.conversationId)
                                    assistantPcExecuteContext = null
                                    Log.d(TAG, "自定义小助手 PC 执行结果(complete)已发送")
                                }
                            }
                            if (guiCtx != null) {
                                withContext(Dispatchers.Main) {
                                    guiCtx.sendResult(text, null)
                                    assistantGuiExecuteContext = null
                                    Log.d(TAG, "自定义小助手 GUI 执行结果(complete)已发送")
                                }
                            }
                            return@launch
                        }
                        "call_user" -> {
                            val msg = chatResponse.params ?: chatResponse.message ?: "需要您确认"
                            addChatMessage(assistant.name, msg, isAnswer = true)
                            val pcCtx = assistantPcExecuteContext
                            val guiCtx = assistantGuiExecuteContext
                            if (pcCtx != null) {
                                withContext(Dispatchers.Main) {
                                    (activity as? MainActivity)?.getCustomerServiceWebSocket()
                                        ?.sendExecuteResult(msg, pcCtx.messageId, pcCtx.uuid, pcCtx.conversationId)
                                    assistantPcExecuteContext = null
                                    Log.d(TAG, "自定义小助手 PC 执行结果(call_user)已发送")
                                }
                            }
                            if (guiCtx != null) {
                                withContext(Dispatchers.Main) {
                                    guiCtx.sendResult(msg, null)
                                    assistantGuiExecuteContext = null
                                    Log.d(TAG, "自定义小助手 GUI 执行结果(call_user)已发送")
                                }
                            }
                            return@launch
                        }
                        "answer" -> {
                            val text = chatResponse.params ?: chatResponse.message ?: chatResponse.thought ?: ""
                            if (text.isNotBlank()) addChatMessage(assistant.name, text, isAnswer = true)
                            val guiCtx = assistantGuiExecuteContext
                            if (guiCtx != null && text.isNotBlank()) {
                                withContext(Dispatchers.Main) {
                                    guiCtx.sendResult(text, null)
                                    assistantGuiExecuteContext = null
                                    Log.d(TAG, "自定义小助手 GUI 执行结果(answer)已发送")
                                }
                            }
                            return@launch
                        }
                        else -> {
                            // 所有屏幕操作（click、swipe、type、open、back、home、long_press、wait 等）统一走 executeAction
                            customAssistantShouldStop = false
                            try {
                                executeAction(chatResponse, fromCustomAssistant = true)
                            } catch (e: Exception) {
                                Log.e(TAG, "自定义小助手 executeAction 异常: ${e.message}", e)
                                addChatMessage("系统", "执行异常: ${e.message}")
                                return@launch
                            }
                            if (customAssistantShouldStop) {
                                return@launch
                            }
                            delay(actionCompletionDelayMs)
                        }
                    }
                }
                if (step >= maxSteps) {
                    addChatMessage("系统", "已执行 $maxSteps 步，停止继续执行")
                    val guiCtx = assistantGuiExecuteContext
                    if (guiCtx != null) {
                        withContext(Dispatchers.Main) {
                            guiCtx.sendResult(null, "已执行 $maxSteps 步停止")
                            assistantGuiExecuteContext = null
                        }
                    }
                }
            } catch (e: CancellationException) {
                Log.d(TAG, "自定义小助手执行协程已取消")
            } catch (e: Exception) {
                Log.e(TAG, "自定义小助手执行异常: ${e.message}", e)
                addChatMessage("系统", "执行异常: ${e.message}")
                val guiCtx = assistantGuiExecuteContext
                if (guiCtx != null) {
                    withContext(Dispatchers.Main) {
                        guiCtx.sendResult(null, e.message ?: "执行异常")
                        assistantGuiExecuteContext = null
                    }
                }
            } finally {
                withContext(Dispatchers.Main) {
                    if (isAdded) {
                        taskJob = null
                        isTaskRunning = false
                        isCustomAssistantProcessing = false
                        (activity as? MainActivity)?.isTaskRunning = false
                        TaskIndicatorOverlayManager.updateOverlayForTaskStatus(false)
                        val mainActivity = activity as? MainActivity
                        if (mainActivity != null && !TaskIndicatorOverlayManager.isCompanionModeEnabled(requireContext())) {
                            TaskIndicatorOverlayManager.hide()
                        }
                        // PC 端或端侧发起：任务完成后都切回应用，便于用户查看结果
                        mainActivity?.bringAppToForeground()
                    }
                }
            }
        }
    }
    
    /**
     * 用户通过悬浮球手动结束任务：终止本地执行并向 gui_execute_request 回传手动结束结果。
     */
    fun stopTaskFromOverlayByUser() {
        val manualStopMessage = "用户手动结束任务"
        val guiCtx = assistantGuiExecuteContext
            ?: pendingCustomAssistantExecution?.guiExecuteContext
            ?: pendingCustomAssistantAfterIME?.guiExecuteContext
        val stopThreadId = guiCtx?.threadId?.takeIf { it.isNotBlank() }
        if (guiCtx != null) {
            try {
                guiCtx.sendResult(manualStopMessage, null)
                Log.d(TAG, "已向 GUI 执行回传手动结束结果")
            } catch (e: Exception) {
                Log.e(TAG, "回传 GUI 手动结束结果失败: ${e.message}", e)
            }
        }
        if (stopThreadId != null) {
            try {
                val ws = (activity as? MainActivity)?.getCustomerServiceWebSocket()
                val stopPayload = JSONObject().apply {
                    put("type", "stop")
                    put("thread_id", stopThreadId)
                    put("timestamp", System.currentTimeMillis())
                }
                val sent = ws?.sendCustomMessage(stopPayload) ?: false
                if (sent) {
                    Log.d(TAG, "悬浮球手动结束：已发送全任务 stop, thread_id=$stopThreadId")
                } else {
                    Log.w(TAG, "悬浮球手动结束：发送全任务 stop 失败, thread_id=$stopThreadId")
                }
            } catch (e: Exception) {
                Log.e(TAG, "悬浮球手动结束：发送全任务 stop 异常: ${e.message}", e)
            }
        }
        assistantGuiExecuteContext = null
        pendingCustomAssistantExecution = null
        pendingCustomAssistantExecutionGlobal = null
        pendingCustomAssistantAfterIME = null
        pendingCustomAssistantAfterIMEGlobal = null
        addChatMessage("小助手", manualStopMessage, isAnswer = true)
        stopTask()
    }
    
    /**
     * 格式化reason为思考文本（用于拼接到系统消息同一行）
     */
    private fun formatReasonAsThought(reason: String?): String {
        if (reason.isNullOrBlank()) {
            return ""
        }
        // 将 reason: xxx 格式转换为 思考：xxx
        val thoughtText = if (reason.startsWith("reason:", ignoreCase = true)) {
            reason.substring(7).trim()
        } else if (reason.startsWith("reason：", ignoreCase = true)) {
            reason.substring(8).trim()
        } else {
            reason
        }
        return " 思考：$thoughtText"
    }
    
    /**
     * 执行动作（TopoClaw的统一执行逻辑）
     * @param fromCustomAssistant 若为 true，则跳过动作前截图上传、long_screenshot 时不调用 continueTaskLoop，open 失败时设置 customAssistantShouldStop
     */
    private suspend fun executeAction(chatResponse: ChatResponse, fromCustomAssistant: Boolean = false) {
        val actionType = chatResponse.action_type ?: return
        Log.d(TAG, "executeAction: actionType=$actionType, reason=${chatResponse.reason}, thought=${chatResponse.thought}, fromCustomAssistant=$fromCustomAssistant")

        // 防止long_screenshot无限循环：如果最近一次执行的动作是long_screenshot，且云侧又返回long_screenshot，则跳过执行
        if (actionType.lowercase() == "long_screenshot" && lastExecutedActionType == "long_screenshot") {
            Log.w(TAG, "检测到连续两次long_screenshot动作，跳过执行避免无限循环")
            withContext(Dispatchers.Main) {
                addChatMessage("系统", "长截图动作已跳过（防止无限循环）")
            }
            delay(actionCompletionDelayMs)
            if (!fromCustomAssistant && isTaskRunning) {
                continueTaskLoop()
            }
            return
        }
        
        // 记录当前执行的动作类型
        lastExecutedActionType = actionType.lowercase()
        
        // 动作执行前：截图并上传到对比文件夹（仅在点击和长按动作时执行，其他动作不增加耗时）
        // 使用缓存的开关状态（避免每次动作执行前都读取SharedPreferences，减少耗时）
        val actionTypeLower = actionType.lowercase()
        val shouldCaptureBeforeAction = !fromCustomAssistant && sendBeforeActionImageEnabled && 
            (actionTypeLower == "click" || actionTypeLower == "long_press")

        if (shouldCaptureBeforeAction) {
            Log.d(TAG, "[动作对比] 开始动作前截图流程: actionType=$actionType, step=$currentStep")
            try {
                val chatService = ChatScreenshotService.getInstance()
                if (chatService == null) {
                    Log.w(TAG, "[动作对比] ChatScreenshotService未初始化")
                } else {
                    val beforeActionBitmap = chatService.captureScreenshot()
                    if (beforeActionBitmap == null) {
                        Log.w(TAG, "[动作对比] 动作前截图获取失败")
                    } else {
                        Log.d(TAG, "[动作对比] 动作前截图获取成功，开始转换为Base64")
                        val beforeActionBase64 = screenshotBitmapToBase64(beforeActionBitmap).also { 
                            beforeActionBitmap.recycle() 
                        }
                        Log.d(TAG, "[动作对比] Base64转换完成，长度: ${beforeActionBase64.length}")
                        
                        // 检查是否有medium截图
                        val mediumBase64 = mediumScreenshotBase64
                        if (mediumBase64 != null) {
                            Log.d(TAG, "[动作对比] 检测到medium截图，将发送两张图: medium+动作前")
                        } else {
                            Log.d(TAG, "[动作对比] 未检测到medium截图，只发送动作前截图")
                        }
                        
                        // 异步上传，不阻塞动作执行
                        mainScope.launch(Dispatchers.IO) {
                            try {
                                val apiService = NetworkService.getApiService()
                                if (apiService == null) {
                                    Log.w(TAG, "[动作对比] ApiService未初始化")
                                } else if (chatUuid.isEmpty()) {
                                    Log.w(TAG, "[动作对比] chatUuid为空")
                                } else {
                                    // 如果有medium截图，发送两张图；否则只发送动作前截图
                                    if (mediumBase64 != null) {
                                        Log.d(TAG, "[动作对比] 开始上传两张截图: medium+动作前, uuid=$chatUuid, step=$currentStep")
                                        
                                        // URL编码base64字符串
                                        val urlEncodedMediumBase64 = try {
                                            java.net.URLEncoder.encode(mediumBase64, "UTF-8")
                                        } catch (e: Exception) {
                                            Log.e(TAG, "[动作对比] medium截图URL编码失败: ${e.message}", e)
                                            mediumBase64
                                        }
                                        
                                        val urlEncodedBeforeActionBase64 = try {
                                            java.net.URLEncoder.encode(beforeActionBase64, "UTF-8")
                                        } catch (e: Exception) {
                                            Log.e(TAG, "[动作对比] 动作前截图URL编码失败: ${e.message}", e)
                                            beforeActionBase64
                                        }
                                        
                                        // 使用sendChatMessage发送两张图（medium作为image，动作前作为image2）
                                        val response = apiService.sendChatMessage(
                                            uuid = chatUuid,
                                            query = "",  // 空query，仅用于发送对比截图
                                            image = urlEncodedMediumBase64,
                                            image2 = urlEncodedBeforeActionBase64,
                                            outputLanguage = LanguageManager.getSavedLanguage(requireContext()),
                                            installApps = getInstallAppsParamForUpload()
                                        )
                                        
                                        if (response.isSuccessful) {
                                            Log.d(TAG, "[动作对比] 两张截图上传成功: step=$currentStep, actionType=$actionType")
                                        } else {
                                            Log.w(TAG, "[动作对比] 两张截图上传失败: code=${response.code()}, message=${response.message()}")
                                        }
                                        
                                        // 发送后清空medium截图
                                        mediumScreenshotBase64 = null
                                    } else {
                                        // 没有medium截图，使用原有逻辑只发送动作前截图
                                        Log.d(TAG, "[动作对比] 开始上传动作前截图: uuid=$chatUuid, step=$currentStep")
                                        
                                        val urlEncodedBase64 = try {
                                            java.net.URLEncoder.encode(beforeActionBase64, "UTF-8")
                                        } catch (e: Exception) {
                                            Log.e(TAG, "[动作对比] URL编码失败: ${e.message}", e)
                                            beforeActionBase64
                                        }
                                        
                                        val response = apiService.saveActionComparisonScreenshot(
                                            uuid = chatUuid,
                                            step = currentStep,  // 使用当前步骤号
                                            actionType = actionTypeLower,
                                            image = urlEncodedBase64
                                        )
                                        if (response.isSuccessful) {
                                            Log.d(TAG, "[动作对比] 动作前截图上传成功: step=$currentStep, actionType=$actionType")
                                        } else {
                                            Log.w(TAG, "[动作对比] 动作前截图上传失败: code=${response.code()}, message=${response.message()}")
                                        }
                                    }
                                }
                            } catch (e: Exception) {
                                Log.e(TAG, "[动作对比] 动作前截图上传异常: ${e.message}", e)
                            }
                        }
                    }
                }
            } catch (e: Exception) {
                Log.e(TAG, "[动作对比] 动作前截图异常: ${e.message}", e)
            }
        } else {
            // 如果不是点击/长按动作，清空medium截图（不保存）
            if (mediumScreenshotBase64 != null) {
                Log.d(TAG, "[动作对比] 动作类型($actionType)不是点击/长按，清空medium截图")
                mediumScreenshotBase64 = null
            }
        }
        // 注意：对于非点击/长按动作，直接跳过，不增加任何耗时（仅一次布尔判断）
        
        // 递增步骤号
        currentStep++
        
        // 记录动作开始时间，用于监测单步超时（2分钟）
        val actionStartTime = System.currentTimeMillis()
        val TIMEOUT_DURATION = 2 * 60 * 1000L // 2分钟（毫秒）
        
        // 检查超时的辅助函数
        suspend fun checkTimeout(): Boolean {
            val elapsedTime = System.currentTimeMillis() - actionStartTime
            if (elapsedTime > TIMEOUT_DURATION) {
                Log.w(TAG, "动作执行超时: actionType=$actionType, elapsedTime=${elapsedTime}ms")
                withContext(Dispatchers.Main) {
                    // 停止任务
                    stopTask()
                    // 返回应用
                    (activity as? MainActivity)?.bringAppToForeground()
                    // 显示超时消息
                    addChatMessage("系统", "任务超时")
                }
                return true
            }
            return false
        }
        
        // 检查暂停的辅助函数
        suspend fun checkPaused(): Boolean {
            if (isTaskPaused) {
                Log.d(TAG, "动作执行过程中任务已暂停: actionType=$actionType")
                return true
            }
            return false
        }
        
        // 在执行动作前检查是否已经超时（防止动作执行时间过长）
        if (checkTimeout()) {
            return
        }
        
        // 在执行动作前检查是否已暂停
        if (checkPaused()) {
            return
        }
        
        when (actionType.lowercase()) {
            "open" -> {
                val appName = chatResponse.app_name
                if (appName != null) {
                    // 获取包名（需要在主线程）
                    val (packageName, targetPackageName) = withContext(Dispatchers.Main) {
                        val ctx = activity ?: return@withContext Pair(null, null)
                        val (fromDefaultMapping, targetPkgName) = if (isFetchInstalledAppsForCloudEnabled()) {
                            // 开关打开时：仅从「获取的已安装应用」列表中查找，不使用默认映射表
                            val installedMap = AppInstallHelper.getInstalledAppsNameToPackageMap(ctx)
                            val exact = installedMap[appName]
                            val found = if (exact != null) {
                                Log.d(TAG, "从已安装应用列表找到包名(精确): $appName -> $exact")
                                exact
                            } else {
                                installedMap.entries.find { (k, _) ->
                                    k.contains(appName) || appName.contains(k)
                                }?.value?.also {
                                    Log.d(TAG, "从已安装应用列表找到包名(模糊): $appName -> $it")
                                }
                            }
                            Pair(null, found)  // fromDefaultMapping=null 表示非默认映射
                        } else {
                            // 开关关闭时：先查默认映射表，再查已安装应用
                            val pkg = AppMappingManager.getPackageName(appName)
                            if (pkg != null) {
                                Pair(pkg, pkg)
                            } else {
                                val found = AppMappingManager.findPackageNameByAppName(appName, ctx)
                                if (found != null) {
                                    Log.d(TAG, "从已安装应用中找到包名: $appName -> $found")
                                    AppMappingManager.addMapping(appName, found)
                                }
                                Pair(null, found)
                            }
                        }
                        if (targetPkgName == null) {
                            if (!fromCustomAssistant) {
                                isOpenFailed = true
                                Log.d(TAG, "未找到应用，准备显示下载许可弹窗: $appName")
                                mainScope.launch { requestAppInstall(appName) }
                            }
                            addChatMessage("系统", "✗ 未找到应用: $appName")
                            return@withContext Pair(null, null)
                        }
                        Pair(fromDefaultMapping, targetPkgName)
                    }
                    
                    if (targetPackageName == null) {
                        // 未找到包名，open失败
                        if (fromCustomAssistant) {
                            customAssistantShouldStop = true
                        } else {
                            isOpenFailed = true
                        }
                        // 检查超时和暂停
                        if (checkTimeout() || checkPaused()) {
                            return
                        }
                        // open失败时直接返回，不继续任务循环
                        return
                    }
                    
                    // 在执行open动作前再次检查暂停
                    if (checkPaused()) {
                        return
                    }
                    
                    // 执行open动作（需要在主线程）
                    val success = withContext(Dispatchers.Main) {
                        (activity as? MainActivity)?.launchAppFromActivity(targetPackageName) ?: false
                    }
                    
                    if (!success) {
                        withContext(Dispatchers.Main) {
                            addChatMessage("系统", "✗ 打开应用失败: $appName")
                        }
                        if (!fromCustomAssistant) {
                            isOpenFailed = true
                            Log.d(TAG, "open失败，准备显示下载许可弹窗: $appName")
                            mainScope.launch { requestAppInstall(appName) }
                        }
                        // 检查超时和暂停
                        if (checkTimeout() || checkPaused()) {
                            return
                        }
                        return
                    }
                    
                    // 在执行open动作前再次检查暂停
                    if (checkPaused()) {
                        return
                    }
                    
                    withContext(Dispatchers.Main) {
                        val reasonText = formatReasonAsThought(chatResponse.reason)
                        addChatMessage("系统", "正在打开应用: $appName$reasonText")
                    }
                    
                    // 检测应用是否真的打开（可能需要用户允许权限）
                    // 轮询检测应用是否成功打开，如果没打开则等待用户操作
                    // 注意：将等待逻辑移出withContext，避免阻塞主线程
                    // 新应用打开时，无障碍服务需要时间接收事件并更新包名，先等待一下
                    delay(800) // 等待无障碍服务接收事件并更新包名
                    
                    val maxWaitTime = 5000L // 减少等待时间到5秒（因为已经等待了800ms）
                    val checkInterval = 300L // 减少检测间隔到300ms，提高响应速度
                    val startTime = System.currentTimeMillis()
                    var appOpened = false
                    
                    while (System.currentTimeMillis() - startTime < maxWaitTime) {
                        // 检查是否已暂停
                        if (checkPaused()) {
                            Log.d(TAG, "等待应用打开时任务已暂停，停止等待")
                            return
                        }
                        val (currentPackageName, _) = MyAccessibilityService.getCurrentActivityInfo()
                        if (currentPackageName == targetPackageName) {
                            // 应用已成功打开
                            appOpened = true
                            Log.d(TAG, "检测到应用已成功打开: $appName ($targetPackageName)")
                            withContext(Dispatchers.Main) {
                                addChatMessage("系统", "✓ 已打开应用: $appName")
                            }
                            break
                        }
                        delay(checkInterval)
                    }
                    
                    if (!appOpened) {
                        // 应用还没打开，可能是需要用户允许权限，或者无障碍服务还没更新包名
                        // 继续等待用户操作，但减少等待时间
                        Log.d(TAG, "应用可能正在启动或需要用户允许权限，继续等待...")
                        withContext(Dispatchers.Main) {
                            addChatMessage("系统", "等待应用打开或用户允许权限...")
                        }
                        
                        // 继续轮询检测，直到应用打开或超时（减少到10秒）
                        val extendedMaxWaitTime = 10000L
                        val extendedStartTime = System.currentTimeMillis()
                        val extendedCheckInterval = 300L
                        
                        while (System.currentTimeMillis() - extendedStartTime < extendedMaxWaitTime) {
                            // 检查是否已暂停
                            if (checkPaused()) {
                                Log.d(TAG, "等待应用打开时任务已暂停，停止等待")
                                return
                            }
                            val (currentPackageName, _) = MyAccessibilityService.getCurrentActivityInfo()
                            if (currentPackageName == targetPackageName) {
                                // 应用已成功打开（用户已允许权限）
                                appOpened = true
                                Log.d(TAG, "检测到应用已成功打开（用户已允许）: $appName ($targetPackageName)")
                                withContext(Dispatchers.Main) {
                                    addChatMessage("系统", "✓ 已打开应用: $appName")
                                }
                                break
                            }
                            delay(extendedCheckInterval)
                        }
                        
                        if (!appOpened) {
                            // 超时仍未打开，但可能应用已经打开了，只是无障碍服务还没更新
                            // 不显示错误，直接继续，让后续的截图来验证
                            Log.w(TAG, "等待超时，但继续执行（可能应用已打开但无障碍服务未及时更新）: $appName")
                            withContext(Dispatchers.Main) {
                                addChatMessage("系统", "应用可能已打开，继续执行...")
                            }
                            // 假设应用已打开，继续执行
                            appOpened = true
                        }
                    }
                    
                    // 如果open成功，检查是否需要提取并记录包名（用于安装后的应用）
                    if (appOpened && (packageName == null || AppMappingManager.getPackageName(appName) == null)) {
                        // 可能是刚安装的应用，等待应用完全打开后提取包名
                        delay(1000) // 等待应用完全打开
                        val (currentPackageName, _) = MyAccessibilityService.getCurrentActivityInfo()
                        if (currentPackageName != null && currentPackageName != "com.cloudcontrol.demo" && currentPackageName == targetPackageName) {
                            // 提取到包名，添加到映射
                            Log.d(TAG, "检测到应用已打开，提取包名: $appName -> $currentPackageName")
                            withContext(Dispatchers.Main) {
                                AppMappingManager.addMapping(appName, currentPackageName)
                                addChatMessage("系统", "✓ 已记录应用映射: $appName -> $currentPackageName")
                            }
                        }
                    }
                    
                    // 应用打开后，只等待很短时间让应用界面稳定，然后立即返回，让continueTaskLoop()能够执行
                    // 减少等待时间，避免阻塞太久
                    if (appOpened) {
                        delay(500) // 进一步减少等待时间到500ms，让应用界面基本稳定即可
                        Log.d(TAG, "应用已打开，等待完成，准备继续任务循环")
                    }
                    
                    // 检查超时和暂停
                    if (checkTimeout() || checkPaused()) {
                        return
                    }
                }
            }
            "click" -> {
                val (compressedX, compressedY) = if (chatResponse.click != null && chatResponse.click.size >= 2) {
                    Pair(chatResponse.click[0], chatResponse.click[1])
                } else if (chatResponse.x != null && chatResponse.y != null) {
                    Pair(chatResponse.x, chatResponse.y)
                } else {
                    Pair(null, null)
                }
                
                if (compressedX != null && compressedY != null) {
                    // 将压缩后坐标映射回原始屏幕坐标
                    val (x, y) = mapCompressedCoordinateToOriginal(compressedX, compressedY)
                    
                    val accessibilityService = MyAccessibilityService.getInstance()
                    if (accessibilityService != null && Build.VERSION.SDK_INT >= Build.VERSION_CODES.N) {
                        // 显示点击效果（使用原始坐标）
                        withContext(Dispatchers.Main) {
                            InteractionOverlayManager.showClickEffect(x, y)
                        }
                        
                        // 模型发起：点击前设置 IME 零高度模式，避免点击输入框时键盘弹出
                        MyAccessibilityService.prepareForModelInput()
                        
                        val success = withContext(Dispatchers.Main) {
                            val result = accessibilityService.performClick(x, y, fromModel = true)
                            // 无论成功与否都需恢复 IME 模式，否则用户手动点输入框时键盘不弹
                            MyAccessibilityService.hideKeyboardAfterClickWithRetries()
                            result
                        }
                        withContext(Dispatchers.Main) {
                            val reasonText = formatReasonAsThought(chatResponse.reason)
                            if (success) {
                                addChatMessage("系统", "✓ 已执行点击: ($x, $y)$reasonText")
                            } else {
                                addChatMessage("系统", "✗ 点击失败: ($x, $y)$reasonText")
                            }
                        }
                        delay(500)
                    } else {
                        // 无障碍服务未就绪，显示弹窗
                        withContext(Dispatchers.Main) {
                            showAccessibilityServiceDialog {
                                openAccessibilitySettings()
                            }
                            addChatMessage("系统", "需要无障碍服务才能执行点击操作")
                        }
                        return
                    }
                    // 检查超时和暂停
                    if (checkTimeout() || checkPaused()) {
                        return
                    }
                }
            }
            "type" -> {
                var x: Int? = null
                var y: Int? = null
                var inputText: String? = null
                var hasCoordinates = false  // 标记是否有坐标
                
                // 优先从type字段获取参数
                val typeParams = chatResponse.type
                if (typeParams != null) {
                    when (typeParams.size) {
                        1 -> {
                            // 格式：[text] - 只有文本，没有坐标，直接输入到当前聚焦的输入框
                            inputText = when (val textParam = typeParams[0]) {
                                is String -> textParam
                                is Number -> textParam.toString()
                                else -> textParam.toString()
                            }
                            hasCoordinates = false
                            Log.d(TAG, "检测到type格式: [text]，将直接输入到当前聚焦的输入框")
                        }
                        3 -> {
                            // 格式：[x, y, text] - 完整格式，先点击坐标再输入
                            x = (typeParams[0] as? Number)?.toInt()
                            y = (typeParams[1] as? Number)?.toInt()
                            inputText = when (val textParam = typeParams[2]) {
                                is String -> textParam
                                is Number -> textParam.toString()
                                else -> textParam.toString()
                            }
                            hasCoordinates = true
                            Log.d(TAG, "检测到type格式: [x, y, text]，将先点击坐标再输入")
                        }
                        else -> {
                            Log.w(TAG, "type字段格式不支持: size=${typeParams.size}，期望1或3")
                        }
                    }
                } else {
                    // 如果type字段不存在，尝试从text字段解析（格式："x,y,text"）
                    val textField = chatResponse.text
                    if (textField != null && textField.contains(",")) {
                        val parts = textField.split(",")
                        if (parts.size >= 3) {
                            try {
                                x = parts[0].trim().toIntOrNull()
                                y = parts[1].trim().toIntOrNull()
                                // 文本可能包含逗号，所以取后面所有部分
                                inputText = parts.subList(2, parts.size).joinToString(",").trim()
                                hasCoordinates = true
                                Log.d(TAG, "从text字段解析到坐标格式: x=$x, y=$y, text=$inputText")
                            } catch (e: Exception) {
                                Log.e(TAG, "解析text字段失败: ${e.message}")
                                withContext(Dispatchers.Main) {
                                    addChatMessage("系统", "✗ 解析type动作参数失败: $textField")
                                }
                                return
                            }
                        } else if (parts.size == 1) {
                            // 如果只有一个部分，可能是纯文本格式（兼容处理）
                            inputText = parts[0].trim()
                            hasCoordinates = false
                            Log.d(TAG, "从text字段解析到纯文本格式: text=$inputText")
                        }
                    } else if (textField != null) {
                        // text字段存在但不包含逗号，作为纯文本处理
                        inputText = textField
                        hasCoordinates = false
                        Log.d(TAG, "从text字段解析到纯文本: text=$inputText")
                    }
                }
                
                // 验证参数：至少需要文本
                if (inputText == null) {
                    Log.e(TAG, "type动作参数不完整: 缺少文本内容, type=$typeParams, textField=${chatResponse.text}")
                    withContext(Dispatchers.Main) {
                        addChatMessage("系统", "✗ type动作参数不完整: 缺少文本内容")
                    }
                    return
                }
                
                // 如果有坐标，验证坐标完整性
                if (hasCoordinates && (x == null || y == null)) {
                    Log.e(TAG, "type动作参数不完整: 坐标格式错误, x=$x, y=$y, text=$inputText")
                    withContext(Dispatchers.Main) {
                        addChatMessage("系统", "✗ type动作参数不完整: 坐标格式错误")
                    }
                    return
                }
                
                val accessibilityService = MyAccessibilityService.getInstance()
                if (accessibilityService != null && Build.VERSION.SDK_INT >= Build.VERSION_CODES.N) {
                    Log.d(TAG, "========== TYPE操作开始 ==========")
                    Log.d(TAG, "输入文本: $inputText")
                    Log.d(TAG, "是否有坐标: $hasCoordinates")
                    
                    var inputSuccess = false
                    
                    if (hasCoordinates) {
                        // 有坐标：先点击坐标，再输入文本
                        // 将压缩后坐标映射回原始屏幕坐标
                        val (originalX, originalY) = mapCompressedCoordinateToOriginal(x!!, y!!)
                        
                        Log.d(TAG, "压缩后坐标: ($x, $y) -> 原始坐标: ($originalX, $originalY)")
                        
                        // 显示输入效果（在输入框位置，使用原始坐标）
                        withContext(Dispatchers.Main) {
                            InteractionOverlayManager.showInputEffect(originalX, originalY)
                        }
                        
                        // 模型发起：在点击输入框前隐藏键盘，避免点击后键盘弹出
                        if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.N) {
                            MyAccessibilityService.prepareForModelInput()
                        }
                        
                        val clickSuccess = withContext(Dispatchers.Main) {
                            Log.d(TAG, "步骤1: 点击输入框坐标 ($originalX, $originalY)...")
                            val result = accessibilityService.performClick(originalX, originalY, fromModel = true)
                            Log.d(TAG, "步骤1结果: ${if (result) "✓ 点击成功" else "❌ 点击失败"}")
                            // 无论成功与否都需恢复 IME 模式
                            MyAccessibilityService.hideKeyboardAfterClickWithRetries()
                            result
                        }
                        
                        if (clickSuccess) {
                            Log.d(TAG, "步骤2: 等待输入框激活 (300ms)...")
                            delay(300)
                            Log.d(TAG, "步骤3: 开始输入文本...")
                            inputSuccess = withContext(Dispatchers.Main) {
                                accessibilityService.inputText(inputText, fromModel = true)
                            }
                            Log.d(TAG, "步骤3结果: ${if (inputSuccess) "✓ 输入成功" else "❌ 输入失败"}")
                        } else {
                            withContext(Dispatchers.Main) {
                                addChatMessage("系统", "✗ 点击输入框失败: ($x, $y)")
                            }
                            delay(500)
                            // 检查超时
                            if (checkTimeout()) {
                                return
                            }
                            return
                        }
                    } else {
                        // 无坐标：直接输入到当前聚焦的输入框
                        Log.d(TAG, "步骤1: 直接输入文本到当前聚焦的输入框...")
                        inputSuccess = withContext(Dispatchers.Main) {
                            accessibilityService.inputText(inputText, fromModel = true)
                        }
                        Log.d(TAG, "步骤1结果: ${if (inputSuccess) "✓ 输入成功" else "❌ 输入失败"}")
                    }
                    
                    // 如果输入失败，检测输入法状态
                    if (!inputSuccess) {
                        val accessibilityService = MyAccessibilityService.getInstance()
                        val currentIME = accessibilityService?.getCurrentIME()
                        val packageName = requireContext().packageName
                        val className = SimpleInputMethodService::class.java.name
                        val customIMEId1 = "$packageName/$className"
                        val customIMEId2 = "$packageName/.${SimpleInputMethodService::class.java.simpleName}"
                        
                        // 支持两种格式匹配
                        val isCustomIME = currentIME != null && (currentIME == customIMEId1 || currentIME == customIMEId2)
                        
                        if (!isCustomIME) {
                            Log.w(TAG, "输入失败且当前不是自定义输入法，显示引导弹窗")
                            // 保存TYPE参数以便重试
                            if (hasCoordinates) {
                                val (originalX, originalY) = mapCompressedCoordinateToOriginal(x!!, y!!)
                                pendingTypeParams = Triple(originalX, originalY, inputText)
                            } else {
                                // 无坐标时，保存null坐标和文本
                                pendingTypeParams = Triple(0, 0, inputText)  // 使用0,0作为标记，表示无坐标
                            }
                            pendingTypeAutoSubmit = chatResponse.auto_submit == true
                            
                            // 显示引导弹窗
                            withContext(Dispatchers.Main) {
                                MyAccessibilityService.setWaitingForIMESwitch(true)
                                IMESwitchGuideOverlayManager.show(
                                    context = requireContext(),
                                    onSettings = {
                                        Log.d(TAG, "用户点击设置，已打开设置页面")
                                    },
                                    onContinue = {
                                        Log.d(TAG, "========== onContinue回调执行 ==========")
                                        Log.d(TAG, "用户点击继续，重置状态并重新执行TYPE操作")
                                        MyAccessibilityService.setWaitingForIMESwitch(false)
                                        // 在协程中重新执行TYPE操作
                                        mainScope.launch {
                                            Log.d(TAG, "mainScope.launch 已启动，准备调用 retryTypeOperation")
                                            try {
                                                retryTypeOperation()
                                                Log.d(TAG, "retryTypeOperation 执行完成")
                                            } catch (e: Exception) {
                                                Log.e(TAG, "retryTypeOperation 执行异常: ${e.message}", e)
                                            }
                                        }
                                    },
                                    onCancel = {
                                        Log.d(TAG, "========== 用户取消输入法切换，结束任务 ==========")
                                        // 重置输入法切换状态
                                        MyAccessibilityService.resetIMESwitchState()
                                        pendingTypeParams = null
                                        pendingTypeAutoSubmit = false
                                        // 显示用户中断消息（助手气泡消息）
                                        addChatMessage("小助手", "任务已中断（用户取消输入法切换）", isAnswer = true)
                                        // 停止任务
                                        stopTask()
                                        // 通知任务完成（气泡返回）
                                        notifyTaskComplete()
                                    }
                                )
                            }
                            return
                        } else {
                            Log.w(TAG, "输入失败但输入法正确，可能是其他原因导致")
                        }
                    }
                    
                    // 步骤4: 如果 auto_submit 为 true，自动发送回车（搜索页面）
                    // 调试：检查 auto_submit 字段
                    Log.d(TAG, "========== 调试 auto_submit ==========")
                    Log.d(TAG, "inputSuccess: $inputSuccess")
                    Log.d(TAG, "chatResponse.auto_submit: ${chatResponse.auto_submit}")
                    Log.d(TAG, "chatResponse.auto_submit 类型: ${chatResponse.auto_submit?.javaClass?.simpleName}")
                    
                    // 判断 auto_submit 值（Boolean? 类型）
                    val autoSubmitValue = chatResponse.auto_submit == true
                    
                    val shouldAutoSubmit = inputSuccess && autoSubmitValue
                    Log.d(TAG, "autoSubmitValue: $autoSubmitValue")
                    Log.d(TAG, "shouldAutoSubmit: $shouldAutoSubmit")
                    
                    if (shouldAutoSubmit) {
                        Log.d(TAG, "步骤4: 检测到 auto_submit=true，自动发送回车...")
                        delay(200) // 等待输入完成
                        
                        // 通过Broadcast发送回车请求到自定义输入法
                        val currentContext = context
                        if (currentContext != null) {
                            val enterIntent = Intent(SimpleInputMethodService.ACTION_SEND_ENTER).apply {
                                setPackage(currentContext.packageName)
                            }
                            currentContext.sendBroadcast(enterIntent)
                            Log.d(TAG, "步骤4结果: ✓ 已发送回车Broadcast")
                        } else {
                            Log.w(TAG, "步骤4结果: ❌ Context为null，无法发送回车Broadcast")
                        }
                        
                        delay(100) // 等待回车发送完成
                    } else {
                        Log.d(TAG, "步骤4: 跳过自动提交 - inputSuccess=$inputSuccess, autoSubmitValue=$autoSubmitValue")
                    }
                    
                    Log.d(TAG, "========== TYPE操作结束 ==========")
                    
                    withContext(Dispatchers.Main) {
                        val reasonText = formatReasonAsThought(chatResponse.reason)
                        if (inputSuccess) {
                            val submitText = if (chatResponse.auto_submit == true) "并自动提交搜索" else ""
                            if (hasCoordinates) {
                                addChatMessage("系统", "✓ 已执行输入: 点击($x, $y)后输入\"$inputText\"$submitText$reasonText")
                            } else {
                                addChatMessage("系统", "✓ 已执行输入: 输入\"$inputText\"$submitText$reasonText")
                            }
                        } else {
                            addChatMessage("系统", "✗ 输入文本失败: $inputText$reasonText")
                        }
                    }
                    delay(500)
                    // 检查超时
                    if (checkTimeout()) {
                        return
                    }
                } else {
                    // 无障碍服务未就绪，显示弹窗
                    withContext(Dispatchers.Main) {
                        showAccessibilityServiceDialog {
                            openAccessibilitySettings()
                        }
                        addChatMessage("系统", "需要无障碍服务才能执行输入操作")
                    }
                    return
                }
            }
            "wait" -> {
                delay(100)
                withContext(Dispatchers.Main) {
                    val reasonText = formatReasonAsThought(chatResponse.reason)
                    addChatMessage("系统", "✓ 已等待0.1秒$reasonText")
                }
                // 检查超时
                if (checkTimeout()) {
                    return
                }
            }
            "swipe" -> {
                val swipeParams = chatResponse.swipe
                if (swipeParams != null && swipeParams.size >= 4) {
                    val compressedX1 = swipeParams[0]
                    val compressedY1 = swipeParams[1]
                    val compressedX2 = swipeParams[2]
                    val compressedY2 = swipeParams[3]
                    
                    // 将压缩后坐标映射回原始屏幕坐标
                    val (x1, y1) = mapCompressedCoordinateToOriginal(compressedX1, compressedY1)
                    val (x2, y2) = mapCompressedCoordinateToOriginal(compressedX2, compressedY2)
                    
                    val distance = kotlin.math.sqrt(
                        ((x2 - x1) * (x2 - x1) + (y2 - y1) * (y2 - y1)).toDouble()
                    ).toInt()
                    
                    if (distance >= 100) {
                        val accessibilityService = MyAccessibilityService.getInstance()
                        if (accessibilityService != null && Build.VERSION.SDK_INT >= Build.VERSION_CODES.N) {
                            val success = withContext(Dispatchers.Main) {
                                accessibilityService.performSwipe(x1, y1, x2, y2)
                            }
                            
                            withContext(Dispatchers.Main) {
                                val reasonText = formatReasonAsThought(chatResponse.reason)
                                if (success) {
                                    addChatMessage("系统", "✓ 已执行滑动: ($x1, $y1) -> ($x2, $y2)$reasonText")
                                } else {
                                    addChatMessage("系统", "✗ 滑动失败: ($x1, $y1) -> ($x2, $y2)$reasonText")
                                }
                            }
                            delay(500)
                        }
                        // 检查超时
                        if (checkTimeout()) {
                            return
                        }
                    } else {
                        withContext(Dispatchers.Main) {
                            addChatMessage("系统", "✗ 滑动距离不足100像素")
                        }
                    }
                }
            }
            "long_press" -> {
                // 优先从long_press字段获取坐标
                var longPressParams = chatResponse.long_press

                // 兼容新格式：coordinates: [x, y]
                if (longPressParams == null || longPressParams.size < 2) {
                    val coordinates = chatResponse.coordinates
                    if (coordinates != null && coordinates.size >= 2) {
                        longPressParams = coordinates.take(2)
                    }
                }

                // 兼容旧格式：params "x,y"
                if (longPressParams == null || longPressParams.size < 2) {
                    val params = chatResponse.params
                    if (params != null && params.contains(",")) {
                        try {
                            val coords = params.split(",").map { it.trim().toInt() }
                            if (coords.size >= 2) {
                                longPressParams = coords.take(2)
                            }
                        } catch (e: Exception) {
                            Log.w(TAG, "解析long_press params失败: ${e.message}")
                        }
                    }
                }

                // 兼容更老格式：x/y
                if (longPressParams == null || longPressParams.size < 2) {
                    val x = chatResponse.x
                    val y = chatResponse.y
                    if (x != null && y != null) {
                        longPressParams = listOf(x, y)
                    }
                }

                if (longPressParams != null && longPressParams.size >= 2) {
                    val compressedX = longPressParams[0]
                    val compressedY = longPressParams[1]
                    
                    // 将压缩后坐标映射回原始屏幕坐标
                    val (x, y) = mapCompressedCoordinateToOriginal(compressedX, compressedY)
                    
                    val accessibilityService = MyAccessibilityService.getInstance()
                    if (accessibilityService != null && Build.VERSION.SDK_INT >= Build.VERSION_CODES.N) {
                        // 显示长按效果（使用原始坐标）
                        withContext(Dispatchers.Main) {
                            InteractionOverlayManager.showLongPressEffect(x, y)
                        }
                        
                        // 使用更长的长按时间（1000ms）确保能被识别
                        val success = withContext(Dispatchers.Main) {
                            accessibilityService.performLongClick(x, y, 1000)
                        }
                        
                        withContext(Dispatchers.Main) {
                            val reasonText = formatReasonAsThought(chatResponse.reason)
                            if (success) {
                                addChatMessage("系统", "✓ 已执行长按: ($x, $y)$reasonText")
                            } else {
                                addChatMessage("系统", "✗ 长按失败: ($x, $y)$reasonText")
                            }
                        }
                        delay(1500)  // 等待长按完成
                        delay(500)   // 长按专用：额外等待弹窗出现
                    } else {
                        // 无障碍服务未就绪，显示弹窗
                        withContext(Dispatchers.Main) {
                            showAccessibilityServiceDialog {
                                openAccessibilitySettings()
                            }
                            addChatMessage("系统", "需要无障碍服务才能执行长按操作")
                        }
                        return
                    }
                    // 检查超时
                    if (checkTimeout()) {
                        return
                    }
                } else {
                    withContext(Dispatchers.Main) {
                        addChatMessage("系统", "✗ 长按动作缺少坐标参数")
                    }
                    Log.w(
                        TAG,
                        "long_press动作缺少坐标参数: long_press=$longPressParams, coordinates=${chatResponse.coordinates}, params=${chatResponse.params}, x=${chatResponse.x}, y=${chatResponse.y}"
                    )
                }
            }
            "back" -> {
                Log.d(TAG, "执行back动作")
                val accessibilityService = MyAccessibilityService.getInstance()
                if (accessibilityService != null) {
                    Log.d(TAG, "无障碍服务已就绪，执行返回操作")
                    withContext(Dispatchers.Main) {
                        accessibilityService.goBack()
                        val reasonText = formatReasonAsThought(chatResponse.reason)
                        addChatMessage("系统", "✓ 已执行返回$reasonText")
                    }
                    Log.d(TAG, "返回操作已执行，等待500ms")
                    delay(500)
                    // 检查超时
                    if (checkTimeout()) {
                        return
                    }
                } else {
                    Log.w(TAG, "无障碍服务未就绪，无法执行返回")
                    withContext(Dispatchers.Main) {
                        addChatMessage("系统", "✗ 无障碍服务未就绪")
                    }
                }
            }
            "home" -> {
                Log.d(TAG, "执行home动作")
                val accessibilityService = MyAccessibilityService.getInstance()
                if (accessibilityService != null) {
                    Log.d(TAG, "无障碍服务已就绪，执行返回主页操作")
                    withContext(Dispatchers.Main) {
                        accessibilityService.goHome()
                        val reasonText = formatReasonAsThought(chatResponse.reason)
                        addChatMessage("系统", "✓ 已返回主页$reasonText")
                    }
                    Log.d(TAG, "返回主页操作已执行，等待500ms")
                    delay(500)
                    // 检查超时
                    if (checkTimeout()) {
                        return
                    }
                } else {
                    Log.w(TAG, "无障碍服务未就绪，无法执行返回主页")
                    withContext(Dispatchers.Main) {
                        addChatMessage("系统", "✗ 无障碍服务未就绪")
                    }
                }
            }
            "enter" -> {
                Log.d(TAG, "执行enter动作")
                // 通过Broadcast发送回车请求到自定义输入法
                val currentContext = context
                if (currentContext != null) {
                    val enterIntent = Intent(SimpleInputMethodService.ACTION_SEND_ENTER).apply {
                        setPackage(currentContext.packageName)
                    }
                    currentContext.sendBroadcast(enterIntent)
                    Log.d(TAG, "✓ 已发送回车键事件")
                    withContext(Dispatchers.Main) {
                        val reasonText = formatReasonAsThought(chatResponse.reason)
                        addChatMessage("系统", "✓ 已发送回车键事件$reasonText")
                    }
                    delay(200) // 等待回车发送完成
                    // 检查超时
                    if (checkTimeout()) {
                        return
                    }
                } else {
                    Log.w(TAG, "Context为null，无法发送回车键事件")
                    withContext(Dispatchers.Main) {
                        addChatMessage("系统", "✗ 无法发送回车键事件")
                    }
                }
            }
            "get_wechat_link" -> {
                // params 可选，表示每次点击间间隔（毫秒），默认 500
                val delayMs = chatResponse.params?.toLongOrNull() ?: 500L
                val accessibilityService = MyAccessibilityService.getInstance()
                if (accessibilityService != null && Build.VERSION.SDK_INT >= Build.VERSION_CODES.N) {
                    val points = accessibilityService.getWechatLinkClickPixels()
                    withContext(Dispatchers.Main) {
                        val reasonText = formatReasonAsThought(chatResponse.reason)
                        addChatMessage("系统", "正在执行 get_wechat_link（共 6 步，间隔 ${delayMs}ms）$reasonText")
                    }
                    for ((i, p) in points.withIndex()) {
                        val (x, y) = p
                        if (checkTimeout() || checkPaused()) return
                        val success = accessibilityService.performClick(x, y)
                        withContext(Dispatchers.Main) {
                            if (success) {
                                addChatMessage("系统", "✓ step${i + 1}: 点击 ($x, $y)")
                            } else {
                                addChatMessage("系统", "✗ step${i + 1}: 点击失败 ($x, $y)")
                            }
                        }
                        if (i < points.size - 1) {
                            if (i == 3) {
                                delay(GET_WECHAT_LINK_EXTRA_DELAY_AFTER_STEP4_MS)
                            }
                            delay(delayMs)
                        }
                    }
                    withContext(Dispatchers.Main) {
                        addChatMessage("系统", "✓ get_wechat_link 完成")
                    }
                    delay(500)
                } else {
                    withContext(Dispatchers.Main) {
                        addChatMessage("系统", "✗ 无障碍服务未就绪或 Android 版本过低，无法执行 get_wechat_link")
                    }
                }
            }
            "screenshot" -> {
                Log.d(TAG, "执行screenshot动作")
                val chatService = ChatScreenshotService.getInstance()
                if (chatService == null || !chatService.isReady()) {
                    Log.w(TAG, "截图服务未就绪")
                    withContext(Dispatchers.Main) {
                        addChatMessage("小助手", "✗ 截图服务未就绪，请先在服务页面授权截图权限")
                    }
                    return
                }
                
                val bitmap = withContext(Dispatchers.IO) {
                    chatService.captureScreenshot()
                }
                
                if (bitmap != null) {
                    val savedUri = ScreenshotHelper.saveBitmapToGallery(
                        requireContext(),
                        bitmap,
                        displayName = null
                    )
                    bitmap.recycle()
                    
                    withContext(Dispatchers.Main) {
                        val reasonText = formatReasonAsThought(chatResponse.reason)
                        if (savedUri != null) {
                            addChatMessage("小助手", "✓ 截图已保存到相册$reasonText")
                        } else {
                            addChatMessage("小助手", "✗ 保存截图失败$reasonText")
                        }
                    }
                } else {
                    Log.w(TAG, "截图获取失败")
                    withContext(Dispatchers.Main) {
                        addChatMessage("小助手", "✗ 截图获取失败")
                    }
                }
                
                delay(500)
                if (checkTimeout()) {
                    return
                }
            }
            "clear" -> {
                Log.d(TAG, "执行clear动作：清除后台应用")
                val accessibilityService = MyAccessibilityService.getInstance()
                if (accessibilityService != null && Build.VERSION.SDK_INT >= Build.VERSION_CODES.N) {
                    Log.d(TAG, "无障碍服务已就绪，开始清除后台应用")
                    try {
                        val success = accessibilityService.clearAppFromRecentTasks()
                        withContext(Dispatchers.Main) {
                            val reasonText = formatReasonAsThought(chatResponse.reason)
                            if (success) {
                                addChatMessage("系统", "✓ 已清除后台应用$reasonText")
                            } else {
                                addChatMessage("系统", "✗ 清除后台应用失败$reasonText")
                            }
                        }
                        // 等待清除操作完成
                        delay(2000)
                        // 检查超时
                        if (checkTimeout()) {
                            return
                        }
                    } catch (e: Exception) {
                        Log.e(TAG, "清除后台应用异常: ${e.message}", e)
                        withContext(Dispatchers.Main) {
                            addChatMessage("系统", "✗ 清除后台应用异常: ${e.message}")
                        }
                    }
                } else {
                    Log.w(TAG, "无障碍服务未就绪或Android版本过低，无法执行清除后台应用")
                    withContext(Dispatchers.Main) {
                        addChatMessage("系统", "✗ 无障碍服务未就绪或Android版本过低")
                    }
                }
            }
            "drag" -> {
                Log.d(TAG, "执行drag动作：长按并拖拽")
                val dragParams = chatResponse.drag
                
                if (dragParams != null && dragParams.size >= 4) {
                    val compressedX1 = dragParams[0]
                    val compressedY1 = dragParams[1]
                    val compressedX2 = dragParams[2]
                    val compressedY2 = dragParams[3]
                    
                    // 将压缩后坐标映射回原始屏幕坐标
                    val (x1, y1) = mapCompressedCoordinateToOriginal(compressedX1, compressedY1)
                    val (x2, y2) = mapCompressedCoordinateToOriginal(compressedX2, compressedY2)
                    
                    val accessibilityService = MyAccessibilityService.getInstance()
                    if (accessibilityService != null && Build.VERSION.SDK_INT >= Build.VERSION_CODES.N) {
                        val success = withContext(Dispatchers.Main) {
                            accessibilityService.performDrag(x1, y1, x2, y2)
                        }
                        
                        withContext(Dispatchers.Main) {
                            val reasonText = formatReasonAsThought(chatResponse.reason)
                            if (success) {
                                addChatMessage("系统", "✓ 已执行拖拽: ($x1, $y1) -> ($x2, $y2)$reasonText")
                            } else {
                                addChatMessage("系统", "✗ 拖拽失败: ($x1, $y1) -> ($x2, $y2)$reasonText")
                            }
                        }
                        delay(1000)  // 等待拖拽完成
                    } else {
                        withContext(Dispatchers.Main) {
                            showAccessibilityServiceDialog {
                                openAccessibilitySettings()
                            }
                            addChatMessage("系统", "需要无障碍服务才能执行拖拽操作")
                        }
                    }
                } else {
                    withContext(Dispatchers.Main) {
                        addChatMessage("系统", "✗ 拖拽参数不足，需要起始坐标和目标坐标")
                    }
                }
                
                // 检查超时
                if (checkTimeout()) {
                    return
                }
            }
            "long_screenshot" -> {
                Log.d(TAG, "执行long_screenshot动作：获取长截图")
                val longScreenshotParams = chatResponse.long_screenshot
                
                val direction = if (longScreenshotParams != null) {
                    (longScreenshotParams["direction"] as? String) ?: "down"
                } else {
                    "down"
                }
                
                val steps = if (longScreenshotParams != null) {
                    when (val stepsValue = longScreenshotParams["steps"]) {
                        is Int -> stepsValue.coerceIn(1, 10)
                        is Number -> stepsValue.toInt().coerceIn(1, 10)
                        else -> 3
                    }
                } else {
                    3
                }
                
                Log.d(TAG, "长截图参数: direction=$direction, steps=$steps")
                
                withContext(Dispatchers.Main) {
                    val reasonText = formatReasonAsThought(chatResponse.reason)
                    addChatMessage("系统", "开始获取长截图（${direction}方向，${steps}次滚动）...$reasonText")
                }
                
                try {
                    // 在长截图执行前检查超时
                    if (checkTimeout()) {
                        return
                    }
                    
                    val screenshotResult = LongScreenshotHelper.captureLongScreenshot(direction, steps)
                    
                    // 在长截图执行后检查超时
                    if (checkTimeout()) {
                        return
                    }
                    
                    if (screenshotResult != null) {
                        val longScreenshot = screenshotResult.longScreenshot
                        val currentScreen = screenshotResult.currentScreen
                        
                        val screenshotWidth = longScreenshot.width
                        val screenshotHeight = longScreenshot.height
                        val currentScreenWidth = currentScreen.width
                        val currentScreenHeight = currentScreen.height
                        
                        Log.d(TAG, "长截图获取成功，尺寸: ${screenshotWidth}x${screenshotHeight}")
                        Log.d(TAG, "当前屏幕截图获取成功，尺寸: ${currentScreenWidth}x${currentScreenHeight}")
                        
                        // 转换为Base64
                        val longScreenshotBase64 = screenshotBitmapToBase64(longScreenshot)
                        val currentScreenBase64 = screenshotBitmapToBase64(currentScreen)
                        
                        longScreenshot.recycle()
                        currentScreen.recycle()
                        
                        // 清理Base64字符串
                        val cleanLongScreenshotBase64 = longScreenshotBase64.trim().replace("\n", "").replace("\r", "").replace(" ", "")
                        val cleanCurrentScreenBase64 = currentScreenBase64.trim().replace("\n", "").replace("\r", "").replace(" ", "")
                        
                        withContext(Dispatchers.Main) {
                            addChatMessage("系统", "✓ 长截图获取成功，尺寸: ${screenshotWidth}x${screenshotHeight}")
                            addChatMessage("系统", "✓ 当前屏幕截图获取成功，尺寸: ${currentScreenWidth}x${currentScreenHeight}")
                            // 注意：长截图动作的reason已经在开始时添加，这里不需要重复添加
                        }
                        
                        // 确保使用当前对话对应的服务地址
                        ensureNetworkServiceInitialized()
                        
                        // 将长截图和当前屏幕截图发送到云侧（继续任务循环）
                        // 使用当前query和uuid，将两张图片作为新的截图发送
                        val apiService = NetworkService.getApiService()
                        if (apiService != null && isTaskRunning && currentQuery != null) {
                            try {
                                // URL编码
                                val urlEncodedLongScreenshot = try {
                                    java.net.URLEncoder.encode(cleanLongScreenshotBase64, "UTF-8")
                                } catch (e: Exception) {
                                    Log.e(TAG, "URL编码失败: ${e.message}", e)
                                    cleanLongScreenshotBase64
                                }
                                
                                val urlEncodedCurrentScreen = try {
                                    java.net.URLEncoder.encode(cleanCurrentScreenBase64, "UTF-8")
                                } catch (e: Exception) {
                                    Log.e(TAG, "URL编码失败: ${e.message}", e)
                                    cleanCurrentScreenBase64
                                }
                                
                                // 检查任务是否暂停，如果暂停则不发送请求
                                if (isTaskPaused) {
                                    Log.d(TAG, "任务已暂停，不向云侧发送长截图")
                                    return
                                }
                                
                                Log.d(TAG, "发送长截图和当前屏幕截图到云侧...")
                                
                                // 更新最后一次交互时间（发送请求前）
                                updateLastInteractionTime()
                                
                                // 获取当前 Activity 信息
                                val (packageName, className) = MyAccessibilityService.getCurrentActivityInfo()
                                val imei = ProfileManager.getOrGenerateImei(requireContext())
                                
                                val response = try {
                                    // 检测是否为批测模式
                                    val mainActivity = activity as? MainActivity
                                    val isBatchTesting = mainActivity?.isBatchTesting ?: false
                                    
                                    apiService.sendChatMessage(
                                        uuid = chatUuid,
                                        query = currentQuery!!,
                                        image = urlEncodedLongScreenshot,
                                        image2 = urlEncodedCurrentScreen,  // 第二张图片：当前屏幕截图
                                        userResponse = null,
                                        userExample = null,
                                        packageName = packageName,
                                        className = className,
                                        imei = imei,
                                        proMode = if (isProModeEnabled) true else null,
                                        batchTestMode = if (isBatchTesting) true else null,
                                        outputLanguage = LanguageManager.getSavedLanguage(requireContext()),
                                        installApps = getInstallAppsParamForUpload()
                                    )
                                } catch (e: Exception) {
                                    // 对timeout异常进行特殊处理
                                    val isTimeoutException = e is java.net.SocketTimeoutException || 
                                                             e is java.io.InterruptedIOException ||
                                                             (e.message?.contains("timeout", ignoreCase = true) == true)
                                    
                                    if (isTimeoutException) {
                                        // timeout异常：显示友好提示，不显示具体的timeout错误信息
                                        Log.w(TAG, "请求超时，正在重试... (${e.message})")
                                        withContext(Dispatchers.Main) {
                                            addChatMessage("系统", "请求超时，正在重试...")
                                        }
                                    } else {
                                        // 其他异常：重新抛出，让外层catch处理
                                        throw e
                                    }
                                    // timeout时继续重试
                                    if (isTaskRunning) {
                                        delay(2000)
                                        continueTaskLoop()
                                    }
                                    return
                                }
                                
                                // 更新最后一次交互时间（收到响应后）
                                updateLastInteractionTime()
                                
                                Log.d(TAG, "长截图发送成功，收到响应")
                                
                                // 处理响应（与performSendChatMessage中的逻辑一致）
                                if (response.isSuccessful) {
                                    val chatResponse = response.body()
                                    if (chatResponse != null) {
                                        Log.d(TAG, "收到响应: $chatResponse")
                                        withContext(Dispatchers.Main) {
                                            // 显示云侧返回的消息
                                            // 如果是call_user动作，不在这里添加message，让call_user处理逻辑统一处理
                                            val actionType = chatResponse.action_type
                                            if (chatResponse.message != null && actionType?.lowercase() != "call_user") {
                                                addChatMessage("云侧", chatResponse.message)
                                            }
                                        }
                                        
                                        // 处理操作指令
                                        val actionType = chatResponse.action_type
                                        if (actionType != null && isTaskRunning) {
                                            Log.d(TAG, "收到操作指令: $actionType")
                                            
                                            // 处理complete指令
                                            if (actionType.lowercase() == "complete") {
                                                Log.d(TAG, "收到complete指令，任务完成")
                                                
                                                withContext(Dispatchers.Main) {
                                                    val reason = chatResponse.reason ?: ""
                                                    val isMaxStepTriggered = reason.contains("执行步数已达到最大限制") || 
                                                                             reason.contains("超过最大执行步数限制")
                                                    val displayText = ChatResponseDisplayHelper.getCompleteDisplayText(chatResponse, useNextActionApi(), isMaxStepTriggered)
                                                    addChatMessage("小助手", displayText, isAnswer = true)
                                                    if (!ChatResponseDisplayHelper.hasCompleteAnswerContent(chatResponse, useNextActionApi()) &&
                                                        !shouldSuppressCustomAssistantTaskCompletedCheckmark()) {
                                                        addChatMessage("系统", "任务已完成 ✓", isComplete = true)
                                                    }
                                                    stopTask()
                                                    notifyTaskComplete()
                                                }
                                                return
                                            }
                                            
                                            // 处理answer指令（等同于complete，直接结束任务）
                                            if (actionType.lowercase() == "answer") {
                                                val answerText = chatResponse.params ?: chatResponse.text
                                                if (answerText != null && answerText.isNotBlank()) {
                                                    Log.d(TAG, "收到answer指令，文本内容: $answerText，任务完成")
                                                    withContext(Dispatchers.Main) {
                                                        // 步骤1: 将TopoClaw应用带到前台（不重新启动）
                                                        try {
                                                            val success = (activity as? MainActivity)?.bringAppToForeground() ?: false
                                                            if (success) {
                                                                Log.d(TAG, "已返回到TopoClaw应用页面")
                                                                // 等待应用切换到前台
                                                                delay(300)
                                                            } else {
                                                                Log.w(TAG, "返回到TopoClaw应用页面失败")
                                                            }
                                                        } catch (e: Exception) {
                                                            Log.e(TAG, "返回到应用页面时出错: ${e.message}", e)
                                                        }
                                                        
                                                        // 步骤2: 显示answer消息
                                                        addChatMessage("小助手", answerText, isAnswer = true)
                                                        notifyAnswerReceived(answerText)
                                                        
                                                        // 步骤3: 在停止任务之前保存任务的uuid和query（用于反馈评测）
                                                        val taskUuidForFeedback = chatUuid
                                                        val taskQueryForFeedback = currentQuery
                                                        
                                                        // 步骤4: 停止任务（不再继续循环）
                                                        stopTask()
                                                        notifyTaskComplete()
                                                        // stopTask()已经清除了图片状态并更新了按钮可见性，无需再次手动设置
                                                        
                                                        // 步骤5: 显示评价请求（answer指令表示正常完成）
                                                        Log.d(TAG, "[answer指令-长截图] 准备调用showFeedbackRequest()")
                                                        showFeedbackRequest(taskUuidForFeedback, taskQueryForFeedback)
                                                    }
                                                    return
                                                } else {
                                                    // 即使没有文本，也停止任务
                                                    withContext(Dispatchers.Main) {
                                                        // 返回到应用前台
                                                        try {
                                                            val success = (activity as? MainActivity)?.bringAppToForeground() ?: false
                                                            if (success) {
                                                                delay(300)
                                                            }
                                                        } catch (e: Exception) {
                                                            Log.e(TAG, "返回到应用页面时出错: ${e.message}", e)
                                                        }
                                                        
                                                        if (!shouldSuppressCustomAssistantTaskCompletedCheckmark()) {
                                                            addChatMessage("系统", "任务已完成 ✓", isComplete = true)
                                                        }
                                                        stopTask()
                                                        notifyTaskComplete()
                                                        // stopTask()已经清除了图片状态并更新了按钮可见性，无需再次手动设置
                                                    }
                                                    return
                                                }
                                            }
                                            
                                            // 处理call_user指令
                                            if (actionType.lowercase() == "call_user") {
                                                val callUserText = chatResponse.text
                                                if (callUserText != null && callUserText.isNotBlank()) {
                                                    withContext(Dispatchers.Main) {
                                                        // 播放call_user提示音效
                                                        playCallUserSound()
                                                        
                                                        // 保存原始query（如果还没有保存）
                                                        if (originalQuery == null) {
                                                            originalQuery = currentQuery
                                                        }
                                                        
                                                        // 停止任务循环，等待用户输入
                                                        taskJob?.cancel()
                                                        taskJob = null
                                                        
                                                        // 显示悬浮窗输入框（不再跳转回应用）
                                                        // 先将call_user消息添加到聊天界面
                                                        addChatMessage("云侧", callUserText, isAnswer = true)
                                                        Log.d(TAG, "call_user消息已添加到聊天框")
                                                        
                                                        val currentActivity = activity
                                                        if (currentActivity != null) {
                                                            val savedOriginalQuery: String? = originalQuery
                                                            CallUserInputOverlayManager.show(
                                                                context = currentActivity,
                                                                questionText = callUserText,
                                                                onSend = { userInput: String ->
                                                                    Log.d(TAG, "用户通过悬浮窗输入: $userInput")
                                                                    // 将用户输入添加到聊天界面
                                                                    addChatMessage("我", userInput)
                                                                    // 用户输入后，继续任务
                                                                    if (savedOriginalQuery != null) {
                                                                        originalQuery = null
                                                                        handleCallUserResponse(savedOriginalQuery, userInput)
                                                                    }
                                                                },
                                                                onCancel = {
                                                                    Log.d(TAG, "用户取消输入，停止任务")
                                                                    // 用户取消，停止任务
                                                                    stopTask()
                                                                    notifyTaskComplete()
                                                                },
                                                                onManualTakeover = {
                                                                    Log.d(TAG, "用户点击手动接管")
                                                                    // 设置手动接管状态
                                                                    isManualTakeover = true
                                                                    // 停止任务循环
                                                                    taskJob?.cancel()
                                                                    taskJob = null
                                                                    // 添加提示消息
                                                                    addChatMessage("系统", "已进入手动接管模式，请手动操作屏幕。操作完成后，点击悬浮球结束手动操作。")
                                                                }
                                                            )
                                                        } else {
                                                            Log.w(TAG, "Activity为null，无法显示悬浮窗")
                                                        }
                                                    }
                                                    return
                                                }
                                            }
                                            
                                            // 防止无限循环：如果云侧返回long_screenshot，说明已经在executeAction的long_screenshot分支中处理过了
                                            // 不应该再次执行，直接返回避免无限循环
                                            // 注意：这个检查已经在executeAction函数开始处处理了，这里保留作为双重保险
                                            if (actionType.lowercase() == "long_screenshot") {
                                                Log.w(TAG, "检测到云侧返回long_screenshot动作，已在当前分支处理过，跳过执行避免无限循环")
                                                // 重置lastExecutedActionType，允许下次正常执行
                                                lastExecutedActionType = null
                                                // 直接继续循环，不再次执行长截图
                                                if (isTaskRunning) {
                                                    delay(actionCompletionDelayMs)
                                                    continueTaskLoop()
                                                }
                                                return
                                            }
                                            
                                            // 执行其他操作（添加异常处理，确保即使出错也能继续循环）
                                            val executedActionType = chatResponse.action_type
                                            try {
                                                executeAction(chatResponse)
                                                Log.d(TAG, "动作执行完成")
                                            } catch (e: Exception) {
                                                Log.e(TAG, "执行动作时发生异常: ${e.message}", e)
                                                withContext(Dispatchers.Main) {
                                                    addChatMessage("系统", "执行动作异常: ${e.message}")
                                                }
                                            }
                                            
                                            // 执行完动作后，继续循环（无论成功还是失败都要继续）
                                            if (isTaskRunning) {
                                                Log.d(TAG, "动作执行完成，准备继续任务循环")
                                                delay(actionCompletionDelayMs)
                                                continueTaskLoop()
                                            } else {
                                                Log.w(TAG, "任务已停止，不继续循环")
                                            }
                                        } else {
                                            // 没有操作指令，继续循环
                                            if (isTaskRunning) {
                                                delay(2000)
                                                continueTaskLoop()
                                            }
                                        }
                                    } else {
                                        Log.w(TAG, "响应体为空")
                                        if (isTaskRunning) {
                                            delay(2000)
                                            continueTaskLoop()
                                        }
                                    }
                                } else {
                                    Log.w(TAG, "请求失败: ${response.code()}")
                                    withContext(Dispatchers.Main) {
                                        addChatMessage("系统", "请求失败: ${response.code()}")
                                    }
                                    if (isTaskRunning) {
                                        delay(2000)
                                        continueTaskLoop()
                                    }
                                }
                            } catch (e: Exception) {
                                // 对timeout异常进行特殊处理
                                val isTimeoutException = e is java.net.SocketTimeoutException || 
                                                         e is java.io.InterruptedIOException ||
                                                         (e.message?.contains("timeout", ignoreCase = true) == true)
                                
                                if (isTimeoutException) {
                                    // timeout异常：显示友好提示，不显示具体的timeout错误信息
                                    Log.w(TAG, "请求超时，正在重试... (${e.message})")
                                    withContext(Dispatchers.Main) {
                                        addChatMessage("系统", "请求超时，正在重试...")
                                    }
                                } else {
                                    // 其他异常：显示错误消息
                                    Log.e(TAG, "发送长截图到云侧失败: ${e.message}", e)
                                    withContext(Dispatchers.Main) {
                                        addChatMessage("小助手", "✗ 发送长截图到云侧失败: ${e.message}")
                                    }
                                }
                                // 继续任务循环
                                if (isTaskRunning) {
                                    delay(2000)
                                    continueTaskLoop()
                                }
                            }
                        } else {
                            Log.w(TAG, "无法发送长截图：apiService=${apiService != null}, isTaskRunning=$isTaskRunning, currentQuery=$currentQuery")
                            // 继续任务循环
                            if (isTaskRunning) {
                                delay(2000)
                                continueTaskLoop()
                            }
                        }
                    } else {
                        Log.e(TAG, "长截图获取失败")
                        // 重置lastExecutedActionType，允许下次重试
                        lastExecutedActionType = null
                        withContext(Dispatchers.Main) {
                            addChatMessage("小助手", "✗ 长截图获取失败")
                        }
                        // 继续任务循环
                        if (isTaskRunning) {
                            delay(2000)
                            continueTaskLoop()
                        }
                    }
                } catch (e: Exception) {
                    Log.e(TAG, "获取长截图时发生异常: ${e.message}", e)
                    // 重置lastExecutedActionType，允许下次重试
                    lastExecutedActionType = null
                    withContext(Dispatchers.Main) {
                        addChatMessage("系统", "✗ 获取长截图异常: ${e.message}")
                    }
                    // 继续任务循环
                    if (isTaskRunning) {
                        delay(2000)
                        continueTaskLoop()
                    }
                }
            }
        }
        
        // 动作执行完成后，如果不是long_screenshot，重置lastExecutedActionType
        // 这样下次可以正常执行long_screenshot
        if (actionType.lowercase() != "long_screenshot") {
            lastExecutedActionType = null
        }
        
        // 动作执行完成后，最后检查一次超时
        checkTimeout()
    }
    
    /**
     * 从推荐任务开始执行
     */
    fun startTaskFromRecommendation(recommendation: String) {
        Log.d(TAG, "从推荐任务开始执行: $recommendation")
        executeQueryFromExternal(recommendation)
    }
    
    /**
     * 开始任务
     * @return 是否成功开始任务（如果输入法未启用，返回false，任务不会开始）
     */
    private suspend fun startTaskInternal(query: String): Boolean {
        Log.d(TAG, "========== startTaskInternal 开始执行 ==========")
        Log.d(TAG, "startTaskInternal: query=$query, Fragment状态 - isAdded=$isAdded, view=$view, binding=$binding")
        Log.d(TAG, "startTaskInternal: 当前协程上下文=${kotlin.coroutines.coroutineContext}")
        
        // 检查Fragment状态
        if (!isAdded || view == null) {
            Log.e(TAG, "startTaskInternal: Fragment未就绪，无法开始任务 - isAdded=$isAdded, view=$view")
            return false
        }
        
        if (isTaskRunning) {
            stopTask()
        }
        
        // 如果是从悬浮球发起的任务，跳过输入法检查，直接开始任务
        // 如果后续TYPE操作失败，会通过错误处理逻辑提示用户
        val mainActivity = activity as? MainActivity
        val isFromCompanionMode = mainActivity?.isTaskFromCompanionMode ?: false
        if (isFromCompanionMode) {
            Log.d(TAG, "任务开始：从悬浮球发起，跳过输入法检查，直接开始任务")
            // 直接设置任务状态并返回true
            try {
                withContext(Dispatchers.Main) {
                    // 再次检查Fragment状态
                    if (!isAdded || view == null || _binding == null) {
                        Log.e(TAG, "startTaskInternal: Fragment状态无效，无法开始任务")
                        return@withContext
                    }
                    
                    // 确保推荐任务面板始终显示（收起状态）
                    try {
                        binding.llRecommendationsPanel.visibility = android.view.View.VISIBLE
                        isRecommendationsExpanded = false
                        binding.llRecommendationsContent.visibility = android.view.View.GONE
                    } catch (e: Exception) {
                        Log.e(TAG, "startTaskInternal: 更新推荐面板异常: ${e.message}", e)
                    }
                    
                    isTaskRunning = true
                    isTaskPaused = false
                    isCustomAssistantProcessing = false
                    currentQuery = query
                    currentStep = 0  // 初始化步骤号
                    isFirstSendInTask = true
                    screenshotFailCount = 0  // 重置截图失败计数
                    
                    // 记录任务开始时间
                    lastInteractionTime = System.currentTimeMillis()
                    
                    // 启动交互超时监测
                    try {
                        startInteractionTimeoutMonitoring()
                    } catch (e: Exception) {
                        Log.e(TAG, "startTaskInternal: 启动交互超时监测异常: ${e.message}", e)
                    }
                    
                    // 启动剪切板监视（如果启用）
                    try {
                        val context = context ?: return@withContext
                        ClipboardMonitorManager.startMonitoring(context, chatUuid)
                    } catch (e: Exception) {
                        Log.e(TAG, "startTaskInternal: 启动剪切板监视异常: ${e.message}", e)
                    }
                    
                    // 通知MainActivity任务已开始
                    mainActivity?.isTaskRunning = true
                    
                    // 更新悬浮窗状态（任务运行中）
                    try {
                        TaskIndicatorOverlayManager.updateOverlayForTaskStatus(true)
                    } catch (e: Exception) {
                        Log.e(TAG, "startTaskInternal: 更新悬浮窗状态异常: ${e.message}", e)
                    }
                    
                    try {
                        binding.btnSendChat.isEnabled = true
                        binding.btnStopTask.visibility = View.VISIBLE
                    } catch (e: Exception) {
                        Log.e(TAG, "startTaskInternal: 更新按钮状态异常: ${e.message}", e)
                    }
                    
                    // 更新按钮可见性
                    try {
                        updateButtonVisibility()
                    } catch (e: Exception) {
                        Log.e(TAG, "startTaskInternal: 更新按钮可见性异常: ${e.message}", e)
                    }
                    
                    // 检查悬浮窗功能是否开启
                    try {
                        val context = context ?: return@withContext
                        val prefs = context.getSharedPreferences("app_prefs", android.content.Context.MODE_PRIVATE)
                        val overlayEnabled = prefs.getBoolean("task_indicator_overlay_enabled", true)
                        if (overlayEnabled && !TaskIndicatorOverlayManager.isOverlayShowing() && mainActivity != null) {
                            Log.d(TAG, "任务启动，悬浮窗功能已开启，显示任务指示器")
                            TaskIndicatorOverlayManager.show(mainActivity)
                        }
                    } catch (e: Exception) {
                        Log.e(TAG, "startTaskInternal: 检查悬浮窗功能异常: ${e.message}", e)
                    }
                }
                Log.d(TAG, "startTaskInternal: 从悬浮球发起的任务已开始")
                return true
            } catch (e: Exception) {
                Log.e(TAG, "startTaskInternal: 从悬浮球发起任务异常: ${e.message}", e)
                e.printStackTrace()
                return false
            }
        }
        
        // 保存当前输入法并切换到自定义输入法
        try {
            // 如果无障碍服务实例暂时为null，等待一下再重试（最多等待2秒）
            var accessibilityService = MyAccessibilityService.getInstance()
            Log.d(TAG, "startTaskInternal: 开始输入法检查，无障碍服务实例=${if (accessibilityService != null) "已就绪" else "为null"}")
            if (accessibilityService == null) {
                Log.d(TAG, "startTaskInternal: 无障碍服务实例暂时为null，等待服务实例准备好...")
                for (i in 1..4) {
                    delay(500)
                    accessibilityService = MyAccessibilityService.getInstance()
                    if (accessibilityService != null) {
                        Log.d(TAG, "startTaskInternal: 无障碍服务实例已准备好（等待${i * 500}ms后）")
                        break
                    }
                }
            }
            
            if (accessibilityService != null) {
                Log.d(TAG, "startTaskInternal: 无障碍服务实例已就绪，开始输入法检查流程")
                // 保存原始输入法
                try {
                    originalIME = accessibilityService.getCurrentIME()
                    Log.d(TAG, "任务开始：保存原始输入法: $originalIME")
                } catch (e: Exception) {
                    Log.e(TAG, "startTaskInternal: 获取当前输入法异常: ${e.message}", e)
                    e.printStackTrace()
                    return false
                }
                
                // 检查当前是否是自定义输入法（双重验证）
                val customIMEId = try {
                    "${requireContext().packageName}/${SimpleInputMethodService::class.java.name}"
                } catch (e: Exception) {
                    Log.e(TAG, "startTaskInternal: 获取customIMEId异常: ${e.message}", e)
                    e.printStackTrace()
                    return false
                }
                Log.d(TAG, "startTaskInternal: customIMEId=$customIMEId")
                
                // 方法1：检查输入法服务实例是否已激活（最可靠）
                val imeService = SimpleInputMethodService.getInstance()
                val isServiceActive = imeService != null
                
                // 方法2：检查系统设置中的默认输入法ID
                val currentIME = accessibilityService.getCurrentIME()
                val normalizedCurrentIME = currentIME?.trim()?.lowercase()
                val normalizedCustomIMEId = customIMEId.trim().lowercase()
                val isIMEIdMatch = normalizedCurrentIME == normalizedCustomIMEId
                
                // 详细日志
                Log.d(TAG, "========== 输入法检查详情 ==========")
                Log.d(TAG, "  - SimpleInputMethodService实例: ${if (isServiceActive) "已激活" else "未激活"}")
                Log.d(TAG, "  - 系统默认输入法ID: $currentIME (null=${currentIME == null})")
                Log.d(TAG, "  - 目标输入法ID: $customIMEId")
                Log.d(TAG, "  - ID匹配结果: $isIMEIdMatch")
                Log.d(TAG, "  - 综合判断: 自定义输入法${if (isServiceActive || isIMEIdMatch) "已激活" else "未激活"}")
                Log.d(TAG, "=====================================")
                
                // 双重验证：只要服务已激活或ID匹配，就认为已激活（情况3：已是默认输入法）
                val isCustomIMEActive = isServiceActive || isIMEIdMatch
                
                if (isCustomIMEActive) {
                    // 情况3：已是默认输入法，无需任何操作
                    Log.d(TAG, "✓ 任务开始：自定义输入法已是默认输入法，无需切换")
                } else {
                    // 情况1或2：需要检查输入法是否已在系统中启用
                    val context = context
                    if (context == null) {
                        Log.e(TAG, "startTaskInternal: context为null，无法检查输入法")
                        return false
                    }
                    val isIMEEnabled = withContext(Dispatchers.Main) {
                        try {
                            checkIfIMEEnabled(context, customIMEId)
                        } catch (e: Exception) {
                            Log.e(TAG, "startTaskInternal: 检查输入法启用状态异常: ${e.message}", e)
                            false
                        }
                    }
                    
                    Log.d(TAG, "输入法启用状态检查: ${if (isIMEEnabled) "已启用" else "未启用"}")
                    
                    if (!isIMEEnabled) {
                        // 情况1：未在系统启用，显示引导对话框
                        Log.w(TAG, "⚠ 任务开始：自定义输入法未在系统中启用，需要先启用")
                        Log.d(TAG, "startTaskInternal: 准备显示输入法启用引导对话框")
                        
                        // 保存待发送的消息和图片，等待用户启用输入法后自动重试
                        try {
                            withContext(Dispatchers.Main) {
                                Log.d(TAG, "startTaskInternal: 进入withContext(Dispatchers.Main)，准备显示弹窗")
                                pendingQueryAfterIME = query
                                pendingImageAfterIME = selectedImageBase64
                                
                                Log.d(TAG, "startTaskInternal: 准备调用showIMEEnableGuideDialog")
                                showIMEEnableGuideDialog(customIMEId)
                                Log.d(TAG, "startTaskInternal: showIMEEnableGuideDialog调用完成")
                                
                                // 显示提示消息
                                addChatMessage("系统", "检测到输入法未启用，已保存您的消息。启用输入法后将自动发送。")
                                Log.d(TAG, "startTaskInternal: 提示消息已添加")
                            }
                            Log.d(TAG, "startTaskInternal: withContext(Dispatchers.Main)执行完成")
                        } catch (e: Exception) {
                            Log.e(TAG, "startTaskInternal: 显示输入法启用引导对话框异常: ${e.message}", e)
                            e.printStackTrace()
                        }
                        
                        // 返回false，表示任务未开始
                        Log.d(TAG, "startTaskInternal: 返回false，等待用户启用输入法")
                        return false
                    }
                    
                    // 情况2：已在系统启用但不是默认输入法，显示输入法选择器并等待用户切换
                    Log.d(TAG, "任务开始：自定义输入法已在系统中启用，但不是默认输入法，尝试切换...")
                    if (currentIME == null) {
                        Log.w(TAG, "⚠ 任务开始：无法获取当前输入法ID（可能权限不足），但输入法已在系统中启用，尝试切换...")
                    } else {
                        Log.d(TAG, "任务开始：当前默认输入法($currentIME)，需要切换到自定义输入法")
                    }
                    
                    // 尝试使用InputMethodManager.showInputMethodPicker()显示输入法选择器
                    var switchSuccess = false
                    try {
                        val context = context
                        if (context == null) {
                            Log.e(TAG, "startTaskInternal: context为null，无法显示输入法选择器")
                            return false
                        }
                        withContext(Dispatchers.Main) {
                            try {
                                // 先让输入框获得焦点，这样showInputMethodPicker()才能正常工作
                                if (_binding != null && _binding?.etChatInput != null) {
                                    Log.d(TAG, "任务开始：让输入框获得焦点")
                                    binding.etChatInput.requestFocus()
                                } else {
                                    Log.w(TAG, "任务开始：binding或输入框为null，无法设置焦点")
                                }
                            } catch (e: Exception) {
                                Log.e(TAG, "startTaskInternal: 设置输入框焦点异常: ${e.message}", e)
                                e.printStackTrace()
                            }
                        }
                        
                        // 延迟一下，确保焦点已经设置
                        delay(300)
                        
                        // 显示输入法选择器
                        withContext(Dispatchers.Main) {
                            try {
                                val imm = context.getSystemService(android.content.Context.INPUT_METHOD_SERVICE) as? android.view.inputmethod.InputMethodManager
                                if (imm != null) {
                                    Log.d(TAG, "任务开始：调用showInputMethodPicker()显示输入法选择器")
                                    try {
                                        imm.showInputMethodPicker()
                                        Log.d(TAG, "任务开始：showInputMethodPicker()已调用")
                                    } catch (e: Exception) {
                                        Log.e(TAG, "任务开始：showInputMethodPicker()调用失败: ${e.message}", e)
                                        e.printStackTrace()
                                    }
                                } else {
                                    Log.e(TAG, "任务开始：无法获取InputMethodManager")
                                }
                            } catch (e: Exception) {
                                Log.e(TAG, "startTaskInternal: 获取InputMethodManager异常: ${e.message}", e)
                                e.printStackTrace()
                            }
                        }
                        
                        // 等待用户选择输入法（最多5秒）
                        Log.d(TAG, "任务开始：等待用户选择输入法（最多5秒）...")
                        for (i in 1..10) {
                            delay(500)
                            // 重新检查：优先检查服务实例，再检查ID
                            val newImeService = SimpleInputMethodService.getInstance()
                            val newIME = accessibilityService.getCurrentIME()
                            val newNormalizedIME = newIME?.trim()?.lowercase()
                            
                            if (newImeService != null || newNormalizedIME == normalizedCustomIMEId) {
                                Log.d(TAG, "✓ 任务开始：已切换到自定义输入法（等待${i * 500}ms后检测到）")
                                switchSuccess = true
                                break
                            }
                        }
                        
                        if (!switchSuccess) {
                            // 切换失败，保存待发送的消息和图片，等待用户手动切换后重试
                            Log.w(TAG, "⚠ 任务开始：等待5秒后仍未切换到自定义输入法")
                            val finalIME = accessibilityService.getCurrentIME()
                            val finalImeService = SimpleInputMethodService.getInstance()
                            Log.w(TAG, "  - 当前输入法ID: $finalIME")
                            Log.w(TAG, "  - 输入法服务状态: ${if (finalImeService != null) "已激活" else "未激活"}")
                            
                            // 保存待发送的消息和图片，等待用户切换输入法后自动重试
                            try {
                                Log.d(TAG, "startTaskInternal: 准备显示输入法切换对话框")
                                withContext(Dispatchers.Main) {
                                    Log.d(TAG, "startTaskInternal: 进入withContext(Dispatchers.Main)，准备显示切换弹窗")
                                    pendingQueryAfterIME = query
                                    pendingImageAfterIME = selectedImageBase64
                                    
                                    Log.d(TAG, "startTaskInternal: 准备调用showIMESwitchDialog")
                                    try {
                                        Log.d(TAG, "startTaskInternal: 开始调用showIMESwitchDialog函数")
                                        showIMESwitchDialog()
                                        Log.d(TAG, "startTaskInternal: showIMESwitchDialog函数调用返回")
                                    } catch (e: Exception) {
                                        Log.e(TAG, "startTaskInternal: 调用showIMESwitchDialog时出现异常: ${e.message}", e)
                                        e.printStackTrace()
                                    }
                                    Log.d(TAG, "startTaskInternal: showIMESwitchDialog调用完成")
                                }
                                Log.d(TAG, "startTaskInternal: withContext(Dispatchers.Main)执行完成")
                            } catch (e: Exception) {
                                Log.e(TAG, "startTaskInternal: 显示输入法切换对话框异常: ${e.message}", e)
                                e.printStackTrace()
                            }
                            
                            // 返回false，表示任务未开始，等待用户切换输入法后再重试
                            Log.d(TAG, "任务开始：等待用户切换输入法，任务暂不开始")
                            return false
                        }
                    } catch (e: Exception) {
                        // 重新抛出CancellationException，避免吞掉协程取消信号
                        if (e is kotlinx.coroutines.CancellationException) throw e
                        Log.e(TAG, "任务开始：显示输入法选择器失败: ${e.message}", e)
                        // 异常情况下也保存待发送的消息
                        withContext(Dispatchers.Main) {
                            pendingQueryAfterIME = query
                            pendingImageAfterIME = selectedImageBase64
                        }
                        return false
                    }
                    
                    // 切换成功，继续执行任务设置（不返回false）
                    Log.d(TAG, "✓ 任务开始：输入法切换成功，继续执行任务")
                }
                } else {
                    // 无障碍服务未启用，无法检查键盘，返回false
                    Log.e(TAG, "startTaskInternal: 无障碍服务实例为null，无法检查输入法，任务未开始。等待2秒后仍为null，转入待恢复状态")
                    withContext(Dispatchers.Main) {
                        val oldPending = pendingQueryAfterAccessibility
                        pendingQueryAfterAccessibility = query
                        if (oldPending != query) {
                            addChatMessage("系统", "无障碍服务连接中，连接成功后将自动继续并检查输入法...")
                        }
                    }
                    ensurePendingAccessibilityRecovery("startTaskInternal(服务未连接)")
                    return false
                }
        } catch (e: Exception) {
            // 重新抛出CancellationException，避免吞掉协程取消信号导致在Fragment销毁后继续执行
            if (e is kotlinx.coroutines.CancellationException) throw e
            Log.e(TAG, "任务开始：切换输入法时出错: ${e.message}", e)
            e.printStackTrace()
            // 打印完整堆栈
            val sw = java.io.StringWriter()
            val pw = java.io.PrintWriter(sw)
            e.printStackTrace(pw)
            Log.e(TAG, "任务开始：切换输入法异常堆栈:\n${sw.toString()}")
            // 异常情况下也返回false，确保任务不会在键盘检查失败时开始
            return false
        }
        
        // 设置任务状态（只有在输入法检查通过后才执行）
        // 确保推荐任务面板始终显示（收起状态）
        try {
            // 再次检查Fragment状态
            if (!isAdded || view == null || _binding == null) {
                Log.e(TAG, "startTaskInternal: Fragment状态无效，无法设置任务状态")
                return false
            }
            
            try {
                binding.llRecommendationsPanel.visibility = android.view.View.VISIBLE
                isRecommendationsExpanded = false
                binding.llRecommendationsContent.visibility = android.view.View.GONE
            } catch (e: Exception) {
                Log.e(TAG, "startTaskInternal: 更新推荐面板异常: ${e.message}", e)
            }
            
            isTaskRunning = true
            isTaskPaused = false  // 任务开始时未暂停
            currentQuery = query
            currentStep = 0  // 初始化步骤号
            isFirstSendInTask = true  // 任务开始时标记为第一次发送
            screenshotFailCount = 0  // 重置截图失败计数
            
            // 记录任务开始时间（作为第一次交互时间）
            lastInteractionTime = System.currentTimeMillis()
            
            // 启动交互超时监测
            try {
                startInteractionTimeoutMonitoring()
            } catch (e: Exception) {
                Log.e(TAG, "startTaskInternal: 启动交互超时监测异常: ${e.message}", e)
            }
            
            // 启动剪切板监视（如果启用）
            try {
                val context = context
                if (context != null) {
                    ClipboardMonitorManager.startMonitoring(context, chatUuid)
                }
            } catch (e: Exception) {
                Log.e(TAG, "startTaskInternal: 启动剪切板监视异常: ${e.message}", e)
            }
            
            // 通知MainActivity任务已开始
            mainActivity?.isTaskRunning = true
            
            // 更新悬浮窗状态（任务运行中）
            try {
                TaskIndicatorOverlayManager.updateOverlayForTaskStatus(true)
            } catch (e: Exception) {
                Log.e(TAG, "startTaskInternal: 更新悬浮窗状态异常: ${e.message}", e)
            }
            
            // 显示炫彩边框特效
            try {
                BorderEffectOverlayManager.show(requireContext())
            } catch (e: Exception) {
                Log.e(TAG, "startTaskInternal: 显示边框特效异常: ${e.message}", e)
            }
            
            try {
                binding.btnSendChat.isEnabled = true
                binding.btnStopTask.visibility = View.VISIBLE
            } catch (e: Exception) {
                Log.e(TAG, "startTaskInternal: 更新按钮状态异常: ${e.message}", e)
            }
            
            // 更新按钮可见性
            try {
                updateButtonVisibility()
            } catch (e: Exception) {
                Log.e(TAG, "startTaskInternal: 更新按钮可见性异常: ${e.message}", e)
            }
            
            // 检查悬浮窗功能是否开启，如果开启了且浮窗未显示，就显示浮窗
            // 这样问字按钮触发的任务也能显示浮窗
            try {
                val context = context
                if (mainActivity != null && context != null) {
                    val prefs = context.getSharedPreferences("app_prefs", android.content.Context.MODE_PRIVATE)
                    val overlayEnabled = prefs.getBoolean("task_indicator_overlay_enabled", true) // 默认true（打开）
                    if (overlayEnabled && !TaskIndicatorOverlayManager.isOverlayShowing()) {
                        Log.d(TAG, "任务启动，悬浮窗功能已开启，显示任务指示器")
                        TaskIndicatorOverlayManager.show(mainActivity)
                    }
                }
            } catch (e: Exception) {
                Log.e(TAG, "startTaskInternal: 检查悬浮窗功能异常: ${e.message}", e)
            }
            
            Log.d(TAG, "========== startTaskInternal 执行完成，返回true ==========")
            return true
        } catch (e: Exception) {
            Log.e(TAG, "startTaskInternal: 设置任务状态异常: ${e.message}", e)
            e.printStackTrace()
            return false
        }
    }
    
    
    /**
     * 检查输入法是否已在系统中启用（在输入法管理界面中启用）
     * @param context 上下文
     * @param customIMEId 自定义输入法的完整ID（格式：packageName/className）
     * @return 是否已启用
     */
    private fun checkIfIMEEnabled(context: Context, customIMEId: String): Boolean {
        return try {
            val imm = context.getSystemService(android.content.Context.INPUT_METHOD_SERVICE) as? android.view.inputmethod.InputMethodManager
            if (imm == null) {
                Log.w(TAG, "无法获取InputMethodManager，无法检查输入法启用状态")
                return false
            }
            
            val enabledInputMethods = imm.enabledInputMethodList
            val normalizedCustomIMEId = customIMEId.trim().lowercase()
            
            // 提取包名用于额外匹配
            val packageName = context.packageName.lowercase()
            
            Log.d(TAG, "========== 检查输入法启用状态 ==========")
            Log.d(TAG, "  - 目标输入法ID: $customIMEId")
            Log.d(TAG, "  - 目标输入法ID(规范化): $normalizedCustomIMEId")
            Log.d(TAG, "  - 应用包名: $packageName")
            Log.d(TAG, "  - 已启用的输入法数量: ${enabledInputMethods.size}")
            
            for (inputMethod in enabledInputMethods) {
                val imeId = inputMethod.id.trim().lowercase()
                val imePackageName = inputMethod.packageName.lowercase()
                
                Log.d(TAG, "  - 已启用输入法:")
                Log.d(TAG, "    * ID: ${inputMethod.id}")
                Log.d(TAG, "    * ID(规范化): $imeId")
                Log.d(TAG, "    * 包名: ${inputMethod.packageName}")
                
                // 精确匹配：ID完全一致
                if (imeId == normalizedCustomIMEId) {
                    Log.d(TAG, "✓ 找到匹配（精确匹配ID）")
                    return true
                }
                
                // 备用匹配：包名匹配且ID包含SimpleInputMethodService
                if (imePackageName == packageName && 
                    (imeId.contains("simpleinputmethodservice", ignoreCase = true) ||
                     imeId.contains("inputmethod", ignoreCase = true))) {
                    Log.d(TAG, "✓ 找到匹配（包名+类名匹配）")
                    return true
                }
            }
            
            Log.w(TAG, "✗ 自定义输入法未在系统中启用")
            Log.d(TAG, "=====================================")
            false
        } catch (e: Exception) {
            Log.e(TAG, "检查输入法启用状态失败: ${e.message}", e)
            e.printStackTrace()
            false
        }
    }
    
    /**
     * 显示输入法切换提示弹窗
     */
    private fun showIMESwitchDialog() {
        Log.d(TAG, "showIMESwitchDialog: 函数被调用")
        try {
            Log.d(TAG, "showIMESwitchDialog: 开始显示弹窗")
            Log.d(TAG, "showIMESwitchDialog: Fragment状态 - isAdded=$isAdded, context=${context}")
            Log.d(TAG, "showIMESwitchDialog: 准备调用requireContext()")
            val context = requireContext()
            Log.d(TAG, "showIMESwitchDialog: requireContext()返回成功，context=$context")
            val dialog = android.app.AlertDialog.Builder(context)
                .setTitle("需要切换输入法")
                .setMessage("任务开始前需要将输入法换成自定义输入法，请在更改输入法弹窗出现时点击 TopoClaw。")
                .setPositiveButton("确定", null)  // 点击确定只是关闭弹窗，不做任何操作
                .setCancelable(true)
                .create()
            Log.d(TAG, "showIMESwitchDialog: 弹窗已创建，准备显示")
            dialog.show()
            Log.d(TAG, "showIMESwitchDialog: 弹窗已显示")
        } catch (e: Exception) {
            Log.e(TAG, "显示输入法切换提示弹窗失败: ${e.message}", e)
            e.printStackTrace()
        }
    }

    private fun showIMESwitchDialogWithPicker() {
        try {
            val ctx = requireContext()
            val dialog = android.app.AlertDialog.Builder(ctx)
                .setTitle("需要切换输入法")
                .setMessage("任务开始前需要将输入法换成自定义输入法，请在弹窗中选择 TopoClaw。")
                .setPositiveButton("切换输入法") { _, _ ->
                    try {
                        _binding?.etChatInput?.requestFocus()
                        val imm = ctx.getSystemService(Context.INPUT_METHOD_SERVICE) as? InputMethodManager
                        imm?.showInputMethodPicker()
                        Log.d(TAG, "showIMESwitchDialogWithPicker: 用户点击确定后弹出系统输入法选择器")
                    } catch (e: Exception) {
                        Log.e(TAG, "showIMESwitchDialogWithPicker: showInputMethodPicker 失败: ${e.message}", e)
                    }
                }
                .setNegativeButton("取消") { _, _ ->
                    val gui = pendingCustomAssistantAfterIME?.guiExecuteContext
                    if (gui != null) {
                        pendingCustomAssistantAfterIME = null
                        gui.sendResult(null, "用户取消切换输入法")
                    }
                }
                .setCancelable(true)
                .create()
            dialog.show()
            addChatMessage("系统", "需要切换到 TopoClaw 输入法后才能执行，请在弹窗中选择 TopoClaw")
        } catch (e: Exception) {
            Log.e(TAG, "showIMESwitchDialogWithPicker 失败: ${e.message}", e)
        }
    }
    
    /**
     * 启动输入法变化监听，检测用户是否已切换到自定义输入法
     */
    private fun startIMEChangeMonitoring() {
        val pendingQuery = pendingQueryAfterIME
        val pendingImage = pendingImageAfterIME
        
        if (pendingQuery == null) {
            Log.d(TAG, "startIMEChangeMonitoring: 没有待发送的消息，无需监听")
            return
        }
        
        Log.d(TAG, "startIMEChangeMonitoring: 开始监听输入法变化，待发送消息: $pendingQuery")
        
        mainScope.launch {
            val accessibilityService = MyAccessibilityService.getInstance()
            if (accessibilityService == null) {
                Log.w(TAG, "startIMEChangeMonitoring: 无障碍服务未启用，无法监听")
                return@launch
            }
            
            val customIMEId = "${requireContext().packageName}/${SimpleInputMethodService::class.java.name}"
            val normalizedCustomIMEId = customIMEId.trim().lowercase()
            
            // 先等待2秒，给用户足够的时间去点击输入法选择器
            Log.d(TAG, "startIMEChangeMonitoring: 等待2秒，给用户时间选择输入法...")
            delay(2000)
            
            // 记录开始监听时的输入法状态（用于判断是否真的发生了切换）
            val initialImeService = SimpleInputMethodService.getInstance()
            val initialIME = accessibilityService.getCurrentIME()
            val normalizedInitialIME = initialIME?.trim()?.lowercase()
            val initialIsServiceActive = initialImeService != null
            val initialIsIMEIdMatch = normalizedInitialIME == normalizedCustomIMEId
            val initialIsCustomIMEActive = initialIsServiceActive || initialIsIMEIdMatch
            
            Log.d(TAG, "startIMEChangeMonitoring: 初始输入法状态 - 服务激活: $initialIsServiceActive, ID匹配: $initialIsIMEIdMatch, 是自定义输入法: $initialIsCustomIMEActive")
            
            // 如果初始状态就已经是自定义输入法，说明用户可能已经选择了，但为了安全起见，再等待一下确认
            if (initialIsCustomIMEActive) {
                Log.d(TAG, "startIMEChangeMonitoring: 初始状态已是自定义输入法，等待1秒确认...")
                delay(1000)
                
                // 再次检查确认
                val confirmImeService = SimpleInputMethodService.getInstance()
                val confirmIME = accessibilityService.getCurrentIME()
                val normalizedConfirmIME = confirmIME?.trim()?.lowercase()
                val confirmIsServiceActive = confirmImeService != null
                val confirmIsIMEIdMatch = normalizedConfirmIME == normalizedCustomIMEId
                val confirmIsCustomIMEActive = confirmIsServiceActive || confirmIsIMEIdMatch
                
                if (confirmIsCustomIMEActive) {
                    Log.d(TAG, "✓ startIMEChangeMonitoring: 确认输入法已切换为自定义输入法")
                    
                    // 恢复图片并自动发送待发送的消息
                    withContext(Dispatchers.Main) {
                        pendingQueryAfterIME = null
                        selectedImageBase64 = pendingImageAfterIME
                        pendingImageAfterIME = null
                        
                        addChatMessage("系统", "输入法已切换为默认输入法，正在自动发送消息...")
                        executeQueryInternal(pendingQuery)
                    }
                    return@launch
                } else {
                    Log.d(TAG, "startIMEChangeMonitoring: 确认检查时输入法已不是自定义输入法，继续监听...")
                }
            }
            
            // 监听最多10秒（每500ms检查一次）
            for (i in 1..20) {
                delay(500)
                
                // 检查输入法是否已切换为自定义输入法
                val imeService = SimpleInputMethodService.getInstance()
                val isServiceActive = imeService != null
                val currentIME = accessibilityService.getCurrentIME()
                val normalizedCurrentIME = currentIME?.trim()?.lowercase()
                val isIMEIdMatch = normalizedCurrentIME == normalizedCustomIMEId
                val isCustomIMEActive = isServiceActive || isIMEIdMatch
                
                // 只有当输入法从非自定义变为自定义时，才执行任务（确保用户真的切换了）
                if (isCustomIMEActive && !initialIsCustomIMEActive) {
                    Log.d(TAG, "✓ startIMEChangeMonitoring: 检测到输入法已从非自定义切换为自定义输入法（等待${2000 + i * 500}ms后检测到）")
                    
                    // 恢复图片并自动发送待发送的消息
                    withContext(Dispatchers.Main) {
                        pendingQueryAfterIME = null
                        selectedImageBase64 = pendingImageAfterIME
                        pendingImageAfterIME = null
                        
                        addChatMessage("系统", "输入法已切换为默认输入法，正在自动发送消息...")
                        executeQueryInternal(pendingQuery)
                    }
                    return@launch
                }
            }
            
            Log.w(TAG, "startIMEChangeMonitoring: 等待12秒后仍未检测到输入法切换")
        }
    }
    
    /**
     * 显示输入法启用引导对话框
     * @param customIMEId 自定义输入法的完整ID
     * @param forCustomAssistantExecution 自定义小助手/gui_execute 执行链：第 4 步文案为继续执行而非发送消息
     * @param onNegative 取消时回调（如 gui_execute 回传错误）
     */
    private fun showIMEEnableGuideDialog(
        customIMEId: String,
        forCustomAssistantExecution: Boolean = false,
        onNegative: (() -> Unit)? = null
    ) {
        try {
            Log.d(TAG, "showIMEEnableGuideDialog: 开始显示弹窗，customIMEId=$customIMEId")
            Log.d(TAG, "showIMEEnableGuideDialog: Fragment状态 - isAdded=$isAdded, context=${context}")
            val step4 = if (forCustomAssistantExecution) {
                "4. 返回应用后将自动继续执行操作"
            } else {
                "4. 返回应用后将自动发送您的消息"
            }
            val dialog = android.app.AlertDialog.Builder(requireContext())
                .setTitle("需要启用输入法")
                .setMessage("检测到 TopoClaw 输入法未在系统中启用。\n\n" +
                        "请按照以下步骤操作：\n" +
                        "1. 点击\"去设置\"按钮\n" +
                        "2. 在输入法列表中找到 \"TopoClaw\"\n" +
                        "3. 打开开关启用该输入法\n" +
                        step4)
                .setPositiveButton("去设置") { _, _ ->
                    try {
                        val intent = Intent(Settings.ACTION_INPUT_METHOD_SETTINGS).apply {
                            flags = Intent.FLAG_ACTIVITY_NEW_TASK
                        }
                        startActivity(intent)
                        Log.d(TAG, "已跳转到输入法设置页面")
                    } catch (e: Exception) {
                        Log.e(TAG, "跳转到输入法设置页面失败: ${e.message}", e)
                        Toast.makeText(requireContext(), "打开设置失败: ${e.message}", Toast.LENGTH_SHORT).show()
                    }
                }
                .setNegativeButton("取消") { _, _ -> onNegative?.invoke() }
                .setCancelable(true)
                .create()
            Log.d(TAG, "showIMEEnableGuideDialog: 弹窗已创建，准备显示")
            dialog.show()
            Log.d(TAG, "showIMEEnableGuideDialog: 弹窗已显示")
        } catch (e: Exception) {
            Log.e(TAG, "显示输入法启用引导对话框失败: ${e.message}", e)
            e.printStackTrace()
        }
    }
    
    /**
     * 启动交互超时监测
     */
    private fun startInteractionTimeoutMonitoring() {
        // 取消之前的监测Job
        interactionTimeoutJob?.cancel()
        
        interactionTimeoutJob = mainScope.launch {
            while (isTaskRunning) {
                delay(5000) // 每5秒检查一次
                
                val currentTime = System.currentTimeMillis()
                val elapsedTime = currentTime - lastInteractionTime
                
                if (elapsedTime > INTERACTION_TIMEOUT) {
                    Log.w(TAG, "任务交互超时: elapsedTime=${elapsedTime}ms")
                    withContext(Dispatchers.Main) {
                        // 停止任务
                        stopTask()
                        // 返回应用
                        (activity as? MainActivity)?.bringAppToForeground()
                        // 显示超时消息
                        addChatMessage("系统", "请求超时")
                    }
                    break
                }
            }
        }
    }
    
    /**
     * 更新最后一次交互时间
     */
    private fun updateLastInteractionTime() {
        lastInteractionTime = System.currentTimeMillis()
        Log.d(TAG, "更新最后一次交互时间: $lastInteractionTime")
    }
    
    // 加载中检测重试计数（用于异常检测）
    private var loadingRetryCount = 0
    private val maxLoadingRetries = 3
    
    // 端侧异常检测状态管理
    private var hasJustCalledUser = false  // 标记是否刚刚执行了 call_user（执行后必须上发云侧）
    private var consecutiveWaitCount = 0  // 连续 wait 的次数（最多 1 次）
    private var isWaitRetry = false  // 是否是 wait 后的重试（用于避免误判截图失败）
    
    // 截图失败重试计数
    private var screenshotFailCount = 0
    private val maxScreenshotFailRetries = 3
    
    /**
     * 处理截图并进行异常检测（用于ChatFragment）
     * @param bitmap 截图
     * @return Pair<Boolean, Boolean> 第一个值表示是否应该发送到云侧，第二个值表示是否是wait（用于区分call_user和wait）
     */
    private suspend fun processScreenshotWithAnomalyDetection(bitmap: android.graphics.Bitmap): Pair<Boolean, Boolean> {
        Log.i(TAG, "========== [ChatFragment] 开始异常检测 ==========")
        
        // 检查端侧模型开关
        if (!ScreenshotService.isEdgeModelEnabled(requireContext())) {
            Log.i(TAG, "[开关] 端侧模型已禁用，直接发送到云侧")
            // 重置状态
            hasJustCalledUser = false
            consecutiveWaitCount = 0
            isWaitRetry = false
            return Pair(true, false)  // 发送到云侧，不是wait
        }
        
        // 检查是否刚刚执行了 call_user，如果是，必须发送到云侧
        if (hasJustCalledUser) {
            Log.i(TAG, "[状态检查] 刚刚执行了 call_user，强制发送到云侧")
            hasJustCalledUser = false  // 重置状态
            consecutiveWaitCount = 0   // 重置 wait 计数
            isWaitRetry = false
            return Pair(true, false)  // 发送到云侧，不是wait
        }
        
        val manager = AnomalyDetectionManager.getInstance(requireContext())
        
        try {
            // 1. 检测异常
            Log.i(TAG, "[异常检测] 开始检测，截图尺寸: ${bitmap.width}x${bitmap.height}")
            val detectionResult = manager.detect(bitmap)
            
            // 打印完整的检测结果（使用Log.i确保输出，每条日志单独打印避免被截断）
            Log.i(TAG, "========== 异常检测结果详情 ==========")
            Log.i(TAG, "[检测结果] hasAnomaly = ${detectionResult.hasAnomaly}")
            Log.i(TAG, "[检测结果] anomalyType = ${detectionResult.anomalyType}")
            Log.i(TAG, "[检测结果] anomalyTypeName = ${getAnomalyTypeName(detectionResult.anomalyType)}")
            Log.i(TAG, "[检测结果] anomalyConfidence = ${detectionResult.anomalyConfidence}")
            Log.i(TAG, "[检测结果] closeButtonX (归一化) = ${detectionResult.closeButtonX}")
            Log.i(TAG, "[检测结果] closeButtonY (归一化) = ${detectionResult.closeButtonY}")
            Log.i(TAG, "[检测结果] closeButtonConfidence = ${detectionResult.closeButtonConfidence}")
            Log.i(TAG, "[检测结果] 截图尺寸 = ${bitmap.width}x${bitmap.height}")
            
            // 构建检测结果消息并显示到系统消息
            val resultMessage = StringBuilder()
            resultMessage.append("【异常检测结果】\n")
            resultMessage.append("截图尺寸: ${bitmap.width}x${bitmap.height}\n")
            resultMessage.append("检测到异常: ${if (detectionResult.hasAnomaly) "是" else "否"}\n")
            
            if (detectionResult.hasAnomaly) {
                val anomalyTypeName = getAnomalyTypeName(detectionResult.anomalyType)
                resultMessage.append("异常类型: $anomalyTypeName(${detectionResult.anomalyType})\n")
                resultMessage.append("异常置信度: ${String.format("%.2f", detectionResult.anomalyConfidence ?: 0f)}\n")
            }
            
            // 如果有关闭按钮，计算并打印实际坐标
            if (detectionResult.closeButtonX != null && detectionResult.closeButtonY != null) {
                val (actualX, actualY) = manager.normalizeToActualCoordinates(
                    detectionResult.closeButtonX,
                    detectionResult.closeButtonY,
                    bitmap.width,
                    bitmap.height
                )
                Log.i(TAG, "[检测结果] 关闭按钮实际坐标 = ($actualX, $actualY)")
                Log.i(TAG, "[检测结果] 坐标映射: 归一化(${detectionResult.closeButtonX}, ${detectionResult.closeButtonY}) -> 实际($actualX, $actualY)")
                Log.i(TAG, "[检测结果] 坐标计算: X=${detectionResult.closeButtonX} * ${bitmap.width} = $actualX, Y=${detectionResult.closeButtonY} * ${bitmap.height} = $actualY")
                
                resultMessage.append("关闭按钮位置: ($actualX, $actualY)\n")
                resultMessage.append("关闭按钮置信度: ${String.format("%.2f", detectionResult.closeButtonConfidence ?: 0f)}\n")
            } else {
                Log.i(TAG, "[检测结果] 未检测到关闭按钮")
                resultMessage.append("关闭按钮: 未检测到\n")
            }
            
            // 添加到系统消息
            withContext(Dispatchers.Main) {
                addChatMessage("系统", resultMessage.toString().trim())
            }
            
            Log.i(TAG, "=====================================")
            
            if (detectionResult.hasAnomaly) {
                val anomalyTypeName = getAnomalyTypeName(detectionResult.anomalyType)
                Log.i(TAG, "[异常检测] ✓✓✓ 检测到异常: type=$anomalyTypeName(${detectionResult.anomalyType}), confidence=${detectionResult.anomalyConfidence}")
                
                // 2. 处理异常
                val handled = handleAnomalyInChat(detectionResult, bitmap)
                
                if (handled) {
                    Log.i(TAG, "[异常处理] ✓✓✓ 异常已在端侧处理成功（call_user），跳过云侧请求")
                    // call_user 已处理，等待后重新检测
                    delay(1000)
                    return Pair(false, false) // 不发送到云侧，不是wait（是call_user）
                } else {
                    // 其他异常类型，发送到云侧
                    Log.i(TAG, "[异常处理] 发送到云侧处理")
                    consecutiveWaitCount = 0  // 重置 wait 计数
                    return Pair(true, false)  // 发送到云侧，不是wait
                }
            } else {
                // 3. 无异常，检查是否加载中
                val isLoading = manager.checkLoading(bitmap)
                
                // 添加加载检测结果到系统消息
                val loadingMessage = StringBuilder()
                loadingMessage.append("【加载状态检测】\n")
                loadingMessage.append("页面状态: ${if (isLoading) "加载中" else "加载完成"}\n")
                
                if (isLoading) {
                    consecutiveWaitCount++
                    Log.i(TAG, "[加载检测] ⏳ 检测到页面加载中，连续 wait 计数: $consecutiveWaitCount/1")
                    loadingMessage.append("连续 wait 计数: $consecutiveWaitCount/1\n")
                    
                    // 添加到系统消息
                    withContext(Dispatchers.Main) {
                        addChatMessage("系统", loadingMessage.toString().trim())
                    }
                    
                    if (consecutiveWaitCount < 1) {
                        // 等待后重试（wait）
                        Log.d(TAG, "[加载处理] 等待2秒后重试（wait），跳过云侧请求")
                        delay(2000)
                        return Pair(false, true) // 不发送到云侧，是wait
                    } else {
                        // 超过最大连续 wait 次数（1次），发送到云侧
                        Log.w(TAG, "[加载处理] 超过最大连续 wait 次数（1次），发送到云侧")
                        consecutiveWaitCount = 0  // 重置计数
                        return Pair(true, false)  // 发送到云侧，不是wait
                    }
                } else {
                    // 正常页面，发送到云侧
                    // 注意：不在这里重置 consecutiveWaitCount，只在发送到云侧时重置
                    loadingRetryCount = 0     // 重置旧的计数（兼容）
                    Log.i(TAG, "[异常检测] 正常页面（无异常且未加载中），发送到云侧")
                    
                    // 添加到系统消息
                    withContext(Dispatchers.Main) {
                        addChatMessage("系统", loadingMessage.toString().trim())
                    }
                    
                    // 发送到云侧时，在 performSendChatMessage 中会重置 consecutiveWaitCount
                    return Pair(true, false)  // 发送到云侧，不是wait
                }
            }
        } catch (e: Exception) {
            Log.e(TAG, "[异常检测] ✗✗✗ 处理失败: ${e.message}", e)
            // 检测失败，降级到云侧处理
            return Pair(true, false)  // 发送到云侧，不是wait
        }
    }
    
    /**
     * 获取异常类型名称
     */
    private fun getAnomalyTypeName(type: Int?): String {
        return when (type) {
            0 -> "权限类"
            1 -> "登录类"
            2 -> "验证类"
            3 -> "支付类"
            4 -> "隐私类"
            else -> "未知类型"
        }
    }
    
    /**
     * 处理检测到的异常（ChatFragment版本）
     * @param detectionResult 检测结果
     * @param bitmap 原始截图
     * @return true表示处理成功，false表示处理失败
     */
    private suspend fun handleAnomalyInChat(
        detectionResult: AnomalyDetectionManager.DetectionResult,
        bitmap: android.graphics.Bitmap
    ): Boolean {
        return try {
            val anomalyType = detectionResult.anomalyType
            val anomalyTypeName = getAnomalyTypeName(anomalyType)
            Log.i(TAG, "[异常处理] 检测到异常，异常类型: $anomalyTypeName($anomalyType), confidence=${detectionResult.anomalyConfidence}")
            
            // 新模型类别0-4（权限类、登录类、验证类、支付类、隐私类）均需要用户操作
            when (anomalyType) {
                0, 1, 2, 3, 4 -> {
                    Log.i(TAG, "[异常处理] 需要用户操作的异常类型($anomalyTypeName)，返回call_user动作")
                    val callUserText = "检测到$anomalyTypeName，请手动操作"
                    handleCallUserFromAnomalyDetection(callUserText)
                    true
                }
                else -> {
                    Log.i(TAG, "[异常处理] 异常类型($anomalyTypeName)，发送到云侧处理")
                    false
                }
            }
        } catch (e: Exception) {
            Log.e(TAG, "处理异常时出错: ${e.message}", e)
            false
        }
    }
    
    /**
     * 重新执行TYPE操作（用于输入法切换后重试）
     */
    private suspend fun retryTypeOperation() {
        val params = pendingTypeParams
        if (params == null) {
            Log.w(TAG, "retryTypeOperation: 没有待重试的TYPE参数")
            return
        }
        
        val (x, y, text) = params
        val autoSubmit = pendingTypeAutoSubmit
        
        // 判断是否有坐标：如果x和y都为0，认为是无坐标的情况（直接输入到当前聚焦的输入框）
        val hasCoordinates = !(x == 0 && y == 0)
        
        Log.d(TAG, "========== 重新执行TYPE操作 ==========")
        Log.d(TAG, "坐标: ($x, $y), 文本: $text, autoSubmit: $autoSubmit, hasCoordinates: $hasCoordinates")
        
        val accessibilityService = MyAccessibilityService.getInstance()
        if (accessibilityService == null || Build.VERSION.SDK_INT < Build.VERSION_CODES.N) {
            Log.e(TAG, "retryTypeOperation: 无障碍服务不可用")
            pendingTypeParams = null
            pendingTypeAutoSubmit = false
            return
        }
        
        var inputSuccess = false
        
        if (hasCoordinates) {
            // 有坐标：先点击坐标，再输入文本
            // 显示输入效果
            withContext(Dispatchers.Main) {
                InteractionOverlayManager.showInputEffect(x, y)
            }
            
            // 模型发起：在点击输入框前隐藏键盘
            if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.N) {
                MyAccessibilityService.prepareForModelInput()
            }
            
            // 点击输入框
            val clickSuccess = accessibilityService.performClick(x, y, fromModel = true)
            // 无论成功与否都需恢复 IME 模式
            MyAccessibilityService.hideKeyboardAfterClickWithRetries()
            
            if (!clickSuccess) {
                Log.w(TAG, "retryTypeOperation: 点击输入框失败")
                withContext(Dispatchers.Main) {
                    addChatMessage("系统", "✗ 点击输入框失败: ($x, $y)")
                }
                pendingTypeParams = null
                pendingTypeAutoSubmit = false
                return
            }
            
            delay(300)
            
            // 输入文本
            inputSuccess = withContext(Dispatchers.Main) {
                accessibilityService.inputText(text, fromModel = true)
            }
        } else {
            // 无坐标：直接输入到当前聚焦的输入框
            Log.d(TAG, "retryTypeOperation: 无坐标，直接输入到当前聚焦的输入框")
            inputSuccess = withContext(Dispatchers.Main) {
                accessibilityService.inputText(text, fromModel = true)
            }
        }
        
        if (inputSuccess) {
            Log.d(TAG, "retryTypeOperation: ✓ 输入成功")
            
            // 处理自动提交
            if (autoSubmit) {
                delay(200)
                val currentContext = context
                if (currentContext != null) {
                    val enterIntent = Intent(SimpleInputMethodService.ACTION_SEND_ENTER).apply {
                        setPackage(currentContext.packageName)
                    }
                    currentContext.sendBroadcast(enterIntent)
                }
                delay(100)
            }
            
            withContext(Dispatchers.Main) {
                val submitText = if (autoSubmit) "并自动提交搜索" else ""
                if (hasCoordinates) {
                    addChatMessage("系统", "✓ 已执行输入: 点击($x, $y)后输入\"$text\"$submitText")
                } else {
                    addChatMessage("系统", "✓ 已执行输入: 输入\"$text\"$submitText")
                }
            }
            
            // 清空待重试参数
            pendingTypeParams = null
            pendingTypeAutoSubmit = false
            
            // 延迟后继续任务循环（截图并发送到云侧）
            delay(500)
            if (isTaskRunning) {
                continueTaskLoop()
            }
        } else {
            Log.w(TAG, "retryTypeOperation: ✗ 输入失败")
            withContext(Dispatchers.Main) {
                addChatMessage("系统", "✗ 输入文本失败: $text")
            }
            pendingTypeParams = null
            pendingTypeAutoSubmit = false
        }
    }
    
    /**
     * 停止任务
     * @param delaySummary 是否延迟调用总结（默认false，用于确保所有消息都已保存）
     */
    fun stopTask(delaySummary: Boolean = false) {
        if (!isTaskRunning && !isCustomAssistantProcessing) {
            return
        }
        if (!isTaskRunning && isCustomAssistantProcessing) {
            isCustomAssistantProcessing = false
            try { updateButtonVisibility() } catch (_: Exception) {}
            // 仅 custom assistant processing 的快速收尾分支，也要清理任务来源标记，
            // 避免后续应用内任务误判为悬浮球来源而弹结果窗。
            val mainActivity = activity as? MainActivity
            mainActivity?.isTaskFromExternalApp = false
            mainActivity?.isTaskFromCompanionMode = false
            mainActivity?.isCompanionAskScreenEnabled = false
            mainActivity?.originalPackageName = null
            Log.d(TAG, "stopTask - 快速收尾已清除任务来源标记")
            return
        }
        
        isTaskRunning = false
        isTaskPaused = false  // 停止任务时清除暂停状态
        isManualTakeover = false  // 停止任务时清除手动接管状态
        isCustomAssistantProcessing = false
        currentQuery = null
        isFirstSendInTask = false  // 停止任务时清除第一次发送标志
        currentStep = 0  // 重置步骤号
        loadingRetryCount = 0  // 重置加载重试计数
        screenshotFailCount = 0  // 重置截图失败计数
        mediumScreenshotBase64 = null  // 清理medium截图
        taskJob?.cancel()
        taskJob = null
        
        // 停止交互超时监测
        interactionTimeoutJob?.cancel()
        interactionTimeoutJob = null
        lastInteractionTime = 0
        
        // 停止剪切板监视
        try {
            val context = context
            if (context != null) {
                ClipboardMonitorManager.stopMonitoring(context)
            }
        } catch (e: Exception) {
            Log.e(TAG, "stopTask: 停止剪切板监视异常: ${e.message}", e)
        }
        
        // 恢复原始输入法
        if (originalIME != null) {
            mainScope.launch {
                try {
                    val accessibilityService = MyAccessibilityService.getInstance()
                    if (accessibilityService != null) {
                        val currentIME = accessibilityService.getCurrentIME()
                        val customIMEId = "${requireContext().packageName}/${SimpleInputMethodService::class.java.name}"
                        
                        // 如果当前是自定义输入法，且保存了原始输入法，尝试恢复
                        if (currentIME == customIMEId && originalIME != customIMEId) {
                            Log.d(TAG, "任务结束：尝试恢复原始输入法: $originalIME")
                            
                            // 尝试使用InputMethodManager.switchToLastInputMethod()切换回上一个输入法
                            try {
                                val imm = requireContext().getSystemService(android.content.Context.INPUT_METHOD_SERVICE) as? android.view.inputmethod.InputMethodManager
                                if (imm != null && Build.VERSION.SDK_INT >= Build.VERSION_CODES.P) {
                                    // 尝试切换到上一个输入法（通常是用户之前使用的）
                                    val switched = imm.switchToLastInputMethod(null)
                                    if (switched) {
                                        Log.d(TAG, "✓ 任务结束：已切换到上一个输入法")
                                        delay(500)
                                        val newIME = accessibilityService.getCurrentIME()
                                        if (newIME == originalIME) {
                                            Log.d(TAG, "✓✓ 任务结束：已成功恢复原始输入法: $originalIME")
                                        } else {
                                            Log.w(TAG, "⚠ 任务结束：切换后的输入法($newIME)与原始输入法($originalIME)不一致")
                                        }
                                    } else {
                                        Log.w(TAG, "⚠ 任务结束：switchToLastInputMethod返回false，无法自动恢复")
                                        Log.d(TAG, "任务结束：用户可能需要手动切换回原始输入法: $originalIME")
                                    }
                                } else {
                                    Log.w(TAG, "⚠ 任务结束：无法获取InputMethodManager或Android版本过低，无法自动恢复")
                                    Log.d(TAG, "任务结束：用户可能需要手动切换回原始输入法: $originalIME")
                                }
                            } catch (e: Exception) {
                                Log.e(TAG, "任务结束：恢复输入法时出错: ${e.message}", e)
                                Log.d(TAG, "任务结束：用户可能需要手动切换回原始输入法: $originalIME")
                            }
                        } else {
                            Log.d(TAG, "任务结束：当前输入法($currentIME)与自定义输入法($customIMEId)不一致，或原始输入法为空，无需恢复")
                        }
                    }
                } catch (e: Exception) {
                    Log.e(TAG, "任务结束：恢复输入法时出错: ${e.message}", e)
                } finally {
                    originalIME = null  // 清除保存的原始输入法
                }
            }
        }
        
        // 重置输入法切换状态
        MyAccessibilityService.resetIMESwitchState()
        IMESwitchGuideOverlayManager.hide()
        
        // 清空TYPE重试参数
        pendingTypeParams = null
        pendingTypeAutoSubmit = false
        
        // 清除call_user相关状态
        pendingCallUser = false
        pendingCallUserText = null
        originalQuery = null
        
        // 清除问字按钮请求标记
        isQuestionButtonRequest = false
        
        // 清除群组@TopoClaw上下文（如果存在）
        // 注意：若存在 groupManagerFeedbackContext（群组管理小助手 flow），不清除 context，
        // 由 doGroupManagerFeedbackFlow 负责恢复和清除，避免竞态导致 bringAppToForeground 未执行
        val groupContext = assistantGroupContext
        if (groupContext != null) {
            if (groupManagerFeedbackContext == null) {
                Log.d(TAG, "stopTask - 检测到群组上下文(普通)，恢复原始对话上下文")
                currentConversation = groupContext.originalConversation
                assistantGroupContext = null
                groupManagerFeedbackContext = null
                Log.d(TAG, "stopTask - 已恢复原始对话上下文: ${groupContext.originalConversation?.id}")
            } else {
                Log.d(TAG, "stopTask - 检测到群组管理反馈上下文，跳过清除，由 doGroupManagerFeedbackFlow 负责跳转回应用并清除")
            }
        }
        
        // 清除任务来源标记（任务结束时清理）
        val mainActivity = activity as? MainActivity
        mainActivity?.isTaskFromExternalApp = false
        mainActivity?.isTaskFromCompanionMode = false
        mainActivity?.isCompanionAskScreenEnabled = false
        mainActivity?.originalPackageName = null
        Log.d(TAG, "stopTask - 已清除任务来源标记: isTaskFromExternalApp=false, isTaskFromCompanionMode=false, isCompanionAskScreenEnabled=false")
        
        // 通知MainActivity任务已结束
        mainActivity?.isTaskRunning = false
        
        // 更新悬浮窗状态（任务未运行）
        TaskIndicatorOverlayManager.updateOverlayForTaskStatus(false)
        
        // 隐藏任务指示器悬浮窗（如果伴随模式未开启）
        if (mainActivity != null && !TaskIndicatorOverlayManager.isCompanionModeEnabled(requireContext())) {
            TaskIndicatorOverlayManager.hide()
        }
        
        // 隐藏炫彩边框特效
        try {
            BorderEffectOverlayManager.hide()
        } catch (e: Exception) {
            Log.e(TAG, "stopTask: 隐藏边框特效异常: ${e.message}", e)
        }
        
        // 隐藏call_user输入框悬浮窗
        CallUserInputOverlayManager.hide()
        
        // 隐藏reasoning悬浮窗并清理pendingReasoning
        ReasoningOverlayManager.hide()
        pendingReasoning = null
        
        // 保存当前UUID用于总结请求（在重置之前）
        val taskUuidForSummary = chatUuid
        
        // 重置UUID
        chatUuid = UUID.randomUUID().toString()
        Log.d(TAG, "任务已停止，UUID已重置: $chatUuid")
        (activity as? MainActivity)?.addLog("任务已停止，UUID已重置: $chatUuid")
        
        // 先设置停止任务相关的按钮状态
        binding.btnSendChat.isEnabled = true
        binding.btnStopTask.visibility = View.GONE
        
        // 清除图片相关状态（确保任务完成后按钮状态正确）
        // 避免因为时序问题导致selectedImageBase64还未清除，从而显示错误的按钮状态
        selectedImageBase64 = null
        selectedImageUri = null
        selectedImageBitmap?.recycle()
        selectedImageBitmap = null
        // 隐藏图片预览区域
        binding.llImagePreview.visibility = android.view.View.GONE
        binding.ivSelectedImage.setImageBitmap(null)
        
        // 更新按钮可见性（变回加号按钮，除非输入框内有内容）
        // 注意：必须在isTaskRunning设置为false之后调用，这样updateButtonVisibility才能正确判断
        // 注意：必须在清除图片状态之后调用，确保按钮状态正确
        updateButtonVisibility()
        
        // 任务结束时，发送聊天历史到云侧请求总结（使用任务结束前的UUID）
        // 如果delaySummary为true，延迟500ms确保所有消息都已保存到chatMessages
        if (delaySummary) {
            mainScope.launch {
                delay(500) // 延迟500ms，确保所有消息都已保存
                Log.d(TAG, "延迟后调用总结，当前消息数量: ${chatMessages.size}")
                requestChatSummary(taskUuidForSummary)
            }
        } else {
            requestChatSummary(taskUuidForSummary)
        }
    }
    
    /**
     * 请求聊天截图权限
     */
    private fun requestChatScreenshotPermission() {
        val mediaProjectionManager = requireContext().getSystemService(android.content.Context.MEDIA_PROJECTION_SERVICE) as MediaProjectionManager
        val captureIntent = mediaProjectionManager.createScreenCaptureIntent()
        startActivityForResult(captureIntent, ChatConstants.REQUEST_MEDIA_PROJECTION_CHAT)
    }
    
    /**
     * 显示截图权限弹窗
     */
    /** onConfirm 置后，便于调用处使用尾随 lambda；onCancel 可选且在前 */
    private fun showScreenshotPermissionDialog(onCancel: (() -> Unit)? = null, onConfirm: () -> Unit) {
        android.app.AlertDialog.Builder(requireContext())
            .setTitle("需要截图权限")
            .setMessage("发送消息需要截图权限，是否立即授权？")
            .setPositiveButton("立即授权") { _, _ ->
                onConfirm()
            }
            .setNegativeButton("取消") { _, _ ->
                onCancel?.invoke()
            }
            .show()
    }
    
    /**
     * 显示无障碍服务弹窗
     */
    private fun showAccessibilityServiceDialog(onCancel: (() -> Unit)? = null, onConfirm: () -> Unit) {
        val isFromCompanionMode = (activity as? MainActivity)?.isTaskFromCompanionMode ?: false
        if (isFromCompanionMode) {
            Log.d(TAG, "showAccessibilityServiceDialog: 悬浮球发起，跳过无障碍弹窗")
            onCancel?.invoke()
            return
        }
        android.app.AlertDialog.Builder(requireContext())
            .setTitle("需要无障碍服务")
            .setMessage("执行操作需要无障碍服务，是否前往设置开启？")
            .setPositiveButton("去设置") { _, _ ->
                onConfirm()
            }
            .setNegativeButton("取消") { _, _ ->
                onCancel?.invoke()
            }
            .show()
    }
    
