    /**
     * 检查无障碍服务是否已启用（检查系统设置级别的权限状态 或 服务实例已连接）
     * 注意：之前只检查 getInstance() != null，导致在 onActivityResult 中的条件判断逻辑错误
     * 现在同时检查系统权限设置，确保在权限已授予但服务尚未连接时也返回 true
     */
    private fun isAccessibilityServiceEnabled(): Boolean {
        // 先检查服务实例是否已连接（最快）
        if (MyAccessibilityService.getInstance() != null) {
            return true
        }
        // 再检查系统设置中是否已授予权限（服务可能正在启动中）
        return checkAccessibilityServicePermission()
    }
    
    /**
     * 检查无障碍服务权限是否已授予（系统设置级别）
     * 注意：此方法只检查权限状态，不检查服务连接状态
     */
    private fun checkAccessibilityServicePermission(): Boolean {
        return try {
            val accessibilityManager = requireContext().getSystemService(Context.ACCESSIBILITY_SERVICE) as? AccessibilityManager
            if (accessibilityManager != null) {
                val enabledServices = AccessibilityManagerCompat.getEnabledAccessibilityServiceList(
                    accessibilityManager,
                    AccessibilityServiceInfo.FEEDBACK_ALL_MASK
                )
                enabledServices.any { 
                    it.resolveInfo.serviceInfo.packageName == requireContext().packageName 
                }
            } else {
                false
            }
        } catch (e: Exception) {
            Log.w(TAG, "检查无障碍服务权限失败: ${e.message}", e)
            false
        }
    }
    
    /**
     * 检查并处理待发送的消息（无障碍服务授权后）
     * 供 MainActivity 调用，当用户从无障碍设置页面返回时
     * @return 是否有待发送的消息
     */
    fun checkAndHandlePendingAccessibilityQuery(): Boolean {
        val pendingQuery = pendingQueryAfterAccessibility
        Log.d(TAG, "checkAndHandlePendingAccessibilityQuery: pendingQuery=$pendingQuery")
        if (pendingQuery != null) {
            // 先检查系统权限状态（权限可能已授予但服务未连接）
            val hasPermission = checkAccessibilityServicePermission()
            val serviceConnected = MyAccessibilityService.getInstance() != null
            Log.d(TAG, "checkAndHandlePendingAccessibilityQuery: 权限已授予=$hasPermission, 服务已连接=$serviceConnected")
            
            if (hasPermission) {
                // 权限已授予，等待服务连接后自动发送
                pendingQueryAfterAccessibility = null
                Log.d(TAG, "checkAndHandlePendingAccessibilityQuery: 无障碍服务权限已授予，等待服务连接后自动发送: $pendingQuery")
                
                // 如果服务已经连接，立即发送（但需要先检查输入法）
                if (serviceConnected) {
                    Log.d(TAG, "checkAndHandlePendingAccessibilityQuery: 无障碍服务已连接，准备检查输入法后发送消息: $pendingQuery")
                    view?.post {
                        addChatMessage("系统", "无障碍服务已启用，正在检查输入法...")
                        // 直接调用，与截图权限授予后的处理方式一致
                        executeQueryInternal(pendingQuery)
                    }
                } else {
                    // 服务未连接，等待服务连接（最多等待10秒）
                    var retryCount = 0
                    val maxRetries = 20
                    val delayMs = 500L
                    
                    val checkServiceConnection = object : Runnable {
                        override fun run() {
                            val accessibilityService = MyAccessibilityService.getInstance()
                                if (accessibilityService != null) {
                                    // 服务已连接，自动发送（但需要先检查输入法）
                                    Log.d(TAG, "checkAndHandlePendingAccessibilityQuery: 无障碍服务已连接，准备检查输入法后发送消息: $pendingQuery")
                                    view?.post {
                                        addChatMessage("系统", "无障碍服务已启用，正在检查输入法...")
                                        // 直接调用，与截图权限授予后的处理方式一致
                                        executeQueryInternal(pendingQuery)
                                    }
                            } else if (retryCount < maxRetries) {
                                // 服务未连接，继续等待
                                retryCount++
                                Log.d(TAG, "checkAndHandlePendingAccessibilityQuery: 等待无障碍服务连接... ($retryCount/$maxRetries)")
                                view?.postDelayed(this, delayMs)
                            } else {
                                // 超时，恢复pendingQuery让用户可以手动发送
                                Log.w(TAG, "checkAndHandlePendingAccessibilityQuery: 无障碍服务连接超时，请稍后手动发送")
                                pendingQueryAfterAccessibility = pendingQuery
                                view?.post {
                                    addChatMessage("系统", "服务连接超时，请稍后手动发送消息")
                                }
                            }
                        }
                    }
                    
                    view?.postDelayed(checkServiceConnection, 500) // 延迟500ms开始检查
                }
                return true
            } else {
                // 权限未授予，但可能是系统状态更新延迟，延迟一下再检查一次
                Log.d(TAG, "checkAndHandlePendingAccessibilityQuery: 权限未授予，延迟500ms后再次检查（可能是系统状态更新延迟）")
                view?.postDelayed({
                    val retryHasPermission = checkAccessibilityServicePermission()
                    val retryServiceConnected = MyAccessibilityService.getInstance() != null
                    Log.d(TAG, "checkAndHandlePendingAccessibilityQuery: 延迟检查无障碍服务状态 - 权限已授予=$retryHasPermission, 服务已连接=$retryServiceConnected")
                    if (retryHasPermission) {
                        // 权限已授予，等待服务连接后自动发送
                        val retryPendingQuery = pendingQueryAfterAccessibility
                        if (retryPendingQuery != null) {
                            pendingQueryAfterAccessibility = null
                            Log.d(TAG, "checkAndHandlePendingAccessibilityQuery: 延迟检查发现权限已授予，等待服务连接后自动发送: $retryPendingQuery")
                            
                            if (retryServiceConnected) {
                                // 服务已连接，立即发送（但需要先检查输入法）
                                Log.d(TAG, "checkAndHandlePendingAccessibilityQuery: 延迟检查发现服务已连接，准备检查输入法后发送消息: $retryPendingQuery")
                                view?.post {
                                    addChatMessage("系统", "无障碍服务已启用，正在检查输入法...")
                                    // 直接调用，与截图权限授予后的处理方式一致
                                    executeQueryInternal(retryPendingQuery)
                                }
                            } else {
                                // 服务未连接，等待服务连接
                                var retryCount = 0
                                val maxRetries = 20
                                val delayMs = 500L
                                
                                val checkServiceConnection = object : Runnable {
                                    override fun run() {
                                        val accessibilityService = MyAccessibilityService.getInstance()
                                        if (accessibilityService != null) {
                                            Log.d(TAG, "checkAndHandlePendingAccessibilityQuery: 延迟检查后服务已连接，准备检查输入法后发送消息: $retryPendingQuery")
                                            view?.post {
                                                addChatMessage("系统", "无障碍服务已启用，正在检查输入法...")
                                                // 直接调用，与截图权限授予后的处理方式一致
                                                executeQueryInternal(retryPendingQuery)
                                            }
                                        } else if (retryCount < maxRetries) {
                                            retryCount++
                                            Log.d(TAG, "checkAndHandlePendingAccessibilityQuery: 延迟检查后等待无障碍服务连接... ($retryCount/$maxRetries)")
                                            view?.postDelayed(this, delayMs)
                                        } else {
                                            Log.w(TAG, "checkAndHandlePendingAccessibilityQuery: 延迟检查后无障碍服务连接超时，请稍后手动发送")
                                            pendingQueryAfterAccessibility = retryPendingQuery
                                            view?.post {
                                                addChatMessage("系统", "服务连接超时，请稍后手动发送消息")
                                            }
                                        }
                                    }
                                }
                                
                                view?.postDelayed(checkServiceConnection, 500)
                            }
                        }
                    } else {
                        // 权限确实未授予，保持pendingQuery不变
                        Log.d(TAG, "checkAndHandlePendingAccessibilityQuery: 延迟检查确认无障碍服务权限未授予，等待用户授权")
                    }
                }, 500)
                return true
            }
        }
        return false
    }
    
    /**
     * 上传视频和动作数据到云侧
     */
    private var isUploading = false  // 防止重复上传
    
    /**
     * 从悬浮球添加视频消息（公共方法，供TaskIndicatorOverlayManager调用）
     */
    fun addVideoMessageFromOverlay(videoPath: String) {
        addVideoMessage(videoPath, saveToHistory = true)
    }
    
    /**
     * 从悬浮球上传视频（公共方法，供TaskIndicatorOverlayManager调用）
     */
    fun uploadVideoToCloudFromOverlay(videoPath: String, screenWidth: Int, screenHeight: Int) {
        uploadVideoToCloud(videoPath, screenWidth, screenHeight)
    }
    
    /**
     * 上传视频到云侧（第一次上传，只上传视频，等待用户输入操作目的）
     */
    internal fun uploadVideoToCloud(videoPath: String, screenWidth: Int, screenHeight: Int) {
        // 第一次上传：只保存视频信息，不实际上传，等待用户输入操作目的
        waitingForVideoPurpose = true
        pendingVideoPath = videoPath
        pendingScreenWidth = screenWidth
        pendingScreenHeight = screenHeight
        
        // 自动发送提示消息（使用 isAnswer = true 表示这是小助手的消息）
        addChatMessage("小助手", "请简单形容你的视频操作目的~", isAnswer = true)
        Log.d(TAG, "视频录制完成，等待用户输入操作目的")
    }
    
    /**
     * 上传视频到云侧（带query，用户输入操作目的后调用）
     * @param videoPath 视频文件路径
     * @param screenWidth 屏幕宽度
     * @param screenHeight 屏幕高度
     * @param query 用户查询文本（视频操作目的）
     */
    private fun uploadVideoToCloudWithQuery(videoPath: String, screenWidth: Int, screenHeight: Int, query: String) {
        // 防止重复上传
        if (isUploading) {
            Log.w(TAG, "视频正在上传中，忽略重复请求")
            return
        }
        
        isUploading = true
        
        // 在后台协程中执行上传
        CoroutineScope(Dispatchers.IO).launch {
            try {
                // 注意：不再读取和转换动作数据，不再发送 user_example 字段
                // 云侧将使用基于均匀取帧的视频解析方式（每0.9秒提取一帧）
                
                // 读取视频文件
                val videoFile = java.io.File(videoPath)
                if (!videoFile.exists()) {
                    Log.e(TAG, "视频文件不存在: $videoPath")
                    withContext(Dispatchers.Main) {
                        Toast.makeText(requireContext(), "视频文件不存在", Toast.LENGTH_SHORT).show()
                    }
                    return@launch
                }
                
                // 确保使用当前对话对应的服务地址
                ensureNetworkServiceInitialized()
                
                // 准备上传（使用视频上传专用的ApiService，无timeout限制）
                val apiService = NetworkService.getVideoUploadApiService()
                if (apiService == null) {
                    Log.e(TAG, "VideoUploadApiService未初始化")
                    withContext(Dispatchers.Main) {
                        Toast.makeText(requireContext(), "网络服务未初始化", Toast.LENGTH_SHORT).show()
                    }
                    return@launch
                }
                
                // 创建Multipart请求
                // 使用扩展函数 toMediaType()（OkHttp 4.x）
                val videoMediaType = "video/mp4".toMediaType()
                val videoRequestBody = okhttp3.RequestBody.create(
                    videoMediaType,
                    videoFile
                )
                val videoPart = okhttp3.MultipartBody.Part.createFormData(
                    "video",
                    videoFile.name,
                    videoRequestBody
                )
                
                // 创建UUID和query的RequestBody
                val textMediaType = "text/plain".toMediaType()
                val uuidRequestBody = okhttp3.RequestBody.create(
                    textMediaType,
                    chatUuid.ifEmpty { UUID.randomUUID().toString() }
                )
                val queryRequestBody = okhttp3.RequestBody.create(
                    textMediaType,
                    query
                )
                
                // 发送请求（不再发送 user_example 字段）
                withContext(Dispatchers.Main) {
                    addChatMessage("系统", "正在上传视频...")
                }
                
                val imei = ProfileManager.getOrGenerateImei(requireContext())
                val imeiRequestBody = imei?.let { 
                    okhttp3.RequestBody.create(null, it) 
                }
                
                val response = apiService.uploadVideo(
                    uuid = uuidRequestBody,
                    query = queryRequestBody,
                    video = videoPart,
                    imei = imeiRequestBody
                )
                
                if (response.isSuccessful) {
                    val chatResponse = response.body()
                    withContext(Dispatchers.Main) {
                        Toast.makeText(requireContext(), "视频和操作目的已上传成功", Toast.LENGTH_SHORT).show()
                        Log.d(TAG, "视频和操作目的上传成功，query: $query")
                        
                        // 检查是否是学习模式响应
                        if (chatResponse != null && chatResponse.action_type == "learning" && chatResponse.video_analysis != null) {
                            // 格式化并显示视频分析结果（带按钮）
                            val analysisResult = formatVideoAnalysisResult(chatResponse.video_analysis)
                            addVideoAnalysisMessage(analysisResult)
                        } else {
                            addChatMessage("系统", "✓ 视频和操作目的已上传到云侧，开始学习")
                        }
                    }
                } else {
                    val errorMsg = "上传失败: ${response.code()} - ${response.message()}"
                    Log.e(TAG, errorMsg)
                    withContext(Dispatchers.Main) {
                        Toast.makeText(requireContext(), errorMsg, Toast.LENGTH_SHORT).show()
                        addChatMessage("系统", "✗ $errorMsg")
                    }
                }
                
            } catch (e: Exception) {
                Log.e(TAG, "上传视频失败: ${e.message}", e)
                withContext(Dispatchers.Main) {
                    Toast.makeText(requireContext(), "上传失败: ${e.message}", Toast.LENGTH_SHORT).show()
                    addChatMessage("系统", "✗ 上传失败: ${e.message}")
                }
            } finally {
                // 重置上传标志
                isUploading = false
            }
        }
    }
    
    /**
     * 格式化视频分析结果为用户友好的消息格式
     * @param videoAnalysis 视频分析结果列表
     * @return VideoAnalysisResult 包含格式化消息和原始数据
     */
    private fun formatVideoAnalysisResult(videoAnalysis: List<com.cloudcontrol.demo.VideoAnalysisItem>): VideoAnalysisResult {
        val result = StringBuilder()
        
        // 查找 summary 项（用户操作目的）
        var userPurpose: String? = null
        val actionSteps = mutableListOf<Pair<String, String>>() // (action_type, reason)
        
        for (item in videoAnalysis) {
            if (item.action_type == "summary") {
                // 提取用户操作目的（从 reason 中提取，格式：用户操作目的：...）
                userPurpose = item.reason
            } else {
                // 收集操作步骤
                val actionType = item.action_type ?: ""
                val reason = item.reason ?: ""
                if (actionType.isNotEmpty() && reason.isNotEmpty()) {
                    actionSteps.add(Pair(actionType, reason))
                }
            }
        }
        
        // 添加用户操作目的
        if (userPurpose != null) {
            result.append(userPurpose)
            result.append("\n\n")
        }
        
        // 格式化步骤列表
        val formattedSteps = mutableListOf<String>()
        
        // 添加操作步骤
        actionSteps.forEachIndexed { index, (actionType, reason) ->
            val stepNumber = index + 1
            // 格式化 reason：如果是 "open" 类型且 reason 是 "打开XXX" 格式，转换为 "点击XXX图标"
            val formattedReason = when {
                actionType == "open" && reason.startsWith("打开") -> {
                    val appName = reason.substring(2) // 去掉 "打开" 前缀
                    "点击${appName}图标"
                }
                else -> reason
            }
            val stepText = "step$stepNumber：$formattedReason"
            result.append(stepText)
            formattedSteps.add(stepText)
            if (index < actionSteps.size - 1) {
                result.append("\n")
            }
        }
        
        return VideoAnalysisResult(
            formattedMessage = result.toString(),
            userPurpose = userPurpose,
            actionSteps = formattedSteps,
            originalVideoAnalysis = videoAnalysis
        )
    }
    
    /**
     * 简化用户操作目的（去掉"用户操作目的："前缀）
     */
    internal fun simplifyUserPurpose(originalPurpose: String?): String {
        if (originalPurpose == null) return ""
        return originalPurpose.removePrefix("用户操作目的：").trim()
    }
    
    
    /**
     * 获取当前用户的显示名称（群组对话中使用）
     * 如果有昵称则显示昵称，否则显示IMEI前8位
     */
    private fun getCurrentUserDisplayName(): String {
        val profile = ProfileManager.loadProfileLocally(requireContext())
        return if (!profile?.name.isNullOrEmpty()) {
            profile!!.name!!
        } else {
            val imei = ProfileManager.getOrGenerateImei(requireContext())
            imei.take(8) + "..."
        }
    }

    private fun isGroupConversationId(conversationId: String?): Boolean {
        if (conversationId.isNullOrBlank()) return false
        return conversationId.startsWith("group_") || conversationId == ConversationListFragment.CONVERSATION_ID_GROUP
    }

    private fun resolveMemberDisplayNameFromImei(senderImei: String?, fallbackName: String? = null): String {
        val imei = senderImei?.trim().orEmpty()
        if (imei.isEmpty()) return fallbackName?.trim().orEmpty()
        if (CustomAssistantManager.isCustomAssistantId(imei)) {
            val assistant = CustomAssistantManager.getById(requireContext(), imei)
            return assistant?.name ?: fallbackName?.trim().orEmpty()
        }
        val currentImei = ProfileManager.getOrGenerateImei(requireContext())
        if (imei == currentImei) return getCurrentUserDisplayName()
        val friend = FriendManager.getFriend(requireContext(), imei)
        return friend?.nickname?.takeIf { it.isNotBlank() } ?: (imei.take(8) + "...")
    }

    private fun formatAssistantDisplayNameWithOwner(sender: String, senderImei: String?): String {
        if (senderImei != null && CustomAssistantManager.isCustomAssistantId(senderImei)) {
            // 自定义小助手：服务端 sender 已包含正确的展示名（如 "TopoClaw（主人昵称）"）
            if (sender.contains("（") && sender.endsWith("）")) {
                return sender
            }
            val assistant = CustomAssistantManager.getById(requireContext(), senderImei)
            return assistant?.name ?: sender.ifBlank { "小助手" }
        }
        val assistantName = DisplayNameHelper.getDisplayName(requireContext(), sender).ifBlank { sender.ifBlank { "小助手" } }
        val ownerName = resolveMemberDisplayNameFromImei(senderImei)
        return if (ownerName.isNotBlank()) "$assistantName（$ownerName）" else assistantName
    }
    
    /**
     * 根据senderImei解析发送者显示名称
     * 如果有好友信息则使用昵称，否则使用IMEI前8位
     */
    private fun resolveSenderDisplayName(sender: String, senderImei: String?): String {
        val conversationId = currentConversation?.id
            ?: (arguments?.getSerializable("conversation") as? Conversation)?.id
        val normalizedSender = ChatConstants.normalizeAssistantSenderForConversation(sender, conversationId)
        val isGroupConversation = isGroupConversationId(conversationId)

        // 如果是特殊发送者（小助手等），直接返回
        if (ChatConstants.isMainAssistantSender(normalizedSender) || normalizedSender == "技能学习小助手" || normalizedSender == "人工客服" || normalizedSender == "系统") {
            return if (isGroupConversation && normalizedSender != "系统") {
                formatAssistantDisplayNameWithOwner(normalizedSender, senderImei)
            } else {
                normalizedSender
            }
        }
        
        // 如果有senderImei，从好友列表获取昵称
        if (!senderImei.isNullOrEmpty()) {
            val currentImei = ProfileManager.getOrGenerateImei(requireContext())
            // 如果是自己发送的消息，在群组对话中显示昵称，其他对话显示"我"
            if (senderImei == currentImei) {
                return if (isGroupConversation) {
                    getCurrentUserDisplayName()
                } else {
                    "我"
                }
            }

            // 自定义小助手：优先使用服务端 sender（已含主人昵称），或从本地配置获取助手名
            if (CustomAssistantManager.isCustomAssistantId(senderImei)) {
                return if (isGroupConversation) formatAssistantDisplayNameWithOwner(sender, senderImei) else {
                    CustomAssistantManager.getById(requireContext(), senderImei)?.name ?: normalizedSender
                }
            }
            
            // 从好友列表获取昵称
            return resolveMemberDisplayNameFromImei(senderImei, normalizedSender).ifBlank { normalizedSender }
        }
        
        // 如果没有senderImei，检查sender是否已经是昵称格式（包含"..."）
        // 如果是，说明可能是之前保存的IMEI格式，尝试解析
        if (normalizedSender.endsWith("...") && normalizedSender.length == 11) {
            // 可能是IMEI前8位格式，保持原样
            return normalizedSender
        }
        
        // 其他情况，返回原始sender
        return normalizedSender
    }
    
    /**
     * 获取发送消息时的显示名称
     * 群组对话中显示用户昵称或IMEI，其他对话显示"我"
     */
    private fun getSenderDisplayName(): String {
        val conversationId = currentConversation?.id 
            ?: (arguments?.getSerializable("conversation") as? Conversation)?.id
            ?: return "我"
        
        // 群组对话：显示用户昵称或IMEI
        if (conversationId.startsWith("group_") || conversationId == ConversationListFragment.CONVERSATION_ID_GROUP) {
            return getCurrentUserDisplayName()
        }
        
        // 其他对话：显示"我"
        return "我"
    }
    
    /**
     * 将群成员 IMEI 解析为显示名称（不特别标注「我」）
     * 自己用 ProfileManager，他人用 FriendManager
     */
    private fun getMemberDisplayName(memberImei: String): String {
        val currentImei = ProfileManager.getOrGenerateImei(requireContext())
        if (memberImei == currentImei) {
            val profile = ProfileManager.loadProfileLocally(requireContext())
            return profile?.name ?: memberImei.take(8) + "..."
        }
        val friend = FriendManager.getFriend(requireContext(), memberImei)
        return friend?.nickname ?: (memberImei.take(8) + "...")
    }
    
    /** 将群成员 IMEI 列表解析为显示名称列表 */
    private fun getGroupMemberNames(memberImeis: List<String>): List<String> {
        return memberImeis.map { getMemberDisplayName(it) }
    }
    
    /**
     * 判断消息是否应该显示在右侧（用户消息）
     * 管理员模式下，反转逻辑：客服消息在右边，用户消息在左边
     */
    private fun isUserMessageForDisplay(sender: String): Boolean {
        return if (currentConversation?.id == ConversationListFragment.CONVERSATION_ID_ADMIN_CUSTOMER_SERVICE) {
            // 管理员模式：人工客服消息显示在右边（代表我们），用户消息显示在左边
            sender == "人工客服" || sender == "我"
        } else {
            // 普通模式：用户消息显示在右边
            // 群组对话中，sender可能是用户昵称或IMEI，需要检查是否是当前用户
            val conversationId = currentConversation?.id 
                ?: (arguments?.getSerializable("conversation") as? Conversation)?.id
            val isGroupConversation = conversationId?.startsWith("group_") == true || 
                                     conversationId == ConversationListFragment.CONVERSATION_ID_GROUP
            
            if (isGroupConversation) {
                // 群组对话：检查sender是否是当前用户的显示名称
                val currentDisplayName = getCurrentUserDisplayName()
                sender == currentDisplayName || sender == "我"
            } else {
                sender == "我" || sender == "用户"
            }
        }
    }
    
    /**
     * 添加聊天消息
     * @param sender 发送者
     * @param message 消息内容
     * @param isComplete 是否是任务完成消息（使用特殊颜色）
     * @param isAnswer 是否是answer消息（使用和用户消息一样的格式）
     * @param recommendations 推荐任务列表（用于任务完成消息）
