    }

    fun addChatMessage(sender: String, message: String, isComplete: Boolean = false, isAnswer: Boolean = false, skipSystemMessageContainer: Boolean = false, recommendations: List<String>? = null, timestamp: Long? = null, skillId: String? = null, senderImei: String? = null, clearThinking: Boolean = false) {
        try {
            val currentActivity = activity
            if (currentActivity == null) {
                Log.w(TAG, "Activity为null，无法添加消息到UI，但会保存到记录中")
                    // 即使Activity为null，也保存到聊天记录
                val messageType = when {
                    sender == "我" || sender == "用户" -> "user"
                    isComplete -> "complete"
                    isAnswer -> "answer"
                    else -> "system"
                }
                val currentTime = timestamp ?: System.currentTimeMillis()
                val isUserMsg = isUserMessageForDisplay(sender)
                val chatMessage = ChatMessage(sender, message, messageType, currentTime, chatUuid, skillId = skillId, senderImei = senderImei)
                if (addMessageToList(chatMessage)) {
                    // 用户消息立即保存，避免丢失
                    if (isUserMsg) {
                        saveChatMessages(sync = false) // 用户消息立即保存，但使用异步避免阻塞UI
                    } else {
                        saveChatMessagesDebounced() // 其他消息使用防抖保存
                    }
                    if (isUserMsg || isAnswer) {
                        saveChatContext(sender, message, currentTime)
                    }
                }
                return
            }
            
            // 检查binding是否有效
            if (_binding == null) {
                Log.w(TAG, "Binding为null，无法添加消息到UI，但会保存到记录中")
                val messageType = when {
                    sender == "我" || sender == "用户" -> "user"
                    isComplete -> "complete"
                    isAnswer -> "answer"
                    else -> "system"
                }
                val currentTime = timestamp ?: System.currentTimeMillis()
                val isUserMsg = isUserMessageForDisplay(sender)
                val chatMessage = ChatMessage(sender, message, messageType, currentTime, chatUuid, skillId = skillId, senderImei = senderImei)
                if (addMessageToList(chatMessage)) {
                    // 用户消息立即保存，避免丢失
                    if (isUserMsg) {
                        saveChatMessages(sync = false) // 用户消息立即保存，但使用异步避免阻塞UI
                    } else {
                        saveChatMessagesDebounced() // 其他消息使用防抖保存
                    }
                    if (isUserMsg || isAnswer) {
                        saveChatContext(sender, message, currentTime)
                    }
                }
                return
            }
            
            currentActivity.runOnUiThread {
                try {
                    // 定义isUserMessage，在整个UI线程块内使用
                    val isUserMessage = isUserMessageForDisplay(sender)
                    val currentConvId = currentConversation?.id
                    val isCustomAssistantConversation = CustomAssistantManager.isCustomAssistantId(currentConvId)
                    
                    // 再次检查binding（可能在UI线程执行时已经变为null）
                    if (_binding == null) {
                        Log.w(TAG, "Binding在UI线程中为null，仅保存到记录")
                        val messageType = when {
                            sender == "我" || sender == "用户" -> "user"
                            isComplete -> "complete"
                            isAnswer -> "answer"
                            else -> "system"
                        }
                        val currentTime = timestamp ?: System.currentTimeMillis()
                        val chatMessage = ChatMessage(sender, message, messageType, currentTime, chatUuid, senderImei = senderImei)
                        if (addMessageToList(chatMessage)) {
                            // 用户消息立即保存，避免丢失
                            if (isUserMessage) {
                                saveChatMessages(sync = false) // 用户消息立即保存，但使用异步避免阻塞UI
                            } else {
                                saveChatMessagesDebounced() // 其他消息使用防抖保存
                            }
                            if (isUserMessage || isAnswer) {
                                saveChatContext(sender, message, currentTime)
                            }
                        }
                        return@runOnUiThread
                    }
                    
                    // 先检查是否是技能消息并解析skillId（如果需要）
                    // 这样可以在保存消息时使用正确的skillId
                    var resolvedSkillId = skillId // 用于保存消息的skillId
                    if (skillId == null || skillId.isEmpty()) {
                        // 没有skillId，尝试从消息文本解析
                        val parsedSkillForId = parseSkillFromMessage(message)
                        if (parsedSkillForId != null) {
                            // 从消息中解析出技能，生成稳定的ID（基于消息内容的hash）
                            val stableSkillId = "temp_skill_${message.hashCode()}_${parsedSkillForId.title.hashCode()}"
                            resolvedSkillId = stableSkillId
                            // 保存到临时技能存储
                            val skillWithStableId = parsedSkillForId.copy(id = stableSkillId)
                            TemporarySkillManager.saveTemporarySkill(requireContext(), skillWithStableId, currentConversation?.id)
                            Log.d(TAG, "从消息解析出技能ID并保存到临时存储: skillId=$stableSkillId, title=${skillWithStableId.title}")
                        }
                    }
                    
                    // 保存到聊天记录（使用addMessageToList确保去重和正确保存）
                    val messageType = when {
                        sender == "我" || sender == "用户" -> "user"
                        isComplete -> "complete"
                        isAnswer -> "answer"
                        else -> "system"
                    }
                    val currentTime = timestamp ?: System.currentTimeMillis()
                    val chatMessage = ChatMessage(sender, message, messageType, currentTime, chatUuid, skillId = resolvedSkillId, senderImei = senderImei)
                    if (addMessageToList(chatMessage)) {
                        // 用户消息立即保存，避免丢失
                        if (isUserMessage) {
                            saveChatMessages(sync = false) // 用户消息立即保存，但使用异步避免阻塞UI
                        } else {
                            saveChatMessagesDebounced() // 其他消息使用防抖保存
                        }
                        // 端云同步：系统/小助手消息上报后端，PC 可实时展示
                        if ((sender == "系统" || sender == "小助手") && currentConversation?.id == ConversationListFragment.CONVERSATION_ID_ASSISTANT && assistantGroupContext == null) {
                            (currentActivity as? MainActivity)?.getCustomerServiceWebSocket()?.sendAssistantSyncMessage(sender, message)
                        }
                    }
                    
                    // 保存聊天上下文（如果开关开启，且是用户消息或助手回复）
                    if (isUserMessage || isAnswer) {
                        saveChatContext(sender, message, currentTime)
                    }
                    
                    val adapter = chatAdapter
                    
                    if (adapter == null) {
                        Log.w(TAG, "Adapter为null，无法添加消息到UI，但消息已保存到记录中")
                        // 消息已经保存到记录中（在上面的代码中），当restoreChatMessages执行时会恢复显示
                        // 但如果是在Fragment初始化过程中，我们需要等待adapter初始化后再添加
                        // 使用postDelayed等待adapter初始化
                        view?.postDelayed({
                            val retryAdapter = chatAdapter
                            if (retryAdapter != null) {
                                Log.d(TAG, "Adapter已初始化，重新添加消息到UI")
                                // 重新添加消息到UI（消息已经保存到记录中，这里只是添加到UI）
                                val shouldShowTime = lastMessageTimestamp == 0L || 
                                    (currentTime - lastMessageTimestamp) > 10 * 60 * 1000
                                if (shouldShowTime) {
                                    retryAdapter.addItem(ChatItem.TimeStamp(currentTime))
                                }
                                lastMessageTimestamp = currentTime
                                
                                // 检查是否是技能消息（优先使用skillId，如果没有则通过消息格式识别）
                                val skill = if (skillId != null && skillId.isNotEmpty()) {
                                    // 优先使用skillId查找技能
                                    findSkillById(skillId) ?: run {
                                        // 如果通过ID找不到，尝试从消息文本解析
                                        val skillTitle = extractSkillTitleFromMessage(message)
                                        skillTitle?.let { findSkillByTitle(it, message) }
                                    }
                                } else {
                                    // 没有skillId，通过消息格式识别
                                    val skillTitle = extractSkillTitleFromMessage(message)
                                    skillTitle?.let { findSkillByTitle(it, message) }
                                }
                                
                                if (skill != null) {
                                    retryAdapter.addItem(ChatItem.SkillMessage(skill, sender, currentTime, isUserMessage, senderImei))
                                } else {
                                    retryAdapter.addItem(
                                        ChatItem.Message(
                                            sender = sender,
                                            message = message,
                                            isUserMessage = isUserMessage,
                                            isComplete = isComplete,
                                            isAnswer = isAnswer,
                                            timestamp = currentTime,
                                            recommendations = recommendations,
                                            senderImei = senderImei
                                        )
                                    )
                                }
                                
                                loadedMessageCount++
                                updateScrollBehavior()
                                binding?.rvChatMessages?.postDelayed({
                                    scrollToBottom()
                                }, 100)
                            } else {
                                Log.w(TAG, "Adapter仍未初始化，消息已保存到记录中，将在恢复消息时显示")
                            }
                        }, 500) // 等待500ms，给adapter初始化时间
                        return@runOnUiThread
                    }
            
            // 如果是普通系统消息（不是用户消息，也不是任务完成消息，也不是answer消息），且不跳过系统消息容器，添加到固定容器
            if (!isUserMessage && !isComplete && !isAnswer && !skipSystemMessageContainer) {
                // 端云同步已在 addMessageToList 分支统一处理
                // 添加到固定系统消息容器（不添加到RecyclerView）
                // 注意：系统消息不更新对话列表，因为它们不是真正的聊天消息（气泡消息）
                addSystemMessageToFixedContainer(sender, message)
                return@runOnUiThread
            }
            
            // 只有真正添加到RecyclerView的消息（气泡消息）才更新对话列表
            // 用户消息、小助手消息、云侧消息、人工客服消息、任务完成消息、answer消息都会更新
            // 好友消息（在好友对话页面）也应该更新对话列表
            val isFriendConversation = currentConversation?.id?.startsWith("friend_") == true
            // 只有在对应对话页面时才更新对话列表，避免好友消息更新人工客服对话
            if (isFriendConversation) {
                // 好友对话：只更新好友对话列表
                currentConversation?.let { conversation ->
                    updateConversationLastMessage(conversation.id, message)
                }
            } else if (sender == "我" || sender == "用户" || sender == "小助手" || sender == "云侧" || sender == "人工客服" || isComplete || isAnswer) {
                // 非好友对话：更新当前对话列表（人工客服、小助手等）
                currentConversation?.let { conversation ->
                    updateConversationLastMessage(conversation.id, message)
                }
            }
            
            // 检查是否需要显示时间（距离上一条消息超过10分钟）
            val shouldShowTime = lastMessageTimestamp == 0L || 
                (currentTime - lastMessageTimestamp) > 10 * 60 * 1000 // 10分钟
            
            // 如果存在新话题提示，先移除它（确保新消息添加在提示之前）
            val items = adapter.getItems()
            val newTopicHintIndex = items.indexOfFirst { it is ChatItem.NewTopicHint }
            val hasNewTopicHint = newTopicHintIndex >= 0
            
            lastMessageTimestamp = currentTime
            
            // 检查是否是技能消息（优先使用resolvedSkillId）
            val skill = if (resolvedSkillId != null && resolvedSkillId.isNotEmpty()) {
                // 优先使用resolvedSkillId查找技能
                Log.d(TAG, "通过skillId查找技能: skillId=$resolvedSkillId")
                findSkillById(resolvedSkillId) ?: run {
                    // 如果通过ID找不到，尝试从消息文本解析
                    Log.d(TAG, "通过skillId未找到技能，尝试从消息文本解析")
                    val parsedSkill = parseSkillFromMessage(message)
                    if (parsedSkill != null) {
                        // 从消息中解析出技能，但使用resolvedSkillId（而不是临时ID）
                        val skillWithResolvedId = parsedSkill.copy(id = resolvedSkillId)
                        // 保存到临时技能存储，确保退出重进后也能找到
                        TemporarySkillManager.saveTemporarySkill(requireContext(), skillWithResolvedId, currentConversation?.id)
                        Log.d(TAG, "从消息解析出技能并保存到临时存储: skillId=$resolvedSkillId, title=${skillWithResolvedId.title}")
                        skillWithResolvedId
                    } else {
                        // 如果解析失败，尝试通过标题查找
                        val skillTitle = extractSkillTitleFromMessage(message)
                        skillTitle?.let { findSkillByTitle(it, message) }
                    }
                }
            } else {
                // 没有skillId，通过消息格式识别
                val skillTitle = extractSkillTitleFromMessage(message)
                skillTitle?.let { findSkillByTitle(it, message) }
            }
            
            val messageItem: ChatItem = if (skill != null) {
                Log.d(TAG, "识别到技能消息，显示为技能卡片: skillTitle=${skill.title}, skillId=${skill.id}")
                ChatItem.SkillMessage(skill, sender, currentTime, isUserMessage, senderImei)
            } else {
                Log.d(TAG, "创建消息气泡: sender=$sender, isUserMessage=$isUserMessage, isComplete=$isComplete, isAnswer=$isAnswer")
                ChatItem.Message(
                    sender = sender,
                    message = message,
                    isUserMessage = isUserMessage,
                    isComplete = isComplete,
                    isAnswer = isAnswer,
                    timestamp = currentTime,
                    recommendations = recommendations,
                    senderImei = senderImei
                )
            }

            if (clearThinking) {
                val itemsToAdd = mutableListOf<ChatItem>()
                if (shouldShowTime) itemsToAdd.add(ChatItem.TimeStamp(currentTime))
                itemsToAdd.add(messageItem)
                adapter.addItemsClearingThinking(*itemsToAdd.toTypedArray())
            } else {
                if (shouldShowTime) {
                    adapter.addItem(ChatItem.TimeStamp(currentTime))
                }
                adapter.addItem(messageItem)
            }
            
            // 更新已加载消息计数（新消息总是显示在最底部）
            loadedMessageCount++
            
            // 确保新话题提示在最后（如果存在）
            ensureNewTopicHintAtEnd()
            
            // 根据消息数量决定滚动行为
            updateScrollBehavior()
            
            // 如果是小助手发送的消息，自动滚动到底部
            if (sender == "小助手") {
                binding.rvChatMessages.postDelayed({
                    scrollToBottom()
                }, 100) // 延迟100ms，确保消息已完全添加到UI
            } else {
                // 添加消息后检查按钮可见性
                binding.rvChatMessages.postDelayed({
                    checkScrollToBottomButtonVisibility()
                }, 100)
            }
            
            Log.d(TAG, "消息已成功添加到UI: sender=$sender, message=$message")
                } catch (e: Exception) {
                    Log.e(TAG, "在UI线程中添加消息失败: ${e.message}", e)
                    // 即使UI更新失败，也保存到记录
                    val messageType = when {
                        sender == "我" || sender == "用户" -> "user"
                        isComplete -> "complete"
                        isAnswer -> "answer"
                        else -> "system"
                    }
                    val chatMessage = ChatMessage(sender, message, messageType)
                    if (addMessageToList(chatMessage)) {
                        saveChatMessagesDebounced()
                    }
                }
            }
        } catch (e: Exception) {
            Log.e(TAG, "addChatMessage异常: ${e.message}", e)
            // 即使异常，也保存到记录
            try {
                val messageType = when {
                    sender == "我" || sender == "用户" -> "user"
                    isComplete -> "complete"
                    isAnswer -> "answer"
                    else -> "system"
                }
                val chatMessage = ChatMessage(sender, message, messageType)
                if (addMessageToList(chatMessage)) {
                    saveChatMessagesDebounced()
                }
            } catch (e2: Exception) {
                Log.e(TAG, "保存聊天记录也失败: ${e2.message}", e2)
            }
        }
    }
    
    /**
     * 添加视频分析结果消息（带"加入技能"按钮）
     * @param analysisResult 视频分析结果
     */
    private fun addVideoAnalysisMessage(analysisResult: VideoAnalysisResult) {
        try {
            val currentActivity = activity
            if (currentActivity == null) {
                Log.w(TAG, "Activity为null，无法添加视频分析消息到UI")
                return
            }
            
            // 检查binding是否有效
            if (_binding == null) {
                Log.w(TAG, "Binding为null，无法添加视频分析消息到UI")
                return
            }
            
            currentActivity.runOnUiThread {
                try {
                    if (_binding == null) {
                        Log.w(TAG, "Binding在UI线程中为null")
                        return@runOnUiThread
                    }
                    
                    // 保存到聊天记录
                    val currentTime = System.currentTimeMillis()
                    val chatMessage = ChatMessage("小助手", analysisResult.formattedMessage, "answer", currentTime, chatUuid)
                    if (addMessageToList(chatMessage)) {
                        saveChatMessagesDebounced()
                    }
                    
                    // 添加到聊天消息列表（通过Adapter）
                    val adapter = chatAdapter
                    if (adapter != null) {
                        // 检查是否需要显示时间
                        val shouldShowTime = lastMessageTimestamp == 0L || 
                            (System.currentTimeMillis() - lastMessageTimestamp) > 10 * 60 * 1000
                        if (shouldShowTime) {
                            // 时间戳插入到底部（最新消息在底部）
                            adapter.addItem(ChatItem.TimeStamp(System.currentTimeMillis()))
                        }
                        lastMessageTimestamp = System.currentTimeMillis()
                        // 使用新的 VideoAnalysisMessage 类型，包含加号按钮
                        adapter.addItem(ChatItem.VideoAnalysisMessage(analysisResult, System.currentTimeMillis()))
                        loadedMessageCount++
                        
                        // 确保新话题提示在最后（如果存在）
                        ensureNewTopicHintAtEnd()
                        
                        updateScrollBehavior()
                        
                        // 小助手发送视频分析消息后，自动滚动到底部
                        binding.rvChatMessages.postDelayed({
                            scrollToBottom()
                        }, 100) // 延迟100ms，确保消息已完全添加到UI
                    }
                    
                } catch (e: Exception) {
                    Log.e(TAG, "添加视频分析消息失败: ${e.message}", e)
                }
            }
        } catch (e: Exception) {
            Log.e(TAG, "添加视频分析消息失败: ${e.message}", e)
        }
    }
    
    /**
     * 添加技能消息到聊天记录（显示技能卡片）
     */
    fun addSkillMessage(skill: Skill, sender: String, isUserMessage: Boolean = true) {
        try {
            val currentActivity = activity
            if (currentActivity == null) {
                Log.w(TAG, "Activity为null，无法添加技能消息到UI")
                // 即使Activity为null，也保存到聊天记录
                val currentTime = System.currentTimeMillis()
                val skillMessageText = formatSkillAsMessage(skill)
                val chatMessage = ChatMessage(sender, skillMessageText, if (isUserMessage) "user" else "system", currentTime, chatUuid, skillId = skill.id)
                if (addMessageToList(chatMessage)) {
                    saveChatMessagesDebounced()
                }
                return
            }
            
            // 检查binding是否有效
            if (_binding == null) {
                Log.w(TAG, "Binding为null，无法添加技能消息到UI，但会保存到记录中")
                val currentTime = System.currentTimeMillis()
                val skillMessageText = formatSkillAsMessage(skill)
                val chatMessage = ChatMessage(sender, skillMessageText, if (isUserMessage) "user" else "system", currentTime, chatUuid, skillId = skill.id)
                if (addMessageToList(chatMessage)) {
                    saveChatMessagesDebounced()
                }
                return
            }
            
            currentActivity.runOnUiThread {
                try {
                    if (_binding == null) {
                        Log.w(TAG, "Binding在UI线程中为null，仅保存到记录")
                        val currentTime = System.currentTimeMillis()
                        val skillMessageText = formatSkillAsMessage(skill)
                        val chatMessage = ChatMessage(sender, skillMessageText, if (isUserMessage) "user" else "system", currentTime, chatUuid, skillId = skill.id)
                        if (addMessageToList(chatMessage)) {
                            saveChatMessagesDebounced()
                        }
                        return@runOnUiThread
                    }
                    
                    // 保存到聊天记录（使用文本格式保存，以便恢复时也能显示）
                    val currentTime = System.currentTimeMillis()
                    val skillMessageText = formatSkillAsMessage(skill)
                    // 保存技能ID，以便恢复时能正确显示技能卡
                    Log.d(TAG, "保存技能消息 - skillId: ${skill.id}, skillTitle: ${skill.title}, message: ${skillMessageText.take(50)}")
                    val chatMessage = ChatMessage(sender, skillMessageText, if (isUserMessage) "user" else "system", currentTime, chatUuid, skillId = skill.id)
                    if (addMessageToList(chatMessage)) {
                        // 用户消息立即保存，避免丢失
                        if (isUserMessage) {
                            saveChatMessages(sync = false)
                        } else {
                            saveChatMessagesDebounced()
                        }
                        Log.d(TAG, "技能消息已保存到chatMessages列表")
                    }
                    
                    // 更新对话列表
                    if (isUserMessage || sender == "小助手" || sender == "人工客服") {
                        currentConversation?.let { conversation ->
                            updateConversationLastMessage(conversation.id, "📋 ${skill.title}")
                        }
                    }
                    
                    // 添加到聊天消息列表（通过Adapter）
                    val adapter = chatAdapter
                    if (adapter != null) {
                        // 检查是否需要显示时间
                        val shouldShowTime = lastMessageTimestamp == 0L || 
                            (currentTime - lastMessageTimestamp) > 10 * 60 * 1000
                        if (shouldShowTime) {
                            adapter.addItem(ChatItem.TimeStamp(currentTime))
                        }
                        lastMessageTimestamp = currentTime
                        
                        // 使用新的 SkillMessage 类型，显示技能卡片
                        adapter.addItem(ChatItem.SkillMessage(skill, sender, currentTime, isUserMessage, null))
                        loadedMessageCount++
                        
                        // 确保新话题提示在最后（如果存在）
                        ensureNewTopicHintAtEnd()
                        
                        updateScrollBehavior()
                        
                        // 自动滚动到底部
                        binding.rvChatMessages.postDelayed({
                            scrollToBottom()
                        }, 100) // 延迟100ms，确保消息已完全添加到UI
                    }
                    
                } catch (e: Exception) {
                    Log.e(TAG, "添加技能消息失败: ${e.message}", e)
                }
            }
        } catch (e: Exception) {
            Log.e(TAG, "添加技能消息异常: ${e.message}", e)
        }
    }
    
    /**
     * 将技能格式化为消息内容（用于保存到聊天记录）
     */
    private fun formatSkillAsMessage(skill: Skill): String {
        val sb = StringBuilder()
        sb.append(getString(R.string.skill_share_format, skill.title))
        sb.append(getString(R.string.action_steps_label))
        sb.append("\n")
        skill.steps.forEachIndexed { index, step ->
            sb.append("${index + 1}. $step\n")
        }
        if (skill.originalPurpose != null) {
            sb.append(getString(R.string.original_purpose_format, skill.originalPurpose))
        }
        return sb.toString()
    }
    
    /**
     * 分享技能给指定好友（供 ActionButtonsViewHolder 调用）
     */
    fun shareSkillToFriend(targetImei: String, skill: Skill) {
        try {
            val mainActivity = activity as? MainActivity ?: return
            val webSocket = mainActivity.getCustomerServiceWebSocket()
            if (webSocket == null || !webSocket.isConnected()) {
                Toast.makeText(requireContext(), "无法连接到服务器，请稍后重试", Toast.LENGTH_SHORT).show()
                return
            }
            val message = formatSkillAsMessage(skill)
            webSocket.sendFriendMessage(targetImei, message, skillId = skill.id)
            val friendConversationId = "friend_$targetImei"
            val friendConversation = Conversation(
                id = friendConversationId,
                name = "好友",
                avatar = null,
                lastMessage = null,
                lastMessageTime = System.currentTimeMillis()
            )
            val chatFragment = mainActivity.getOrCreateChatFragment(friendConversation)
            chatFragment.addSkillMessage(skill, "我", isUserMessage = true)
            mainActivity.switchToChatFragment(friendConversation)
            Toast.makeText(requireContext(), "技能已分享给好友", Toast.LENGTH_SHORT).show()
        } catch (e: Exception) {
            Log.e(TAG, "分享技能到好友失败: ${e.message}", e)
            Toast.makeText(requireContext(), "分享失败：${e.message}", Toast.LENGTH_SHORT).show()
        }
    }
    
    /**
     * 分享技能到群组（供 ActionButtonsViewHolder 调用）
     */
    fun shareSkillToGroup(skill: Skill) {
        try {
            val groups = GroupManager.getGroups(requireContext())
            val options = mutableListOf<String>()
            val optionTypes = mutableListOf<String>()
            groups.forEach { group ->
                options.add("群组: ${group.name}")
                optionTypes.add(group.groupId)
            }
            if (options.isEmpty()) {
                Toast.makeText(requireContext(), "暂无群组可分享", Toast.LENGTH_SHORT).show()
                return
            }
            android.app.AlertDialog.Builder(requireContext())
                .setTitle("选择群组")
                .setItems(options.toTypedArray()) { _, which ->
                    val groupId = optionTypes[which]
                    val mainActivity = activity as? MainActivity ?: return@setItems
                    val webSocket = mainActivity.getCustomerServiceWebSocket()
                    if (webSocket == null || !webSocket.isConnected()) {
                        Toast.makeText(requireContext(), "无法连接到服务器，请稍后重试", Toast.LENGTH_SHORT).show()
                        return@setItems
                    }
                    val message = formatSkillAsMessage(skill)
                    val messageId = webSocket.sendGroupMessage(groupId, message)
                    markOwnGroupMessageSent(
                        groupId = groupId,
                        content = message,
                        messageType = "text",
                        messageId = messageId
                    )
                    val groupConversationId = "group_$groupId"
                    val groupConversation = Conversation(
                        id = groupConversationId,
                        name = "群组",
                        avatar = null,
                        lastMessage = null,
                        lastMessageTime = System.currentTimeMillis()
                    )
                    val chatFragment = mainActivity.getOrCreateChatFragment(groupConversation)
                    chatFragment.addSkillMessage(skill, "我", isUserMessage = true)
                    mainActivity.switchToChatFragment(groupConversation)
                    Toast.makeText(requireContext(), "技能已分享到群组", Toast.LENGTH_SHORT).show()
                }
                .setNegativeButton("取消", null)
                .show()
        } catch (e: Exception) {
            Log.e(TAG, "分享技能到群组失败: ${e.message}", e)
            Toast.makeText(requireContext(), "分享失败：${e.message}", Toast.LENGTH_SHORT).show()
        }
    }
    
