    /**
     * 从消息文本中提取技能标题（用于恢复技能消息）
     * @param message 消息文本
     * @return 技能标题，如果不是技能消息则返回null
     */
    private fun extractSkillTitleFromMessage(message: String): String? {
        // 检查是否是技能消息格式：📋 技能分享：${skill.title} 或 📋 Skill share: ${skill.title}
        val pattern = Regex("📋\\s*(?:技能分享|Skill share)[：:]\\s*(.+?)(?:\\n|$)")
        val match = pattern.find(message)
        return match?.groupValues?.get(1)?.trim()
    }
    
    /**
     * 从消息文本中解析技能信息（用于创建临时技能对象）
     * @param message 消息文本
     * @return 技能对象，如果解析失败则返回null
     */
    private fun parseSkillFromMessage(message: String): Skill? {
        return try {
            // 提取技能标题（支持中英文格式）
            val titlePattern = Regex("📋\\s*(?:技能分享|Skill share)[：:]\\s*(.+?)(?:\\n|$)")
            val titleMatch = titlePattern.find(message)
            val title = titleMatch?.groupValues?.get(1)?.trim() ?: return null
            
            // 提取操作步骤部分（从"操作步骤："或"Steps:"到"原始目的："或"Original purpose:"或消息结尾）
            val stepsStartPattern = Regex("(?:操作步骤|Steps)[：:]?\\s*\\n")
            val stepsStartMatch = stepsStartPattern.find(message)
            if (stepsStartMatch == null) {
                Log.e(TAG, "未找到操作步骤部分")
                return null
            }
            
            val stepsStartIndex = stepsStartMatch.range.last + 1
            val remainingText = message.substring(stepsStartIndex)
            
            // 查找"原始目的："或"Original purpose:"的位置，如果存在则截取到那里
            val purposePattern = Regex("\\n(?:原始目的|Original purpose)[：:]")
            val purposeMatch = purposePattern.find(remainingText)
            val stepsText = if (purposeMatch != null) {
                remainingText.substring(0, purposeMatch.range.first)
            } else {
                remainingText
            }
            
            // 解析步骤列表（每行一个步骤，格式：数字. 步骤内容）
            val steps = stepsText.split("\n")
                .mapNotNull { line ->
                    val trimmedLine = line.trim()
                    if (trimmedLine.isEmpty()) {
                        return@mapNotNull null
                    }
                    
                    // 匹配格式：数字. 步骤内容 或 数字、步骤内容
                    val stepPattern = Regex("^\\d+[.、]\\s*(.+)$")
                    val stepMatch = stepPattern.find(trimmedLine)
                    if (stepMatch != null) {
                        stepMatch.groupValues[1].trim().takeIf { it.isNotEmpty() }
                    } else {
                        // 如果没有匹配到格式，但行不为空，可能是格式不标准，直接使用整行
                        trimmedLine.takeIf { it.isNotEmpty() }
                    }
                }
                .filter { it.isNotEmpty() }
            
            if (steps.isEmpty()) {
                Log.e(TAG, "解析出的步骤列表为空")
                return null
            }
            
            Log.d(TAG, "解析技能消息成功: title=$title, stepsCount=${steps.size}, steps=$steps")
            
            // 提取原始目的（可选）
            val originalPurposePattern = Regex("原始目的[：:]?\\s*(.+?)(?:\\n|$)")
            val originalPurposeMatch = originalPurposePattern.find(message)
            val originalPurpose = originalPurposeMatch?.groupValues?.get(1)?.trim()
            
            // 创建临时技能对象（使用临时ID）
            Skill(
                id = "temp_${title.hashCode()}_${System.currentTimeMillis()}",
                title = title,
                steps = steps,
                createdAt = System.currentTimeMillis(),
                originalPurpose = originalPurpose
            )
        } catch (e: Exception) {
            Log.e(TAG, "解析技能消息失败: ${e.message}", e)
            e.printStackTrace()
            null
        }
    }
    
    /**
     * 根据技能ID查找技能
     * @param skillId 技能ID
     * @return 找到的技能，如果找不到则返回null
     */
    private fun findSkillById(skillId: String): Skill? {
        return try {
            // 1. 先从我的技能中查找
            val mySkills = SkillManager.loadSkills(requireContext())
            val skill = mySkills.find { it.id == skillId }
            if (skill != null) {
                return skill
            }
            
            // 2. 如果我的技能中找不到，从技能社区中查找
            val communitySkills = SkillManager.loadCommunitySkills(requireContext())
            val communitySkill = communitySkills.find { it.id == skillId }
            if (communitySkill != null) {
                return communitySkill
            }
            
            // 3. 如果都找不到，从临时技能存储中查找（新增）
            val temporarySkill = TemporarySkillManager.findTemporarySkill(requireContext(), skillId)
            if (temporarySkill != null) {
                return temporarySkill
            }
            
            null
        } catch (e: Exception) {
            Log.e(TAG, "根据ID查找技能失败: ${e.message}", e)
            null
        }
    }
    
    /**
     * 重新尝试恢复待恢复的技能卡片
     * 在技能加载完成后调用，尝试通过skillId恢复技能卡片
     */
    private fun retryPendingSkillMessages() {
        if (pendingSkillMessages.isEmpty()) {
            return
        }
        
        val adapter = chatAdapter ?: return
        if (!isAdded || _binding == null) {
            return
        }
        
        Log.d(TAG, "开始重新尝试恢复 ${pendingSkillMessages.size} 条待恢复的技能消息")
        
        val successfullyRestored = mutableListOf<ChatMessage>()
        
        // 遍历待恢复的技能消息
        pendingSkillMessages.forEach { chatMessage ->
            val skillId = chatMessage.skillId ?: return@forEach
            
            // 尝试通过skillId查找技能
            val skill = findSkillById(skillId)
            if (skill != null) {
                Log.d(TAG, "通过skillId找到技能: ${skill.title}，开始替换消息")
                
                // 查找对应的消息项（通过timestamp和sender匹配）
                val items = adapter.getItems()
                val messageIndex = items.indexOfFirst { item ->
                    when (item) {
                        is ChatItem.Message -> {
                            item.timestamp == chatMessage.timestamp && 
                            item.sender == chatMessage.sender &&
                            item.message == chatMessage.message
                        }
                        else -> false
                    }
                }
                
                if (messageIndex >= 0) {
                    // 找到对应的消息项，替换为技能卡片
                    val isUserMsg = chatMessage.type == "user"
                    
                    // 移除文本消息
                    adapter.removeItemAt(messageIndex)
                    
                    // 添加技能卡片
                    adapter.addItemAt(messageIndex, ChatItem.SkillMessage(
                        skill, 
                        chatMessage.sender, 
                        chatMessage.timestamp, 
                        isUserMsg,
                        chatMessage.senderImei
                    ))
                    
                    Log.d(TAG, "成功替换消息为技能卡片: ${skill.title}")
                    successfullyRestored.add(chatMessage)
                } else {
                    Log.w(TAG, "未找到对应的消息项，无法替换: skillId=$skillId, timestamp=${chatMessage.timestamp}")
                }
            } else {
                Log.d(TAG, "仍未找到技能，继续等待: skillId=$skillId")
            }
        }
        
        // 移除已成功恢复的消息
        pendingSkillMessages.removeAll(successfullyRestored)
        
        if (successfullyRestored.isNotEmpty()) {
            Log.d(TAG, "成功恢复 ${successfullyRestored.size} 条技能消息，剩余 ${pendingSkillMessages.size} 条待恢复")
        }
    }
    
    /**
     * 根据技能标题查找技能（从我的技能和技能社区中查找）
     * 如果找不到，尝试从消息文本中解析技能信息
     * @param skillTitle 技能标题
     * @param message 原始消息文本（用于解析技能信息）
     * @return 找到的技能，如果找不到则返回null
     */
    private fun findSkillByTitle(skillTitle: String, message: String? = null): Skill? {
        return try {
            // 先从我的技能中查找
            val mySkills = SkillManager.loadSkills(requireContext())
            val skill = mySkills.find { it.title == skillTitle }
            if (skill != null) {
                return skill
            }
            
            // 如果我的技能中找不到，从技能社区中查找
            val communitySkills = SkillManager.loadCommunitySkills(requireContext())
            val communitySkill = communitySkills.find { it.title == skillTitle }
            if (communitySkill != null) {
                return communitySkill
            }
            
            // 如果都找不到，且提供了消息文本，尝试从消息中解析技能信息
            if (message != null) {
                val parsedSkill = parseSkillFromMessage(message)
                if (parsedSkill != null) {
                    Log.d(TAG, "从消息文本中解析出技能: ${parsedSkill.title}")
                    return parsedSkill
                }
            }
            
            null
        } catch (e: Exception) {
            Log.e(TAG, "查找技能失败: ${e.message}", e)
            null
        }
    }
    
    /**
     * 创建查看图标
     */
    internal fun createViewIcon(container: android.widget.LinearLayout, skillTitle: String) {
        val viewIcon = android.widget.ImageView(requireContext()).apply {
            // 使用 View.generateViewId() 生成唯一ID，避免ID冲突
            id = android.view.View.generateViewId()
            tag = "view_skill_icon" // 使用tag标记，方便查找
            // 图标高度仅比字体大一点：按钮字体是12sp，图标设为14dp（仅大一点）
            val iconSize = (14 * resources.displayMetrics.density).toInt() // 14dp，仅比12sp字体大一点
            layoutParams = android.widget.LinearLayout.LayoutParams(
                iconSize, // 14dp
                iconSize  // 14dp
            ).apply {
                setMargins((8 * resources.displayMetrics.density).toInt(), 0, 0, 0) // 左边距8dp
            }
            scaleType = android.widget.ImageView.ScaleType.FIT_CENTER
            setImageResource(android.R.drawable.ic_menu_view) // 使用系统查看图标
            setColorFilter(0xFF81C784.toInt()) // 浅绿色，与按钮颜色一致
            contentDescription = "查看技能"
            
            // 点击事件：跳转到技能详情页
            setOnClickListener {
                // 从 SkillManager 查找技能
                val skills = SkillManager.loadSkills(requireContext())
                val skill = skills.find { it.title == skillTitle }
                
                if (skill != null) {
                    // 跳转到技能详情页
                    navigateToSkillDetail(skill.id)
                } else {
                    android.widget.Toast.makeText(
                        requireContext(),
                        "技能不存在",
                        android.widget.Toast.LENGTH_SHORT
                    ).show()
                }
            }
        }
        container.addView(viewIcon)
    }
    
    /**
     * 跳转到技能详情页
     */
    internal fun navigateToSkillDetail(skillId: String) {
        try {
            // 检查Fragment状态
            if (!isAdded || activity == null) {
                Log.w(TAG, "Fragment未附加或Activity为null，无法跳转到技能详情页")
                return
            }
            
            // 检查skillId有效性
            if (skillId.isNullOrEmpty()) {
                Log.e(TAG, "技能ID无效，无法跳转到技能详情页")
                Toast.makeText(requireContext(), "技能ID无效", Toast.LENGTH_SHORT).show()
                return
            }
            
            // 通过 MainActivity 跳转到技能详情页
            val mainActivity = activity as? MainActivity
            if (mainActivity != null) {
                // 直接跳转到详情页，不需要先切换到技能页面
                // 使用 post 延迟执行，确保当前 Fragment 的状态稳定
                view?.post {
                    try {
                        // 再次检查 Fragment 状态
                        if (isAdded && activity != null) {
                            val detailFragment = SkillDetailFragment.newInstance(skillId)
                            mainActivity.supportFragmentManager.beginTransaction()
                                .setCustomAnimations(0, 0, 0, 0)
                                .replace(R.id.fragmentContainer, detailFragment)
                                .addToBackStack(null)
                                .commitAllowingStateLoss()
                        }
                    } catch (e: Exception) {
                        Log.e(TAG, "跳转到技能详情页失败: ${e.message}", e)
                        try {
                            Toast.makeText(requireContext(), getString(R.string.open_skill_detail_failed, e.message ?: ""), Toast.LENGTH_SHORT).show()
                        } catch (e2: Exception) {
                            Log.e(TAG, "显示Toast失败: ${e2.message}", e2)
                        }
                    }
                }
            } else {
                Log.e(TAG, "MainActivity为null，无法跳转到技能详情页")
                Toast.makeText(requireContext(), getString(R.string.cannot_open_skill_detail), Toast.LENGTH_SHORT).show()
            }
        } catch (e: Exception) {
            Log.e(TAG, "跳转到技能详情页失败: ${e.message}", e)
            try {
                Toast.makeText(requireContext(), getString(R.string.open_skill_detail_failed, e.message ?: ""), Toast.LENGTH_SHORT).show()
            } catch (e2: Exception) {
                Log.e(TAG, "显示Toast失败: ${e2.message}", e2)
            }
        }
    }
    
