    /**
     * 创建时间显示视图
     * @param timestamp 时间戳
     */
    private fun createTimeView(timestamp: Long): android.widget.TextView {
        val timeText = formatTime(timestamp)
        return android.widget.TextView(requireContext()).apply {
            text = timeText
            textSize = 11f  // 时间戳保持小字体
            setTextColor(0xFF999999.toInt())
            setPadding(16, 8, 16, 8)
            gravity = android.view.Gravity.CENTER
            layoutParams = android.widget.LinearLayout.LayoutParams(
                android.widget.LinearLayout.LayoutParams.MATCH_PARENT,
                android.widget.LinearLayout.LayoutParams.WRAP_CONTENT
            ).apply {
                setMargins(0, 8, 0, 8)
            }
        }
    }
    
    /**
     * 格式化时间（类似微信）
     * @param timestamp 时间戳
     * @return 格式化后的时间字符串
     */
    internal fun formatTime(timestamp: Long): String {
        val calendar = Calendar.getInstance()
        val messageCalendar = Calendar.getInstance().apply {
            timeInMillis = timestamp
        }
        
        val today = Calendar.getInstance()
        today.set(Calendar.HOUR_OF_DAY, 0)
        today.set(Calendar.MINUTE, 0)
        today.set(Calendar.SECOND, 0)
        today.set(Calendar.MILLISECOND, 0)
        
        val yesterday = Calendar.getInstance().apply {
            timeInMillis = today.timeInMillis
            add(Calendar.DAY_OF_YEAR, -1)
        }
        
        val messageDate = Calendar.getInstance().apply {
            timeInMillis = timestamp
            set(Calendar.HOUR_OF_DAY, 0)
            set(Calendar.MINUTE, 0)
            set(Calendar.SECOND, 0)
            set(Calendar.MILLISECOND, 0)
        }
        
        val timeFormat = SimpleDateFormat("HH:mm", Locale.getDefault())
        val dateFormat = SimpleDateFormat("yyyy/MM/dd", Locale.getDefault())
        
        return when {
            // 今天
            messageDate.timeInMillis == today.timeInMillis -> {
                "${getString(R.string.today)} ${timeFormat.format(Date(timestamp))}"
            }
            // 昨天
            messageDate.timeInMillis == yesterday.timeInMillis -> {
                "${getString(R.string.yesterday)} ${timeFormat.format(Date(timestamp))}"
            }
            // 更早的日期
            else -> {
                "${dateFormat.format(Date(timestamp))} ${timeFormat.format(Date(timestamp))}"
            }
        }
    }
    
    /**
     * 处理app://协议链接，跳转到指定应用
     */
    private fun handleAppLink(appName: String) {
        Log.d(TAG, "【handleAppLink】开始处理应用链接: $appName")
        
        // 处理特殊链接：使用说明
        if (appName == "tutorial") {
            Log.d(TAG, "【handleAppLink】打开使用说明对话框")
            try {
                val tutorialDialog = TutorialDialog(requireContext())
                tutorialDialog.show()
                Log.d(TAG, "【handleAppLink】✓ 成功打开使用说明对话框")
            } catch (e: Exception) {
                Log.e(TAG, "【handleAppLink】✗ 打开使用说明对话框失败: ${e.message}", e)
                Toast.makeText(requireContext(), "打开使用说明失败", Toast.LENGTH_SHORT).show()
            }
            return
        }
        
        // 处理应用链接
        val packageName = AppMappingManager.getPackageName(appName)
        Log.d(TAG, "【handleAppLink】应用名: $appName, 包名: $packageName")
        
        if (packageName != null) {
            val mainActivity = activity as? MainActivity
            if (mainActivity != null) {
                Log.d(TAG, "【handleAppLink】调用launchAppFromLink: $packageName")
                val success = mainActivity.launchAppFromLink(packageName)
                Log.d(TAG, "【handleAppLink】launchAppFromLink返回: $success")
                if (!success) {
                    Log.w(TAG, "【handleAppLink】✗ 无法打开应用: $appName")
                    Toast.makeText(requireContext(), "无法打开应用: $appName", Toast.LENGTH_SHORT).show()
                } else {
                    Log.d(TAG, "【handleAppLink】✓ 成功打开应用: $appName")
                }
            } else {
                Log.e(TAG, "【handleAppLink】✗ MainActivity为null")
            }
        } else {
            Log.w(TAG, "【handleAppLink】✗ 未找到应用: $appName")
            Toast.makeText(requireContext(), "未找到应用: $appName", Toast.LENGTH_SHORT).show()
        }
    }
    
    /**
     * 为TextView设置Markwon并处理app://链接点击
     */
    internal fun setupMarkwonWithAppLinks(textView: android.widget.TextView, markdownText: String, markwon: Markwon) {
        Log.d(TAG, "setupMarkwonWithAppLinks: 开始处理，markdownText包含app://: ${markdownText.contains("app://")}")
        
        // "跳转查看"部分的链接已经在同一行，不需要特殊处理
        markwon.setMarkdown(textView, markdownText)
        
        // 获取渲染后的文本
        val text = textView.text
        Log.d(TAG, "setupMarkwonWithAppLinks: 文本类型: ${text.javaClass.simpleName}, 长度: ${text.length}")
        
        if (text is android.text.Spannable) {
            var replacedCount = 0
            
            // 查找所有LinkSpan并替换app://链接（使用反射，如果失败则跳过）
            try {
                val linkSpanClass = Class.forName("io.noties.markwon.LinkSpan")
                val linkSpans = text.getSpans(0, text.length, linkSpanClass)
                Log.d(TAG, "setupMarkwonWithAppLinks: 找到 ${linkSpans.size} 个LinkSpan")
                
                for (linkSpan in linkSpans) {
                    val getLinkMethod = linkSpanClass.getMethod("getLink")
                    val url = getLinkMethod.invoke(linkSpan) as? String
                    Log.d(TAG, "setupMarkwonWithAppLinks: LinkSpan URL: $url")
                    
                    if (url != null && url.startsWith("app://")) {
                        val appName = url.removePrefix("app://")
                        val spanStart = text.getSpanStart(linkSpan)
                        val spanEnd = text.getSpanEnd(linkSpan)
                        val spanFlags = text.getSpanFlags(linkSpan)
                        
                        Log.d(TAG, "setupMarkwonWithAppLinks: 找到app://链接: $appName (位置: $spanStart-$spanEnd)")
                        
                        // 移除原来的LinkSpan
                        text.removeSpan(linkSpan)
                        
                        // 创建自定义的ClickableSpan来处理app://链接
                        val appLinkSpan = object : android.text.style.ClickableSpan() {
                            override fun onClick(widget: android.view.View) {
                                Log.d(TAG, "【点击事件】ClickableSpan.onClick被调用: $appName")
                                handleAppLink(appName)
                            }
                            
                            override fun updateDrawState(ds: android.text.TextPaint) {
                                super.updateDrawState(ds)
                                // 保持链接样式（蓝色、下划线）
                                ds.color = 0xFF2196F3.toInt()
                                ds.isUnderlineText = true
                            }
                        }
                        
                        // 添加自定义的ClickableSpan
                        text.setSpan(appLinkSpan, spanStart, spanEnd, spanFlags)
                        replacedCount++
                        Log.d(TAG, "setupMarkwonWithAppLinks: ✓ 已替换app://链接: $appName (位置: $spanStart-$spanEnd)")
                    }
                }
            } catch (e: ClassNotFoundException) {
                // LinkSpan类不存在，这是正常的，Markwon可能使用URLSpan
                Log.d(TAG, "setupMarkwonWithAppLinks: LinkSpan类不存在，跳过（Markwon可能使用URLSpan）")
            } catch (e: Exception) {
                Log.e(TAG, "setupMarkwonWithAppLinks: 处理Markwon LinkSpan失败: ${e.message}", e)
            }
            
            // 检查URLSpan（Markwon通常使用URLSpan）
            val urlSpans = text.getSpans(0, text.length, android.text.style.URLSpan::class.java)
            Log.d(TAG, "setupMarkwonWithAppLinks: 找到 ${urlSpans.size} 个URLSpan")
            for (urlSpan in urlSpans) {
                val url = urlSpan.url
                Log.d(TAG, "setupMarkwonWithAppLinks: URLSpan URL: $url")
                if (url.startsWith("app://")) {
                    val appName = url.removePrefix("app://")
                    val spanStart = text.getSpanStart(urlSpan)
                    val spanEnd = text.getSpanEnd(urlSpan)
                    val spanFlags = text.getSpanFlags(urlSpan)
                    
                    Log.d(TAG, "setupMarkwonWithAppLinks: 找到app://链接(URLSpan): $appName (位置: $spanStart-$spanEnd)")
                    
                    // 移除原来的URLSpan
                    text.removeSpan(urlSpan)
                    
                    // 创建自定义的ClickableSpan
                    val appLinkSpan = object : android.text.style.ClickableSpan() {
                        override fun onClick(widget: android.view.View) {
                            Log.d(TAG, "【点击事件】ClickableSpan.onClick被调用(URLSpan): $appName")
                            handleAppLink(appName)
                        }
                        
                        override fun updateDrawState(ds: android.text.TextPaint) {
                            super.updateDrawState(ds)
                            ds.color = 0xFF2196F3.toInt()
                            ds.isUnderlineText = true
                        }
                    }
                    
                    text.setSpan(appLinkSpan, spanStart, spanEnd, spanFlags)
                    replacedCount++
                    Log.d(TAG, "setupMarkwonWithAppLinks: ✓ 已替换app://链接(URLSpan): $appName")
                }
            }
            
            // 最后检查所有ClickableSpan
            val allClickableSpans = text.getSpans(0, text.length, android.text.style.ClickableSpan::class.java)
            Log.d(TAG, "setupMarkwonWithAppLinks: 最终ClickableSpan数量: ${allClickableSpans.size}, 已替换app://链接数量: $replacedCount")
        } else {
            Log.w(TAG, "setupMarkwonWithAppLinks: 文本不是Spannable类型，无法处理链接")
        }
        
        // 使用OnTouchListener直接处理链接点击，这样可以与setTextIsSelectable共存
        // 注意：需要在ACTION_DOWN时检查是否有链接，如果有则消费事件；否则让TextView处理文本选择
        var touchedSpan: android.text.style.ClickableSpan? = null
        
        textView.setOnTouchListener { view, event ->
            recordBubbleTouch(event)
            Log.d(TAG, "【触摸事件】TextView.setOnTouchListener: action=${event.action}, x=${event.x}, y=${event.y}")
            
            val textView = view as? android.widget.TextView ?: return@setOnTouchListener false
            val text = textView.text
            if (text !is android.text.Spannable) {
                Log.d(TAG, "【触摸事件】文本不是Spannable类型")
                return@setOnTouchListener false
            }
            
            val layout = textView.layout
            if (layout == null) {
                Log.d(TAG, "【触摸事件】layout为null")
                return@setOnTouchListener false
            }
            
            // 计算点击位置在文本中的偏移量
            val x = event.x.toInt()
            val y = event.y.toInt()
            val line = layout.getLineForVertical(y - textView.totalPaddingTop + textView.scrollY)
            val offset = layout.getOffsetForHorizontal(line, (x - textView.totalPaddingLeft + textView.scrollX).toFloat())
            
            Log.d(TAG, "【触摸事件】点击位置: line=$line, offset=$offset, text.length=${text.length}, action=${event.action}")
            
            // 查找包含该位置的ClickableSpan
            val clickableSpans = text.getSpans(0, text.length, android.text.style.ClickableSpan::class.java)
            Log.d(TAG, "【触摸事件】找到 ${clickableSpans.size} 个ClickableSpan")
            
            val matchingSpan = clickableSpans.find { span ->
                val spanStart = text.getSpanStart(span)
                val spanEnd = text.getSpanEnd(span)
                val contains = spanStart <= offset && offset < spanEnd
                if (contains) {
                    Log.d(TAG, "【触摸事件】匹配span: start=$spanStart, end=$spanEnd, offset=$offset")
                }
                contains
            }
            
            when (event.action) {
                android.view.MotionEvent.ACTION_DOWN -> {
                    touchedSpan = matchingSpan
                    if (matchingSpan != null) {
                        Log.d(TAG, "【触摸事件】ACTION_DOWN: 点击到链接，消费事件")
                        return@setOnTouchListener true // 消费事件，防止文本选择
                    } else {
                        Log.d(TAG, "【触摸事件】ACTION_DOWN: 未点击到链接，允许文本选择")
                        return@setOnTouchListener false // 不消费事件，让TextView处理文本选择
                    }
                }
                android.view.MotionEvent.ACTION_UP -> {
                    if (touchedSpan != null && touchedSpan == matchingSpan) {
                        Log.d(TAG, "【触摸事件】ACTION_UP: 触发链接点击")
                        matchingSpan?.onClick(textView)
                        touchedSpan = null
                        return@setOnTouchListener true // 消费事件
                    } else {
                        Log.d(TAG, "【触摸事件】ACTION_UP: 未点击到链接或span已改变")
                        touchedSpan = null
                        return@setOnTouchListener false
                    }
                }
                android.view.MotionEvent.ACTION_CANCEL -> {
                    touchedSpan = null
                    return@setOnTouchListener false
                }
                else -> {
                    // 其他事件（如ACTION_MOVE）
                    if (touchedSpan != null) {
                        // 如果之前点击到了链接，继续消费事件
                        return@setOnTouchListener true
                    }
                    return@setOnTouchListener false
                }
            }
        }
        
        // 设置LinkMovementMethod以支持链接样式（下划线、颜色等）
        textView.movementMethod = android.text.method.LinkMovementMethod.getInstance()
        
        Log.d(TAG, "setupMarkwonWithAppLinks: 完成处理，已设置OnTouchListener和LinkMovementMethod")
    }
    
    /**
     * 检测并转换消息为Markdown格式
     * 支持格式：标题：xxx\n正文：xxx\n图片/视频描述：xxx
     * 也支持包含\n字面量的普通消息（如列表格式）
     */
    /**
     * 过滤消息中的SOP内容，用于显示
     * 保留原始消息用于分享等功能
     */
    private fun filterSOPFromMessage(message: String): String {
        // 如果消息包含SOP标记，移除SOP部分及其后的所有内容
        if (message.contains("###SOP###")) {
            // 找到###SOP###的位置，移除从该位置开始到消息结尾的所有内容
            val sopIndex = message.indexOf("###SOP###")
            if (sopIndex >= 0) {
                // 截取SOP标记之前的内容
                var filtered = message.substring(0, sopIndex).trim()
                
                // 清理末尾多余的换行符
                filtered = filtered.replace(Regex("\\n+$"), "")
                
                // 如果过滤后消息为空或只有空白，保留原始消息（避免完全清空）
                if (filtered.isBlank()) {
                    return message
                }
                
                return filtered
            }
        }
        return message
    }
    
    internal fun convertToMarkdown(message: String): String {
        var markdown = message
        
        // 首先处理\n字面量（字符串中的反斜杠n），转换为真正的换行符
        markdown = markdown.replace("\\n", "\n")
        
        // 将单个换行符转换为 Markdown 硬换行（两个空格 + 换行符）
        // 这样在 Markdown 渲染时能正确显示换行
        markdown = markdown.replace(Regex("([^\n])\n([^\n])"), "$1  \n$2")
        
        // 检测是否包含"标题："、"正文："、"图片/视频描述："等关键字
        val hasSpecialFormat = message.contains("标题：") || message.contains("正文：") || message.contains("图片/视频描述：")
        
        if (hasSpecialFormat) {
            // 转换标题格式：标题：xxx -> ## xxx
            markdown = markdown.replace(Regex("标题：(.+?)(\\n|$)"), "## \$1\n\n")
            
            // 转换正文格式：正文： -> 移除，保留后面的内容
            markdown = markdown.replace(Regex("正文：\\s*\\n"), "")
            
            // 转换图片/视频描述：xxx -> \n\n---\n\n*图片/视频描述：xxx*
            markdown = markdown.replace(Regex("图片/视频描述：(.+?)(\\n|$)"), "\n\n---\n\n*图片/视频描述：\$1*")
            
            // 处理列表项（以❌、‼️、📍、🚗、🚄、✈️等emoji开头的行，后面跟空格或直接跟文字）
            // 匹配模式：行首或换行后，emoji，可选空格，内容，换行或结尾
            markdown = markdown.replace(Regex("(^|\\n)([❌‼️📍🚗🚄✈️])\\s*(.+?)(\\n|$)"), "\$1- \$3\n")
            
            // 处理Day X：格式为粗体
            markdown = markdown.replace(Regex("(Day \\d+：)"), "**\$1**")
        }
        
        // 处理数字列表格式（1. 2. 3. 等），转换为Markdown列表
        // 匹配模式：行首或换行后，数字，点号，空格，内容
        markdown = markdown.replace(Regex("(^|\\n)(\\d+)\\.\\s+(.+?)(\\n|$)"), "\$1\$2. \$3\n")
        
        // 保留原有的换行结构，但确保列表项前后有适当的空行
        // 在列表项前添加空行（如果前面不是空行且不是列表项）
        markdown = markdown.replace(Regex("([^\\n\\-])\\n([\\-\\d])"), "\$1\n\n\$2")
        
        // 第三层：压缩分割线上下留白，避免看起来过于空旷
        markdown = compactThematicBreakSpacing(markdown)
        // 第一层：压缩段落空行，让整体阅读更紧凑
        markdown = compactParagraphSpacing(markdown)
        
        return markdown
    }

    private fun compactParagraphSpacing(input: String): String {
        // 压缩连续空白行（包含仅空格/制表符的空行）为单换行
        return input.replace(Regex("\\n[\\t \\u3000]*\\n+"), "\n")
    }

    private fun compactThematicBreakSpacing(input: String): String {
        // 统一把 thematic break 前后的空白压到最小：`\n---\n`
        return input
            .replace(Regex("\\n{2,}(\\s*(?:-{3,}|\\*{3,}|_{3,})\\s*)\\n{2,}"), "\n\$1\n")
            .replace(Regex("\\n{2,}(\\s*(?:-{3,}|\\*{3,}|_{3,})\\s*)"), "\n\$1")
            .replace(Regex("((?:-{3,}|\\*{3,}|_{3,})\\s*)\\n{2,}"), "\$1\n")
    }

    private fun bindMarkdownContentToBubble(
        bubble: android.widget.TextView,
        markdownMessage: String,
        markwon: Markwon
    ): android.view.View {
        val blocks = MarkdownTableParser.splitBlocks(markdownMessage)
        val hasTable = blocks.any { it is MarkdownTableParser.Block.Table }
        if (!hasTable) {
            setupMarkwonWithAppLinks(bubble, markdownMessage, markwon)
            return bubble
        }

        val context = requireContext()
        val density = resources.displayMetrics.density
        val visibleWidth = bubble.maxWidth.takeIf { it > 0 } ?: (resources.displayMetrics.widthPixels * 0.76f).toInt()
        val blockSpacing = (8f * density).toInt()
        val dividerVerticalMargin = (8f * density).toInt()

        val originalPaddingLeft = bubble.paddingLeft
        val originalPaddingTop = bubble.paddingTop
        val originalPaddingRight = bubble.paddingRight
        val originalPaddingBottom = bubble.paddingBottom
        val originalLayoutParams = bubble.layoutParams as? android.widget.LinearLayout.LayoutParams
        val contentVisibleWidth = (visibleWidth - originalPaddingLeft - originalPaddingRight).coerceAtLeast((160f * density).toInt())
        val tableBubbleBackgroundColor = assistantTextBubbleBackgroundColor
        val tableBubbleBackground = android.graphics.drawable.GradientDrawable().apply {
            setColor(tableBubbleBackgroundColor)
            cornerRadius = chatTextBubbleCornerRadius
        }

        bubble.background = null
        bubble.setPadding(0, 0, 0, 0)
        bubble.layoutParams = android.widget.LinearLayout.LayoutParams(
            android.widget.LinearLayout.LayoutParams.WRAP_CONTENT,
            android.widget.LinearLayout.LayoutParams.WRAP_CONTENT
        )

        val wrapper = android.widget.LinearLayout(context).apply {
            orientation = android.widget.LinearLayout.VERTICAL
            background = tableBubbleBackground
            setPadding(originalPaddingLeft, originalPaddingTop, originalPaddingRight, originalPaddingBottom)
            layoutParams = originalLayoutParams?.let {
                android.widget.LinearLayout.LayoutParams(it).apply {
                    width = visibleWidth
                }
            }
                ?: android.widget.LinearLayout.LayoutParams(
                    visibleWidth,
                    android.widget.LinearLayout.LayoutParams.WRAP_CONTENT
                )
        }

        var hasPrimaryTextAttached = false
        var hasAnyBlockAttached = false
        var previousBlockWasSeparator = false

        for (block in blocks) {
            when (block) {
                is MarkdownTableParser.Block.Text -> {
                    if (block.markdown.isBlank()) continue
                    val segments = splitTextBlockByTableSeparators(block.markdown)
                    for (segment in segments) {
                        if (segment.isSeparator) {
                            val divider = createTableSeparatorView()
                            val dividerLp = android.widget.LinearLayout.LayoutParams(
                                android.widget.LinearLayout.LayoutParams.MATCH_PARENT,
                                android.widget.LinearLayout.LayoutParams.WRAP_CONTENT
                            ).apply {
                                if (hasAnyBlockAttached) topMargin = dividerVerticalMargin
                                bottomMargin = dividerVerticalMargin
                            }
                            wrapper.addView(divider, dividerLp)
                            hasAnyBlockAttached = true
                            previousBlockWasSeparator = true
                            continue
                        }
                        if (segment.markdown.isBlank()) continue
                        val textView = if (!hasPrimaryTextAttached) {
                            bubble.also {
                                setupMarkwonWithAppLinks(it, segment.markdown, markwon)
                            }
                        } else {
                            android.widget.TextView(context).apply {
                                textSize = bubble.textSize / resources.displayMetrics.scaledDensity
                                setTextColor(bubble.currentTextColor)
                                maxWidth = contentVisibleWidth
                                minWidth = 0
                                setTextIsSelectable(true)
                                setupMarkwonWithAppLinks(this, segment.markdown, markwon)
                            }
                        }
                        val textLp = android.widget.LinearLayout.LayoutParams(
                            android.widget.LinearLayout.LayoutParams.WRAP_CONTENT,
                            android.widget.LinearLayout.LayoutParams.WRAP_CONTENT
                        ).apply {
                            if (hasAnyBlockAttached && !previousBlockWasSeparator) topMargin = blockSpacing
                        }
                        wrapper.addView(textView, textLp)
                        hasPrimaryTextAttached = true
                        hasAnyBlockAttached = true
                        previousBlockWasSeparator = false
                    }
                }
                is MarkdownTableParser.Block.Table -> {
                    val tableView = createHorizontalScrollableTableView(block, contentVisibleWidth)
                    val tableLp = android.widget.LinearLayout.LayoutParams(
                        contentVisibleWidth,
                        android.widget.LinearLayout.LayoutParams.WRAP_CONTENT
                    ).apply {
                        if (hasAnyBlockAttached && !previousBlockWasSeparator) topMargin = blockSpacing
                    }
                    wrapper.addView(tableView, tableLp)
                    hasAnyBlockAttached = true
                    previousBlockWasSeparator = false
                }
            }
        }

        if (!hasAnyBlockAttached) {
            setupMarkwonWithAppLinks(bubble, markdownMessage, markwon)
            return bubble
        }

        return wrapper
    }

    private data class TableAwareTextSegment(
        val markdown: String,
        val isSeparator: Boolean
    )

    private fun splitTextBlockByTableSeparators(markdown: String): List<TableAwareTextSegment> {
        val segments = mutableListOf<TableAwareTextSegment>()
        val buffer = mutableListOf<String>()

        fun flushBuffer() {
            if (buffer.isEmpty()) return
            val text = buffer.joinToString("\n").trim('\n')
            if (text.isNotBlank()) {
                segments.add(TableAwareTextSegment(markdown = text, isSeparator = false))
            }
            buffer.clear()
        }

        markdown.lines().forEach { line ->
            if (isTableSeparatorTextBlock(line.trim())) {
                flushBuffer()
                segments.add(TableAwareTextSegment(markdown = line, isSeparator = true))
            } else {
                buffer.add(line)
            }
        }
        flushBuffer()
        return segments
    }

    private fun isTableSeparatorTextBlock(markdown: String): Boolean {
        val trimmed = markdown.trim()
        if (trimmed.isEmpty()) return false
        // 兼容目前文本分隔符以及标准 Markdown 分隔线写法
        return Regex("^(?:[-*_]{3,}|[─—]{3,})$").matches(trimmed)
    }

    private fun createTableSeparatorView(): android.view.View {
        val density = resources.displayMetrics.density
        val heightPx = (1f * density).toInt().coerceAtLeast(1)
        return android.view.View(requireContext()).apply {
            layoutParams = android.widget.LinearLayout.LayoutParams(
                android.widget.LinearLayout.LayoutParams.MATCH_PARENT,
                heightPx
            )
            setBackgroundColor(0x66000000)
        }
    }

    private fun attachUnifiedBubbleLongPressMenu(
        rootView: android.view.View,
        primaryTextView: android.widget.TextView?,
        fullMessage: String,
        timestamp: Long
    ) {
        bindTouchTrackingRecursively(rootView)
        val handler = android.view.View.OnLongClickListener { pressedView ->
            if (suppressUnifiedBubbleLongPress) {
                return@OnLongClickListener false
            }
            showUnifiedBubbleLongPressMenu(
                anchor = pressedView,
                primaryTextView = primaryTextView,
                fullMessage = fullMessage,
                timestamp = timestamp
            )
            true
        }
        bindLongPressRecursively(rootView, handler)
    }

    private fun bindTouchTrackingRecursively(view: android.view.View) {
        if (view !is android.widget.TextView) {
            view.setOnTouchListener { _, event ->
                recordBubbleTouch(event)
                false
            }
        }
        if (view is android.view.ViewGroup) {
            for (i in 0 until view.childCount) {
                bindTouchTrackingRecursively(view.getChildAt(i))
            }
        }
    }

    private fun recordBubbleTouch(event: android.view.MotionEvent) {
        when (event.actionMasked) {
            android.view.MotionEvent.ACTION_DOWN,
            android.view.MotionEvent.ACTION_MOVE,
            android.view.MotionEvent.ACTION_UP -> {
                lastBubbleTouchRawX = event.rawX.toInt()
                lastBubbleTouchRawY = event.rawY.toInt()
                lastBubbleTouchTimestamp = android.os.SystemClock.uptimeMillis()
            }
        }
    }

    private fun bindLongPressRecursively(
        view: android.view.View,
        handler: android.view.View.OnLongClickListener
    ) {
        view.isLongClickable = true
        view.setOnLongClickListener(handler)
        if (view is android.view.ViewGroup) {
            for (i in 0 until view.childCount) {
                bindLongPressRecursively(view.getChildAt(i), handler)
            }
        }
    }

    private fun showUnifiedBubbleLongPressMenu(
        anchor: android.view.View,
        primaryTextView: android.widget.TextView?,
        fullMessage: String,
        timestamp: Long
    ) {
        val context = requireContext()
        val density = resources.displayMetrics.density
        val menuCornerRadius = 10f * density
        val menuPaddingV = (4f * density).toInt()
        val menuItemPaddingH = (14f * density).toInt()
        val menuItemPaddingV = (10f * density).toInt()
        val separatorHeight = (1f * density).toInt().coerceAtLeast(1)
        val separatorColor = 0x14000000

        val menuContainer = android.widget.LinearLayout(context).apply {
            orientation = android.widget.LinearLayout.VERTICAL
            background = android.graphics.drawable.GradientDrawable().apply {
                setColor(0xFFFDFDFD.toInt())
                cornerRadius = menuCornerRadius
                setStroke((1f * density).toInt().coerceAtLeast(1), 0x1F000000)
            }
            setPadding(0, menuPaddingV, 0, menuPaddingV)
            elevation = 8f * density
        }

        lateinit var popupWindow: android.widget.PopupWindow

        BubbleLongPressAction.values().forEachIndexed { index, action ->
            val itemView = android.widget.TextView(context).apply {
                text = action.label
                textSize = 14f
                setTextColor(0xFF222222.toInt())
                setPadding(menuItemPaddingH, menuItemPaddingV, menuItemPaddingH, menuItemPaddingV)
                isClickable = true
                isFocusable = true
                setOnClickListener {
                    popupWindow.dismiss()
                    when (action) {
                        BubbleLongPressAction.COPY -> copyBubbleMessage(fullMessage)
                        BubbleLongPressAction.SELECT -> openBubbleTextSelection(primaryTextView)
                        BubbleLongPressAction.SHARE -> shareBubbleMessage(fullMessage)
                        BubbleLongPressAction.MULTI_SELECT -> enterMultiSelectMode(timestamp)
                        BubbleLongPressAction.DELETE -> deleteMessageByTimestamp(timestamp)
                    }
                }
            }
            menuContainer.addView(
                itemView,
                android.widget.LinearLayout.LayoutParams(
                    android.widget.LinearLayout.LayoutParams.WRAP_CONTENT,
                    android.widget.LinearLayout.LayoutParams.WRAP_CONTENT
                )
            )
            if (index < BubbleLongPressAction.values().lastIndex) {
                menuContainer.addView(
                    android.view.View(context).apply {
                        setBackgroundColor(separatorColor)
                    },
                    android.widget.LinearLayout.LayoutParams(
                        android.widget.LinearLayout.LayoutParams.MATCH_PARENT,
                        separatorHeight
                    )
                )
            }
        }

        popupWindow = android.widget.PopupWindow(
            menuContainer,
            android.widget.LinearLayout.LayoutParams.WRAP_CONTENT,
            android.widget.LinearLayout.LayoutParams.WRAP_CONTENT,
            true
        ).apply {
            isOutsideTouchable = true
            setBackgroundDrawable(android.graphics.drawable.ColorDrawable(android.graphics.Color.TRANSPARENT))
        }

        menuContainer.measure(
            android.view.View.MeasureSpec.makeMeasureSpec(resources.displayMetrics.widthPixels, android.view.View.MeasureSpec.AT_MOST),
            android.view.View.MeasureSpec.makeMeasureSpec(resources.displayMetrics.heightPixels, android.view.View.MeasureSpec.AT_MOST)
        )
        val popupWidth = menuContainer.measuredWidth
        val popupHeight = menuContainer.measuredHeight

        val screenWidth = resources.displayMetrics.widthPixels
        val screenHeight = resources.displayMetrics.heightPixels
        val safeMargin = (8f * density).toInt()
        val location = IntArray(2)
        anchor.getLocationOnScreen(location)
        val anchorLeft = location[0]
        val anchorTop = location[1]
        val anchorRight = anchorLeft + anchor.width
        val anchorBottom = anchorTop + anchor.height
        val now = android.os.SystemClock.uptimeMillis()
        val hasRecentTouchPoint = now - lastBubbleTouchTimestamp <= 2000L &&
            lastBubbleTouchRawX in 0..screenWidth &&
            lastBubbleTouchRawY in 0..screenHeight &&
            lastBubbleTouchRawX in anchorLeft..anchorRight &&
            lastBubbleTouchRawY in anchorTop..anchorBottom
        val anchorCenterX = if (hasRecentTouchPoint) lastBubbleTouchRawX else location[0] + anchor.width / 2
        val anchorTopY = if (hasRecentTouchPoint) lastBubbleTouchRawY else location[1]

        var targetX = anchorCenterX - popupWidth / 2
        var targetY = anchorTopY - popupHeight - (6f * density).toInt()
        if (targetY < safeMargin) {
            targetY = location[1] + anchor.height + (6f * density).toInt()
        }

        targetX = targetX.coerceIn(safeMargin, (screenWidth - popupWidth - safeMargin).coerceAtLeast(safeMargin))
        targetY = targetY.coerceIn(safeMargin, (screenHeight - popupHeight - safeMargin).coerceAtLeast(safeMargin))

        val hostView = _binding?.root ?: view ?: anchor
        popupWindow.showAtLocation(hostView, android.view.Gravity.NO_GRAVITY, targetX, targetY)
    }

    private fun copyBubbleMessage(message: String) {
        val clipboard = requireContext().getSystemService(Context.CLIPBOARD_SERVICE) as? ClipboardManager
        clipboard?.setPrimaryClip(ClipData.newPlainText("消息", message))
        Toast.makeText(requireContext(), "已复制", Toast.LENGTH_SHORT).show()
    }

    private fun shareBubbleMessage(message: String) {
        if (message.isBlank()) return
        showBubbleShareEntrySheet(message)
    }

    private fun openBubbleTextSelection(primaryTextView: android.widget.TextView?) {
        if (primaryTextView == null) {
            Toast.makeText(requireContext(), "当前内容不可选择", Toast.LENGTH_SHORT).show()
            return
        }
        suppressUnifiedBubbleLongPress = true
        primaryTextView.post {
            try {
                primaryTextView.requestFocus()
                primaryTextView.performLongClick()
            } finally {
                primaryTextView.post {
                    suppressUnifiedBubbleLongPress = false
                }
            }
        }
    }

    private fun showBubbleShareEntrySheet(message: String) {
        if (!isAdded) return
        val context = requireContext()
        val density = resources.displayMetrics.density

        val container = android.widget.LinearLayout(context).apply {
            orientation = android.widget.LinearLayout.HORIZONTAL
            setPadding((16f * density).toInt(), (12f * density).toInt(), (16f * density).toInt(), (18f * density).toInt())
            background = android.graphics.drawable.GradientDrawable().apply {
                setColor(0xFFFFFFFF.toInt())
                cornerRadius = 16f * density
            }
        }

        fun createActionButton(label: String): android.widget.Button {
            return android.widget.Button(context).apply {
                text = label
                textSize = 15f
                isAllCaps = false
                background = android.graphics.drawable.GradientDrawable().apply {
                    setColor(0xFFF7F7F7.toInt())
                    cornerRadius = 22f * density
                    setStroke((1f * density).toInt().coerceAtLeast(1), 0x33000000)
                }
                setTextColor(0xFF222222.toInt())
                setPadding((18f * density).toInt(), (10f * density).toInt(), (18f * density).toInt(), (10f * density).toInt())
            }
        }

        val copyButton = createActionButton("复制文本")
        val generateButton = createActionButton("生成分享图").apply {
            background = android.graphics.drawable.GradientDrawable().apply {
                setColor(0xFF3B6DFF.toInt())
                cornerRadius = 22f * density
            }
            setTextColor(0xFFFFFFFF.toInt())
        }

        container.addView(
            copyButton,
            android.widget.LinearLayout.LayoutParams(0, android.widget.LinearLayout.LayoutParams.WRAP_CONTENT, 1f).apply {
                marginEnd = (8f * density).toInt()
            }
        )
        container.addView(
            generateButton,
            android.widget.LinearLayout.LayoutParams(0, android.widget.LinearLayout.LayoutParams.WRAP_CONTENT, 1f)
        )

        val dialog = Dialog(context).apply {
            setContentView(container)
            setCancelable(true)
            setCanceledOnTouchOutside(true)
        }
        dialog.window?.apply {
            setBackgroundDrawable(android.graphics.drawable.ColorDrawable(android.graphics.Color.TRANSPARENT))
            setLayout(android.view.ViewGroup.LayoutParams.MATCH_PARENT, android.view.ViewGroup.LayoutParams.WRAP_CONTENT)
            setGravity(android.view.Gravity.BOTTOM)
            attributes = attributes.apply {
                y = (12f * density).toInt()
            }
        }

        copyButton.setOnClickListener {
            dialog.dismiss()
            copyBubbleMessage(message)
        }
        generateButton.setOnClickListener {
            dialog.dismiss()
            showGeneratedShareImagePreview(message)
        }

        dialog.show()
    }

    private fun showGeneratedShareImagePreview(message: String) {
        showGeneratedShareImagePreviewInternal {
            generateShareBitmapFromMessage(message)
        }
    }

    private fun showGeneratedShareImagePreviewFromConversation(selectedItems: List<ChatItem>) {
        showGeneratedShareImagePreviewInternal {
            generateShareBitmapFromConversationItems(selectedItems)
        }
    }

    private fun showGeneratedShareImagePreviewInternal(
        bitmapGenerator: () -> android.graphics.Bitmap
    ) {
        if (!isAdded) return
        val context = requireContext()
        val density = resources.displayMetrics.density
        val bitmap = try {
            bitmapGenerator()
        } catch (e: Exception) {
            Log.e(TAG, "生成分享图失败: ${e.message}", e)
            Toast.makeText(context, "生成分享图失败", Toast.LENGTH_SHORT).show()
            return
        }

        val root = android.widget.LinearLayout(context).apply {
            orientation = android.widget.LinearLayout.VERTICAL
            setBackgroundColor(0xFFF5F5F5.toInt())
        }

        val previewScroll = android.widget.ScrollView(context).apply {
            isFillViewport = true
        }
        val previewHolder = android.widget.LinearLayout(context).apply {
            orientation = android.widget.LinearLayout.VERTICAL
            gravity = android.view.Gravity.CENTER_HORIZONTAL
            setPadding((12f * density).toInt(), (16f * density).toInt(), (12f * density).toInt(), (16f * density).toInt())
        }
        val imageView = android.widget.ImageView(context).apply {
            setImageBitmap(bitmap)
            adjustViewBounds = true
            scaleType = android.widget.ImageView.ScaleType.FIT_CENTER
            background = android.graphics.drawable.GradientDrawable().apply {
                setColor(0xFFFFFFFF.toInt())
                cornerRadius = 14f * density
            }
            setPadding((8f * density).toInt(), (8f * density).toInt(), (8f * density).toInt(), (8f * density).toInt())
        }
        previewHolder.addView(
            imageView,
            android.widget.LinearLayout.LayoutParams(
                android.widget.LinearLayout.LayoutParams.MATCH_PARENT,
                android.widget.LinearLayout.LayoutParams.WRAP_CONTENT
            )
        )
        previewScroll.addView(
            previewHolder,
            android.widget.FrameLayout.LayoutParams(
                android.widget.FrameLayout.LayoutParams.MATCH_PARENT,
                android.widget.FrameLayout.LayoutParams.WRAP_CONTENT
            )
        )
        root.addView(
            previewScroll,
            android.widget.LinearLayout.LayoutParams(
                android.widget.LinearLayout.LayoutParams.MATCH_PARENT,
                0,
                1f
            )
        )

        val bottomBar = android.widget.LinearLayout(context).apply {
            orientation = android.widget.LinearLayout.HORIZONTAL
            setPadding((12f * density).toInt(), (10f * density).toInt(), (12f * density).toInt(), (14f * density).toInt())
            setBackgroundColor(0xFFFFFFFF.toInt())
        }

        fun createBottomActionButton(label: String, filled: Boolean): android.widget.Button {
            return android.widget.Button(context).apply {
                text = label
                textSize = 15f
                isAllCaps = false
                background = android.graphics.drawable.GradientDrawable().apply {
                    setColor(if (filled) 0xFF3B6DFF.toInt() else 0xFFF7F7F7.toInt())
                    cornerRadius = 22f * density
                    if (!filled) {
                        setStroke((1f * density).toInt().coerceAtLeast(1), 0x33000000)
                    }
                }
                setTextColor(if (filled) 0xFFFFFFFF.toInt() else 0xFF222222.toInt())
                setPadding((16f * density).toInt(), (10f * density).toInt(), (16f * density).toInt(), (10f * density).toInt())
            }
        }

        val shareButton = createBottomActionButton("分享", filled = true)
        val saveButton = createBottomActionButton("保存到相册", filled = false)

        bottomBar.addView(
            shareButton,
            android.widget.LinearLayout.LayoutParams(0, android.widget.LinearLayout.LayoutParams.WRAP_CONTENT, 1f).apply {
                marginEnd = (8f * density).toInt()
            }
        )
        bottomBar.addView(
            saveButton,
            android.widget.LinearLayout.LayoutParams(0, android.widget.LinearLayout.LayoutParams.WRAP_CONTENT, 1f)
        )

        root.addView(
            bottomBar,
            android.widget.LinearLayout.LayoutParams(
                android.widget.LinearLayout.LayoutParams.MATCH_PARENT,
                android.widget.LinearLayout.LayoutParams.WRAP_CONTENT
            )
        )

        val dialog = Dialog(context).apply {
            setContentView(root)
            setCancelable(true)
            setCanceledOnTouchOutside(true)
            setOnDismissListener {
                if (!bitmap.isRecycled) {
                    bitmap.recycle()
                }
            }
        }
        dialog.window?.apply {
            setBackgroundDrawable(android.graphics.drawable.ColorDrawable(0xCC000000.toInt()))
            setLayout(android.view.ViewGroup.LayoutParams.MATCH_PARENT, android.view.ViewGroup.LayoutParams.MATCH_PARENT)
        }

        shareButton.setOnClickListener {
            shareGeneratedBitmap(bitmap)
        }
        saveButton.setOnClickListener {
            val savedUri = ScreenshotHelper.saveBitmapToGallery(
                context = context,
                bitmap = bitmap,
                displayName = "TopoClaw_Share_${System.currentTimeMillis()}.jpg",
                saveToScreenshotsFolder = true
            )
            Toast.makeText(context, if (savedUri != null) "已保存到相册" else "保存失败", Toast.LENGTH_SHORT).show()
        }

        dialog.show()
    }

    private fun generateShareBitmapFromMessage(message: String): android.graphics.Bitmap {
        val context = requireContext()
        val density = resources.displayMetrics.density
        val screenWidth = resources.displayMetrics.widthPixels
        val contentWidth = (screenWidth - (32f * density).toInt()).coerceAtLeast((260f * density).toInt())

        val root = android.widget.LinearLayout(context).apply {
            orientation = android.widget.LinearLayout.VERTICAL
            setBackgroundColor(0xFFF5F5F5.toInt())
            setPadding((16f * density).toInt(), (16f * density).toInt(), (16f * density).toInt(), (16f * density).toInt())
        }

        val card = android.widget.LinearLayout(context).apply {
            orientation = android.widget.LinearLayout.VERTICAL
            background = android.graphics.drawable.GradientDrawable().apply {
                setColor(0xFFFFFFFF.toInt())
                cornerRadius = 14f * density
            }
            setPadding((16f * density).toInt(), (14f * density).toInt(), (16f * density).toInt(), (14f * density).toInt())
        }

        val title = android.widget.TextView(context).apply {
            text = "TopoClaw"
            textSize = 14f
            setTextColor(0xFF666666.toInt())
        }
        val divider = android.view.View(context).apply {
            setBackgroundColor(0x1F000000)
        }
        val content = android.widget.TextView(context).apply {
            textSize = 16f
            setTextColor(0xFF1F1F1F.toInt())
            setLineSpacing(2f * density, 1.1f)
        }
        val markdownMessage = convertToMarkdown(filterSOPFromMessage(message))
        MarkdownRenderer.createMarkwon(context).setMarkdown(content, markdownMessage)

        card.addView(
            title,
            android.widget.LinearLayout.LayoutParams(
                android.widget.LinearLayout.LayoutParams.MATCH_PARENT,
                android.widget.LinearLayout.LayoutParams.WRAP_CONTENT
            )
        )
        card.addView(
            divider,
            android.widget.LinearLayout.LayoutParams(
                android.widget.LinearLayout.LayoutParams.MATCH_PARENT,
                (1f * density).toInt().coerceAtLeast(1)
            ).apply {
                topMargin = (8f * density).toInt()
                bottomMargin = (10f * density).toInt()
            }
        )
        card.addView(
            content,
            android.widget.LinearLayout.LayoutParams(
                android.widget.LinearLayout.LayoutParams.MATCH_PARENT,
                android.widget.LinearLayout.LayoutParams.WRAP_CONTENT
            )
        )

        root.addView(
            card,
            android.widget.LinearLayout.LayoutParams(
                android.widget.LinearLayout.LayoutParams.MATCH_PARENT,
                android.widget.LinearLayout.LayoutParams.WRAP_CONTENT
            )
        )

        val widthSpec = android.view.View.MeasureSpec.makeMeasureSpec(contentWidth, android.view.View.MeasureSpec.EXACTLY)
        val heightSpec = android.view.View.MeasureSpec.makeMeasureSpec(0, android.view.View.MeasureSpec.UNSPECIFIED)
        root.measure(widthSpec, heightSpec)
        root.layout(0, 0, contentWidth, root.measuredHeight)

        val bitmap = android.graphics.Bitmap.createBitmap(
            contentWidth,
            root.measuredHeight.coerceAtLeast(1),
            android.graphics.Bitmap.Config.ARGB_8888
        )
        val canvas = android.graphics.Canvas(bitmap)
        root.draw(canvas)
        return bitmap
    }

    private fun generateShareBitmapFromConversationItems(selectedItems: List<ChatItem>): android.graphics.Bitmap {
        val context = requireContext()
        val density = resources.displayMetrics.density
        val screenWidth = resources.displayMetrics.widthPixels
        val contentWidth = (screenWidth - (24f * density).toInt()).coerceAtLeast((280f * density).toInt())
        val markwon = MarkdownRenderer.createMarkwon(context)

        val root = android.widget.LinearLayout(context).apply {
            orientation = android.widget.LinearLayout.VERTICAL
            setBackgroundColor(0xFFEDEDED.toInt())
            setPadding((10f * density).toInt(), (10f * density).toInt(), (10f * density).toInt(), (10f * density).toInt())
        }

        val chatCard = android.widget.LinearLayout(context).apply {
            orientation = android.widget.LinearLayout.VERTICAL
            background = android.graphics.drawable.GradientDrawable().apply {
                setColor(0xFFF5F5F5.toInt())
                cornerRadius = 12f * density
            }
            setPadding((8f * density).toInt(), (10f * density).toInt(), (8f * density).toInt(), (10f * density).toInt())
        }

        val title = android.widget.TextView(context).apply {
            text = currentConversation?.name?.takeIf { it.isNotBlank() } ?: "会话分享"
            textSize = 14f
            gravity = android.view.Gravity.CENTER
            setTextColor(0xFF666666.toInt())
            setPadding(0, 0, 0, (8f * density).toInt())
        }
        chatCard.addView(
            title,
            android.widget.LinearLayout.LayoutParams(
                android.widget.LinearLayout.LayoutParams.MATCH_PARENT,
                android.widget.LinearLayout.LayoutParams.WRAP_CONTENT
            )
        )

        selectedItems.forEach { item ->
            val timestamp = when (item) {
                is ChatItem.Message -> item.timestamp
                is ChatItem.ImageMessage -> item.timestamp
                else -> null
            } ?: return@forEach

            val timeView = android.widget.TextView(context).apply {
                text = formatTime(timestamp)
                textSize = 11f
                gravity = android.view.Gravity.CENTER
                setTextColor(0xFF9A9A9A.toInt())
                setPadding(0, (4f * density).toInt(), 0, (4f * density).toInt())
            }
            chatCard.addView(
                timeView,
                android.widget.LinearLayout.LayoutParams(
                    android.widget.LinearLayout.LayoutParams.MATCH_PARENT,
                    android.widget.LinearLayout.LayoutParams.WRAP_CONTENT
                )
            )

            val bubbleRow = when (item) {
                is ChatItem.Message -> {
                    createMessageBubbleForAdapter(
                        sender = item.sender,
                        message = item.message,
                        isUserMessage = item.isUserMessage,
                        isComplete = item.isComplete,
                        isAnswer = item.isAnswer,
                        senderImei = item.senderImei,
                        markwon = markwon,
                        onAvatarClick = {},
                        timestamp = item.timestamp,
                        recommendations = item.recommendations
                    )
                }
                is ChatItem.ImageMessage -> {
                    createConversationStyleShareImageRow(item)
                }
                else -> null
            } ?: return@forEach

            chatCard.addView(
                bubbleRow,
                android.widget.LinearLayout.LayoutParams(
                    android.widget.LinearLayout.LayoutParams.MATCH_PARENT,
                    android.widget.LinearLayout.LayoutParams.WRAP_CONTENT
                ).apply {
                    bottomMargin = (2f * density).toInt()
                }
            )
        }

        root.addView(
            chatCard,
            android.widget.LinearLayout.LayoutParams(
                android.widget.LinearLayout.LayoutParams.MATCH_PARENT,
                android.widget.LinearLayout.LayoutParams.WRAP_CONTENT
            )
        )

        val widthSpec = android.view.View.MeasureSpec.makeMeasureSpec(contentWidth, android.view.View.MeasureSpec.EXACTLY)
        val heightSpec = android.view.View.MeasureSpec.makeMeasureSpec(0, android.view.View.MeasureSpec.UNSPECIFIED)
        root.measure(widthSpec, heightSpec)
        root.layout(0, 0, contentWidth, root.measuredHeight)

        val bitmap = android.graphics.Bitmap.createBitmap(
            contentWidth,
            root.measuredHeight.coerceAtLeast(1),
            android.graphics.Bitmap.Config.ARGB_8888
        )
        val canvas = android.graphics.Canvas(bitmap)
        root.draw(canvas)
        return bitmap
    }

    private fun createConversationStyleShareImageRow(item: ChatItem.ImageMessage): android.view.View {
        val context = requireContext()
        val density = resources.displayMetrics.density
        val avatarSize = (34f * density).toInt()
        val avatarMargin = (8f * density).toInt()
        val imageMaxHeight = (180f * density).toInt()

        val row = android.widget.LinearLayout(context).apply {
            orientation = android.widget.LinearLayout.HORIZONTAL
            gravity = if (item.isUserMessage) android.view.Gravity.END or android.view.Gravity.TOP else android.view.Gravity.START or android.view.Gravity.TOP
            layoutParams = android.widget.LinearLayout.LayoutParams(
                android.widget.LinearLayout.LayoutParams.MATCH_PARENT,
                android.widget.LinearLayout.LayoutParams.WRAP_CONTENT
            )
        }

        val content = android.widget.LinearLayout(context).apply {
            orientation = android.widget.LinearLayout.VERTICAL
            layoutParams = android.widget.LinearLayout.LayoutParams(
                android.widget.LinearLayout.LayoutParams.WRAP_CONTENT,
                android.widget.LinearLayout.LayoutParams.WRAP_CONTENT
            )
        }

        val imageBitmap = loadImageThumbnail(item.imagePath, imageMaxHeight)
        val fallbackWidth = (140f * density).toInt()
        val imageWidth = imageBitmap?.width ?: fallbackWidth
        val imageHeight = imageBitmap?.height ?: imageMaxHeight
        val imageBubble = android.widget.ImageView(context).apply {
            layoutParams = android.widget.LinearLayout.LayoutParams(imageWidth, imageHeight)
            scaleType = android.widget.ImageView.ScaleType.CENTER_CROP
            setImageBitmap(imageBitmap)
            if (imageBitmap == null) {
                setBackgroundColor(0xFFD8D8D8.toInt())
            }
            val cornerRadius = 14f * density
            background = android.graphics.drawable.GradientDrawable().apply {
                setColor(0xFFEDEDED.toInt())
                this.cornerRadius = cornerRadius
            }
            outlineProvider = object : android.view.ViewOutlineProvider() {
                override fun getOutline(view: android.view.View, outline: android.graphics.Outline) {
                    outline.setRoundRect(0, 0, view.width, view.height, cornerRadius)
                }
            }
            clipToOutline = true
        }
        content.addView(imageBubble)

        val caption = item.query.trim()
        if (caption.isNotBlank() && !ChatConstants.isImageOnlyPlaceholderCaption(caption)) {
            val bubbleColor = if (item.isUserMessage) 0xFF95EC69.toInt() else assistantTextBubbleBackgroundColor
            val captionView = android.widget.TextView(context).apply {
                text = caption
                textSize = 15f
                setTextColor(0xFF111111.toInt())
                setPadding((10f * density).toInt(), (8f * density).toInt(), (10f * density).toInt(), (8f * density).toInt())
                maxWidth = (resources.displayMetrics.widthPixels * 0.72f).toInt()
                background = android.graphics.drawable.GradientDrawable().apply {
                    setColor(bubbleColor)
                    cornerRadius = 14f * density
                }
                layoutParams = android.widget.LinearLayout.LayoutParams(
                    android.widget.LinearLayout.LayoutParams.WRAP_CONTENT,
                    android.widget.LinearLayout.LayoutParams.WRAP_CONTENT
                ).apply {
                    topMargin = (6f * density).toInt()
                }
            }
            content.addView(captionView)
        }

        val avatarView = android.widget.ImageView(context).apply {
            layoutParams = android.widget.LinearLayout.LayoutParams(avatarSize, avatarSize).apply {
                if (item.isUserMessage) {
                    marginStart = avatarMargin
                } else {
                    marginEnd = avatarMargin
                }
            }
            scaleType = android.widget.ImageView.ScaleType.CENTER_CROP
            outlineProvider = object : android.view.ViewOutlineProvider() {
                override fun getOutline(view: android.view.View, outline: android.graphics.Outline) {
                    outline.setOval(0, 0, view.width, view.height)
                }
            }
            clipToOutline = true
            background = ContextCompat.getDrawable(context, R.drawable.circle_background)
        }
        if (item.isUserMessage) {
            val userProfile = ProfileManager.loadProfileLocally(context)
            AvatarCacheManager.loadBase64Avatar(
                context = context,
                imageView = avatarView,
                base64String = userProfile?.avatar,
                defaultResId = R.drawable.ic_person,
                cacheKey = "share_user_avatar"
            )
        } else {
            avatarView.setImageResource(R.drawable.ic_assistant_avatar)
        }

        if (item.isUserMessage) {
            row.addView(content)
            row.addView(avatarView)
        } else {
            row.addView(avatarView)
            row.addView(content)
        }
        return row
    }

    private fun shareGeneratedBitmap(bitmap: android.graphics.Bitmap) {
        if (!isAdded) return
        try {
            val context = requireContext()
            val cacheDir = java.io.File(context.cacheDir, "share_images").apply { mkdirs() }
            val outFile = java.io.File(cacheDir, "share_${System.currentTimeMillis()}.jpg")
            outFile.outputStream().use { stream ->
                bitmap.compress(android.graphics.Bitmap.CompressFormat.JPEG, 92, stream)
                stream.flush()
            }
            val uri = FileProvider.getUriForFile(
                context,
                "${context.packageName}.fileprovider",
                outFile
            )
            val shareIntent = Intent(Intent.ACTION_SEND).apply {
                type = "image/jpeg"
                putExtra(Intent.EXTRA_STREAM, uri)
                addFlags(Intent.FLAG_GRANT_READ_URI_PERMISSION)
            }
            startActivity(Intent.createChooser(shareIntent, "分享图片"))
        } catch (e: Exception) {
            Log.e(TAG, "分享生成图片失败: ${e.message}", e)
            Toast.makeText(requireContext(), "分享失败", Toast.LENGTH_SHORT).show()
        }
    }

    private fun createHorizontalScrollableTableView(
        table: MarkdownTableParser.Block.Table,
        contentVisibleWidth: Int
    ): android.view.View {
        val context = requireContext()
        val density = resources.displayMetrics.density
        val strokeColor = 0xFF9FB0BF.toInt()
        val headerBackgroundColor = 0xFFF2F5F8.toInt()
        val rowBackgroundColor = assistantTextBubbleBackgroundColor
        val tableCornerRadius = 6f * density
        val outerStrokeWidth = (1f * density).toInt().coerceAtLeast(1)
        val cellHorizontalPadding = (10f * density).toInt()
        val cellVerticalPadding = (6f * density).toInt()
        val cellMinWidth = (96f * density).toInt()
        val textSizeSp = 13f

        fun cellBackground(fillColor: Int): android.graphics.drawable.GradientDrawable {
            return android.graphics.drawable.GradientDrawable().apply {
                setColor(fillColor)
                setStroke((1f * density).toInt().coerceAtLeast(1), strokeColor)
            }
        }

        fun createCell(text: String, isHeader: Boolean): android.widget.TextView {
            return android.widget.TextView(context).apply {
                this.text = text
                textSize = textSizeSp
                if (isHeader) setTypeface(typeface, android.graphics.Typeface.BOLD)
                setTextColor(0xFF222222.toInt())
                setPadding(cellHorizontalPadding, cellVerticalPadding, cellHorizontalPadding, cellVerticalPadding)
                minWidth = cellMinWidth
                isSingleLine = true
                ellipsize = android.text.TextUtils.TruncateAt.END
                background = cellBackground(if (isHeader) headerBackgroundColor else rowBackgroundColor)
                setOnTouchListener { _, event ->
                    recordBubbleTouch(event)
                    false
                }
            }
        }

        val tableLayout = android.widget.TableLayout(context).apply {
            isShrinkAllColumns = false
            isStretchAllColumns = false
            layoutParams = android.widget.TableLayout.LayoutParams(
                android.widget.TableLayout.LayoutParams.WRAP_CONTENT,
                android.widget.TableLayout.LayoutParams.WRAP_CONTENT
            )
        }

        val headerRow = android.widget.TableRow(context)
        table.headers.forEach { header ->
            headerRow.addView(createCell(header, isHeader = true))
        }
        tableLayout.addView(headerRow)

        table.rows.forEach { row ->
            val rowView = android.widget.TableRow(context)
            val fullRow = if (row.size < table.headers.size) {
                row + List(table.headers.size - row.size) { "" }
            } else {
                row
            }
            fullRow.take(table.headers.size).forEach { cell ->
                rowView.addView(createCell(cell, isHeader = false))
            }
            tableLayout.addView(rowView)
        }

        val tableContentClip = android.widget.FrameLayout(context).apply {
            layoutParams = android.widget.FrameLayout.LayoutParams(
                android.widget.FrameLayout.LayoutParams.WRAP_CONTENT,
                android.widget.FrameLayout.LayoutParams.WRAP_CONTENT
            )
            background = android.graphics.drawable.GradientDrawable().apply {
                setColor(rowBackgroundColor)
                cornerRadius = (tableCornerRadius - outerStrokeWidth).coerceAtLeast(0f)
            }
            clipToOutline = true
            addView(tableLayout)
        }

        val tableClipContainer = android.widget.FrameLayout(context).apply {
            layoutParams = android.widget.FrameLayout.LayoutParams(
                android.widget.FrameLayout.LayoutParams.WRAP_CONTENT,
                android.widget.FrameLayout.LayoutParams.WRAP_CONTENT
            )
            background = android.graphics.drawable.GradientDrawable().apply {
                setColor(rowBackgroundColor)
                cornerRadius = tableCornerRadius
                setStroke(outerStrokeWidth, strokeColor)
            }
            setPadding(outerStrokeWidth, outerStrokeWidth, outerStrokeWidth, outerStrokeWidth)
            addView(tableContentClip)
        }

        val horizontalScroll = android.widget.HorizontalScrollView(context).apply {
            isHorizontalScrollBarEnabled = false
            isFillViewport = false
            layoutParams = android.widget.LinearLayout.LayoutParams(
                contentVisibleWidth,
                android.widget.LinearLayout.LayoutParams.WRAP_CONTENT
            )
            addView(tableClipContainer)
        }

        val indicatorHeight = (2f * density).toInt().coerceAtLeast(1)
        val indicatorTopMargin = (4f * density).toInt()
        val indicatorMinWidth = (18f * density).toInt()

        val indicatorTrack = android.widget.FrameLayout(context).apply {
            visibility = android.view.View.GONE
            layoutParams = android.widget.LinearLayout.LayoutParams(
                contentVisibleWidth,
                indicatorHeight
            ).apply {
                topMargin = indicatorTopMargin
            }
            background = android.graphics.drawable.GradientDrawable().apply {
                setColor(0x1F000000)
                cornerRadius = indicatorHeight / 2f
            }
        }

        val indicatorThumb = android.view.View(context).apply {
            background = android.graphics.drawable.GradientDrawable().apply {
                setColor(0x66000000)
                cornerRadius = indicatorHeight / 2f
            }
        }
        indicatorTrack.addView(
            indicatorThumb,
            android.widget.FrameLayout.LayoutParams(indicatorMinWidth, android.widget.FrameLayout.LayoutParams.MATCH_PARENT)
        )

        fun updateIndicator() {
            val contentWidth = tableLayout.width
            val viewportWidth = horizontalScroll.width
            val trackWidth = indicatorTrack.width
            if (contentWidth <= 0 || viewportWidth <= 0 || trackWidth <= 0 || contentWidth <= viewportWidth) {
                indicatorTrack.visibility = android.view.View.GONE
                return
            }
            indicatorTrack.visibility = android.view.View.VISIBLE
            val thumbWidth = max((viewportWidth.toFloat() / contentWidth * trackWidth).toInt(), indicatorMinWidth)
            val maxScroll = contentWidth - viewportWidth
            val maxLeft = (trackWidth - thumbWidth).coerceAtLeast(0)
            val thumbLeft = if (maxScroll > 0) {
                (horizontalScroll.scrollX.toFloat() / maxScroll * maxLeft).toInt()
            } else {
                0
            }

            val lp = indicatorThumb.layoutParams as android.widget.FrameLayout.LayoutParams
            lp.width = thumbWidth
            lp.leftMargin = thumbLeft.coerceIn(0, maxLeft)
            indicatorThumb.layoutParams = lp
        }

        horizontalScroll.viewTreeObserver.addOnScrollChangedListener {
            updateIndicator()
        }
        horizontalScroll.post {
            updateIndicator()
        }
        tableLayout.post {
            updateIndicator()
        }

        return android.widget.LinearLayout(context).apply {
            orientation = android.widget.LinearLayout.VERTICAL
            layoutParams = android.widget.LinearLayout.LayoutParams(
                contentVisibleWidth,
                android.widget.LinearLayout.LayoutParams.WRAP_CONTENT
            )
            addView(horizontalScroll)
            addView(indicatorTrack)
        }
    }
    
    /**
     * 创建消息气泡
     * @param sender 发送者
     * @param message 消息内容
     * @param isUserMessage 是否是用户消息
     * @param isComplete 是否是任务完成消息
     * @param isAnswer 是否是answer消息
     */
    private fun createMessageBubble(sender: String, message: String, isUserMessage: Boolean, isComplete: Boolean, isAnswer: Boolean = false): android.widget.LinearLayout {
        // 创建消息容器
        val messageContainer = android.widget.LinearLayout(requireContext()).apply {
            orientation = android.widget.LinearLayout.HORIZONTAL
            layoutParams = android.widget.LinearLayout.LayoutParams(
                android.widget.LinearLayout.LayoutParams.MATCH_PARENT,
                android.widget.LinearLayout.LayoutParams.WRAP_CONTENT
            ).apply {
                setMargins(0, 8, 0, 8)
            }
            // 根据消息类型设置对齐方式：系统消息左对齐，用户消息右对齐
            gravity = if (isUserMessage) android.view.Gravity.END or android.view.Gravity.TOP else android.view.Gravity.START or android.view.Gravity.TOP
        }
        
        // 头像尺寸（统一）
        val avatarSize = (36 * resources.displayMetrics.density).toInt() // 36dp
        val avatarMargin = (8 * resources.displayMetrics.density).toInt() // 8dp
        // 左右边距（统一，确保对齐）
        val sideMargin = (8 * resources.displayMetrics.density).toInt() // 8dp（系统头像左边距，减少以增加气泡宽度）
        val userAvatarRightMargin = (4 * resources.displayMetrics.density).toInt() // 4dp（用户头像右侧留白，避免贴边）
        
        // 计算左右固定宽度（头像 + 边距）
        // 左侧：系统头像左边距 + 头像 + 头像与气泡间距
        // 右侧：用户头像 + 头像与气泡间距 + 用户头像右边距
        val leftRightFixedWidth = avatarSize + avatarMargin + sideMargin
        val screenWidth = resources.displayMetrics.widthPixels
        val userBubbleMaxWidthByLayout = (
            screenWidth - leftRightFixedWidth - avatarSize - avatarMargin - userAvatarRightMargin
            ).coerceAtLeast((screenWidth * 0.4f).toInt())
        val userBubbleMaxWidth = minOf((screenWidth * 0.76f).toInt(), userBubbleMaxWidthByLayout)
        
        if (isUserMessage) {
            // 用户消息：创建内部容器（消息气泡 + 头像），整体右对齐
            val contentContainer = android.widget.LinearLayout(requireContext()).apply {
                orientation = android.widget.LinearLayout.HORIZONTAL
                layoutParams = android.widget.LinearLayout.LayoutParams(
                    android.widget.LinearLayout.LayoutParams.WRAP_CONTENT,
                    android.widget.LinearLayout.LayoutParams.WRAP_CONTENT
                )
                gravity = android.view.Gravity.TOP
            }
            
            // 创建消息气泡
            val bubble = android.widget.TextView(requireContext()).apply {
                // 过滤SOP内容用于显示，但保留原始消息用于分享等功能
                val displayMessage = filterSOPFromMessage(message)
                val markdownMessage = convertToMarkdown(displayMessage)
                val markwon = MarkdownRenderer.createMarkwon(requireContext())
                setupMarkwonWithAppLinks(this, markdownMessage, markwon)
                
                textSize = 16f  // 用户消息：16sp（统一字体大小）
                setPadding(
                    chatTextBubbleHorizontalPadding,
                    chatTextBubbleVerticalPadding,
                    chatTextBubbleHorizontalPadding,
                    chatTextBubbleVerticalPadding
                )
                // 限制最大宽度，避免多行时把“气泡+头像”整体挤到右侧
                maxWidth = userBubbleMaxWidth
                minWidth = 0 // 允许收缩
                
                // 启用文本选择功能（长按可以选择和复制）
                setTextIsSelectable(true)
                
                // 用户消息：浅绿色背景，深色文字
                val drawable = android.graphics.drawable.GradientDrawable().apply {
                    setColor(0xFF95EC69.toInt()) // 浅绿色，类似微信
                    cornerRadius = chatTextBubbleCornerRadius
                }
                background = drawable
                setTextColor(0xFF000000.toInt()) // 黑色文字，更易读
                
                layoutParams = android.widget.LinearLayout.LayoutParams(
                    android.widget.LinearLayout.LayoutParams.WRAP_CONTENT,
                    android.widget.LinearLayout.LayoutParams.WRAP_CONTENT
                )
            }
            contentContainer.addView(bubble)
            
            // 添加用户头像（在右侧）
            val avatarImageView = android.widget.ImageView(requireContext()).apply {
                layoutParams = android.widget.LinearLayout.LayoutParams(avatarSize, avatarSize).apply {
                    setMargins(avatarMargin, 0, userAvatarRightMargin, 0)
                }
                scaleType = android.widget.ImageView.ScaleType.CENTER_CROP
                visibility = android.view.View.VISIBLE
                minimumWidth = avatarSize
                minimumHeight = avatarSize
                
                // 设置圆形裁剪
                outlineProvider = object : android.view.ViewOutlineProvider() {
                    override fun getOutline(view: android.view.View, outline: android.graphics.Outline) {
                        outline.setOval(0, 0, view.width, view.height)
                    }
                }
                clipToOutline = true
                
                // 设置点击事件：跳转到用户主页
                isClickable = true
                isFocusable = true
                setOnClickListener {
                    // 使用hide而不是replace，这样ChatFragment不会被销毁，返回时是同一个实例
                    val userProfileFragment = UserProfileFragment.newInstance()
                    parentFragmentManager.beginTransaction()
                        .setCustomAnimations(0, 0, 0, 0)  // 禁用所有动画
                        .hide(this@ChatFragment)  // 隐藏当前ChatFragment，而不是replace
                        .add(R.id.fragmentContainer, userProfileFragment)  // 添加新的Fragment
                        .addToBackStack(null)
                        .commitAllowingStateLoss()
                }
                
                // 用户头像：从个人主页获取（使用AvatarCacheManager缓存）
                val userProfile = ProfileManager.loadProfileLocally(requireContext())
                val avatarBase64 = userProfile?.avatar
                AvatarCacheManager.loadBase64Avatar(
                    requireContext(),
                    this,
                    avatarBase64,
                    R.drawable.ic_person,
                    "user_avatar"
                )
                background = ContextCompat.getDrawable(requireContext(), R.drawable.circle_background)
            }
            contentContainer.addView(avatarImageView)
            
            // 添加左侧占位符，确保与系统消息对齐
            val leftSpacer = android.view.View(requireContext()).apply {
                layoutParams = android.widget.LinearLayout.LayoutParams(
                    leftRightFixedWidth,
                    android.widget.LinearLayout.LayoutParams.WRAP_CONTENT
                )
            }
            messageContainer.addView(leftSpacer)
            messageContainer.addView(contentContainer)
            
            Log.d(TAG, "用户消息已创建，整体右对齐")
        } else {
            // 系统消息：先添加系统头像（在左侧）
            val avatarImageView = android.widget.ImageView(requireContext()).apply {
                layoutParams = android.widget.LinearLayout.LayoutParams(avatarSize, avatarSize).apply {
                    setMargins(sideMargin, 0, avatarMargin, 0)
                }
                scaleType = android.widget.ImageView.ScaleType.FIT_CENTER
                
                // 设置圆形裁剪
                outlineProvider = object : android.view.ViewOutlineProvider() {
                    override fun getOutline(view: android.view.View, outline: android.graphics.Outline) {
                        outline.setOval(0, 0, view.width, view.height)
                    }
                }
                clipToOutline = true
                
                // 设置点击事件：跳转到助手主页
                isClickable = true
                isFocusable = true
                setOnClickListener {
                    currentConversation?.let { conversation ->
                        // 使用hide而不是replace，这样ChatFragment不会被销毁，返回时是同一个实例
                        val profileFragment = ConversationProfileFragment.newInstance(conversation)
                        parentFragmentManager.beginTransaction()
                            .setCustomAnimations(0, 0, 0, 0)  // 禁用所有动画
                            .hide(this@ChatFragment)  // 隐藏当前ChatFragment，而不是replace
                            .add(R.id.fragmentContainer, profileFragment)  // 添加新的Fragment
                            .addToBackStack(null)
                            .commitAllowingStateLoss()
                    }
                }
                
                // 先显示默认头像，然后异步加载实际头像
                setImageResource(R.drawable.ic_system_avatar)
            }
            // 根据对话ID异步加载实际头像（在apply块外调用）
            loadConversationAvatar(avatarImageView)
            messageContainer.addView(avatarImageView)
        
        // 创建消息气泡
        val bubble = android.widget.TextView(requireContext()).apply {
            // 过滤SOP内容用于显示，但保留原始消息用于分享等功能
            val displayMessage = filterSOPFromMessage(message)
            val markdownMessage = convertToMarkdown(displayMessage)
            val markwon = MarkdownRenderer.createMarkwon(requireContext())
            setupMarkwonWithAppLinks(this, markdownMessage, markwon)
            
            // 根据sender设置字体大小：
            // 系统消息（sender = "系统"）：12sp（调小两号，从14f调到12f）
            // 助手消息（sender = "云侧"或"小助手"）：16sp
            // 端侧小助手消息（isAnswer = true）：16sp（与用户消息一致）
            // 任务完成消息（isComplete = true）：16sp（与用户消息一致）
            textSize = when {
                sender == "系统" && (isAnswer || isComplete) -> 16f  // 端侧小助手消息或任务完成消息：16sp
                sender == "系统" -> 12f  // 系统消息调小两号
                sender == "云侧" || sender == "小助手" -> 16f  // 助手消息：16sp
                else -> 14f  // 其他消息保持原大小
            }
            setPadding(
                chatTextBubbleHorizontalPadding,
                chatTextBubbleVerticalPadding,
                chatTextBubbleHorizontalPadding,
                chatTextBubbleVerticalPadding
            )
                // 与图文消息气泡一致：最大宽度为屏宽 76%
                maxWidth = (resources.displayMetrics.widthPixels * 0.76f).toInt()
                minWidth = 0 // 允许收缩
                
                // 启用文本选择功能（长按可以选择和复制）
                setTextIsSelectable(true)
            
            // 设置背景和文字颜色（微信风格：浅绿色和浅蓝色）
                // 助手侧消息（含普通/answer/complete）统一使用更深一点的灰色背景
                val drawable = android.graphics.drawable.GradientDrawable().apply {
                    setColor(assistantTextBubbleBackgroundColor)
                    cornerRadius = chatTextBubbleCornerRadius
                }
                background = drawable
                setTextColor(0xFF000000.toInt())
            
            layoutParams = android.widget.LinearLayout.LayoutParams(
                android.widget.LinearLayout.LayoutParams.WRAP_CONTENT,
                android.widget.LinearLayout.LayoutParams.WRAP_CONTENT
            )
        }
        messageContainer.addView(bubble)
        
            // 添加固定宽度的占位符在右侧（answer消息也显示在左侧）
            val spacer = android.view.View(requireContext()).apply {
                layoutParams = android.widget.LinearLayout.LayoutParams(
                    leftRightFixedWidth,
                    android.widget.LinearLayout.LayoutParams.WRAP_CONTENT
                )
            }
            messageContainer.addView(spacer)
        }
        
        return messageContainer
    }
    
    /**
     * 创建消息气泡（用于RecyclerView Adapter）
     * @param sender 发送者
     * @param message 消息内容
     * @param isUserMessage 是否是用户消息
     * @param isComplete 是否是任务完成消息
     * @param isAnswer 是否是answer消息
     * @param markwon Markwon实例（复用）
     * @param onAvatarClick 头像点击回调
     * @param timestamp 时间戳
     * @param recommendations 推荐任务列表（用于任务完成消息）
     */
    fun createMessageBubbleForAdapter(
        sender: String,
        message: String,
        isUserMessage: Boolean,
        isComplete: Boolean,
        isAnswer: Boolean,
        senderImei: String? = null,
        showAssistantAvatar: Boolean = true,
        markwon: Markwon,
        onAvatarClick: (String) -> Unit,
        timestamp: Long = System.currentTimeMillis(),
        recommendations: List<String>? = null
    ): android.widget.LinearLayout {
        // 创建消息容器
        val messageContainer = android.widget.LinearLayout(requireContext()).apply {
            orientation = android.widget.LinearLayout.HORIZONTAL
            layoutParams = android.widget.LinearLayout.LayoutParams(
                android.widget.LinearLayout.LayoutParams.MATCH_PARENT,
                android.widget.LinearLayout.LayoutParams.WRAP_CONTENT
            )
            // 根据消息类型设置对齐方式：系统消息左对齐，用户消息右对齐
            gravity = if (isUserMessage) android.view.Gravity.END or android.view.Gravity.TOP else android.view.Gravity.START or android.view.Gravity.TOP
            
            // 管理员模式下，用户消息保存IMEI到tag中（用于快速查找）
            if (currentConversation?.id == ConversationListFragment.CONVERSATION_ID_ADMIN_CUSTOMER_SERVICE && sender == "用户") {
                // 查找该消息对应的IMEI并保存到tag
                val foundImei = findImeiForMessage(sender, message, timestamp)
                if (foundImei != null) {
                    tag = foundImei
                }
            }
        }
        
        // 头像尺寸（统一）
        val avatarSize = (36 * resources.displayMetrics.density).toInt() // 36dp
        val avatarMargin = (8 * resources.displayMetrics.density).toInt() // 8dp
        // 左右边距（统一，确保对齐）
        val sideMargin = (8 * resources.displayMetrics.density).toInt() // 8dp（系统头像左边距，减少以增加气泡宽度）
        val userAvatarRightMargin = (4 * resources.displayMetrics.density).toInt() // 4dp（用户头像右侧留白，避免贴边）
        
        // 计算左右固定宽度（头像 + 边距）
        val leftRightFixedWidth = avatarSize + avatarMargin + sideMargin
        val screenWidth = resources.displayMetrics.widthPixels
        val userBubbleMaxWidthByLayout = (
            screenWidth - leftRightFixedWidth - avatarSize - avatarMargin - userAvatarRightMargin
            ).coerceAtLeast((screenWidth * 0.4f).toInt())
        val userBubbleMaxWidth = minOf((screenWidth * 0.76f).toInt(), userBubbleMaxWidthByLayout)
        val conversationId = currentConversation?.id
        val isGroupMessage = conversationId?.startsWith("group_") == true || conversationId == ConversationListFragment.CONVERSATION_ID_GROUP
        val senderNameForAvatar = sender.replace(Regex("（[^（）]*）$"), "").trim().ifBlank { sender }
        
        if (isUserMessage) {
            // 用户消息：创建内部容器（消息气泡 + 头像），整体右对齐
            val contentContainer = android.widget.LinearLayout(requireContext()).apply {
                orientation = android.widget.LinearLayout.HORIZONTAL
                layoutParams = android.widget.LinearLayout.LayoutParams(
                    android.widget.LinearLayout.LayoutParams.WRAP_CONTENT,
                    android.widget.LinearLayout.LayoutParams.WRAP_CONTENT
                )
                gravity = android.view.Gravity.TOP
            }
            
            // 创建消息气泡
            val displayMessage = filterSOPFromMessage(message)
            val markdownMessage = convertToMarkdown(displayMessage)
            val bubble = android.widget.TextView(requireContext()).apply {
                textSize = 16f
                setPadding(
                    chatTextBubbleHorizontalPadding,
                    chatTextBubbleVerticalPadding,
                    chatTextBubbleHorizontalPadding,
                    chatTextBubbleVerticalPadding
                )
                // 限制最大宽度，避免多行时把“气泡+头像”整体挤到右侧
                maxWidth = userBubbleMaxWidth
                minWidth = 0
                setTextIsSelectable(true)
                
                // 设置自定义ActionMode，保留默认功能并添加删除选项
                customSelectionActionModeCallback = object : ActionMode.Callback {
                    private val MENU_ITEM_DELETE = 1001
                    
                    override fun onCreateActionMode(mode: ActionMode?, menu: Menu?): Boolean {
                        // onCreateActionMode中不添加菜单项，让系统先添加默认项
                        return true
                    }
                    
                    override fun onPrepareActionMode(mode: ActionMode?, menu: Menu?): Boolean {
                        menu?.let {
                            // 清除所有菜单项，避免重复
                            it.clear()
                            
                            // 重新添加需要的菜单项：复制、全选、分享、删除
                            it.add(0, android.R.id.copy, 0, "复制")
                                .setShowAsAction(MenuItem.SHOW_AS_ACTION_IF_ROOM)
                            it.add(0, android.R.id.selectAll, 0, "全选")
                                .setShowAsAction(MenuItem.SHOW_AS_ACTION_IF_ROOM)
                            it.add(0, android.R.id.shareText, 0, "分享")
                                .setShowAsAction(MenuItem.SHOW_AS_ACTION_IF_ROOM)
                            // 添加删除菜单项
                            it.add(0, MENU_ITEM_DELETE, 0, "删除")
                                .setShowAsAction(MenuItem.SHOW_AS_ACTION_IF_ROOM)
                        }
                        return true
                    }
                    
                    override fun onActionItemClicked(mode: ActionMode?, item: MenuItem?): Boolean {
                        when (item?.itemId) {
                            android.R.id.copy -> {
                                // 复制功能由系统处理
                                return false
                            }
                            android.R.id.selectAll -> {
                                // 全选功能由系统处理
                                return false
                            }
                            android.R.id.shareText -> {
                                // 分享功能由系统处理
                                return false
                            }
                            MENU_ITEM_DELETE -> {
                                // 删除该条消息
                                deleteMessageByTimestamp(timestamp)
                                mode?.finish()
                                return true
                            }
                        }
                        return false
                    }
                    
                    override fun onDestroyActionMode(mode: ActionMode?) {
                    }
                }
                
                val drawable = android.graphics.drawable.GradientDrawable().apply {
                    setColor(0xFF95EC69.toInt())
                    cornerRadius = chatTextBubbleCornerRadius
                }
                background = drawable
                setTextColor(0xFF000000.toInt())
                
                layoutParams = android.widget.LinearLayout.LayoutParams(
                    android.widget.LinearLayout.LayoutParams.WRAP_CONTENT,
                    android.widget.LinearLayout.LayoutParams.WRAP_CONTENT
                )
            }
            val bubbleContentView = bindMarkdownContentToBubble(bubble, markdownMessage, markwon)
            attachUnifiedBubbleLongPressMenu(
                rootView = bubbleContentView,
                primaryTextView = bubble,
                fullMessage = displayMessage,
                timestamp = timestamp
            )
            contentContainer.addView(bubbleContentView)
            
            // 添加用户头像（在右侧）
            val avatarImageView = android.widget.ImageView(requireContext()).apply {
                layoutParams = android.widget.LinearLayout.LayoutParams(avatarSize, avatarSize).apply {
                    setMargins(avatarMargin, 0, userAvatarRightMargin, 0)
                }
                scaleType = android.widget.ImageView.ScaleType.CENTER_CROP
                visibility = android.view.View.VISIBLE
                minimumWidth = avatarSize
                minimumHeight = avatarSize
                
                outlineProvider = object : android.view.ViewOutlineProvider() {
                    override fun getOutline(view: android.view.View, outline: android.graphics.Outline) {
                        outline.setOval(0, 0, view.width, view.height)
                    }
                }
                clipToOutline = true
                
                isClickable = true
                isFocusable = true
                setOnClickListener { onAvatarClick(if (currentConversation?.id == ConversationListFragment.CONVERSATION_ID_ADMIN_CUSTOMER_SERVICE && sender == "人工客服") "人工客服" else "我") }
                
                // 管理员模式下，客服消息显示客服头像；普通模式下，用户消息显示用户头像
                if (currentConversation?.id == ConversationListFragment.CONVERSATION_ID_ADMIN_CUSTOMER_SERVICE && sender == "人工客服") {
                    // 管理员模式：显示客服头像
                    setImageResource(R.drawable.ic_customer_service_avatar)
                } else {
                    // 用户头像：从个人主页获取（使用AvatarCacheManager缓存）
                    val userProfile = ProfileManager.loadProfileLocally(requireContext())
                    val avatarBase64 = userProfile?.avatar
                    AvatarCacheManager.loadBase64Avatar(
                        requireContext(),
                        this,
                        avatarBase64,
                        R.drawable.ic_person,
                        "user_avatar"
                    )
                    background = ContextCompat.getDrawable(requireContext(), R.drawable.circle_background)
                }
            }
            contentContainer.addView(avatarImageView)
            
            // 添加左侧占位符
            val leftSpacer = android.view.View(requireContext()).apply {
                layoutParams = android.widget.LinearLayout.LayoutParams(
                    leftRightFixedWidth,
                    android.widget.LinearLayout.LayoutParams.WRAP_CONTENT
                )
            }
            messageContainer.addView(leftSpacer)
            messageContainer.addView(contentContainer)
        } else {
            if (showAssistantAvatar) {
                // 系统消息：先添加系统头像（在左侧）
                val avatarImageView = android.widget.ImageView(requireContext()).apply {
                    layoutParams = android.widget.LinearLayout.LayoutParams(avatarSize, avatarSize).apply {
                        setMargins(sideMargin, 0, avatarMargin, 0)
                    }
                    scaleType = android.widget.ImageView.ScaleType.FIT_CENTER
                    
                    outlineProvider = object : android.view.ViewOutlineProvider() {
                        override fun getOutline(view: android.view.View, outline: android.graphics.Outline) {
                            outline.setOval(0, 0, view.width, view.height)
                        }
                    }
                    clipToOutline = true
                    
                    isClickable = true
                    isFocusable = true
                    
                    // 检查是否是群组消息，如果是，需要特殊处理点击事件
                    if (isGroupMessage) {
                        // 群组消息：根据发送者跳转到对应的主页
                        setOnClickListener {
                            when {
                                sender == "我" -> {
                                    // 跳转到用户主页
                                    val userProfileFragment = UserProfileFragment.newInstance()
                                    parentFragmentManager.beginTransaction()
                                        .setCustomAnimations(0, 0, 0, 0)
                                        .hide(this@ChatFragment)
                                        .add(R.id.fragmentContainer, userProfileFragment)
                                        .addToBackStack(null)
                                        .commitAllowingStateLoss()
                                }
                                ChatConstants.isMainAssistantSender(senderNameForAvatar) -> {
                                    // 跳转到小助手主页
                                    val assistantConv = Conversation(
                                        id = ConversationListFragment.CONVERSATION_ID_ASSISTANT,
                                        name = ChatConstants.ASSISTANT_DISPLAY_NAME,
                                        avatar = null,
                                        lastMessage = null,
                                        lastMessageTime = System.currentTimeMillis()
                                    )
                                    val profileFragment = ConversationProfileFragment.newInstance(assistantConv)
                                    parentFragmentManager.beginTransaction()
                                        .setCustomAnimations(0, 0, 0, 0)
                                        .hide(this@ChatFragment)
                                        .add(R.id.fragmentContainer, profileFragment)
                                        .addToBackStack(null)
                                        .commitAllowingStateLoss()
                                }
                                else -> {
                                    // 尝试从好友列表中查找匹配的好友
                                    val friends = FriendManager.getFriends(requireContext())
                                    val friend = if (!senderImei.isNullOrBlank()) {
                                        FriendManager.getFriend(requireContext(), senderImei)
                                    } else {
                                        friends.find {
                                            it.nickname == sender || it.nickname == senderNameForAvatar ||
                                                (senderNameForAvatar.endsWith("...") && it.imei.take(8) == senderNameForAvatar.removeSuffix("..."))
                                        }
                                    }
                                    
                                    if (friend != null) {
                                        // 找到好友，跳转到好友对话页面
                                        val friendConversation = Conversation(
                                            id = "friend_${friend.imei}",
                                            name = friend.nickname ?: friend.imei.take(8) + "...",
                                            avatar = friend.avatar,
                                            lastMessage = null,
                                            lastMessageTime = System.currentTimeMillis()
                                        )
                                        val profileFragment = ConversationProfileFragment.newInstance(friendConversation)
                                        parentFragmentManager.beginTransaction()
                                            .setCustomAnimations(0, 0, 0, 0)
                                            .hide(this@ChatFragment)
                                            .add(R.id.fragmentContainer, profileFragment)
                                            .addToBackStack(null)
                                            .commitAllowingStateLoss()
                                    } else {
                                        // 未找到好友，跳转到当前群组主页（作为后备方案）
                                        currentConversation?.let { conversation ->
                                            val profileFragment = ConversationProfileFragment.newInstance(conversation)
                                            parentFragmentManager.beginTransaction()
                                                .setCustomAnimations(0, 0, 0, 0)
                                                .hide(this@ChatFragment)
                                                .add(R.id.fragmentContainer, profileFragment)
                                                .addToBackStack(null)
                                                .commitAllowingStateLoss()
                                        }
                                    }
                                }
                            }
                        }
                    } else {
                        // 非群组消息：使用默认的点击处理
                        setOnClickListener { onAvatarClick(sender) }
                    }
                    
                    // 管理员模式下，用户消息显示用户头像；其他情况显示系统头像
                    if (currentConversation?.id == ConversationListFragment.CONVERSATION_ID_ADMIN_CUSTOMER_SERVICE && sender == "用户") {
                        // 管理员模式：用户消息显示用户头像（使用AvatarCacheManager缓存）
                        scaleType = android.widget.ImageView.ScaleType.CENTER_CROP
                        val userProfile = ProfileManager.loadProfileLocally(requireContext())
                        val avatarBase64 = userProfile?.avatar
                        AvatarCacheManager.loadBase64Avatar(
                            requireContext(),
                            this,
                            avatarBase64,
                            R.drawable.ic_person,
                            "user_avatar"
                        )
                        background = ContextCompat.getDrawable(requireContext(), R.drawable.circle_background)
                    } else {
                        // 检查是否是群组消息
                        if (isGroupMessage) {
                            // 群组消息：根据发送者加载头像
                            scaleType = android.widget.ImageView.ScaleType.CENTER_CROP
                            when {
                                sender == "我" -> {
                                    // 当前用户：显示用户头像（使用AvatarCacheManager缓存）
                                    val userProfile = ProfileManager.loadProfileLocally(requireContext())
                                    val avatarBase64 = userProfile?.avatar
                                    AvatarCacheManager.loadBase64Avatar(
                                        requireContext(),
                                        this,
                                        avatarBase64,
                                        R.drawable.ic_person,
                                        "user_avatar"
                                    )
                                    background = ContextCompat.getDrawable(requireContext(), R.drawable.circle_background)
                                }
                                ChatConstants.isMainAssistantSender(senderNameForAvatar) -> {
                                    // TopoClaw：显示专用头像
                                    setImageResource(R.drawable.ic_assistant_avatar)
                                }
                                else -> {
                                    // 自定义小助手：优先使用其原始头像（如有），不使用TopoClaw头像或默认头像
                                    val groupForAvatar = when {
                                        conversationId?.startsWith("group_") == true -> {
                                            val groupId = conversationId.removePrefix("group_")
                                            GroupManager.getGroup(requireContext(), groupId)
                                        }
                                        conversationId == ConversationListFragment.CONVERSATION_ID_GROUP -> {
                                            GroupManager.getGroup(requireContext(), conversationId)
                                        }
                                        else -> null
                                    }
                                    // 优先按 senderImei（助手 ID）直接查找，避免名称截断导致匹配失败
                                    var customAssistant: CustomAssistantManager.CustomAssistant? = null
                                    if (!senderImei.isNullOrBlank() && CustomAssistantManager.isCustomAssistantId(senderImei)) {
                                        customAssistant = CustomAssistantManager.getById(requireContext(), senderImei)
                                    }
                                    // 按名称从群组内查找
                                    if (customAssistant == null) {
                                        customAssistant = groupForAvatar?.assistants?.firstNotNullOfOrNull { aid ->
                                            if (CustomAssistantManager.isCustomAssistantId(aid)) {
                                                CustomAssistantManager.getById(requireContext(), aid)?.takeIf { it.name == senderNameForAvatar }
                                            } else null
                                        }
                                    }
                                    // 群组内未找到时，从所有自定义小助手中按名称匹配（兼容群组结构差异）
                                    if (customAssistant == null) {
                                        customAssistant = CustomAssistantManager.getAll(requireContext()).find { it.name == senderNameForAvatar }
                                    }
                                    if (customAssistant != null) {
                                        // 自定义小助手：有头像用其头像，无头像用首字（与助手页面一致，不用TopoClaw头像）
                                        AvatarCacheManager.loadCustomAssistantAvatar(
                                            context = requireContext(),
                                            imageView = this,
                                            assistant = customAssistant,
                                            cacheKey = "custom_assistant_${customAssistant.id}",
                                            validationTag = customAssistant.id,
                                            sizePx = avatarSize
                                        )
                                        background = ContextCompat.getDrawable(requireContext(), R.drawable.circle_background)
                                    } else {
                                        // 其他发送者：尝试从好友列表查找（使用AvatarCacheManager缓存，避免闪烁）
                                        val friends = FriendManager.getFriends(requireContext())
                                        val friend = if (!senderImei.isNullOrBlank()) {
                                            FriendManager.getFriend(requireContext(), senderImei)
                                        } else {
                                            friends.find { it.nickname == sender || it.nickname == senderNameForAvatar }
                                        }
                                    if (friend != null) {
                                        // 找到好友，使用AvatarCacheManager加载好友头像
                                        val cacheKey = "friend_${friend.imei}"
                                        AvatarCacheManager.loadBase64Avatar(
                                            context = requireContext(),
                                            imageView = this,
                                            base64String = friend.avatar,
                                            defaultResId = R.drawable.ic_person,
                                            cacheKey = cacheKey,
                                            validationTag = friend.imei
                                        )
                                        background = ContextCompat.getDrawable(requireContext(), R.drawable.circle_background)
                                    } else {
                                        // 未找到好友，使用默认头像
                                        setImageResource(R.drawable.ic_person)
                                        background = ContextCompat.getDrawable(requireContext(), R.drawable.circle_background)
                                    }
                                    }
                                }
                            }
                        } else {
                            // 普通模式：显示系统头像
                            setImageResource(R.drawable.ic_system_avatar)
                            loadConversationAvatar(this)
                        }
                    }
                }
                messageContainer.addView(avatarImageView)
            } else {
                // 与“正在思考”共用头像：最终回答气泡不再单独绘制头像，仅保留同等左侧缩进
                val leftSpacer = android.view.View(requireContext()).apply {
                    layoutParams = android.widget.LinearLayout.LayoutParams(
                        leftRightFixedWidth,
                        android.widget.LinearLayout.LayoutParams.WRAP_CONTENT
                    )
                }
                messageContainer.addView(leftSpacer)
            }
        
            // 管理员模式下，用户消息查找IMEI并保存（用于快速查找）
            val userMessageImei = if (currentConversation?.id == ConversationListFragment.CONVERSATION_ID_ADMIN_CUSTOMER_SERVICE && sender == "用户") {
                findImeiForMessage(sender, message, timestamp)
            } else {
                null
            }
            
            val bubbleColumn = android.widget.LinearLayout(requireContext()).apply {
                orientation = android.widget.LinearLayout.VERTICAL
                layoutParams = android.widget.LinearLayout.LayoutParams(
                    android.widget.LinearLayout.LayoutParams.WRAP_CONTENT,
                    android.widget.LinearLayout.LayoutParams.WRAP_CONTENT
                )
            }

            if (isGroupMessage && sender != "我" && sender.isNotBlank()) {
                val senderNameView = android.widget.TextView(requireContext()).apply {
                    text = sender
                    textSize = 12f
                    setTextColor(0xFF8A8A8A.toInt())
                    layoutParams = android.widget.LinearLayout.LayoutParams(
                        android.widget.LinearLayout.LayoutParams.WRAP_CONTENT,
                        android.widget.LinearLayout.LayoutParams.WRAP_CONTENT
                    ).apply {
                        setMargins(2, 0, 0, 4)
                    }
                }
                bubbleColumn.addView(senderNameView)
            }

            // 创建消息气泡
            val displayMessage = filterSOPFromMessage(message)
            val markdownMessage = convertToMarkdown(displayMessage)
            val bubble = android.widget.TextView(requireContext()).apply {
                // 管理员模式下，用户消息在bubble的tag中也保存IMEI（用于长按回复时快速读取）
                // 如果有IMEI，保存到tag中（用于管理员模式快速回复）
                if (userMessageImei != null) {
                    tag = userMessageImei
                }
                
                textSize = when {
                    sender == "系统" && (isAnswer || isComplete) -> 16f
                    sender == "系统" -> 12f
                    sender == "云侧" || sender == "小助手" -> 16f
                    else -> 14f
                }
                setPadding(
                    chatTextBubbleHorizontalPadding,
                    chatTextBubbleVerticalPadding,
                    chatTextBubbleHorizontalPadding,
                    chatTextBubbleVerticalPadding
                )
                // 与图文消息气泡一致：最大宽度为屏宽 76%
                maxWidth = (resources.displayMetrics.widthPixels * 0.76f).toInt()
                minWidth = 0
                setTextIsSelectable(true)
                
                // 管理员模式：用户消息可点击选中
                if (currentConversation?.id == ConversationListFragment.CONVERSATION_ID_ADMIN_CUSTOMER_SERVICE && sender == "用户") {
                    isClickable = true
                    isFocusable = true
                    setOnClickListener {
                        // 优先从bubble的tag中读取IMEI（创建时已保存）
                        var imei = tag as? String
                        
                        // 如果tag中没有，使用查找函数（不依赖timestamp）
                        if (imei == null) {
                            imei = findImeiForMessage(sender, message, timestamp)
                        }
                        
                        val finalImei = imei
                        if (finalImei != null) {
                            selectedUserImei = finalImei
                            android.widget.Toast.makeText(
                                requireContext(),
                                "已选中用户: ${finalImei.take(8)}...",
                                android.widget.Toast.LENGTH_SHORT
                            ).show()
                            // 更新输入框提示
                            updateAdminInputHint()
                        } else {
                            Log.w(TAG, "无法找到用户IMEI: sender=$sender, message=${message.take(50)}, timestamp=$timestamp")
                            Log.d(TAG, "messageImeiMap大小: ${messageImeiMap.size}, messageDirectImeImeiMap大小: ${messageDirectImeiMap.size}")
                        }
                    }
                }
                
                // 设置自定义ActionMode，保留默认功能并添加删除选项
                val actionModeCallback = object : ActionMode.Callback {
                    private val MENU_ITEM_DELETE = 1001
                    private val MENU_ITEM_REPLY = 1002
                    private val MENU_ITEM_MULTI_SELECT = 1003
                    
                    override fun onCreateActionMode(mode: ActionMode?, menu: Menu?): Boolean {
                        // 在onCreateActionMode中也添加菜单项，确保菜单被创建
                        Log.d(TAG, "onCreateActionMode被调用: sender=$sender")
                        menu?.let {
                            it.add(0, android.R.id.copy, 0, "复制")
                                .setShowAsAction(MenuItem.SHOW_AS_ACTION_IF_ROOM)
                            it.add(0, android.R.id.selectAll, 0, "全选")
                                .setShowAsAction(MenuItem.SHOW_AS_ACTION_IF_ROOM)
                            it.add(0, android.R.id.shareText, 0, "分享")
                                .setShowAsAction(MenuItem.SHOW_AS_ACTION_IF_ROOM)
                            // 添加多选选项
                            it.add(0, MENU_ITEM_MULTI_SELECT, 0, "多选")
                                .setShowAsAction(MenuItem.SHOW_AS_ACTION_IF_ROOM)
                            // 管理员模式下，用户消息添加回复选项
                            if (currentConversation?.id == ConversationListFragment.CONVERSATION_ID_ADMIN_CUSTOMER_SERVICE && sender == "用户") {
                                it.add(0, MENU_ITEM_REPLY, 0, "回复")
                                    .setShowAsAction(MenuItem.SHOW_AS_ACTION_IF_ROOM)
                            }
                            it.add(0, MENU_ITEM_DELETE, 0, "删除")
                                .setShowAsAction(MenuItem.SHOW_AS_ACTION_IF_ROOM)
                        }
                        return true
                    }
                    
                    override fun onPrepareActionMode(mode: ActionMode?, menu: Menu?): Boolean {
                        Log.d(TAG, "onPrepareActionMode被调用: sender=$sender")
                        menu?.let {
                            it.clear()
                            it.add(0, android.R.id.copy, 0, "复制")
                                .setShowAsAction(MenuItem.SHOW_AS_ACTION_IF_ROOM)
                            it.add(0, android.R.id.selectAll, 0, "全选")
                                .setShowAsAction(MenuItem.SHOW_AS_ACTION_IF_ROOM)
                            it.add(0, android.R.id.shareText, 0, "分享")
                                .setShowAsAction(MenuItem.SHOW_AS_ACTION_IF_ROOM)
                            // 添加多选选项
                            it.add(0, MENU_ITEM_MULTI_SELECT, 0, "多选")
                                .setShowAsAction(MenuItem.SHOW_AS_ACTION_IF_ROOM)
                            // 管理员模式下，用户消息添加回复选项
                            if (currentConversation?.id == ConversationListFragment.CONVERSATION_ID_ADMIN_CUSTOMER_SERVICE && sender == "用户") {
                                it.add(0, MENU_ITEM_REPLY, 0, "回复")
                                    .setShowAsAction(MenuItem.SHOW_AS_ACTION_IF_ROOM)
                            }
                            it.add(0, MENU_ITEM_DELETE, 0, "删除")
                                .setShowAsAction(MenuItem.SHOW_AS_ACTION_IF_ROOM)
                        }
                        return true
                    }
                    
                    override fun onActionItemClicked(mode: ActionMode?, item: MenuItem?): Boolean {
                        return when (item?.itemId) {
                            android.R.id.copy, android.R.id.selectAll, android.R.id.shareText -> false
                            MENU_ITEM_MULTI_SELECT -> {
                                // 进入多选模式
                                mode?.finish()
                                enterMultiSelectMode(timestamp)
                                true
                            }
                            MENU_ITEM_REPLY -> {
                                // 管理员模式：回复用户消息
                                // 优先从bubble的tag中读取IMEI（创建时已保存）
                                var imei: String? = null
                                try {
                                    // 从当前TextView（bubble）的tag中读取IMEI
                                    imei = this@apply.tag as? String
                                } catch (e: Exception) {
                                    Log.d(TAG, "从tag读取IMEI失败，使用查找函数: ${e.message}")
                                }
                                
                                // 如果tag中没有，使用查找函数（不依赖timestamp）
                                if (imei == null) {
                                    imei = findImeiForMessage(sender, message, timestamp)
                                }
                                
                                val finalImei = imei
                                if (finalImei != null && _binding != null) {
                                    selectedUserImei = finalImei
                                    updateAdminInputHint()
                                    binding.etChatInput.requestFocus()
                                    android.widget.Toast.makeText(
                                        requireContext(),
                                        "已选中用户: ${finalImei.take(8)}...",
                                        android.widget.Toast.LENGTH_SHORT
                                    ).show()
                                } else {
                                    Log.w(TAG, "无法找到用户IMEI: sender=$sender, message=${message.take(50)}, timestamp=$timestamp")
                                    Log.d(TAG, "messageImeiMap大小: ${messageImeiMap.size}, messageDirectImeiMap大小: ${messageDirectImeiMap.size}")
                                    android.widget.Toast.makeText(
                                        requireContext(),
                                        "无法找到用户信息，请尝试点击消息选中用户",
                                        android.widget.Toast.LENGTH_SHORT
                                    ).show()
                                }
                                mode?.finish()
                                true
                            }
                            MENU_ITEM_DELETE -> {
                                deleteMessageByTimestamp(timestamp)
                                mode?.finish()
                                true
                            }
                            else -> false
                        }
                    }
                    
                    override fun onDestroyActionMode(mode: ActionMode?) {}
                }
                // 设置自定义ActionMode回调
                customSelectionActionModeCallback = actionModeCallback
            
                // 助手侧消息（含普通/answer/complete）统一使用更深一点的灰色背景
                val drawable = android.graphics.drawable.GradientDrawable().apply {
                    setColor(assistantTextBubbleBackgroundColor)
                    cornerRadius = chatTextBubbleCornerRadius
                }
                background = drawable
                setTextColor(0xFF000000.toInt())
                
                layoutParams = android.widget.LinearLayout.LayoutParams(
                    android.widget.LinearLayout.LayoutParams.WRAP_CONTENT,
                    android.widget.LinearLayout.LayoutParams.WRAP_CONTENT
                )
            }
            val bubbleContentView = bindMarkdownContentToBubble(bubble, markdownMessage, markwon)
            attachUnifiedBubbleLongPressMenu(
                rootView = bubbleContentView,
                primaryTextView = bubble,
                fullMessage = displayMessage,
                timestamp = timestamp
            )
            bubbleColumn.addView(bubbleContentView)
            messageContainer.addView(bubbleColumn)
            
            // 添加固定宽度的占位符在右侧
            val spacer = android.view.View(requireContext()).apply {
                layoutParams = android.widget.LinearLayout.LayoutParams(
                    leftRightFixedWidth,
                    android.widget.LinearLayout.LayoutParams.WRAP_CONTENT
                )
            }
            messageContainer.addView(spacer)
        }
        
        return messageContainer
    }
    
    /**
     * 添加系统消息到可折叠容器
     */
    private fun addSystemMessageToCollapsible(sender: String, message: String) {
        // 如果折叠容器不存在，创建它
        if (systemMessagesContainer == null) {
            createSystemMessagesContainer()
        }
        
        // 创建系统消息气泡
        val messageContainer = android.widget.LinearLayout(requireContext()).apply {
            orientation = android.widget.LinearLayout.HORIZONTAL
            layoutParams = android.widget.LinearLayout.LayoutParams(
                android.widget.LinearLayout.LayoutParams.MATCH_PARENT,
                android.widget.LinearLayout.LayoutParams.WRAP_CONTENT
            ).apply {
                setMargins(0, 4, 0, 4)
            }
        }
        
        // 添加左侧占位符
        val leftSpacer = android.view.View(requireContext()).apply {
            layoutParams = android.widget.LinearLayout.LayoutParams(
                0,
                android.widget.LinearLayout.LayoutParams.WRAP_CONTENT,
                1f
            )
        }
        messageContainer.addView(leftSpacer)
        
        // 创建消息气泡
        val bubble = android.widget.TextView(requireContext()).apply {
            // 过滤SOP内容用于显示，但保留原始消息用于分享等功能
            val displayMessage = filterSOPFromMessage(message)
            val markdownMessage = convertToMarkdown(displayMessage)
            val markwon = MarkdownRenderer.createMarkwon(requireContext())
            setupMarkwonWithAppLinks(this, markdownMessage, markwon)
            
            // 根据sender设置字体大小：系统消息12sp，助手消息16sp
            // 端侧小助手消息（sender = "小助手"）：16sp（与用户消息一致）
            textSize = when (sender) {
                "系统" -> 12f  // 系统消息调小两号
                "云侧", "小助手" -> 16f  // 助手消息：16sp（包括端侧小助手）
                else -> 12f  // 其他消息默认12sp
            }
            setPadding(
                systemTextBubbleHorizontalPadding,
                systemTextBubbleVerticalPadding,
                systemTextBubbleHorizontalPadding,
                systemTextBubbleVerticalPadding
            )
            maxWidth = (resources.displayMetrics.widthPixels * 0.7).toInt()
            
            // 启用文本选择功能（长按可以选择和复制）
            setTextIsSelectable(true)
            
            val drawable = android.graphics.drawable.GradientDrawable().apply {
                setColor(0xFFFFFFFF.toInt())
                cornerRadius = systemTextBubbleCornerRadius
            }
            background = drawable
            setTextColor(0xFF000000.toInt())
            
            layoutParams = android.widget.LinearLayout.LayoutParams(
                android.widget.LinearLayout.LayoutParams.WRAP_CONTENT,
                android.widget.LinearLayout.LayoutParams.WRAP_CONTENT
            )
        }
        messageContainer.addView(bubble)
        
        // 添加右侧占位符
        val rightSpacer = android.view.View(requireContext()).apply {
            layoutParams = android.widget.LinearLayout.LayoutParams(
                0,
                android.widget.LinearLayout.LayoutParams.WRAP_CONTENT,
                1f
            )
        }
        messageContainer.addView(rightSpacer)
        
        // 添加到系统消息容器
        systemMessagesContent?.addView(messageContainer)
        
        // 更新计数
        systemMessageCount++
        updateSystemMessagesTitle()
    }
    
    /**
     * 创建系统消息折叠容器
     */
    private fun createSystemMessagesContainer() {
        // 创建主容器
        systemMessagesContainer = android.widget.LinearLayout(requireContext()).apply {
            orientation = android.widget.LinearLayout.VERTICAL
            layoutParams = android.widget.LinearLayout.LayoutParams(
                android.widget.LinearLayout.LayoutParams.MATCH_PARENT,
                android.widget.LinearLayout.LayoutParams.WRAP_CONTENT
            ).apply {
                setMargins(0, 8, 0, 8)
            }
        }
        
        // 创建标题栏（可点击）
        systemMessagesTitle = android.widget.TextView(requireContext()).apply {
            text = getString(R.string.system_messages_format, 0, getString(R.string.system_messages_collapsed))
            textSize = 11f  // 系统消息标题：11sp（小两个号）
            setPadding(14, 6, 14, 6)  // 减小上下内边距，让高度更紧凑
            setBackgroundColor(0xFFF9F9F9.toInt())  // 浅灰色背景，与聊天内容一致
            setTextColor(0xFF333333.toInt())
            
            // 点击切换展开/折叠
            setOnClickListener {
                toggleSystemMessages()
            }
            
            layoutParams = android.widget.LinearLayout.LayoutParams(
                android.widget.LinearLayout.LayoutParams.MATCH_PARENT,
                android.widget.LinearLayout.LayoutParams.WRAP_CONTENT
            )
        }
        systemMessagesContainer?.addView(systemMessagesTitle)
        
        // 创建内容容器（默认隐藏）
        systemMessagesContent = android.widget.LinearLayout(requireContext()).apply {
            orientation = android.widget.LinearLayout.VERTICAL
            layoutParams = android.widget.LinearLayout.LayoutParams(
                android.widget.LinearLayout.LayoutParams.MATCH_PARENT,
                android.widget.LinearLayout.LayoutParams.WRAP_CONTENT
            )
            visibility = android.view.View.GONE
        }
        systemMessagesContainer?.addView(systemMessagesContent)
        
        // 注意：这个方法现在不再使用，系统消息通过RecyclerView Adapter管理
        // 保留此方法仅为了兼容性，但不再添加到视图
    }
    
    /**
