        // 更新计数和标题
        systemMessageCount++
        updateSystemMessagesTitle()
    }
    
    /**
     * 切换系统消息展开/折叠状态
     */
    internal fun toggleSystemMessages() {
        isSystemMessagesExpanded = !isSystemMessagesExpanded
        systemMessagesScrollView?.visibility = if (isSystemMessagesExpanded) {
            android.view.View.VISIBLE
        } else {
            android.view.View.GONE
        }
        updateSystemMessagesTitle()
    }
    
    /**
     * 更新系统消息标题
     */
    private fun updateSystemMessagesTitle() {
        if (systemMessageCount > 0) {
            systemMessagesTitle?.text = getString(R.string.system_messages_format, systemMessageCount, getString(if (isSystemMessagesExpanded) R.string.system_messages_expanded else R.string.system_messages_collapsed))
            systemMessagesTitle?.visibility = android.view.View.VISIBLE
        } else {
            systemMessagesTitle?.visibility = android.view.View.GONE
        }
    }
    
    /**
     * 滚动到底部
     */
    /**
     * 滚动到顶部（显示最旧的消息）
     * 正向布局模式下，位置0是最旧的消息
     */
    private fun scrollToTop() {
        binding.rvChatMessages.post {
            val adapter = chatAdapter ?: return@post
            if (adapter.itemCount > 0) {
                binding.rvChatMessages.scrollToPosition(0)
            }
        }
    }
    
    /**
     * 滚动到底部（显示最新消息）
     */
    internal fun scrollToBottom() {
        binding.rvChatMessages.post {
            val adapter = chatAdapter ?: return@post
            if (adapter.itemCount > 0) {
                binding.rvChatMessages.scrollToPosition(adapter.itemCount - 1)
            }
            // 滚动后检查按钮可见性
            checkScrollToBottomButtonVisibility()
        }
    }
    
    /**
     * 检查是否滚动到底部，控制滚动到底部按钮的显示/隐藏
     * 取中间值：当最后一个可见项是最后一项或倒数第二项时，认为到底部了
     */
    internal fun checkScrollToBottomButtonVisibility() {
        val layoutManager = binding.rvChatMessages.layoutManager as? LinearLayoutManager ?: return
        val adapter = chatAdapter ?: return
        
        val itemCount = adapter.itemCount
        if (itemCount == 0) {
            binding.btnScrollToBottom.visibility = android.view.View.GONE
            return
        }
        
        val lastVisiblePosition = layoutManager.findLastVisibleItemPosition()
        
        // 取中间值：当最后一个可见项是最后一项或倒数第二项时，认为到底部了
        // 这样既不会太早消失，也不会在真正到底部时还显示
        val isAtBottom = lastVisiblePosition >= itemCount - 2
        
        // 如果不在底部，显示按钮；如果在底部，隐藏按钮
        binding.btnScrollToBottom.visibility = if (isAtBottom) android.view.View.GONE else android.view.View.VISIBLE
    }
    
    /**
     * 根据消息数量决定滚动行为
     * 如果消息不足一页，置顶显示；如果超过一页，滚动到底部
     */
    private fun updateScrollBehavior() {
        val layoutManager = binding.rvChatMessages.layoutManager as? LinearLayoutManager
        val adapter = chatAdapter
        val itemCount = adapter?.itemCount ?: 0
        
        if (itemCount <= MESSAGES_PER_PAGE) {
            // 消息不足一页，置顶显示
            layoutManager?.stackFromEnd = false
        } else {
            // 消息超过一页，从底部开始显示，滚动到底部
            layoutManager?.stackFromEnd = true
            scrollToBottom()
        }
    }
    
    /**
     * 加载更多历史消息（向上滚动加载更旧的消息）
     */
    internal fun loadMoreHistoryMessages() {
        if (isLoadingMore || !hasMoreMessages) {
            return
        }
        
        isLoadingMore = true
        
        // 计算需要加载的消息范围（更旧的消息）
        val startIndex = chatMessages.size - loadedMessageCount - MESSAGES_PER_PAGE
        val endIndex = chatMessages.size - loadedMessageCount
        
        if (startIndex < 0) {
            // 没有更多消息了
            hasMoreMessages = false
            isLoadingMore = false
            return
        }
        
        // 获取要加载的消息（从旧到新）
        val messagesToLoad = chatMessages.subList(startIndex, endIndex)
        
        val adapter = chatAdapter ?: run {
            isLoadingMore = false
            return
        }
        
        // 保存当前滚动位置（顶部位置，用于恢复滚动位置）
        val layoutManager = binding.rvChatMessages.layoutManager as? LinearLayoutManager
        val firstVisiblePosition = layoutManager?.findFirstVisibleItemPosition() ?: 0
        val firstVisibleView = layoutManager?.findViewByPosition(firstVisiblePosition)
        val offset = firstVisibleView?.top ?: 0
        
        // 正向遍历消息列表，从旧到新插入到顶部（位置0），这样更旧的消息显示在顶部
        var lastTimestamp: Long = 0
        for (i in 0 until messagesToLoad.size) {
            val chatMessage = messagesToLoad[i]
            // 重新解析发送者名称（如果有senderImei，从好友列表获取昵称）
            val resolvedSender = resolveSenderDisplayName(chatMessage.sender, chatMessage.senderImei)
            val isComplete = chatMessage.type == "complete"
            val isAnswer = chatMessage.type == "answer"
            val isUserMsg = isUserMessageForDisplay(resolvedSender)
            
            // 检查是否需要显示时间（与上一条消息比较）
            val shouldShowTime = lastTimestamp == 0L || 
                (chatMessage.timestamp - lastTimestamp) > 10 * 60 * 1000
            
            if (shouldShowTime) {
                adapter.addItemAt(0, ChatItem.TimeStamp(chatMessage.timestamp))
            }
            lastTimestamp = chatMessage.timestamp
            
            // 插入消息到顶部（位置0），更旧的消息显示在顶部
            when {
                chatMessage.type == "image" && _binding != null -> {
                    // 图片消息处理：优先使用保存的imagePath字段
                    val imagePathToUse = chatMessage.imagePath
                    val imageFile = if (imagePathToUse != null) {
                        java.io.File(imagePathToUse)
                    } else {
                        // 兼容旧格式：从消息中提取图片文件名（支持中文和英文冒号）
                        val messageParts = chatMessage.message.split("\n")
                        val imageFileName = messageParts.find { 
                            it.startsWith("[图片: ") || it.startsWith("[图片：")
                        }?.let { part ->
                            when {
                                part.startsWith("[图片: ") -> part.removePrefix("[图片: ").removeSuffix("]")
                                part.startsWith("[图片：") -> part.removePrefix("[图片：").removeSuffix("]")
                                else -> ""
                            }
                        } ?: ""
                        if (imageFileName.isNotEmpty()) {
                            val imagesDir = java.io.File(requireContext().getExternalFilesDir(null), "images")
                            java.io.File(imagesDir, imageFileName)
                        } else {
                            null
                        }
                    }
                    
                    if (imageFile != null && imageFile.exists()) {
                        // 从消息中提取文本内容，去除图片标记（支持中文和英文冒号）
                        val messageParts = chatMessage.message.split("\n")
                        val queryText = messageParts.filter { 
                            !it.startsWith("[图片: ") && !it.startsWith("[图片：")
                        }.joinToString("\n").trim()
                        
                        // 判断是用户发送的图片还是接收到的图片
                        if (chatMessage.senderImei != null || !isUserMsg) {
                            adapter.addItemAt(0, ChatItem.ReceivedImageMessage(imageFile.absolutePath, queryText, resolvedSender, chatMessage.timestamp, chatMessage.senderImei))
                        } else {
                            adapter.addItemAt(0, ChatItem.ImageMessage(imageFile.absolutePath, queryText, chatMessage.timestamp, isUserMessage = true, senderName = resolvedSender))
                        }
                    } else {
                        adapter.addItemAt(
                            0,
                            ChatItem.Message(
                                sender = resolvedSender,
                                message = chatMessage.message,
                                isUserMessage = isUserMsg,
                                isComplete = isComplete,
                                isAnswer = isAnswer,
                                timestamp = chatMessage.timestamp,
                                senderImei = chatMessage.senderImei
                            )
                        )
                    }
                }
                chatMessage.type == "video" && _binding != null -> {
                    // 视频消息处理
                    val videoFileName = chatMessage.message.removePrefix("[视频: ").removeSuffix("]")
                    val recordingsDir = java.io.File(requireContext().getExternalFilesDir(null), "recordings")
                    val videoFile = java.io.File(recordingsDir, videoFileName)
                    if (videoFile.exists()) {
                        addVideoMessage(videoFile.absolutePath, saveToHistory = false)
                    } else {
                        adapter.addItemAt(
                            0,
                            ChatItem.Message(
                                sender = resolvedSender,
                                message = chatMessage.message,
                                isUserMessage = isUserMsg,
                                isComplete = isComplete,
                                isAnswer = isAnswer,
                                timestamp = chatMessage.timestamp,
                                senderImei = chatMessage.senderImei
                            )
                        )
                    }
                }
                else -> {
                    // 首先检查是否是技能消息（优先使用保存的skillId字段）
                    val skill = if (chatMessage.skillId != null && chatMessage.skillId.isNotEmpty()) {
                        // 优先使用保存的技能ID查找技能
                        findSkillById(chatMessage.skillId) ?: run {
                            // 如果通过ID找不到，尝试从消息文本解析
                            Log.d(TAG, "加载更多消息时，通过skillId未找到技能: ${chatMessage.skillId}，尝试从消息文本解析")
                            val parsedSkill = parseSkillFromMessage(chatMessage.message)
                            if (parsedSkill != null) {
                                // 从消息中解析出技能，但使用原始的skillId（而不是临时ID）
                                val skillWithOriginalId = parsedSkill.copy(id = chatMessage.skillId)
                                // 保存到临时技能存储，确保退出重进后也能找到
                                TemporarySkillManager.saveTemporarySkill(requireContext(), skillWithOriginalId, currentConversation?.id)
                                Log.d(TAG, "从消息解析出技能并保存到临时存储: skillId=${chatMessage.skillId}, title=${skillWithOriginalId.title}")
                                skillWithOriginalId
                            } else {
                                // 如果解析失败，尝试通过标题查找
                                val skillTitle = extractSkillTitleFromMessage(chatMessage.message)
                                skillTitle?.let { findSkillByTitle(it, chatMessage.message) }
                            }
                        }
                    } else {
                        // 兼容旧格式：通过消息格式识别
                        val skillTitle = extractSkillTitleFromMessage(chatMessage.message)
                        if (skillTitle != null) {
                            findSkillByTitle(skillTitle, chatMessage.message)
                        } else {
                            null
                        }
                    }
                    
                    if (skill != null) {
                        // 找到技能，显示为技能卡片
                        adapter.addItemAt(0, ChatItem.SkillMessage(skill, chatMessage.sender, chatMessage.timestamp, isUserMsg, chatMessage.senderImei))
                        continue
                    } else {
                        // 如果通过skillId找不到技能，保存到待恢复列表（等待技能加载完成后再尝试）
                        if (chatMessage.skillId != null && chatMessage.skillId.isNotEmpty()) {
                            Log.w(TAG, "加载更多消息时，通过skillId未找到技能: ${chatMessage.skillId}，保存到待恢复列表")
                            pendingSkillMessages.add(chatMessage)
                        }
                    }
                    // 如果找不到技能，继续显示为普通文本消息
                    
                    // 普通消息
                    if (!isUserMsg && !isComplete && !isAnswer && chatMessage.message != "开始学习~") {
                        // 系统消息，添加到系统消息容器
                        addSystemMessageToFixedContainer(resolvedSender, chatMessage.message)
                    } else {
                        adapter.addItemAt(
                            0,
                            ChatItem.Message(
                                sender = resolvedSender,
                                message = chatMessage.message,
                                isUserMessage = isUserMsg,
                                isComplete = isComplete,
                                isAnswer = isAnswer,
                                timestamp = chatMessage.timestamp,
                                senderImei = chatMessage.senderImei
                            )
                        )
                    }
                }
            }
        }
        
        // 更新已加载消息计数
        loadedMessageCount += messagesToLoad.size
        
        // 检查是否还有更多消息
        hasMoreMessages = startIndex > 0
        
        // 恢复滚动位置（保持用户看到的第一个消息位置不变）
        binding.rvChatMessages.post {
            if (firstVisiblePosition >= 0 && firstVisiblePosition < adapter.itemCount) {
                layoutManager?.scrollToPositionWithOffset(firstVisiblePosition + messagesToLoad.size, offset)
            }
        }
        
        isLoadingMore = false
    }
    
    /**
     * 根据时间戳删除消息
     */
    private fun deleteMessageByTimestamp(timestamp: Long) {
        try {
            // 从chatMessages列表中移除
            val removed = chatMessages.removeAll { it.timestamp == timestamp }
            if (removed) {
                // 保存更新后的消息列表
                saveChatMessages()
                
                // 从adapter的items中移除对应的消息项
                val adapter = chatAdapter
                if (adapter != null) {
                    val items = adapter.getItems()
                    val indexToRemove = items.indexOfFirst { item ->
                        when (item) {
                            is ChatItem.Message -> item.timestamp == timestamp
                            is ChatItem.ImageMessage -> item.timestamp == timestamp
                            else -> false
                        }
                    }
                    
                    if (indexToRemove >= 0) {
                        // 移除消息项
                        adapter.removeItemAt(indexToRemove)
                        
                        // 检查是否需要移除时间戳（如果时间戳下没有其他消息）
                        if (indexToRemove > 0 && items[indexToRemove - 1] is ChatItem.TimeStamp) {
                            // 检查时间戳后是否还有其他消息
                            var hasOtherMessages = false
                            for (i in indexToRemove until items.size) {
                                if (items[i] is ChatItem.Message || items[i] is ChatItem.ImageMessage) {
                                    hasOtherMessages = true
                                    break
                                }
                                if (items[i] is ChatItem.TimeStamp) {
                                    break
                                }
                            }
                            
                            // 如果时间戳下没有其他消息，也移除时间戳
                            if (!hasOtherMessages) {
                                adapter.removeItemAt(indexToRemove - 1)
                            }
                        }
                        
                        Toast.makeText(requireContext(), "已删除该条消息", Toast.LENGTH_SHORT).show()
                    }
                }
            }
        } catch (e: Exception) {
            Log.e(TAG, "删除消息失败: ${e.message}", e)
            Toast.makeText(requireContext(), "删除失败", Toast.LENGTH_SHORT).show()
        }
    }
    
    /**
     * 进入多选模式
     */
    private fun enterMultiSelectMode(initialTimestamp: Long) {
        if (isMultiSelectMode) return
        
        isMultiSelectMode = true
        selectedMessageTimestamps.clear()
        selectedMessageTimestamps.add(initialTimestamp)
        
        // 创建并显示多选工具栏
        createMultiSelectToolbar()
        
        // 刷新adapter以显示选中状态（使用 payload 优化）
        chatAdapter?.notifyMultiSelectModeChanged()
        
        Log.d(TAG, "进入多选模式，初始选中消息: $initialTimestamp")
    }
    
    /**
     * 退出多选模式
     */
    private fun exitMultiSelectMode() {
        if (!isMultiSelectMode) return
        
        isMultiSelectMode = false
        selectedMessageTimestamps.clear()
        
        // 移除多选工具栏（而不是只隐藏）
        try {
            multiSelectToolbar?.let { toolbar ->
                val parent = toolbar.parent as? android.view.ViewGroup
                parent?.removeView(toolbar)
            }
            multiSelectToolbar = null
        } catch (e: Exception) {
            Log.e(TAG, "移除多选工具栏失败: ${e.message}", e)
            // 如果移除失败，至少隐藏它
            multiSelectToolbar?.visibility = View.GONE
        }
        
        // 刷新adapter以隐藏选中状态（使用 payload 优化）
        chatAdapter?.notifyMultiSelectModeChanged()
        
        Log.d(TAG, "退出多选模式")
    }
    
    /**
     * 切换消息选中状态（供 ChatAdapter 调用）
     */
    fun toggleMessageSelection(timestamp: Long) {
        if (!isMultiSelectMode) return
        
        if (selectedMessageTimestamps.contains(timestamp)) {
            selectedMessageTimestamps.remove(timestamp)
        } else {
            selectedMessageTimestamps.add(timestamp)
        }
        
        // 更新工具栏显示
        updateMultiSelectToolbar()
        
        // 刷新adapter以更新选中状态（使用 payload 优化）
        chatAdapter?.notifySelectionChanged()
        
        Log.d(TAG, "切换消息选中状态: $timestamp, 当前选中数量: ${selectedMessageTimestamps.size}")
    }
    
