        try {
            val titleBar = binding.llTitleBar
            val parentContainer = titleBar.parent as? android.view.ViewGroup
            
            if (parentContainer != null) {
                // 检查是否已经有父容器，如果有先移除
                val currentParent = toolbar.parent as? android.view.ViewGroup
                currentParent?.removeView(toolbar)
                
                // 找到titleBar在父容器中的索引
                val titleBarIndex = parentContainer.indexOfChild(titleBar)
                
                // 设置工具栏的布局参数
                val layoutParams = android.view.ViewGroup.LayoutParams(
                    android.view.ViewGroup.LayoutParams.MATCH_PARENT,
                    android.view.ViewGroup.LayoutParams.WRAP_CONTENT
                )
                toolbar.layoutParams = layoutParams
                
                // 插入到titleBar下面（索引+1），紧贴标题栏
                parentContainer.addView(toolbar, titleBarIndex + 1)
                multiSelectToolbar = toolbar
                
                // 更新工具栏显示
                updateMultiSelectToolbar()
                
                Log.d(TAG, "多选工具栏已创建并添加到标题栏下方")
            } else {
                Log.e(TAG, "无法获取标题栏的父容器，无法添加多选工具栏")
                // 如果失败，尝试添加到根布局底部（降级方案）
                val rootView = _binding?.root
                if (rootView != null && rootView is android.view.ViewGroup) {
                    val rootLayout = rootView as android.view.ViewGroup
                    val currentParent = toolbar.parent as? android.view.ViewGroup
                    currentParent?.removeView(toolbar)
                    
                    val layoutParams = android.widget.FrameLayout.LayoutParams(
                        android.view.ViewGroup.LayoutParams.MATCH_PARENT,
                        android.view.ViewGroup.LayoutParams.WRAP_CONTENT
                    ).apply {
                        gravity = android.view.Gravity.BOTTOM
                    }
                    toolbar.layoutParams = layoutParams
                    rootLayout.addView(toolbar)
                    multiSelectToolbar = toolbar
                    updateMultiSelectToolbar()
                    Log.d(TAG, "多选工具栏已添加到根布局底部（降级方案）")
                }
            }
        } catch (e: Exception) {
            Log.e(TAG, "添加多选工具栏失败: ${e.message}", e)
            e.printStackTrace()
            // 如果添加失败，至少设置引用，避免后续空指针
            multiSelectToolbar = toolbar
        }
    }
    
    /**
     * 更新多选工具栏显示
     */
    private fun updateMultiSelectToolbar() {
        val toolbar = multiSelectToolbar ?: return
        
        // 更新选中数量
        val countText = toolbar.findViewWithTag<TextView>("countText")
        countText?.text = "已选中 ${selectedMessageTimestamps.size} 条"
        
        // 更新全选按钮文本
        val selectAllButton = toolbar.findViewWithTag<TextView>("selectAllButton")
        val adapter = chatAdapter ?: return
        val items = adapter.getItems()
        val messageCount = items.count { it is ChatItem.Message || it is ChatItem.ImageMessage }
        val isAllSelected = messageCount > 0 && selectedMessageTimestamps.size >= messageCount
        selectAllButton?.text = if (isAllSelected) "取消全选" else "全选"
        
        // 根据选中数量更新分享/删除按钮状态
        val hasSelection = selectedMessageTimestamps.isNotEmpty()
        val shareButton = toolbar.findViewWithTag<TextView>("shareButton")
        shareButton?.isEnabled = hasSelection
        shareButton?.setTextColor(if (hasSelection) 0xFF2196F3.toInt() else 0xFFCCCCCC.toInt())

        val deleteButton = toolbar.findViewWithTag<TextView>("deleteButton")
        deleteButton?.isEnabled = hasSelection
        deleteButton?.setTextColor(if (hasSelection) 0xFFF44336.toInt() else 0xFFCCCCCC.toInt())
    }

    /**
     * 多选消息生成分享图并进入预览
     */
    private fun shareSelectedMessagesAsImage() {
        if (selectedMessageTimestamps.isEmpty()) {
            Toast.makeText(requireContext(), "请先选择要分享的消息", Toast.LENGTH_SHORT).show()
            return
        }
        val selectedItems = buildSelectedShareableConversationItems()
        if (selectedItems.isEmpty()) {
            Toast.makeText(requireContext(), "暂无可分享内容", Toast.LENGTH_SHORT).show()
            return
        }
        showGeneratedShareImagePreviewFromConversation(selectedItems)
    }

    /**
     * 获取已选择的可分享会话消息（按时间升序）
     */
    private fun buildSelectedShareableConversationItems(): List<ChatItem> {
        val adapter = chatAdapter ?: return emptyList()
        return adapter.getItems().mapNotNull { item ->
            when (item) {
                is ChatItem.Message -> {
                    if (!selectedMessageTimestamps.contains(item.timestamp)) return@mapNotNull null
                    item
                }
                is ChatItem.ImageMessage -> {
                    if (!selectedMessageTimestamps.contains(item.timestamp)) return@mapNotNull null
                    item
                }
                else -> null
            }
        }.sortedBy {
            when (it) {
                is ChatItem.Message -> it.timestamp
                is ChatItem.ImageMessage -> it.timestamp
                else -> Long.MAX_VALUE
            }
        }
    }
    
    /**
     * 全选/取消全选
     */
    private fun toggleSelectAll() {
        val adapter = chatAdapter ?: return
        val items = adapter.getItems()
        val messageItems = items.filter { it is ChatItem.Message || it is ChatItem.ImageMessage }
        
        val messageCount = messageItems.size
        val selectedCount = selectedMessageTimestamps.size
        
        if (selectedCount >= messageCount) {
            // 取消全选
            selectedMessageTimestamps.clear()
        } else {
            // 全选
            messageItems.forEach { item ->
                when (item) {
                    is ChatItem.Message -> selectedMessageTimestamps.add(item.timestamp)
                    is ChatItem.ImageMessage -> selectedMessageTimestamps.add(item.timestamp)
                    else -> {}
                }
            }
        }
        
        updateMultiSelectToolbar()
        // 刷新adapter以更新选中状态（使用 payload 优化）
        chatAdapter?.notifySelectionChanged()
        
        Log.d(TAG, "全选/取消全选，当前选中数量: ${selectedMessageTimestamps.size}")
    }
    
    /**
     * 删除选中的消息
     */
    private fun deleteSelectedMessages() {
        if (selectedMessageTimestamps.isEmpty()) {
            Toast.makeText(requireContext(), "请先选择要删除的消息", Toast.LENGTH_SHORT).show()
            return
        }
        
        // 确认对话框
        android.app.AlertDialog.Builder(requireContext())
            .setTitle("确认删除")
            .setMessage("确定要删除选中的 ${selectedMessageTimestamps.size} 条消息吗？")
            .setPositiveButton("删除") { _, _ ->
                try {
                    val timestampsToDelete = selectedMessageTimestamps.toList()
                    
                    // 从chatMessages列表中移除
                    val removed = chatMessages.removeAll { it.timestamp in timestampsToDelete }
                    
                    if (removed) {
                        // 保存更新后的消息列表
                        saveChatMessages()
                        
                        // 从adapter的items中移除对应的消息项
                        val adapter = chatAdapter
                        if (adapter != null) {
                            val items = adapter.getItems()
                            val indicesToRemove = mutableListOf<Int>()
                            
                            // 收集需要删除的索引（从后往前，避免索引变化）
                            items.forEachIndexed { index, item ->
                                when (item) {
                                    is ChatItem.Message -> {
                                        if (item.timestamp in timestampsToDelete) {
                                            indicesToRemove.add(index)
                                        }
                                    }
                                    is ChatItem.ImageMessage -> {
                                        if (item.timestamp in timestampsToDelete) {
                                            indicesToRemove.add(index)
                                        }
                                    }
                                    else -> {}
                                }
                            }
                            
                            // 从后往前删除，避免索引变化
                            indicesToRemove.sortedDescending().forEach { index ->
                                adapter.removeItemAt(index)
                            }
                        }
                        
                        Toast.makeText(requireContext(), "已删除 ${timestampsToDelete.size} 条消息", Toast.LENGTH_SHORT).show()
                        
                        // 退出多选模式
                        exitMultiSelectMode()
                    }
                } catch (e: Exception) {
                    Log.e(TAG, "批量删除消息失败: ${e.message}", e)
                    Toast.makeText(requireContext(), "删除失败", Toast.LENGTH_SHORT).show()
                }
            }
            .setNegativeButton("取消", null)
            .show()
    }
    
    /**
     * 检查消息是否被选中
     */
    internal fun isMessageSelected(timestamp: Long): Boolean {
        return isMultiSelectMode && selectedMessageTimestamps.contains(timestamp)
    }
    
    /**
     * 生成消息的唯一标识（用于去重）
     * 使用timestamp+sender+message的前100个字符的hash，保证高效且唯一
     */
    private fun rawMessageHash(message: ChatMessage): String {
        // 不包含 uuid：adapter 中的 ChatItem 不存储 uuid，重建后 uuid 为空，
        // 导致 adapter 侧与 ViewModel 侧哈希不一致、dedup 失效、消息重复（与 ChatViewModel.generateMessageHash 对齐）
        val messageHash = message.message.hashCode()
        return "${message.timestamp}_${message.sender}_$messageHash"
    }

    /** 好友私聊用逻辑键去重（与 FriendChatMessagePrefsStore / ViewModel 一致） */
    private fun messageHashForDedup(message: ChatMessage): String {
        return if (currentConversation?.id?.startsWith("friend_") == true) {
            FriendChatMessagePrefsStore.logicalDedupKeyFromMessage(message)
        } else {
            rawMessageHash(message)
        }
    }

    /** 从已展示的 ChatItem 还原好友逻辑去重键（与 logicalDedupKeyFromMessage 对齐：优先 IMEI，避免「好友」与昵称不一致） */
    private fun adapterLogicalKeyForFriendRestore(item: ChatItem): String? {
        val convId = currentConversation?.id ?: return null
        val peerImei = if (convId.startsWith("friend_")) convId.removePrefix("friend_").takeIf { it.isNotBlank() } else null
        return when (item) {
            is ChatItem.Message -> {
                val typeStr = when {
                    item.isUserMessage -> "user"
                    item.isComplete -> "complete"
                    item.isAnswer -> "answer"
                    else -> "system"
                }
                val sim = when {
                    item.isUserMessage -> null
                    peerImei != null -> peerImei
                    else -> null
                }
                FriendChatMessagePrefsStore.logicalDedupKeyFromMessage(
                    ChatMessage(item.sender, item.message, typeStr, item.timestamp, senderImei = sim)
                )
            }
            is ChatItem.ReceivedImageMessage -> FriendChatMessagePrefsStore.logicalDedupKeyFromMessage(
                ChatMessage(
                    item.senderName,
                    item.query,
                    "image",
                    item.timestamp,
                    senderImei = item.senderImei?.takeIf { it.isNotBlank() } ?: peerImei
                )
            )
            is ChatItem.ImageMessage -> FriendChatMessagePrefsStore.logicalDedupKeyFromMessage(
                ChatMessage(item.senderName ?: "我", item.query, "image", item.timestamp)
            )
            is ChatItem.SkillMessage -> FriendChatMessagePrefsStore.logicalDedupKeyFromMessage(
                ChatMessage(
                    item.sender,
                    item.skill.title,
                    "skill",
                    item.timestamp,
                    "",
                    null,
                    item.skill.id,
                    item.senderImei?.takeIf { it.isNotBlank() } ?: peerImei
                )
            )
            else -> null
        }
    }
    
    /**
     * 解析远程指令，提取@用户名和实际指令
     * @param message 原始消息
     * @return RemoteCommand对象，如果没有@其他用户则返回null
     */
    private fun parseRemoteCommand(message: String): RemoteCommand? {
        // 匹配@用户名模式（排除@TopoClaw等）
        val userMentionPattern = "@([^@\\s]+)".toRegex()
        val mentions = userMentionPattern.findAll(message).toList()
        
        // 过滤掉小助手相关的@
        val assistantMentions = listOf(
            ChatConstants.ASSISTANT_DISPLAY_NAME,
            ChatConstants.ASSISTANT_LEGACY_INTERNAL_NAME,
            ChatConstants.ASSISTANT_LEGACY_TOPOCLAW_NAME,
            "小助手",
            "assistant",
            "自动执行助手",
        )
        val userMentions = mentions.filter { mention ->
            val username = mention.groupValues[1]
            !assistantMentions.any { assistant -> username.contains(assistant, ignoreCase = true) }
        }
        
        // 如果没有@其他用户，返回null
        if (userMentions.isEmpty()) {
            return null
        }
        
        // 取第一个@的用户作为目标用户
        val targetUsername = userMentions[0].groupValues[1]
        
        // 提取实际指令（移除所有@提及，使用正则表达式更精确）
        var command = ChatConstants.stripMainAssistantMentions(message)
        // 移除小助手别名相关
        command = command
            .replace("@小助手", "", ignoreCase = true)
            .replace("@assistant", "", ignoreCase = true)
            .replace("@自动执行助手", "", ignoreCase = true)
        // 移除目标用户的@提及（精确匹配）
        command = command.replace("@$targetUsername", "", ignoreCase = true)
        // 清理多余空格
        command = command.replace(Regex("\\s+"), " ").trim()
        
        return RemoteCommand(targetUsername, command)
    }
    
    /**
     * 根据用户名查找IMEI（从群组成员和好友列表中查找）
     * @param username 用户名或昵称
     * @param groupId 群组ID
     * @return IMEI，如果找不到返回null
     */
    private fun findImeiByUsername(username: String, groupId: String): String? {
        val currentImei = ProfileManager.getOrGenerateImei(requireContext())
        
        // 1. 从群组成员中查找
        val group = GroupManager.getGroup(requireContext(), groupId)
        group?.members?.forEach { imei ->
            if (imei == currentImei) {
                // 检查是否是自己的昵称
                val profile = ProfileManager.loadProfileLocally(requireContext())
                if (profile?.name == username || username == "我") {
                    return imei
                }
            } else {
                // 检查好友昵称或IMEI前8位
                val friend = FriendManager.getFriend(requireContext(), imei)
                if (friend?.nickname == username || imei.take(8) == username) {
                    return imei
                }
            }
        }
        
        // 2. 从好友列表中查找
        val friends = FriendManager.getFriends(requireContext())
        friends.find { it.nickname == username }?.imei?.let { return it }
        
        // 3. 尝试直接匹配IMEI（如果用户输入的是IMEI）
        if (group?.members?.contains(username) == true) {
            return username
        }
        
        return null
    }
    
    /**
     * 查找消息对应的IMEI（用于管理员回复）
     * 优先使用简单的sender+message匹配，不依赖timestamp，确保所有消息都能找到
     */
    private fun findImeiForMessage(sender: String, message: String, timestamp: Long? = null): String? {
        // 优先使用简单映射（sender, message）-> IMEI，不依赖timestamp
        // 这是最可靠的方式，因为不依赖timestamp，确保所有消息都能找到
        val simpleImei = messageSimpleImeiMap[Pair(sender, message)]
        if (simpleImei != null) {
            Log.d(TAG, "通过简单映射找到IMEI: sender=$sender, message=${message.take(30)}")
            return simpleImei
        }
        
        // 如果简单映射中没有，尝试从chatMessages中查找匹配的消息（使用hash查找）
        val actualMessage = chatMessages.find { 
            it.sender == sender && it.message == message
        }
        
        // 如果找到匹配，使用其hash查找
        if (actualMessage != null) {
            val messageHash = messageHashForDedup(actualMessage)
            val imei = messageImeiMap[messageHash]
            if (imei != null) {
                Log.d(TAG, "通过hash映射找到IMEI: sender=$sender, message=${message.take(30)}")
                return imei
            }
        }
        
        // 如果timestamp不为null，尝试使用timestamp的精确匹配（作为备用）
        if (timestamp != null) {
            val directImei = messageDirectImeiMap[Triple(sender, message, timestamp)]
            if (directImei != null) {
                Log.d(TAG, "通过timestamp精确匹配找到IMEI: sender=$sender, message=${message.take(30)}")
                return directImei
            }
            
            // 尝试使用不同的type值生成hash查找（优先尝试user_message）
            val possibleTypes = listOf("user_message", "user", "text", "system")
            for (type in possibleTypes) {
                val testHash = messageHashForDedup(ChatMessage(sender, message, type, timestamp, ""))
                val imei = messageImeiMap[testHash]
                if (imei != null) {
                    Log.d(TAG, "通过type遍历找到IMEI: sender=$sender, message=${message.take(30)}, type=$type")
                    return imei
                }
            }
        }
        
        // 最后尝试：遍历所有直接映射，只匹配sender和message（完全忽略timestamp）
        for ((key, value) in messageDirectImeiMap) {
            if (key.first == sender && key.second == message) {
                Log.d(TAG, "通过遍历直接映射找到IMEI: sender=$sender, message=${message.take(30)}")
                return value
            }
        }
        
        Log.w(TAG, "无法找到IMEI: sender=$sender, message=${message.take(30)}")
        return null
    }
    
    /**
     * 添加消息到列表（带去重检查）
     * 去重逻辑：1）连续两条 sender+content 完全相同则跳过；2）messageHashSet 已有的也跳过
     */
    private fun addMessageToList(message: ChatMessage): Boolean {
        // 连续完全相同去重：不区分来源，只要上一条消息 sender+content 完全一致就不添加
        if (chatMessages.isNotEmpty()) {
            val last = chatMessages.last()
            if (last.sender == message.sender && last.message == message.message) {
                Log.d(TAG, "连续重复消息，跳过: ${message.sender} - ${message.message.take(50)}")
                return false
            }
        }
        val messageHash = messageHashForDedup(message)
        if (!messageHashSet.contains(messageHash)) {
            chatMessages.add(message)
            messageHashSet.add(messageHash)
            // 同时添加到 ViewModel
            try {
                getViewModel().addMessage(message)
            } catch (e: Exception) {
                Log.w(TAG, "添加消息到 ViewModel 失败: ${e.message}", e)
            }
            return true
        } else {
            Log.d(TAG, "检测到重复消息，跳过: ${message.sender} - ${message.message.take(50)}")
            return false
        }
    }
    
    /**
     * 防抖保存聊天记录（延迟300ms，避免频繁保存）
     */
    private fun saveChatMessagesDebounced() {
        // 取消之前的保存任务
        saveJob?.cancel()
        // 创建新的保存任务（延迟300ms）
        saveJob = mainScope.launch(Dispatchers.IO) {
            delay(300)
            saveChatMessages()
        }
    }
    
    /**
     * 保存聊天记录到SharedPreferences（通过 ViewModel）
     * @param sync 是否同步保存（使用commit），默认false使用apply异步保存
     */
    private fun saveChatMessages(sync: Boolean = false) {
        try {
            // 检查Fragment是否还存在
            val context = context ?: return
            
            // 确保 currentConversation 已同步（从 arguments 恢复）
            ensureCurrentConversationSynced()
            
            val conversationId = currentConversation?.id
                ?: arguments?.getSerializable("conversation")?.let { (it as? Conversation)?.id }
                ?: viewModelConversationId
                ?: "default"
            
            val vm = getViewModel()
            
            // 多 session 自定义小助手时传入 sessionId
            val sessionId = CustomAssistantManager.getById(requireContext(), conversationId)
                ?.takeIf { it.multiSession }
                ?.let { currentSessionIdForMultiSession }
            
            // 校验 ViewModel 的 conversationId 是否一致
            val vmConversationId = vm.getCurrentConversationId()
            if (vmConversationId != null && vmConversationId != conversationId) {
                Log.w(TAG, "保存时 conversationId 不一致！ViewModel: $vmConversationId, 当前: $conversationId，使用 ViewModel 的 ID")
                // 使用 ViewModel 的 conversationId，确保一致性
                val finalConversationId = vmConversationId
                syncAdapterToViewModel()
                val finalSessionId = CustomAssistantManager.getById(requireContext(), finalConversationId)
                    ?.takeIf { it.multiSession }
                    ?.let { currentSessionIdForMultiSession }
                vm.saveMessagesToPrefs(context, finalConversationId, sync, finalSessionId)
                Log.d(TAG, "保存消息 - 已通过 ViewModel 保存，对话ID: $finalConversationId")
            } else {
                // 确保 ViewModel 中的数据是最新的（从 adapter 同步）
                syncAdapterToViewModel()
                
                // 使用 ViewModel 的保存方法
                vm.saveMessagesToPrefs(context, conversationId, sync, sessionId)
                Log.d(TAG, "保存消息 - 已通过 ViewModel 保存，对话ID: $conversationId")
            }
        } catch (e: Exception) {
            Log.e(TAG, "保存聊天记录失败: ${e.message}", e)
        }
    }
    
    /**
     * 确保 currentConversation 已从 arguments 同步
     * 如果 arguments 中的 conversation 与 currentConversation 不一致，以 arguments 为准
     */
    private fun ensureCurrentConversationSynced() {
        val conversationFromArgs = arguments?.getSerializable("conversation") as? Conversation
        
        if (conversationFromArgs != null) {
            // 如果 currentConversation 为空，或者 ID 不一致，更新它
            if (currentConversation == null) {
                currentConversation = conversationFromArgs
                Log.d(TAG, "从 arguments 恢复 currentConversation: ${currentConversation?.id}")
            } else if (currentConversation?.id != conversationFromArgs.id) {
                Log.w(TAG, "currentConversation ID 不一致！当前: ${currentConversation?.id}, arguments: ${conversationFromArgs.id}，更新为 arguments")
                currentConversation = conversationFromArgs
                // 如果 conversationId 变化，需要重置 ViewModel
                viewModel = null
                viewModelConversationId = null
            }
        } else if (currentConversation == null) {
            Log.w(TAG, "无法从 arguments 获取 conversation，currentConversation 仍为 null")
        }
    }
    
    /**
     * 同步 adapter 数据到 ViewModel（确保数据一致性）
     */
    private fun syncAdapterToViewModel() {
        try {
            val adapter = chatAdapter ?: return
            val items = adapter.getItems()
            val vm = getViewModel()
            
            // 从 adapter 恢复数据到 chatMessages（用于兼容现有代码）
            chatMessages.clear()
            messageHashSet.clear()
            items.forEach { item ->
                when (item) {
                    is ChatItem.Message -> {
                        val chatMessage = ChatMessage(
                            sender = item.sender,
                            message = item.message,
                            type = when {
                                item.isUserMessage -> "user"
                                item.isComplete -> "complete"
                                item.isAnswer -> "answer"
                                else -> "system"
                            },
                            timestamp = item.timestamp,
                            uuid = "",
                            senderImei = item.senderImei
                        )
                        val messageHash = messageHashForDedup(chatMessage)
                        if (!messageHashSet.contains(messageHash)) {
                            chatMessages.add(chatMessage)
                            messageHashSet.add(messageHash)
                        }
                    }
                    is ChatItem.ImageMessage -> {
                        // 处理用户发送的图片消息
                        val imageFile = java.io.File(item.imagePath)
                        val messageText = if (item.query.isNotEmpty()) {
                            "${item.query}\n[图片: ${imageFile.name}]"
                        } else {
                            "[图片: ${imageFile.name}]"
                        }
                        val chatMessage = ChatMessage(
                            sender = "我",
                            message = messageText,
                            type = "image",
                            timestamp = item.timestamp,
                            uuid = "",
                            imagePath = item.imagePath // 保存绝对路径
                        )
                        val messageHash = messageHashForDedup(chatMessage)
                        if (!messageHashSet.contains(messageHash)) {
                            chatMessages.add(chatMessage)
                            messageHashSet.add(messageHash)
                            Log.d(TAG, "同步图片消息到ViewModel: imagePath=${item.imagePath}")
                        }
                    }
                    is ChatItem.ReceivedImageMessage -> {
                        // 处理接收到的图片消息
                        val imageFile = java.io.File(item.imagePath)
                        val messageText = if (item.query.isNotEmpty()) {
                            "${item.query}\n[图片: ${imageFile.name}]"
                        } else {
                            "[图片: ${imageFile.name}]"
                        }
                        val chatMessage = ChatMessage(
                            sender = item.senderName,
                            message = messageText,
                            type = "image",
                            timestamp = item.timestamp,
                            uuid = "",
                            imagePath = item.imagePath, // 保存绝对路径
                            senderImei = item.senderImei
                        )
                        val messageHash = messageHashForDedup(chatMessage)
                        if (!messageHashSet.contains(messageHash)) {
                            chatMessages.add(chatMessage)
                            messageHashSet.add(messageHash)
                            Log.d(TAG, "同步接收到的图片消息到ViewModel: imagePath=${item.imagePath}, sender=${item.senderName}")
                        }
                    }
                    else -> {
                        // 其他类型的item（如TimeStamp、SystemMessage等）不需要同步到ViewModel
                    }
                }
            }
            
            // 同步到 ViewModel
            val vmMessages = vm.getMessages()
            if (chatMessages.isEmpty() && vmMessages.isNotEmpty()) {
                // adapter 为空但 ViewModel 有数据：异步批量恢复可能还未完成，不要用空数据覆盖 ViewModel
                Log.d(TAG, "同步adapter数据到ViewModel: adapter有0条但ViewModel有${vmMessages.size}条，保留ViewModel数据（避免丢失）")
            } else if (vmMessages.size != chatMessages.size) {
                Log.d(TAG, "同步adapter数据到ViewModel: adapter有${chatMessages.size}条，ViewModel有${vmMessages.size}条")
                vm.clearMessages()
                vm.addMessages(chatMessages)
            } else {
                // 即使数量相同，也要检查是否有图片消息的imagePath丢失
                val hasImagePathMissing = vmMessages.any { vmMsg ->
                    vmMsg.type == "image" && vmMsg.imagePath == null
                }
                val adapterHasImagePath = chatMessages.any { adapterMsg ->
                    adapterMsg.type == "image" && adapterMsg.imagePath != null
                }
                if (hasImagePathMissing && adapterHasImagePath) {
                    Log.d(TAG, "检测到ViewModel中图片消息缺少imagePath，重新同步")
                    vm.clearMessages()
                    vm.addMessages(chatMessages)
                }
            }
        } catch (e: Exception) {
            Log.e(TAG, "同步adapter数据到ViewModel失败: ${e.message}", e)
        }
    }
    
    /**
     * 从 ViewModel 恢复聊天记录（优先使用，避免重新加载）
     */
    private fun scheduleRestoreFromViewModelRetry(nextRetry: Int, delayMs: Long, reason: String) {
        ensureMainScopeActive()
        mainScope.launch {
            Log.d(TAG, "$reason：${delayMs}ms后触发重试（第${nextRetry}次）")
            delay(delayMs)
            restoreChatMessagesFromViewModel(nextRetry)
        }
    }

    private suspend fun restoreChatMessagesFromViewModel(retryCount: Int = 0): Unit = withContext(Dispatchers.Main) {
        if (isRestoringMessages) {
            Log.w(TAG, "正在恢复消息，跳过重复调用")
            return@withContext
        }
        
        isRestoringMessages = true
        Log.d(TAG, "========== 从 ViewModel 恢复聊天记录 ==========")
        try {
            val vm = getViewModel()
            val messages = vm.getMessages()
            Log.d(TAG, "ViewModel中有${messages.size}条消息")
            
            if (messages.isEmpty()) {
                Log.d(TAG, "ViewModel中没有消息，跳过恢复")
                isRestoringMessages = false
                return@withContext
            }
            
            // 同步到本地 chatMessages（用于兼容现有代码）
            chatMessages.clear()
            chatMessages.addAll(messages)
            messageHashSet.clear()
            messages.forEach { message ->
                messageHashSet.add(messageHashForDedup(message))
            }
            
            // 使用现有的批量恢复方法
            val adapter = chatAdapter ?: run {
                if (retryCount < 3 && isAdded) {
                    val nextRetry = retryCount + 1
                    val delayMs = 80L * nextRetry
                    Log.w(TAG, "chatAdapter为空，延迟${delayMs}ms后重试恢复（第${nextRetry}次）")
                    isRestoringMessages = false
                    scheduleRestoreFromViewModelRetry(nextRetry, delayMs, "chatAdapter为空")
                    return@withContext
                }
                Log.w(TAG, "chatAdapter为空，无法恢复消息（已达重试上限）")
                isRestoringMessages = false
                return@withContext
            }
            
            // 先清空 adapter，避免残留旧 items 导致 hash 去重不一致而产生重复消息
            adapter.clear()
            Log.d(TAG, "已清空 adapter，准备从 ViewModel 全量恢复")
            
            // 在恢复消息前，先根据消息数量设置正确的 stackFromEnd，避免布局跳转
            val bindingRef = _binding ?: run {
                if (retryCount < 3 && isAdded) {
                    val nextRetry = retryCount + 1
                    val delayMs = 80L * nextRetry
                    Log.w(TAG, "binding为空，延迟${delayMs}ms后重试恢复（第${nextRetry}次）")
                    isRestoringMessages = false
                    scheduleRestoreFromViewModelRetry(nextRetry, delayMs, "binding为空")
                    return@withContext
                }
                Log.w(TAG, "binding为空，无法恢复消息（已达重试上限）")
                isRestoringMessages = false
                return@withContext
            }
            val layoutManager = bindingRef.rvChatMessages.layoutManager as? LinearLayoutManager
            if (messages.size <= MESSAGES_PER_PAGE) {
                // 消息不足一页，置顶显示
                layoutManager?.stackFromEnd = false
                Log.d(TAG, "从ViewModel恢复：消息不足一页(${messages.size}条)，设置stackFromEnd=false（置顶显示）")
            } else {
                // 消息超过一页，从底部开始显示
                layoutManager?.stackFromEnd = true
                Log.d(TAG, "从ViewModel恢复：消息超过一页(${messages.size}条)，设置stackFromEnd=true（从底部开始显示）")
            }
            
            restoreChatMessagesInBatches(adapter, messages, isInitialLoad = true) {
                isRestoringMessages = false
                Log.d(TAG, "========== 从 ViewModel 恢复聊天记录完成 ==========")
            }
        } catch (e: Exception) {
            Log.e(TAG, "从 ViewModel 恢复消息失败: ${e.message}", e)
            isRestoringMessages = false
        }
    }
    
    /**
     * 从SharedPreferences恢复聊天记录（仅在 ViewModel 为空时使用）
     */
    private suspend fun restoreChatMessages() = withContext(Dispatchers.IO) {
        // 防止重复加载
        if (isRestoringMessages) {
            Log.w(TAG, "正在恢复消息，跳过重复调用")
            return@withContext
        }
        
        isRestoringMessages = true
        Log.d(TAG, "========== 开始恢复聊天记录 ==========")
        try {
            // 如果currentConversation为null，尝试从arguments中重新获取
            if (currentConversation == null) {
                val conversationFromArgs = arguments?.getSerializable("conversation") as? Conversation
                if (conversationFromArgs != null) {
                    currentConversation = conversationFromArgs
                    Log.d(TAG, "恢复消息 - currentConversation为null，从arguments重新获取: ${conversationFromArgs.id}")
                }
            }
            val conversationId = currentConversation?.id ?: "default"
            Log.d(TAG, "恢复消息 - currentConversation: ${currentConversation?.id}, conversationId: $conversationId")
            val prefs = requireContext().getSharedPreferences("app_prefs", android.content.Context.MODE_PRIVATE)
            
            // 检查应用是否重启：比较保存的启动时间戳和当前的启动时间戳
            var currentAppStartTime = prefs.getLong("app_start_time", 0)
            val savedChatStartTime = prefs.getLong("chat_messages_start_time_$conversationId", 0)
            
            // 如果app_start_time未设置，快速重试几次（确保MainActivity已设置，避免固定延迟）
            if (currentAppStartTime == 0L) {
                repeat(3) { // 最多重试3次
                    delay(10) // 每次只等待10ms
                    currentAppStartTime = prefs.getLong("app_start_time", 0)
                    if (currentAppStartTime != 0L) return@repeat
                }
                if (currentAppStartTime == 0L) {
                    currentAppStartTime = System.currentTimeMillis()
                    prefs.edit().putLong("app_start_time", currentAppStartTime).apply()
                    Log.d(TAG, "app_start_time未设置，设置为当前时间: $currentAppStartTime")
                }
            }
            
            // 如果时间戳不匹配且时间差超过1小时，说明应用已重启
            // 应用重启后，所有对话的聊天记录都应该保留，只更新启动时间戳
            val timeDiff = kotlin.math.abs(currentAppStartTime - savedChatStartTime)
            if (savedChatStartTime != 0L && timeDiff > 3600000) {
                // 应用已重启，更新启动时间戳，但保留所有聊天记录
                Log.d(TAG, "检测到应用重启，保留所有聊天记录并更新启动时间戳 (current=$currentAppStartTime, saved=$savedChatStartTime)")
                prefs.edit().putLong("chat_messages_start_time_$conversationId", currentAppStartTime).apply()
            }
            
            // 根据对话ID加载对应的聊天记录
            val messagesJson = prefs.getString("chat_messages_$conversationId", null)
            Log.d(TAG, "恢复消息 - 从SharedPreferences加载，key: chat_messages_$conversationId, messagesJson存在: ${messagesJson != null}, 长度: ${messagesJson?.length ?: 0}")
            val messagesToRestore = mutableListOf<ChatMessage>()
            
            if (messagesJson != null) {
                val jsonArray = org.json.JSONArray(messagesJson)
                for (i in 0 until jsonArray.length()) {
                    val obj = jsonArray.getJSONObject(i)
                    val sender = obj.getString("sender")
                    val message = obj.getString("message")
                    
                    // 如果是人工客服对话，过滤掉欢迎消息（欢迎消息由ensureWelcomeMessageAtTop()管理，置顶显示）
                    if (conversationId == ConversationListFragment.CONVERSATION_ID_CUSTOMER_SERVICE && 
                        sender == "人工客服" && 
                        message.contains("我是人工客服") && 
                        (message.contains("使用说明") || message.contains("清除数据"))) {
                        Log.d(TAG, "过滤掉欢迎消息（由置顶逻辑管理）: ${message.take(50)}")
                        continue
                    }
                    
                    // 兼容旧格式（没有type字段）
                    val type = if (obj.has("type")) obj.getString("type") else {
                        // 根据sender和message推断类型
                        when {
                            sender == "我" || sender == "用户" -> "user"
                            message == "任务已完成" || message == "任务已完成 ✓" -> "complete"
                            else -> "system"
                        }
                    }
                    // 兼容旧格式（没有timestamp字段）
                    var timestamp = if (obj.has("timestamp")) {
                        val timestampValue = obj.get("timestamp")
                        when (timestampValue) {
                            is Long -> timestampValue
                            is Int -> timestampValue.toLong()
                            is Double -> timestampValue.toLong()
                            is String -> {
                                // 如果是字符串，尝试解析（可能是ISO格式）
                                ChatWebSocketJsonUtils.parseMessageTimestamp(obj, "timestamp")
                            }
                            else -> System.currentTimeMillis()
                        }
                    } else {
                        System.currentTimeMillis()
                    }
                    
                    // 注意：已移除自动修复时间戳逻辑，避免反复修改时间戳导致时间混乱
                    // 时间戳统一由parseTimestamp函数处理，确保时区解析一致
                    
                    // 兼容旧格式（没有uuid字段）
                    val uuid = if (obj.has("uuid")) obj.getString("uuid") else ""
                    // 读取额外字段（图片路径、技能ID、发送者IMEI）
                    // 注意：optString 如果字段不存在会返回默认值，如果字段存在但值为空字符串也会返回空字符串
                    // 所以需要检查字段是否存在，并且值不为空字符串
                    val imagePath = if (obj.has("imagePath")) {
                        val path = obj.optString("imagePath", null)
                        if (path != null && path.isNotEmpty()) path else null
                    } else null
                    val skillId = if (obj.has("skillId")) {
                        val id = obj.optString("skillId", null)
                        if (id != null && id.isNotEmpty()) id else null
                    } else null
                    val senderImei = if (obj.has("senderImei")) {
                        val imei = obj.optString("senderImei", null)
                        if (imei != null && imei.isNotEmpty()) imei else null
                    } else null
                    Log.d(TAG, "恢复消息 - sender: $sender, type: $type, imagePath: $imagePath, skillId: $skillId, senderImei: $senderImei")
                    val chatMessage = ChatMessage(sender, message, type, timestamp, uuid, imagePath, skillId, senderImei)
                    messagesToRestore.add(chatMessage)
                }
                Log.d(TAG, "恢复消息 - 从JSON解析出 ${messagesToRestore.size} 条消息")
            } else {
                Log.w(TAG, "恢复消息 - 未找到保存的消息，conversationId: $conversationId")
            }
            
            // 如果是人工客服对话，合并待处理消息到恢复列表中
            // 这样可以确保待处理消息不会丢失，即使恢复消息时清空了adapter
            if (conversationId == ConversationListFragment.CONVERSATION_ID_CUSTOMER_SERVICE) {
                try {
                    val unreadPrefs = requireContext().getSharedPreferences("customer_service_unread", android.content.Context.MODE_PRIVATE)
                    val pendingMessagesJson = unreadPrefs.getString("pending_messages", "[]")
                    val pendingMessagesArray = org.json.JSONArray(pendingMessagesJson)
                    Log.d(TAG, "发现 ${pendingMessagesArray.length()} 条待处理消息，合并到恢复列表中")
                    
                    for (i in 0 until pendingMessagesArray.length()) {
                        val msgObj = pendingMessagesArray.getJSONObject(i)
                        val sender = msgObj.getString("sender")
                        val content = msgObj.getString("content")
                        
                        // 过滤掉欢迎消息（欢迎消息由ensureWelcomeMessageAtTop()管理，置顶显示）
                        if (sender == "人工客服" && 
                            content.contains("我是人工客服") && 
                            (content.contains("使用说明") || content.contains("清除数据"))) {
                            Log.d(TAG, "过滤掉待处理消息中的欢迎消息（由置顶逻辑管理）: ${content.take(50)}")
                            continue
                        }
                        
                        val timestamp = msgObj.optLong("timestamp", System.currentTimeMillis())
                        // 待处理消息通常是人工客服发送的消息，类型为system
                        val chatMessage = ChatMessage(sender, content, "system", timestamp, "")
                        messagesToRestore.add(chatMessage)
                        Log.d(TAG, "合并待处理消息: sender=$sender, content=${content.take(50)}")
                    }
                } catch (e: Exception) {
                    Log.e(TAG, "合并待处理消息失败: ${e.message}", e)
                }
            }
            
            // 按时间戳稳定排序（时间戳相同时按uuid和消息内容排序，确保顺序稳定）
            messagesToRestore.sortWith(compareBy<ChatMessage> { it.timestamp }
                .thenBy { it.uuid }
                .thenBy { it.message.hashCode() })
            
            // 切换到主线程更新UI（分批恢复，避免阻塞）
            withContext(Dispatchers.Main) {
                Log.d(TAG, "========== 开始恢复UI，消息数量: ${messagesToRestore.size} ==========")
                
                // 检查Fragment是否仍然有效（防止在恢复过程中Fragment被销毁）
                if (!isAdded || _binding == null) {
                    Log.w(TAG, "Fragment已销毁或binding为null，取消恢复")
                    isRestoringMessages = false
                    return@withContext
                }
                
                // 先检查adapter是否已有消息，如果有说明已经恢复过了（防止重复恢复）
                val adapter = chatAdapter
                if (adapter == null) {
                    Log.w(TAG, "Adapter为null，无法恢复消息")
                    isRestoringMessages = false
                    return@withContext
                }
                
                val currentItems = adapter.getItems()
                val hasExistingItems = currentItems.isNotEmpty()
                
                // 先填充内存中的消息列表（在清空UI之前，确保数据已准备好）
                // 清空并重新填充消息列表和hash集合（高效去重）
                val tempChatMessages = mutableListOf<ChatMessage>()
                val tempMessageHashSet = mutableSetOf<String>()
                messagesToRestore.forEach { message ->
                    val messageHash = messageHashForDedup(message)
                    if (!tempMessageHashSet.contains(messageHash)) {
                        tempChatMessages.add(message)
                        tempMessageHashSet.add(messageHash)
                    }
                }
                Log.d(TAG, "去重后准备恢复的消息数量: ${tempChatMessages.size}")
                
                // 如果内存中已有消息，优先合并内存列表（数据更完整）
                if (chatMessages.isNotEmpty()) {
                    Log.d(TAG, "检测到内存中已有${chatMessages.size}条消息，优先合并内存列表")
                    chatMessages.forEach { existingMessage ->
                        // 如果是人工客服对话，过滤掉欢迎消息
                        if (conversationId == ConversationListFragment.CONVERSATION_ID_CUSTOMER_SERVICE && 
                            existingMessage.sender == "人工客服" && 
                            existingMessage.message.contains("我是人工客服") && 
                            (existingMessage.message.contains("使用说明") || existingMessage.message.contains("清除数据"))) {
                            return@forEach
                        }
                        val messageHash = messageHashForDedup(existingMessage)
                        if (!tempMessageHashSet.contains(messageHash)) {
                            tempChatMessages.add(existingMessage)
                            tempMessageHashSet.add(messageHash)
                        }
                    }
                    Log.d(TAG, "合并内存消息后准备恢复的消息数量: ${tempChatMessages.size}")
                } else if (hasExistingItems) {
                    // 如果内存为空，才从adapter提取（作为备选方案）
                    Log.d(TAG, "检测到adapter中已有${currentItems.size}条消息，从adapter合并")
                    currentItems.forEach { item ->
                        if (item is ChatItem.Message) {
                            // 如果是人工客服对话，过滤掉欢迎消息
                            if (conversationId == ConversationListFragment.CONVERSATION_ID_CUSTOMER_SERVICE && 
                                item.sender == "人工客服" && 
                                item.message.contains("我是人工客服") && 
                                (item.message.contains("使用说明") || item.message.contains("清除数据"))) {
                                return@forEach
                            }
                            
                            // 尝试从chatMessages中找到对应的完整消息（包含uuid）
                            val existingMessage = chatMessages.find { 
                                it.sender == item.sender && 
                                it.message == item.message && 
                                it.timestamp == item.timestamp 
                            } ?: ChatMessage(
                                sender = item.sender,
                                message = item.message,
                                type = when {
                                    item.isUserMessage -> "user"
                                    item.isComplete -> "complete"
                                    item.isAnswer -> "answer"
                                    else -> "system"
                                },
                                timestamp = item.timestamp,
                                uuid = chatUuid
                            )
                            val messageHash = messageHashForDedup(existingMessage)
                            if (!tempMessageHashSet.contains(messageHash)) {
                                tempChatMessages.add(existingMessage)
                                tempMessageHashSet.add(messageHash)
                            }
                        }
                    }
                    Log.d(TAG, "合并adapter消息后准备恢复的消息数量: ${tempChatMessages.size}")
                }
                
                // 合并后需要重新排序，确保消息按时间戳顺序排列（稳定排序）
                tempChatMessages.sortWith(compareBy<ChatMessage> { it.timestamp }
                    .thenBy { it.uuid }
                    .thenBy { it.message.hashCode() })
                Log.d(TAG, "合并后已重新排序，确保消息顺序正确")
                
                // 再次检查Fragment是否仍然有效（防止在数据处理过程中Fragment被销毁）
                if (!isAdded || _binding == null) {
                    Log.w(TAG, "Fragment在数据处理过程中被销毁，取消恢复")
                    isRestoringMessages = false
                    return@withContext
                }
                
                // 如果合并了现有消息，需要清空adapter并重新添加所有消息（确保顺序正确）
                // 如果只是恢复消息（没有现有消息），也清空adapter
                if (hasExistingItems) {
                    Log.d(TAG, "adapter已有消息，清空adapter并重新添加所有消息（包括现有消息和新消息），确保顺序正确")
                    chatAdapter?.clear()
                } else {
                    Log.d(TAG, "adapter为空，清空UI准备恢复")
                    chatAdapter?.clear()
                }
                
                // 清空系统消息容器内容，但保持容器引用（不从binding中移除）
                systemMessagesContent?.removeAllViews()
                isSystemMessagesExpanded = false
                systemMessageCount = 0
                lastMessageTimestamp = 0
                // 隐藏系统消息容器（如果有系统消息会重新显示）
                systemMessagesContainer?.visibility = android.view.View.GONE
                
                // 将准备好的数据复制到实际的消息列表
                chatMessages.clear()
                messageHashSet.clear()
                chatMessages.addAll(tempChatMessages)
                messageHashSet.addAll(tempMessageHashSet)
                Log.d(TAG, "去重后chatMessages中的消息数量: ${chatMessages.size}")
                
                // 同步到 ViewModel（确保 ViewModel 中的数据是最新的）
                try {
                    val vm = getViewModel()
                    vm.clearMessages()
                    vm.addMessages(tempChatMessages)
                    Log.d(TAG, "已同步${tempChatMessages.size}条消息到 ViewModel")
                } catch (e: Exception) {
                    Log.w(TAG, "同步消息到 ViewModel 失败: ${e.message}", e)
                }
                
                // 重置分页加载状态
                loadedMessageCount = 0
                hasMoreMessages = messagesToRestore.size > MESSAGES_PER_PAGE
                
                // 再次检查Fragment是否仍然有效（防止在准备恢复时Fragment被销毁）
                if (!isAdded || _binding == null) {
                    Log.w(TAG, "Fragment在准备恢复时被销毁，取消恢复")
                    isRestoringMessages = false
                    return@withContext
                }
                
                // 只加载最近2页的消息（分页加载）
                val messagesToLoad = if (tempChatMessages.size > MESSAGES_PER_PAGE) {
                    // 只取最新的MESSAGES_PER_PAGE条消息
                    tempChatMessages.takeLast(MESSAGES_PER_PAGE)
                } else {
                    tempChatMessages
                }
                Log.d(TAG, "准备恢复的消息数量: ${messagesToLoad.size}，时间范围: ${messagesToLoad.firstOrNull()?.timestamp} - ${messagesToLoad.lastOrNull()?.timestamp}")
                
                // 在恢复消息之前，先根据消息数量设置正确的 stackFromEnd，避免布局跳转
                // 如果消息不足一页，设置为 false（置顶显示）；如果超过一页，设置为 true（从底部开始显示）
                withContext(Dispatchers.Main) {
                    val layoutManager = binding.rvChatMessages.layoutManager as? LinearLayoutManager
                    if (messagesToLoad.size <= MESSAGES_PER_PAGE) {
                        // 消息不足一页，置顶显示
                        layoutManager?.stackFromEnd = false
                        Log.d(TAG, "消息不足一页(${messagesToLoad.size}条)，设置stackFromEnd=false（置顶显示）")
                    } else {
                        // 消息超过一页，从底部开始显示
                        layoutManager?.stackFromEnd = true
                        Log.d(TAG, "消息超过一页(${messagesToLoad.size}条)，设置stackFromEnd=true（从底部开始显示）")
                    }
                }
                
                // 性能优化：在恢复消息时暂时禁用RecyclerView的动画和布局优化
                val recyclerView = binding.rvChatMessages
                val originalItemAnimator = recyclerView.itemAnimator
                recyclerView.itemAnimator = null // 禁用动画，加快恢复速度
                
                // 性能优化：暂时禁用RecyclerView的绘制，批量更新完成后再启用
                recyclerView.setHasFixedSize(true) // 临时设置，避免频繁测量
                
                // 分批恢复消息，避免主线程阻塞
                restoreChatMessagesInBatches(adapter, messagesToLoad, isInitialLoad = true) {
                    // 恢复完成后，重新启用动画和布局
                    recyclerView.post {
                        // 再次检查Fragment是否仍然有效
                        if (isAdded && _binding != null) {
                            recyclerView.itemAnimator = originalItemAnimator
                            recyclerView.setHasFixedSize(false) // 恢复原设置
                            // 强制重新布局，确保显示正确
                            recyclerView.requestLayout()
                            
                            // 如果是人工客服对话，确保欢迎消息存在并置顶
                            if (conversationId == ConversationListFragment.CONVERSATION_ID_CUSTOMER_SERVICE) {
                                ensureWelcomeMessageAtTop()
                            }
                            
                            // 更新新话题提示的显示状态
                            updateNewTopicHintVisibility()
                            
                            // 确保新话题提示在最后（如果存在）
                            ensureNewTopicHintAtEnd()
                        }
                        // 恢复完成，重置标志
                        isRestoringMessages = false
                    }
                }
            }
        } catch (e: Exception) {
            Log.e(TAG, "恢复聊天记录失败: ${e.message}", e)
            // 确保异常时也重置标志
            isRestoringMessages = false
        }
    }
    
    /**
     * 加载所有用户与人工客服的聊天记录（管理员模式）
     */
    private suspend fun loadAllCustomerServiceChats(forceRefresh: Boolean = false) = withContext(Dispatchers.IO) {
        if (isRestoringMessages && !forceRefresh) {
            Log.w(TAG, "正在加载消息，跳过重复调用")
            return@withContext
        }
        
        isRestoringMessages = true
        Log.d(TAG, "========== 开始加载所有客服聊天记录 ==========")
        
        // 先显示加载提示
        withContext(Dispatchers.Main) {
            addChatMessage("系统", "正在加载所有聊天记录...", skipSystemMessageContainer = true)
        }
        
        try {
            // 管理员模式：直接使用人工客服的v4地址获取所有聊天记录
            val prefs = requireContext().getSharedPreferences("app_prefs", android.content.Context.MODE_PRIVATE)
            val conversationId = ConversationListFragment.CONVERSATION_ID_CUSTOMER_SERVICE
            val specificKey = "chat_server_url_$conversationId"
            
            // 优先使用人工客服专用配置，如果没有则使用默认v4地址
            val customerServiceUrl = prefs.getString(specificKey, null)
                ?: prefs.getString("customer_service_url", null)
                ?: ServiceUrlConfig.DEFAULT_CUSTOMER_SERVICE_URL
            
            Log.d(TAG, "管理员模式：使用客服服务地址: $customerServiceUrl")
            CustomerServiceNetwork.initialize(customerServiceUrl)
            
            val apiService = CustomerServiceNetwork.getApiService()
            if (apiService == null) {
                Log.e(TAG, "CustomerServiceNetwork未初始化")
                withContext(Dispatchers.Main) {
                    addChatMessage("系统", "无法连接到客服服务，请检查服务地址配置\n当前地址: $customerServiceUrl")
                }
                isRestoringMessages = false
                return@withContext
            }
            
            // 调用API获取所有聊天记录
            Log.d(TAG, "准备调用getAllChats API")
            val response = apiService.getAllChats()
            Log.d(TAG, "API调用完成，response.isSuccessful=${response.isSuccessful}, code=${response.code()}")
            
            if (response.isSuccessful) {
                val responseBody = response.body()
                Log.d(TAG, "响应体: success=${responseBody?.success}, message=${responseBody?.message}, chats数量=${responseBody?.chats?.size ?: 0}")
                
                if (responseBody == null) {
                    Log.e(TAG, "响应体为null")
                    withContext(Dispatchers.Main) {
                        addChatMessage("系统", "服务器返回空响应，请检查服务状态")
                    }
                    isRestoringMessages = false
                    return@withContext
                }
                
                if (responseBody.success == true) {
                    val chats = responseBody.chats ?: emptyList()
                    Log.d(TAG, "成功获取 ${chats.size} 个用户的聊天记录")
                    
                    // 打印详细信息用于调试
                    chats.forEachIndexed { index, userChat ->
                        Log.d(TAG, "用户[$index]: imei=${userChat.imei}, 消息数=${userChat.messages?.size ?: 0}")
                    }
                    
                    // 转换为ChatMessage并显示
                    val allMessages = mutableListOf<ChatMessage>()
                    messageImeiMap.clear()  // 清空之前的映射
                    messageDirectImeiMap.clear()  // 清空直接映射
                    messageSimpleImeiMap.clear()  // 清空简单映射
                    
                    if (chats.isEmpty()) {
                        // 如果没有聊天记录，显示提示信息
                        Log.d(TAG, "暂无聊天记录")
                        withContext(Dispatchers.Main) {
                            addChatMessage("系统", "暂无聊天记录，请等待用户与人工客服开始对话")
                        }
                        isRestoringMessages = false
                        return@withContext
                    }
                    
                    // 收集所有用户的IMEI列表
                    allUserImeis = chats.map { it.imei }
                    
                    chats.forEach { userChat ->
                        val imei = userChat.imei
                        // 如果设置了筛选，只处理匹配的用户
                        if (filteredImeis.isNotEmpty() && !filteredImeis.contains(imei)) {
                            return@forEach
                        }
                        
                        val messages = userChat.messages ?: emptyList()
                        Log.d(TAG, "处理用户 $imei，消息数量: ${messages.size}")
                        
                        if (messages.isNotEmpty()) {
                            // 添加用户标识消息
                            val userHeaderMessage = ChatMessage(
                                sender = "系统",
                                message = "========== 用户: $imei ==========",
                                type = "system",
                                timestamp = messages.firstOrNull()?.timestamp ?: System.currentTimeMillis(),
                                uuid = ""
                            )
                            allMessages.add(userHeaderMessage)
                            
                            // 添加该用户的所有消息
                            messages.forEach { msg ->
                                val chatMessage = ChatMessage(
                                    sender = msg.sender,
                                    message = msg.content,
                                    type = msg.message_type,
                                    timestamp = msg.timestamp,
                                    uuid = ""
                                )
                                allMessages.add(chatMessage)
                                
                                // 保存消息对应的IMEI（用于管理员回复）
                                val messageHash = messageHashForDedup(chatMessage)
                                messageImeiMap[messageHash] = imei
                                // 同时保存直接映射（sender, message, timestamp）-> IMEI，作为备用查找方式
                                messageDirectImeiMap[Triple(msg.sender, msg.content, msg.timestamp)] = imei
                                // 保存简单映射（sender, message）-> IMEI，不依赖timestamp，确保所有消息都能找到
                                messageSimpleImeiMap[Pair(msg.sender, msg.content)] = imei
                                
                                // 如果是用户消息，也保存到chatMessages中以便查找
                                if (msg.sender == "用户") {
                                    chatMessages.add(chatMessage)
                                    messageHashSet.add(messageHash)
                                }
                            }
                        }
                    }
                    
                    if (allMessages.isEmpty()) {
                        Log.d(TAG, "转换后的消息列表为空")
                        withContext(Dispatchers.Main) {
                            val message = when {
                                filteredImeis.isEmpty() -> "暂无有效的聊天记录"
                                filteredImeis.size == 1 -> "用户 ${filteredImeis.first()} 暂无聊天记录"
                                else -> "选中的 ${filteredImeis.size} 个用户暂无聊天记录"
                            }
                            addChatMessage("系统", message)
                        }
                        isRestoringMessages = false
                        return@withContext
                    }
                    
                    // 按时间戳排序
                    allMessages.sortBy { it.timestamp }
                    Log.d(TAG, "排序后共有 ${allMessages.size} 条消息")
                    
                    // 更新最后刷新时间
                    if (allMessages.isNotEmpty()) {
                        lastRefreshTime = allMessages.maxOfOrNull { it.timestamp } ?: System.currentTimeMillis()
                    }
                    
                    // 切换到主线程更新UI
                    withContext(Dispatchers.Main) {
                        if (!isAdded || _binding == null) {
                            Log.w(TAG, "Fragment已销毁，取消显示消息")
                            isRestoringMessages = false
                            return@withContext
                        }
                        
                        val adapter = chatAdapter ?: return@withContext
                        
                        // 清空现有消息
                        chatMessages.clear()
                        messageHashSet.clear()
                        adapter.clear()
                        
                        // 添加所有消息
                        allMessages.forEach { message ->
                            val messageHash = messageHashForDedup(message)
                            if (!messageHashSet.contains(messageHash)) {
                                chatMessages.add(message)
                                messageHashSet.add(messageHash)
                                
                                // 使用addChatMessage方法添加消息（它会处理UI更新）
                                val isComplete = message.type == "complete"
                                val isAnswer = message.type == "answer"
                                // 管理员模式下，所有消息都显示在RecyclerView中（包括系统消息）
                                // 传递真实的timestamp，确保查找IMEI时能匹配上
                                addChatMessage(
                                    sender = message.sender,
                                    message = message.message,
                                    isComplete = isComplete,
                                    isAnswer = isAnswer,
                                    skipSystemMessageContainer = true,  // 管理员模式下，所有消息都显示在RecyclerView
                                    timestamp = message.timestamp  // 传递真实的timestamp
                                )
                            }
                        }
                        
                        // 更新筛选按钮文本
                        when {
                            filteredImeis.isEmpty() -> {
                                binding.btnFilterUsers.text = "筛选用户"
                            }
                            filteredImeis.size == 1 -> {
                                binding.btnFilterUsers.text = "筛选用户 (${filteredImeis.first()})"
                            }
                            else -> {
                                binding.btnFilterUsers.text = "筛选用户 (${filteredImeis.size}个)"
                            }
                        }
                        
                        // 滚动到底部
                        binding.rvChatMessages.post {
                            val layoutManager = binding.rvChatMessages.layoutManager as? LinearLayoutManager
                            layoutManager?.stackFromEnd = true
                            binding.rvChatMessages.smoothScrollToPosition(adapter.itemCount - 1)
                        }
                        
                        Log.d(TAG, "已显示 ${allMessages.size} 条消息")
                    }
                } else {
                    val errorMsg = responseBody.message ?: "API返回success=false"
                    Log.e(TAG, "API返回失败: success=${responseBody.success}, message=$errorMsg")
                    withContext(Dispatchers.Main) {
                        addChatMessage("系统", "获取聊天记录失败: $errorMsg\n请检查后端服务日志")
                    }
                }
            } else {
                val errorBody = try {
                    response.errorBody()?.string()
                } catch (e: Exception) {
                    null
                }
                val errorMsg = errorBody ?: "HTTP错误: ${response.code()}"
                Log.e(TAG, "HTTP请求失败: code=${response.code()}, errorBody=$errorBody")
                withContext(Dispatchers.Main) {
                    addChatMessage("系统", "获取聊天记录失败: $errorMsg\n请检查：\n1. 服务地址是否正确\n2. 服务是否正在运行\n3. 网络连接是否正常")
                }
            }
        } catch (e: Exception) {
            Log.e(TAG, "加载所有客服聊天记录失败: ${e.message}", e)
            withContext(Dispatchers.Main) {
                addChatMessage("系统", "加载失败: ${e.message}")
            }
        } finally {
            isRestoringMessages = false
        }
    }
    
    /**
     * 分批恢复聊天消息，避免主线程阻塞
     * 性能优化：使用批量添加而不是单个添加，减少RecyclerView布局计算次数
     * @param isInitialLoad 是否为初始加载（初始加载需要滚动到底部）
     * @param onComplete 恢复完成后的回调
     */
    private fun restoreChatMessagesInBatches(
        adapter: ChatAdapter,
        messagesToRestore: List<ChatMessage>,
        isInitialLoad: Boolean = false,
        onComplete: (() -> Unit)? = null
    ) {
        val sessionId = ++batchRestoreSessionId
        fun isBatchRestoreActive(): Boolean =
            isAdded && _binding != null && sessionId == batchRestoreSessionId
        
        Log.d(TAG, "========== restoreChatMessagesInBatches 开始 ==========")
        Log.d(TAG, "  - messagesToRestore数量: ${messagesToRestore.size}")
        Log.d(TAG, "  - adapter当前items数量: ${adapter.getItems().size}")
        Log.d(TAG, "  - isInitialLoad: $isInitialLoad")
        
        if (!isBatchRestoreActive()) {
            Log.d(TAG, "restoreChatMessagesInBatches: Fragment 或 binding 无效，放弃恢复")
            return
        }
        
        // 在恢复消息前，先根据消息数量设置正确的 stackFromEnd，避免布局跳转
        if (isInitialLoad) {
            val layoutManager = binding.rvChatMessages.layoutManager as? LinearLayoutManager
            if (messagesToRestore.size <= MESSAGES_PER_PAGE) {
                // 消息不足一页，置顶显示
                layoutManager?.stackFromEnd = false
                Log.d(TAG, "消息不足一页(${messagesToRestore.size}条)，设置stackFromEnd=false（置顶显示）")
            } else {
                // 消息超过一页，从底部开始显示
                layoutManager?.stackFromEnd = true
                Log.d(TAG, "消息超过一页(${messagesToRestore.size}条)，设置stackFromEnd=true（从底部开始显示）")
            }
        }
        
        if (messagesToRestore.isEmpty()) {
            // 没有消息时，设置为置顶显示
            if (isInitialLoad) {
                val rv = binding.rvChatMessages
                rv.post {
                    if (!isBatchRestoreActive()) return@post
                    scrollToTop()
                }
            }
            return
        }
        
        // 分批处理消息，每批处理一定数量后延迟一下，避免主线程阻塞
        // 批次大小要适中：太小会增加notify次数，太大会导致单次布局计算时间过长
        // 使用较小的批次大小，确保每次布局计算不会太久，保持滑动流畅
        val BATCH_SIZE = 5 // 减小批次大小，减少单次布局计算时间，避免卡顿
        var currentIndex = 0
        var lastTimestamp: Long = 0
        var hasSystemMessages = false
        val systemMessagesList = mutableListOf<Pair<String, String>>()
        val isFriendConversation = currentConversation?.id?.startsWith("friend_") == true
        // 好友：跨批次累计逻辑键，避免同一条在 prefs 里两条 uuid / 分批恢复时重复插入
        val friendRestoreDedup = mutableSetOf<String>().apply {
            if (isFriendConversation) {
                adapter.getItems().forEach { item ->
                    adapterLogicalKeyForFriendRestore(item)?.let { add(it) }
                }
            }
        }
        // 跨批次累计哈希：adapter.getItems() 依赖 submitList 异步结果，可能返回旧列表，
        // 用本地 Set 替代，确保多批次间去重正确且不受 ListAdapter 异步更新影响。
        val batchRestoreDedup = mutableSetOf<String>().apply {
            if (!isFriendConversation) {
                adapter.getItems().mapNotNull { item ->
                    if (item is ChatItem.Message) {
                        val existingMessage = ChatMessage(
                            sender = item.sender,
                            message = item.message,
                            type = when {
                                item.isUserMessage -> "user"
                                item.isComplete -> "complete"
                                item.isAnswer -> "answer"
                                else -> "system"
                            },
                            timestamp = item.timestamp,
                            uuid = ""
                        )
                        messageHashForDedup(existingMessage)
                    } else null
                }.forEach { add(it) }
            }
        }
        
        fun processBatch() {
            if (!isBatchRestoreActive()) {
                Log.d(TAG, "restoreChatMessagesInBatches: processBatch 已取消（会话失效或视图销毁）")
                return
            }
            if (currentIndex >= messagesToRestore.size) {
                // 所有消息处理完成，批量添加系统消息到固定容器
                Log.d(TAG, "恢复消息完成，检查系统消息: hasSystemMessages=$hasSystemMessages, systemMessagesList.size=${systemMessagesList.size}, systemMessageCount=$systemMessageCount")
                if (hasSystemMessages && systemMessagesList.isNotEmpty()) {
                    // 确保系统消息容器已初始化
                    if (systemMessagesContainer == null) {
                        systemMessagesContainer = binding.llSystemMessagesContainer
                        systemMessagesTitle = binding.tvSystemMessagesTitle
                        systemMessagesScrollView = binding.svSystemMessagesContent
                        systemMessagesContent = binding.llSystemMessagesContent
                        Log.d(TAG, "系统消息容器已初始化")
                    }
                    
                    // 确保容器可见
                    systemMessagesContainer?.visibility = android.view.View.VISIBLE
                    Log.d(TAG, "系统消息容器设置为可见")
                    
                    // 重置计数（因为addSystemMessageToFixedContainer会重新增加）
                    systemMessageCount = 0
                    
                    // 批量添加系统消息
                    for ((sender, message) in systemMessagesList) {
                        addSystemMessageToFixedContainer(sender, message)
                    }
                    
                    Log.d(TAG, "系统消息已添加: 共${systemMessagesList.size}条, 最终计数=$systemMessageCount")
                    
                    // 确保系统消息标题可见（如果有消息）
                    updateSystemMessagesTitle()
                } else {
                    Log.d(TAG, "没有系统消息需要恢复")
                }
                
                // 更新已加载消息计数
                loadedMessageCount = messagesToRestore.size
                
                // 初始加载时，使用 ViewTreeObserver 监听布局完成后再滚动，避免视觉跳跃
                if (isInitialLoad) {
                    val recyclerView = binding.rvChatMessages
                    val layoutManager = recyclerView.layoutManager as? LinearLayoutManager
                    val adapter = chatAdapter
                    val itemCount = adapter?.itemCount ?: 0
                    
                    if (itemCount > 0) {
                        // 使用 ViewTreeObserver 监听布局完成，而不是固定延迟
                        val viewTreeObserver = recyclerView.viewTreeObserver
                        val listener = object : ViewTreeObserver.OnGlobalLayoutListener {
                            override fun onGlobalLayout() {
                                // 移除监听器，避免重复调用
                                recyclerView.viewTreeObserver.removeOnGlobalLayoutListener(this)
                                
                                // 检查Fragment是否仍然有效（含分批恢复会话）
                                if (!isBatchRestoreActive()) {
                                    return
                                }
                                
                                val finalItemCount = adapter?.itemCount ?: 0
                                if (finalItemCount <= MESSAGES_PER_PAGE) {
                                    // 消息不足一页，滚动到顶部
                                    Log.d(TAG, "消息不足一页(${finalItemCount}条)，滚动到顶部")
                                    if (finalItemCount > 0) {
                                        recyclerView.scrollToPosition(0)
                                    }
                                } else {
                                    // 消息超过一页，滚动到底部
                                    Log.d(TAG, "消息超过一页(${finalItemCount}条)，滚动到底部")
                                    recyclerView.scrollToPosition(finalItemCount - 1)
                                    // 滚动后检查按钮可见性
                                    checkScrollToBottomButtonVisibility()
                                }
                            }
                        }
                        viewTreeObserver.addOnGlobalLayoutListener(listener)
                    }
                }
                
                // 执行完成回调
                onComplete?.invoke()
                return
            }
            
            // 收集当前批次要添加的items（批量添加优化）
            val itemsToAdd = mutableListOf<ChatItem>()
            
            // 处理当前批次（正向遍历，从最旧到最新，插入到底部）
            // 消息按时间顺序添加到底部，最新消息在最后
            val endIndex = minOf(currentIndex + BATCH_SIZE, messagesToRestore.size)
            for (i in currentIndex until endIndex) {
                val chatMessage = messagesToRestore[i]
                
                // 检查消息是否已存在（去重）
                if (isFriendConversation) {
                    val fk = FriendChatMessagePrefsStore.logicalDedupKeyFromMessage(chatMessage)
                    if (fk in friendRestoreDedup) {
                        Log.d(TAG, "好友恢复去重跳过: ${chatMessage.message.take(50)}")
                        continue
                    }
                    friendRestoreDedup.add(fk)
                } else {
                    val messageHash = messageHashForDedup(chatMessage)
                    if (batchRestoreDedup.contains(messageHash)) {
                        Log.d(TAG, "消息已存在，跳过: ${chatMessage.message.take(50)}")
                        continue
                    }
                    batchRestoreDedup.add(messageHash)
                }
                // 重新解析发送者名称（如果有senderImei，从好友列表获取昵称）
                val resolvedSender = resolveSenderDisplayName(chatMessage.sender, chatMessage.senderImei)
                val isComplete = chatMessage.type == "complete"
                val isAnswer = chatMessage.type == "answer"
                val isVideo = chatMessage.type == "video"
                val isUserMsg = isUserMessageForDisplay(resolvedSender)
                
                // 如果是图片消息，特殊处理
                if (chatMessage.type == "image" && _binding != null) {
                    // 优先使用保存的imagePath字段，如果没有则从消息文本中解析
                    val imagePathToUse = chatMessage.imagePath
                    Log.d(TAG, "恢复图片消息 - imagePath: $imagePathToUse, sender: ${chatMessage.sender}, message: ${chatMessage.message.take(50)}")
                    
                    var imageFile: java.io.File? = null
                    var imageFileName: String? = null // 保存文件名，用于备用查找
                    
                    // 方案1：优先使用保存的imagePath字段（绝对路径）
                    if (imagePathToUse != null && imagePathToUse.isNotEmpty()) {
                        val file = java.io.File(imagePathToUse)
                        if (file.exists() && file.length() > 0) {
                            Log.d(TAG, "使用保存的图片路径: $imagePathToUse, 文件存在，大小: ${file.length()} bytes")
                            imageFile = file
                            imageFileName = file.name // 保存文件名，用于备用查找
                        } else {
                            Log.w(TAG, "保存的图片路径文件不存在或为空: $imagePathToUse, exists: ${file.exists()}, length: ${file.length()}")
                            // 如果imagePath指向的文件不存在，尝试从路径中提取文件名
                            imageFileName = file.name
                        }
                    }
                    
                    // 方案2：如果imagePath字段无效或文件不存在，尝试从消息文本中解析文件名（备用方案）
                    if (imageFile == null) {
                        // 如果还没有文件名，尝试从消息文本中解析（支持中文和英文冒号）
                        if (imageFileName == null) {
                            Log.d(TAG, "imagePath无效，尝试从消息文本解析文件名")
                            val messageParts = chatMessage.message.split("\n")
                            imageFileName = messageParts.find { 
                                it.startsWith("[图片: ") || it.startsWith("[图片：")
                            }?.let { part ->
                                when {
                                    part.startsWith("[图片: ") -> part.removePrefix("[图片: ").removeSuffix("]")
                                    part.startsWith("[图片：") -> part.removePrefix("[图片：").removeSuffix("]")
                                    else -> ""
                                }
                            } ?: ""
                        }
                        
                        if (imageFileName != null && imageFileName.isNotEmpty()) {
                            val imagesDir = java.io.File(requireContext().getExternalFilesDir(null), "images")
                            val file = java.io.File(imagesDir, imageFileName)
                            if (file.exists() && file.length() > 0) {
                                Log.d(TAG, "从文件名找到图片文件: ${file.absolutePath}, 文件存在，大小: ${file.length()} bytes")
                                imageFile = file
                            } else {
                                Log.w(TAG, "从文件名解析出的图片文件不存在或为空: ${file.absolutePath}, exists: ${file.exists()}, length: ${file.length()}")
                                
                                // 方案3：尝试在images目录中搜索同名文件（处理路径变化的情况）
                                if (imagesDir.exists() && imagesDir.isDirectory) {
                                    val files = imagesDir.listFiles()
                                    val foundFile = files?.find { it.name == imageFileName && it.length() > 0 }
                                    if (foundFile != null) {
                                        Log.d(TAG, "在images目录中找到同名文件: ${foundFile.absolutePath}, 大小: ${foundFile.length()} bytes")
                                        imageFile = foundFile
                                    } else {
                                        Log.w(TAG, "在images目录中未找到同名文件: $imageFileName, 目录中文件数: ${files?.size ?: 0}")
                                    }
                                }
                            }
                        } else {
                            Log.w(TAG, "无法从消息文本中解析出图片文件名: ${chatMessage.message.take(100)}")
                        }
                    }
                    
                    if (imageFile != null && imageFile.exists()) {
                        // 从消息中提取query文本，去除图片标记（支持中文和英文冒号）
                        val messageParts = chatMessage.message.split("\n")
                        val queryText = messageParts.filter { 
                            !it.startsWith("[图片: ") && !it.startsWith("[图片：")
                        }.joinToString("\n").trim()
                        
                        // 检查是否需要显示时间
                        val shouldShowTime = lastTimestamp == 0L || 
                            (chatMessage.timestamp - lastTimestamp) > 10 * 60 * 1000
                        if (shouldShowTime) {
                            itemsToAdd.add(ChatItem.TimeStamp(chatMessage.timestamp))
                        }
                        lastTimestamp = chatMessage.timestamp
                        
                        // 判断是用户发送的图片还是接收到的图片
                        if (chatMessage.senderImei != null || !isUserMsg) {
                            // 接收到的图片消息（左侧对齐）
                            Log.d(TAG, "恢复接收到的图片消息: ${imageFile.absolutePath}, senderImei: ${chatMessage.senderImei}, resolvedSender: $resolvedSender")
                            itemsToAdd.add(ChatItem.ReceivedImageMessage(imageFile.absolutePath, queryText, resolvedSender, chatMessage.timestamp, chatMessage.senderImei))
                        } else {
                            // 用户发送的图片消息（右侧对齐）
                            Log.d(TAG, "恢复用户发送的图片消息: ${imageFile.absolutePath}, resolvedSender: $resolvedSender")
                            itemsToAdd.add(ChatItem.ImageMessage(imageFile.absolutePath, queryText, chatMessage.timestamp, isUserMessage = true, senderName = resolvedSender))
                        }
                    } else {
                        // 图片文件不存在，显示文本消息
                        Log.w(TAG, "图片文件不存在，显示为文本消息: ${chatMessage.message.take(50)}")
                        val shouldShowTime = lastTimestamp == 0L || 
                            (chatMessage.timestamp - lastTimestamp) > 10 * 60 * 1000
                        if (shouldShowTime) {
                            itemsToAdd.add(ChatItem.TimeStamp(chatMessage.timestamp))
                        }
                        lastTimestamp = chatMessage.timestamp
                        itemsToAdd.add(
                            ChatItem.Message(
                                sender = resolvedSender,
                                message = chatMessage.message,
                                isUserMessage = isUserMsg,
                                isComplete = isComplete,
                                isAnswer = isAnswer,
                                timestamp = chatMessage.timestamp,
                                senderImei = chatMessage.senderImei
                            )
                        )
                    }
                    continue
                }
                
                // 如果是视频消息，特殊处理（视频消息需要特殊处理，不能批量添加）
                if (isVideo && _binding != null) {
                    // 先批量添加已收集的items
                    if (itemsToAdd.isNotEmpty()) {
                        adapter.addItems(itemsToAdd)
                        itemsToAdd.clear()
                    }
                    
                    // 从消息中提取视频文件名，尝试找到视频文件
                    val videoFileName = chatMessage.message.removePrefix("[视频: ").removeSuffix("]")
                    // 尝试在录制目录中查找视频文件
                    val recordingsDir = java.io.File(requireContext().getExternalFilesDir(null), "recordings")
                    val videoFile = java.io.File(recordingsDir, videoFileName)
                    if (videoFile.exists()) {
                        // 检查是否需要显示时间
                        val shouldShowTime = lastTimestamp == 0L || 
                            (chatMessage.timestamp - lastTimestamp) > 10 * 60 * 1000
                        
                        if (shouldShowTime) {
                            adapter.addItem(ChatItem.TimeStamp(chatMessage.timestamp))
                        }
                        lastTimestamp = chatMessage.timestamp
                        
                        // 恢复视频消息（显示占位符，不保存到历史记录，避免重复）
                        addVideoMessage(videoFile.absolutePath, saveToHistory = false)
                    } else {
                        // 视频文件不存在，显示文本消息
                        val shouldShowTime = lastTimestamp == 0L || 
                            (chatMessage.timestamp - lastTimestamp) > 10 * 60 * 1000
                        if (shouldShowTime) {
                            itemsToAdd.add(ChatItem.TimeStamp(chatMessage.timestamp))
                        }
                        lastTimestamp = chatMessage.timestamp
                        itemsToAdd.add(
                            ChatItem.Message(
                                sender = resolvedSender,
                                message = chatMessage.message,
                                isUserMessage = isUserMsg,
                                isComplete = isComplete,
                                isAnswer = isAnswer,
                                timestamp = chatMessage.timestamp,
                                senderImei = chatMessage.senderImei
                            )
                        )
                    }
                    continue
                } else {
                    // 首先检查是否是技能消息（优先使用保存的skillId字段）
                    val skill = if (chatMessage.skillId != null && chatMessage.skillId.isNotEmpty()) {
                        // 优先使用保存的技能ID查找技能
                        Log.d(TAG, "恢复技能消息 - skillId: ${chatMessage.skillId}")
                        val foundSkill = findSkillById(chatMessage.skillId)
                        if (foundSkill != null) {
                            Log.d(TAG, "通过skillId找到技能: ${foundSkill.title}")
                            foundSkill
                        } else {
                            Log.w(TAG, "通过skillId未找到技能: ${chatMessage.skillId}，尝试从消息文本解析并保存到临时存储")
                            // 如果通过ID找不到，尝试从消息文本解析
                            val parsedSkill = parseSkillFromMessage(chatMessage.message)
                            if (parsedSkill != null) {
                                // 从消息中解析出技能，但使用原始的skillId（而不是临时ID）
                                val skillWithOriginalId = parsedSkill.copy(id = chatMessage.skillId)
                                // 保存到临时技能存储，确保退出重进后也能找到
                                TemporarySkillManager.saveTemporarySkill(requireContext(), skillWithOriginalId, currentConversation?.id)
                                Log.d(TAG, "从消息解析出技能并保存到临时存储: skillId=${chatMessage.skillId}, title=${skillWithOriginalId.title}")
                                skillWithOriginalId
                            } else {
                                // 如果解析失败，尝试通过标题查找（兼容技能被删除的情况）
                                val skillTitle = extractSkillTitleFromMessage(chatMessage.message)
                                if (skillTitle != null) {
                                    findSkillByTitle(skillTitle, chatMessage.message)
                                } else {
                                    null
                                }
                            }
                        }
                    } else {
                        // 兼容旧格式：通过消息格式识别
                        Log.d(TAG, "skillId为空，尝试从消息文本解析技能")
                        val skillTitle = extractSkillTitleFromMessage(chatMessage.message)
                        if (skillTitle != null) {
                            val foundSkill = findSkillByTitle(skillTitle, chatMessage.message)
                            if (foundSkill != null) {
                                Log.d(TAG, "通过标题找到技能: ${foundSkill.title}")
                            }
                            foundSkill
                        } else {
                            null
                        }
                    }
                    
                    if (skill != null) {
                        // 找到技能，显示为技能卡片
                        Log.d(TAG, "恢复技能卡片: ${skill.title}, skillId: ${skill.id}")
                        val shouldShowTime = lastTimestamp == 0L || 
                            (chatMessage.timestamp - lastTimestamp) > 10 * 60 * 1000
                        
                        if (shouldShowTime) {
                            itemsToAdd.add(ChatItem.TimeStamp(chatMessage.timestamp))
                        }
                        lastTimestamp = chatMessage.timestamp
                        
                        // 添加技能消息卡片
                        itemsToAdd.add(ChatItem.SkillMessage(skill, chatMessage.sender, chatMessage.timestamp, isUserMsg, chatMessage.senderImei))
                        continue
                    } else {
                        // 如果通过skillId找不到技能，保存到待恢复列表（等待技能加载完成后再尝试）
                        if (chatMessage.skillId != null && chatMessage.skillId.isNotEmpty()) {
                            Log.w(TAG, "通过skillId未找到技能: ${chatMessage.skillId}，保存到待恢复列表，等待技能加载完成")
                            pendingSkillMessages.add(chatMessage)
                        }
                        Log.d(TAG, "未找到技能，显示为普通文本消息: ${chatMessage.message.take(50)}")
                    }
                    // 如果找不到技能，继续显示为普通文本消息
                    
                    // 如果不是技能消息，继续处理其他类型的消息
                    if (!isUserMsg && !isComplete && !isAnswer) {
                        // 检查是否需要跳过系统消息容器
                        // "开始学习~"消息、"人工客服"消息、好友/群组/「我的电脑」会话应显示为普通气泡，不放入顶部系统消息折叠区
                        val currentConversationId = currentConversation?.id
                        val isFriendConversation = currentConversationId?.startsWith("friend_") == true
                        val isGroupConversation = currentConversationId?.startsWith("group_") == true || currentConversationId == ConversationListFragment.CONVERSATION_ID_GROUP
                        val isMeConversation = currentConversationId == ConversationListFragment.CONVERSATION_ID_ME
                        val skipSystemContainer = chatMessage.message == "开始学习~" || 
                                                 chatMessage.sender == "人工客服" || 
                                                 isFriendConversation || 
                                                 isGroupConversation ||
                                                 isMeConversation
                        if (!skipSystemContainer) {
                            // 如果是普通系统消息，收集到列表中（不添加到RecyclerView）
                            if (!hasSystemMessages) {
                                hasSystemMessages = true
                            }
                            systemMessagesList.add(Pair(chatMessage.sender, chatMessage.message))
                            systemMessageCount++
                            Log.d(TAG, "恢复系统消息: sender=${chatMessage.sender}, message=${chatMessage.message.take(50)}, count=$systemMessageCount")
                            continue
                        }
                        // 如果跳过系统消息容器，继续处理为普通消息
                    }
                    
                    // 普通消息（用户消息、任务完成消息、answer消息、或需要显示的系统消息）
                    val shouldShowTime = lastTimestamp == 0L || 
                        (chatMessage.timestamp - lastTimestamp) > 10 * 60 * 1000
                    
                    if (shouldShowTime) {
                        itemsToAdd.add(ChatItem.TimeStamp(chatMessage.timestamp))
                    }
                    lastTimestamp = chatMessage.timestamp
                    
                    itemsToAdd.add(
                        ChatItem.Message(
                            sender = resolvedSender,
                            message = chatMessage.message,
                            isUserMessage = isUserMsg,
                            isComplete = isComplete,
                            isAnswer = isAnswer,
                            timestamp = chatMessage.timestamp,
                            senderImei = chatMessage.senderImei
                        )
                    )
                }
            }
            
            // 批量添加收集的items（性能优化：一次性添加而不是逐个添加）
            if (itemsToAdd.isNotEmpty()) {
                val adapterItemsBeforeAdd = adapter.getItems().size
                Log.d(TAG, "批量添加items: ${itemsToAdd.size}条，adapter当前items数量: $adapterItemsBeforeAdd")
                adapter.addItems(itemsToAdd)
                val adapterItemsAfterAdd = adapter.getItems().size
                Log.d(TAG, "批量添加后adapter items数量: $adapterItemsAfterAdd")
            }
            
            currentIndex = endIndex
            
            // 如果还有消息未处理，延迟一下再处理下一批
            // 使用post确保在当前帧完成后再处理下一批，避免阻塞UI线程
            if (currentIndex < messagesToRestore.size) {
                // 每处理完一批后，让UI线程有时间渲染，保持滑动流畅
                // 使用post + postDelayed双重延迟，确保布局计算完成后再处理下一批
                val rv = binding.rvChatMessages
                rv.post {
                    if (!isBatchRestoreActive()) return@post
                    rv.postDelayed({
                        if (!isBatchRestoreActive()) return@postDelayed
                        processBatch()
                    }, 100) // 增加延迟到100ms，给主线程更多时间
                }
            } else {
                // 所有消息处理完成
                processBatch() // 处理系统消息和滚动
            }
        }
        
        // 开始处理第一批
        processBatch()
    }
    
    /**
     * 恢复聊天消息（内部方法，用于恢复，不保存）
     */
    private fun restoreChatMessageInternal(sender: String, message: String, isComplete: Boolean = false, isAnswer: Boolean = false, skipSystemMessageContainer: Boolean = false) {
        val isUserMessage = isUserMessageForDisplay(sender)
        
        // 如果是普通系统消息（不是用户消息，也不是任务完成消息，也不是answer消息），且不跳过系统消息容器，添加到折叠容器
        if (!isUserMessage && !isComplete && !isAnswer && !skipSystemMessageContainer) {
            // 如果折叠容器不存在，创建它
            if (systemMessagesContainer == null) {
                createSystemMessagesContainer()
            }
            // 创建系统消息气泡并添加到容器
            val messageContainer = android.widget.LinearLayout(requireContext()).apply {
                orientation = android.widget.LinearLayout.HORIZONTAL
                layoutParams = android.widget.LinearLayout.LayoutParams(
                    android.widget.LinearLayout.LayoutParams.MATCH_PARENT,
                    android.widget.LinearLayout.LayoutParams.WRAP_CONTENT
                ).apply {
                    setMargins(0, 4, 0, 4)
                }
            }
            
            val leftSpacer = android.view.View(requireContext()).apply {
                layoutParams = android.widget.LinearLayout.LayoutParams(
                    0,
                    android.widget.LinearLayout.LayoutParams.WRAP_CONTENT,
                    1f
                )
            }
            messageContainer.addView(leftSpacer)
            
            val bubble = android.widget.TextView(requireContext()).apply {
                // 检测并渲染Markdown格式
                val markdownMessage = convertToMarkdown(message)
                val markwon = MarkdownRenderer.createMarkwon(requireContext())
                setupMarkwonWithAppLinks(this, markdownMessage, markwon)
                
                textSize = 10f  // 系统消息内容：10sp（小两个号）
                setPadding(
                    systemTextBubbleHorizontalPadding,
                    systemTextBubbleVerticalPadding,
                    systemTextBubbleHorizontalPadding,
                    systemTextBubbleVerticalPadding
                )
                maxWidth = (resources.displayMetrics.widthPixels * 0.7).toInt()
                
                val drawable = android.graphics.drawable.GradientDrawable().apply {
                    setColor(0xFFE8E8E8.toInt())  // 浅灰色背景
                    cornerRadius = systemTextBubbleCornerRadius
                }
                background = drawable
                setTextColor(0xFF666666.toInt())
                
                layoutParams = android.widget.LinearLayout.LayoutParams(
                    android.widget.LinearLayout.LayoutParams.WRAP_CONTENT,
                    android.widget.LinearLayout.LayoutParams.WRAP_CONTENT
                )
            }
            messageContainer.addView(bubble)
            
            val rightSpacer = android.view.View(requireContext()).apply {
                layoutParams = android.widget.LinearLayout.LayoutParams(
                    0,
                    android.widget.LinearLayout.LayoutParams.WRAP_CONTENT,
                    1f
                )
            }
            messageContainer.addView(rightSpacer)
            
            systemMessagesContent?.addView(messageContainer)
            systemMessageCount++
            updateSystemMessagesTitle()
            return
        }
        
        // 用户消息、任务完成消息和answer消息直接显示
        // 注意：这个方法现在不再使用，消息通过RecyclerView Adapter管理
        // 保留此方法仅为了兼容性
        val adapter = chatAdapter
        if (adapter != null) {
            adapter.addItem(ChatItem.Message(sender, message, isUserMessage, isComplete, isAnswer, System.currentTimeMillis()))
            loadedMessageCount++
            updateScrollBehavior()
        }
    }
    
    
    
    /**
     * 添加视频消息到聊天框（用户消息，右侧对齐）
     * @param videoPath 视频文件路径
     * @param saveToHistory 是否保存到聊天记录（恢复时设为false，避免重复）
     */
    internal fun addVideoMessage(videoPath: String, saveToHistory: Boolean = true) {
        if (_binding == null || !isAdded) {
            Log.w(TAG, "Fragment未附加，无法显示视频消息")
            return
        }
        
        try {
            val videoFile = java.io.File(videoPath)
            if (!videoFile.exists()) {
                Log.e(TAG, "视频文件不存在: $videoPath")
                return
            }
            
            // 创建视频消息容器（右对齐，用户消息样式）
            val messageContainer = android.widget.LinearLayout(requireContext()).apply {
                orientation = android.widget.LinearLayout.HORIZONTAL
                layoutParams = android.widget.LinearLayout.LayoutParams(
                    android.widget.LinearLayout.LayoutParams.MATCH_PARENT,
                    android.widget.LinearLayout.LayoutParams.WRAP_CONTENT
                ).apply {
                    setMargins(0, 8, 0, 8)
                }
                gravity = android.view.Gravity.END or android.view.Gravity.TOP
            }
            
            // 头像尺寸
            val avatarSize = (36 * resources.displayMetrics.density).toInt()
            val avatarMargin = (8 * resources.displayMetrics.density).toInt()
            val sideMargin = (16 * resources.displayMetrics.density).toInt()
            val userAvatarRightMargin = 0
            
            // 左侧占位符（保持对齐）
            val leftSpacer = android.view.View(requireContext()).apply {
                layoutParams = android.widget.LinearLayout.LayoutParams(
                    0,
                    android.widget.LinearLayout.LayoutParams.WRAP_CONTENT,
                    1f
                )
            }
            messageContainer.addView(leftSpacer)
            
            // 视频容器（用户消息样式：浅绿色背景）
            // 高度保持现在的尺寸，宽度按视频真实比例计算
            val originalSize = (resources.displayMetrics.widthPixels * 0.6).toInt() // 原来的宽度
            val videoHeight = originalSize / 2 // 高度：缩小为原来的1/2（保持现在的尺寸）
            
            // 先使用默认宽高比创建容器，后续异步更新
            val defaultVideoWidth = videoHeight // 默认使用正方形
            
            val videoContainer = android.widget.FrameLayout(requireContext()).apply {
                layoutParams = android.widget.LinearLayout.LayoutParams(
                    defaultVideoWidth, // 先使用默认宽度，后续异步更新
                    videoHeight  // 保持现在的高度
                )
                
                // 设置背景（方形气泡，用户消息样式）
                val drawable = android.graphics.drawable.GradientDrawable().apply {
                    setColor(0xFF95EC69.toInt()) // 浅绿色背景，与用户消息一致
                    cornerRadius = 0f  // 方形边缘，不需要圆角
                }
                background = drawable
            }
            
            // 视频占位符（显示视频缩略图，不加载视频）
            val placeholderContainer = android.widget.FrameLayout(requireContext()).apply {
                layoutParams = android.widget.FrameLayout.LayoutParams(
                    android.widget.FrameLayout.LayoutParams.MATCH_PARENT,
                    android.widget.FrameLayout.LayoutParams.MATCH_PARENT
                )
                
                // 设置点击事件：点击后全屏播放视频
                isClickable = true
                isFocusable = true
                setOnClickListener {
                    // 点击后全屏播放视频
                    playVideoFullscreen(videoPath)
                }
            }
            
            // 视频缩略图（使用视频中任意一帧作为封面）
            val thumbnailImageView = android.widget.ImageView(requireContext()).apply {
                layoutParams = android.widget.FrameLayout.LayoutParams(
                    android.widget.FrameLayout.LayoutParams.MATCH_PARENT,
                    android.widget.FrameLayout.LayoutParams.MATCH_PARENT
                )
                scaleType = android.widget.ImageView.ScaleType.CENTER_CROP
                // 方形边缘，不需要圆角
                clipToOutline = false
            }
            
            // 异步加载视频宽高比和缩略图
            mainScope.launch {
                // 先异步获取视频宽高比，然后更新容器宽度
                val videoAspectRatio = withContext(Dispatchers.IO) {
                    getVideoAspectRatio(videoPath)
                }
                
                // 更新视频容器宽度（如果获取成功）
                if (videoAspectRatio > 0 && _binding != null && isAdded) {
                    val newVideoWidth = (videoHeight * videoAspectRatio).toInt()
                    videoContainer.layoutParams = android.widget.LinearLayout.LayoutParams(
                        newVideoWidth,
                        videoHeight
                    )
                }
                
                // 异步加载视频缩略图（带缓存）
                val thumbnail = withContext(Dispatchers.IO) {
                    extractVideoThumbnailWithCache(videoPath)
                }
                if (thumbnail != null && _binding != null && isAdded) {
                    thumbnailImageView.setImageBitmap(thumbnail)
                } else {
                    // 如果提取失败，显示默认背景
                    thumbnailImageView.setBackgroundColor(0xFFCCCCCC.toInt())
                }
            }
            
            placeholderContainer.addView(thumbnailImageView)
            
            // 播放按钮图标（覆盖在缩略图上）
            val playButton = android.widget.ImageView(requireContext()).apply {
                layoutParams = android.widget.FrameLayout.LayoutParams(
                    (48 * resources.displayMetrics.density).toInt(),
                    (48 * resources.displayMetrics.density).toInt(),
                    android.view.Gravity.CENTER
                )
                // 使用系统播放图标
                setImageResource(android.R.drawable.ic_media_play)
                scaleType = android.widget.ImageView.ScaleType.CENTER_INSIDE
                // 设置半透明背景，使播放按钮更明显
                setBackgroundColor(0x80000000.toInt()) // 半透明黑色
                setPadding(
                    (8 * resources.displayMetrics.density).toInt(),
                    (8 * resources.displayMetrics.density).toInt(),
                    (8 * resources.displayMetrics.density).toInt(),
                    (8 * resources.displayMetrics.density).toInt()
                )
            }
            placeholderContainer.addView(playButton)
            
            videoContainer.addView(placeholderContainer)
            
            // 创建内部容器（视频 + 头像），整体右对齐
            val contentContainer = android.widget.LinearLayout(requireContext()).apply {
                orientation = android.widget.LinearLayout.HORIZONTAL
                layoutParams = android.widget.LinearLayout.LayoutParams(
                    android.widget.LinearLayout.LayoutParams.WRAP_CONTENT,
                    android.widget.LinearLayout.LayoutParams.WRAP_CONTENT
                )
                gravity = android.view.Gravity.TOP
            }
            
            contentContainer.addView(videoContainer)
            
            // 添加用户头像（在右侧）
            val avatarImageView = android.widget.ImageView(requireContext()).apply {
                layoutParams = android.widget.LinearLayout.LayoutParams(avatarSize, avatarSize).apply {
                    setMargins(avatarMargin, 0, userAvatarRightMargin, 0)
                }
                scaleType = android.widget.ImageView.ScaleType.CENTER_CROP
                visibility = android.view.View.VISIBLE
                minimumWidth = avatarSize
                minimumHeight = avatarSize
                
                // 设置圆形裁剪
                outlineProvider = object : android.view.ViewOutlineProvider() {
                    override fun getOutline(view: android.view.View, outline: android.graphics.Outline) {
                        outline.setOval(0, 0, view.width, view.height)
                    }
                }
                clipToOutline = true
                
                // 设置点击事件：跳转到用户主页
                isClickable = true
                isFocusable = true
                setOnClickListener {
                    val userProfileFragment = UserProfileFragment.newInstance()
                    parentFragmentManager.beginTransaction()
                        .setCustomAnimations(0, 0, 0, 0)
                        .replace(R.id.fragmentContainer, userProfileFragment)
                        .addToBackStack(null)
                        .commitAllowingStateLoss()
                }
                
                // 用户头像：从个人主页获取（使用AvatarCacheManager缓存）
                val userProfile = ProfileManager.loadProfileLocally(requireContext())
                val avatarBase64 = userProfile?.avatar
                AvatarCacheManager.loadBase64Avatar(
                    requireContext(),
                    this,
                    avatarBase64,
                    R.drawable.ic_person,
                    "user_avatar"
                )
                background = androidx.core.content.ContextCompat.getDrawable(requireContext(), R.drawable.circle_background)
            }
            contentContainer.addView(avatarImageView)
            
            messageContainer.addView(contentContainer)
            
            // 添加到聊天消息列表（通过Adapter）
            val adapter = chatAdapter
            if (adapter != null) {
                // 检查是否需要显示时间
                val shouldShowTime = lastMessageTimestamp == 0L || 
                    (System.currentTimeMillis() - lastMessageTimestamp) > 10 * 60 * 1000
                if (shouldShowTime) {
                    // 时间戳插入到底部（最新消息在底部）
                    adapter.addItem(ChatItem.TimeStamp(System.currentTimeMillis()))
                }
                lastMessageTimestamp = System.currentTimeMillis()
                adapter.addItem(ChatItem.Message("我", "[视频: ${videoFile.name}]", true, false, false, System.currentTimeMillis()))
                loadedMessageCount++
                
                // 确保新话题提示在最后（如果存在）
                ensureNewTopicHintAtEnd()
                
                updateScrollBehavior()
                
                // 更新对话列表的最后消息（只有真正的用户操作才更新，恢复时saveToHistory=false不更新）
                if (saveToHistory) {
                    currentConversation?.let { conversation ->
                        updateConversationLastMessage(conversation.id, "[视频: ${videoFile.name}]")
                    }
                }
            }
            
            // 保存到聊天记录（用户消息）（仅在需要时保存，避免恢复时重复）
            if (saveToHistory) {
                val currentTime = System.currentTimeMillis()
                val chatMessage = ChatMessage("我", "[视频: ${videoFile.name}]", "video", currentTime, chatUuid)
                if (addMessageToList(chatMessage)) {
                    saveChatMessages(sync = false) // 用户消息立即保存
                }
            }
            
            Log.d(TAG, "视频消息已添加到聊天框: $videoPath")
        } catch (e: Exception) {
            Log.e(TAG, "添加视频消息失败: ${e.message}", e)
        }
    }
    
    /**
     * 获取视频的宽高比
     * @param videoPath 视频文件路径
     * @return 宽高比（宽度/高度），如果失败返回0
     */
    private fun getVideoAspectRatio(videoPath: String): Float {
        return try {
            val retriever = android.media.MediaMetadataRetriever()
            retriever.setDataSource(videoPath)
            
            // 获取视频宽度和高度
            val widthStr = retriever.extractMetadata(android.media.MediaMetadataRetriever.METADATA_KEY_VIDEO_WIDTH)
            val heightStr = retriever.extractMetadata(android.media.MediaMetadataRetriever.METADATA_KEY_VIDEO_HEIGHT)
            
            retriever.release()
            
            if (widthStr != null && heightStr != null) {
                val width = widthStr.toIntOrNull() ?: 0
                val height = heightStr.toIntOrNull() ?: 0
                
                if (width > 0 && height > 0) {
                    val aspectRatio = width.toFloat() / height.toFloat()
                    Log.d(TAG, "视频宽高比: $width x $height, 比例: $aspectRatio")
                    return aspectRatio
                }
            }
            
            Log.w(TAG, "无法获取视频宽高比: $videoPath")
            0f
        } catch (e: Exception) {
            Log.e(TAG, "获取视频宽高比异常: ${e.message}", e)
            0f
        }
    }
    
    /**
     * 获取缩略图缓存文件路径
     * @param videoPath 视频文件路径
     * @return 缓存文件路径
     */
    private fun getThumbnailCachePath(videoPath: String): java.io.File {
        val videoFile = java.io.File(videoPath)
        val cacheDir = java.io.File(requireContext().cacheDir, "video_thumbnails")
        if (!cacheDir.exists()) {
            cacheDir.mkdirs()
        }
        // 使用视频文件名（不含扩展名）+ .jpg 作为缓存文件名
        val cacheFileName = "${videoFile.nameWithoutExtension}.jpg"
        return java.io.File(cacheDir, cacheFileName)
    }
    
    /**
     * 提取视频缩略图（从视频中提取任意一帧，带缓存和压缩）
     * @param videoPath 视频文件路径
     * @return 缩略图Bitmap，如果失败返回null
     */
    private fun extractVideoThumbnailWithCache(videoPath: String): android.graphics.Bitmap? {
        return try {
            val cacheFile = getThumbnailCachePath(videoPath)
            
            // 先检查缓存
            if (cacheFile.exists()) {
                try {
                    val cachedBitmap = android.graphics.BitmapFactory.decodeFile(cacheFile.absolutePath)
                    if (cachedBitmap != null && !cachedBitmap.isRecycled) {
                        Log.d(TAG, "从缓存加载视频缩略图: $videoPath")
                        return cachedBitmap
                    }
                } catch (e: Exception) {
                    Log.w(TAG, "读取缓存缩略图失败，重新提取: ${e.message}")
                }
            }
            
            // 缓存不存在或读取失败，从视频提取
            val retriever = android.media.MediaMetadataRetriever()
            retriever.setDataSource(videoPath)
            
            // 获取视频的第一帧作为缩略图
            var bitmap = retriever.getFrameAtTime(0, android.media.MediaMetadataRetriever.OPTION_CLOSEST_SYNC)
            retriever.release()
            
            if (bitmap != null) {
                // 压缩缩略图（最大尺寸300x300，减少内存占用）
                val maxSize = 300
                val width = bitmap.width
                val height = bitmap.height
                
                val scaledBitmap = if (width > maxSize || height > maxSize) {
                    val scale = minOf(maxSize.toFloat() / width, maxSize.toFloat() / height)
                    val scaledWidth = (width * scale).toInt()
                    val scaledHeight = (height * scale).toInt()
                    android.graphics.Bitmap.createScaledBitmap(bitmap, scaledWidth, scaledHeight, true)
                } else {
                    bitmap
                }
                
                // 如果进行了缩放，回收原始bitmap
                if (scaledBitmap != bitmap) {
                    bitmap.recycle()
                }
                
                // 保存到缓存
                try {
                    cacheFile.parentFile?.mkdirs()
                    val outputStream = java.io.FileOutputStream(cacheFile)
                    scaledBitmap.compress(android.graphics.Bitmap.CompressFormat.JPEG, 85, outputStream)
                    outputStream.close()
                    Log.d(TAG, "视频缩略图已保存到缓存: ${cacheFile.absolutePath}")
                } catch (e: Exception) {
                    Log.w(TAG, "保存缩略图缓存失败: ${e.message}")
                }
                
                Log.d(TAG, "成功提取并压缩视频缩略图: $videoPath (${scaledBitmap.width}x${scaledBitmap.height})")
                return scaledBitmap
            } else {
                Log.w(TAG, "提取视频缩略图失败: $videoPath")
                return null
            }
        } catch (e: Exception) {
            Log.e(TAG, "提取视频缩略图异常: ${e.message}", e)
            null
        }
    }
    
