    /**
     * 保存图片到本地
     * @param uri 图片URI
     * @return 保存的文件路径，如果失败返回null
     */
    private suspend fun saveImageToLocal(uri: android.net.Uri): String? = withContext(Dispatchers.IO) {
        try {
            val imagesDir = java.io.File(requireContext().getExternalFilesDir(null), "images")
            if (!imagesDir.exists()) {
                imagesDir.mkdirs()
            }
            
            val timestamp = System.currentTimeMillis()
            val imageFile = java.io.File(imagesDir, "image_$timestamp.jpg")
            
            requireContext().contentResolver.openInputStream(uri)?.use { inputStream ->
                imageFile.outputStream().use { outputStream ->
                    inputStream.copyTo(outputStream)
                }
            }
            
            Log.d(TAG, "图片已保存到本地: ${imageFile.absolutePath}")
            return@withContext imageFile.absolutePath
        } catch (e: Exception) {
            Log.e(TAG, "保存图片到本地失败: ${e.message}", e)
            return@withContext null
        }
    }
    
    /**
     * 从Base64字符串保存图片到本地
     */
    internal suspend fun saveImageFromBase64(base64: String): String? =
        ChatImageUtils.saveImageFromBase64(requireContext(), base64)
    
    /**
     * 添加接收到的图片消息（左侧对齐）
     */
    internal fun addReceivedImageMessage(imagePath: String, text: String, senderName: String, timestamp: Long, senderImei: String? = null, clearThinking: Boolean = false) {
        if (_binding == null || !isAdded) {
            Log.w(TAG, "Fragment未附加，无法显示接收到的图片消息")
            return
        }
        
        try {
            val conversationId = currentConversation?.id
                ?: (arguments?.getSerializable("conversation") as? Conversation)?.id
            val normalizedSenderName = ChatConstants.normalizeAssistantSenderForConversation(senderName, conversationId)
            val imageFile = java.io.File(imagePath)
            if (!imageFile.exists()) {
                Log.e(TAG, "图片文件不存在: $imagePath")
                addChatMessage(normalizedSenderName, if (text.isNotEmpty()) text else "[图片]", skipSystemMessageContainer = true, timestamp = timestamp, clearThinking = clearThinking)
                return
            }
            
            val adapter = chatAdapter
            if (adapter == null) {
                Log.w(TAG, "Adapter为null，无法添加接收到的图片消息")
                return
            }
            
            // 检查是否需要显示时间
            val shouldShowTime = lastMessageTimestamp == 0L || 
                (timestamp - lastMessageTimestamp) > 10 * 60 * 1000
            lastMessageTimestamp = timestamp

            if (clearThinking) {
                val itemsToAdd = mutableListOf<ChatItem>()
                if (shouldShowTime) itemsToAdd.add(ChatItem.TimeStamp(timestamp))
                itemsToAdd.add(ChatItem.ReceivedImageMessage(imagePath, text, normalizedSenderName, timestamp, senderImei))
                adapter.addItemsClearingThinking(*itemsToAdd.toTypedArray())
            } else {
                if (shouldShowTime) adapter.addItem(ChatItem.TimeStamp(timestamp))
                adapter.addItem(ChatItem.ReceivedImageMessage(imagePath, text, normalizedSenderName, timestamp, senderImei))
            }
            loadedMessageCount++
            
            // 确保新话题提示在最后（如果存在）
            ensureNewTopicHintAtEnd()
            
            updateScrollBehavior()
            
            // 更新对话列表的最后消息
            currentConversation?.let { conversation ->
                val messageText = if (text.isNotEmpty()) {
                    "$text\n[图片: ${imageFile.name}]"
                } else {
                    "[图片: ${imageFile.name}]"
                }
                updateConversationLastMessage(conversation.id, messageText)
            }
            
            // 保存到聊天记录（保存图片路径和发送者IMEI，以便恢复时能正确显示）
            val messageText = if (text.isNotEmpty()) {
                "$text\n[图片: ${imageFile.name}]"
            } else {
                "[图片: ${imageFile.name}]"
            }
            // 使用绝对路径，确保恢复时能找到文件
            val absoluteImagePath = imageFile.absolutePath
            Log.d(TAG, "保存接收到的图片消息 - imagePath: $absoluteImagePath, senderImei: $senderImei, message: ${messageText.take(50)}")
            val chatMessage = ChatMessage(normalizedSenderName, messageText, "image", timestamp, "", imagePath = absoluteImagePath, senderImei = senderImei)
            if (addMessageToList(chatMessage)) {
                saveChatMessages(sync = false) // 异步保存，避免阻塞UI
                Log.d(TAG, "接收到的图片消息已保存到chatMessages列表")
            }
            
            Log.d(TAG, "接收到的图片消息已添加到聊天框: $imagePath")
        } catch (e: Exception) {
            Log.e(TAG, "添加接收到的图片消息失败: ${e.message}", e)
            val conversationId = currentConversation?.id
                ?: (arguments?.getSerializable("conversation") as? Conversation)?.id
            val normalizedSenderName = ChatConstants.normalizeAssistantSenderForConversation(senderName, conversationId)
            addChatMessage(normalizedSenderName, if (text.isNotEmpty()) text else "[图片]", skipSystemMessageContainer = true, timestamp = timestamp)
        }
    }
    
    /**
     * 添加图片消息到聊天框（用户消息，右侧对齐）
     * @param imagePath 图片文件路径
     * @param query 用户查询文本（可选）
     * @param saveToHistory 是否保存到聊天记录（恢复时设为false，避免重复）
     */
    private fun addImageMessage(imagePath: String, query: String = "", saveToHistory: Boolean = true, sender: String? = null) {
        if (_binding == null || !isAdded) {
            Log.w(TAG, "Fragment未附加，无法显示图片消息")
            return
        }
        
        try {
            val imageFile = java.io.File(imagePath)
            if (!imageFile.exists()) {
                Log.e(TAG, "图片文件不存在: $imagePath")
                return
            }
            
            val adapter = chatAdapter
            if (adapter == null) {
                Log.w(TAG, "Adapter为null，无法添加图片消息")
                return
            }
            
            val currentTime = System.currentTimeMillis()
            
            // 检查是否需要显示时间
            val shouldShowTime = lastMessageTimestamp == 0L || 
                (currentTime - lastMessageTimestamp) > 10 * 60 * 1000
            if (shouldShowTime) {
                // 时间戳插入到底部（最新消息在底部）
                adapter.addItem(ChatItem.TimeStamp(currentTime))
            }
            lastMessageTimestamp = currentTime
            
            // 通过Adapter添加图片消息（显示缩略图，插入到底部）
            val senderName = sender ?: getSenderDisplayName()
            adapter.addItem(ChatItem.ImageMessage(imagePath, query, currentTime, isUserMessage = true, senderName = senderName))
            loadedMessageCount++
            
            // 确保新话题提示在最后（如果存在）
            ensureNewTopicHintAtEnd()
            
            updateScrollBehavior()
            
            // 更新对话列表的最后消息（只有真正的用户操作才更新，恢复时saveToHistory=false不更新）
            if (saveToHistory) {
                currentConversation?.let { conversation ->
                    val messageText = if (query.isNotEmpty()) {
                        "$query\n[图片: ${imageFile.name}]"
                    } else {
                        "[图片: ${imageFile.name}]"
                    }
                    updateConversationLastMessage(conversation.id, messageText)
                }
            }
            
            // 保存到聊天记录（仅在需要时保存，避免恢复时重复）
            if (saveToHistory) {
                val messageText = if (query.isNotEmpty()) {
                    "$query\n[图片: ${imageFile.name}]"
                } else {
                    "[图片: ${imageFile.name}]"
                }
                // 保存图片路径，以便恢复时能正确显示图片
                // 使用绝对路径，确保恢复时能找到文件
                val absoluteImagePath = imageFile.absolutePath
                val senderName = sender ?: getSenderDisplayName()
                Log.d(TAG, "保存图片消息 - imagePath: $absoluteImagePath, message: ${messageText.take(50)}, sender: $senderName")
                val chatMessage = ChatMessage(senderName, messageText, "image", currentTime, chatUuid, imagePath = absoluteImagePath)
                if (addMessageToList(chatMessage)) {
                    saveChatMessages(sync = false) // 用户消息立即保存
                    Log.d(TAG, "图片消息已保存到chatMessages列表")
                }
                
                // 保存聊天上下文（如果开关开启）
                // 分别保存query和图片信息
                if (query.isNotEmpty()) {
                    saveChatContext(senderName, query, currentTime)
                }
                // 图片信息也保存（作为用户消息的一部分）
                saveChatContext(senderName, "[图片: ${imageFile.name}]", currentTime)
            }
            
            updateScrollBehavior()
            Log.d(TAG, "图片消息已添加到聊天框: $imagePath")
        } catch (e: Exception) {
            Log.e(TAG, "添加图片消息失败: ${e.message}", e)
        }
    }
    
    /**
     * 加载图片缩略图（压缩，避免卡顿）
     * @param imagePath 图片文件路径
     * @param maxHeight 最大高度
     * @return 缩略图Bitmap，如果失败返回null
     */
    internal fun loadImageThumbnail(imagePath: String, maxHeight: Int): android.graphics.Bitmap? {
        return try {
            val imageFile = ChatImagePathGuard.resolveSafeLocalImageFile(requireContext(), imagePath)
            if (imageFile == null) {
                Log.e(TAG, "图片文件不安全或不存在: $imagePath")
                return null
            }
            
            Log.d(TAG, "开始加载图片缩略图: ${imageFile.absolutePath}, 文件大小: ${imageFile.length()} bytes")
            
            val options = android.graphics.BitmapFactory.Options().apply {
                inJustDecodeBounds = true
            }
            android.graphics.BitmapFactory.decodeFile(imageFile.absolutePath, options)
            
            if (options.outWidth <= 0 || options.outHeight <= 0) {
                Log.e(TAG, "无法读取图片尺寸: width=${options.outWidth}, height=${options.outHeight}")
                return null
            }
            
            val imageHeight = options.outHeight
            val imageWidth = options.outWidth
            Log.d(TAG, "图片原始尺寸: ${imageWidth}x${imageHeight}")
            
            val scale = if (imageHeight > maxHeight) {
                (imageHeight / maxHeight.toFloat()).toInt().coerceAtLeast(1)
            } else {
                1
            }
            
            val decodeOptions = android.graphics.BitmapFactory.Options().apply {
                inSampleSize = scale
            }
            
            val bitmap = android.graphics.BitmapFactory.decodeFile(imageFile.absolutePath, decodeOptions)
            if (bitmap != null && !bitmap.isRecycled) {
                Log.d(TAG, "图片解码成功: ${bitmap.width}x${bitmap.height}")
                // 进一步压缩到目标尺寸
                val targetWidth = (maxHeight * (imageWidth.toFloat() / imageHeight)).toInt()
                val scaledBitmap = android.graphics.Bitmap.createScaledBitmap(bitmap, targetWidth, maxHeight, true)
                // 回收原始bitmap
                if (scaledBitmap != bitmap) {
                    bitmap.recycle()
                }
                Log.d(TAG, "图片缩略图创建成功: ${scaledBitmap.width}x${scaledBitmap.height}")
                scaledBitmap
            } else {
                Log.e(TAG, "图片解码失败或bitmap为null")
                null
            }
        } catch (e: Exception) {
            Log.e(TAG, "加载图片缩略图失败: ${e.message}", e)
            e.printStackTrace()
            null
        }
    }
    
    /**
     * 全屏播放视频
     * @param videoPath 视频文件路径
     */
    private fun playVideoFullscreen(videoPath: String) {
        try {
            val videoFile = java.io.File(videoPath)
            if (!videoFile.exists()) {
                Log.e(TAG, "视频文件不存在: $videoPath")
                Toast.makeText(requireContext(), "视频文件不存在", Toast.LENGTH_SHORT).show()
                return
            }
            
            // 使用FileProvider获取安全的URI（Android 7.0+需要）
            val videoUri = if (android.os.Build.VERSION.SDK_INT >= android.os.Build.VERSION_CODES.N) {
                androidx.core.content.FileProvider.getUriForFile(
                    requireContext(),
                    "${requireContext().packageName}.fileprovider",
                    videoFile
                )
            } else {
                @Suppress("DEPRECATION")
                android.net.Uri.fromFile(videoFile)
            }
            
            // 创建Intent启动系统视频播放器
            val intent = android.content.Intent(android.content.Intent.ACTION_VIEW).apply {
                setDataAndType(videoUri, "video/*")
                addFlags(android.content.Intent.FLAG_ACTIVITY_NEW_TASK)
                addFlags(android.content.Intent.FLAG_GRANT_READ_URI_PERMISSION)
                // 添加FLAG_GRANT_READ_URI_PERMISSION以确保其他应用可以读取文件
                if (android.os.Build.VERSION.SDK_INT >= android.os.Build.VERSION_CODES.N) {
                    addFlags(android.content.Intent.FLAG_GRANT_PERSISTABLE_URI_PERMISSION)
                }
            }
            
            // 尝试启动视频播放器
            try {
                startActivity(intent)
                Log.d(TAG, "已启动全屏视频播放: $videoPath")
            } catch (e: android.content.ActivityNotFoundException) {
                Log.e(TAG, "未找到视频播放器: ${e.message}", e)
                Toast.makeText(requireContext(), "未找到视频播放器", Toast.LENGTH_SHORT).show()
            }
        } catch (e: Exception) {
            Log.e(TAG, "全屏播放视频失败: ${e.message}", e)
            Toast.makeText(requireContext(), "播放视频失败: ${e.message}", Toast.LENGTH_SHORT).show()
        }
    }
    
    /**
     * 添加查询到历史记录
     */
    private fun addQueryToHistory(query: String) {
        // 如果已存在，先移除（避免重复）
        userQueryHistory.remove(query)
        // 添加到最前面（最新的在前面）
        userQueryHistory.add(0, query)
        // 限制历史记录数量
        if (userQueryHistory.size > MAX_HISTORY_SIZE) {
            userQueryHistory.removeAt(userQueryHistory.size - 1)
        }
        // 保存到SharedPreferences
        saveUserQueryHistory()
    }
    
    /**
     * 保存用户查询历史到SharedPreferences
     */
    private fun saveUserQueryHistory() {
        val prefs = requireContext().getSharedPreferences("app_prefs", android.content.Context.MODE_PRIVATE)
        val editor = prefs.edit()
        // 使用Set保存，避免重复
        editor.putStringSet("user_query_history", userQueryHistory.toSet())
        editor.apply()
        Log.d(TAG, "已保存用户查询历史，共${userQueryHistory.size}条")
    }
    
    /**
     * 从SharedPreferences加载用户查询历史
     */
    private fun loadUserQueryHistory() {
        val prefs = requireContext().getSharedPreferences("app_prefs", android.content.Context.MODE_PRIVATE)
        val historySet = prefs.getStringSet("user_query_history", null)
        if (historySet != null) {
            userQueryHistory.clear()
            userQueryHistory.addAll(historySet)
            Log.d(TAG, "已加载用户查询历史，共${userQueryHistory.size}条")
        }
    }
    
    /**
     * 加载对话对象的实际头像（异步，避免阻塞UI）
     * 使用缓存机制，避免重复加载和闪烁
     */
    private fun loadConversationAvatar(avatarImageView: android.widget.ImageView) {
        // 优先使用 currentConversation，如果为 null 则从 arguments 获取
        val conversationId = currentConversation?.id 
            ?: (arguments?.getSerializable("conversation") as? Conversation)?.id
            ?: return
        
        // 先检查缓存，优先使用缓存避免闪烁
        when {
            conversationId == ConversationListFragment.CONVERSATION_ID_ASSISTANT -> {
                // TopoClaw头像（资源文件，无需缓存）
                avatarImageView.setImageResource(R.drawable.ic_assistant_avatar)
                return
            }
            conversationId == ConversationListFragment.CONVERSATION_ID_SKILL_LEARNING -> {
                // 技能学习小助手头像（资源文件，无需缓存）
                avatarImageView.setImageResource(R.drawable.ic_skill_learning_avatar)
                return
            }
            conversationId == ConversationListFragment.CONVERSATION_ID_CUSTOMER_SERVICE -> {
                // 人工客服头像（资源文件，无需缓存）
                avatarImageView.setImageResource(R.drawable.ic_customer_service_avatar)
                return
            }
            conversationId == ConversationListFragment.CONVERSATION_ID_CHAT_ASSISTANT -> {
                // 聊天小助手头像（资源文件，无需缓存）
                avatarImageView.setImageResource(R.drawable.ic_chat_assistant_avatar)
                return
            }
            conversationId == ConversationListFragment.CONVERSATION_ID_ME -> {
                // 我的电脑头像（电脑图标）
                avatarImageView.setImageResource(R.drawable.ic_computer_avatar)
                return
            }
            conversationId == ConversationListFragment.CONVERSATION_ID_GROUP -> {
                // 好友群头像：先检查GroupAvatarHelper缓存
                val avatarSize = (36 * resources.displayMetrics.density).toInt()
                val cachedAvatar = GroupAvatarHelper.getCachedFriendsGroupAvatar(requireContext(), avatarSize)
                if (cachedAvatar != null) {
                    avatarImageView.setImageBitmap(cachedAvatar)
                    return
                }
                // 缓存未命中，先设置默认头像，然后异步加载
                avatarImageView.setImageResource(R.drawable.ic_system_avatar)
            }
            conversationId.startsWith("group_") -> {
                // 动态群组头像：先检查GroupAvatarHelper缓存
                val groupId = conversationId.removePrefix("group_")
                val group = GroupManager.getGroup(requireContext(), groupId)
                if (group != null) {
                    val avatarSize = (36 * resources.displayMetrics.density).toInt()
                    val cachedAvatar = GroupAvatarHelper.getCachedGroupAvatarFromMembers(
                        group.members,
                        avatarSize,
                        group.assistants
                    )
                    if (cachedAvatar != null) {
                        avatarImageView.setImageBitmap(cachedAvatar)
                        return
                    }
                    // 缓存未命中，先设置默认头像，然后异步加载
                    avatarImageView.setImageResource(R.drawable.ic_system_avatar)
                } else {
                    // 群组不存在，使用默认头像
                    avatarImageView.setImageResource(R.drawable.ic_system_avatar)
                    return
                }
            }
            conversationId.startsWith("friend_") -> {
                // 好友对话：使用AvatarCacheManager加载（优先使用缓存）
                val friendImei = conversationId.removePrefix("friend_")
                val friend = FriendManager.getFriend(requireContext(), friendImei)
                val cacheKey = "conversation_${conversationId}"
                AvatarCacheManager.loadBase64Avatar(
                    context = requireContext(),
                    imageView = avatarImageView,
                    base64String = friend?.avatar,
                    defaultResId = R.drawable.ic_person,
                    cacheKey = cacheKey,
                    validationTag = conversationId
                )
                return
            }
            CustomAssistantManager.isCustomAssistantId(conversationId) -> {
                // 自定义小助手：有头像用其头像，无头像用首字（与助手页面一致，不用TopoClaw头像）
                val assistant = CustomAssistantManager.getById(requireContext(), conversationId)
                if (assistant != null) {
                    val avatarSize = (36 * resources.displayMetrics.density).toInt()
                    AvatarCacheManager.loadCustomAssistantAvatar(
                        context = requireContext(),
                        imageView = avatarImageView,
                        assistant = assistant,
                        cacheKey = "conversation_${conversationId}",
                        validationTag = conversationId,
                        sizePx = avatarSize
                    )
                } else {
                    avatarImageView.setImageResource(R.drawable.ic_system_avatar)
                }
                return
            }
            else -> {
                // 其他情况使用默认头像
                avatarImageView.setImageResource(R.drawable.ic_person)
                return
            }
        }
        
        // 缓存未命中的群组头像，异步加载
        mainScope.launch {
            val avatarBitmap = withContext(Dispatchers.IO) {
                when {
                    conversationId == ConversationListFragment.CONVERSATION_ID_GROUP -> {
                        // 好友群头像：需要拼接
                        val avatarSize = (36 * resources.displayMetrics.density).toInt()
                        GroupAvatarHelper.createFriendsGroupAvatar(requireContext(), avatarSize)
                    }
                    conversationId.startsWith("group_") -> {
                        // 动态群组头像：使用群组成员头像拼接
                        val groupId = conversationId.removePrefix("group_")
                        val group = GroupManager.getGroup(requireContext(), groupId)
                        if (group != null) {
                            val avatarSize = (36 * resources.displayMetrics.density).toInt()
                            GroupAvatarHelper.createGroupAvatarFromMembers(
                                requireContext(),
                                group.members,
                                avatarSize,
                                group.assistants
                            )
                        } else {
                            null
                        }
                    }
                    else -> null
                }
            }
            
            // 切换到主线程更新UI
            if (_binding != null && avatarBitmap != null && !avatarBitmap.isRecycled) {
                try {
                    avatarImageView.setImageBitmap(avatarBitmap)
                } catch (e: Exception) {
                    Log.w(TAG, "更新群组头像失败: ${e.message}")
                }
            }
        }
    }
    
    /**
     * 更新对话列表的最后消息
     */
    internal fun updateConversationLastMessage(conversationId: String, message: String) {
        val prefs = requireContext().getSharedPreferences("conversations", android.content.Context.MODE_PRIVATE)
        prefs.edit()
            .putString("${conversationId}_last_message", message)
            .putLong("${conversationId}_last_time", System.currentTimeMillis())
            .apply()
        
        try {
            val main = activity as? MainActivity
            val clf = main?.findConversationListFragment()
            if (clf != null && clf.isAdded) {
                clf.updateLastMessage(conversationId, message)
            } else {
                val conversationListFragment = parentFragmentManager.fragments.find { it is ConversationListFragment } as? ConversationListFragment
                conversationListFragment?.updateLastMessage(conversationId, message)
            }
        } catch (e: Exception) {
            Log.w(TAG, "更新对话列表失败: ${e.message}")
        }
    }
    
    override fun onDestroyView() {
        PcOnlineStatusManager.removeListener(pcOnlineStatusListener)
        PcOnlineStatusManager.stopChecking()
        val pending = pendingLocationToolRequest ?: pendingLocationPermissionRequest
        pending?.let {
            clearPendingLocationRequest(it.requestId)
            sendMobileToolResult(
                requestId = it.requestId,
                protocol = it.protocol,
                conversationId = it.conversationId,
                ok = false,
                tool = "device.get_location",
                data = null,
                errorCode = "CANCELLED",
                errorMessage = "定位请求因页面销毁被取消",
                retryable = true
            )
        }
        pendingCustomAssistantA11yReconnectJob?.cancel()
        pendingCustomAssistantA11yReconnectJob = null
        pendingAccessibilityReconnectJob?.cancel()
        pendingAccessibilityReconnectJob = null
        // 停止语音识别
        if (isVoiceRecording) {
            stopVoiceRecognition()
        }
        
        // 停止转圈动画
        stopRecordingRingAnimation()
        
        // 清理语音识别资源
        try {
            audioRecorderManager?.stopRecord()
            audioRecorderManager = null
            mAsr = null
        } catch (e: Exception) {
            Log.e(TAG, "清理语音识别资源异常: ${e.message}", e)
        }
        
        // 停止管理员模式刷新
        stopAdminModeRefresh()
        
        // 保存聊天记录（Fragment销毁前的最后机会，使用同步保存）
        try {
            saveJob?.cancel()
            if (isAdded && context != null) {
                // 总是从adapter恢复数据，确保保存的是最新的完整数据
                val adapter = chatAdapter
                if (adapter != null && adapter.getItems().isNotEmpty()) {
                    Log.d(TAG, "onDestroyView: Fragment销毁，从adapter恢复数据到chatMessages（adapter有${adapter.getItems().size}条消息）")
                    val items = adapter.getItems()
                    // 清空现有数据，从adapter重新构建完整的数据
                    chatMessages.clear()
                    messageHashSet.clear()
                    items.forEach { item ->
                        if (item is ChatItem.Message) {
                            val chatMessage = ChatMessage(
                                sender = item.sender,
                                message = item.message,
                                type = when {
                                    item.isUserMessage -> "user"
                                    item.isComplete -> "complete"
                                    item.isAnswer -> "answer"
                                    else -> "system"
                                },
                                timestamp = item.timestamp,
                                uuid = "",
                                senderImei = item.senderImei
                            )
                            val messageHash = messageHashForDedup(chatMessage)
                            if (!messageHashSet.contains(messageHash)) {
                                chatMessages.add(chatMessage)
                                messageHashSet.add(messageHash)
                            }
                        }
                    }
                    Log.d(TAG, "onDestroyView: 从adapter恢复了${chatMessages.size}条消息到chatMessages，准备保存")
                } else {
                    Log.d(TAG, "onDestroyView: adapter为空或没有消息，直接保存chatMessages中的${chatMessages.size}条消息")
                }
                saveChatMessages(sync = true)
            }
        } catch (e: Exception) {
            Log.w(TAG, "保存聊天记录失败: ${e.message}", e)
        }
        
        // 清除当前对话的 assistant_push 回调（连接池保持连接，供其他页面使用）
        currentConversation?.id?.let { convId ->
            val imei = ProfileManager.getOrGenerateImei(requireContext())
            val threadId = if (convId == ConversationListFragment.CONVERSATION_ID_CHAT_ASSISTANT)
                Uuid5Util.chatAssistantThreadId(imei) else "${imei}_${convId}"
            ChatWebSocketPool.setOnAssistantPush(threadId, null)
        }
        // 清理弹窗
        popupWindow?.dismiss()
        popupWindow = null
        betaWelcomePopupWindow?.dismiss()
        betaWelcomePopupWindow = null
        // 清理表情面板的触摸监听器
        try {
            _binding?.root?.setOnTouchListener(null)
            emojiPanelTouchListener = null
        } catch (e: Exception) {
            Log.w(TAG, "清理表情面板触摸监听器失败: ${e.message}")
        }
        
        super.onDestroyView()
        stopTask()
        mainScope.cancel()
        
        // 移除系统返回键回调
        onBackPressedCallback?.remove()
        onBackPressedCallback = null
        
        // 移除键盘监听器
        keyboardLayoutListener?.let { listener ->
            _binding?.let { binding ->
                try {
                    binding.root.viewTreeObserver.removeOnGlobalLayoutListener(listener)
                } catch (e: Exception) {
                    Log.w(TAG, "移除键盘监听器失败: ${e.message}")
                }
            }
        }
        keyboardLayoutListener = null
        
        // 清理ScrollView的点击监听
        _binding?.let { binding ->
            try {
                binding.rvChatMessages.setOnClickListener(null)
            } catch (e: Exception) {
                Log.w(TAG, "清理ScrollView点击监听失败: ${e.message}")
            }
        }
        mediaPanelBackgroundView = null
        
        // 隐藏媒体面板和语音面板（不访问binding，只更新状态）
        isMediaPanelVisible = false
        isVoicePanelVisible = false
        
        // 清理录屏悬浮窗
        RecordingOverlayManager.hide()
        
        // 清理录屏回调
        ScreenRecordingService.setCallback(null)
        recordingCallback = null
        
        // 注意：不再在onDestroyView时清理头像缓存，改为使用时间窗口缓存机制
        // 头像缓存由AvatarCacheManager统一管理，5分钟内有效，避免每次进出页面都重新加载
        
        chatAudioFeedback.release()

        batchRestoreSessionId++
        if (isRestoringMessages) {
            isRestoringMessages = false
        }

        _binding = null
    }
    
    /**
     * 检查是否启用了上下文记录
     */
    private fun isContextRecordingEnabled(): Boolean {
        val conversationId = currentConversation?.id ?: return false
        val prefs = requireContext().getSharedPreferences("app_prefs", android.content.Context.MODE_PRIVATE)
        // 群组聊天和好友聊天默认不开启上下文记录
        val defaultValue = when {
            conversationId.startsWith("group_") -> false  // 群组聊天默认关闭
            conversationId.startsWith("friend_") -> false  // 好友聊天默认关闭
            else -> true  // 其他情况默认打开
        }
        return prefs.getBoolean("enable_context_recording_$conversationId", defaultValue)
    }
    
    /**
     * 保存聊天上下文（仅保存用户消息和助手回复）
     */
    private fun saveChatContext(sender: String, message: String, timestamp: Long = System.currentTimeMillis()) {
        if (!isContextRecordingEnabled()) {
            return
        }
        
        mainScope.launch(Dispatchers.IO) {
            try {
                val conversationId = currentConversation?.id ?: return@launch
                val prefs = requireContext().getSharedPreferences("app_prefs", android.content.Context.MODE_PRIVATE)
                val key = "chat_context_$conversationId"
                
                // 读取现有上下文
                val existingJson = prefs.getString(key, null)
                val contextArray = if (existingJson != null) {
                    org.json.JSONArray(existingJson)
                } else {
                    org.json.JSONArray()
                }
                
                // 添加新消息
                contextArray.put(org.json.JSONObject().apply {
                    put("sender", sender)
                    put("message", message)
                    put("timestamp", timestamp)
                })
                
                // 限制最大记录数（1000条）
                val maxRecords = 1000
                if (contextArray.length() > maxRecords) {
                    // 删除最旧的记录，保留最新的1000条
                    val newArray = org.json.JSONArray()
                    val startIndex = contextArray.length() - maxRecords
                    for (i in startIndex until contextArray.length()) {
                        newArray.put(contextArray.get(i))
                    }
                    prefs.edit().putString(key, newArray.toString()).apply()
                } else {
                    prefs.edit().putString(key, contextArray.toString()).apply()
                }
                
                // 更新新话题提示的显示状态（保存历史记录后）
                withContext(Dispatchers.Main) {
                    updateNewTopicHintVisibility()
                }
            } catch (e: Exception) {
                Log.e(TAG, "保存聊天上下文失败: ${e.message}", e)
            }
        }
    }
    
    /**
     * 请求聊天历史总结
     * @param taskUuid 任务UUID（用于标识任务）
     */
    private fun requestChatSummary(taskUuid: String) {
        // 检查"记录聊天上下文"开关是否开启
        if (!isContextRecordingEnabled()) {
            Log.d(TAG, "记录聊天上下文开关已关闭，跳过总结请求")
            return
        }
        
        // 使用默认conversationId如果currentConversation为null
        val conversationId = currentConversation?.id ?: "default"
        
        // 聊天小助手使用 Chat_Assistants 后端，无 /api/summarize-chat 接口，跳过
        if (conversationId == ConversationListFragment.CONVERSATION_ID_CHAT_ASSISTANT) {
            Log.d(TAG, "聊天小助手对话，后端无 summarize-chat 接口，跳过总结请求")
            return
        }
        if (currentConversation == null) {
            Log.w(TAG, "currentConversation为null，使用默认conversationId: $conversationId")
        }
        
        if (chatMessages.isEmpty()) {
            Log.d(TAG, "聊天记录为空，跳过总结请求")
            return
        }
        
        Log.d(TAG, "准备发送聊天历史总结请求，消息数量: ${chatMessages.size}, UUID: $taskUuid, conversationId: $conversationId")
        
        // 记录所有消息的详细信息，用于调试
        chatMessages.forEachIndexed { index, msg ->
            Log.d(TAG, "消息[$index]: sender=${msg.sender}, type=${msg.type}, message=${msg.message.take(50)}...")
        }
        
        mainScope.launch(Dispatchers.IO) {
            try {
                // 构建聊天历史JSON
                val historyJson = org.json.JSONArray()
                chatMessages.forEach { msg ->
                    // 处理图片消息：将图片部分替换为占位符，保留文本部分
                    val processedMessage = if (msg.type == "image") {
                        // 图片消息格式可能是："query\n[图片: filename]" 或 "[图片: filename]"
                        val messageText = msg.message
                        if (messageText.contains("\n")) {
                            // 有query文本，提取query部分，图片部分用占位符替换
                            val parts = messageText.split("\n", limit = 2)
                            val queryPart = parts[0].trim()
                            val imagePart = parts[1].trim()
                            if (queryPart.isNotEmpty()) {
                                "$queryPart\n[图片]"
                            } else {
                                "[图片]"
                            }
                        } else {
                            // 只有图片，没有query文本
                            "[图片]"
                        }
                    } else {
                        // 非图片消息，直接使用原消息
                        msg.message
                    }
                    
                    historyJson.put(org.json.JSONObject().apply {
                        put("sender", msg.sender)
                        put("message", processedMessage)
                        // 图片消息转换为user类型，以便服务端处理
                        put("type", if (msg.type == "image") "user" else msg.type)
                        put("timestamp", msg.timestamp)
                        put("uuid", msg.uuid)
                    })
                }
                
                // 确保使用当前对话对应的服务地址
                ensureNetworkServiceInitialized()
                
                val apiService = NetworkService.getApiService()
                if (apiService == null) {
                    Log.w(TAG, "ApiService未初始化，无法请求总结")
                    return@launch
                }
                
                Log.d(TAG, "发送聊天历史总结请求，消息数量: ${chatMessages.size}, UUID: $taskUuid, conversationId: $conversationId")
                val response = apiService.summarizeChatHistory(
                    uuid = taskUuid,
                    chatHistory = historyJson.toString(),
                    requestType = "summary"
                )
                
                Log.d(TAG, "收到总结响应，状态码: ${response.code()}, 是否成功: ${response.isSuccessful}")
                
                if (response.isSuccessful) {
                    val summaryResponse = response.body()
                    Log.d(TAG, "总结响应体: success=${summaryResponse?.success}, summary长度=${summaryResponse?.summary?.length}, recommendations数量=${summaryResponse?.recommendations?.size ?: 0}")
                    if (summaryResponse?.success == true && summaryResponse.summary != null) {
                        // 保存总结
                        saveChatSummary(conversationId, summaryResponse.summary)
                        chatSummary = summaryResponse.summary
                        Log.d(TAG, "总结请求成功，已保存总结，长度: ${summaryResponse.summary.length}")
                        
                        // 显示推荐任务到上拉弹窗（如果有新推荐则更新，否则复用上一次的）
                        val validRecommendations = summaryResponse.recommendations?.filter { it.isNotBlank() }
                        if (!validRecommendations.isNullOrEmpty()) {
                            // 有新推荐，更新
                            withContext(Dispatchers.Main) {
                                showRecommendationsPanel(validRecommendations)
                            }
                            Log.d(TAG, "已更新推荐任务到弹窗，数量: ${validRecommendations.size}")
                        } else {
                            // 没有新推荐，复用上一次的推荐（如果有）
                            withContext(Dispatchers.Main) {
                                if (currentRecommendations == null) {
                                    // 如果连上一次的推荐都没有，使用默认推荐
                                    showRecommendationsPanel(ChatConstants.DEFAULT_RECOMMENDATIONS)
                                } else {
                                    // 复用上一次的推荐
                                    showRecommendationsPanel(currentRecommendations!!)
                                }
                            }
                            Log.d(TAG, "没有新推荐，复用上一次的推荐任务")
                        }
                        
                        // 总结已保存，不需要更新UI（因为按钮已移到历史记录页面）
                    } else {
                        Log.w(TAG, "总结请求返回失败: success=${summaryResponse?.success}, message=${summaryResponse?.message}")
                    }
                } else {
                    Log.e(TAG, "总结请求失败: ${response.code()} - ${response.message()}")
                    // 尝试读取错误响应体
                    try {
                        val errorBody = response.errorBody()?.string()
                        Log.e(TAG, "错误响应体: $errorBody")
                    } catch (e: Exception) {
                        Log.e(TAG, "读取错误响应体失败: ${e.message}")
                    }
                }
            } catch (e: Exception) {
                Log.e(TAG, "请求聊天历史总结异常: ${e.message}", e)
                e.printStackTrace()
            }
        }
    }
    
    /**
     * 保存聊天总结
     */
    private fun saveChatSummary(conversationId: String, summary: String) {
        try {
            val prefs = requireContext().getSharedPreferences("app_prefs", android.content.Context.MODE_PRIVATE)
            val key = "chat_summary_$conversationId"
            prefs.edit().putString(key, summary).apply()
            Log.d(TAG, "已保存聊天总结: $conversationId")
            
            // 更新新话题提示的显示状态（保存对话总结后）
            updateNewTopicHintVisibility()
        } catch (e: Exception) {
            Log.e(TAG, "保存聊天总结失败: ${e.message}", e)
        }
    }
    
    /**
     * 加载聊天总结
     */
    private fun loadChatSummary(conversationId: String): String? {
        return try {
            val prefs = requireContext().getSharedPreferences("app_prefs", android.content.Context.MODE_PRIVATE)
            val key = "chat_summary_$conversationId"
            val summary = prefs.getString(key, null)
            if (summary != null) {
                chatSummary = summary
            }
            summary
        } catch (e: Exception) {
            Log.e(TAG, "加载聊天总结失败: ${e.message}", e)
            null
        }
    }
    
    /**
     * 清除聊天历史记录和对话总结（不清空当前聊天页面）
     * 效果和点击聊天历史记录右上角的删除图标一样
     */
    internal fun clearChatHistoryAndSummary() {
        val conversationId = currentConversation?.id ?: return
        
        try {
            val prefs = requireContext().getSharedPreferences("app_prefs", android.content.Context.MODE_PRIVATE)
            
            // 删除历史记录（chat_context）
            val contextKey = "chat_context_$conversationId"
            prefs.edit().remove(contextKey).apply()
            Log.d(TAG, "已删除历史记录: $contextKey")
            
            // 删除对话总结
            val summaryKey = "chat_summary_$conversationId"
            prefs.edit().remove(summaryKey).apply()
            Log.d(TAG, "已删除对话总结: $summaryKey")
            
            // 清除内存中的对话总结
            chatSummary = null
            
            // 更新新话题提示的显示状态（清除后应该消失）
            updateNewTopicHintVisibility()
            
            // 显示成功提示
            android.widget.Toast.makeText(
                requireContext(),
                "历史记录和对话总结已清空",
                android.widget.Toast.LENGTH_SHORT
            ).show()
        } catch (e: Exception) {
            Log.e(TAG, "清除聊天历史记录和对话总结失败: ${e.message}", e)
            android.widget.Toast.makeText(
                requireContext(),
                "清空失败: ${e.message}",
                android.widget.Toast.LENGTH_SHORT
            ).show()
        }
    }
    
