     * 当有历史记录或对话总结时显示，无历史记录和对话总结时隐藏
     * 暂时禁用：不显示新话题提示，并移除已存在的提示
     */
    private fun updateNewTopicHintVisibility() {
        // 暂时禁用新话题提示功能，并移除已存在的提示
        val adapter = chatAdapter ?: return
        try {
            val items = adapter.getItems()
            val hintIndices = items.mapIndexedNotNull { index, item ->
                if (item is ChatItem.NewTopicHint) index else null
            }
            
            // 移除所有已存在的新话题提示（从后往前移除，避免索引变化）
            hintIndices.sortedDescending().forEach { index ->
                adapter.removeItemAt(index)
            }
        } catch (e: Exception) {
            Log.e(TAG, "移除新话题提示失败: ${e.message}", e)
        }
        return
        
